pub const DEFAULT_DT_SECONDS: f64 = 1.0 / 15.0;
/// Convert a real-world duration in seconds to a whole number of simulation ticks at the
/// default timestep. This is the SINGLE place tick durations derive from the timestep — change
/// `DEFAULT_DT_SECONDS` above and every `secs_to_ticks(..)`-defined window rescales with it
/// (DRY), instead of every duration constant hard-coding a tick count tied to one tick rate.
pub const fn secs_to_ticks(seconds: f64) -> u64 {
    (seconds / DEFAULT_DT_SECONDS + 0.5) as u64
}
pub const DEFAULT_DURATION_SECONDS: f64 = 10.0 * 60.0;
pub const DEFAULT_MATCH_HALVES: u8 = 1;
pub const DEFAULT_HALF_DURATION_SECONDS: f64 = 0.0;
pub const DEFAULT_HALFTIME_FATIGUE_RECOVERY: f64 = 0.0;
const SITE_PLAYBACK_RECORD_EVERY_TICKS: u64 = 1;
pub const DEFAULT_FIELD_LENGTH_YARDS: f64 = 120.0;
pub const DEFAULT_FIELD_WIDTH_YARDS: f64 = 80.0;
pub const DEFAULT_GOAL_WIDTH_YARDS: f64 = 8.0;
pub const DEFAULT_BALL_DRAG_PER_TICK: f64 = 0.028;
pub const DEFAULT_BALL_AIR_RESISTANCE: f64 = 0.0085;
// Fraction of the ground-style linear + quadratic drag relieved for a fully airborne ball.
// Airborne x-y speed should be close to ballistic free flight; the old partial relief still bled
// so much speed that long lofts crawled horizontally while the gravity timer kept running.
const AERIAL_FLIGHT_DRAG_RELIEF: f64 = 0.88;
pub const DEFAULT_BALL_GRASS_RESISTANCE_YPS2: f64 = 0.96;
pub const DEFAULT_BALL_STOP_SPEED_YPS: f64 = 0.55;
pub const DEFAULT_PLAYER_VISION_SKILL: f64 = 7.6;
pub const DEFAULT_CONTROLLER_DEBOUNCE_MS: u64 = 4;
const PLAYER_CONTROL_RADIUS_YARDS: f64 = 1.55;
// First-touch settle cap: when a player gains control of a ball from a distance
// (within the control radius but not at their feet), the held ball is drawn in to
// the feet by at most this much per tick instead of teleporting. This kills the
// jarring "ball 2–3yd away then snaps to 0.5yd" animation — a controlled ball now
// settles to the feet over ~2 ticks (a realistic first touch). Comfortably above
// the dribble carry lead (0.92yd) so ordinary carrying tracks the feet exactly.
const CONTROL_FIRST_TOUCH_SETTLE_MAX_STEP_YARDS: f64 = 1.4;
// Maximum ball-to-feet distance at which a holder may STRIKE the ball (pass, shoot,
// clear, route-one). During the first-touch settle above, the holder is the ball's
// owner (`has_ball`) while the ball is still 1.4–2.8yd out being drawn in. Letting
// them strike in that window launched the ball from out there / teleported it onto
// the feet first — a "ghost kick" with no player visibly at the ball. A strike is
// only legal once the ball has settled to within this reach; until then the holder
// takes a settling touch. Pinned JUST above the dribble carry lead (0.92yd) and orbit
// max (1.10yd) so ordinary carrying/dribbling release is never blocked, but as low as
// that allows so a just-won ball still 1.2–2.3yd off the feet (control snaps it onto its
// own travel segment, not the feet — see `nearest_ball_controller_for_segment`) cannot be
// struck. At 1.6 the slack above the orbit max was itself the phantom band: a strike fired
// with the ball up to ~1.6yd (≈5ft) from any player. The settle draws the ball in at
// 1.4yd/tick, so this only ever costs ~one extra tick before the strike fires cleanly.
const CONTROLLED_STRIKE_REACH_YARDS: f64 = 1.25;
// Physical reach caps for contesting a moving ball. A fast ball that only nicks
// the skill-based control radius is unreachable: a player can close at most a
// lunge (`INTERCEPT_LUNGE_REACH_YARDS`) plus the ground they cover while the ball
// travels to the contact point. Only applied above a min ball speed so that
// slow/stationary balls keep their normal (multi-tick) control behavior.
const INTERCEPT_LUNGE_REACH_YARDS: f64 = 1.3;
const KINEMATIC_GATE_MIN_BALL_SPEED_YPS: f64 = 10.0;
// Reaction lag before a defender can commit to cutting out a pass that's just been played:
// they must read it and start moving. Used by the movement-aware pass-lane check so it
// predicts the same sprint-reach interceptions the physics resolver makes (a defender
// stationary NOW but able to step into the lane), minus a beat for human reaction.
const PASS_LANE_INTERCEPT_REACTION_SECONDS: f64 = 0.22;
// Cap on the interception sprint window. A defender only realistically steps into a lane in
// the brief moment the ball is passing near them — they cannot read a pass and hold a perfect
// perpendicular sprint for the WHOLE flight of a long ball. Without this cap, a far-along lane
// point (large ball-time-to-arrival) hands a distant defender a huge reach (sprint × seconds),
// flagging defenders 25+ yd off the lane. Bounds the reach to a believable step-in radius.
const PASS_LANE_INTERCEPT_MAX_WINDOW_SECONDS: f64 = 0.6;
// Decision-time fast-bypass relief: a driven floor pass above ~35mph that reaches a defender
// inside most of the reaction window is not treated as an automatic set interception. It is
// still risk-priced by the lane/MPC model, but left legal so learning can discover when speed
// beats the trap.
const PASS_FAST_BYPASS_MIN_SPEED_YPS: f64 = 17.1;
const PASS_FAST_BYPASS_REACTION_WINDOW_SECONDS: f64 = 0.16;
// Decision-time pass safety looks beyond "is the lane clear right now" and asks whether
// an opponent can step into the corridor over the next couple seconds. This is a graded
// POMDP/MPC risk, not a hard physics outcome; the runtime resolver still decides who
// actually controls the moving ball.
const PASS_LANE_DECISION_LOOKAHEAD_SECONDS: f64 = 2.0;
const PASS_LANE_DYNAMIC_RISK_HIGH: f64 = 0.62;
const PASS_LANE_DYNAMIC_RISK_GATE_STRENGTH: f64 = 0.74;
const PASS_LANE_DYNAMIC_RISK_SCORE_PENALTY: f64 = 3.8;
const OWN_HALF_PASS_LANE_DYNAMIC_RISK_SCORE_MULT: f64 = 1.55;
// Misplaced-pass guard: the linear risk penalty above is not enough on its own — a juicy
// forward option can still outscore it and get played straight to an opponent. For a SAFE pass
// (we need OUR man to actually receive it), pile on this STEEP extra penalty for every unit of
// interception risk ABOVE the HIGH threshold, so a lane an opponent already owns drops out of
// contention. Deliberate threaded/killer balls (`require_reception_won == false`) are exempt —
// their risk is priced in, not vetoed.
const PASS_LANE_SAFE_PASS_OVERRISK_PENALTY: f64 = 14.0;
const PASS_TURNOVER_SAFETY_DIRECT_RISK_FLOOR: f64 = 0.34;
const PASS_TURNOVER_SAFETY_RECEIPT_FLOOR: f64 = 0.50;
const PASS_TURNOVER_SAFETY_DAMP: f64 = 0.74;
const PASS_TURNOVER_SAFETY_FINAL_THIRD_FORWARD_DAMP: f64 = 0.56;
// ---------------------------------------------------------------------------
// Bayesian opponent-press belief (lightweight Beta-Bernoulli filter).
// ---------------------------------------------------------------------------
// A POMDP only yields Bayesian effects if a belief is actually maintained. The
// analytic pass-lane interception risk (`pass_lane_interception_risk`) prices a
// lane from the CURRENT geometry alone — it has no memory of whether THIS
// opponent has actually been stepping into lanes. This layer carries a per-player
// posterior over each player's propensity to press / step toward the ball (their
// "will they really cut this lane?" tendency), updated online from observed
// closing behaviour with a conjugate Beta-Bernoulli update and an exponential
// forget toward the prior. The posterior mean shades the geometric lane risk into
// a Bayesian POSTERIOR risk that feeds pass selection: a proven aggressor
// amplifies the priced risk, a passive sitter discounts it. Pure arithmetic, no
// RNG => deterministic / parity-safe; OFF by default, and a disabled match leaves
// the belief map empty so risk is byte-identical to the analytic-only path.
//
// Future hook: the prior (α0, β0) can be seeded per opponent/team from retrieved
// similar moments in Postgres ("this defender closes this lane 70% of the time")
// instead of the neutral prior, without changing any consumer.
//
// Neutral prior Beta(α0, β0): mean 0.5, deliberately weak so a few seconds of
// observation can move it.
const OPPONENT_PRESS_PRIOR_ALPHA: f64 = 2.0;
const OPPONENT_PRESS_PRIOR_BETA: f64 = 2.0;
// Only players within this radius of the ball are "in a position to contest", so
// only they generate a press/hold observation this tick; everyone else just
// forgets toward the prior.
const OPPONENT_PRESS_OBSERVE_RADIUS_YARDS: f64 = 14.0;
// Closing speed toward the ball that counts as a full "stepping in" observation (e=1).
const OPPONENT_PRESS_REFERENCE_CLOSING_YPS: f64 = 4.0;
// Pseudo-count added per observed tick (fractional via soft evidence e in [0,1]).
const OPPONENT_PRESS_OBSERVATION_WEIGHT: f64 = 1.0;
// Memory time-constant of the exponential forget toward the prior (seconds): the
// belief reflects roughly the last ~2s of behaviour, so a defender switching from
// sitting to pressing is re-learned quickly.
const OPPONENT_PRESS_FORGET_TAU_SECONDS: f64 = 2.0;
// Posterior mean that maps to "no change" to the geometric risk (the prior mean).
const OPPONENT_PRESS_NEUTRAL_TENDENCY: f64 = 0.5;
// Clamp on the risk modulation factor: a passive defender discounts the priced lane
// risk to ~0.5x, a proven aggressor amplifies it to ~1.4x.
const OPPONENT_PRESS_RISK_MODULATION_FLOOR: f64 = 0.5;
const OPPONENT_PRESS_RISK_MODULATION_CEIL: f64 = 1.4;
// Hard cap on the total pseudo-count alpha+beta. The exponential forget already bounds the
// concentration at any positive dt, but a degenerate dt of 0 (some playback/trace configs)
// makes the forget factor 1.0 (no decay) and lets the counts grow every tick toward f64
// overflow -> NaN. Capping the concentration (scaling alpha,beta proportionally so the mean is
// preserved) keeps the belief finite and bounds how certain it can ever get. At normal dt the
// fixed point is ~40, far below this, so it never bites in live play.
const OPPONENT_PRESS_MAX_CONCENTRATION: f64 = 400.0;
// During the launch tick, same-team bystanders ignore the first sliver of an outgoing pass so
// the passer cannot ping it into a teammate standing on top of the kick animation. After this
// progress, normal controllable-trajectory logic may take over.
const PASS_SAME_TICK_BYSTANDER_IGNORE_PROGRESS: f64 = 0.12;
const REACTIVE_GROUND_PASS_MIN_SPEED_YPS: f64 = 1.0;
const REACTIVE_GROUND_PASS_LOOKAHEAD_SECONDS: f64 = 1.40;
const REACTIVE_GROUND_PASS_CLAIM_GAP_PENALTY_SECONDS_PER_YARD: f64 = 0.04;
const REACTIVE_GROUND_PASS_GEOMETRY_EPSILON_YARDS: f64 = 1e-3;
const REACTIVE_GROUND_PASS_NUMERIC_EPSILON: f64 = 1e-6;
// A ball flying overhead can only be contacted by players who can get up to it:
// a standing reach plus a jump scaled by aerial ability. Higher balls fly over
// grounded players (the correct "aerial pass passed through" behavior).
const CONTROL_STANDING_REACH_YARDS: f64 = 1.6;
const CONTROL_AERIAL_JUMP_REACH_YARDS: f64 = 2.2;
// ...but a ball at or below ~6ft (head/chest height) is reachable by ANY standing
// player without leaping, so it is always within interception reach regardless of
// aerial ability — a pass played through a player at that height must be contestable
// (proximity permitting), not allowed to sail past a poor leaper. Aerial ability only
// extends reach ABOVE this floor (jumping headers). Matches the existing "low ball"
// threshold (`LOW_BALL_FACING_REQUIRED_ALTITUDE_YARDS`).
const LOW_BALL_INTERCEPT_REACH_FLOOR_YARDS: f64 = 2.0; // ~6 ft
                                                       // Body rotation about the vertical (z) axis. A player's heading turns toward the
                                                       // thing it wants to watch (the ball, or where it's playing) at up to a
                                                       // biomechanical max yaw rate — this also smooths the rendered facing. Turning
                                                       // faster than a comfortable rate, repeatedly, accrues *dizziness* (vestibular
                                                       // disorientation) that decays with rest and degrades control/perception, and it
                                                       // costs energy. Players therefore learn to watch the ball with economical
                                                       // movement rather than whipping their head around.
const MAX_BODY_YAW_RATE_RAD_S: f64 = 5.0; // ~286 deg/s, a hard biomechanical cap (players were spinning too fast)
                                          // While in possession the body cannot whip around — you have to keep the ball under
                                          // control, and the faster you are moving the less you can change direction (momentum).
                                          // The max yaw rate for the carrier ramps DOWN from a near-stop value to a sprint value
                                          // by speed fraction (current speed / the player's own top speed): a jogging carrier can
                                          // turn fairly tightly, a sprinting one only bends the run.
const POSSESSION_MAX_YAW_RATE_SLOW_RAD_S: f64 = 3.0; // ~172 deg/s near a standstill
const POSSESSION_MAX_YAW_RATE_FAST_RAD_S: f64 = 0.9; // ~52 deg/s at a flat-out sprint
                                                     // OFF the ball the body was uncapped (MAX_BODY_YAW_RATE_RAD_S, ~372 deg/s) so players gyroscoped.
                                                     // Cap it too, scaled by speed: a near-stationary player can pivot to keep eyes on the ball, but a
                                                     // runner/sprinter can only bend their heading (they face where they move).
const OFF_BALL_MAX_YAW_RATE_SLOW_RAD_S: f64 = 3.4; // ~195 deg/s near a standstill
const OFF_BALL_MAX_YAW_RATE_FAST_RAD_S: f64 = 1.35; // ~77 deg/s at a flat-out sprint
                                                    // Below this speed a player is effectively stationary and simply faces the ball; above it, the
                                                    // facing follows the GAIT (forward gaits face the movement; back-pedalling / skipping face the
                                                    // ball within a cone of the movement).
const MOVING_FACING_MIN_SPEED_YPS: f64 = 1.2;
// Angular-acceleration cap: the turn rate itself can only change this fast, so a
// player cannot instantly start or stop spinning even on an instant decision.
// Models rotational inertia of the body. At 18 rad/s² it takes ~0.25 s to wind up
// to the max rate and ~0.45 s to REVERSE a flat-out spin (±4 rad/s) — so transient
// 1-2 tick target jitter can't whip the body around. (Was 80, which let the body
// reverse spin in ~1.5 ticks — that produced the "facing flips 5+ times in 3 s"
// flip-flop, since the cap was 20x too high to impose any real inertia.)
const MAX_BODY_YAW_ACCEL_RAD_S2: f64 = 12.0;
const PLAYER_ACCEL_JERK_LIMIT_YPS3: f64 = 34.0;
// --- Locomotion commitment (movement momentum / anti-jitter) ---------------------
// A decision is instant, but a body has inertia: a player cannot commit to a sprint
// one tick, drop to a run the next, sprint again, run again. Effort and travel
// heading therefore carry a short commitment — once a player settles into an effort
// tier (or a travel heading) they hold it for a minimum dwell before changing it.
// This is the locomotion analogue of the body-yaw angular-acceleration cap above.
//
// Once a gait effort tier is entered it is held at least this long before changing —
// in EITHER direction — so effort cannot oscillate tick-to-tick ("sprint, run,
// sprint, run"). Two things bypass the lock, because they are decisive acts a real
// player performs without hesitation: pulling up to a full STOP (you can always brake
// to a halt), and an EMERGENCY (an explosive reaction to a threat / a flat-out
// recovery sprint). Note the dwell only bites when a gait was changed within the last
// dwell window: a player who has held a gait a while (the common case) reacts to a
// new decision immediately; only rapid successive changes are damped. ~0.2 s.
const GAIT_COMMIT_SECONDS: f64 = 0.20;
// A committed travel heading must be held at least this long before it may be
// REVERSED (turned more sharply than the threshold below). Gentle steering — bending
// a run, tracking a moving target, lateral adjustments — is always free; only a hard
// change of direction (a cut-back) carries this commitment. ~0.1 s.
const HEADING_REVERSAL_COMMIT_SECONDS: f64 = 0.10;
// How sharp a heading change counts as a genuine "change of direction" (and is thus
// gated by the dwell above): a turn of more than 90° off the committed heading, i.e.
// the new heading has a non-positive projection onto the old one. Below 90° the
// player is steering/correcting, not reversing, and is never locked.
const HEADING_REVERSAL_COS_THRESHOLD: f64 = 0.0; // cos(90°)
                                                 // Human-scale mass bounds (lbs) the physics smoke report holds players within.
const PLAYER_MIN_WEIGHT_POUNDS: f64 = 90.0;
const PLAYER_MAX_WEIGHT_POUNDS: f64 = 320.0;
// Soft bias pulling the ball-carrier's body toward forward so it doesn't twirl to
// face every cut/carry-out (z-axis spin for no reason). A nudge, not a clamp: a
// genuine shield/turn still dominates; this just tilts the resting facing forward.
const CARRIER_FORWARD_FACING_NUDGE: f64 = 0.55;
// As the ball orbits the carrier, the carrier turns to FOLLOW it (you keep the ball
// in front of your body) ~all of the time — this is how strongly the carrier's
// resting facing tracks the ball's current bearing. The yaw-rate cap and dizziness
// model then bound how fast/far they can keep swivelling.
const CARRIER_BALL_FACING_FOLLOW: f64 = 0.82;
// Hysteresis deadband on the CARRIER's committed action-facing bucket: keep the
// current heading unless the new movement intent points more than ~60° away from
// it (dot < cos60° = 0.5). Buckets are 45° apart, so this suppresses flip-flopping
// between two adjacent buckets every tick while still letting a genuine cut/turn
// (≥~70°) re-commit. Stops the decision layer from churning the target heading.
const CARRIER_FACING_COMMIT_DOT: f64 = 0.5;
const COMFORT_YAW_RATE_RAD_S: f64 = 2.8; // below this, turning is free of dizziness
const DIZZINESS_GAIN_PER_RAD: f64 = 0.22; // accrual per rad/s over comfort, per sec
const DIZZINESS_RECOVERY_PER_SECOND: f64 = 0.60;
const DIZZINESS_MAX: f64 = 1.2;
const DIZZINESS_CONTROL_PENALTY: f64 = 0.30; // control-radius loss at max dizziness
const DIZZINESS_REWARD_PENALTY_POINTS: f64 = 2.2; // per unit dizziness, per second
                                                  // A disoriented carrier (too much swivelling in a short window) is easier to
                                                  // dispossess: scales the steal probability up by this much per unit dizziness.
const DIZZINESS_DISPOSSESSION_RISK: f64 = 0.55;
const YAW_ENERGY_FATIGUE_PER_RAD: f64 = 0.0006; // energy cost of rotating (per radian turned)
                                                // Sustained, contiguous high-urgency involvement near the ball is tiring. Scaled
                                                // to the same all-match budget as the anaerobic gait rates (see `fatigue_delta`):
                                                // the 12yd ball radius catches many players, so a high rate here would wall the
                                                // whole midfield within seconds.
const BALL_INVOLVEMENT_FATIGUE_PER_SECOND: f64 = 0.005;
const BALL_INVOLVEMENT_RADIUS_YARDS: f64 = 12.0;
const ENERGY_ECONOMY_LOOKAHEAD_SECONDS: f64 = 10.0;
const ENERGY_ECONOMY_LOW_VALUE_MOVEMENT_YARDS: f64 = 16.0;
const ENERGY_ECONOMY_REFERENCE_MOVEMENT_YARDS: f64 = 42.0;
const ENERGY_ECONOMY_FAST_SPEED_YPS: f64 = 4.0;
const ENERGY_ECONOMY_REWARD_PENALTY_POINTS: f64 = 0.06;
const ENERGY_ECONOMY_MARL_TEAM_PENALTY_POINTS: f64 = ENERGY_ECONOMY_REWARD_PENALTY_POINTS;
// Default symmetric bound for the (gated) MAPPO team-component clamp — about a shot's reward
// magnitude, so dense per-tick differentials pass through but a sparse single-team event spike is
// capped. See `dd_soccer_enable_marl_team_component_clamp` / `soccer_marl_team_component`.
const MARL_TEAM_COMPONENT_CLAMP_POINTS_DEFAULT: f64 = 12.0;
// A whole-team urgency wave: roughly six minutes rising/spent and six minutes recovering.
const ENERGY_RHYTHM_PERIOD_SECONDS: f64 = 12.0 * 60.0;
// Two-tier energy: `fatigue` is the slow aerobic drain; `anaerobic_load` is the
// fast burst reserve spent by sprints/accelerations and recovered over ~tens of
// seconds. Effort (committing energy to win a contest) is rewarded; coasting in
// a high-urgency moment near the ball is penalized — energy is the constraint.
const ANAEROBIC_SPRINT_LOAD_PER_SECOND: f64 = 0.085;
const ANAEROBIC_ACCEL_LOAD_PER_YPS2: f64 = 0.0024;
const ANAEROBIC_RECOVERY_PER_SECOND: f64 = 0.022;
// ---------------------------------------------------------------------------
// Power-duration ceiling (critical-power / W′ model).
//
// Exercise physiology puts a hard-ish upper bound on metabolic power as a
// function of effort duration: short bursts draw on a finite anaerobic reserve
// (W′), but anything sustained collapses onto the *critical power* (CP) — the
// highest output the aerobic engine can hold for "basically all match". We
// ground the abstract two-tier energy above (`fatigue`, `anaerobic_load`) in
// this curve so neither aerobic nor anaerobic ability is unbounded:
//
//   * Each tick we estimate metabolic power demand (W) from mass, speed and
//     acceleration (running cost + the dearer cost of changing speed).
//   * Demand ABOVE CP drains W′ (the sprint battery); demand BELOW CP recharges
//     it, fastest at rest and tapering as demand climbs toward CP.
//   * `anaerobic_load` IS the W′ depletion fraction (0 = full battery, 1 = empty).
//   * When the battery empties, the burst-speed ceiling drops off a cliff — a
//     gassed player physically cannot conjure another sprint until W′ recovers.
//   * Sustained supra-CP work also bleeds a little into the slow aerobic
