const ANAEROBIC_CEILING_KNEE: f64 = 0.72; // depletion fraction where the cliff begins
const ANAEROBIC_CEILING_CLIFF_DROP: f64 = 0.32;
const ANAEROBIC_CEILING_FLOOR: f64 = 0.52; // a fully-gassed player can still jog
