const PACING_MAX_THROTTLE: f64 = 0.30; // at most ~30% slower to save energy
const PACING_FLOOR: f64 = 0.62;
const EFFORT_REWARD_POINTS: f64 = 2.6;
const LAZINESS_PENALTY_POINTS: f64 = 2.6;
