const OPEN_LANE_DRIBBLE_SPRINT_PRESSURE: f64 = 0.60;
const OPEN_LANE_DRIBBLE_SPRINT_TRACK_YPS: f64 = 4.5;
// Decision (MDP/POMDP) appetite: a solid option (it keeps the ball AND creates a pass), lifted by
