const OPEN_LANE_DRIBBLE_BASE_APPETITE: f64 = 0.62;
const OPEN_LANE_DRIBBLE_MAX_APPETITE: f64 = 1.20;
const OPEN_LANE_DRIBBLE_UPFIELD_APPETITE_BONUS: f64 = 0.40;
