// Center-backs must remain the last line: penalize a central defender for every
// yard they advance ahead of their wing-backs, amplified when the ball is in the
// attacking part of the field (so they stay the deepest two ~95% of the time).
// (center-back-ahead-of-wingback penalty/yard folded into tunables().reward — env/PG-overridable)
const NEAR_GOAL_NO_SHOT_PENALTY_POINTS: f64 = 5.0;
const EXCESSIVE_HOLD_PENALTY_POINTS: f64 = 2.10;
const STALE_DRIBBLE_STEAL_EXTRA_PENALTY_POINTS: f64 = 5.25;
const NON_ELITE_DRIBBLE_HOLD_SKILL_CUTOFF: f64 = 0.90;
const NON_ELITE_DRIBBLE_HOLD_BASE_SECONDS: f64 = 2.35;
const ELITE_DRIBBLE_HOLD_BASE_SECONDS: f64 = 4.8;
// Two complementary slow-holder mechanisms, kept together (both are wired into live code):
//
// (1) Stationary-hold SURCHARGE on the excessive-hold penalty. A carrier who holds while
// STANDING STILL or WALKING (rather than driving it forward) is a passing failure — with open
// outlets it must release NOW. The excessive-hold penalty is multiplied by up to this factor for
// a dead-stationary (or back-pedalling) holder, ramping down to 1× once the carrier is jogging
// forward. Dribbling forward at pace is untouched. The cutoff is the FORWARD speed (yards/sec
// toward the opponent goal) at/above which the carry counts as "driving forward": ~3.5 yps sits
// just above a walk (~2.7 yps) and at a slow jog, so walking/standing is fully surcharged while a
// genuine forward jog/run/sprint pays nothing extra. (see `stationary_hold_penalty_multiplier`)
const STATIONARY_HOLD_PENALTY_MAX_MULT: f64 = 10.0;
const STATIONARY_HOLD_FORWARD_JOG_YPS: f64 = 3.5;
// (2) Slow-holder RELEASE rule: a standing/walking carrier with an open 5-15yd forward pass
// should move the ball now. Dribbling forward stays exempt via ball-forward velocity relief; this
// only punishes static/walking possession. Where (1) surcharges the *hold* by gait, (2) rewards
// *releasing* to a good forward option — the two reinforce the same "don't stand on the ball"
// directive from opposite ends and are both consumed live (see the slow-holder-release scorer).
const SLOW_HOLDER_RELEASE_PASS_MIN_YARDS: f64 = 5.0;
const SLOW_HOLDER_RELEASE_PASS_IDEAL_MAX_YARDS: f64 = 15.0;
const SLOW_HOLDER_RELEASE_PASS_TAPER_YARDS: f64 = 5.0;
const SLOW_HOLDER_RELEASE_MAX_SPEED_YPS: f64 = 1.65;
const SLOW_HOLDER_FORWARD_PROGRESS_RELIEF_YPS: f64 = 2.25;
const SLOW_HOLDER_RELEASE_START_SECONDS: f64 = 0.20;
const SLOW_HOLDER_RELEASE_FULL_SECONDS: f64 = 0.95;
const SLOW_HOLDER_RELEASE_MIN_OPTION_QUALITY: f64 = 0.34;
const SLOW_HOLDER_HOLD_PENALTY_MULTIPLIER: f64 = 10.0;
// When a teammate is genuinely open AHEAD of the ball, prefer the pass over driving
// into traffic ("pass even if a player is open ahead"). Scales pass scores up and the
// dribble proclivity down; collapses to no-effect when there is no open forward outlet.
const OPEN_FORWARD_OUTLET_PASS_BIAS_GAIN: f64 = 0.46;
const OPEN_FORWARD_OUTLET_DRIBBLE_DAMP: f64 = 0.22;
// Dwell-on-the-ball release: the longer a player carries — even unpressured — the more
// a pass/shot should win out over continuing to dribble. Grace before it starts, then a
// linear ramp. Mild so a player in acres of space can still carry, but it compounds with
// the open-forward-outlet bias so a dwelling carrier with an open option releases.
const DRIBBLE_DWELL_GRACE_SECONDS: f64 = 2.1;
const DRIBBLE_DWELL_RAMP_SECONDS: f64 = 3.0;
const DRIBBLE_DWELL_DRIBBLE_DAMP: f64 = 0.28;
const DRIBBLE_DWELL_RELEASE_LIFT: f64 = 0.22;
// Human-scale decision cadence: at 15Hz, tick indexes 0, 3, 7 are legal
// commitments (1st, 4th, 8th ticks). This keeps players from changing strategy
// faster than reaction/mental processing speed while still allowing genuine
// reflex branches elsewhere in the player logic.
const PLAYER_DECISION_COMMITMENT_SHORT_WINDOW_TICKS: u64 = 3;
const PLAYER_DECISION_COMMITMENT_MAX_IN_SHORT_WINDOW: usize = 1;
const PLAYER_DECISION_COMMITMENT_LONG_WINDOW_TICKS: u64 = 7;
const PLAYER_DECISION_COMMITMENT_MAX_IN_LONG_WINDOW: usize = 2;
// Anti-spasm: a holder commits to one dribble move-kind (and its touch) for this window
// instead of re-evaluating a fresh cut/feint/swivel every single tick. Without it the ball
// jerks in a new direction each frame (the "spasm" look). ~0.45s is long enough to read as
// one deliberate touch but short enough to still react. Stateless: the state-scored touch
// is quantized to this window, so a committed move is stable across the window's ticks.
const DRIBBLE_COMMIT_WINDOW_TICKS: u64 = secs_to_ticks(0.45);
// Rate-of-change-of-pressure ("d(pressure)/dt") signal. A nearest opponent closing at this
// speed (a hard sprint straight at the holder) saturates the rising signal; it only counts
// while that opponent is within the engagement radius (a distant chaser must not spike it).
const PRESSURE_RISING_REF_CLOSING_YPS: f64 = 6.0;
const PRESSURE_RISING_ENGAGE_YARDS: f64 = 12.0;
// Reference closing ACCELERATION (yards/sec^2) that saturates the dynamic pressure term —
// a hard burst onto you. Used by the granular pressure composite (location+velocity+accel).
const GRANULAR_PRESSURE_REF_ACCEL_YPS2: f64 = 12.0;
// The holder's "release sooner" pressure is a SMOOTH, anticipatory ramp (no hard
// cutoff): under mounting pressure the comfortable on-ball window eases down from the
// skill-based base toward this soft floor (never clamped to a cliff), and the urge to
// release begins rising while there is still time, so MEDIUM pressure already nudges an
// earlier release and the carrier can pick a GOOD ball instead of dwelling to a hard
// limit and being forced into a bad last-second pass. SPAN sets how gradually the ramp
// saturates once the comfortable window is spent.
const EXCESSIVE_HOLD_SOFT_FLOOR_SECONDS: f64 = 0.5;
const EXCESSIVE_HOLD_RAMP_SPAN_SECONDS: f64 = 3.0;
// Point 4: keep the carrier ~1.5-2yd off opponents in open play (dribbling straight
// into a defender is a needless turnover); relax to a tight buffer in the final
// third, where taking a man on is worth the risk.
const DRIBBLE_OPEN_PLAY_MIN_FORWARD_SPACE_YARDS: f64 = 2.0;
const DRIBBLE_FINAL_THIRD_YARDS_TO_GOAL: f64 = 36.0;
/// Minimum (proximity/closing) pressure for the CROWDED won-ball escape floor to fire. Below it the
/// freshly-won carrier is in traffic and should accelerate AWAY into the open lane instead of
/// settling into a shield. Sits just under the forward-drive block's pressure cutoff so the calm
/// `tunables().fresh_possession_escape` floor and the crowded escape floor stay complementary.
const WON_BALL_PRESSURE_ESCAPE_MIN_PRESSURE: f64 = 0.45;
// "There's an open man — play it." When the learned policy proposes a dribble
// but a teammate is this open with at least this expected completion, release
// the ball to them rather than carrying on into traffic. Closes the hole where
// the learned policy dribbles straight past an obviously open advanced outlet.
const OPEN_OUTLET_RELEASE_OPENNESS: f64 = 0.55;
const OPEN_OUTLET_RELEASE_COMPLETION: f64 = 0.62;
// Under the genuine pressure that reaches the elite-dribbler hold exemption, even an
// elite carrier with forward room yields the ball to a clearly-open ADVANCED outlet
// rather than carrying into the tackle. Lower than the pressure-independent
// `OPEN_OUTLET_RELEASE_OPENNESS` (0.55) on purpose: we only get here when the carrier
// is already under real pressure, where moving the ball to an open forward runner
// beats dribbling on. Closes the "elite ignored an open pass and dribbled into a
// turnover" hole. The elite only yields when ALSO genuinely about to be
// dispossessed (below) — in moderate pressure he keeps the carry, which is the
// whole point of the exemption.
const ELITE_HOLD_OPEN_FORWARD_OUTLET_OPENNESS: f64 = 0.46;
// The elite-carry exemption is only overridden when the carrier is genuinely about
// to lose the ball. Above this immediate-dispossession risk, carrying on with an
// open forward outlet is a likely giveaway, so the elite yields the pass.
const ELITE_HOLD_YIELD_DISPOSSESSION_RISK: f64 = 0.5;
// A learned-policy pass is only executed if SOMETHING about it is viable — either
// a real completion estimate or an open receiver. When BOTH are below these floors
// the "pass" is a hoof at nobody (the giveaways seen live: aerial-pass at
// completion 0.0 / openness 0.0 straight to an opponent). Below the floor we
// decline the learned pass and defer to the heuristic possession scorer (which
// has the gift-pass floor and shield/clear logic) instead of gifting possession.
const LEARNED_PASS_MIN_COMPLETION: f64 = 0.30;
const LEARNED_PASS_MIN_OPENNESS: f64 = 0.30;
// An aerial ball with interception risk above this is a hoof into a defender —
// veto it regardless of receiver openness (openness ≠ lane is clear).
const LEARNED_PASS_MAX_INTERCEPTION_RISK: f64 = 0.45;
// "Calm down and pass" damp on flashy evade moves (feint / side-step / swivel) when an
// unpressured holder has a clean pass on. DAMP is the max fraction shaved off; FLOOR keeps
// a legal evade from ever being fully zeroed (it can still fire if it's truly the best).
const CALM_PASS_FOCUS_DAMP: f64 = 0.55;
const CALM_PASS_FOCUS_FLOOR: f64 = 0.45;
// Passing into a crowd gets the ball turned over even when the direct lane reads clear,
// because the receiver is swarmed the instant it arrives. Count OPPONENTS within this
// radius of the prospective reception point and tax expected completion per body, down to
// a floor — a strong deterrent against feeding a congested area.
const PASS_RECEPTION_CONGESTION_RADIUS_YARDS: f64 = 4.0;
const PASS_RECEPTION_CONGESTION_PENALTY_PER_OPPONENT: f64 = 0.20;
const PASS_RECEPTION_CONGESTION_FLOOR: f64 = 0.28;
// A receiver this tightly marked is not merely "a little less open": under pressure,
// playing into that player's feet is often the same failure mode as passing directly to
// the opponent. Keep this below the broader congestion radius so ordinary contested
// final-third passes still exist.
const TIGHT_MAN_MARK_RECEIVER_RADIUS_YARDS: f64 = 3.35;
const TIGHT_MAN_MARK_RECEIVER_HARD_RADIUS_YARDS: f64 = 2.55;
const TIGHT_MAN_MARK_PASSER_PRESSURE: f64 = 0.58;
const TIGHT_MAN_MARK_COMPLETION_DAMP: f64 = 0.72;
const TIGHT_MAN_MARK_SCORE_PENALTY: f64 = 7.5;
// A ground pass is only allowed if the nearest opponent's time to the reception point is at
// least this fraction of the ball's time to it — i.e. the receiver/ball wins the race. Just
// under 1.0 because the opponent-arrival estimate assumes a perfect sprint (no reaction
// delay) and the receiver is also contesting the point.
const PASS_RECEPTION_OPPONENT_TIME_MARGIN: f64 = 0.95;
// Release-time safety net: if endpoint noise/MPC lead would aim a floor pass this much
// closer to an opponent than the intended teammate, pull it back toward the teammate/lead.
const PASS_RELEASE_OPPONENT_AIM_BUFFER_YARDS: f64 = 0.35;
// Hopeless-pass veto (`pass_reception_loses_to_opponent`): the nearest opponent must beat the
// intended receiver to the reception point by at least this margin for the release to count as a
// straight giveaway. Keeps a 50/50 ball the receiver can contest from tripping the veto.
const PASS_RECEPTION_LOSES_RECEIVER_MARGIN_YARDS: f64 = 1.5;
// Hopeless-pass veto (completion model): at release, a chosen pass whose `expected_completion`
// (the same `pass_target_quality_for_snapshot` model the option scorer / decision-trace uses) is
// below this floor is aborted — the carrier keeps the ball rather than gift a near-certain
// interception. Set well below the ~0.69 median of completed passes so only the clearly-doomed
// ball (a covered receiver / blocked lane the model rates <25%) is vetoed, leaving brave threaded
// passes alone. Tune via A/B against giveaway-rate vs completion-rate.
const HOPELESS_PASS_COMPLETION_FLOOR: f64 = 0.15;
// Selection-time counterpart to the release guard: a led floor-pass point that is
// materially nearer an opponent than the teammate is a likely direct giveaway.
const PASS_DIRECT_OPPONENT_AIM_HARD_VETO_MARGIN_YARDS: f64 = 2.0;
const PASS_DIRECT_OPPONENT_AIM_RELEASE_CORRECTION_RISK: f64 = 0.58;
const PASS_DIRECT_OPPONENT_AIM_NOISE_CORRECTION_MARGIN: f64 = 0.08;
const PASS_DIRECT_OPPONENT_AIM_SCORE_PENALTY: f64 = 12.0;
// HARD veto magnitude: when a candidate pass point sits clearly closer to an opponent than to the
// intended receiver (`pass_point_directly_favors_opponent`), it is a direct giveaway — sink the
// candidate by this much so it can never outrank holding or a safe outlet.
const PASS_DIRECT_OPPONENT_AIM_HARD_VETO_PENALTY: f64 = 1000.0;
// "Reception conceded to an opponent" hard veto. The aim-point veto above only fires when
// an opponent is strictly CLOSER to the aim than the intended receiver, so it misses two
// real giveaways: (a) the ball played near an opponent's FEET (the receiver is marginally
// closer, so the aim-point test stays silent), and (b) the ball played to a teammate who
// is tightly MAN-MARKED — the marker doesn't beat the receiver to the ball, he dispossesses
// the instant it arrives. Both are turnovers. A defender within `AT_FEET` of the reception
// point that can physically REACH the arriving ball is always a concession (case a); a
// marker within `MARK_RADIUS` is a concession only when the passer is genuinely pressured
// (case b) — which leaves a brave pass to a half-open man, and a contested final-third
// reception to an OPEN receiver, to the soft congestion penalty rather than hard-vetoing
// them. The reach check (lane-arrival + sprint reach) keeps a slow/distant marker, or a
// ball driven past too fast to be cut out, from tripping it.
const PASS_RECEPTION_CONCEDE_MARK_RADIUS_YARDS: f64 = 2.25;
const PASS_RECEPTION_CONCEDE_AT_FEET_RADIUS_YARDS: f64 = 1.25;
// Perception gate for the man-marked concede veto (POMDP: ~240° FOV, no rear vision,
// confidence decaying as the head turns — see `player_position_confidence_for_point`). A
// passer is only expected to AVOID feeding a marked man he can actually perceive; a marker
// arriving on the blindside (low confidence) is a realistic loss, not a vetoable decision.
// The ball-to-an-opponent's-feet case is NOT gated by this — playing it straight to the
// opposition is a gross error regardless of where the passer is looking.
const PASS_CONCEDE_PERCEPTION_MIN_CONFIDENCE: f64 = 0.42;
// Inter-tick sweep horizons (in ticks) for the concede reach model: a pass may resolve in
// 1, 2, 4, or 4+ ticks, so sample the ball's flight at these multiples of `dt` (each capped
// at the ball's arrival time) and project each opponent forward with its own momentum. Keeps
// the single-horizon reach as a strict superset so the static unit tests stay byte-identical.
const PASS_CONCEDE_SWEEP_TICK_HORIZONS: [f64; 4] = [1.0, 2.0, 4.0, 8.0];

fn direct_opponent_aim_score_penalty(risk: f64) -> f64 {
    let risk = risk.clamp(0.0, 1.0);
    let emergency_penalty = if risk >= PASS_DIRECT_OPPONENT_AIM_RELEASE_CORRECTION_RISK {
        PASS_DIRECT_OPPONENT_AIM_SCORE_PENALTY * 3.0
    } else {
        0.0
    };
    PASS_DIRECT_OPPONENT_AIM_SCORE_PENALTY * (risk + risk * risk) + emergency_penalty
}
// Pass-vs-hold under pressure: a pinned carrier's CONTESTED pass (low expected completion) has its
// pass score damped by `heat * (1 - completion) * this` so it loses to shield/hold/dribble rather
// than being forced into traffic (the turnover the user hates). Calm play and a genuinely open pass
// are untouched (heat or contested ≈ 0). Gated `DD_SOCCER_DISABLE_PRESSURED_PASS_DAMP`.
const PRESSURED_CONTESTED_PASS_DAMP: f64 = 0.40;
// A BACKWARD ball (aim point this far behind the passer along the attack direction)
// is only safe to a CLEARLY OPEN teammate — recycling backwards into coverage hands
// the ball back toward the opponent. A backward pass whose receiver has an opponent
// within `BACKWARD_PASS_COVERED_RADIUS_YARDS` is vetoed (the holder keeps / shields /
// clears it instead).
const BACKWARD_PASS_MIN_FORWARD_YARDS: f64 = 1.0;
// ~openness 0.2 on the (distance-2.5)/7.5 openness curve: a backward ball is only safe
// to a teammate with at least this much space from the nearest opponent.
const BACKWARD_PASS_COVERED_RADIUS_YARDS: f64 = 4.0;
// A short backward drop (≤5yd) keeps the ball safe and recyclable; a LONG backward pass
// (>5yd) concedes territory and should be a last resort. The escalating per-yard demerit for
// the long retreat itself lives in `long_backward_pass_penalty` (LONG_BACKWARD_PASS_*); this
// cap additionally replaces the (8yd-optimal) length-PREFERENCE bonus for backward balls with
// a SHORT-favouring curve (`backward_pass_length_preference`) so a 3-5yd drop isn't treated as
// "sub-optimal length" relative to a longer backward ball.
const BACKWARD_PASS_SHORT_MAX_YARDS: f64 = 5.0;
// Backward pass-length preference fades from full (at the 5yd short cap) to zero over this
// many additional yards.
const BACKWARD_PASS_LENGTH_FADE_BAND_YARDS: f64 = 18.0;
// Tactical anti-recycle rule ("men behind the ball"), from the attacking team's perspective
// while in possession. If FEWER than this many opposing players are goal-side of the ball
// (between the ball and the goal we are attacking) the opponent has committed numbers forward —
// a settled back four + keeper is exactly 5 — so a long backward recycle needlessly relieves
// that committed press and hands back the territory they have vacated.
const BACKWARD_RECYCLE_OPP_BEHIND_COUNT: usize = 5;
// In that situation a backward pass may travel at most this far (a short reset to a supporting
// player is still fine); a longer backward ball is vetoed …
const BACKWARD_RECYCLE_MAX_BACKWARD_YARDS: f64 = 3.0;
// … UNLESS there are fewer than this many attacking players ahead of the ball, i.e. there is no
// real forward outlet — then a backward ball is the only safe option and the restriction lifts.
const BACKWARD_RECYCLE_MIN_FORWARD_ATTACKERS: usize = 2;
// The constant forward "lead the runner into space" bias tapers to zero over this much space
// remaining to the attacking goal line, so a receiver near the box isn't led past the byline.
const RECEPTION_FORWARD_BIAS_TAPER_YARDS: f64 = 28.0;
// Keep an anticipated reception point at least this far in front of the goal line — a pass
// can't be received past the byline.
const RECEPTION_BYLINE_MARGIN_YARDS: f64 = 1.5;
// When a pass has no resolved short target, look for an OPEN advanced teammate (striker /
// midfielder) this far ahead and play a purposeful forward ball there instead of a fixed
// blind hoof. Sweet-spot ~30yd.
const PASS_FORWARD_OUTLET_MIN_YARDS: f64 = 10.0;
const PASS_FORWARD_OUTLET_MAX_YARDS: f64 = 42.0;
const PASS_FORWARD_OUTLET_BAND_CENTER_YARDS: f64 = 24.0;
// Keep the aim point comfortably inside the pitch so the long ball isn't over-hit out of
// play (touchline / byline margins, robust to launch scatter).
const PASS_FORWARD_OUTLET_TOUCHLINE_MARGIN_YARDS: f64 = 5.0;
const PASS_FORWARD_OUTLET_BYLINE_MARGIN_YARDS: f64 = 7.0;
const LONG_AERIAL_BOUNDS_MIN_DISTANCE_YARDS: f64 = 24.0;
const LONG_AERIAL_BOUNDS_REFERENCE_DISTANCE_YARDS: f64 = 46.0;
const LONG_AERIAL_BOUNDS_SAFE_TOUCHLINE_MARGIN_YARDS: f64 =
    PASS_FORWARD_OUTLET_TOUCHLINE_MARGIN_YARDS;
const LONG_AERIAL_BOUNDS_SAFE_BYLINE_MARGIN_YARDS: f64 = PASS_FORWARD_OUTLET_BYLINE_MARGIN_YARDS;
const LONG_AERIAL_BOUNDS_REFERENCE_MARGIN_YARDS: f64 = 8.0;
const LONG_AERIAL_BOUNDS_COMPLETION_GATE_STRENGTH: f64 = 0.72;
const LONG_AERIAL_BOUNDS_SCORE_PENALTY: f64 = 6.4;
const LONG_AERIAL_OUT_OF_PLAY_PASSER_PENALTY_POINTS: f64 = 5.6;
// A no-target forward ball is only played to a teammate who is genuinely open (nearest opponent
// far) and down a reasonably clear lane — never straight to a marked man / into a blocked lane.
const FORWARD_OUTLET_MIN_RECEIVER_OPENNESS: f64 = 0.38;
const FORWARD_OUTLET_LANE_HALF_WIDTH_YARDS: f64 = 2.0;
// A pass with NO resolved receiver ("to nobody in particular") is only a legitimate ball into
// space — a deliberate forward delivery for runners to chase — never a square/short giveaway.
