const PASS_TO_NOBODY_MAX_CONE_DEGREES: f64 = 70.0;
const PASS_TO_NOBODY_MIN_YARDS: f64 = 25.0;
// Playing out from your OWN penalty box under pressure. A defender on the ball in the box with
