const OWN_BOX_PRESSURE_OPP_RADIUS_YARDS: f64 = 3.0;
// Passes shorter than this from the pressured box are penalised (1-2yd give-aways).
const OWN_BOX_MIN_SAFE_PASS_YARDS: f64 = 3.0;
const OWN_BOX_SHORT_PASS_PENALTY: f64 = 2.6;
// A target within this of a touchline counts as "to the flank" — the preferred out-ball; the
// wider it is, the bigger the reward.
const OWN_BOX_FLANK_WIDTH_YARDS: f64 = 18.0;
const OWN_BOX_FLANK_REWARD: f64 = 2.4;
// A pass that crosses the centre in front of your own goal (square across the goal face) is
