// the final third and ramps back to the normal requirement over this band just OUTSIDE the
// line, so the relaxation eases in through the middle third instead of switching on abruptly.
const FINAL_THIRD_FORWARD_RACE_RELAX_BAND_YARDS: f64 = 14.0;
// Weight of the optimal-pass-length tiebreaker. The single peak is 8yd; shorter taps
// and 12yd+ balls are useful, but no longer share the "optimal" score.
const PASS_LENGTH_PREFERENCE_WEIGHT: f64 = 0.5;
const PASS_LENGTH_OPTIMAL_YARDS: f64 = 8.0;
const PASS_LENGTH_FADEOUT_YARDS: f64 = 24.0;
// Ideal-pass-length target: a ~15yd ball is the ideal length (progresses the play, still
// reliably completed and within a good player's field of vision, which already extends to
// 28-56yd). When `DD_SOCCER_ENABLE_IDEAL_PASS_LENGTH_15YD` is on, the optimal-length peak
// shifts from 8yd to 15yd (fade-out stretched proportionally) so the engine prefers a
// meaningful 15yd progression over a short square pass.
const IDEAL_PASS_LENGTH_OPTIMAL_YARDS: f64 = 15.0;
const IDEAL_PASS_LENGTH_FADEOUT_YARDS: f64 = 32.0;
const GROUND_LATERAL_PASS_PENALTY: f64 = 1.85;
const AERIAL_LATERAL_PASS_PENALTY: f64 = 1.20;
// Build-up short-pass discouragement. OUTSIDE the final attacking third, sub-4yd passes are
// dangerous busy-work that neither progresses nor relieves — longer, progressive balls are
// prioritised. This penalty applies regardless of pressure (unlike the pressure-gated
// `POINTLESS_SHORT_PASS_PENALTY`) and is fully lifted in the final third, where short
// combination play around the box is valuable. Scaled by how far under 4yd the pass is.
const SHORT_PASS_BUILDUP_MAX_YARDS: f64 = 4.0;
const SHORT_PASS_BUILDUP_PENALTY: f64 = 2.8;
// Own-half short-pass LIABILITY. In our own half a sub-4yd pass that is not a genuine
// pressure-escape is a liability, not build-up: it keeps the ball in front of our own
// goal for no progress and is the giveaway that turns into a chance against. Unlike
// `SHORT_PASS_BUILDUP_PENALTY` (which fades linearly to ~0 as the pass approaches 4yd, so
// a 3-4yd square ball is barely touched), this carries a strong FLOOR so every sub-4yd
// own-half pass is demoted hard enough that a 4+yd forward ball — or just keeping the
// dribble — outranks it. Stacks on top of the build-up penalty in the own half; the
// middle third keeps only the (mild) build-up penalty and the final third stays free.
// Waived for a real escape (receiver clearly less pressured than the holder). Gated by
// `DD_SOCCER_DISABLE_OWN_HALF_SHORT_PASS_LIABILITY` (default-on; off ⇒ byte-identical).
const OWN_HALF_SHORT_PASS_LIABILITY_MAX_YARDS: f64 = 4.0;
const OWN_HALF_SHORT_PASS_LIABILITY_PENALTY: f64 = 5.5;
// Fraction of the penalty applied even at the 4yd edge (no fade-to-zero): a 3.9yd square
