const OWN_HALF_SHORT_PASS_LIABILITY_FLOOR_FRACTION: f64 = 0.6;
// Layer 2 (decision): when the only floor pass on offer in our own half is short, damp the
// generic pass action so the carrier prefers to keep the dribble / hold rather than play it.
// `DAMP` is the max fraction shaved off `pass_score`; the cut scales with how short the ball
// is and eases for a wide-open receiver (a genuine out). `MIN_MULT` floors the multiplier so
// a short pass is demoted, never hard-vetoed (dribbling into trouble can still be worse).
const OWN_HALF_SHORT_PASS_DRIBBLE_DAMP: f64 = 0.78;
const OWN_HALF_SHORT_PASS_DRIBBLE_MIN_MULT: f64 = 0.22;
// Scoop (lofted dink over a close defender): a teammate this far away, open on all sides by
// this radius, with a defender within this distance of the direct lane.
const SCOOP_PASS_MIN_RANGE_YARDS: f64 = 5.0;
// A delicate chip can comfortably clear a close defender onto a mate up to ~12yd away (was
// 8.0, which — combined with the "open by 4yd" and "defender in the lane" gates below — made
// the joint window geometrically near-impossible, so the scoop never fired in play).
const SCOOP_PASS_MAX_RANGE_YARDS: f64 = 12.0;
// The chip drops into a pocket: the receiver only needs ~3yd of space, not 4 (a 4yd ring while
// a defender also sits in the lane is self-contradictory at these short ranges).
const SCOOP_PASS_RECEIVER_OPEN_RADIUS_YARDS: f64 = 3.0;
// A defender standing this far off the direct line still blocks a GROUND pass with their reach —
// which is exactly what we lift the ball over (was 1.8, too tight to catch real blockers).
const SCOOP_PASS_DEFENDER_LANE_RADIUS_YARDS: f64 = 2.4;
// Nearby pressure is a bonus, not a hard gate: the essential trigger is an otherwise-ideal
// teammate whose direct floor lane is blocked by an opponent. The receiver must sit within ±75°
// (a 150° cone) of the way the carrier is facing — a pressured player chips across their body
// more than a tight ±50° allowed.
const SCOOP_PASS_PASSER_CROWD_RADIUS_YARDS: f64 = 7.0;
const SCOOP_PASS_PASSER_MIN_CROWD: usize = 2;
const SCOOP_PASS_FACING_HALF_CONE_DEGREES: f64 = 75.0;
const GOALMOUTH_CARRY_REWARD_POINTS: f64 = 1.35;
const ENDLINE_DRIBBLE_TRAP_PENALTY_POINTS: f64 = 1.85;
// (low-pressure forced-pass penalty folded into tunables().reward — env/PG-overridable)
const DEFENSIVE_CLEAR_AND_HOLD_FIRST_SECONDS: f64 = 5.0;
const DEFENSIVE_CLEAR_AND_HOLD_SECOND_SECONDS: f64 = 10.0;
const DEFENSIVE_CLEAR_AND_HOLD_FIRST_REWARD_POINTS: f64 = 10.0;
const DEFENSIVE_CLEAR_AND_HOLD_SECOND_REWARD_POINTS: f64 = 20.0;
const DEFENSIVE_DISPOSSESSION_REWARD_POINTS: f64 = 10.0;
// Winning the ball inside EITHER 18-yard box is worth much more than a midfield steal: in our
// defensive box it snuffs a near-certain chance; in the attacking box the steal IS a chance. So
// the dispossession / 50-50 / loose-ball reward is multiplied by this when the ball is won inside
// a box — training defenders (and attackers) to attack the ball hard in both boxes rather than
// stand off. (User rule: steal rewards higher in the 18yd box, both offense and defense.)
const STEAL_IN_BOX_REWARD_MULTIPLIER: f64 = 2.5;
// While the back line is defending, train it mostly on LP/IPM position quality.
// Ball-winning stays positive, but no longer dominates the shape gradient.
const DEFENSIVE_POSITIONING_FOCUS_CHASE_REWARD_MULTIPLIER: f64 = 0.42;
const DEFENSIVE_POSITIONING_FOCUS_POSSESSION_REWARD_MULTIPLIER: f64 = 0.34;
const DEFENSIVE_POSITIONING_FOCUS_LP_REWARD_MULTIPLIER: f64 = 2.25;
// Losing the ball is a team failure, not just the dribbler's. When a defender wins
// the ball, blame the recent possession chain: the player dispossessed eats the
// largest share, and the previous one or two who built the move share the rest.
// Raised from 7.0: losing the ball is the single most-costly outcome short of conceding,
// so the learners weight retention (completing passes, shielding the dribble) above forcing
// a low-percentage forward ball. Combined with the softened back-pass penalties, this trains
// "keep the ball" over "gamble it forward".
const LOST_POSSESSION_CHAIN_PENALTY_POINTS: f64 = 10.0;
const LOST_POSSESSION_CHAIN_PENALTY_WEIGHTS: [f64; 3] = [0.55, 0.30, 0.15];
// --- Discounted turnover-chain blame (gated DD_SOCCER_ENABLE_TURNOVER_CHAIN_BLAME) ---
// A bad pass that is intercepted (`record_interception_reward`) penalizes the player who lost
// the ball in full, but the previous one/two passers who built the doomed move escape untouched.
// This blame term spreads a STEEPLY discounted share of the loser's OWN penalty back over those
// prior passers — so the build-up gets a small corrective gradient too, not just the final
// (often forced) touch. The discount is a fraction of the ball-loser's penalty by recency:
// index 0 is the ball-loser (100% — applied in full by the interception handler, so this array
// only documents it and the blame loop SKIPS it), index 1 the immediately-preceding passer
// (20%), index 2 the one before that (5%). Steeper than `LOST_POSSESSION_CHAIN_PENALTY_WEIGHTS`
// on purpose: blame should concentrate hard on the player who actually gave it away. Targeted
// per-player credit assignment, complementary to the net-Φ PBRS danger asymmetry and
// MARL/MAPPO's global team-reward share; off by default under test so the parity suite is
// byte-identical.
const TURNOVER_CHAIN_BLAME_DISCOUNTS: [f64; 3] = [1.0, 0.20, 0.05];
// Below this the discounted blame is dropped (negligible tail / sub-noise nudge).
const TURNOVER_CHAIN_BLAME_MIN_POINTS: f64 = 0.05;
const INTERCEPTED_PASS_BASE_PENALTY_MIN_POINTS: f64 = 6.0;
const INTERCEPTED_PASS_BASE_PENALTY_MAX_POINTS: f64 = 20.0;
const BACKWARD_INTERCEPTED_PASS_PENALTY_MULTIPLIER: f64 = 2.0;
// Bad-pass turnover blame is not a normalized pool: the passer gets the full
// chain penalty, then the prior two teammates get discounted echoes.
const BAD_PASS_CHAIN_PENALTY_MULTIPLIERS: [f64; 3] = [1.0, 0.20, 0.05];
// Beyond the immediate possession-chain penalty above, a turnover also retroactively
// penalizes the LOSING team's actions over the last ~5 seconds: every learning transition
// for that team in the window is re-queued with a recency-scaled negative reward (full at
// the turnover, ramping to zero at the window edge), so all gradient learners — tabular Q
// (`train_adversarial` + `policy.train`) and the neural value/critic models — nudge those
// state→action pairs down. 5 s = 75 ticks at dt = 1/15.
pub(crate) const TURNOVER_PENALTY_WINDOW_TICKS: u64 = 75;
const TURNOVER_WINDOW_PENALTY_POINTS: f64 = 4.5;
// Severity multipliers on the per-transition turnover penalty for dangerous giveaways
// (see `keeper_giveaway_severity`). A goalkeeper losing possession is the worst case —
// he is the last line — so it is scaled hardest; any giveaway deep in our own end ramps
// up toward the own goal line. Both default to making the giveaways the policy should
// fear materially costlier than a routine midfield turnover, without touching the benign
// case. Disable the whole weighting with `DD_SOCCER_DISABLE_KEEPER_GIVEAWAY_PENALTY`.
pub(crate) const KEEPER_GIVEAWAY_ROLE_MULT: f64 = 2.5;
pub(crate) const KEEPER_GIVEAWAY_DANGER_ZONE_MAX_MULT: f64 = 2.0;
// Bound the re-queued work per turnover (newest, most-blameworthy transitions first) so a
// flurry of turnovers can't back up the deferred-training queue.
const TURNOVER_PENALTY_MAX_TRANSITIONS: usize = 64;
const FAILED_DISPOSSESSION_PENALTY_POINTS: f64 = 2.0;
const WON_FIFTY_FIFTY_DUEL_REWARD_POINTS: f64 = DEFENSIVE_DISPOSSESSION_REWARD_POINTS;
const LOST_FIFTY_FIFTY_DUEL_PENALTY_POINTS: f64 = FAILED_DISPOSSESSION_PENALTY_POINTS;
// --- Wasted-energy penalty (off-ball running with no ball involvement) ------------
// A small, retroactive MDP/POMDP cost for locomotion energy a player spends in a tick
// that turns out to buy NO ball interaction over the following 10 s — i.e. pointless
// running. Mirrors the turnover-window mechanism: a tick-age-windowed history of recent
// transitions, each re-queued into `deferred_reward_transitions` with a tiny negative
// reward once its 10 s lookahead closes with no touch. Gated OFF by default
// (`DD_SOCCER_ENABLE_WASTED_ENERGY_PENALTY`); when off it is byte-identical and zero-cost.
// The complement, not the contradiction, of the near-ball effort reward
// (`EFFORT_REWARD_POINTS`), which only fires inside a high-urgency contest at the ball.
pub(crate) const WASTED_ENERGY_WINDOW_TICKS: u64 = secs_to_ticks(10.0);
// Only ticks above this locomotion cost are "moving a lot" — walking/standing is exempt,
// so a player is never taxed for economical positioning, only for hard off-ball running.
// ~70 J/tick at dt = 1/15 ≈ a sustained run for a ~75 kg player (a flat-out sprint is
// ~150 J/tick); below it the sample is never even retained.
const WASTED_ENERGY_MIN_JOULES_PER_TICK: f64 = 70.0;
// Normalises the spent joules to a ~unit ratio at a hard sprint, so the points below read
// as "per fully-wasted sprint tick".
const WASTED_ENERGY_REFERENCE_JOULES_PER_TICK: f64 = 145.0;
// Penalty points for one fully-wasted hard-sprint tick. Deliberately tiny: the policy is
// nudged off pointless running "to a small degree", not whipped off all movement.
const WASTED_ENERGY_PENALTY_POINTS: f64 = 0.02;
// Cap the energy ratio so a transient solver speed spike can't fabricate a large penalty.
const WASTED_ENERGY_PENALTY_RATIO_CLAMP: f64 = 1.5;
// Bound the windowed history (and thus the deferred re-train backlog) the same way the
// turnover window is bounded — newest samples evict the oldest past this many.
const WASTED_ENERGY_MAX_PENDING_SAMPLES: usize = 1024;
// --- Sustained-effort-no-outcome refinement -------------------------------------
// (`DD_SOCCER_ENABLE_SUSTAINED_EFFORT_NO_OUTCOME_PENALTY`) A stricter, team-aware variant
// of the wasted-energy penalty. A windowed sample is only RETAINED when the player was in a
// genuine SUSTAINED flat-out sprint (≥ SUSTAINED_EFFORT_SPEED_FRACTION of top speed, held for
// ≥ SUSTAINED_EFFORT_MIN_SECONDS and covering ≥ SUSTAINED_EFFORT_MIN_DISTANCE_YARDS), and that
// run only counts as "paid off" if the sprinter touched the ball OR the player's team produced
// a real positive outcome in the lookahead — winning the ball back, a shot, a goal, beating a
// defender on the dribble, or a 2+ forward-pass sequence (see
// `SoccerRewardEventKind::is_positive_team_outcome`). Otherwise the big effort bought nothing,
// so the run is docked ever so slightly (same tiny per-tick points as the base penalty). OFF
// ⇒ the joules-only / touch-only legacy behaviour, byte-identical & zero-cost.
// 98% of the player's top speed = a true flat-out sprint, not an honest run.
const SUSTAINED_EFFORT_SPEED_FRACTION: f64 = 0.98;
// Held this long before the sprint is "sustained" — a couple of seconds of all-out effort,
// not a single explosive step.
const SUSTAINED_EFFORT_MIN_SECONDS: f64 = 2.0;
// ...and covering this far — "really sprints a long way". ~18yd ≈ 2s at a top-end pace.
const SUSTAINED_EFFORT_MIN_DISTANCE_YARDS: f64 = 18.0;
// --- Far-from-ball off-ball energy conservation ---------------------------------
// (`DD_SOCCER_ENABLE_FAR_OFFBALL_ENERGY_CONSERVATION`) A player with no urgent reason to run
// who is well clear of the ball eases off to bank energy instead of drifting about at full
// pace. The output throttle ramps SMOOTHLY (smoothstep, no cliff) from no reduction at
// FAR_OFFBALL_CONSERVE_START_YARDS to a FAR_OFFBALL_CONSERVE_MAX_REDUCTION cut by
// FAR_OFFBALL_CONSERVE_FULL_YARDS. Every real movement cue is exempt (see
// `far_offball_conservation_factor`). OFF ⇒ byte-identical & zero-cost.
const FAR_OFFBALL_CONSERVE_START_YARDS: f64 = 40.0;
const FAR_OFFBALL_CONSERVE_FULL_YARDS: f64 = 60.0;
const FAR_OFFBALL_CONSERVE_MAX_REDUCTION: f64 = 0.20;
// --- Slide tackle (a committed, high-variance defensive challenge) ---------------
// A slide tackle is a LAST-DITCH lunge a defender throws at a ball-carrier who is
// moving too fast to be contained on foot. It reaches further than a standing
// challenge and wins the ball more often, but committing the body is all-or-nothing:
// MISS and the defender is flat on the grass, out of the play, for ~2 seconds while
// the attacker carries the ball past unchallenged.
//
// Reach band (yards): a slide extends the contact envelope beyond a standing tackle's
// (~1.85yd), but the defender must already be close enough to launch the lunge — you
// cannot slide a ball that is 4 yards away.
const SLIDE_TACKLE_MIN_REACH_YARDS: f64 = 1.0;
const SLIDE_TACKLE_MAX_REACH_YARDS: f64 = 2.9;
