const SAME_TEAM_PROXIMITY_BAND_LT6_YARDS: f64 = 6.0;
const SAME_TEAM_PROXIMITY_BAND_LT5_YARDS: f64 = 5.0;

/// Whether the hard same-team 4-yard separation floor (barrier + graduated penalty + MPC
/// keep-out) is active this process. Default-ON in production; opt-in under `#[cfg(test)]`
/// so the default test corpus stays byte-identical (set
/// `DD_SOCCER_ENABLE_SAME_TEAM_SEPARATION_FLOOR=1` to exercise it in a test).
pub(crate) fn dd_soccer_enable_same_team_separation_floor() -> bool {
    #[cfg(test)]
    {
        // Read fresh under test so a single process can A/B the gate per test.
        soccer_env_flag_enabled("DD_SOCCER_ENABLE_SAME_TEAM_SEPARATION_FLOOR")
    }
    #[cfg(not(test))]
    {
        use std::sync::OnceLock;
        static V: OnceLock<bool> = OnceLock::new();
        *V.get_or_init(|| gate_default_on("DD_SOCCER_ENABLE_SAME_TEAM_SEPARATION_FLOOR"))
    }
}

/// Graduated same-team proximity penalty as a fraction of
/// [`SAME_TEAM_PROXIMITY_PENALTY_POINTS`] for a realized nearest-teammate distance
/// (yards). Zero at/beyond the influence radius (8yd), linearly rising to 1.0 at the
/// 4yd floor ("small at 7, medium at 6, big at 5"), and rising further (up to 2.0) below
/// the floor ("huge inside 4"). Pure / RNG-free.
pub(crate) fn same_team_proximity_penalty_unit(distance_yards: f64) -> f64 {
    if !distance_yards.is_finite() {
        return 0.0;
    }
    let floor = SAME_TEAM_MIN_SEPARATION_YARDS;
    let influence = floor + SAME_TEAM_SEPARATION_INFLUENCE_YARDS;
    if distance_yards >= influence {
        return 0.0;
    }
    if distance_yards <= floor {
        // At/inside the floor the penalty is "huge" and keeps growing the tighter the
        // crowd, capped so a degenerate overlap can't produce an unbounded term.
        return (1.0 + (floor - distance_yards).max(0.0) / floor).min(2.0);
    }
    let t = (influence - distance_yards) / (influence - floor); // 0 at influence, 1 at floor
    t.clamp(0.0, 1.0)
}

/// Advance the three nested same-team proximity dwell timers by `dt` for the current
/// nearest-NON-EXEMPT teammate `distance` (yards). Each band accumulates while the pair is inside
/// its radius and resets to 0 the instant they are farther than it — so elapsed time carries
/// across tighter bands (never reset on the way in) but is forgiven once the pair genuinely
/// separates past that band. Pass `f64::INFINITY` when there is no eligible teammate (all reset).
/// Pure / RNG-free; the single source of truth for the grace-timer update so the live loop and
/// tests agree.
fn advance_same_team_proximity_dwell(
    dwell_lt7: &mut f64,
    dwell_lt6: &mut f64,
    dwell_lt5: &mut f64,
    distance: f64,
    dt: f64,
) {
    let step = |timer: &mut f64, band: f64| {
        if distance < band {
            *timer += dt;
        } else {
            *timer = 0.0;
        }
    };
    step(dwell_lt7, SAME_TEAM_PROXIMITY_BAND_LT7_YARDS);
    step(dwell_lt6, SAME_TEAM_PROXIMITY_BAND_LT6_YARDS);
    step(dwell_lt5, SAME_TEAM_PROXIMITY_BAND_LT5_YARDS);
}

/// True when the graduated same-team proximity penalty has passed its GRACE window and should
/// begin to accrue, given the player's three nested proximity dwell timers (seconds). The penalty
/// starts the instant ANY band's timer reaches that band's grace: 7yd/3s, 6yd/2s, 5yd/1s. Because
/// the bands nest (`lt5 ≤ lt6 ≤ lt7`), a slow drift-in trips the 7yd/3s timer while a fast dive
/// inside 5yd trips the 5yd/1s timer first — exactly the user's graduated-grace intent.
fn same_team_proximity_penalty_past_grace(dwell_lt7: f64, dwell_lt6: f64, dwell_lt5: f64) -> bool {
    dwell_lt7 >= SAME_TEAM_PROXIMITY_GRACE_LT7_SECONDS
        || dwell_lt6 >= SAME_TEAM_PROXIMITY_GRACE_LT6_SECONDS
        || dwell_lt5 >= SAME_TEAM_PROXIMITY_GRACE_LT5_SECONDS
}

/// Distance (yards) from the player `player_id` to its nearest same-team teammate in
/// `snapshot`, EXCLUDING any teammate for which the floor is waived because BOTH are inside
/// an 18-yard box. `None` when the player is missing / off-pitch or has no eligible
/// teammate. Feeds the graduated same-team proximity penalty.
pub(crate) fn nearest_same_team_distance_for_floor(
    snapshot: &WorldSnapshot,
    player_id: usize,
    team: Team,
) -> Option<f64> {
    let me = snapshot.players.iter().find(|p| p.id == player_id)?;
    let me_pos = me.position;
    if !me_pos.x.is_finite() || !me_pos.y.is_finite() {
        return None;
    }
    let me_in_box =
        soccer_point_in_either_penalty_area(me_pos, snapshot.field_width, snapshot.field_length);
    let mut nearest = f64::INFINITY;
    for other in snapshot.players.iter() {
        if other.id == player_id || other.team != team {
            continue;
        }
        if !other.position.x.is_finite() || !other.position.y.is_finite() {
            continue;
        }
        // Both-in-box exception: goalmouth congestion is legitimate.
        if me_in_box
            && soccer_point_in_either_penalty_area(
                other.position,
                snapshot.field_width,
                snapshot.field_length,
            )
        {
            continue;
        }
        nearest = nearest.min(me_pos.distance(other.position));
    }
    nearest.is_finite().then_some(nearest)
}

/// The same-team crowding penalty (a POSITIVE magnitude to SUBTRACT from reward) for `player`
/// on the `after` snapshot: gate + grace + 18yd-box exception + graduated distance curve, in one
/// place so the dense reward and the budget-exemption wrapper compute the identical value. Zero
/// when the gate is off, the grace window has not elapsed, or there is no eligible teammate.
/// Pure w.r.t. the two inputs; RNG-free. Reward/learning-only — never touches physics.
pub(crate) fn same_team_separation_reward_penalty(
    player: &PlayerAgent,
    after: &WorldSnapshot,
) -> f64 {
    if !dd_soccer_enable_same_team_separation_floor()
        || !same_team_proximity_penalty_past_grace(
            player.same_team_proximity_dwell_lt7_seconds,
            player.same_team_proximity_dwell_lt6_seconds,
            player.same_team_proximity_dwell_lt5_seconds,
        )
    {
        return 0.0;
    }
    match nearest_same_team_distance_for_floor(after, player.id, player.team) {
        Some(nearest) => {
            same_team_proximity_penalty_unit(nearest) * SAME_TEAM_PROXIMITY_PENALTY_POINTS
        }
        None => 0.0,
    }
}

// NOTE: an earlier design also damped a player's velocity to physically prevent crossing inside
// 4yd (a "hard floor"). That was removed on purpose: per the directive it is NOT a hard floor —
// closing inside 4yd is permitted, it just draws a strong/huge crowding penalty (the graduated
// reward term below) plus an MPC route cost. The 4yd line lives on only as the penalty's peak.

// The "hard" (tighter) overlap band of the legacy soft-spacing framework. Raised to 0.80 of the
// minimum-spacing radius so it lands at 4yd outside the box (5 * 0.80) — deliberately aligned
// with the new SAME_TEAM_MIN_SEPARATION_YARDS floor above so the legacy overlap policing and the
// new hard floor agree on the same 4yd line — and 2.4yd (3 * 0.80) under the both-in-box
// exception. Hard overlaps are policed sooner than merely-soft ones.
const TEAMMATE_SPACING_HARD_FRACTION: f64 = 0.80;
// Grace windows before a *sustained* overlap is flagged and one of the pair is
// nudged to move. Open-play bunching is tolerated longer at the edge of the
// 7-yard floor, then the window shrinks as the pair gets tighter.
const TEAMMATE_SPACING_GRACE_UNDER_SEVEN_SECONDS: f64 = 3.0;
const TEAMMATE_SPACING_GRACE_UNDER_SIX_SECONDS: f64 = 2.0;
const TEAMMATE_SPACING_GRACE_UNDER_FIVE_SECONDS: f64 = 1.0;
// A separated pair cools its overlap clock back down at this multiple of real
// time, so a single frame of separation does not instantly forgive a long camp,
// but genuine dispersal clears the flag quickly.
const TEAMMATE_SPACING_COOLDOWN_RATE: f64 = 1.5;
// NOTE(merge): the off-ball spacing nudge bias is defined once as
// `TEAMMATE_SPACING_NUDGE_BIAS` near the proximity-spacing constants above (0.75).
// A parallel branch proposed a gentler 0.14 ("small on purpose") for this same
// config field; both spacing systems read it via `config.spacing.nudge_bias`.
// Sustained-overlap pressure (the 0..1 learnable signal) saturates once a pair
// has camped this many seconds past its grace window.
const TEAMMATE_SPACING_PRESSURE_SATURATION_SECONDS: f64 = 2.5;
// Ideal *relative* role positions, so the team travels up and down the pitch as a
// cohesive unit. These are statistical-distance seeds (min enforced, ideal
// targeted) that shape the formation-LP anchors; the LP/learners refine them.
// Forward layering (measured along the team's attack direction). Goal-to-goal the
// team holds three staggered lines: the midfield AVERAGE sits 5-20yd ahead of the
// defensive AVERAGE, and the striker AVERAGE sits 3-20yd ahead of the midfield
// AVERAGE, with an IDEAL resting separation of 8yd for each step (raised 2026-06-18
// from 1-20 / 2-20, then refined to a 3-20 band around an 8yd ideal). The lines are
// eventually consistent — a ball-distance-scaled grace before the band is enforced —
// so a transient stagger while transitioning is fine, a sustained collapse is not. The
// IDEAL (the 8yd resting target the line settles at) is applied while OUT OF POSSESSION
// only: a compact, press-ready block that rides up off the line behind it. In our own
// possession we hold just the hard band so the attack can stretch (otherwise an 8+8
// stack would pull the forwards back onto the ball during our build-up).
const MID_AHEAD_OF_DEF_MIN_YARDS: f64 = 5.0;
const MID_AHEAD_OF_DEF_MAX_YARDS: f64 = 20.0;
const MID_AHEAD_OF_DEF_IDEAL_YARDS: f64 = 10.0;
const MID_AHEAD_OF_DEF_CONSISTENCY_TARGET_SECONDS: f64 = 3.0;
// MIDFIELD LINE MODEL (gated `DD_SOCCER_ENABLE_MIDFIELD_LINE_MODEL`): when on, the
// midfield forms an ACTUAL flat line (like the back four, but with no offside
// semantics) at a dynamic/learned depth, eased over a 5-second consistency window
// (longer than the back four's ~3s — the midfield is allowed to be looser).
// Fore-aft level band thickness for that flat line (±half this off the centre).
const MIDFIELD_LINE_LEVEL_BAND_YARDS: f64 = 3.0;
// The 5-second eventual-consistency window the midfield line eases onto its target
// over (vs `MID_AHEAD_OF_DEF_CONSISTENCY_TARGET_SECONDS` for the legacy band).
const MIDFIELD_LINE_MODEL_CONSISTENCY_SECONDS: f64 = 5.0;
const STRIKER_AHEAD_OF_MID_MIN_YARDS: f64 = 5.0;
const STRIKER_AHEAD_OF_MID_MAX_YARDS: f64 = 20.0;
// In possession the strikers are let off the leash to push forward and hold a high line —
// pinning the opponent's back four and offering an advanced outlet — instead of being
// dragged back onto the midfield band. They are still bounded (onside-capped elsewhere, and
// this keeps the line from drifting so far it disconnects), just far higher than the
// compact defending block. See `forward_line_band_adjusted_target`.
const STRIKER_AHEAD_OF_MID_MAX_IN_POSSESSION_YARDS: f64 = 32.0;
// The resting stagger ahead of midfield while defending — nudged up so the striker line
// presses from a higher starting point ("push forward more").
const STRIKER_AHEAD_OF_MID_IDEAL_YARDS: f64 = 13.0;
const STRIKER_AHEAD_OF_MID_CONSISTENCY_TARGET_SECONDS: f64 = 3.0;
// Wingback lateral (width) discipline by phase (off the ball, 3s eventual consistency):
// - DEFENDING: pinch IN toward centre, but only as far as the wider (closer-to-touchline) of
//   {the outermost opponent on that flank, the near edge of the 6-yard box} — never further,
//   so the wide channel / box corner stays protected.
// - IN POSSESSION: outside backs may push forward with the ball beyond the back-four line, but
//   only open laterally to the touchline when they are a playable short ground outlet.
// The 6-yard box (goal area) extends this far either side of each post.
const SIX_YARD_BOX_DEPTH_YARDS: f64 = 6.0;
const WINGBACK_WIDTH_CONSISTENCY_TARGET_SECONDS: f64 = 3.0;
const WINGBACK_ATTACK_TOUCHLINE_BUFFER_YARDS: f64 = 4.0;
const WINGBACK_ATTACK_NO_COVER_BUFFER_YARDS: f64 = 8.0;
const WINGBACK_ATTACK_COVER_BEHIND_BALL_MIN: usize = 2;
// When the ball is this many yards or more AHEAD of our back-four line average, a wide
// DEFENDER pushes up with the play but stops bombing out to the touchline to "open up":
// opening wide from behind an advanced ball only isolates him and vacates the flank he
// covers. He keeps his width only while he is still a live ground-pass outlet (below).
const WINGBACK_BALL_AHEAD_HOLD_WIDTH_YARDS: f64 = 10.0;
// The "live outlet" exception to the hold-width rule: a wide defender keeps opening wide
// even with the ball advanced when a ground pass could actually reach him — i.e. he is
// within this range of the ball with a clear (un-intercepted) lane.
const WINGBACK_GROUND_PASS_OUTLET_YARDS: f64 = 20.0;
const ROLE_LINE_CONSISTENCY_URGENCY_DEADBAND_YARDS: f64 = 0.5;
const ROLE_LINE_CONSISTENCY_URGENCY_FULL_ERROR_YARDS: f64 = 14.0;
// Ball-proximity-scaled "get into shape" grace, in ALL directions (fore-aft layering
// AND lateral spacing). The urgency to recover formation shape rises as the ball
// nears: a line gets ~1s of grace to become consistent when the ball is close (snap
// into shape) stretching to ~5s when the ball is far (drift back at leisure). Lerps
// the grace seconds across the yard band between NEAR and FAR. Replaces the fixed
// per-line consistency horizons in the formation stagger.
const BALL_PROXIMITY_GRACE_NEAR_SECONDS: f64 = 1.0;
const BALL_PROXIMITY_GRACE_FAR_SECONDS: f64 = 5.0;
const BALL_PROXIMITY_GRACE_NEAR_YARDS: f64 = 12.0;
const BALL_PROXIMITY_GRACE_FAR_YARDS: f64 = 45.0;

/// The shape-recovery grace (seconds) for a line whose mean position is
/// `distance_yards` from the ball: short (urgent) when close, long (relaxed) when far.
fn ball_proximity_grace_seconds(distance_yards: f64) -> f64 {
    let d = distance_yards.max(0.0);
    if d <= BALL_PROXIMITY_GRACE_NEAR_YARDS {
        BALL_PROXIMITY_GRACE_NEAR_SECONDS
    } else if d >= BALL_PROXIMITY_GRACE_FAR_YARDS {
        BALL_PROXIMITY_GRACE_FAR_SECONDS
    } else {
        let t = (d - BALL_PROXIMITY_GRACE_NEAR_YARDS)
            / (BALL_PROXIMITY_GRACE_FAR_YARDS - BALL_PROXIMITY_GRACE_NEAR_YARDS);
        BALL_PROXIMITY_GRACE_NEAR_SECONDS
            + t * (BALL_PROXIMITY_GRACE_FAR_SECONDS - BALL_PROXIMITY_GRACE_NEAR_SECONDS)
    }
}

fn role_layer_gap_band_error_yards(gap_yards: f64, min_yards: f64, max_yards: f64) -> f64 {
    if !gap_yards.is_finite() {
        0.0
    } else if gap_yards < min_yards {
        min_yards - gap_yards
    } else if gap_yards > max_yards {
        gap_yards - max_yards
    } else {
        0.0
    }
}

// Lateral spread within a line (adjacent players ordered by home-x): centre-backs
// and centre-back-to-wing-back, and the midfield line.
// Adjacent same-line lateral (x = sideline-to-sideline) spacing, held as a BAND:
// each neighbouring pair stays `MIN`..`MAX` yd apart, in static home-x order (so the
// back four reads LWB < LCB < RCB < RWB left-to-right and never reshuffles). The band
// is a group constraint distributed symmetrically across the line (no single player
// must move — the others can), and it is only EVENTUALLY consistent: the LP nudges the
// anchors back into band and MPC/locomotion carries the players there over ~seconds,
// so the line is momentarily perfect but constantly striving back into place.
// Counterparts in a line must HOLD their width, not bunch: the floor (`MIN`) keeps
// adjacent same-line players a real channel apart, and the back-line ceiling (`MAX`)
// is set near the formation's own home spacing (back four home gaps are ~17yd:
// LB 14 / LCB 31 / RCB 49 / RB 66) so the line stays spread across the pitch instead
// of being squeezed into a narrow central block. The line still compacts ball-side
// (the absolute anchors track the ball); this band only bounds the RELATIVE gap.
