const MPC_STEAL_STANDING_MIN_QP_ACCEL_FIT: f64 = 0.10;
const MPC_STEAL_SLIDE_MIN_QP_ACCEL_FIT: f64 = 0.06;
const MPC_STEAL_SUCCESS_MULTIPLIER_FLOOR: f64 = 0.42;
const MPC_STEAL_SUCCESS_MULTIPLIER_SPAN: f64 = 0.68;
