// behind a high line up the pitch is not a recovery emergency). The two nearest defenders + the
// keeper strive goalside; the 2nd man covers this far goalside of the ball; the keeper may
// sweep up to _GK_MAX_ADVANCE off its line. Pace (run vs sprint) follows the granular pressure
// from the chasing attacker (>= _SPRINT_PRESSURE → sprint).
const BALL_IN_BEHIND_MARGIN_YARDS: f64 = 2.0;
const BALL_IN_BEHIND_MAX_FROM_GOAL_YARDS: f64 = 55.0;
const IN_BEHIND_COVER_DISTANCE_YARDS: f64 = 6.0;
// The second man covering a ball played in behind stays at least this far goalside of the
// recovery point — even where the line band relaxes its minimum standoff near our own goal.
const IN_BEHIND_COVER_MIN_GOALSIDE_YARDS: f64 = 2.0;
const IN_BEHIND_SPRINT_PRESSURE: f64 = 0.45;
const IN_BEHIND_GK_MAX_ADVANCE_YARDS: f64 = 16.0;
/// Low-to-mid pressure ceiling for a backfield carrier to have enough time/space to pick out
/// a long pass. Above this, off-ball attackers should not assume the holder can deliver it.
const BACKFIELD_LONG_PASS_RUN_MAX_PRESSURE: f64 = 0.58;
/// A "backfield" long-pass setup can start in the own half or just past halfway; beyond this
/// margin, the existing attacking-third / through-ball cues own the behavior.
const BACKFIELD_LONG_PASS_RUN_MIDFIELD_MARGIN_YARDS: f64 = 8.0;
/// Minimum scored invite for attackers to treat a calm backfield carrier as a real long-pass cue.
const BACKFIELD_LONG_PASS_RUN_MIN_INVITE: f64 = 0.26;
/// When that cue exists, widen the staging band so strikers/attacking mids start the run even
/// before they are already parked on the defensive shoulder.
const BACKFIELD_LONG_PASS_RUN_STAGING_TOLERANCE_YARDS: f64 = 34.0;
/// MAPPO/POMDP option floor for "run-in-behind" under the backfield long-pass cue.
const BACKFIELD_LONG_PASS_RUN_OPTION_FLOOR_BASE: f64 = 0.38;
const BACKFIELD_LONG_PASS_RUN_OPTION_FLOOR_LIFT: f64 = 0.34;
/// A midfielder/striker carrier counts as "driving at goal" — the cue for other attackers
/// to make urgent sprinting runs in behind — when, beyond running/sprinting gait, they have
/// covered at least this many yards goalward in the last second (a deliberate forward carry,
/// not a static or sideways hold).
const ATTACKING_CARRIER_DRIVE_PROGRESS_YARDS: f64 = 2.0;
// Forward attacking momentum: the cue that pulls MORE off-ball attackers into forward
// runs (and lifts them to a sprint) — the ball is being driven forward at the carrier's
// feet, or a long / aerial ball is in flight toward our attack.
/// Minimum goalward progress over the recent window for a running carrier to count as
/// "driving the ball forward at his feet".
const FORWARD_MOMENTUM_CARRY_PROGRESS_YARDS: f64 = 1.0;
/// A pass at least this long counts as a long ball worth chasing forward in numbers.
const FORWARD_MOMENTUM_LONG_BALL_YARDS: f64 = 22.0;
/// ...and it must travel at least this far goalward (not a square/back long ball).
const FORWARD_MOMENTUM_LONG_BALL_FORWARD_YARDS: f64 = 12.0;
// Forward intent: an off-ball attacker on the attack keeps threatening the goal — he does
// not drift backward unless we lose the ball. While we hold possession with the ball at or
// past halfway, an offensive-minded mid/forward's support point may not move them net
// backward beyond a small tolerance.
/// The ball must be at least this far into our attacking half (measured from halfway) for
/// the no-retreat floor to apply — in our own half, dropping to receive is still valid.
const ATTACK_FORWARD_INTENT_MIN_BALL_DEPTH_YARDS: f64 = 0.0;
/// At most this much backward give is allowed (preserves micro-shape adjustments).
const ATTACK_FORWARD_INTENT_BACKWARD_TOLERANCE_YARDS: f64 = 1.5;
/// A teammate carrying the ball counts as unpressured — a cue to support forward in
/// numbers — while the nearest opponent is at least this far from him, i.e. no one is
