// attempt it (and the actual outcome) is emergent.
/// The man-to-beat must sit within this many yards GOALSIDE/ahead of the carrier. Widened
/// from 7.0: a one-two is the answer whenever a defender has stepped to engage, which starts
/// a little further out than a tight 7yd — the narrow trigger zone was the main reason the
/// combination so rarely became available.
const WALL_PASS_MAN_TO_BEAT_AHEAD_YARDS: f64 = 9.0;
/// ...and within this lateral band of the carrier (he is in front, not out wide).
const WALL_PASS_MAN_TO_BEAT_LATERAL_YARDS: f64 = 6.0;
/// ...and no further than this from the carrier (close enough that beating him matters).
const WALL_PASS_MAN_TO_BEAT_RANGE_YARDS: f64 = 9.0;
/// The burst run breaks into the channel this far to the side of the carrier.
const WALL_PASS_RUN_CHANNEL_YARDS: f64 = 5.0;
/// ...and this far forward (before the onside cap clamps it back behind the line).
const WALL_PASS_RUN_FORWARD_YARDS: f64 = 12.0;
/// The run must net at least this much ground toward goal to be worth attempting. Lowered
/// from 6.0: near the box the onside cap legitimately clamps the burst short, so demanding a
/// full 6yd net gain vetoed otherwise-good one-twos in the final third.
const WALL_PASS_MIN_RUN_GAIN_YARDS: f64 = 4.0;
/// Distance band carrier→wall for the lay-off (too short = no combination, too long =
/// not a one-two).
const WALL_PASS_GIVE_MIN_YARDS: f64 = 5.0;
const WALL_PASS_GIVE_MAX_YARDS: f64 = 16.0;
/// The wall must not sit deeper than this behind the carrier (negative = slightly behind
/// is allowed — a give back to a supporting runner — but not a backward escape ball). This
/// is a loose definitional floor on "what is a wall partner", NOT the backward-distance
/// risk control: a one-two can legitimately include a short backpass, and longer/through-
/// traffic backward legs are SOFT-penalised in the quality score (see
/// `WALL_PASS_BACKWARD_RISK_*`), not hard-capped.
const WALL_PASS_GIVE_MIN_FORWARD_YARDS: f64 = -5.0;
/// Soft risk demerit (in quality units, 0..1) for the BACKWARD component of a one-two leg.
/// A short backpass is part of the combination, but the further back a leg is played — and
/// the more opponents sit in its corridor — the riskier it is, so quality is reduced by
/// exponential backward-distance risk units, capped. This demotes (but never vetoes) a long
/// backward give/return, especially through traffic.
const WALL_PASS_BACKWARD_RISK_PER_UNIT_PER_BODY: f64 = 0.16;
const WALL_PASS_BACKWARD_RISK_MAX: f64 = 0.6;
/// Corridor half-width used to test the give and return lanes are clean.
const WALL_PASS_LANE_RADIUS_YARDS: f64 = 1.6;
/// The wall needs at least this much space to turn the ball around first-time.
const WALL_PASS_PARTNER_MIN_SPACE_YARDS: f64 = 2.0;
/// A one-two commitment lapses this many seconds after the give if the return never comes.
/// The window covers the give travelling to the wall, the wall's first touch, and the led
/// return travelling back to the runner. A shorter window expired too many combinations while
/// the ball was still moving, so the apparent wall pass rarely completed as a give-and-go.
const WALL_PASS_RUN_TTL_SECONDS: f64 = 3.6;
/// Base appetite to attempt an available wall pass (scaled by quality, pressure, skill,
/// goal proximity, and the active maneuver). A give-and-go is genuinely tried, not rare — the
/// one-two is a primary attacking route, so when a clean combination is on it is taken often.
// Base wall-pass appetite kept at the lower 0.46 (not theirs' 0.54): in the merged build the raw
// appetite stacks BOTH the give-and-go ambition multiplier AND the pass-and-move context lift, so
// the lower base keeps the combined appetite from running away.
const WALL_PASS_BASE_APPETITE: f64 = 0.46;
/// Moderate, default-ON live-frequency bump applied under [`give_and_go_ambition_enabled`]: how
/// much further to widen the man-to-beat trigger zone (so a one-two is *available* more often —
/// every quality/onside/lane check still applies, this only widens availability) and how much to
/// multiply the carrier's raw wall-pass appetite (so an available good one-two competes with
/// carries/through-balls instead of being out-scored). Off (kill switch
/// `DD_SOCCER_ENABLE_GIVE_AND_GO_AMBITION=0`) ⇒ none of this applies.
const GIVE_AND_GO_AMBITION_AHEAD_WIDEN_YARDS: f64 = 3.0;
const GIVE_AND_GO_AMBITION_LATERAL_WIDEN_YARDS: f64 = 1.5;
const GIVE_AND_GO_AMBITION_RANGE_WIDEN_YARDS: f64 = 2.0;
const GIVE_AND_GO_AMBITION_PARTNER_SPACE_EASE_YARDS: f64 = 0.5;
const GIVE_AND_GO_AMBITION_APPETITE_MULTIPLIER: f64 = 1.4;
/// Lifted appetite clamp ceiling under the ambition bump (vs. the baseline 0.92), so a strong
/// available one-two is not capped below decisive options.
const GIVE_AND_GO_AMBITION_APPETITE_CEILING: f64 = 0.95;
/// When the team's active attacking maneuver IS a give-and-go / one-two, the carrier is
/// looking to combine — lift the appetite hard.
const WALL_PASS_STRATEGY_APPETITE_BOOST: f64 = 2.35;
/// And make that strategy a real commitment once the geometry exists, not just a
/// background nudge that loses most ticks to generic pass/dribble rolls.
const WALL_PASS_STRATEGY_MIN_APPETITE: f64 = 0.86;
/// Minimum quality for a named one-two strategy to commit immediately.
const WALL_PASS_STRATEGY_COMMIT_MIN_QUALITY: f64 = 0.18;
/// Live option-score lift from the existing pass-and-move POMDP features when
/// a real one-two plan is available.
const WALL_PASS_PASS_AND_MOVE_CONTEXT_APPETITE_BOOST: f64 = 0.42;
/// Goal-proximity reference: appetite to combine ramps up inside this distance to goal.
const WALL_PASS_GOAL_PROXIMITY_REFERENCE_YARDS: f64 = 40.0;
/// Firm-but-controlled power for the lay-off give (skill adds a little).
const WALL_PASS_GIVE_POWER: f64 = 0.58;
// Hold-and-summon support ("wait-for-support" / delay-before-pass). A calm, unpressured
// carrier with NO good forward outlet yet may deliberately keep the ball (shield/slow) and
// *signal* teammates to improve their position — either push forward into space
