// Warm-start invariant: this cap MUST exceed the serialized size of a fully
// auto-pruned policy (see SOCCER_LIVE_POLICY_AUTOPRUNE_* below) — otherwise the
// policy we prune-to on shutdown can never be autoloaded on the next start, and
// warm-start silently dies ("autoload policy skipped: … above … byte limit").
// The old 64 MiB cap was ~18x smaller than the ~1.2 GiB a max-pruned policy
// serializes to (fat grid-state JSON keys), so warm-start was structurally
// impossible. Sized to comfortably clear the lowered autoprune ceiling.
const DEFAULT_LIVE_POLICY_AUTOLOAD_MAX_BYTES: u64 = 768 * 1024 * 1024;
const MIN_POLICY_AUTOSAVE_INTERVAL_TICKS: u64 = 50;
const DEFAULT_POLICY_AUTOSAVE_INTERVAL_TICKS: u64 = 600;
const DEFAULT_POLICY_HISTORY_RECORD_LIMIT: usize = 24;
const MAX_POLICY_HISTORY_RECORD_LIMIT: usize = 500;
const SOCCER_POLICY_PROBABILITY_STATE_LIMIT: usize = 48;
const SOCCER_POLICY_PROBABILITY_ACTION_LIMIT: usize = 6;
const DEFAULT_MOMENT_HISTORY_RECORD_LIMIT: usize = 24;
const MAX_MOMENT_HISTORY_RECORD_LIMIT: usize = 500;
const LIVE_EPISODE_HISTORY_LIMIT: usize = 12;
// Bounds the per-match in-memory tracking-frame buffer for long-running live
// sessions (mode 2 is no-rewind, so unbounded history is never needed). The
// limit dwarfs the SOCCER_MOMENT_WINDOW_SECONDS lookback (≤ ~100 ticks at the
// configured dt), so moment detection is unaffected; only the oldest frames of
// a single very long continuous match are evicted FIFO.
const SOCCER_LIVE_TRACKING_FRAMES_LIMIT: usize = 18_000;
// The Q-policy probability summary (UI only) scans the whole, growing Q-table;
// refresh it at most this often instead of every step so per-step time stays flat.
const SOCCER_LIVE_POLICY_SUMMARY_REFRESH_TICKS: u64 = secs_to_ticks(9.0);
// Hard cap on entries scanned for the (UI-only) policy-probability summary, so it can't
// become a multi-hundred-ms hitch on the live step as the Q-table grows.
const SOCCER_POLICY_PROBABILITY_SUMMARY_SCAN_CAP: usize = 2500;
// The relaxed/facing tabular lookups iterate index buckets that grow with the (large) Q-table,
// so a single per-player learned-policy query was costing 5-24ms and climbing as a match ran —
// the tabular Q dominating the per-tick budget. The NEURAL net is the primary decision driver
// now; the tabular value is only a weak prior, so bound how many keys any one lookup examines.
// Beyond this it stops scanning (the best of a large bounded sample is plenty for a prior), so
// the lookup is O(1)-bounded regardless of table size.
const SOCCER_LEARNED_LOOKUP_SCAN_CAP: usize = 48;
/// How many tabular candidates the retrieval prior re-ranks over. Small: the
/// prior nudges among the policy's already-plausible actions, not the long tail.
const SOCCER_RETRIEVAL_PRIOR_RERANK_LIMIT: usize = 12;
// Long-match memory hygiene: when a team Q-table grows past the high-water mark,
// slough the least-visited entries back down to the low-water mark (keeping the
// most-visited, best-learned states). Hysteresis avoids pruning every step.
// Bounded so a fully-pruned policy serializes to well under
// DEFAULT_LIVE_POLICY_AUTOLOAD_MAX_BYTES (the warm-start invariant). The old
// 220k/360k ceilings serialized to ~1.2 GiB — never autoloadable. Because the
// tabular state-dim is so high that visits/entry ≈ 1.0 (audited live: 22.1k
// visits across 21.5k entries after 2k ticks), the dropped entries are
// single-visit noise that never converges anyway; pruning keeps the
// most-visited (best-learned) states. The NEURAL critic is the real learner.
const SOCCER_LIVE_POLICY_AUTOPRUNE_HIGH_ENTRIES: usize = 60_000;
const SOCCER_LIVE_POLICY_AUTOPRUNE_LOW_ENTRIES: usize = 45_000;
// Target-preference entries grow far faster than action entries (a grid per
// state-action), so they need their own ceiling — without it the policy bloats to
// gigabytes while the action-entry trigger stays silent.
const SOCCER_LIVE_POLICY_AUTOPRUNE_TARGET_HIGH_ENTRIES: usize = 70_000;
const SOCCER_LIVE_POLICY_AUTOPRUNE_TARGET_LOW_ENTRIES: usize = 55_000;
// Capped in-memory ring of human coaching-feedback notes captured at paused frames.
const SOCCER_LIVE_COACHING_FEEDBACK_LIMIT: usize = 1_000;
const SOCCER_MOMENT_WINDOW_SECONDS: f64 = 10.0;
const SOCCER_MOMENT_HISTORY_LIMIT: usize = 24;
const SOCCER_MOMENT_ACTION_LIMIT: usize = 12;
const SOCCER_MOMENT_FEATURE_FRAME_SAMPLES: usize = 8;
const SOCCER_MOMENT_EMBEDDER_VERSION: &str = "soccer-moment-local-v5";
const ADVERSARIAL_EMBEDDING_SIGNAL_REFRESH_TICKS: u64 = 5;
const SOCCER_MOMENT_ROLE_ALIGNED_PLAYERS: usize = 22;
