#[derive(Clone, Copy, Debug, Default, PartialEq, Serialize, Deserialize)]
pub struct Vec2 {
    pub x: f64,
    pub y: f64,
}

impl Vec2 {
    pub fn new(x: f64, y: f64) -> Self {
        Vec2 { x, y }
    }

    pub fn zero() -> Self {
        Vec2 { x: 0.0, y: 0.0 }
    }

    pub fn len(self) -> f64 {
        (self.x * self.x + self.y * self.y).sqrt()
    }

    pub fn distance(self, other: Vec2) -> f64 {
        (self - other).len()
    }

    pub fn dot(self, other: Vec2) -> f64 {
        self.x * other.x + self.y * other.y
    }

    pub fn normalized(self) -> Vec2 {
        let l = self.len();
        if !l.is_finite() || l <= 1e-9 {
            Vec2::zero()
        } else {
            self / l
        }
    }

    pub fn clamp_to_pitch(self, field_width: f64, field_length: f64) -> Vec2 {
        let (field_width, field_length) = sane_pitch_dimensions(field_width, field_length);
        Vec2 {
            x: if self.x.is_finite() {
                self.x.clamp(0.0, field_width)
            } else {
                field_width * 0.5
            },
            y: if self.y.is_finite() {
                self.y.clamp(0.0, field_length)
            } else {
                field_length * 0.5
            },
        }
    }
}

fn sane_pitch_dimensions(field_width: f64, field_length: f64) -> (f64, f64) {
    let width = if field_width.is_finite() && field_width > 0.0 {
        field_width
    } else {
        DEFAULT_FIELD_WIDTH_YARDS
    };
    let length = if field_length.is_finite() && field_length > 0.0 {
        field_length
    } else {
        DEFAULT_FIELD_LENGTH_YARDS
    };
    (width, length)
}

fn finite_pitch_point(point: Vec2, field_width: f64, field_length: f64, fallback: Vec2) -> Vec2 {
    let (width, length) = sane_pitch_dimensions(field_width, field_length);
    let fallback = Vec2::new(
        if fallback.x.is_finite() {
            fallback.x.clamp(0.0, width)
        } else {
            width * 0.5
        },
        if fallback.y.is_finite() {
            fallback.y.clamp(0.0, length)
        } else {
            length * 0.5
        },
    );
    Vec2::new(
        if point.x.is_finite() {
            point.x
        } else {
            fallback.x
        },
        if point.y.is_finite() {
            point.y
        } else {
            fallback.y
        },
    )
    .clamp_to_pitch(width, length)
}

fn finite_vec2(vector: Vec2, fallback: Vec2) -> Vec2 {
    let fallback = Vec2::new(
        if fallback.x.is_finite() {
            fallback.x
        } else {
            0.0
        },
        if fallback.y.is_finite() {
            fallback.y
        } else {
            0.0
        },
    );
    Vec2::new(
        if vector.x.is_finite() {
            vector.x
        } else {
            fallback.x
        },
        if vector.y.is_finite() {
            vector.y
        } else {
            fallback.y
        },
    )
}

fn limit_vec2_len(vector: Vec2, max_len: f64) -> Vec2 {
    let vector = finite_vec2(vector, Vec2::zero());
    if !max_len.is_finite() || max_len <= 1e-9 {
        Vec2::zero()
    } else if vector.len() > max_len {
        vector.normalized() * max_len
    } else {
        vector
    }
}

/// Floor on the integration step. Stops an absurdly tiny `dt` (whether from a future
/// client-supplied config or a bug) from making `total_ticks()` astronomically large —
/// `duration / dt` would otherwise approach `u64::MAX` and turn `run_simulation` into an
/// effectively unbounded loop. No ceiling: a large `dt` only yields FEWER ticks (the engine
/// supports coarse single-step integration, e.g. dt=2.0 in goal-line-overshoot tests).
const MIN_SANE_DT_SECONDS: f64 = 1.0 / 240.0;
/// Upper bound on a sanitized match duration (24 h) — far beyond any real fixture; exists
/// only to keep `total_ticks()` bounded against a pathological/huge `duration_seconds`.
const MAX_MATCH_DURATION_SECONDS: f64 = 24.0 * 60.0 * 60.0;
/// Runtime period structure bound. The CLI training paths already accept at most
/// 8 halves; keep the library sanitizer aligned so malformed configs cannot turn
/// per-tick period-boundary checks into an unbounded loop.
const MAX_MATCH_HALVES: u8 = 8;
const MAX_MATCH_PERIODS: usize = 8;

fn sane_dt_seconds(dt_seconds: f64, fallback: f64) -> f64 {
    let chosen = if dt_seconds.is_finite() && dt_seconds > 0.0 {
        dt_seconds
    } else if fallback.is_finite() && fallback > 0.0 {
        fallback
    } else {
        DEFAULT_DT_SECONDS
    };
    chosen.max(MIN_SANE_DT_SECONDS)
}

fn loose_ball_unclaimed_pressure_from_elapsed(elapsed_seconds: f64) -> f64 {
    if !elapsed_seconds.is_finite() {
        return 0.0;
    }
    let over_grace = elapsed_seconds - LOOSE_BALL_MAX_UNCONTESTED_SECONDS;
    if over_grace <= 0.0 {
        return 0.0;
    }
    (over_grace / LOOSE_BALL_UNCLAIMED_PRESSURE_FULL_SECONDS.max(1e-6)).clamp(0.0, 1.0)
}

fn bounded_tick_count(duration_seconds: f64, dt_seconds: f64) -> u64 {
    if !duration_seconds.is_finite()
        || !dt_seconds.is_finite()
        || duration_seconds <= 0.0
        || dt_seconds <= 0.0
    {
        return 0;
    }
    let seconds = duration_seconds.min(MAX_MATCH_DURATION_SECONDS);
    let dt = dt_seconds.max(MIN_SANE_DT_SECONDS);
    let max_ticks = MAX_MATCH_DURATION_SECONDS / MIN_SANE_DT_SECONDS;
    (seconds / dt).round().clamp(0.0, max_ticks) as u64
}

impl std::ops::Add for Vec2 {
    type Output = Vec2;

    fn add(self, rhs: Vec2) -> Self::Output {
        Vec2::new(self.x + rhs.x, self.y + rhs.y)
    }
}

impl std::ops::AddAssign for Vec2 {
    fn add_assign(&mut self, rhs: Vec2) {
        self.x += rhs.x;
        self.y += rhs.y;
    }
}

impl std::ops::Sub for Vec2 {
    type Output = Vec2;

    fn sub(self, rhs: Vec2) -> Self::Output {
        Vec2::new(self.x - rhs.x, self.y - rhs.y)
    }
}

impl std::ops::Mul<f64> for Vec2 {
    type Output = Vec2;

    fn mul(self, rhs: f64) -> Self::Output {
        Vec2::new(self.x * rhs, self.y * rhs)
    }
}

impl std::ops::Div<f64> for Vec2 {
    type Output = Vec2;

    fn div(self, rhs: f64) -> Self::Output {
        Vec2::new(self.x / rhs, self.y / rhs)
    }
}

#[derive(Clone, Copy, Debug, PartialEq, Eq, Hash, Serialize, Deserialize)]
pub enum Team {
    Home,
    Away,
}

impl Team {
    pub fn other(self) -> Team {
        match self {
            Team::Home => Team::Away,
            Team::Away => Team::Home,
        }
    }

    pub fn attack_dir(self) -> f64 {
        match self {
            Team::Home => 1.0,
            Team::Away => -1.0,
        }
    }

    pub fn goal_y(self, field_length: f64) -> f64 {
        match self {
            Team::Home => field_length,
            Team::Away => 0.0,
        }
    }

    pub fn label(self) -> &'static str {
        match self {
            Team::Home => "Home",
            Team::Away => "Away",
        }
    }
}

fn throw_in_no_offside_defender_line_y(
    defending_team: Team,
    ball_y: f64,
    field_length: f64,
) -> f64 {
    let length = field_length.max(1.0);
    let own_goal_y = defending_team.other().goal_y(length);
    let raw = ball_y - defending_team.attack_dir() * THROW_IN_NO_OFFSIDE_DEFENDER_DEPTH_YARDS;
    match defending_team {
        Team::Home => raw.clamp(own_goal_y, length),
        Team::Away => raw.clamp(0.0, own_goal_y),
    }
}

fn throw_in_no_offside_defender_tracking_target(
    defending_team: Team,
    ball_y: f64,
    runner_target: Vec2,
    field_width: f64,
    field_length: f64,
) -> Option<Vec2> {
    if !runner_target.x.is_finite() || !runner_target.y.is_finite() {
        return None;
    }
    let (width, length) = sane_pitch_dimensions(field_width, field_length);
    let attacking_dir = defending_team.other().attack_dir();
    let runner_depth = (runner_target.y - ball_y) * attacking_dir;
    if !runner_depth.is_finite() || runner_depth < 0.0 {
        return None;
    }
    let tracking_depth = (runner_depth + THROW_IN_RUNNER_TRACK_GOAL_SIDE_YARDS).clamp(
        THROW_IN_NO_OFFSIDE_DEFENDER_DEPTH_YARDS,
        THROW_IN_RUNNER_TRACK_DEPTH_YARDS,
    );
    let y = (ball_y + attacking_dir * tracking_depth).clamp(0.0, length);
    Some(Vec2::new(runner_target.x.clamp(0.0, width), y))
}

#[derive(Clone, Copy, Debug, PartialEq, Eq, Hash, Serialize, Deserialize)]
pub enum PlayerRole {
    Goalkeeper,
    Defender,
    Midfielder,
    Forward,
}

fn vertical_lane_index(x: f64, field_width: f64) -> usize {
    let width = field_width.max(1.0);
    let lane_width = width / VERTICAL_LANE_COUNT as f64;
    ((x.clamp(0.0, width - f64::EPSILON) / lane_width).floor() as usize)
        .min(VERTICAL_LANE_COUNT.saturating_sub(1))
}

fn vertical_lane_bounds(lane: usize, field_width: f64) -> (f64, f64) {
    let width = field_width.max(1.0);
    let lane_width = width / VERTICAL_LANE_COUNT as f64;
    let lane = lane.min(VERTICAL_LANE_COUNT.saturating_sub(1));
    (lane as f64 * lane_width, (lane + 1) as f64 * lane_width)
}

/// In-possession lane radius (in lanes) a wide defender (wing-back) is held to when
/// [`wingback_lane_stickiness_enabled`] is on — tighter than the shared defender band so the
/// wing-back keeps its wide channel and does not drift infield. Defense already holds a ±1
/// band, so only the looser in-possession band is tightened.
const WINGBACK_LANE_RADIUS_POSSESSION: isize = 1;

/// Whether a defender whose HOME x sits in the outer ~28% of the pitch is a wide defender
/// (wing-back). Mirrors [`WorldSnapshot::is_wide_defender`]'s threshold but as a free helper
/// usable from the lane math (which only has `home_x` / `field_width`).
fn is_wide_defender_home_x(home_x: f64, field_width: f64) -> bool {
    field_width > 0.0
        && home_x.is_finite()
        && (home_x < field_width * 0.28 || home_x > field_width * 0.72)
}

fn role_vertical_lane_range(
    role: PlayerRole,
    home_x: f64,
    field_width: f64,
    in_possession: bool,
) -> (usize, usize) {
    let lane_tunables = &tunables().lane_affinity;
    let home_lane = vertical_lane_index(home_x, field_width);
    let clamp_lane = |lane: isize| -> usize {
        lane.clamp(0, VERTICAL_LANE_COUNT.saturating_sub(1) as isize) as usize
    };
    let centered_band = |radius: isize| -> (usize, usize) {
        (
            clamp_lane(home_lane as isize - radius),
            clamp_lane(home_lane as isize + radius),
        )
    };
    // Wing-back lane stickiness: a wide defender in possession holds a narrower lane band so it
    // keeps its width instead of drifting infield. Off ⇒ the shared defender band.
    let wide_defender = wingback_lane_stickiness_enabled()
        && role == PlayerRole::Defender
        && is_wide_defender_home_x(home_x, field_width);
    match role {
        PlayerRole::Defender if in_possession && wide_defender => {
            centered_band(WINGBACK_LANE_RADIUS_POSSESSION)
        }
        // Forwards keep their freedom to drift and make runs, but not across the
        // WHOLE pitch: a generous home-centred band (±3 of 12 lanes ≈ ±20yd) lets a
        // striker work the centre and both half-spaces while still stopping it from
        // wandering onto the opposite touchline and emptying the team's width. Forwards
        // still carry a lighter lane prior than the back/midfield lines, but the learned
        // and MPC shape scorers now see that prior instead of treating forwards as
        // lane-less.
        PlayerRole::Forward => centered_band(lane_tunables.forward_lane_radius as isize),
        PlayerRole::Defender if in_possession => {
            centered_band(lane_tunables.defender_lane_radius_possession as isize)
        }
        PlayerRole::Defender => centered_band(lane_tunables.defender_lane_radius_defense as isize),
        PlayerRole::Midfielder if in_possession => {
            centered_band(lane_tunables.midfielder_lane_radius_possession as isize)
        }
        PlayerRole::Midfielder => {
            centered_band(lane_tunables.midfielder_lane_radius_defense as isize)
        }
        PlayerRole::Goalkeeper => (home_lane, home_lane),
    }
}

fn role_vertical_lane_commitment(role: PlayerRole, in_possession: bool) -> f64 {
    let lane_tunables = &tunables().lane_affinity;
    // Scalar pull back into the home lane (0 = free, 1 = hard), tuned to the 4-lane
    // (~20yd quarter-pitch) `VERTICAL_LANE_COUNT`. The richer, ball/field-config-aware
    // per-player lane affinity lives in `dynamic_lane_affinity_for_player_target`.
    match role {
        PlayerRole::Goalkeeper => 1.0,
        // In possession the team must STRETCH the pitch, not collapse onto the ball:
        // hold the width lane firmly (was 0.48 / 0.45). Above the 0.65 hard-lock
        // threshold this snaps a player back to its lane once it drifts clear OUTSIDE
        // its ~13yd in-possession band UNLESS it has a relief reason (an attacking run,
        // tracking a mark, no outlet, covering a teammate, team urgency) — i.e. players
        // only leave their primary lane for those already-specified reasons. Drift
        // INSIDE the band is still free; this only bounds the band edge.
        PlayerRole::Defender if in_possession => lane_tunables.defender_commitment_possession,
        PlayerRole::Defender => lane_tunables.defender_commitment_defense,
        PlayerRole::Midfielder if in_possession => lane_tunables.midfielder_commitment_possession,
        PlayerRole::Midfielder => lane_tunables.midfielder_commitment_defense,
        // A light containment pull for forwards: enough to keep the lane clamp/penalty
        // alive against a cross-pitch drift (commitment must be > 0 to engage at all),
        // but well below the 0.65 hard-lock threshold and eroded by genuine attacking
        // runs (`offensive_high_speed_run_relief`), so striker movement stays free.
        PlayerRole::Forward if in_possession => lane_tunables.forward_commitment_possession,
        PlayerRole::Forward => lane_tunables.forward_commitment_defense,
    }
}

fn vertical_lane_deviation_yards(
    target_x: f64,
    role: PlayerRole,
    home_x: f64,
    field_width: f64,
    in_possession: bool,
) -> f64 {
    let (min_lane, max_lane) = role_vertical_lane_range(role, home_x, field_width, in_possession);
    let (left, _) = vertical_lane_bounds(min_lane, field_width);
    let (_, right) = vertical_lane_bounds(max_lane, field_width);
    if target_x < left {
        left - target_x
    } else if target_x > right {
        target_x - right
    } else {
        0.0
    }
}

fn vertical_lane_fit_for_role_target(
    role: PlayerRole,
    home_x: f64,
    target_x: f64,
    field_width: f64,
    in_possession: bool,
    relief: f64,
) -> VerticalLaneFit {
    let lane_tunables = &tunables().lane_affinity;
    let commitment = role_vertical_lane_commitment(role, in_possession)
        * (1.0 - relief.clamp(0.0, lane_tunables.commitment_relief_max));
    if commitment <= 1e-9 {
        return VerticalLaneFit {
            affinity_score: 1.0,
            deviation_yards: 0.0,
            commitment: 0.0,
        };
    }
    let (min_lane, max_lane) = role_vertical_lane_range(role, home_x, field_width, in_possession);
    let target_lane = vertical_lane_index(target_x, field_width);
    let lane_gap = if target_lane < min_lane {
        min_lane - target_lane
    } else if target_lane > max_lane {
        target_lane - max_lane
    } else {
        0
    };
    let deviation_yards =
        vertical_lane_deviation_yards(target_x, role, home_x, field_width, in_possession);
    let affinity_score = if lane_discipline::lane_discipline_v2_enabled() {
        // Yard-based 12-lane re-derivation (grid-/pitch-size invariant).
        lane_discipline::static_affinity_score(deviation_yards, commitment)
    } else if lane_gap == 0 {
        1.0
    } else {
        (1.0 - commitment
            * (lane_tunables.lane_gap_base_penalty
                + lane_gap as f64 * lane_tunables.lane_gap_step_penalty))
            .clamp(0.0, 1.0)
    };
    VerticalLaneFit {
        affinity_score,
        deviation_yards,
        commitment,
    }
}

fn vertical_lane_clamped_x_for_role(
    role: PlayerRole,
    home_x: f64,
    target_x: f64,
    field_width: f64,
    in_possession: bool,
) -> f64 {
    let (min_lane, max_lane) = role_vertical_lane_range(role, home_x, field_width, in_possession);
    let (left, _) = vertical_lane_bounds(min_lane, field_width);
    let (_, right) = vertical_lane_bounds(max_lane, field_width);
    let lo = left + 0.05;
    let hi = (right - 0.05).max(lo);
    // Self-sanitising: a non-finite target_x would otherwise propagate (f64::clamp
    // returns NaN for a NaN input). Fall back to the player's own lane.
    let x = if target_x.is_finite() {
        target_x
    } else if home_x.is_finite() {
        home_x
    } else {
        lo
    };
    x.clamp(lo, hi)
}

#[derive(Clone, Copy, Debug, Default, PartialEq, Eq, Hash, Serialize, Deserialize)]
pub enum IncomingBallKind {
    #[default]
    None,
    GroundPass,
    AerialPass,
    Cross,
    AerialCross,
    LooseBall,
}

#[derive(Clone, Copy, Debug, Default, PartialEq, Eq, Hash, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub enum PassFlight {
    #[default]
    Floor,
    Aerial,
    /// A delicate lofted CHIP/scoop: slow horizontally (~10mph) but high (up to ~15ft), to
    /// drop over a close defender onto a nearby (5-8yd) open teammate. Reuses the aerial
    /// control/interception physics (`is_aerial()` is true), but its launch speed is low and
    /// fixed and its loft is high — both decoupled from power (an Aerial can't be ~10mph;
    /// its floor is ~19mph, and aerial loft scales with speed, the opposite of a scoop).
    Scoop,
    /// A killer-pass variant clipped over the opponent back four: 25-35yd, about 12ft up,
    /// with an angled target away from the opposing goalkeeper rather than straight at goal.
    OverTop,
}

impl PassFlight {
    fn is_aerial(self) -> bool {
        matches!(
            self,
            PassFlight::Aerial | PassFlight::Scoop | PassFlight::OverTop
        )
    }
    fn is_scoop(self) -> bool {
        matches!(self, PassFlight::Scoop)
    }
    fn is_over_top(self) -> bool {
        matches!(self, PassFlight::OverTop)
    }
}

