impl SoccerTacticalLearningSummary {
    pub fn from_transitions(transitions: &[SoccerLearningTransition]) -> Self {
        let mut summary = SoccerTacticalLearningSummary::default();
        summary.record_transitions(transitions);
        summary
    }

    pub fn record_transitions(&mut self, transitions: &[SoccerLearningTransition]) {
        for transition in transitions {
            self.record_transition(transition);
        }
    }

    pub fn merge(&mut self, other: &Self) {
        let attack_count = self.attack_transitions;
        let defense_count = self.defense_transitions;
        let shape_count = self.shape_transitions;

        self.mean_attack_team_width_yards = weighted_mean(
            self.mean_attack_team_width_yards,
            attack_count,
            other.mean_attack_team_width_yards,
            other.attack_transitions,
        );
        self.mean_attack_width_delta_yards = weighted_mean(
            self.mean_attack_width_delta_yards,
            attack_count,
            other.mean_attack_width_delta_yards,
            other.attack_transitions,
        );
        self.mean_attack_width_score = weighted_mean(
            self.mean_attack_width_score,
            attack_count,
            other.mean_attack_width_score,
            other.attack_transitions,
        );
        self.mean_attack_flank_lane_score = weighted_mean(
            self.mean_attack_flank_lane_score,
            attack_count,
            other.mean_attack_flank_lane_score,
            other.attack_transitions,
        );
        self.mean_attack_flank_lane_delta = weighted_mean(
            self.mean_attack_flank_lane_delta,
            attack_count,
            other.mean_attack_flank_lane_delta,
            other.attack_transitions,
        );
        self.mean_attack_spacing_score = weighted_mean(
            self.mean_attack_spacing_score,
            attack_count,
            other.mean_attack_spacing_score,
            other.attack_transitions,
        );
        self.mean_attack_tactical_reward = weighted_mean(
            self.mean_attack_tactical_reward,
            attack_count,
            other.mean_attack_tactical_reward,
            other.attack_transitions,
        );
        self.mean_defense_team_width_yards = weighted_mean(
            self.mean_defense_team_width_yards,
            defense_count,
            other.mean_defense_team_width_yards,
            other.defense_transitions,
        );
        self.mean_defense_contract_delta_yards = weighted_mean(
            self.mean_defense_contract_delta_yards,
            defense_count,
            other.mean_defense_contract_delta_yards,
            other.defense_transitions,
        );
        self.mean_defense_contract_score = weighted_mean(
            self.mean_defense_contract_score,
            defense_count,
            other.mean_defense_contract_score,
            other.defense_transitions,
        );
        self.mean_defense_spacing_score = weighted_mean(
            self.mean_defense_spacing_score,
            defense_count,
            other.mean_defense_spacing_score,
            other.defense_transitions,
        );
        self.mean_defense_ball_gap_yards = weighted_mean(
            self.mean_defense_ball_gap_yards,
            defense_count,
            other.mean_defense_ball_gap_yards,
            other.defense_transitions,
        );
        self.mean_defense_ball_gap_score = weighted_mean(
            self.mean_defense_ball_gap_score,
            defense_count,
            other.mean_defense_ball_gap_score,
            other.defense_transitions,
        );
        self.mean_defense_endline_penalty = weighted_mean(
            self.mean_defense_endline_penalty,
            defense_count,
            other.mean_defense_endline_penalty,
            other.defense_transitions,
        );
        self.mean_defense_role_press_score = weighted_mean(
            self.mean_defense_role_press_score,
            defense_count,
            other.mean_defense_role_press_score,
            other.defense_transitions,
        );
        self.mean_defense_tactical_reward = weighted_mean(
            self.mean_defense_tactical_reward,
            defense_count,
            other.mean_defense_tactical_reward,
            other.defense_transitions,
        );
        let keeper_line_count = self.goalkeeper_line_alignment_transitions;
        self.mean_goalkeeper_ball_goal_line_alignment_score = weighted_mean(
            self.mean_goalkeeper_ball_goal_line_alignment_score,
            keeper_line_count,
            other.mean_goalkeeper_ball_goal_line_alignment_score,
            other.goalkeeper_line_alignment_transitions,
        );
        let break_threat_count = self.defensive_line_break_threat_transitions;
        self.mean_defensive_line_break_threat = weighted_mean(
            self.mean_defensive_line_break_threat,
            break_threat_count,
            other.mean_defensive_line_break_threat,
            other.defensive_line_break_threat_transitions,
        );
        let lp_count = self.lp_guided_transitions;
        self.mean_lp_recommended_move_yards = weighted_mean(
            self.mean_lp_recommended_move_yards,
            lp_count,
            other.mean_lp_recommended_move_yards,
            other.lp_guided_transitions,
        );
        self.mean_lp_actual_move_yards = weighted_mean(
            self.mean_lp_actual_move_yards,
            lp_count,
            other.mean_lp_actual_move_yards,
            other.lp_guided_transitions,
        );
        self.mean_lp_disagreement_yards = weighted_mean(
            self.mean_lp_disagreement_yards,
            lp_count,
            other.mean_lp_disagreement_yards,
            other.lp_guided_transitions,
        );
        self.mean_lp_alignment_score = weighted_mean(
            self.mean_lp_alignment_score,
            lp_count,
            other.mean_lp_alignment_score,
            other.lp_guided_transitions,
        );
        self.mean_lp_pair_error_yards = weighted_mean(
            self.mean_lp_pair_error_yards,
            lp_count,
            other.mean_lp_pair_error_yards,
            other.lp_guided_transitions,
        );
        self.mean_vertical_lane_affinity_score = weighted_mean(
            self.mean_vertical_lane_affinity_score,
            shape_count,
            other.mean_vertical_lane_affinity_score,
            other.shape_transitions,
        );
        self.mean_vertical_lane_affinity_delta = weighted_mean(
            self.mean_vertical_lane_affinity_delta,
            shape_count,
            other.mean_vertical_lane_affinity_delta,
            other.shape_transitions,
        );
        self.mean_teammate_congestion_pressure = weighted_mean(
            self.mean_teammate_congestion_pressure,
            shape_count,
            other.mean_teammate_congestion_pressure,
            other.shape_transitions,
        );
        self.mean_teammate_congestion_delta = weighted_mean(
            self.mean_teammate_congestion_delta,
            shape_count,
            other.mean_teammate_congestion_delta,
            other.shape_transitions,
        );
        self.mean_effective_teammate_spacing_pressure = weighted_mean(
            self.mean_effective_teammate_spacing_pressure,
            shape_count,
            other.mean_effective_teammate_spacing_pressure,
            other.shape_transitions,
        );
        self.mean_effective_teammate_spacing_delta = weighted_mean(
            self.mean_effective_teammate_spacing_delta,
            shape_count,
            other.mean_effective_teammate_spacing_delta,
            other.shape_transitions,
        );
        self.mean_role_line_deviation_yards = weighted_mean(
            self.mean_role_line_deviation_yards,
            shape_count,
            other.mean_role_line_deviation_yards,
            other.shape_transitions,
        );
        self.mean_role_line_deviation_delta_yards = weighted_mean(
            self.mean_role_line_deviation_delta_yards,
            shape_count,
            other.mean_role_line_deviation_delta_yards,
            other.shape_transitions,
        );
        self.mean_role_line_cohesion_score = weighted_mean(
            self.mean_role_line_cohesion_score,
            shape_count,
            other.mean_role_line_cohesion_score,
            other.shape_transitions,
        );
        self.mean_role_line_cohesion_delta = weighted_mean(
            self.mean_role_line_cohesion_delta,
            shape_count,
            other.mean_role_line_cohesion_delta,
            other.shape_transitions,
        );
        self.defender_line_depth_training_rows = self
            .defender_line_depth_training_rows
            .saturating_add(other.defender_line_depth_training_rows);
        self.midfield_line_depth_training_rows = self
            .midfield_line_depth_training_rows
            .saturating_add(other.midfield_line_depth_training_rows);
        self.mean_positional_shape_exception_relief = weighted_mean(
            self.mean_positional_shape_exception_relief,
            shape_count,
            other.mean_positional_shape_exception_relief,
            other.shape_transitions,
        );
        self.mean_positional_shape_reward = weighted_mean(
            self.mean_positional_shape_reward,
            shape_count,
            other.mean_positional_shape_reward,
            other.shape_transitions,
        );
        let look_behind_count = self.look_behind_scan_transitions;
        self.mean_look_behind_drift_risk = weighted_mean(
            self.mean_look_behind_drift_risk,
            look_behind_count,
            other.mean_look_behind_drift_risk,
            other.look_behind_scan_transitions,
        );
        self.mean_look_behind_shape_penalty = weighted_mean(
            self.mean_look_behind_shape_penalty,
            look_behind_count,
            other.mean_look_behind_shape_penalty,
            other.look_behind_scan_transitions,
        );
        self.total_transitions = self
            .total_transitions
            .saturating_add(other.total_transitions);
        self.shape_transitions = self
            .shape_transitions
            .saturating_add(other.shape_transitions);
        self.attack_transitions = self
            .attack_transitions
            .saturating_add(other.attack_transitions);
        self.defense_transitions = self
            .defense_transitions
            .saturating_add(other.defense_transitions);
        self.goalkeeper_line_alignment_transitions = self
            .goalkeeper_line_alignment_transitions
            .saturating_add(other.goalkeeper_line_alignment_transitions);
        self.defensive_line_break_threat_transitions = self
            .defensive_line_break_threat_transitions
            .saturating_add(other.defensive_line_break_threat_transitions);
        self.lp_guided_transitions = self
            .lp_guided_transitions
            .saturating_add(other.lp_guided_transitions);
        self.look_behind_scan_transitions = self
            .look_behind_scan_transitions
            .saturating_add(other.look_behind_scan_transitions);
        self.total_tactical_reward =
            finite_metric(self.total_tactical_reward) + finite_metric(other.total_tactical_reward);
        self.mean_tactical_reward = if self.shape_transitions > 0 {
            self.total_tactical_reward / self.shape_transitions as f64
        } else {
            0.0
        };
    }

    fn record_transition(&mut self, transition: &SoccerLearningTransition) {
        self.total_transitions = self.total_transitions.saturating_add(1);
        match transition.role {
            PlayerRole::Goalkeeper => {
                self.goalkeeper_line_alignment_transitions =
                    self.goalkeeper_line_alignment_transitions.saturating_add(1);
                record_running_mean(
                    &mut self.mean_goalkeeper_ball_goal_line_alignment_score,
                    self.goalkeeper_line_alignment_transitions,
                    transition
                        .observation
                        .goalkeeper_ball_goal_line_alignment_score,
                );
            }
            PlayerRole::Defender => {
                self.defensive_line_break_threat_transitions = self
                    .defensive_line_break_threat_transitions
                    .saturating_add(1);
                record_running_mean(
                    &mut self.mean_defensive_line_break_threat,
                    self.defensive_line_break_threat_transitions,
                    transition.observation.defensive_line_break_threat,
                );
            }
            PlayerRole::Midfielder | PlayerRole::Forward => {}
        }
        let trace = &transition.tactical_trace;
        if trace.attack_shape {
            self.shape_transitions = self.shape_transitions.saturating_add(1);
            self.attack_transitions = self.attack_transitions.saturating_add(1);
            self.record_line_depth_training_row(transition);
            record_running_mean(
                &mut self.mean_attack_team_width_yards,
                self.attack_transitions,
                trace.after_team_width_yards,
            );
            record_running_mean(
                &mut self.mean_attack_width_delta_yards,
                self.attack_transitions,
                trace.width_delta_yards,
            );
            record_running_mean(
                &mut self.mean_attack_width_score,
                self.attack_transitions,
                trace.attack_width_score,
            );
            record_running_mean(
                &mut self.mean_attack_flank_lane_score,
                self.attack_transitions,
                trace.after_flank_lane_score,
            );
            record_running_mean(
                &mut self.mean_attack_flank_lane_delta,
                self.attack_transitions,
                trace.flank_lane_delta,
            );
            record_running_mean(
                &mut self.mean_attack_spacing_score,
                self.attack_transitions,
                trace.after_spacing_score,
            );
            record_running_mean(
                &mut self.mean_attack_tactical_reward,
                self.attack_transitions,
                trace.tactical_reward,
            );
            self.total_tactical_reward += finite_metric(trace.tactical_reward);
            self.record_positional_shape_trace(trace);
        } else if trace.defense_shape {
            self.shape_transitions = self.shape_transitions.saturating_add(1);
            self.defense_transitions = self.defense_transitions.saturating_add(1);
            self.record_line_depth_training_row(transition);
            record_running_mean(
                &mut self.mean_defense_team_width_yards,
                self.defense_transitions,
                trace.after_team_width_yards,
            );
            record_running_mean(
                &mut self.mean_defense_contract_delta_yards,
                self.defense_transitions,
                -trace.width_delta_yards,
            );
            record_running_mean(
                &mut self.mean_defense_contract_score,
                self.defense_transitions,
                trace.defense_contract_score,
            );
            record_running_mean(
                &mut self.mean_defense_spacing_score,
                self.defense_transitions,
                trace.after_spacing_score,
            );
            record_running_mean(
                &mut self.mean_defense_ball_gap_yards,
                self.defense_transitions,
                trace.defense_ball_gap_yards,
            );
            record_running_mean(
                &mut self.mean_defense_ball_gap_score,
                self.defense_transitions,
                trace.defense_ball_gap_score,
            );
            record_running_mean(
                &mut self.mean_defense_endline_penalty,
                self.defense_transitions,
                trace.defense_endline_soft_penalty + trace.defense_endline_hard_penalty,
            );
            record_running_mean(
                &mut self.mean_defense_role_press_score,
                self.defense_transitions,
                trace.defense_role_press_score,
            );
            record_running_mean(
                &mut self.mean_defense_tactical_reward,
                self.defense_transitions,
                trace.tactical_reward,
            );
            self.total_tactical_reward += finite_metric(trace.tactical_reward);
            self.record_positional_shape_trace(trace);
        }
        if trace.formation_lp_guidance {
            self.lp_guided_transitions = self.lp_guided_transitions.saturating_add(1);
            record_running_mean(
                &mut self.mean_lp_recommended_move_yards,
                self.lp_guided_transitions,
                trace.formation_lp_recommended_move_yards,
            );
            record_running_mean(
                &mut self.mean_lp_actual_move_yards,
                self.lp_guided_transitions,
                trace.formation_lp_actual_move_yards,
            );
            record_running_mean(
                &mut self.mean_lp_disagreement_yards,
                self.lp_guided_transitions,
                trace.formation_lp_disagreement_yards,
            );
            record_running_mean(
                &mut self.mean_lp_alignment_score,
                self.lp_guided_transitions,
                trace.formation_lp_alignment_score,
            );
            record_running_mean(
                &mut self.mean_lp_pair_error_yards,
                self.lp_guided_transitions,
                trace.formation_lp_pair_error_yards,
            );
        }

        if self.shape_transitions > 0 {
            self.mean_tactical_reward = self.total_tactical_reward / self.shape_transitions as f64;
        }
    }

    fn record_line_depth_training_row(&mut self, transition: &SoccerLearningTransition) {
        let trace = &transition.tactical_trace;
        let usable = trace.before_role_line_deviation_yards.is_finite()
            && trace.after_role_line_deviation_yards.is_finite()
            && trace.before_role_line_cohesion_score.is_finite()
            && trace.after_role_line_cohesion_score.is_finite();
        if !usable {
            return;
        }
        match transition.role {
            PlayerRole::Defender => {
                self.defender_line_depth_training_rows =
                    self.defender_line_depth_training_rows.saturating_add(1);
            }
            PlayerRole::Midfielder => {
                self.midfield_line_depth_training_rows =
                    self.midfield_line_depth_training_rows.saturating_add(1);
            }
            PlayerRole::Goalkeeper | PlayerRole::Forward => {}
        }
    }

    fn record_positional_shape_trace(&mut self, trace: &SoccerTacticalLearningTrace) {
        let count = self.shape_transitions;
        record_running_mean(
            &mut self.mean_vertical_lane_affinity_score,
            count,
            trace.after_vertical_lane_affinity_score,
        );
        record_running_mean(
            &mut self.mean_vertical_lane_affinity_delta,
            count,
            trace.vertical_lane_affinity_delta,
        );
        record_running_mean(
            &mut self.mean_teammate_congestion_pressure,
            count,
            trace.after_teammate_congestion_pressure,
        );
        record_running_mean(
            &mut self.mean_teammate_congestion_delta,
            count,
            trace.teammate_congestion_delta,
        );
        record_running_mean(
            &mut self.mean_effective_teammate_spacing_pressure,
            count,
            trace.after_effective_teammate_spacing_pressure,
        );
        record_running_mean(
            &mut self.mean_effective_teammate_spacing_delta,
            count,
            trace.effective_teammate_spacing_delta,
        );
        record_running_mean(
            &mut self.mean_role_line_deviation_yards,
            count,
            trace.after_role_line_deviation_yards,
        );
        record_running_mean(
            &mut self.mean_role_line_deviation_delta_yards,
            count,
            trace.role_line_deviation_delta_yards,
        );
        record_running_mean(
            &mut self.mean_role_line_cohesion_score,
            count,
            trace.after_role_line_cohesion_score,
        );
        record_running_mean(
            &mut self.mean_role_line_cohesion_delta,
            count,
            trace.role_line_cohesion_delta,
        );
        record_running_mean(
            &mut self.mean_positional_shape_exception_relief,
            count,
            trace.positional_shape_exception_relief,
        );
        record_running_mean(
            &mut self.mean_positional_shape_reward,
            count,
            trace.positional_shape_reward,
        );
        if trace.look_behind_scan_active {
            self.look_behind_scan_transitions = self.look_behind_scan_transitions.saturating_add(1);
            record_running_mean(
                &mut self.mean_look_behind_drift_risk,
                self.look_behind_scan_transitions,
                trace.look_behind_drift_risk,
            );
            record_running_mean(
                &mut self.mean_look_behind_shape_penalty,
                self.look_behind_scan_transitions,
                trace.look_behind_shape_penalty,
            );
        }
    }
}

fn finite_metric(value: f64) -> f64 {
    if value.is_finite() {
        value
    } else {
        0.0
    }
}

fn schedule_order_relative_to_ball(
    scheduled_index: Option<usize>,
    ball_scheduled_index: Option<usize>,
) -> i8 {
    match (scheduled_index, ball_scheduled_index) {
        (Some(player), Some(ball)) if player < ball => -1,
        (Some(player), Some(ball)) if player > ball => 1,
        _ => 0,
    }
}

fn annotate_human_control_observation(
    observation: &mut SoccerPomdpObservation,
    controller_slot: Option<usize>,
    human_input: Option<&HumanInputFrame>,
) {
    observation.controller_slot = controller_slot
        .or(observation.controller_slot)
        .or_else(|| human_input.map(|input| input.controller_slot));
    observation.human_controlled = observation.controller_slot.is_some() || human_input.is_some();
    if let Some(input) = human_input {
        observation.human_input_present = true;
        observation.human_input_seq = Some(input.seq);
    }
}

fn human_input_matches_player(
    input: &HumanInputFrame,
    player_id: usize,
    controller_slot: Option<usize>,
) -> bool {
    if input
        .player_id
        .is_some_and(|input_player| input_player != player_id)
    {
        return false;
    }
    match controller_slot {
        Some(slot) => input.controller_slot == slot,
        None => input.player_id == Some(player_id),
    }
}

fn record_running_mean(mean: &mut f64, count: usize, value: f64) {
    if count == 0 {
        return;
    }
    let value = finite_metric(value);
    *mean += (value - *mean) / count as f64;
}

fn weighted_mean(left_mean: f64, left_count: usize, right_mean: f64, right_count: usize) -> f64 {
    let left_count = left_count as f64;
    let right_count = right_count as f64;
    let total = left_count + right_count;
    if total <= 0.0 {
        return 0.0;
    }
    (finite_metric(left_mean) * left_count + finite_metric(right_mean) * right_count) / total
}

