#[derive(Clone, Debug)]
pub struct SoccerQPolicy {
    pub q_values: HashMap<SoccerQActionKey, f64>,
    pub visits: HashMap<SoccerQActionKey, u32>,
    pub target_values: HashMap<SoccerQTargetKey, f64>,
    pub target_visits: HashMap<SoccerQTargetKey, u32>,
    action_index_keys: Vec<SoccerQActionKey>,
    target_index_keys: Vec<SoccerQTargetKey>,
    action_exact_index: HashMap<SoccerQStateKey, Vec<usize>>,
    action_relaxed_index: HashMap<SoccerQRelaxedIndexKey, Vec<usize>>,
    target_exact_index: HashMap<SoccerQActionKey, Vec<usize>>,
    target_relaxed_index: HashMap<SoccerQTargetRelaxedIndexKey, Vec<usize>>,
    pub options: SoccerQPolicyOptions,
}

impl Default for SoccerQPolicy {
    fn default() -> Self {
        Self::new(SoccerQPolicyOptions::default())
    }
}

fn update_best_target_grid_candidate<'a>(
    policy: &SoccerQPolicy,
    best: &mut Option<(&'a SoccerQTargetKey, f64, u32)>,
    key: &'a SoccerQTargetKey,
) {
    let Some(value) = policy
        .target_values
        .get(key)
        .copied()
        .and_then(soccer_q_sanitized_value)
    else {
        return;
    };
    let visits = policy.target_visits.get(key).copied().unwrap_or(0);
    let replace = best
        .as_ref()
        .map(|(_, best_value, best_visits)| {
            value
                .partial_cmp(best_value)
                .unwrap_or(std::cmp::Ordering::Equal)
                .then_with(|| visits.cmp(best_visits))
                .is_gt()
        })
        .unwrap_or(true);
    if replace {
        *best = Some((key, value, visits));
    }
}

/// Weight a learned target's value by how closely its stored target cell matches
/// the queried grid (Fine 1.0 → WholePitch 0.15) and keep the running best. The
/// weighting is over the *target* (where to move/pass), which is unaffected by the
/// removal of the player's position from the Q-key.
fn update_best_target_preference(
    policy: &SoccerQPolicy,
    best: &mut Option<(f64, u32)>,
    key: &SoccerQTargetKey,
    grid: &PitchGridAddress,
) {
    let Some(value) = policy
        .target_values
        .get(key)
        .copied()
        .and_then(soccer_q_sanitized_value)
    else {
        return;
    };
    let weight = if key.target_matches_grid(grid, PitchGridLevel::Fine) {
        1.0
    } else if key.target_matches_grid(grid, PitchGridLevel::Tactical) {
        0.75
    } else if key.target_matches_grid(grid, PitchGridLevel::Macro) {
        0.45
    } else if key.target_matches_grid(grid, PitchGridLevel::WholePitch) {
        0.15
    } else {
        return;
    };
    let visits = policy.target_visits.get(key).copied().unwrap_or(0);
    let weighted_value = (value * weight).clamp(-5.0, 5.0);
    let replace = best
        .as_ref()
        .map(|(best_value, best_visits)| {
            weighted_value
                .partial_cmp(best_value)
                .unwrap_or(std::cmp::Ordering::Equal)
                .then_with(|| visits.cmp(best_visits))
                .is_gt()
        })
        .unwrap_or(true);
    if replace {
        *best = Some((weighted_value, visits));
    }
}

impl SoccerQPolicy {
    pub fn new(options: SoccerQPolicyOptions) -> Self {
        SoccerQPolicy {
            q_values: HashMap::new(),
            visits: HashMap::new(),
            target_values: HashMap::new(),
            target_visits: HashMap::new(),
            action_index_keys: Vec::new(),
            target_index_keys: Vec::new(),
            action_exact_index: HashMap::new(),
            action_relaxed_index: HashMap::new(),
            target_exact_index: HashMap::new(),
            target_relaxed_index: HashMap::new(),
            options,
        }
    }

    pub fn from_entries(
        options: SoccerQPolicyOptions,
        entries: &[SoccerQEntry],
    ) -> Result<Self, String> {
        Self::from_entries_with_targets(options, entries, &[])
    }

    pub fn from_entries_with_targets(
        options: SoccerQPolicyOptions,
        entries: &[SoccerQEntry],
        target_entries: &[SoccerQTargetEntry],
    ) -> Result<Self, String> {
        validate_soccer_q_policy_options(&options)?;
        let mut policy = SoccerQPolicy::new(options);
        for entry in entries {
            if !entry.value.is_finite() {
                return Err("policy entry value must be finite".to_string());
            }
            let action = normalize_soccer_action_label(&entry.action).to_string();
            if action.trim().is_empty() {
                return Err("policy entry action must not be empty".to_string());
            }
            let key = SoccerQActionKey {
                state: entry.state.clone(),
                action,
            };
            if policy.insert_q_value(key.clone(), entry.value) {
                policy.visits.insert(key, entry.visits);
            }
        }
        for entry in target_entries {
            if !entry.value.is_finite() {
                return Err("policy target entry value must be finite".to_string());
            }
            let action = normalize_soccer_action_label(&entry.action).to_string();
            if action.trim().is_empty() {
                return Err("policy target entry action must not be empty".to_string());
            }
            let key = SoccerQTargetKey {
                state: entry.state.clone(),
                action,
                target_fine_cell_id: entry.target_fine_cell_id,
                target_tactical_cell_id: entry.target_tactical_cell_id,
                target_macro_cell_id: entry.target_macro_cell_id,
                target_root_cell_id: entry.target_root_cell_id,
            };
            if policy.insert_target_value(key.clone(), entry.value) {
                policy.target_visits.insert(key, entry.visits);
            }
        }
        Ok(policy)
    }

    /// Clone the state with a specific facing pair applied. Used to enumerate the
    /// facing-compatible variants of a query state for the exact-context lookup
    /// (`action_exact_index`/`target_exact_index` are keyed by the full state key,
    /// and facings are matched fuzzily — Unknown is a wildcard).
    fn state_with_facing(
        state: &SoccerQStateKey,
        receive_facing: FacingBucket,
        action_facing: FacingBucket,
    ) -> SoccerQStateKey {
        let mut indexed = state.clone();
        indexed.receive_facing = receive_facing;
        indexed.action_facing = action_facing;
        indexed
    }

    fn relaxed_index_key_for_state(state: &SoccerQStateKey) -> SoccerQRelaxedIndexKey {
        SoccerQRelaxedIndexKey {
            role: state.role,
            assigned_position: state.assigned_position,
            possession_relative: state.possession_relative,
            has_ball: state.has_ball,
            visible_ball: state.visible_ball,
            offside_position_bin: state.offside_position_bin,
            offside_recovery_pressure_bin: state.offside_recovery_pressure_bin,
            first_touch_kind: state.first_touch_kind,
            receiving_pending_pass: state.receiving_pending_pass,
            receive_facing: state.receive_facing,
            action_facing: state.action_facing,
        }
    }

    fn facing_query_values(facing: FacingBucket) -> &'static [FacingBucket] {
        if facing == FacingBucket::Unknown {
            &SOCCER_FACING_INDEX_VALUES
        } else {
            match facing {
                FacingBucket::North => &[FacingBucket::North, FacingBucket::Unknown],
                FacingBucket::NorthEast => &[FacingBucket::NorthEast, FacingBucket::Unknown],
                FacingBucket::East => &[FacingBucket::East, FacingBucket::Unknown],
                FacingBucket::SouthEast => &[FacingBucket::SouthEast, FacingBucket::Unknown],
                FacingBucket::South => &[FacingBucket::South, FacingBucket::Unknown],
                FacingBucket::SouthWest => &[FacingBucket::SouthWest, FacingBucket::Unknown],
                FacingBucket::West => &[FacingBucket::West, FacingBucket::Unknown],
                FacingBucket::NorthWest => &[FacingBucket::NorthWest, FacingBucket::Unknown],
                FacingBucket::Unknown => &SOCCER_FACING_INDEX_VALUES,
            }
        }
    }

    /// Facing-compatible variants of a query state for the exact-context lookup.
    /// (Player position is no longer in the key, so there is a single resolution;
    /// only the facing wildcarding remains.)
    fn facing_query_states(state: &SoccerQStateKey) -> Vec<SoccerQStateKey> {
        let mut keys = Vec::new();
        for receive_facing in Self::facing_query_values(state.receive_facing) {
            for action_facing in Self::facing_query_values(state.action_facing) {
                keys.push(Self::state_with_facing(
                    state,
                    *receive_facing,
                    *action_facing,
                ));
            }
        }
        keys
    }

    fn relaxed_query_keys(state: &SoccerQStateKey) -> Vec<SoccerQRelaxedIndexKey> {
        let mut keys = Vec::new();
        for receive_facing in Self::facing_query_values(state.receive_facing) {
            for action_facing in Self::facing_query_values(state.action_facing) {
                let mut key = Self::relaxed_index_key_for_state(state);
                key.receive_facing = *receive_facing;
                key.action_facing = *action_facing;
                keys.push(key);
            }
        }
        keys
    }

    fn index_action_key(&mut self, key: &SoccerQActionKey) {
        let key_id = self.action_index_keys.len();
        self.action_index_keys.push(key.clone());
        self.action_exact_index
            .entry(key.state.clone())
            .or_default()
            .push(key_id);
        self.action_relaxed_index
            .entry(Self::relaxed_index_key_for_state(&key.state))
            .or_default()
            .push(key_id);
    }

    fn insert_q_value(&mut self, key: SoccerQActionKey, value: f64) -> bool {
        let Some(value) = soccer_q_sanitized_value(value) else {
            return false;
        };
        if key.action.trim().is_empty() {
            return false;
        }
        if !self.q_values.contains_key(&key) {
            self.index_action_key(&key);
        }
        self.q_values.insert(key, value);
        true
    }

    fn index_target_key(&mut self, key: &SoccerQTargetKey) {
        let key_id = self.target_index_keys.len();
        self.target_index_keys.push(key.clone());
        self.target_exact_index
            .entry(SoccerQActionKey {
                state: key.state.clone(),
                action: key.action.clone(),
            })
            .or_default()
            .push(key_id);
        self.target_relaxed_index
            .entry(SoccerQTargetRelaxedIndexKey {
                source: Self::relaxed_index_key_for_state(&key.state),
                action: key.action.clone(),
            })
            .or_default()
            .push(key_id);
    }

    fn insert_target_value(&mut self, key: SoccerQTargetKey, value: f64) -> bool {
        let Some(value) = soccer_q_sanitized_value(value) else {
            return false;
        };
        if key.action.trim().is_empty() {
            return false;
        }
        if !self.target_values.contains_key(&key) {
            self.index_target_key(&key);
        }
        self.target_values.insert(key, value);
        true
    }

    pub fn train(&mut self, transitions: &[SoccerLearningTransition]) {
        for transition in transitions {
            self.update(transition);
        }
    }

    pub fn update(&mut self, transition: &SoccerLearningTransition) {
        self.update_with_reward(transition, transition.reward);
    }

    fn update_with_reward(&mut self, transition: &SoccerLearningTransition, reward: f64) {
        let Some(reward) = soccer_q_sanitized_value(reward) else {
            return;
        };
        let state = SoccerQStateKey::from_transition(transition);
        let next_state = SoccerQStateKey::from_next_transition(transition);
        let action = normalize_soccer_action_label(&transition.action).to_string();
        if action.trim().is_empty() {
            return;
        }
        let key = SoccerQActionKey {
            state: state.clone(),
            action: action.clone(),
        };
        let old = self
            .q_values
            .get(&key)
            .copied()
            .and_then(soccer_q_sanitized_value)
            .unwrap_or(0.0);
        let max_next = if transition.done {
            0.0
        } else {
            self.best_value_hierarchical(&next_state).unwrap_or(0.0)
        };
        let alpha = soccer_q_sanitized_alpha(self.options.alpha);
        let gamma = soccer_q_sanitized_gamma(self.options.gamma);
        let target = reward + gamma * max_next;
        let updated = old + alpha * (target - old);
        if self.insert_q_value(key.clone(), updated) {
            let visits = self.visits.entry(key).or_insert(0);
            *visits = visits.saturating_add(1);
        }

        if let Some(grid) = transition
            .action_target
            .as_ref()
            .and_then(|target| target.grid)
        {
            let target_key = SoccerQTargetKey::from_state_action_grid(state, &action, grid);
            let old_target = self
                .target_values
                .get(&target_key)
                .copied()
                .and_then(soccer_q_sanitized_value)
                .unwrap_or(0.0);
            let updated_target = old_target + alpha * (target - old_target);
            if self.insert_target_value(target_key.clone(), updated_target) {
                let visits = self.target_visits.entry(target_key).or_insert(0);
                *visits = visits.saturating_add(1);
            }
        }
    }

    pub fn best_action(&self, state: &SoccerQStateKey) -> Option<String> {
        self.best_action_filtered(state, |_| true)
    }

    pub fn best_action_hierarchical(&self, state: &SoccerQStateKey) -> Option<String> {
        self.best_action_filtered_hierarchical(state, |_| true)
    }

    pub fn best_action_for_snapshot(
        &self,
        snapshot: &WorldSnapshot,
        player_id: usize,
    ) -> Option<String> {
        let mdp_state = snapshot.mdp_state_for_player(player_id);
        let observation = snapshot.observation_for(player_id);
        self.best_action_for_state_observation(snapshot, player_id, &mdp_state, &observation)
    }

    fn best_action_for_state_observation(
        &self,
        snapshot: &WorldSnapshot,
        player_id: usize,
        mdp_state: &SoccerMdpState,
        observation: &SoccerPomdpObservation,
    ) -> Option<String> {
        let player = snapshot.players.iter().find(|p| p.id == player_id)?;
        let state = SoccerQStateKey::from_parts(mdp_state, observation, player.team, player.role);
        self.best_action_filtered_hierarchical_relaxed(&state, |action| {
            learned_action_label_is_legal(action, snapshot, player_id)
        })
    }

    /// As [`Self::best_action_for_state_observation`], but biased by a **retrieval
    /// action prior** (action → bounded favourability), scaled by `weight`. The
    /// chosen action is `argmax_a [ Q(s,a) + weight · prior(a) ]` over the legal
    /// tabular candidates. When `prior` is `None`/empty or `weight == 0` this
    /// delegates to the unbiased path verbatim, so play is byte-identical unless a
    /// caller opts in. The prior only re-weights existing candidates — it never
    /// introduces new actions, so it cannot perturb any RNG draw.
    fn best_action_for_state_observation_with_prior(
        &self,
        snapshot: &WorldSnapshot,
        player_id: usize,
        mdp_state: &SoccerMdpState,
        observation: &SoccerPomdpObservation,
        prior: Option<(&std::collections::HashMap<String, f64>, f64)>,
    ) -> Option<String> {
        let Some((prior, weight)) = prior.filter(|(p, w)| !p.is_empty() && *w != 0.0) else {
            return self.best_action_for_state_observation(
                snapshot,
                player_id,
                mdp_state,
                observation,
            );
        };
        let player = snapshot.players.iter().find(|p| p.id == player_id)?;
        let state = SoccerQStateKey::from_parts(mdp_state, observation, player.team, player.role);
        let ranked = self.ranked_action_values_filtered_hierarchical(
            &state,
            SOCCER_RETRIEVAL_PRIOR_RERANK_LIMIT,
            |action| learned_action_label_is_legal(action, snapshot, player_id),
        );
        let scored = ranked
            .iter()
            .filter(|candidate| candidate.legal)
            .max_by(|a, b| {
                let sa = a.value
                    + weight
                        * prior
                            .get(normalize_soccer_action_label(&a.label))
                            .copied()
                            .unwrap_or(0.0);
                let sb = b.value
                    + weight
                        * prior
                            .get(normalize_soccer_action_label(&b.label))
                            .copied()
                            .unwrap_or(0.0);
                sa.total_cmp(&sb).then_with(|| a.visits.cmp(&b.visits))
            })
            .map(|candidate| candidate.label.clone());
        // If the exact-context scan found no legal candidate, fall back to the
        // relaxed unbiased path so the prior never *loses* a decision the baseline
        // would have made.
        scored.or_else(|| {
            self.best_action_for_state_observation(snapshot, player_id, mdp_state, observation)
        })
    }

    pub fn ranked_action_values_for_snapshot(
        &self,
        snapshot: &WorldSnapshot,
        player_id: usize,
        limit: usize,
    ) -> Option<(SoccerQStateKey, Vec<SoccerLearnedActionTrace>)> {
        let player = snapshot.players.iter().find(|p| p.id == player_id)?;
        let state = SoccerQStateKey::from_parts(
            &snapshot.mdp_state_for_player(player_id),
            &snapshot.observation_for(player_id),
            player.team,
            player.role,
        );
        let actions = self.ranked_action_values_filtered_hierarchical(&state, limit, |action| {
            learned_action_label_is_legal(action, snapshot, player_id)
        });
        Some((state, actions))
    }

    pub fn best_value(&self, state: &SoccerQStateKey) -> Option<f64> {
        self.q_values
            .iter()
            .filter(|(key, _)| &key.state == state)
            .filter_map(|(_, value)| soccer_q_sanitized_value(*value))
            .max_by(|a, b| a.total_cmp(b))
    }

    /// Bellman bootstrap value `max_a Q(s, a)` for the TD update and the neural
    /// critic's training target. Name kept for call-site stability; the former
    /// fine→tactical→macro→root spatial backoff collapsed to a single
    /// exact-context lookup when the player pitch-grid cells left the Q-key.
    pub fn best_value_hierarchical(&self, state: &SoccerQStateKey) -> Option<f64> {
        self.best_value_for_context(state)
    }

    pub fn q_value(&self, state: &SoccerQStateKey, action: &str) -> Option<f64> {
        let key = SoccerQActionKey {
            state: state.clone(),
            action: normalize_soccer_action_label(action).to_string(),
        };
        self.q_values
            .get(&key)
            .copied()
            .and_then(soccer_q_sanitized_value)
    }

    pub fn set_action_value(&mut self, state: SoccerQStateKey, action: &str, value: f64) -> bool {
        let key = SoccerQActionKey {
            state,
            action: normalize_soccer_action_label(action).to_string(),
        };
        if self.insert_q_value(key.clone(), value) {
            self.visits.entry(key).or_insert(1);
            true
        } else {
            false
        }
    }

    pub fn set_action_value_for_snapshot(
        &mut self,
        snapshot: &WorldSnapshot,
        player_id: usize,
        action: &str,
        value: f64,
    ) -> bool {
        let Some(player) = snapshot.players.iter().find(|p| p.id == player_id) else {
            return false;
        };
        let state = SoccerQStateKey::from_parts(
            &snapshot.mdp_state_for_player(player_id),
            &snapshot.observation_for(player_id),
            player.team,
            player.role,
        );
        self.set_action_value(state, action, value)
    }

    pub fn set_target_value(
        &mut self,
        state: SoccerQStateKey,
        action: &str,
        grid: PitchGridAddress,
        value: f64,
    ) -> bool {
        let key = SoccerQTargetKey::from_state_action_grid(state, action, grid);
        if self.insert_target_value(key.clone(), value) {
            self.target_visits.entry(key).or_insert(1);
            true
        } else {
            false
        }
    }

    pub fn set_target_value_for_snapshot(
        &mut self,
        snapshot: &WorldSnapshot,
        player_id: usize,
        action: &str,
        point: Vec2,
        value: f64,
    ) -> bool {
        let Some(player) = snapshot.players.iter().find(|p| p.id == player_id) else {
            return false;
        };
        let state = SoccerQStateKey::from_parts(
            &snapshot.mdp_state_for_player(player_id),
            &snapshot.observation_for(player_id),
            player.team,
            player.role,
        );
        self.set_target_value(
            state,
            action,
            pitch_grid_address(point, snapshot.field_width, snapshot.field_length),
            value,
        )
    }

    pub fn entries(&self) -> Vec<SoccerQEntry> {
        let mut entries = self
            .q_values
            .iter()
            .filter_map(|(key, value)| {
                let value = soccer_q_sanitized_value(*value)?;
                Some(SoccerQEntry {
                    state: key.state.clone(),
                    action: key.action.clone(),
                    value,
                    visits: self.visits.get(key).copied().unwrap_or(0),
                })
            })
            .collect::<Vec<_>>();
        entries.sort_by(|a, b| {
            a.action
                .cmp(&b.action)
                .then_with(|| a.visits.cmp(&b.visits))
                .then_with(|| {
                    a.value
                        .partial_cmp(&b.value)
                        .unwrap_or(std::cmp::Ordering::Equal)
                })
        });
        entries
    }

    pub fn target_entries(&self) -> Vec<SoccerQTargetEntry> {
        let mut entries = self
            .target_values
            .iter()
            .filter_map(|(key, value)| {
                let value = soccer_q_sanitized_value(*value)?;
                Some(SoccerQTargetEntry {
                    state: key.state.clone(),
                    action: key.action.clone(),
                    target_fine_cell_id: key.target_fine_cell_id,
                    target_tactical_cell_id: key.target_tactical_cell_id,
                    target_macro_cell_id: key.target_macro_cell_id,
                    target_root_cell_id: key.target_root_cell_id,
                    value,
                    visits: self.target_visits.get(key).copied().unwrap_or(0),
                })
            })
            .collect::<Vec<_>>();
        entries.sort_by(|a, b| {
            a.action
                .cmp(&b.action)
                .then_with(|| a.target_root_cell_id.cmp(&b.target_root_cell_id))
                .then_with(|| a.target_macro_cell_id.cmp(&b.target_macro_cell_id))
                .then_with(|| a.target_tactical_cell_id.cmp(&b.target_tactical_cell_id))
                .then_with(|| a.target_fine_cell_id.cmp(&b.target_fine_cell_id))
                .then_with(|| a.visits.cmp(&b.visits))
                .then_with(|| {
                    a.value
                        .partial_cmp(&b.value)
                        .unwrap_or(std::cmp::Ordering::Equal)
                })
        });
        entries
    }

    pub fn action_probability_summaries(
        &self,
        state_limit: usize,
        action_limit: usize,
    ) -> Vec<SoccerQStateProbabilitySummary> {
        let mut by_state: HashMap<SoccerQStateKey, Vec<SoccerQActionProbabilityEntry>> =
            HashMap::new();
        // UI-only summary: bound the scan so it never becomes a 300ms+ hitch on the live
        // step as the table grows (it iterates + clones 129-field keys). An approximate
        // top-states view from a bounded sample is fine for display.
        for (key, value) in self
            .q_values
            .iter()
            .take(SOCCER_POLICY_PROBABILITY_SUMMARY_SCAN_CAP)
        {
            let Some(value) = soccer_q_sanitized_value(*value) else {
                continue;
            };
            by_state
                .entry(key.state.clone())
                .or_default()
                .push(SoccerQActionProbabilityEntry {
                    action: key.action.clone(),
                    value,
                    visits: self.visits.get(key).copied().unwrap_or(0),
                    probability: 0.0,
                });
        }

        let mut summaries = by_state
            .into_iter()
            .map(|(state, mut actions)| {
                let total_visits = actions
                    .iter()
                    .map(|action| u64::from(action.visits))
                    .sum::<u64>();
                let action_count = actions.len();
                let max_value = actions
                    .iter()
                    .map(|action| action.value)
                    .fold(f64::NEG_INFINITY, f64::max);
                let mut total = 0.0;
                if max_value.is_finite() {
                    for action in &actions {
                        total += (action.value - max_value).clamp(-40.0, 40.0).exp();
                    }
                }
                if total > 1e-9 {
                    for action in &mut actions {
                        action.probability =
                            (action.value - max_value).clamp(-40.0, 40.0).exp() / total;
                    }
                } else if !actions.is_empty() {
                    let uniform = 1.0 / actions.len() as f64;
                    for action in &mut actions {
                        action.probability = uniform;
                    }
                }
                actions.sort_by(|a, b| {
                    b.probability
                        .partial_cmp(&a.probability)
                        .unwrap_or(std::cmp::Ordering::Equal)
                        .then_with(|| {
                            b.value
                                .partial_cmp(&a.value)
                                .unwrap_or(std::cmp::Ordering::Equal)
                        })
                        .then_with(|| b.visits.cmp(&a.visits))
                        .then_with(|| a.action.cmp(&b.action))
                });
                let best_action = actions.first().map(|action| action.action.clone());
                if action_limit > 0 && actions.len() > action_limit {
                    actions.truncate(action_limit);
                }
                SoccerQStateProbabilitySummary {
                    state,
                    total_visits,
                    action_count,
                    best_action,
                    actions,
                }
            })
            .collect::<Vec<_>>();
        summaries.sort_by(|a, b| {
            b.total_visits
                .cmp(&a.total_visits)
                .then_with(|| b.action_count.cmp(&a.action_count))
                .then_with(|| {
                    a.best_action
                        .as_deref()
                        .unwrap_or("")
                        .cmp(b.best_action.as_deref().unwrap_or(""))
                })
        });
        if state_limit > 0 && summaries.len() > state_limit {
            summaries.truncate(state_limit);
        }
        summaries
    }

    pub fn visit_count(&self) -> u64 {
        self.visits.values().map(|v| u64::from(*v)).sum()
    }

    pub fn target_visit_count(&self) -> u64 {
        self.target_visits.values().map(|v| u64::from(*v)).sum()
    }

    pub fn prune(
        &mut self,
        max_action_entries: usize,
        max_target_entries: usize,
        min_visits: u32,
    ) -> SoccerQPolicyPruneSummary {
        let action_entries_before = self.q_values.len();
        let target_entries_before = self.target_values.len();

        if max_action_entries > 0 || min_visits > 0 {
            let mut kept_actions = self
                .q_values
                .iter()
                .filter_map(|(key, value)| {
                    let value = soccer_q_sanitized_value(*value)?;
                    let visits = self.visits.get(key).copied().unwrap_or(0);
                    (visits >= min_visits).then(|| (key.clone(), value, visits))
                })
                .collect::<Vec<_>>();
            kept_actions.sort_by(|(a_key, a_value, a_visits), (b_key, b_value, b_visits)| {
                b_visits
                    .cmp(a_visits)
                    .then_with(|| {
                        b_value
                            .abs()
                            .partial_cmp(&a_value.abs())
                            .unwrap_or(std::cmp::Ordering::Equal)
                    })
                    .then_with(|| a_key.action.cmp(&b_key.action))
            });
            if max_action_entries > 0 && kept_actions.len() > max_action_entries {
                kept_actions.truncate(max_action_entries);
            }

            self.q_values.clear();
            self.visits.clear();
            self.action_index_keys.clear();
            self.action_exact_index.clear();
            self.action_relaxed_index.clear();
            for (key, value, visits) in kept_actions {
                if self.insert_q_value(key.clone(), value) {
                    self.visits.insert(key, visits);
                }
            }
        }

        if max_target_entries > 0 || min_visits > 0 {
            let mut kept_targets = self
                .target_values
                .iter()
                .filter_map(|(key, value)| {
                    let value = soccer_q_sanitized_value(*value)?;
                    let visits = self.target_visits.get(key).copied().unwrap_or(0);
                    (visits >= min_visits).then(|| (key.clone(), value, visits))
                })
                .collect::<Vec<_>>();
            kept_targets.sort_by(|(a_key, a_value, a_visits), (b_key, b_value, b_visits)| {
                b_visits
                    .cmp(a_visits)
                    .then_with(|| {
                        b_value
                            .abs()
                            .partial_cmp(&a_value.abs())
                            .unwrap_or(std::cmp::Ordering::Equal)
                    })
                    .then_with(|| a_key.action.cmp(&b_key.action))
                    .then_with(|| a_key.target_root_cell_id.cmp(&b_key.target_root_cell_id))
                    .then_with(|| a_key.target_macro_cell_id.cmp(&b_key.target_macro_cell_id))
                    .then_with(|| {
                        a_key
                            .target_tactical_cell_id
                            .cmp(&b_key.target_tactical_cell_id)
                    })
                    .then_with(|| a_key.target_fine_cell_id.cmp(&b_key.target_fine_cell_id))
            });
            if max_target_entries > 0 && kept_targets.len() > max_target_entries {
                kept_targets.truncate(max_target_entries);
            }

            self.target_values.clear();
            self.target_visits.clear();
            self.target_index_keys.clear();
            self.target_exact_index.clear();
            self.target_relaxed_index.clear();
            for (key, value, visits) in kept_targets {
                if self.insert_target_value(key.clone(), value) {
                    self.target_visits.insert(key, visits);
                }
            }
        }

        SoccerQPolicyPruneSummary {
            action_entries_before,
            action_entries_after: self.q_values.len(),
            target_entries_before,
            target_entries_after: self.target_values.len(),
        }
    }

    pub fn best_target_grid_for_state_action(
        &self,
        state: &SoccerQStateKey,
        action: &str,
    ) -> Option<SoccerQTargetEntry> {
        self.best_target_grid_for_state_action_with_context(state, action, false)
            .or_else(|| self.best_target_grid_for_state_action_with_context(state, action, true))
    }

    fn best_target_grid_for_state_action_with_context(
        &self,
        state: &SoccerQStateKey,
        action: &str,
        relaxed: bool,
    ) -> Option<SoccerQTargetEntry> {
        let action = normalize_soccer_action_label(action);
        let mut best: Option<(&SoccerQTargetKey, f64, u32)> = None;
        if relaxed {
            for source in Self::relaxed_query_keys(state) {
                let index_key = SoccerQTargetRelaxedIndexKey {
                    source,
                    action: action.to_string(),
                };
                let Some(keys) = self.target_relaxed_index.get(&index_key) else {
                    continue;
                };
                for key_id in keys {
                    let Some(key) = self.target_index_keys.get(*key_id) else {
                        continue;
                    };
                    if key.action != action || !key.state.matches_relaxed_learning_context(state) {
                        continue;
                    }
                    update_best_target_grid_candidate(self, &mut best, key);
                }
            }
        } else {
            for index_state in Self::facing_query_states(state) {
                let index_key = SoccerQActionKey {
                    state: index_state,
                    action: action.to_string(),
                };
                let Some(keys) = self.target_exact_index.get(&index_key) else {
                    continue;
                };
                for key_id in keys {
                    let Some(key) = self.target_index_keys.get(*key_id) else {
                        continue;
                    };
                    if key.action != action || !key.state.matches_learning_context(state) {
                        continue;
                    }
                    update_best_target_grid_candidate(self, &mut best, key);
                }
            }
        }
        best.map(|(key, value, visits)| SoccerQTargetEntry {
            state: key.state.clone(),
            action: key.action.clone(),
            target_fine_cell_id: key.target_fine_cell_id,
            target_tactical_cell_id: key.target_tactical_cell_id,
            target_macro_cell_id: key.target_macro_cell_id,
            target_root_cell_id: key.target_root_cell_id,
            value,
            visits,
        })
    }

    pub fn target_preference_for_point(
        &self,
        state: &SoccerQStateKey,
        action: &str,
        point: Vec2,
        field_width: f64,
        field_length: f64,
    ) -> f64 {
        let grid = pitch_grid_address(point, field_width, field_length);
        self.target_preference_for_grid(state, action, &grid)
            .unwrap_or(0.0)
    }

    pub fn target_preference_for_snapshot(
        &self,
        snapshot: &WorldSnapshot,
        player_id: usize,
        action: &str,
        point: Vec2,
    ) -> f64 {
        let Some(player) = snapshot.players.iter().find(|p| p.id == player_id) else {
            return 0.0;
        };
        let state = SoccerQStateKey::from_parts(
            &snapshot.mdp_state_for_player(player_id),
            &snapshot.observation_for(player_id),
            player.team,
            player.role,
        );
        self.target_preference_for_point(
            &state,
            action,
            point,
            snapshot.field_width,
            snapshot.field_length,
        )
    }

    pub fn best_target_player_for_snapshot(
        &self,
        snapshot: &WorldSnapshot,
        player_id: usize,
        action: &str,
        candidates: &[usize],
    ) -> Option<usize> {
        let player = snapshot.players.iter().find(|p| p.id == player_id)?;
        let state = SoccerQStateKey::from_parts(
            &snapshot.mdp_state_for_player(player_id),
            &snapshot.observation_for(player_id),
            player.team,
            player.role,
        );
        candidates
            .iter()
            .filter_map(|candidate_id| {
                let position = snapshot.player_position(*candidate_id)?;
                let grid =
                    pitch_grid_address(position, snapshot.field_width, snapshot.field_length);
                let preference = self.target_preference_for_grid(&state, action, &grid)?;
                Some((*candidate_id, preference))
            })
            .max_by(|a, b| a.1.partial_cmp(&b.1).unwrap_or(std::cmp::Ordering::Equal))
            .map(|(candidate_id, _)| candidate_id)
    }

    pub fn best_pass_target_player_for_snapshot(
        &self,
        snapshot: &WorldSnapshot,
        player_id: usize,
        action: &str,
        flight: PassFlight,
        candidates: &[usize],
    ) -> Option<usize> {
        let player = snapshot.players.iter().find(|p| p.id == player_id)?;
        let player_position = snapshot
            .player_position(player_id)
            .unwrap_or(player.position);
        let state = SoccerQStateKey::from_parts(
            &snapshot.mdp_state_for_player(player_id),
            &snapshot.observation_for(player_id),
            player.team,
            player.role,
        );
        let action = normalize_soccer_action_label(action);
        // Re-ranking the candidate pool here would otherwise silently bypass the ranker's
        // concede veto (it only DEMOTES a conceded target, never removes it — see
        // `ranked_pass_targets_filtered_full`), which is how a learned policy could still pick a
        // pass straight to an opponent or into a tightly-marked man. Flag each candidate and
        // refuse to commit to a (perceived) conceded one while any clean option remains.
        let scored: Vec<(usize, f64, bool)> = candidates
            .iter()
            .filter_map(|candidate_id| {
                let target = snapshot.players.iter().find(|p| p.id == *candidate_id)?;
                let position = snapshot.player_position(*candidate_id)?;
                let grid =
                    pitch_grid_address(position, snapshot.field_width, snapshot.field_length);
                let learned_preference = self.target_preference_for_grid(&state, action, &grid);
                let quality = pass_target_quality_for_snapshot(
                    snapshot,
                    player,
                    player_position,
                    target,
                    position,
                    flight,
                );
                let learned_score = learned_preference.unwrap_or(0.0);
                let learned_weight = if learned_preference.is_some() {
                    1.0
                } else {
                    0.0
                };
                let score = learned_score * learned_weight
                    + quality.expected_completion * 0.82
                    + quality.mpc_receipt_probability * 0.52
                    + quality.stride_fit * 0.22
                    + quality.receiver_openness * 0.20;
                let concedes = snapshot.pass_target_concedes_to_perceived_opponent(
                    player_id,
                    *candidate_id,
                    flight,
                );
                Some((*candidate_id, score, concedes))
            })
            .collect();
        let pick = |require_clean: bool| {
            scored
                .iter()
                .filter(|(_, _, concedes)| !require_clean || !*concedes)
                .max_by(|a, b| a.1.total_cmp(&b.1).then_with(|| b.0.cmp(&a.0)))
                .map(|(candidate_id, _, _)| *candidate_id)
        };
        // Only fall back to the least-bad conceded target when EVERY candidate concedes
        // (genuinely no safe pass — the holder should usually be dribbling/holding/clearing then).
        pick(true).or_else(|| pick(false))
    }

    fn best_action_filtered<F>(&self, state: &SoccerQStateKey, is_legal: F) -> Option<String>
    where
        F: Fn(&str) -> bool,
    {
        let mut best: Option<(String, f64, u32)> = None;
        let Some(keys) = self.action_exact_index.get(state) else {
            return None;
        };
        for key_id in keys {
            let Some(key) = self.action_index_keys.get(*key_id) else {
                continue;
            };
            if !is_legal(&key.action) {
                continue;
            }
            let Some(value) = self
                .q_values
                .get(key)
                .copied()
                .and_then(soccer_q_sanitized_value)
            else {
                continue;
            };
            let visits = self.visits.get(key).copied().unwrap_or(0);
            let replace = best
                .as_ref()
                .map(|(_, best_value, best_visits)| {
                    value
                        .partial_cmp(best_value)
                        .unwrap_or(std::cmp::Ordering::Equal)
                        .then_with(|| visits.cmp(best_visits))
                        .is_gt()
                })
                .unwrap_or(true);
            if replace {
                best = Some((key.action.clone(), value, visits));
            }
        }
        best.map(|(action, _, _)| action)
    }

    fn best_action_filtered_hierarchical<F>(
        &self,
        state: &SoccerQStateKey,
        is_legal: F,
    ) -> Option<String>
    where
        F: Fn(&str) -> bool,
    {
        self.best_action_filtered_hierarchical_with_relaxed(state, is_legal, false)
    }

    fn best_action_filtered_hierarchical_relaxed<F>(
        &self,
        state: &SoccerQStateKey,
        is_legal: F,
    ) -> Option<String>
    where
        F: Fn(&str) -> bool,
    {
        self.best_action_filtered_hierarchical_with_relaxed(state, is_legal, true)
    }

    fn best_action_filtered_hierarchical_with_relaxed<F>(
        &self,
        state: &SoccerQStateKey,
        is_legal: F,
        relaxed: bool,
    ) -> Option<String>
    where
        F: Fn(&str) -> bool,
    {
        let strict = self.best_action_filtered_for_context(state, &is_legal, false);
        if strict.is_some() || !relaxed {
            return strict;
        }
        self.best_action_filtered_for_context(state, &is_legal, true)
    }

    fn best_action_filtered_for_context<F>(
        &self,
        state: &SoccerQStateKey,
        is_legal: &F,
        relaxed: bool,
    ) -> Option<String>
    where
        F: Fn(&str) -> bool,
    {
        let mut best: Option<(String, f64, u32)> = None;
        let mut examined = 0usize;
        if relaxed {
            'scan: for index_key in Self::relaxed_query_keys(state) {
                let Some(keys) = self.action_relaxed_index.get(&index_key) else {
                    continue;
                };
                for key_id in keys {
                    examined += 1;
                    if examined > SOCCER_LEARNED_LOOKUP_SCAN_CAP {
                        break 'scan;
                    }
                    let Some(key) = self.action_index_keys.get(*key_id) else {
                        continue;
                    };
                    if !key.state.matches_relaxed_learning_context(state) || !is_legal(&key.action)
                    {
                        continue;
                    }
                    let Some(value) = self
                        .q_values
                        .get(key)
                        .copied()
                        .and_then(soccer_q_sanitized_value)
                    else {
                        continue;
                    };
                    let visits = self.visits.get(key).copied().unwrap_or(0);
                    let replace = best
                        .as_ref()
                        .map(|(_, best_value, best_visits)| {
                            value
                                .partial_cmp(best_value)
                                .unwrap_or(std::cmp::Ordering::Equal)
                                .then_with(|| visits.cmp(best_visits))
                                .is_gt()
                        })
                        .unwrap_or(true);
                    if replace {
                        best = Some((key.action.clone(), value, visits));
                    }
                }
            }
            return best.map(|(action, _, _)| action);
        }
        for index_state in Self::facing_query_states(state) {
            let Some(keys) = self.action_exact_index.get(&index_state) else {
                continue;
            };
            for key_id in keys {
                let Some(key) = self.action_index_keys.get(*key_id) else {
                    continue;
                };
                if !key.state.matches_learning_context(state) || !is_legal(&key.action) {
                    continue;
                }
                let Some(value) = self
                    .q_values
                    .get(key)
                    .copied()
                    .and_then(soccer_q_sanitized_value)
                else {
                    continue;
                };
                let visits = self.visits.get(key).copied().unwrap_or(0);
                let replace = best
                    .as_ref()
                    .map(|(_, best_value, best_visits)| {
                        value
                            .partial_cmp(best_value)
                            .unwrap_or(std::cmp::Ordering::Equal)
                            .then_with(|| visits.cmp(best_visits))
                            .is_gt()
                    })
                    .unwrap_or(true);
                if replace {
                    best = Some((key.action.clone(), value, visits));
                }
            }
        }
        best.map(|(action, _, _)| action)
    }

    fn ranked_action_values_filtered_hierarchical<F>(
        &self,
        state: &SoccerQStateKey,
        limit: usize,
        is_legal: F,
    ) -> Vec<SoccerLearnedActionTrace>
    where
        F: Fn(&str) -> bool,
    {
        let mut by_action: HashMap<String, SoccerLearnedActionTrace> = HashMap::new();
        // Single-resolution exact-context scan (player pitch-grid backoff removed).
        // `level` is retained on the trace for diagnostic-format stability and now
        // reflects the single resolution used. Bounded by SOCCER_LEARNED_LOOKUP_SCAN_CAP so a
        // big Q-table can't make this per-decision lookup grow without bound (neural drives).
        let mut examined = 0usize;
        'scan: for index_state in Self::facing_query_states(state) {
            let Some(keys) = self.action_exact_index.get(&index_state) else {
                continue;
            };
            for key_id in keys {
                examined += 1;
                if examined > SOCCER_LEARNED_LOOKUP_SCAN_CAP {
                    break 'scan;
                }
                let Some(key) = self.action_index_keys.get(*key_id) else {
                    continue;
                };
                if !key.state.matches_learning_context(state) {
                    continue;
                }
                let Some(value) = self
                    .q_values
                    .get(key)
                    .copied()
                    .and_then(soccer_q_sanitized_value)
                else {
                    continue;
                };
                let visits = self.visits.get(key).copied().unwrap_or(0);
                let legal = is_legal(&key.action);
                let candidate = SoccerLearnedActionTrace {
                    label: key.action.clone(),
                    value,
                    visits,
                    probability: 0.0,
                    legal,
                    level: PitchGridLevel::Fine,
                };
                let replace = by_action
                    .get(&key.action)
                    .map(|existing| {
                        value
                            .partial_cmp(&existing.value)
                            .unwrap_or(std::cmp::Ordering::Equal)
                            .then_with(|| visits.cmp(&existing.visits))
                            .is_gt()
                    })
                    .unwrap_or(true);
                if replace {
                    by_action.insert(key.action.clone(), candidate);
                }
            }
        }

        let mut actions = by_action.into_values().collect::<Vec<_>>();
        let legal_values = actions
            .iter()
            .filter(|action| action.legal)
            .map(|action| action.value)
            .collect::<Vec<_>>();
        if !legal_values.is_empty() {
            let max_value = legal_values
                .iter()
                .copied()
                .fold(f64::NEG_INFINITY, f64::max);
            let mut total = 0.0;
            for action in actions.iter().filter(|action| action.legal) {
                total += (action.value - max_value).clamp(-40.0, 40.0).exp();
            }
            if total > 1e-9 {
                for action in actions.iter_mut().filter(|action| action.legal) {
                    action.probability =
                        (action.value - max_value).clamp(-40.0, 40.0).exp() / total;
                }
            }
        }

        actions.sort_by(|a, b| {
            b.legal
                .cmp(&a.legal)
                .then_with(|| {
                    b.probability
                        .partial_cmp(&a.probability)
                        .unwrap_or(std::cmp::Ordering::Equal)
                })
                .then_with(|| {
                    b.value
                        .partial_cmp(&a.value)
                        .unwrap_or(std::cmp::Ordering::Equal)
                })
                .then_with(|| b.visits.cmp(&a.visits))
                .then_with(|| a.label.cmp(&b.label))
        });
        if limit > 0 && actions.len() > limit {
            actions.truncate(limit);
        }
        actions
    }

    fn best_value_for_context(&self, state: &SoccerQStateKey) -> Option<f64> {
        let mut best: Option<f64> = None;
        let mut examined = 0usize;
        'scan: for index_state in Self::facing_query_states(state) {
            let Some(keys) = self.action_exact_index.get(&index_state) else {
                continue;
            };
            for key_id in keys {
                examined += 1;
                if examined > SOCCER_LEARNED_LOOKUP_SCAN_CAP {
                    break 'scan;
                }
                let Some(key) = self.action_index_keys.get(*key_id) else {
                    continue;
                };
                if !key.state.matches_learning_context(state) {
                    continue;
                }
                let Some(value) = self
                    .q_values
                    .get(key)
                    .copied()
                    .and_then(soccer_q_sanitized_value)
                else {
                    continue;
                };
                let replace = best
                    .as_ref()
                    .map(|best_value| {
                        value
                            .partial_cmp(best_value)
                            .unwrap_or(std::cmp::Ordering::Equal)
                            .is_gt()
                    })
                    .unwrap_or(true);
                if replace {
                    best = Some(value);
                }
            }
        }
        best
    }

    fn target_preference_for_grid(
        &self,
        state: &SoccerQStateKey,
        action: &str,
        grid: &PitchGridAddress,
    ) -> Option<f64> {
        self.target_preference_for_grid_with_context(state, action, grid, false)
            .or_else(|| self.target_preference_for_grid_with_context(state, action, grid, true))
    }

    fn target_preference_for_grid_with_context(
        &self,
        state: &SoccerQStateKey,
        action: &str,
        grid: &PitchGridAddress,
        relaxed: bool,
    ) -> Option<f64> {
        let action = normalize_soccer_action_label(action);
        let mut best: Option<(f64, u32)> = None;
        if relaxed {
            for source in Self::relaxed_query_keys(state) {
                let index_key = SoccerQTargetRelaxedIndexKey {
                    source,
                    action: action.to_string(),
                };
                let Some(keys) = self.target_relaxed_index.get(&index_key) else {
                    continue;
                };
                for key_id in keys {
                    let Some(key) = self.target_index_keys.get(*key_id) else {
                        continue;
                    };
                    if key.action != action || !key.state.matches_relaxed_learning_context(state) {
                        continue;
                    }
                    update_best_target_preference(self, &mut best, key, grid);
                }
            }
        } else {
            for index_state in Self::facing_query_states(state) {
                let index_key = SoccerQActionKey {
                    state: index_state,
                    action: action.to_string(),
                };
                let Some(keys) = self.target_exact_index.get(&index_key) else {
                    continue;
                };
                for key_id in keys {
                    let Some(key) = self.target_index_keys.get(*key_id) else {
                        continue;
                    };
                    if key.action != action || !key.state.matches_learning_context(state) {
                        continue;
                    }
                    update_best_target_preference(self, &mut best, key, grid);
                }
            }
        }
        best.map(|(value, _)| value)
    }
}

pub fn train_soccer_q_policy(
    dataset: &SoccerLearningDataset,
    options: SoccerQPolicyOptions,
) -> SoccerQPolicy {
    let mut policy = SoccerQPolicy::new(options);
    policy.train(&dataset.transitions);
    policy
}

fn validate_soccer_q_policy_options(options: &SoccerQPolicyOptions) -> Result<(), String> {
    if !options.alpha.is_finite() || !(0.0..=1.0).contains(&options.alpha) {
        return Err("policy alpha must be finite and between 0.0 and 1.0".to_string());
    }
    if !options.gamma.is_finite() || !(0.0..=0.999).contains(&options.gamma) {
        return Err("policy gamma must be finite and between 0.0 and 0.999".to_string());
    }
    Ok(())
}

#[derive(Clone, Debug)]
pub struct SoccerTeamQPolicies {
    pub home: SoccerQPolicy,
    pub away: SoccerQPolicy,
}

#[derive(Clone, Copy, Debug, Default, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct SoccerTeamQPolicyPruneSummary {
    pub home: SoccerQPolicyPruneSummary,
    pub away: SoccerQPolicyPruneSummary,
}

impl SoccerTeamQPolicyPruneSummary {
    pub fn removed_entries(&self) -> usize {
        self.home.removed_entries() + self.away.removed_entries()
    }
}

impl SoccerTeamQPolicies {
    pub fn new(options: SoccerQPolicyOptions) -> Self {
        SoccerTeamQPolicies {
            home: SoccerQPolicy::new(options.clone()),
            away: SoccerQPolicy::new(options),
        }
    }

    pub fn from_artifact(artifact: &SoccerTeamPolicyArtifact) -> Result<Self, String> {
        let home_options = artifact.home_options.clone().unwrap_or_default();
        let away_options = artifact.away_options.clone().unwrap_or_default();
        Ok(SoccerTeamQPolicies {
            home: SoccerQPolicy::from_entries_with_targets(
                home_options,
                &artifact.home_entries,
                &artifact.home_target_entries,
            )?,
            away: SoccerQPolicy::from_entries_with_targets(
                away_options,
                &artifact.away_entries,
                &artifact.away_target_entries,
            )?,
        })
    }

    pub fn from_self_play_artifact(
        artifact: &SoccerSelfPlayTrainingArtifact,
    ) -> Result<Self, String> {
        Ok(SoccerTeamQPolicies {
            home: SoccerQPolicy::from_entries_with_targets(
                artifact.options.clone(),
                &artifact.home_entries,
                &artifact.home_target_entries,
            )?,
            away: SoccerQPolicy::from_entries_with_targets(
                artifact.options.clone(),
                &artifact.away_entries,
                &artifact.away_target_entries,
            )?,
        })
    }

    pub fn policy(&self, team: Team) -> &SoccerQPolicy {
        match team {
            Team::Home => &self.home,
            Team::Away => &self.away,
        }
    }

    pub fn policy_mut(&mut self, team: Team) -> &mut SoccerQPolicy {
        match team {
            Team::Home => &mut self.home,
            Team::Away => &mut self.away,
        }
    }

    pub fn train(&mut self, transitions: &[SoccerLearningTransition]) {
        for transition in transitions {
            self.policy_mut(transition.team).update(transition);
        }
    }

    pub fn train_adversarial(&mut self, transitions: &[SoccerLearningTransition]) {
        let mut tick_rewards: HashMap<u64, (f64, u32, f64, u32)> = HashMap::new();
        for transition in transitions {
            let entry = tick_rewards.entry(transition.tick).or_default();
            let reward = finite_metric(transition.reward);
            match transition.team {
                Team::Home => {
                    entry.0 += reward;
                    entry.1 += 1;
                }
                Team::Away => {
                    entry.2 += reward;
                    entry.3 += 1;
                }
            }
        }

        for transition in transitions {
            let Some((home_sum, home_count, away_sum, away_count)) =
                tick_rewards.get(&transition.tick).copied()
            else {
                self.policy_mut(transition.team).update(transition);
                continue;
            };
            let home_avg = if home_count == 0 {
                0.0
            } else {
                home_sum / f64::from(home_count)
            };
            let away_avg = if away_count == 0 {
                0.0
            } else {
                away_sum / f64::from(away_count)
            };
            let opponent_avg = match transition.team {
                Team::Home => away_avg,
                Team::Away => home_avg,
            };
            let reward = finite_metric(transition.reward) - opponent_avg;
            self.policy_mut(transition.team)
                .update_with_reward(transition, reward);
        }
    }

    /// Adversarial Q training with an optional per-transition critic baseline
    /// (actor-critic control variate). `baselines[i]` is subtracted from the
    /// opponent-centered reward for `transitions[i]`; `None` entries fall back
    /// to the plain adversarial update. The baseline is a variance-reduction
    /// term — it changes the magnitude of each update, not its sign in
    /// expectation — so a well-correlated critic sharpens credit assignment.
    pub fn train_adversarial_with_baselines(
        &mut self,
        transitions: &[SoccerLearningTransition],
        baselines: &[Option<f64>],
    ) {
        if baselines.len() != transitions.len() {
            // Length mismatch would silently misalign baselines to the wrong
            // transitions; refuse rather than corrupt credit assignment.
            self.train_adversarial(transitions);
            return;
        }
        let mut tick_rewards: HashMap<u64, (f64, u32, f64, u32)> = HashMap::new();
        for transition in transitions {
            let entry = tick_rewards.entry(transition.tick).or_default();
            let reward = finite_metric(transition.reward);
            match transition.team {
                Team::Home => {
                    entry.0 += reward;
                    entry.1 += 1;
                }
                Team::Away => {
                    entry.2 += reward;
                    entry.3 += 1;
                }
            }
        }

        for (transition, baseline) in transitions.iter().zip(baselines.iter()) {
            let Some((home_sum, home_count, away_sum, away_count)) =
                tick_rewards.get(&transition.tick).copied()
            else {
                self.policy_mut(transition.team).update(transition);
                continue;
            };
            let home_avg = if home_count == 0 {
                0.0
            } else {
                home_sum / f64::from(home_count)
            };
            let away_avg = if away_count == 0 {
                0.0
            } else {
                away_sum / f64::from(away_count)
            };
            let opponent_avg = match transition.team {
                Team::Home => away_avg,
                Team::Away => home_avg,
            };
            let centered = finite_metric(transition.reward) - opponent_avg;
            let reward = match baseline {
                Some(value) if value.is_finite() => centered - value,
                _ => centered,
            };
            self.policy_mut(transition.team)
                .update_with_reward(transition, reward);
        }
    }

    pub fn total_entries(&self) -> usize {
        self.home.q_values.len() + self.away.q_values.len()
    }

    pub fn prune(
        &mut self,
        max_action_entries_per_team: usize,
        max_target_entries_per_team: usize,
        min_visits: u32,
    ) -> SoccerTeamQPolicyPruneSummary {
        SoccerTeamQPolicyPruneSummary {
            home: self.home.prune(
                max_action_entries_per_team,
                max_target_entries_per_team,
                min_visits,
            ),
            away: self.away.prune(
                max_action_entries_per_team,
                max_target_entries_per_team,
                min_visits,
            ),
        }
    }
}

#[derive(Clone, Copy, Debug, Default)]
pub(crate) struct SoccerMarlTickReward {
    home_sum: f64,
    home_count: u32,
    home_energy_waste_sum: f64,
    away_sum: f64,
    away_count: u32,
    away_energy_waste_sum: f64,
}

impl SoccerMarlTickReward {
    fn record(&mut self, team: Team, reward: f64, energy_waste_pressure: f64) {
        let reward = finite_metric(reward);
        let energy_waste_pressure = finite_metric(energy_waste_pressure).clamp(0.0, 1.0);
        match team {
            Team::Home => {
                self.home_sum += reward;
                self.home_count = self.home_count.saturating_add(1);
                self.home_energy_waste_sum += energy_waste_pressure;
            }
            Team::Away => {
                self.away_sum += reward;
                self.away_count = self.away_count.saturating_add(1);
                self.away_energy_waste_sum += energy_waste_pressure;
            }
        }
    }

    fn average_for(self, team: Team) -> f64 {
        match team {
            Team::Home if self.home_count > 0 => self.home_sum / f64::from(self.home_count),
            Team::Away if self.away_count > 0 => self.away_sum / f64::from(self.away_count),
            _ => 0.0,
        }
    }

    fn energy_waste_average_for(self, team: Team) -> f64 {
        match team {
            Team::Home if self.home_count > 0 => {
                (self.home_energy_waste_sum / f64::from(self.home_count)).clamp(0.0, 1.0)
            }
            Team::Away if self.away_count > 0 => {
                (self.away_energy_waste_sum / f64::from(self.away_count)).clamp(0.0, 1.0)
            }
            _ => 0.0,
        }
    }

    /// Whether BOTH teams contributed at least one sample this tick. The centralized zero-sum team
    /// component (own mean − opponent mean) is only well-defined when both means exist; with only
    /// one team present `average_for(opponent)` silently returns 0.0, turning the "zero-sum" term
    /// into a one-sided bonus/penalty. See [`soccer_marl_adjusted_reward`].
    fn has_both_teams(self) -> bool {
        self.home_count > 0 && self.away_count > 0
    }
}

pub(crate) fn soccer_marl_tick_rewards(
    transitions: &[SoccerLearningTransition],
) -> HashMap<u64, SoccerMarlTickReward> {
    let mut tick_rewards = HashMap::new();
    for transition in transitions {
        tick_rewards
            .entry(transition.tick)
            .or_insert_with(SoccerMarlTickReward::default)
            .record(
                transition.team,
                transition.reward,
                transition.observation.neural_extended.energy_waste_pressure,
            );
    }
    tick_rewards
}

pub(crate) fn soccer_marl_adjusted_reward(
    transition: &SoccerLearningTransition,
    tick_rewards: &HashMap<u64, SoccerMarlTickReward>,
    config: &SoccerNeuralLearningConfig,
) -> f64 {
    let reward = finite_metric(transition.reward);
    if !config.marl_enabled() {
        return reward;
    }
    let tick_reward = tick_rewards.get(&transition.tick).copied();
    // MAPPO cooperative-credit SHARE (ours): blend the agent's individual reward toward its team's
    // per-tick mean BEFORE the centralized weighting, so off-ball work that sets up a teammate's
    // later goal is credited. Independent actor-critic stays individual even if a runner/default
    // leaves a non-zero MAPPO share in the config.
    let own_avg = tick_reward.map_or(0.0, |tr| tr.average_for(transition.team));
    let share = if config.marl_algorithm == SoccerMarlAlgorithm::Mappo {
        config.sanitized_mappo_team_reward_share()
    } else {
        0.0
    };
    let shared = (1.0 - share) * reward + share * own_avg;
    let intermediate = shared * config.sanitized_marl_intermediate_reward_weight();
    if config.marl_algorithm != SoccerMarlAlgorithm::Mappo {
        return intermediate;
    }
    // Centralized zero-sum team component (theirs): own team's tick mean minus the opponent's.
    let Some(tick_reward) = tick_reward else {
        return intermediate;
    };
    // The "zero-sum" team component is only balanced when BOTH teams logged a sample this tick.
    // In the ONLINE training path, drained deferred reward transitions (goal/shot/chain/turnover
    // credit, re-queued at their ORIGINAL tick) are trained in a batch SEPARATE from their tick's
    // 22-player cohort, so that tick often carries only the scoring team. The opponent mean then
    // defaults to 0.0 and the term degenerates into a one-sided amplification of the sparse event
    // reward (e.g. a +30 chain credit becomes +30·team_weight extra) — and inconsistently with the
    // full-game-replay path, where the same transition IS grouped with its cohort. When the
    // balanced gate is on, the team component is suppressed on such single-team ticks so the
    // centralized signal stays genuinely zero-sum. Gate OFF (default) => byte-identical.
    let team_component = soccer_marl_team_component(
        tick_reward,
        transition.team,
        dd_soccer_enable_marl_balanced_team_component(),
        dd_soccer_enable_marl_team_component_clamp().then(marl_team_component_clamp_points),
    );
    intermediate + team_component * config.sanitized_marl_team_reward_weight()
}

/// Centralized zero-sum team component for the MAPPO advantage: `own_mean − opponent_mean` over the
/// tick. When `balanced` is set and only one team logged a sample this tick, the opponent mean is
/// undefined (it would silently read 0.0 and make the term one-sided), so the component is 0.0 — see
/// [`soccer_marl_adjusted_reward`]. `balanced == false` reproduces the prior (byte-identical) term.
fn soccer_marl_team_component(
    tick_reward: SoccerMarlTickReward,
    team: Team,
    balanced: bool,
    clamp_points: Option<f64>,
) -> f64 {
    if balanced && !tick_reward.has_both_teams() {
        return 0.0;
    }
    let reward_delta = tick_reward.average_for(team) - tick_reward.average_for(team.other());
    let waste_delta = tick_reward.energy_waste_average_for(team)
        - tick_reward.energy_waste_average_for(team.other());
    let component =
        finite_metric(reward_delta - waste_delta * ENERGY_ECONOMY_MARL_TEAM_PENALTY_POINTS);
    // Bound a sparse single-team event spike (gated; None ⇒ unbounded, byte-identical).
    match clamp_points {
        Some(bound) if bound > 0.0 => component.clamp(-bound, bound),
        _ => component,
    }
}

/// The flat Monte-Carlo outcome label `z` each team carries for every transition of
/// a finished match: `+win / draw / −win`, plus a capped per-goal margin bonus, so a
/// decisive win labels harder than a 1-0. Built from the final score; `for_team`
/// returns that team's signed label. See the `MATCH_OUTCOME_*` constants.
#[derive(Clone, Copy, Debug, PartialEq)]
struct MatchOutcomeReward {
    home: f64,
    away: f64,
}

impl MatchOutcomeReward {
    fn from_score(home_goals: u32, away_goals: u32) -> Self {
        let score_diff_home = i64::from(home_goals) - i64::from(away_goals);
        Self::from_home_score_diff(score_diff_home)
    }

    fn from_home_score_diff(score_diff_home: i64) -> Self {
        let margin = score_diff_home.abs() as f64;
        let margin_bonus = MATCH_OUTCOME_PER_GOAL_MARGIN_POINTS
            * (margin - 1.0).clamp(0.0, MATCH_OUTCOME_MARGIN_CAP_GOALS - 1.0);
        let magnitude = MATCH_OUTCOME_WIN_REWARD_POINTS + margin_bonus;
        let (home, away) = match score_diff_home.cmp(&0) {
            std::cmp::Ordering::Greater => (magnitude, -magnitude),
            std::cmp::Ordering::Less => (-magnitude, magnitude),
            std::cmp::Ordering::Equal => (
                MATCH_OUTCOME_DRAW_REWARD_POINTS,
                MATCH_OUTCOME_DRAW_REWARD_POINTS,
            ),
        };
        MatchOutcomeReward { home, away }
    }

    fn for_team(&self, team: Team) -> f64 {
        match team {
            Team::Home => self.home,
            Team::Away => self.away,
        }
    }
}

fn dd_soccer_enable_outcome_credit() -> bool {
    #[cfg(test)]
    {
        soccer_env_flag_enabled(DD_SOCCER_OUTCOME_CREDIT_ENV)
    }
    #[cfg(not(test))]
    {
        use std::sync::OnceLock;
        static ENABLED: OnceLock<bool> = OnceLock::new();
        *ENABLED.get_or_init(|| soccer_env_flag_enabled(DD_SOCCER_OUTCOME_CREDIT_ENV))
    }
}

/// Env flag for the terminal won-game reward broadcast in
/// `soccer_full_game_replay_transitions`. Off ⇒ `match_outcome` is `None` and the
/// replay is byte-identical to the shaped-reward-only behaviour. Read once per
/// process (mirrors [`learned_pass_completion_enabled`]).
pub fn match_outcome_reward_enabled() -> bool {
    #[cfg(test)]
    {
        dd_soccer_enable_outcome_credit()
            || soccer_env_flag_enabled(DD_SOCCER_MATCH_OUTCOME_REWARD_ENV)
    }
    #[cfg(not(test))]
    {
        use std::sync::OnceLock;
        static ENABLED: OnceLock<bool> = OnceLock::new();
        // Promoted to default-ON in production (terminal won-game reward; training-time only).
        *ENABLED.get_or_init(|| {
            dd_soccer_enable_outcome_credit() || gate_default_on(DD_SOCCER_MATCH_OUTCOME_REWARD_ENV)
        })
    }
}

fn soccer_full_game_replay_transitions(
    transitions: &[SoccerLearningTransition],
    match_outcome: Option<MatchOutcomeReward>,
) -> Vec<SoccerLearningTransition> {
    if dd_soccer_enable_dp_bootstrap() {
        return soccer_dp_bootstrapped_replay_transitions(transitions, match_outcome);
    }
    if dd_soccer_enable_outcome_credit() {
        let outcome =
            match_outcome.or_else(|| soccer_outcome_match_reward_from_transitions(transitions));
        return soccer_outcome_credit_replay_transitions(transitions, outcome);
    }
    soccer_correlated_full_game_replay_transitions(transitions, match_outcome)
}

fn soccer_full_game_replay_transitions_with_outcome_credit(
    transitions: &[SoccerLearningTransition],
    outcome_credit: bool,
) -> Vec<SoccerLearningTransition> {
    if outcome_credit {
        return soccer_outcome_credit_replay_transitions(
            transitions,
            soccer_outcome_match_reward_from_transitions(transitions),
        );
    }
    soccer_correlated_full_game_replay_transitions(transitions, None)
}

fn soccer_correlated_full_game_replay_transitions(
    transitions: &[SoccerLearningTransition],
    match_outcome: Option<MatchOutcomeReward>,
) -> Vec<SoccerLearningTransition> {
    if transitions.is_empty() {
        return Vec::new();
    }

    let mut indices_by_tick: BTreeMap<u64, Vec<usize>> = BTreeMap::new();
    for (idx, transition) in transitions.iter().enumerate() {
        indices_by_tick
            .entry(transition.tick)
            .or_default()
            .push(idx);
    }

    let mut home_return = 0.0;
    let mut away_return = 0.0;
    let mut replay = Vec::with_capacity(transitions.len());
    for indices in indices_by_tick.values().rev() {
        let mut home_sum = 0.0;
        let mut home_count = 0usize;
        let mut away_sum = 0.0;
        let mut away_count = 0usize;
        for idx in indices {
            let reward = finite_metric(transitions[*idx].reward);
            match transitions[*idx].team {
                Team::Home => {
                    home_sum += reward;
                    home_count += 1;
                }
                Team::Away => {
                    away_sum += reward;
                    away_count += 1;
                }
            }
        }

        let home_mean = if home_count == 0 {
            0.0
        } else {
            home_sum / home_count as f64
        };
        let away_mean = if away_count == 0 {
            0.0
        } else {
            away_sum / away_count as f64
        };
        home_return = (home_mean + SOCCER_FULL_GAME_RETURN_DISCOUNT_PER_TICK * home_return)
            .clamp(-SOCCER_FULL_GAME_RETURN_CLIP, SOCCER_FULL_GAME_RETURN_CLIP);
        away_return = (away_mean + SOCCER_FULL_GAME_RETURN_DISCOUNT_PER_TICK * away_return)
            .clamp(-SOCCER_FULL_GAME_RETURN_CLIP, SOCCER_FULL_GAME_RETURN_CLIP);

        for idx in indices {
            let mut transition = transitions[*idx].clone();
            let correlated_return = match transition.team {
                Team::Home => home_return,
                Team::Away => away_return,
            };
            let blended = (1.0 - SOCCER_FULL_GAME_RETURN_BLEND) * finite_metric(transition.reward)
                + SOCCER_FULL_GAME_RETURN_BLEND * correlated_return;
            // The "long" reward: a flat per-transition outcome label, added after the
            // shaped blend so a whole game of decisions is credited by the result, not
            // just the dying ticks the 0.995 discount can reach. `None` ⇒ byte-identical.
            let with_outcome = match match_outcome {
                Some(outcome) => blended + outcome.for_team(transition.team),
                None => blended,
            };
            transition.reward =
                with_outcome.clamp(-SOCCER_FULL_GAME_RETURN_CLIP, SOCCER_FULL_GAME_RETURN_CLIP);
            transition.done = true;
            replay.push(transition);
        }
    }
    replay.reverse();
    replay
}

/// Sample-based (fitted) value iteration over the abstract-state MDP. `samples` are
/// `(bucket, reward, next_bucket)` tuples drawn from the replay; `next_bucket = None` marks a
/// terminal step (bootstraps 0 — the flat outcome label is credited separately). Each Jacobi sweep
/// sets `V(b) ← mean over samples from b of [r + γ·V(b')]`; the table is tiny so a few dozen sweeps
/// propagate value across the whole abstract MDP. Values are clamped to the shared return clip.
fn soccer_dp_value_iteration(
    samples: &[(u32, f64, Option<u32>)],
    gamma: f64,
    sweeps: usize,
) -> BTreeMap<u32, f64> {
    let mut value: BTreeMap<u32, f64> = BTreeMap::new();
    for _ in 0..sweeps {
        let mut acc: BTreeMap<u32, (f64, usize)> = BTreeMap::new();
        for (b, r, nb) in samples {
            let boot = match nb {
                Some(nb) => gamma * *value.get(nb).unwrap_or(&0.0),
                None => 0.0,
            };
            let e = acc.entry(*b).or_insert((0.0, 0));
            e.0 += *r + boot;
            e.1 += 1;
        }
        for (b, (sum, count)) in acc {
            if count > 0 {
                value.insert(
                    b,
                    (sum / count as f64)
                        .clamp(-SOCCER_FULL_GAME_RETURN_CLIP, SOCCER_FULL_GAME_RETURN_CLIP),
                );
            }
        }
    }
    value
}

/// n-step bootstrapped return starting at index `start` of one team's decision sequence `seq`
/// (`(tick, reward, bucket)` tuples): `Σ_{k<h} γ^k r_{start+k} + γ^h V(b_{start+h})`. The horizon
/// truncates the Monte-Carlo tail; when the sequence ends before the horizon fills, the tail
/// bootstraps 0 (the outcome label is added by the caller). Clamped to the shared return clip.
fn soccer_dp_nstep_return(
    seq: &[(u64, f64, u32)],
    start: usize,
    horizon: usize,
    gamma: f64,
    value: &BTreeMap<u32, f64>,
) -> f64 {
    let mut ret = 0.0;
    let mut disc = 1.0;
    for k in 0..horizon {
        let j = start + k;
        if j >= seq.len() {
            break;
        }
        ret += disc * seq[j].1;
        disc *= gamma;
        if k + 1 == horizon {
            if let Some(nb) = seq.get(j + 1).map(|n| n.2) {
                ret += disc * *value.get(&nb).unwrap_or(&0.0);
            }
        }
    }
    ret.clamp(-SOCCER_FULL_GAME_RETURN_CLIP, SOCCER_FULL_GAME_RETURN_CLIP)
}

/// Compact, team-relative abstraction of the symbolic MDP state for the DP value table. From the
/// acting team's perspective: attacking-third of the ball (x), lateral third (y), possession
/// (us/them/loose), score sign (winning/level/losing), and a team-relative phase (our-build /
/// our-attack / their-build / their-attack / kickoff / transition). Cardinality ≤ 3·3·3·3·6 = 486
/// so a single game's transitions sample it densely. Away's attacking third is mirrored so that
/// "in our attacking third" maps to the SAME bucket for both teams, pooling samples.
fn soccer_dp_state_bucket(
    state: &SoccerMdpState,
    team: Team,
    ball_x_max: usize,
    ball_y_max: usize,
) -> u32 {
    let third = |z: usize, max: usize| -> u32 {
        if max == 0 {
            return 1;
        }
        ((z as u64 * 3 / (max as u64 + 1)) as u32).min(2)
    };
    let mut x_third = third(state.ball_zone_x, ball_x_max);
    if team == Team::Away {
        x_third = 2 - x_third;
    }
    let y_third = third(state.ball_zone_y, ball_y_max);
    let poss = match state.possession_team {
        Some(t) if t == team => 0u32,
        Some(_) => 1,
        None => 2,
    };
    let sd = match team {
        Team::Home => state.score_diff_for_home,
        Team::Away => -state.score_diff_for_home,
    };
    let score_sign = if sd > 0 {
        2u32
    } else if sd < 0 {
        0
    } else {
        1
    };
    let phase = match (state.phase, team) {
        (TacticalPhase::Kickoff, _) => 4u32,
        (TacticalPhase::Transition, _) => 5,
        (TacticalPhase::HomeBuildUp, Team::Home) | (TacticalPhase::AwayBuildUp, Team::Away) => 0,
        (TacticalPhase::HomeAttack, Team::Home) | (TacticalPhase::AwayAttack, Team::Away) => 1,
        (TacticalPhase::HomeBuildUp, Team::Away) | (TacticalPhase::AwayBuildUp, Team::Home) => 2,
        (TacticalPhase::HomeAttack, Team::Away) | (TacticalPhase::AwayAttack, Team::Home) => 3,
    };
    (((x_third * 3 + y_third) * 3 + poss) * 3 + score_sign) * 6 + phase
}

/// Fitted-value-iteration replay (approximate dynamic programming). Replaces the pure Monte-Carlo
/// correlated team return of `soccer_correlated_full_game_replay_transitions` with an **n-step
/// return bootstrapped by a value-iterated abstract-state table**. The individual-reward blend,
/// flat outcome label, clamps, and `done` flag are byte-identical to the MC path, so the gate is a
/// clean A/B that changes ONLY the correlated-return quantity from full-MC to DP-bootstrapped.
fn soccer_dp_bootstrapped_replay_transitions(
    transitions: &[SoccerLearningTransition],
    match_outcome: Option<MatchOutcomeReward>,
) -> Vec<SoccerLearningTransition> {
    if transitions.is_empty() {
        return Vec::new();
    }
    let gamma = SOCCER_FULL_GAME_RETURN_DISCOUNT_PER_TICK;
    let horizon = dd_soccer_dp_bootstrap_horizon();
    let sweeps = dd_soccer_dp_bootstrap_sweeps();
    let team_index = |team: Team| -> usize {
        match team {
            Team::Home => 0,
            Team::Away => 1,
        }
    };

    // Ball-zone extents for adaptive thirds.
    let mut ball_x_max = 0usize;
    let mut ball_y_max = 0usize;
    for t in transitions {
        ball_x_max = ball_x_max.max(t.state.ball_zone_x);
        ball_y_max = ball_y_max.max(t.state.ball_zone_y);
    }

    // Per-team decision sequences (tick-sorted): mean team reward + abstract bucket at each tick.
    let mut by_tick: BTreeMap<u64, [(f64, usize, u32); 2]> = BTreeMap::new();
    for t in transitions {
        let bucket = soccer_dp_state_bucket(&t.state, t.team, ball_x_max, ball_y_max);
        let slot = &mut by_tick.entry(t.tick).or_insert([(0.0, 0, 0); 2])[team_index(t.team)];
        slot.0 += finite_metric(t.reward);
        slot.1 += 1;
        slot.2 = bucket;
    }
    let mut seq: [Vec<(u64, f64, u32)>; 2] = [Vec::new(), Vec::new()];
    for (tick, slots) in &by_tick {
        for (ti, slot) in slots.iter().enumerate() {
            let (sum, count, bucket) = *slot;
            if count > 0 {
                seq[ti].push((*tick, sum / count as f64, bucket));
            }
        }
    }

    // Sample-based value iteration over pooled (bucket, reward, next_bucket) tuples from both teams.
    let mut samples: Vec<(u32, f64, Option<u32>)> = Vec::new();
    for s in &seq {
        for i in 0..s.len() {
            samples.push((s[i].2, s[i].1, s.get(i + 1).map(|n| n.2)));
        }
    }
    let value = soccer_dp_value_iteration(&samples, gamma, sweeps);

    // n-step bootstrapped correlated return per (team, tick).
    let mut correlated: BTreeMap<(usize, u64), f64> = BTreeMap::new();
    for (ti, s) in seq.iter().enumerate() {
        for i in 0..s.len() {
            correlated.insert(
                (ti, s[i].0),
                soccer_dp_nstep_return(s, i, horizon, gamma, &value),
            );
        }
    }

    // Assemble replay: identical blend / outcome / clamp / done to the MC correlated path.
    let mut replay = Vec::with_capacity(transitions.len());
    for t in transitions {
        let mut transition = t.clone();
        let corr = correlated
            .get(&(team_index(transition.team), transition.tick))
            .copied()
            .unwrap_or(0.0);
        let blended = (1.0 - SOCCER_FULL_GAME_RETURN_BLEND) * finite_metric(transition.reward)
            + SOCCER_FULL_GAME_RETURN_BLEND * corr;
        let with_outcome = match match_outcome {
            Some(outcome) => blended + outcome.for_team(transition.team),
            None => blended,
        };
        transition.reward =
            with_outcome.clamp(-SOCCER_FULL_GAME_RETURN_CLIP, SOCCER_FULL_GAME_RETURN_CLIP);
        transition.done = true;
        replay.push(transition);
    }
    replay
}

#[cfg(test)]
mod soccer_dp_bootstrap_tests {
    use super::*;

    #[test]
    fn value_iteration_propagates_reward_backward_through_chain() {
        // Chain 0 -> 1 -> 2, with reward 10 collected on the terminal step out of bucket 2.
        // Fitted VI should give V(2)=10, V(1)=γ·10, V(0)=γ²·10 (monotone, all positive).
        let samples = vec![
            (0u32, 0.0, Some(1u32)),
            (1u32, 0.0, Some(2u32)),
            (2u32, 10.0, None),
        ];
        let gamma = 0.9;
        let v = soccer_dp_value_iteration(&samples, gamma, 80);
        let v0 = *v.get(&0).unwrap();
        let v1 = *v.get(&1).unwrap();
        let v2 = *v.get(&2).unwrap();
        assert!((v2 - 10.0).abs() < 1e-6, "terminal-reward bucket = raw reward");
        assert!((v1 - gamma * 10.0).abs() < 1e-6, "one step back discounts once");
        assert!(
            (v0 - gamma * gamma * 10.0).abs() < 1e-6,
            "two steps back discounts twice"
        );
        assert!(v0 > 0.0 && v0 < v1 && v1 < v2, "value rises toward the reward");
    }

    #[test]
    fn value_iteration_empty_is_empty() {
        assert!(soccer_dp_value_iteration(&[], 0.98, 40).is_empty());
    }

    #[test]
    fn nstep_return_truncates_horizon_and_bootstraps_value() {
        // seq of (tick, reward, bucket); constant reward 1, all bucket 0; V(0)=5.
        let seq = vec![(0u64, 1.0, 0u32), (1, 1.0, 0), (2, 1.0, 0), (3, 1.0, 0)];
        let mut value = BTreeMap::new();
        value.insert(0u32, 5.0);
        let gamma = 0.9;
        // horizon 2 from start 0: 1 + γ·1 + γ²·V(0) = 1 + 0.9 + 0.81·5 = 5.95.
        let r = soccer_dp_nstep_return(&seq, 0, 2, gamma, &value);
        assert!((r - 5.95).abs() < 1e-6, "n-step = discounted rewards + bootstrap, got {r}");
        // At the tail (start 3) the window can't fill and has no successor ⇒ no bootstrap ⇒ just 1.0.
        let tail = soccer_dp_nstep_return(&seq, 3, 2, gamma, &value);
        assert!((tail - 1.0).abs() < 1e-6, "terminal tail bootstraps 0, got {tail}");
    }

    #[test]
    fn nstep_return_without_value_table_is_plain_discounted_sum() {
        // Empty value table ⇒ bootstrap term is 0 ⇒ pure n-step Monte-Carlo sum.
        let seq = vec![(0u64, 2.0, 7u32), (1, 2.0, 7), (2, 2.0, 7)];
        let empty = BTreeMap::new();
        let r = soccer_dp_nstep_return(&seq, 0, 2, 0.5, &empty);
        // 2 + 0.5·2 + 0.25·V(7=absent→0) = 3.0.
        assert!((r - 3.0).abs() < 1e-9, "got {r}");
    }
}

fn soccer_outcome_credit_replay_transitions(
    transitions: &[SoccerLearningTransition],
    match_outcome: Option<MatchOutcomeReward>,
) -> Vec<SoccerLearningTransition> {
    if transitions.is_empty() {
        return Vec::new();
    }

    let mut indices: Vec<usize> = (0..transitions.len()).collect();
    indices.sort_by_key(|&idx| (transitions[idx].tick, idx));

    let mut replay = Vec::with_capacity(transitions.len());
    for idx in indices {
        let mut transition = transitions[idx].clone();
        let outcome_reward = match_outcome
            .map(|outcome| outcome.for_team(transition.team))
            .unwrap_or(0.0);
        let milestone_reward = soccer_outcome_credit_milestone_reward(&transition);
        let pitch_shaping = soccer_outcome_credit_pitch_value_shaping(&transition);
        transition.reward = finite_metric(outcome_reward + milestone_reward + pitch_shaping)
            .clamp(-SOCCER_FULL_GAME_RETURN_CLIP, SOCCER_FULL_GAME_RETURN_CLIP);
        transition.done = true;
        replay.push(transition);
    }
    replay
}

fn soccer_outcome_credit_milestone_reward(transition: &SoccerLearningTransition) -> f64 {
    // Keep bounded short-term quasi-wins already folded into the transition reward:
    // pass chains, defender-beating dribbles, shots on target, and goals.
    finite_metric(transition.reward)
        .max(0.0)
        .min(SOCCER_OUTCOME_CREDIT_MILESTONE_REWARD_CAP)
}

fn soccer_outcome_match_reward_from_transitions(
    transitions: &[SoccerLearningTransition],
) -> Option<MatchOutcomeReward> {
    let mut latest: Option<(u64, usize, i32)> = None;
    for (idx, transition) in transitions.iter().enumerate() {
        let candidate = (
            transition.tick,
            idx,
            transition.next_state.score_diff_for_home,
        );
        if latest
            .map(|current| (candidate.0, candidate.1) > (current.0, current.1))
            .unwrap_or(true)
        {
            latest = Some(candidate);
        }
    }
    latest.map(|(_, _, score_diff)| MatchOutcomeReward::from_home_score_diff(i64::from(score_diff)))
}

fn soccer_outcome_credit_pitch_value_shaping(transition: &SoccerLearningTransition) -> f64 {
    let scale = tunables().reward.pitch_value_threat_delta_points;
    if scale <= 0.0 || !scale.is_finite() {
        return 0.0;
    }
    let before = soccer_replay_pitch_value_potential(&transition.state, transition.team);
    let after = soccer_replay_pitch_value_potential(&transition.next_state, transition.team);
    // P3 (discount alignment): use the learner's γ when the shaping-discipline is on,
    // else γ=1.0 (byte-identical). PBRS is only policy-invariant when its γ matches the
    // discount the returns use; `disciplined_gamma` closes that gap behind the gate.
    potential_based_shaping(disciplined_gamma(), before, after) * scale
}

fn soccer_replay_pitch_value_potential(state: &SoccerMdpState, team: Team) -> f64 {
    let Some(possession_team) = state.possession_team else {
        return 0.0;
    };
    let point = soccer_replay_ball_grid_center(state);
    let threat = expected_threat(
        possession_team,
        point,
        DEFAULT_FIELD_WIDTH_YARDS,
        DEFAULT_FIELD_LENGTH_YARDS,
    );
    if possession_team == team {
        threat
    } else {
        -threat
    }
}

fn soccer_replay_ball_grid_center(state: &SoccerMdpState) -> Vec2 {
    let cell = if state.ball_grid.fine.columns > 1 || state.ball_grid.fine.rows > 1 {
        state.ball_grid.fine
    } else if state.ball_grid.tactical.columns > 1 || state.ball_grid.tactical.rows > 1 {
        state.ball_grid.tactical
    } else {
        let columns = PITCH_TACTICAL_GRID_COLUMNS.max(1);
        let rows = PITCH_TACTICAL_GRID_ROWS.max(1);
        PitchGridCell {
            level: PitchGridLevel::Tactical,
            columns,
            rows,
            x: state.ball_zone_x.min(columns - 1),
            y: state.ball_zone_y.min(rows - 1),
            id: state.ball_zone_y.min(rows - 1) * columns + state.ball_zone_x.min(columns - 1),
            parent_id: Some(0),
        }
    };
    let columns = cell.columns.max(1);
    let rows = cell.rows.max(1);
    let x = cell.x.min(columns - 1);
    let y = cell.y.min(rows - 1);
    Vec2::new(
        (x as f64 + 0.5) * DEFAULT_FIELD_WIDTH_YARDS / columns as f64,
        (y as f64 + 0.5) * DEFAULT_FIELD_LENGTH_YARDS / rows as f64,
    )
}

