fn ranked_pass_action_family(action: &str) -> Option<&'static str> {
    ["pass", "aerial-pass"].iter().copied().find(|prefix| {
        action
            .strip_prefix(prefix)
            .is_some_and(|suffix| !suffix.is_empty() && suffix.bytes().all(|b| b.is_ascii_digit()))
    })
}

fn learned_discretized_kick_suffix_parts(action: &str) -> Option<(&str, u8)> {
    let (base, suffix) = action.trim().rsplit_once("-kp")?;
    let bucket = suffix.parse::<u8>().ok()?;
    if bucket >= DISCRETIZED_KICK_SPEED_BUCKETS || ranked_pass_action_family(base).is_none() {
        return None;
    }
    Some((base, bucket))
}

pub(crate) fn learned_discretized_kick_candidate_label(base: &str, bucket: u8) -> Option<String> {
    let base = base.trim();
    if bucket >= DISCRETIZED_KICK_SPEED_BUCKETS || ranked_pass_action_family(base).is_none() {
        return None;
    }
    Some(format!("{base}-kp{bucket}"))
}

pub(crate) fn learned_discretized_kick_speed_bucket_for_action_label(action: &str) -> Option<u8> {
    learned_discretized_kick_suffix_parts(action).map(|(_, bucket)| bucket)
}

pub(crate) fn learned_discretized_kick_power_for_action_label(action: &str) -> Option<f64> {
    learned_discretized_kick_speed_bucket_for_action_label(action)
        .map(|bucket| discretized_kick_power_for_bucket(bucket, DiscretizedKickDither::none()))
}

pub(crate) fn learned_discretized_kick_power_is_authoritative(power: f64) -> bool {
    power.is_finite()
        && (0..DISCRETIZED_KICK_SPEED_BUCKETS).any(|bucket| {
            (power - discretized_kick_power_for_bucket(bucket, DiscretizedKickDither::none())).abs()
                <= 1e-9
        })
}

fn normalize_soccer_action_label(action: &str) -> &str {
    let action = learned_discretized_kick_suffix_parts(action)
        .map(|(base, _)| base)
        .unwrap_or(action);
    if let Some(family) = ranked_pass_action_family(action) {
        return family;
    }
    // Alias -> canonical mapping is centralised in `SoccerActionLabel`
    // (soccer/labels.rs). Unrecognised labels pass straight through with no
    // allocation, exactly as the old `other => other` arm did.
    SoccerActionLabel::canonical_str(action).unwrap_or(action)
}

fn learned_mpc_action_label_key(action: &str) -> String {
    let trimmed = action.trim();
    if ranked_pass_action_label(trimmed) {
        trimmed.to_string()
    } else {
        normalize_soccer_action_label(trimmed).to_string()
    }
}

fn learned_mpc_action_labels_match(left: &str, right: &str) -> bool {
    learned_mpc_action_label_key(left) == learned_mpc_action_label_key(right)
}

fn ranked_pass_action_label(action: &str) -> bool {
    let action = learned_discretized_kick_suffix_parts(action)
        .map(|(base, _)| base)
        .unwrap_or(action);
    ranked_pass_action_family(action).is_some()
}

// FLANK_CROSS_MIN_FLANK_SCORE / FLANK_CROSS_MAX_YARDS_TO_GOAL moved to
// `tunables().flank_cross` (env/Postgres-overridable). See soccer/tunables.rs.
const FLANK_OVERLAP_MIN_OPTION_SHARE: f64 = 1.0 / 3.0;

/// Master switch for the "attacking ambition" bundle: more frequent wall-passes
/// (give-and-goes), and crosses available from a touch deeper / narrower so the
/// flanks are actually used as a delivery route, not just for runs that fizzle.
/// ON by default; set `DD_SOCCER_DISABLE_ATTACK_AMBITION` to fall back to the
/// tighter baseline gates (used for A/B and to revert without a redeploy). The
/// switch only ever *widens availability* — every quality/risk/offside check that
/// follows still applies, so a poor combination is still demoted, never forced.
pub(crate) fn attack_ambition_enabled() -> bool {
    use std::sync::OnceLock;
    static V: OnceLock<bool> = OnceLock::new();
    !*V.get_or_init(|| std::env::var("DD_SOCCER_DISABLE_ATTACK_AMBITION").is_ok())
}

/// Whether **formation-hold tightening** is active this process: off-ball players are held closer to
/// their formation home (tighter shape radii) AND a roaming/support/press option is bounded to a
/// generous role radius instead of being unclamped — so the eleven maintain their positions and keep
/// the pitch spread instead of drifting ~20yd off formation and bunching. **Default-ON in production**
/// (`DD_SOCCER_ENABLE_FORMATION_HOLD_TIGHTEN=0/false/no/off` is the kill switch), read once.
/// **Default-OFF under test** so the shape/parity suites stay byte-identical unless a test opts in.
pub(crate) fn formation_hold_tighten_enabled() -> bool {
    #[cfg(test)]
    {
        soccer_env_flag_enabled("DD_SOCCER_ENABLE_FORMATION_HOLD_TIGHTEN")
    }
    #[cfg(not(test))]
    {
        use std::sync::OnceLock;
        static V: OnceLock<bool> = OnceLock::new();
        *V.get_or_init(|| gate_default_on("DD_SOCCER_ENABLE_FORMATION_HOLD_TIGHTEN"))
    }
}

/// Whether the **loose-ball opponent-pace match** is active this process: an elected
/// 1–2 chaser sprints for a loose ball when the nearest opponent has committed a
/// run/sprint at the contest point, keeping the 50/50 a real race rather than jogging
/// and conceding it. **Default-ON in production**
/// (`DD_SOCCER_ENABLE_LOOSE_BALL_OPPONENT_PACE_MATCH=0/false/no/off` is the kill
/// switch), read once. **Default-OFF under test** so the loose-ball gait/parity suites
/// stay byte-identical unless a test opts in. Only the chase gait is affected — who is
/// elected to chase, and where they run, is unchanged.
pub(crate) fn loose_ball_opponent_pace_match_enabled() -> bool {
    #[cfg(test)]
    {
        soccer_env_flag_enabled("DD_SOCCER_ENABLE_LOOSE_BALL_OPPONENT_PACE_MATCH")
    }
    #[cfg(not(test))]
    {
        use std::sync::OnceLock;
        static V: OnceLock<bool> = OnceLock::new();
        *V.get_or_init(|| gate_default_on("DD_SOCCER_ENABLE_LOOSE_BALL_OPPONENT_PACE_MATCH"))
    }
}

/// Whether the **raised scoop apex** is active this process: a blocked-lane scoop chips ~10-13ft
/// (`SCOOP_LOFT_APEX_HIGH_*`) instead of 6-9ft so it clears an upright/jumping defender stood in
/// the lane, not just a standing foot. **Default-ON in production**
/// (`DD_SOCCER_ENABLE_SCOOP_HIGHER_APEX=0/false/no/off` is the kill switch), read once. **Default-OFF
/// under test** so the loft-arc / interception parity suites stay byte-identical unless a test opts in.
pub(crate) fn scoop_higher_apex_enabled() -> bool {
    #[cfg(test)]
    {
        std::env::var("DD_SOCCER_ENABLE_SCOOP_HIGHER_APEX")
            .map(|raw| {
                let v = raw.trim().to_ascii_lowercase();
                matches!(v.as_str(), "1" | "true" | "yes" | "on")
            })
            .unwrap_or(false)
    }
    #[cfg(not(test))]
    {
        use std::sync::OnceLock;
        static V: OnceLock<bool> = OnceLock::new();
        *V.get_or_init(|| gate_default_on("DD_SOCCER_ENABLE_SCOOP_HIGHER_APEX"))
    }
}

/// Whether the **scoop land-on-the-receiver physics fix** is active (gate
/// `DD_SOCCER_ENABLE_SCOOP_LAND_AT_TARGET`, default-ON prod / OFF test). Fixes the "hot-air-balloon"
/// float — a scoop that reaches the receiver's spot then HANGS in the air descending instead of
/// obeying gravity. Two decouplings caused it: (1) the launch speed was paced from a FIXED apex
/// (unit 0.5) while the in-flight altitude clock flew a RANDOM apex, so the gravity hang time the
/// ball actually flew differed from the one its pace was calibrated for; (2) the fixed 16mph
/// min-speed floor over-paced SHORT scoops, landing them at the receiver's spot in a fraction of
/// the hang time. When ON, the scoop apex is deterministic (unit 0.5 — pace and flight agree) and
/// the speed floor is capped at the land-at-target pace, so the chip arrives in ~one hang time and
/// DROPS onto the man. OFF ⇒ byte-identical (random apex + fixed floor).
pub(crate) fn scoop_land_at_target_enabled() -> bool {
    #[cfg(test)]
    {
        std::env::var("DD_SOCCER_ENABLE_SCOOP_LAND_AT_TARGET")
            .map(|raw| {
                let v = raw.trim().to_ascii_lowercase();
                matches!(v.as_str(), "1" | "true" | "yes" | "on")
            })
            .unwrap_or(false)
    }
    #[cfg(not(test))]
    {
        use std::sync::OnceLock;
        static V: OnceLock<bool> = OnceLock::new();
        *V.get_or_init(|| gate_default_on("DD_SOCCER_ENABLE_SCOOP_LAND_AT_TARGET"))
    }
}

/// The per-pass apex "unit" (0..1) for a scoop's loft, given its launch seed. Without the
/// land-at-target fix this is hashed off `launch_tick`/`from` for cosmetic variation; WITH the fix
/// it collapses to a deterministic 0.5 so the apex the ball flies matches the apex its launch speed
/// was paced from (see `scoop_land_at_target_enabled`). Shared by the live-flight and snapshot apex
/// readers so they never disagree.
fn scoop_apex_unit(launch_tick: u64, from_id: usize) -> f64 {
    if scoop_land_at_target_enabled() {
        return 0.5;
    }
    let seed = launch_tick.wrapping_mul(0x9E37_79B9_7F4A_7C15) ^ (from_id as u64).wrapping_shl(17);
    ((seed >> 40) & 0xFFFF) as f64 / 65535.0
}

/// Whether the **moderate give-and-go live-frequency bump** is active this process: a modest
/// extra widening of the wall-pass trigger zone and a lift on the carrier's appetite to combine,
/// so more one-twos actually appear in live play. **Default-ON in production**
/// (`DD_SOCCER_ENABLE_GIVE_AND_GO_AMBITION=0/false/no/off` is the kill switch), read once.
/// **Default-OFF under test** so the option-scoring parity suite stays byte-identical (the bump
/// only ever *widens availability* / lifts a propensity — every quality/onside/lane check still
/// applies, so a poor combination is still demoted, never forced).
pub(crate) fn give_and_go_ambition_enabled() -> bool {
    #[cfg(test)]
    {
        // Default-OFF + env-driven under test (re-read each call) so the parity suite stays
        // byte-identical and a test can toggle it explicitly.
        std::env::var("DD_SOCCER_ENABLE_GIVE_AND_GO_AMBITION")
            .map(|raw| {
                let v = raw.trim().to_ascii_lowercase();
                matches!(v.as_str(), "1" | "true" | "yes" | "on")
            })
            .unwrap_or(false)
    }
    #[cfg(not(test))]
    {
        use std::sync::OnceLock;
        static V: OnceLock<bool> = OnceLock::new();
        *V.get_or_init(|| gate_default_on("DD_SOCCER_ENABLE_GIVE_AND_GO_AMBITION"))
    }
}

/// Scale the scoop-pass option's propensity (and its floor) by how likely the lofted ball
/// actually reaches the target. The scoop option was scored from TECHNIQUE alone and then
/// floored to a 52-64% share, so a chip into a covered lane (aerial interception risk high /
/// aerial completion ~0) won a majority of the probability mass regardless of outcome — the
/// live "passes straight to the opponent". Default-ON; kill switch
/// `DD_SOCCER_ENABLE_SCOOP_COMPLETION_GATE=0` restores the technique-only propensity. Under
/// test it is default-OFF + env-driven so the parity suite stays byte-identical.
pub(crate) fn dd_soccer_enable_scoop_completion_gate() -> bool {
    #[cfg(test)]
    {
        std::env::var("DD_SOCCER_ENABLE_SCOOP_COMPLETION_GATE")
            .map(|raw| {
                let v = raw.trim().to_ascii_lowercase();
                matches!(v.as_str(), "1" | "true" | "yes" | "on")
            })
            .unwrap_or(false)
    }
    #[cfg(not(test))]
    {
        use std::sync::OnceLock;
        static V: OnceLock<bool> = OnceLock::new();
        *V.get_or_init(|| gate_default_on("DD_SOCCER_ENABLE_SCOOP_COMPLETION_GATE"))
    }
}

/// Viability factor in `[0, 1]` for a lofted scoop pass: high only when the ball is both likely
/// to reach the target (`expected_aerial_pass_completion`) AND not sitting in a cuttable flight
/// lane (`aerial_pass_interception_risk`). A receiver can be wide open yet a defender cuts the
/// arc, so BOTH must be favourable. `SCOOP_COMPLETION_GATE_FLOOR` keeps a genuinely technical
/// chip alive rather than zeroing it, so a good scoop still competes; a giveaway collapses.
pub(crate) fn scoop_completion_viability(observation: &SoccerPomdpObservation) -> f64 {
    let completion = observation.expected_aerial_pass_completion.clamp(0.0, 1.0);
    let lane_open = 1.0 - observation.aerial_pass_interception_risk.clamp(0.0, 1.0);
    (completion * lane_open).clamp(0.0, 1.0)
}

fn pass_like_action_flight(action: &str) -> Option<PassFlight> {
    use SoccerActionLabel::*;
    match SoccerActionLabel::classify(normalize_soccer_action_label(action))? {
        Pass | FirstTimePass | FlankLowCross | WallPass | WallReturn | CornerFlagCross
        | SurprisePass | KillerPass | SwitchPlay | RecycleReset => Some(PassFlight::Floor),
        ScoopPass => Some(PassFlight::Scoop),
        AerialPass | FlankHighCross | FlickOn => Some(PassFlight::Aerial),
        _ => None,
    }
}

fn flank_cross_context_score(
    observation: &SoccerPomdpObservation,
    player_position: Vec2,
    field_width_yards: f64,
) -> f64 {
    let cfg = &tunables().flank_cross;
    let flank = flank_lane_score(player_position, field_width_yards).clamp(0.0, 1.0);
    let attacking_depth = (1.0 - observation.yards_to_goal / cfg.max_yards_to_goal).clamp(0.0, 1.0);
    let pressure_release = (observation.perceived_pressure * cfg.perceived_pressure_weight
        + observation.pressure_urgency * cfg.pressure_urgency_weight)
        .clamp(0.0, cfg.pressure_release_cap);
    (flank * cfg.flank_weight + attacking_depth * cfg.attacking_depth_weight + pressure_release)
        .clamp(0.0, 1.0)
}

fn flank_cross_context_is_legal(
    observation: &SoccerPomdpObservation,
    player_position: Vec2,
    field_width_yards: f64,
) -> bool {
    let cfg = &tunables().flank_cross;
    // Attacking ambition: let a wide carrier cross from a touch deeper and a touch
    // narrower so the flanks become a real delivery route (the overlap runs were
    // already firing; the cross at the end of them was not). The scoring still
    // demotes a poor cross — this only opens the door.
    let (max_yards_to_goal, min_flank_score) = if attack_ambition_enabled() {
        (
            (cfg.max_yards_to_goal + 8.0).min(120.0),
            (cfg.min_flank_score - 0.12).max(0.0),
        )
    } else {
        (cfg.max_yards_to_goal, cfg.min_flank_score)
    };
    observation.has_ball
        && observation.yards_to_goal <= max_yards_to_goal
        && flank_lane_score(player_position, field_width_yards).clamp(0.0, 1.0) >= min_flank_score
}

pub(crate) fn pitch_fine_lane_for_position(position: Vec2, field_width_yards: f64) -> usize {
    zone(
        position.x,
        field_width_yards.max(1.0),
        PITCH_FINE_GRID_COLUMNS,
    )
}

pub(crate) fn position_in_outer_flank_fine_lanes(position: Vec2, field_width_yards: f64) -> bool {
    let lane = pitch_fine_lane_for_position(position, field_width_yards);
    let right_flank_start =
        PITCH_FINE_GRID_COLUMNS.saturating_sub(CRASH_BOX_OUTER_FLANK_FINE_LANES);
    lane < CRASH_BOX_OUTER_FLANK_FINE_LANES || lane >= right_flank_start
}

pub(crate) fn position_in_opponent_final_third(
    team: Team,
    position: Vec2,
    field_length_yards: f64,
) -> bool {
    if !position.y.is_finite() || field_length_yards <= 0.0 {
        return false;
    }
    let distance_to_goal = (team.goal_y(field_length_yards) - position.y).abs();
    distance_to_goal <= field_length_yards / 3.0
        && (position.y - field_length_yards * 0.5) * team.attack_dir() > 0.0
}

pub(crate) fn wide_final_third_cross_lane_context(
    team: Team,
    position: Vec2,
    field_width_yards: f64,
    field_length_yards: f64,
) -> bool {
    position_in_outer_flank_fine_lanes(position, field_width_yards)
        && position_in_opponent_final_third(team, position, field_length_yards)
}

fn is_attacking_support_action_label(action: &str) -> bool {
    use SoccerActionLabel::*;
    matches!(
        SoccerActionLabel::classify(action),
        Some(
            Space
                | SupportShape
                | SupportRoam
                | CheckToBall
                | RunInBehind
                | ExploitSpaceRun
                | WideOutlet
                | ShotCreationRun
                | PinchCrossArrival
                | OverlapRun
                | SupportScreen
                | SupportPushUp
                | VerticalAttack
                | VacateSpace
                | DummyClearLane
                | DummyLetRun
                | LaneYield
                | OneTwoRun
                | BuildupReceive
        )
    )
}

fn dribble_move_kind_for_action_label(action: &str) -> Option<DribbleMoveKind> {
    use SoccerActionLabel::*;
    match SoccerActionLabel::classify(action)? {
        LeftCut | SideStep | Dribble | HoldUpFlank | OpenPassingLane | OpenPassLane => {
            Some(DribbleMoveKind::LeftCut)
        }
        CarryForward | VerticalAttack | TurnoverBurst | RoundGoalkeeper | RunaroundDribble => {
            Some(DribbleMoveKind::CarryForward)
        }
        ProtectBall => Some(DribbleMoveKind::ProtectBall),
        XaviTurn => Some(DribbleMoveKind::XaviTurn),
        RightCut => Some(DribbleMoveKind::RightCut),
        Nutmeg => Some(DribbleMoveKind::Nutmeg),
        CarryOutLeft => Some(DribbleMoveKind::CarryOutLeft),
        CarryOutRight => Some(DribbleMoveKind::CarryOutRight),
        FakeLeftCutRight => Some(DribbleMoveKind::FakeLeftCutRight),
        FakeRightCutLeft => Some(DribbleMoveKind::FakeRightCutLeft),
        _ => None,
    }
}

fn is_dribble_action_label(action: &str) -> bool {
    dribble_move_kind_for_action_label(action).is_some()
}

fn dribble_final_cut_kind(kind: DribbleMoveKind) -> DribbleMoveKind {
    match kind {
        DribbleMoveKind::FakeLeftCutRight => DribbleMoveKind::RightCut,
        DribbleMoveKind::FakeRightCutLeft => DribbleMoveKind::LeftCut,
        other => other,
    }
}

fn dribble_touch_bucket_components(bucket: u8) -> (f64, f64) {
    let angle = (bucket % DRIBBLE_TOUCH_ANGLE_BUCKETS) as f64 * DRIBBLE_TOUCH_BUCKET_DEGREES;
    let radians = angle.to_radians();
    (radians.sin(), radians.cos())
}

fn dribble_touch_forward_class(bucket: u8) -> i8 {
    let (_, forward) = dribble_touch_bucket_components(bucket);
    if forward > 0.20 {
        1
    } else if forward < -0.20 {
        -1
    } else {
        0
    }
}

fn dribble_touch_distance_bin(distance_yards: f64) -> u8 {
    distance_bucket(
        distance_yards.clamp(0.0, DRIBBLE_MAX_TOUCH_YARDS),
        &[1.2, 2.0, 3.5, 5.0],
    )
}

fn dribble_touch_angle_weight(kind: DribbleMoveKind, bucket: u8) -> f64 {
    let (lateral, forward) = dribble_touch_bucket_components(bucket);
    let forward_weight = if forward > 0.20 {
        DRIBBLE_FORWARD_ANGLE_WEIGHT
    } else if forward < -0.20 {
        DRIBBLE_BACKWARD_ANGLE_WEIGHT
    } else {
        DRIBBLE_LATERAL_ANGLE_WEIGHT
    };
    let kind_weight = match dribble_final_cut_kind(kind) {
        DribbleMoveKind::CarryForward => {
            if forward > 0.58 {
                3.20
            } else if forward > 0.20 {
                1.55
            } else {
                0.18
            }
        }
        DribbleMoveKind::CarryOutLeft | DribbleMoveKind::CarryOutRight => {
            let diagonal = lateral.abs() * forward.max(0.0);
            if forward > 0.20 {
                0.80 + diagonal * 2.40 + lateral.abs() * 0.42
            } else if lateral.abs() > 0.55 {
                0.72
            } else {
                0.18
            }
        }
        DribbleMoveKind::ProtectBall => {
            if forward < -0.20 {
                1.55
            } else if lateral.abs() > 0.35 {
                1.18
            } else {
                0.50
            }
        }
        DribbleMoveKind::LeftCut => {
            if lateral < -0.20 {
                2.20
            } else if lateral > 0.20 {
                0.55
            } else {
                1.05
            }
        }
        DribbleMoveKind::RightCut => {
            if lateral > 0.20 {
                2.20
            } else if lateral < -0.20 {
                0.55
            } else {
                1.05
            }
        }
        DribbleMoveKind::Nutmeg => {
            let through_lane = forward.max(0.0).powi(2);
            0.45 + through_lane * 2.75
        }
        // The xavi-turn drags the ball laterally/behind on the shielded side as the body
        // wheels around — favour the across-and-back angles, never straight forward into
        // the defender (mirrors the protect-ball shielding weighting).
        DribbleMoveKind::XaviTurn => {
            if forward < -0.20 {
                1.70
            } else if lateral.abs() > 0.35 {
                1.40
            } else {
                0.40
            }
        }
        DribbleMoveKind::FakeLeftCutRight | DribbleMoveKind::FakeRightCutLeft => {
            unreachable!("feints are resolved into their final cut before angle weighting")
        }
    };
    let feint_bonus = if matches!(
        kind,
        DribbleMoveKind::FakeLeftCutRight | DribbleMoveKind::FakeRightCutLeft
    ) {
        1.08
    } else {
        1.0
    };
    (forward_weight * kind_weight * feint_bonus).max(0.01)
}

fn deterministic_unit_draw(tick: u64, player_id: usize, salt: u64) -> f64 {
    let mut value = tick
        .wrapping_mul(0x9e37_79b9_7f4a_7c15)
        .wrapping_add((player_id as u64).wrapping_mul(0xbf58_476d_1ce4_e5b9))
        .wrapping_add(salt.wrapping_mul(0x94d0_49bb_1331_11eb));
    value ^= value >> 30;
    value = value.wrapping_mul(0xbf58_476d_1ce4_e5b9);
    value ^= value >> 27;
    value = value.wrapping_mul(0x94d0_49bb_1331_11eb);
    value ^= value >> 31;
    (value % 10_000) as f64 / 10_000.0
}

fn smoothstep_unit(value: f64) -> f64 {
    let value = if value.is_finite() {
        value.clamp(0.0, 1.0)
    } else {
        0.0
    };
    value * value * (3.0 - 2.0 * value)
}

fn logistic_probability(score: f64) -> f64 {
    if score.is_nan() {
        return 0.5;
    }
    if score == f64::INFINITY {
        return 1.0;
    }
    if score == f64::NEG_INFINITY {
        return 0.0;
    }
    if score >= 0.0 {
        1.0 / (1.0 + (-score).exp())
    } else {
        let exp_score = score.exp();
        exp_score / (1.0 + exp_score)
    }
}

fn probability_with_odds_multiplier(probability: f64, multiplier: f64) -> f64 {
    let probability = if probability.is_finite() {
        probability.clamp(0.0, 1.0)
    } else {
        0.0
    };
    let multiplier = if multiplier.is_finite() {
        multiplier.max(0.0)
    } else {
        0.0
    };
    if probability <= 0.0 || multiplier <= 0.0 {
        return 0.0;
    }
    if probability >= 1.0 {
        return 1.0;
    }
    let odds = probability / (1.0 - probability);
    let adjusted_odds = odds * multiplier;
    (adjusted_odds / (1.0 + adjusted_odds)).clamp(0.0, 1.0)
}

fn is_untargeted_long_ball_action(action: &str) -> bool {
    use SoccerActionLabel::*;
    matches!(
        SoccerActionLabel::classify(action),
        Some(Clearance | RouteOne | LongBallFlight)
    )
}

fn offside_exempt_restart_action(action: &str) -> bool {
    use RestartLabel::*;
    matches!(
        RestartLabel::from_canonical(normalize_soccer_action_label(action)),
        Some(ThrowIn | GoalKick | CornerKick)
    )
}

fn restart_action_label(action: &str) -> Option<&'static str> {
    use RestartLabel::*;
    let restart = RestartLabel::from_canonical(normalize_soccer_action_label(action))?;
    match restart {
        Kickoff | ThrowIn | GoalKick | CornerKick | FreeKick => Some(restart.as_str()),
        // Offside is restarted with an indirect free kick: the taker must play it
        // to a teammate (no dribble), so the double-touch can't happen by design.
        Offside => Some(FreeKick.as_str()),
        DirectFreeKick | IndirectFreeKick => None,
    }
}

fn canonical_set_play_restart_label(label: &str) -> Option<&'static str> {
    let normalized = normalize_soccer_action_label(label.trim());
    if let Some(restart) = RestartLabel::from_canonical(normalized) {
        // Offside is not a set-play restart label here (falls through to the
        // CSV-header aliasing below, which yields None for it) — preserve that.
        if restart != RestartLabel::Offside {
            return Some(restart.as_str());
        }
    }

    match normalize_csv_header(normalized).as_str() {
        "kickoff" | "kickoffpattern" => Some("kickoff"),
        "throwin" | "throw" => Some("throw-in"),
        "goalkick" => Some("goal-kick"),
        "cornerkick" | "corner" => Some("corner-kick"),
        "freekick" | "fk" => Some("free-kick"),
        "directfreekick" | "directfk" | "dfk" => Some("direct-free-kick"),
        "indirectfreekick" | "indirectfk" | "ifk" => Some("indirect-free-kick"),
        _ => None,
    }
}

fn set_play_restart_labels_match(a: &str, b: &str) -> bool {
    let Some(a) = canonical_set_play_restart_label(a) else {
        return false;
    };
    let Some(b) = canonical_set_play_restart_label(b) else {
        return false;
    };
    if a == b {
        return true;
    }
    let (Some(a), Some(b)) = (
        RestartLabel::from_canonical(a),
        RestartLabel::from_canonical(b),
    ) else {
        return false;
    };
    a.is_free_kick_family() && b.is_free_kick_family()
}

fn held_restart_action_for_snapshot(
    snapshot: &WorldSnapshot,
    player_id: usize,
) -> Option<&'static str> {
    if snapshot.ball.holder != Some(player_id) || snapshot.pending_pass.is_some() {
        return None;
    }
    snapshot
        .ball
        .last_decision
        .as_ref()
        .and_then(|decision| restart_action_label(&decision.action))
}

fn loose_long_ball_altitude_yards(speed_yps: f64) -> f64 {
    if speed_yps < 8.0 {
        0.0
    } else {
        (0.035 + (speed_yps - 8.0) / 95.0).clamp(0.035, 0.24)
    }
}

#[derive(Clone, Debug, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub(crate) struct UntargetedLongBallFlight {
    action: String,
    origin: Vec2,
    target: Vec2,
    launch_speed_yps: f64,
    distance_yards: f64,
    // Teammates of the launcher who were in an offside position when this untargeted
    // ball (clearance / route-one / hoof) was played. There is no `pending_pass` for an
    // untargeted ball, so these are carried here so a forward who receives it offside is
    // still flagged (Law 11 applies to any ball played by your own team).
    #[serde(default, skip)]
    offside_candidates: Vec<PendingOffside>,
}

#[derive(Clone, Debug)]
pub(crate) struct ResolvedUntargetedLongBall {
    launcher_id: usize,
    launch_tick: u64,
    team: Team,
    action: String,
    origin: Vec2,
    target: Vec2,
    distance_yards: f64,
}

fn untargeted_long_ball_altitude_yards(
    flight: &UntargetedLongBallFlight,
    ball_position: Vec2,
    current_speed_yps: f64,
) -> f64 {
    let path = flight.target - flight.origin;
    let denom = path.x * path.x + path.y * path.y;
    if denom <= 1e-9 || current_speed_yps < 4.0 {
        return 0.0;
    }
    let progress = dot(ball_position - flight.origin, path) / denom;
    if progress <= 0.0 || progress >= 1.0 {
        return 0.0;
    }
    let carry_speed = flight.launch_speed_yps.max(current_speed_yps);
    // Hoofed long balls were ballooning (the old 4.5..14.0yd / 13..42ft clamp). A typical
    // long hoof now stays under the shared ~30ft (`MAX_LOFT_APEX_YARDS`) ceiling so it can
    // never balloon past a lofted pass. Flatter/driven keeps the ground game quick; the cap
    // is vertical realism only (x/y pace is independent of loft).
    let apex = (3.15 + flight.distance_yards.max(0.0) * 0.062 + carry_speed * 0.037)
        .clamp(3.7, MAX_LOFT_APEX_YARDS);
    (std::f64::consts::PI * progress).sin().max(0.0) * apex
}

#[derive(Clone, Debug, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct HumanInputFrame {
    pub controller_slot: usize,
    pub player_id: Option<usize>,
    pub seq: u64,
    pub axis: Vec2,
    pub sprint: bool,
    /// Tap-tier pace 0..=5 (0 = none/release → stop; 1 walk, 2 skip, 3 jog,
    /// 4 run, 5 sprint). 0 falls back to the legacy `sprint` bool, so older
    /// clients sending only `axis`/`sprint` keep working.
    #[serde(default)]
    pub pace: u8,
    pub pass: bool,
    #[serde(default, alias = "flight")]
    pub pass_flight: PassFlight,
    pub shoot: bool,
    #[serde(default, alias = "command")]
    pub action: Option<String>,
    pub target_player: Option<usize>,
}

fn human_input_has_explicit_command(input: &HumanInputFrame) -> bool {
    input.pass || input.shoot || input.action.is_some()
}

/// Human (tap-tier) control speeds in yds/s, indexed by pace tier 0..=5:
/// 0 = stop, 1 walk, 2 skip, 3 jog, 4 run, 5 sprint — within the realistic band
/// (a flat-out sprint elsewhere tops out ~12 yps).
const HUMAN_PACE_SPEEDS_YPS: [f64; 6] = [0.0, 3.0, 5.0, 7.0, 9.0, 11.5];
/// Per-tick velocity multiplier applied when a controlled player releases — a hard
/// brake so the player stops promptly instead of coasting.
const HUMAN_CONTROL_BRAKE: f64 = 0.30;
/// Accel cap (yds/s^2) for human direct control: high, so starts/turns feel
/// immediate without teleporting.
const HUMAN_CONTROL_ACCEL_YPS2: f64 = 60.0;

fn human_pace_speed_yps(pace: u8) -> f64 {
    HUMAN_PACE_SPEEDS_YPS[(pace.min(5)) as usize].min(SOCCER_PHYSICS_PLAYER_MAX_SPEED_YPS)
}

/// `(player_id, unit direction, pace tier)` a controller commands this tick.
/// No axis (released) → pace 0 (stop). A 0 pace from the client falls back to the
/// legacy `sprint` bool (sprint → tier 5, else jog tier 3).
fn human_control_directive(player_id: usize, input: &HumanInputFrame) -> (usize, Vec2, u8) {
    let axis = input.axis.normalized();
    if axis.len() < 1e-6 {
        return (player_id, Vec2::zero(), 0);
    }
    let pace = if input.pace > 0 {
        input.pace.min(5)
    } else if input.sprint {
        5
    } else {
        3
    };
    (player_id, axis, pace)
}

fn merge_human_controller_input_frames(
    command_source: &HumanInputFrame,
    latest_motion: &HumanInputFrame,
) -> HumanInputFrame {
    if !human_input_has_explicit_command(command_source)
        || human_input_has_explicit_command(latest_motion)
    {
        return latest_motion.clone();
    }

    let mut merged = latest_motion.clone();
    merged.pass = command_source.pass;
    merged.pass_flight = command_source.pass_flight;
    merged.shoot = command_source.shoot;
    merged.action = command_source.action.clone();
    merged.target_player = command_source.target_player;
    merged
}

const HUMAN_INPUT_QUEUE_LIMIT: usize = 256;
const HUMAN_INPUT_MAX_QUEUE_AGE_MS: u64 = 250;

fn soccer_unix_millis() -> u64 {
    SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map(|duration| duration.as_millis().min(u128::from(u64::MAX)) as u64)
        .unwrap_or(0)
}

#[derive(Clone, Debug, Default)]
struct SharedHumanInputStore {
    pending: VecDeque<QueuedHumanInputFrame>,
    latest_seq_by_slot: HashMap<usize, u64>,
    expired_frames_by_slot: HashMap<usize, u64>,
}

#[derive(Clone, Debug)]
struct QueuedHumanInputFrame {
    input: HumanInputFrame,
    enqueued_unix_ms: u64,
}

#[derive(Clone, Debug)]
pub struct HumanInputDrainResult {
    pub input: HumanInputFrame,
    pub enqueued_unix_ms: u64,
    pub queue_age_ms: u64,
}

#[derive(Clone, Copy, Debug, Default, PartialEq, Eq)]
struct HumanControllerSlotMask(u8);

impl HumanControllerSlotMask {
    fn from_slots(controller_slots: &[usize]) -> Self {
        let mut mask = 0u8;
        for &slot in controller_slots {
            if slot < SOCCER_MAX_HUMAN_CONTROLLER_SLOTS {
                mask |= 1u8 << slot;
            }
        }
        HumanControllerSlotMask(mask)
    }

    fn is_empty(self) -> bool {
        self.0 == 0
    }

    fn contains(self, controller_slot: usize) -> bool {
        controller_slot < SOCCER_MAX_HUMAN_CONTROLLER_SLOTS
            && (self.0 & (1u8 << controller_slot)) != 0
    }
}

impl SharedHumanInputStore {
    fn push(&mut self, input: HumanInputFrame, enqueued_unix_ms: u64) -> bool {
        if input.controller_slot >= SOCCER_MAX_HUMAN_CONTROLLER_SLOTS {
            return false;
        }
        if self
            .latest_seq_by_slot
            .get(&input.controller_slot)
            .is_some_and(|last_seq| input.seq <= *last_seq)
        {
            return false;
        }
        self.pending
            .retain(|queued| queued.input.controller_slot != input.controller_slot);
        self.latest_seq_by_slot
            .insert(input.controller_slot, input.seq);
        self.pending.push_back(QueuedHumanInputFrame {
            input,
            enqueued_unix_ms,
        });
        while self.pending.len() > HUMAN_INPUT_QUEUE_LIMIT {
            if let Some(evicted) = self.pending.pop_front() {
                *self
                    .expired_frames_by_slot
                    .entry(evicted.input.controller_slot)
                    .or_default() += 1;
            }
        }
        true
    }

    fn drain_latest_by_slot_with_age(
        &mut self,
        consumed_unix_ms: u64,
    ) -> HashMap<usize, HumanInputFrame> {
        let mut latest = HashMap::new();
        for queued in self.pending.drain(..) {
            let queue_age_ms = consumed_unix_ms.saturating_sub(queued.enqueued_unix_ms);
            if queue_age_ms > HUMAN_INPUT_MAX_QUEUE_AGE_MS {
                *self
                    .expired_frames_by_slot
                    .entry(queued.input.controller_slot)
                    .or_default() += 1;
                continue;
            }
            latest
                .entry(queued.input.controller_slot)
                .and_modify(|current: &mut QueuedHumanInputFrame| {
                    if queued.input.seq > current.input.seq {
                        *current = queued.clone();
                    }
                })
                .or_insert(queued);
        }
        latest
            .into_iter()
            .map(|(slot, queued)| (slot, queued.input))
            .collect()
    }

    fn drain_latest_by_slot(&mut self) -> HashMap<usize, HumanInputFrame> {
        self.drain_latest_by_slot_with_age(soccer_unix_millis())
    }

    fn drain_latest_for_slot(&mut self, controller_slot: usize) -> Option<HumanInputFrame> {
        self.drain_latest_for_slot_with_age(controller_slot, soccer_unix_millis())
            .map(|result| result.input)
    }

    fn drain_latest_for_slot_with_age(
        &mut self,
        controller_slot: usize,
        consumed_unix_ms: u64,
    ) -> Option<HumanInputDrainResult> {
        let mut latest = None;
        let mut retained = VecDeque::with_capacity(self.pending.len());
        while let Some(queued) = self.pending.pop_front() {
            if queued.input.controller_slot == controller_slot {
                if latest
                    .as_ref()
                    .map_or(true, |current: &QueuedHumanInputFrame| {
                        queued.input.seq > current.input.seq
                    })
                {
                    latest = Some(queued);
                }
            } else {
                retained.push_back(queued);
            }
        }
        self.pending = retained;
        latest.and_then(|queued| {
            let queue_age_ms = consumed_unix_ms.saturating_sub(queued.enqueued_unix_ms);
            if queue_age_ms > HUMAN_INPUT_MAX_QUEUE_AGE_MS {
                *self
                    .expired_frames_by_slot
                    .entry(queued.input.controller_slot)
                    .or_default() += 1;
                None
            } else {
                Some(HumanInputDrainResult {
                    queue_age_ms,
                    enqueued_unix_ms: queued.enqueued_unix_ms,
                    input: queued.input,
                })
            }
        })
    }

    fn clear_slot(&mut self, controller_slot: usize) -> bool {
        let pending_before = self.pending.len();
        self.pending
            .retain(|queued| queued.input.controller_slot != controller_slot);
        let removed_pending = self.pending.len() != pending_before;
        let removed_watermark = self.latest_seq_by_slot.remove(&controller_slot).is_some();
        removed_pending || removed_watermark
    }

    fn prune_expired_for_slots(
        &mut self,
        controller_slots: Option<&[usize]>,
        consumed_unix_ms: u64,
    ) -> u64 {
        let slot_mask = controller_slots.map(HumanControllerSlotMask::from_slots);
        if slot_mask.is_some_and(HumanControllerSlotMask::is_empty) {
            return 0;
        }
        let mut expired = 0u64;
        let mut retained = VecDeque::with_capacity(self.pending.len());
        while let Some(queued) = self.pending.pop_front() {
            let slot_matches = slot_mask
                .map(|mask| mask.contains(queued.input.controller_slot))
                .unwrap_or(true);
            let queue_age_ms = consumed_unix_ms.saturating_sub(queued.enqueued_unix_ms);
            if slot_matches && queue_age_ms > HUMAN_INPUT_MAX_QUEUE_AGE_MS {
                *self
                    .expired_frames_by_slot
                    .entry(queued.input.controller_slot)
                    .or_default() += 1;
                expired = expired.saturating_add(1);
            } else {
                retained.push_back(queued);
            }
        }
        self.pending = retained;
        expired
    }

    fn pending_len_for_slots(&self, controller_slots: &[usize]) -> usize {
        let slot_mask = HumanControllerSlotMask::from_slots(controller_slots);
        if slot_mask.is_empty() {
            return 0;
        }
        self.pending
            .iter()
            .filter(|queued| slot_mask.contains(queued.input.controller_slot))
            .count()
    }

    fn expired_len_for_slot(&self, controller_slot: usize) -> u64 {
        self.expired_frames_by_slot
            .get(&controller_slot)
            .copied()
            .unwrap_or(0)
    }

    fn expired_len(&self) -> u64 {
        self.expired_frames_by_slot.values().copied().sum()
    }
}

#[derive(Clone)]
pub struct SharedHumanInputs {
    inner: Arc<RwLock<SharedHumanInputStore>>,
    notifier: Arc<(Mutex<HumanInputNotifierState>, Condvar)>,
}

#[derive(Clone, Debug, Default)]
struct HumanInputNotifierState {
    version: u64,
    version_by_slot: HashMap<usize, u64>,
}

impl HumanInputNotifierState {
    fn record_slot_change(&mut self, controller_slot: usize) {
        self.version = self.version.saturating_add(1);
        self.version_by_slot.insert(controller_slot, self.version);
    }

    fn max_slot_version(&self, controller_slots: &[usize]) -> u64 {
        controller_slots
            .iter()
            .filter_map(|slot| self.version_by_slot.get(slot).copied())
            .max()
            .unwrap_or(0)
    }

    fn slots_changed_since(&self, controller_slots: &[usize], version: u64) -> bool {
        controller_slots.iter().any(|slot| {
            self.version_by_slot
                .get(slot)
                .is_some_and(|slot_version| *slot_version > version)
        })
    }
}

#[derive(Clone, Copy, Debug, Default, PartialEq, Eq)]
pub struct HumanInputWaitResult {
    pub version_before: u64,
    pub version_after: u64,
    pub relevant_version_before: u64,
    pub relevant_version_after: u64,
    pub relevant_notified: bool,
    pub queued_before: usize,
    pub queued_after: usize,
    pub immediate_pending: bool,
    pub notified: bool,
}

impl HumanInputWaitResult {
    fn pending(&self) -> bool {
        self.immediate_pending || self.notified || self.queued_after > 0
    }
}

fn recover_poisoned_soccer_lock(lock_name: &str, access: &str) {
    eprintln!(
        "{{\"event\":\"soccer_lock_poison_recovered\",\"lock\":\"{}\",\"access\":\"{}\"}}",
        lock_name, access
    );
}

fn soccer_rwlock_read<'a, T>(lock: &'a RwLock<T>, lock_name: &str) -> RwLockReadGuard<'a, T> {
    lock.read().unwrap_or_else(|poisoned| {
        recover_poisoned_soccer_lock(lock_name, "read");
        poisoned.into_inner()
    })
}

fn soccer_rwlock_write<'a, T>(lock: &'a RwLock<T>, lock_name: &str) -> RwLockWriteGuard<'a, T> {
    lock.write().unwrap_or_else(|poisoned| {
        recover_poisoned_soccer_lock(lock_name, "write");
        poisoned.into_inner()
    })
}

fn soccer_mutex_lock<'a, T>(lock: &'a Mutex<T>, lock_name: &str) -> MutexGuard<'a, T> {
    lock.lock().unwrap_or_else(|poisoned| {
        recover_poisoned_soccer_lock(lock_name, "mutex");
        poisoned.into_inner()
    })
}

fn soccer_condvar_wait_timeout_while<'a, T, F>(
    condvar: &Condvar,
    guard: MutexGuard<'a, T>,
    timeout: Duration,
    condition: F,
    lock_name: &str,
) -> MutexGuard<'a, T>
where
    F: FnMut(&mut T) -> bool,
{
    condvar
        .wait_timeout_while(guard, timeout, condition)
        .map(|(guard, _)| guard)
        .unwrap_or_else(|poisoned| {
            recover_poisoned_soccer_lock(lock_name, "condvar-wait");
            poisoned.into_inner().0
        })
}

fn soccer_condvar_wait<'a, T>(
    condvar: &Condvar,
    guard: MutexGuard<'a, T>,
    lock_name: &str,
) -> MutexGuard<'a, T> {
    condvar.wait(guard).unwrap_or_else(|poisoned| {
        recover_poisoned_soccer_lock(lock_name, "condvar-wait");
        poisoned.into_inner()
    })
}

fn soccer_condvar_wait_timeout<'a, T>(
    condvar: &Condvar,
    guard: MutexGuard<'a, T>,
    timeout: Duration,
    lock_name: &str,
) -> MutexGuard<'a, T> {
    condvar
        .wait_timeout(guard, timeout)
        .map(|(guard, _)| guard)
        .unwrap_or_else(|poisoned| {
            recover_poisoned_soccer_lock(lock_name, "condvar-wait-timeout");
            poisoned.into_inner().0
        })
}

impl Default for SharedHumanInputs {
    fn default() -> Self {
        SharedHumanInputs {
            inner: Arc::new(RwLock::new(SharedHumanInputStore::default())),
            notifier: Arc::new((
                Mutex::new(HumanInputNotifierState::default()),
                Condvar::new(),
            )),
        }
    }
}

impl SharedHumanInputs {
    pub fn new() -> Self {
        Self::default()
    }

    pub fn push(&self, input: HumanInputFrame) -> bool {
        self.push_with_enqueue_unix_ms(input, soccer_unix_millis())
    }

    fn push_with_enqueue_unix_ms(&self, input: HumanInputFrame, enqueued_unix_ms: u64) -> bool {
        let controller_slot = input.controller_slot;
        let accepted = {
            let mut store = soccer_rwlock_write(&self.inner, "human_input_queue");
            store.push(input, enqueued_unix_ms)
        };
        if accepted {
            let (lock, condvar) = &*self.notifier;
            let mut notifier = soccer_mutex_lock(lock, "human_input_notifier");
            notifier.record_slot_change(controller_slot);
            condvar.notify_all();
        }
        accepted
    }

    pub fn prune_expired(&self) -> u64 {
        soccer_rwlock_write(&self.inner, "human_input_queue")
            .prune_expired_for_slots(None, soccer_unix_millis())
    }

    pub fn prune_expired_for_slots(&self, controller_slots: &[usize]) -> u64 {
        soccer_rwlock_write(&self.inner, "human_input_queue")
            .prune_expired_for_slots(Some(controller_slots), soccer_unix_millis())
    }

    pub fn drain_latest_by_slot(&self) -> HashMap<usize, HumanInputFrame> {
        soccer_rwlock_write(&self.inner, "human_input_queue").drain_latest_by_slot()
    }

    pub fn drain_latest_for_slot(&self, controller_slot: usize) -> Option<HumanInputFrame> {
        soccer_rwlock_write(&self.inner, "human_input_queue").drain_latest_for_slot(controller_slot)
    }

    pub fn drain_latest_for_slot_with_age(
        &self,
        controller_slot: usize,
    ) -> Option<HumanInputDrainResult> {
        soccer_rwlock_write(&self.inner, "human_input_queue")
            .drain_latest_for_slot_with_age(controller_slot, soccer_unix_millis())
    }

    pub fn clear_slot(&self, controller_slot: usize) {
        let cleared =
            soccer_rwlock_write(&self.inner, "human_input_queue").clear_slot(controller_slot);
        if cleared {
            let (lock, condvar) = &*self.notifier;
            let mut notifier = soccer_mutex_lock(lock, "human_input_notifier");
            notifier.record_slot_change(controller_slot);
            condvar.notify_all();
        }
    }

    pub fn notification_version(&self) -> u64 {
        let (lock, _) = &*self.notifier;
        soccer_mutex_lock(lock, "human_input_notifier").version
    }

    pub fn relevant_notification_version(&self, controller_slots: &[usize]) -> u64 {
        let (lock, _) = &*self.notifier;
        soccer_mutex_lock(lock, "human_input_notifier").max_slot_version(controller_slots)
    }

    pub fn wait_for_change_since(&self, version: u64, timeout: Duration) -> u64 {
        let (lock, condvar) = &*self.notifier;
        let guard = soccer_mutex_lock(lock, "human_input_notifier");
        let guard = soccer_condvar_wait_timeout_while(
            condvar,
            guard,
            timeout,
            |current| current.version <= version,
            "human_input_notifier",
        );
        guard.version
    }

    pub fn wait_for_slot_change_since(
        &self,
        controller_slots: &[usize],
        version: u64,
        timeout: Duration,
    ) -> u64 {
        if controller_slots.is_empty() {
            return self.notification_version();
        }
        let (lock, condvar) = &*self.notifier;
        let guard = soccer_mutex_lock(lock, "human_input_notifier");
        let guard = soccer_condvar_wait_timeout_while(
            condvar,
            guard,
            timeout,
            |current| !current.slots_changed_since(controller_slots, version),
            "human_input_notifier",
        );
        guard.version
    }

    pub fn wait_for_pending_input(&self, timeout: Duration) -> bool {
        self.wait_for_pending_input_result(timeout).pending()
    }

    pub fn wait_for_pending_input_result(&self, timeout: Duration) -> HumanInputWaitResult {
        let version = self.notification_version();
        self.prune_expired();
        let queued_before = self.queued_len();
        if queued_before > 0 {
            return HumanInputWaitResult {
                version_before: version,
                version_after: version,
                relevant_version_before: version,
                relevant_version_after: version,
                relevant_notified: false,
                queued_before,
                queued_after: queued_before,
                immediate_pending: true,
                notified: false,
            };
        }
        let next_version = self.wait_for_change_since(version, timeout);
        self.prune_expired();
        let queued_after = self.queued_len();
        HumanInputWaitResult {
            version_before: version,
            version_after: next_version,
            relevant_version_before: version,
            relevant_version_after: next_version,
            relevant_notified: next_version > version,
            queued_before,
            queued_after,
            immediate_pending: false,
            notified: next_version > version,
        }
    }

    pub fn wait_for_pending_input_for_slots_result(
        &self,
        controller_slots: &[usize],
        timeout: Duration,
    ) -> HumanInputWaitResult {
        let version = self.notification_version();
        let relevant_version = self.relevant_notification_version(controller_slots);
        if controller_slots.is_empty() {
            return HumanInputWaitResult {
                version_before: version,
                version_after: version,
                relevant_version_before: 0,
                relevant_version_after: 0,
                relevant_notified: false,
                queued_before: 0,
                queued_after: 0,
                immediate_pending: false,
                notified: false,
            };
        }

        self.prune_expired_for_slots(controller_slots);
        let queued_before = self.queued_len_for_slots(controller_slots);
        if queued_before > 0 {
            return HumanInputWaitResult {
                version_before: version,
                version_after: version,
                relevant_version_before: relevant_version,
                relevant_version_after: relevant_version,
                relevant_notified: false,
                queued_before,
                queued_after: queued_before,
                immediate_pending: true,
                notified: false,
            };
        }

        let deadline = Instant::now() + timeout;
        let mut observed_version = version;
        loop {
            let now = Instant::now();
            if now >= deadline {
                break;
            }
            let next_version = self.wait_for_slot_change_since(
                controller_slots,
                observed_version,
                deadline.saturating_duration_since(now),
            );
            self.prune_expired_for_slots(controller_slots);
            let queued_after = self.queued_len_for_slots(controller_slots);
            if queued_after > 0 {
                let coalesce_deadline =
                    Instant::now() + Duration::from_millis(CONTROLLER_INPUT_COALESCE_MS);
                let mut coalesced_version = next_version;
                let mut coalesced_queued = queued_after;
                while coalesced_queued < controller_slots.len() {
                    let coalesce_now = Instant::now();
                    if coalesce_now >= coalesce_deadline {
                        break;
                    }
                    let next_coalesced_version = self.wait_for_slot_change_since(
                        controller_slots,
                        coalesced_version,
                        coalesce_deadline.saturating_duration_since(coalesce_now),
                    );
                    self.prune_expired_for_slots(controller_slots);
                    let next_coalesced_queued = self.queued_len_for_slots(controller_slots);
                    if next_coalesced_version <= coalesced_version {
                        coalesced_queued = next_coalesced_queued;
                        break;
                    }
                    coalesced_version = next_coalesced_version;
                    coalesced_queued = next_coalesced_queued;
                }
                let final_version = self.notification_version().max(coalesced_version);
                let relevant_version_after = self.relevant_notification_version(controller_slots);
                return HumanInputWaitResult {
                    version_before: version,
                    version_after: final_version,
                    relevant_version_before: relevant_version,
                    relevant_version_after,
                    relevant_notified: relevant_version_after > relevant_version,
                    queued_before,
                    queued_after: coalesced_queued,
                    immediate_pending: queued_before > 0,
                    notified: coalesced_queued > 0 && relevant_version_after > relevant_version,
                };
            }
            if next_version <= observed_version {
                return HumanInputWaitResult {
                    version_before: version,
                    version_after: next_version,
                    relevant_version_before: relevant_version,
                    relevant_version_after: self.relevant_notification_version(controller_slots),
                    relevant_notified: false,
                    queued_before,
                    queued_after,
                    immediate_pending: queued_before > 0,
                    notified: false,
                };
            }
            observed_version = next_version;
        }

        let version_after = self.notification_version();
        self.prune_expired_for_slots(controller_slots);
        let queued_after = self.queued_len_for_slots(controller_slots);
        let relevant_version_after = self.relevant_notification_version(controller_slots);
        HumanInputWaitResult {
            version_before: version,
            version_after,
            relevant_version_before: relevant_version,
            relevant_version_after,
            relevant_notified: relevant_version_after > relevant_version,
            queued_before,
            queued_after,
            immediate_pending: queued_before > 0,
            notified: queued_after > 0 && relevant_version_after > relevant_version,
        }
    }

    pub fn queued_len(&self) -> usize {
        soccer_rwlock_read(&self.inner, "human_input_queue")
            .pending
            .len()
    }

    pub fn queued_len_for_slots(&self, controller_slots: &[usize]) -> usize {
        soccer_rwlock_read(&self.inner, "human_input_queue").pending_len_for_slots(controller_slots)
    }

    pub fn last_seq_for_slot(&self, controller_slot: usize) -> Option<u64> {
        soccer_rwlock_read(&self.inner, "human_input_queue")
            .latest_seq_by_slot
            .get(&controller_slot)
            .copied()
    }

    pub fn expired_len_for_slot(&self, controller_slot: usize) -> u64 {
        soccer_rwlock_read(&self.inner, "human_input_queue").expired_len_for_slot(controller_slot)
    }

    pub fn expired_len(&self) -> u64 {
        soccer_rwlock_read(&self.inner, "human_input_queue").expired_len()
    }
}

