impl ControllerYieldStats {
    fn record_no_assignment(&mut self, queued: usize, version: u64) {
        self.assigned_players = 0;
        self.skipped_no_assignment = self.skipped_no_assignment.saturating_add(1);
        self.last_wait_late = false;
        self.last_notified = false;
        self.last_relevant_notified = false;
        self.last_immediate_pending = false;
        self.last_queued_before = queued;
        self.last_queued_after = queued;
        self.last_version_before = version;
        self.last_version_after = version;
        self.last_relevant_version_before = version;
        self.last_relevant_version_after = version;
        self.last_wait_ms = 0.0;
    }

    fn record_wait(&mut self, assigned_players: usize, result: HumanInputWaitResult, wait_ms: f64) {
        self.record_wait_with_kind(assigned_players, result, wait_ms, false);
    }

    fn record_late_wait(
        &mut self,
        assigned_players: usize,
        result: HumanInputWaitResult,
        wait_ms: f64,
    ) {
        self.record_wait_with_kind(assigned_players, result, wait_ms, true);
    }

    fn record_wait_with_kind(
        &mut self,
        assigned_players: usize,
        result: HumanInputWaitResult,
        wait_ms: f64,
        late: bool,
    ) {
        let wait_ms = finite_metric(wait_ms.max(0.0));
        self.assigned_players = assigned_players;
        self.wait_attempts = self.wait_attempts.saturating_add(1);
        if result.immediate_pending {
            self.immediate_pending_waits = self.immediate_pending_waits.saturating_add(1);
        } else if result.notified || result.queued_after > 0 {
            self.notified_waits = self.notified_waits.saturating_add(1);
        } else {
            self.timed_out_waits = self.timed_out_waits.saturating_add(1);
        }
        if result.relevant_notified {
            self.relevant_notified_waits = self.relevant_notified_waits.saturating_add(1);
        }
        if late {
            self.late_wait_attempts = self.late_wait_attempts.saturating_add(1);
            if result.immediate_pending {
                self.late_immediate_pending_waits =
                    self.late_immediate_pending_waits.saturating_add(1);
            } else if result.notified || result.queued_after > 0 {
                self.late_notified_waits = self.late_notified_waits.saturating_add(1);
            } else {
                self.late_timed_out_waits = self.late_timed_out_waits.saturating_add(1);
            }
            if result.relevant_notified {
                self.late_relevant_notified_waits =
                    self.late_relevant_notified_waits.saturating_add(1);
            }
        }
        self.last_wait_late = late;
        self.last_notified = result.notified || result.queued_after > result.queued_before;
        self.last_relevant_notified = result.relevant_notified;
        self.last_immediate_pending = result.immediate_pending;
        self.last_queued_before = result.queued_before;
        self.last_queued_after = result.queued_after;
        self.last_version_before = result.version_before;
        self.last_version_after = result.version_after;
        self.last_relevant_version_before = result.relevant_version_before;
        self.last_relevant_version_after = result.relevant_version_after;
        self.total_wait_ms += wait_ms;
        self.last_wait_ms = wait_ms;
        self.max_wait_ms = self.max_wait_ms.max(wait_ms);
    }
}

#[derive(Default)]
struct HumanControllerMailboxState {
    latest: Option<HumanInputFrame>,
    closed: bool,
    version: u64,
    accepted_frames: u64,
    pushed_frames: u64,
    overwritten_frames: u64,
    rejected_stale_frames: u64,
    latest_seq_seen: Option<u64>,
    debounced_frames: u64,
    total_debounce_ms: f64,
    last_debounce_ms: f64,
    max_debounce_ms: f64,
}

#[derive(Clone, Default)]
struct HumanControllerMailbox {
    inner: Arc<(Mutex<HumanControllerMailboxState>, Condvar)>,
}

impl HumanControllerMailbox {
    fn send(&self, input: HumanInputFrame) -> Result<bool, String> {
        let (lock, condvar) = &*self.inner;
        let mut state = soccer_mutex_lock(lock, "human_controller_mailbox");
        if state.closed {
            return Err("controller mailbox is closed".to_string());
        }
        if state
            .latest_seq_seen
            .is_some_and(|latest_seq| input.seq <= latest_seq)
        {
            state.rejected_stale_frames = state.rejected_stale_frames.saturating_add(1);
            return Ok(false);
        }

        state.version = state.version.saturating_add(1);
        state.latest_seq_seen = Some(input.seq);
        state.accepted_frames = state.accepted_frames.saturating_add(1);
        if state.latest.is_some() {
            state.overwritten_frames = state.overwritten_frames.saturating_add(1);
        }
        state.latest = Some(input);
        condvar.notify_one();
        Ok(true)
    }

    fn close(&self) {
        let (lock, condvar) = &*self.inner;
        let mut state = soccer_mutex_lock(lock, "human_controller_mailbox");
        state.closed = true;
        condvar.notify_all();
    }

    fn wait_for_debounced_input(&self, debounce_interval: Duration) -> Option<HumanInputFrame> {
        let (lock, condvar) = &*self.inner;
        loop {
            let mut state = soccer_mutex_lock(lock, "human_controller_mailbox");
            while state.latest.is_none() && !state.closed {
                state = soccer_condvar_wait(condvar, state, "human_controller_mailbox");
            }
            if state.closed {
                return None;
            }

            let debounce_started = Instant::now();
            let mut debounce_wait_ms = 0.0;
            if debounce_interval > Duration::from_millis(0) {
                let mut observed_version = state.version;
                let mut quiet_deadline = Instant::now() + debounce_interval;
                loop {
                    let now = Instant::now();
                    if now >= quiet_deadline || state.closed || state.latest.is_none() {
                        break;
                    }
                    let wait_for = quiet_deadline.saturating_duration_since(now);
                    state = soccer_condvar_wait_timeout(
                        condvar,
                        state,
                        wait_for,
                        "human_controller_mailbox",
                    );
                    if state.version != observed_version {
                        observed_version = state.version;
                        quiet_deadline = Instant::now() + debounce_interval;
                    }
                }
                debounce_wait_ms = soccer_live_duration_ms(debounce_started.elapsed());
            }

            if let Some(input) = state.latest.take() {
                let debounce_wait_ms = finite_metric(debounce_wait_ms.max(0.0));
                state.debounced_frames = state.debounced_frames.saturating_add(1);
                state.total_debounce_ms += debounce_wait_ms;
                state.last_debounce_ms = debounce_wait_ms;
                state.max_debounce_ms = state.max_debounce_ms.max(debounce_wait_ms);
                return Some(input);
            }
            if state.closed {
                return None;
            }
        }
    }

    fn record_push(&self, accepted: bool) {
        if !accepted {
            return;
        }
        let (lock, _) = &*self.inner;
        let mut state = soccer_mutex_lock(lock, "human_controller_mailbox");
        state.pushed_frames = state.pushed_frames.saturating_add(1);
    }

    fn clear_pending(&self) {
        let (lock, condvar) = &*self.inner;
        let mut state = soccer_mutex_lock(lock, "human_controller_mailbox");
        state.latest = None;
        state.latest_seq_seen = None;
        state.version = state.version.saturating_add(1);
        condvar.notify_all();
    }

    fn pending_len(&self) -> usize {
        let (lock, _) = &*self.inner;
        let state = soccer_mutex_lock(lock, "human_controller_mailbox");
        usize::from(state.latest.is_some())
    }

    fn stats(&self, controller_slot: usize) -> HumanControllerThreadStats {
        let (lock, _) = &*self.inner;
        let state = soccer_mutex_lock(lock, "human_controller_mailbox");
        HumanControllerThreadStats {
            controller_slot,
            pending: state.latest.is_some(),
            closed: state.closed,
            accepted_frames: state.accepted_frames,
            pushed_frames: state.pushed_frames,
            overwritten_frames: state.overwritten_frames,
            rejected_stale_frames: state.rejected_stale_frames,
            latest_seq_seen: state.latest_seq_seen,
            debounced_frames: state.debounced_frames,
            total_debounce_ms: state.total_debounce_ms,
            last_debounce_ms: state.last_debounce_ms,
            max_debounce_ms: state.max_debounce_ms,
        }
    }
}

#[derive(Clone, Debug, Default)]
pub struct SharedControllerAssignments {
    inner: Arc<RwLock<SharedControllerAssignmentStore>>,
}

#[derive(Clone, Debug, Default)]
struct SharedControllerAssignmentStore {
    human_slots: usize,
    player_by_slot: HashMap<usize, usize>,
}

impl SharedControllerAssignments {
    pub fn new(human_slots: usize) -> Self {
        let assignments = SharedControllerAssignments::default();
        assignments.set_human_slots(human_slots);
        assignments
    }

    pub fn set_human_slots(&self, human_slots: usize) {
        let mut store = soccer_rwlock_write(&self.inner, "controller_assignment");
        store.human_slots = human_slots.min(SOCCER_MAX_HUMAN_CONTROLLER_SLOTS);
        let human_slots = store.human_slots;
        store.player_by_slot.retain(|slot, _| *slot < human_slots);
    }

    pub fn replace_from_assignments(
        &self,
        human_slots: usize,
        assignments: &[ControllerAssignment],
    ) {
        let mut store = soccer_rwlock_write(&self.inner, "controller_assignment");
        store.human_slots = human_slots.min(SOCCER_MAX_HUMAN_CONTROLLER_SLOTS);
        store.player_by_slot.clear();
        for assignment in assignments {
            if assignment.controller_slot < store.human_slots {
                store
                    .player_by_slot
                    .retain(|_, assigned_player_id| *assigned_player_id != assignment.player_id);
                store
                    .player_by_slot
                    .insert(assignment.controller_slot, assignment.player_id);
            }
        }
    }

    pub fn assign_slot(&self, controller_slot: usize, player_id: Option<usize>) {
        let mut store = soccer_rwlock_write(&self.inner, "controller_assignment");
        if controller_slot >= store.human_slots {
            return;
        }
        if let Some(player_id) = player_id {
            // Only one player is ever controlled at a time (the four slot options
            // remain selectable): assigning clears every other slot.
            store.player_by_slot.clear();
            store.player_by_slot.insert(controller_slot, player_id);
        } else {
            store.player_by_slot.remove(&controller_slot);
        }
    }

    pub fn assigned_player_for_slot(&self, controller_slot: usize) -> Option<usize> {
        soccer_rwlock_read(&self.inner, "controller_assignment")
            .player_by_slot
            .get(&controller_slot)
            .copied()
    }

    pub fn accepts_input(&self, input: &HumanInputFrame) -> bool {
        let store = soccer_rwlock_read(&self.inner, "controller_assignment");
        if input.controller_slot >= store.human_slots {
            return false;
        }
        let Some(assigned_player_id) = store.player_by_slot.get(&input.controller_slot) else {
            return false;
        };
        input
            .player_id
            .map_or(true, |player_id| player_id == *assigned_player_id)
    }
}

#[derive(Clone)]
struct HumanControllerInputSink {
    controller_slot: usize,
    mailbox: HumanControllerMailbox,
}

impl HumanControllerInputSink {
    fn send_input(&self, mut input: HumanInputFrame) -> Result<bool, String> {
        input.controller_slot = self.controller_slot;
        self.mailbox.send(input).map_err(|err| {
            format!(
                "controller thread {} send failed: {err}",
                self.controller_slot
            )
        })
    }
}

pub struct HumanControllerThread {
    controller_slot: usize,
    mailbox: HumanControllerMailbox,
    handle: Option<JoinHandle<()>>,
}

impl HumanControllerThread {
    pub fn spawn(
        input_queue: SharedHumanInputs,
        controller_slot: usize,
        debounce_interval: Duration,
    ) -> Result<Self, String> {
        let mailbox = HumanControllerMailbox::default();
        let worker_mailbox = mailbox.clone();
        let handle = thread::Builder::new()
            .name(format!("soccer-human-controller-{controller_slot}"))
            .spawn(move || {
                run_human_controller_thread(
                    input_queue,
                    controller_slot,
                    debounce_interval,
                    worker_mailbox,
                );
            })
            .map_err(|err| format!("failed to spawn controller thread {controller_slot}: {err}"))?;
        Ok(HumanControllerThread {
            controller_slot,
            mailbox,
            handle: Some(handle),
        })
    }

    pub fn controller_slot(&self) -> usize {
        self.controller_slot
    }

    pub fn send_input(&self, mut input: HumanInputFrame) -> Result<bool, String> {
        input.controller_slot = self.controller_slot;
        self.mailbox.send(input).map_err(|err| {
            format!(
                "controller thread {} send failed: {err}",
                self.controller_slot
            )
        })
    }

    fn input_sink(&self) -> HumanControllerInputSink {
        HumanControllerInputSink {
            controller_slot: self.controller_slot,
            mailbox: self.mailbox.clone(),
        }
    }

    pub fn stats(&self) -> HumanControllerThreadStats {
        self.mailbox.stats(self.controller_slot)
    }

    pub fn stop(mut self) -> Result<(), String> {
        self.mailbox.close();
        if let Some(handle) = self.handle.take() {
            handle
                .join()
                .map_err(|_| format!("controller thread {} panicked", self.controller_slot))?;
        }
        Ok(())
    }
}

impl Drop for HumanControllerThread {
    fn drop(&mut self) {
        self.mailbox.close();
        if let Some(handle) = self.handle.take() {
            let _ = handle.join();
        }
    }
}

pub fn spawn_human_controller_threads(
    input_queue: SharedHumanInputs,
    controller_slots: usize,
    debounce_interval: Duration,
) -> Result<Vec<HumanControllerThread>, String> {
    (0..controller_slots.min(SOCCER_MAX_HUMAN_CONTROLLER_SLOTS))
        .map(|slot| HumanControllerThread::spawn(input_queue.clone(), slot, debounce_interval))
        .collect()
}

fn run_human_controller_thread(
    input_queue: SharedHumanInputs,
    controller_slot: usize,
    debounce_interval: Duration,
    mailbox: HumanControllerMailbox,
) {
    while let Some(mut input) = mailbox.wait_for_debounced_input(debounce_interval) {
        input.controller_slot = controller_slot;
        let accepted = input_queue.push(input);
        mailbox.record_push(accepted);
    }
}

#[derive(Clone)]
pub struct HumanControllerInputRouter {
    input_queue: SharedHumanInputs,
    assignments: SharedControllerAssignments,
    controller_sinks: Vec<HumanControllerInputSink>,
}

impl HumanControllerInputRouter {
    fn new(
        input_queue: SharedHumanInputs,
        assignments: SharedControllerAssignments,
        controller_threads: &[HumanControllerThread],
    ) -> Self {
        HumanControllerInputRouter {
            input_queue,
            assignments,
            controller_sinks: controller_threads
                .iter()
                .map(HumanControllerThread::input_sink)
                .collect(),
        }
    }

    pub fn without_controller_threads(
        input_queue: SharedHumanInputs,
        assignments: SharedControllerAssignments,
    ) -> Self {
        HumanControllerInputRouter {
            input_queue,
            assignments,
            controller_sinks: Vec::new(),
        }
    }

    pub fn push_human_input(&self, input: HumanInputFrame) -> bool {
        if !self.assignments.accepts_input(&input) {
            return false;
        }
        self.dispatch_human_input(input)
    }

    pub fn push_human_inputs<I>(&self, inputs: I) -> usize
    where
        I: IntoIterator<Item = HumanInputFrame>,
    {
        let mut latest_by_slot = HashMap::<usize, HumanInputFrame>::new();
        for input in inputs {
            if !self.assignments.accepts_input(&input) {
                continue;
            }
            latest_by_slot
                .entry(input.controller_slot)
                .and_modify(|current| {
                    if input.seq > current.seq {
                        *current = merge_human_controller_input_frames(current, &input);
                    } else if human_input_has_explicit_command(&input)
                        && !human_input_has_explicit_command(current)
                    {
                        *current = merge_human_controller_input_frames(&input, current);
                    }
                })
                .or_insert(input);
        }
        latest_by_slot
            .into_values()
            .filter(|input| self.dispatch_human_input(input.clone()))
            .count()
    }

    fn dispatch_human_input(&self, input: HumanInputFrame) -> bool {
        if let Some(controller) = self
            .controller_sinks
            .iter()
            .find(|controller| controller.controller_slot == input.controller_slot)
        {
            controller.send_input(input).unwrap_or(false)
        } else {
            self.input_queue.push(input)
        }
    }

    pub fn clear_pending_for_slot(&self, controller_slot: usize) {
        self.input_queue.clear_slot(controller_slot);
        if let Some(controller) = self
            .controller_sinks
            .iter()
            .find(|controller| controller.controller_slot == controller_slot)
        {
            controller.mailbox.clear_pending();
        }
    }

    pub fn queued_len(&self) -> usize {
        self.input_queue.queued_len()
            + self
                .controller_sinks
                .iter()
                .map(|controller| controller.mailbox.pending_len())
                .sum::<usize>()
    }

    pub fn assignments(&self) -> SharedControllerAssignments {
        self.assignments.clone()
    }
}

#[derive(Clone, Debug, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct PlayerPositionSample {
    pub player_id: usize,
    pub tick: u64,
    pub clock_seconds: f64,
    pub position: Vec2,
    pub velocity: Vec2,
    pub acceleration: Vec2,
    pub jerk: Vec2,
}

#[derive(Clone, Debug, Default, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct SharedPlayerPositionSnapshot {
    pub latest: Vec<PlayerPositionSample>,
    pub histories: HashMap<usize, Vec<PlayerPositionSample>>,
    #[serde(default)]
    pub official_latest: Vec<OfficialPositionSample>,
    #[serde(default)]
    pub official_histories: HashMap<usize, Vec<OfficialPositionSample>>,
    #[serde(default)]
    pub ball_latest: Option<BallPositionSample>,
    #[serde(default)]
    pub ball_history: Vec<BallPositionSample>,
}

impl SharedPlayerPositionSnapshot {
    pub fn latest_for(&self, player_id: usize) -> Option<&PlayerPositionSample> {
        self.latest
            .iter()
            .find(|sample| sample.player_id == player_id)
    }

    pub fn history_for(&self, player_id: usize) -> Option<&[PlayerPositionSample]> {
        self.histories
            .get(&player_id)
            .map(|history| history.as_slice())
    }

    pub fn official_latest_for(&self, official_id: usize) -> Option<&OfficialPositionSample> {
        self.official_latest
            .iter()
            .find(|sample| sample.official_id == official_id)
    }

    pub fn official_history_for(&self, official_id: usize) -> Option<&[OfficialPositionSample]> {
        self.official_histories
            .get(&official_id)
            .map(|history| history.as_slice())
    }

    pub fn ball_latest(&self) -> Option<&BallPositionSample> {
        self.ball_latest.as_ref()
    }

    pub fn ball_history(&self) -> &[BallPositionSample] {
        self.ball_history.as_slice()
    }

    fn from_player_snapshots(players: &[PlayerSnapshot], tick: u64, clock_seconds: f64) -> Self {
        let latest = players
            .iter()
            .map(|p| PlayerPositionSample {
                player_id: p.id,
                tick,
                clock_seconds,
                position: p.position,
                velocity: p.velocity,
                acceleration: p.acceleration,
                jerk: p.jerk,
            })
            .collect::<Vec<_>>();
        let histories = latest
            .iter()
            .cloned()
            .map(|sample| (sample.player_id, vec![sample]))
            .collect::<HashMap<_, _>>();
        SharedPlayerPositionSnapshot {
            latest,
            histories,
            official_latest: Vec::new(),
            official_histories: HashMap::new(),
            ball_latest: None,
            ball_history: Vec::new(),
        }
    }
}

#[derive(Clone, Debug)]
struct SharedPlayerPositionStore {
    capacity: usize,
    latest: Vec<PlayerPositionSample>,
    histories: HashMap<usize, VecDeque<PlayerPositionSample>>,
    official_latest: Vec<OfficialPositionSample>,
    official_histories: HashMap<usize, VecDeque<OfficialPositionSample>>,
    ball_latest: Option<BallPositionSample>,
    ball_history: VecDeque<BallPositionSample>,
}

impl SharedPlayerPositionStore {
    fn with_capacity(capacity: usize) -> Self {
        SharedPlayerPositionStore {
            capacity: capacity.max(1),
            latest: Vec::new(),
            histories: HashMap::new(),
            official_latest: Vec::new(),
            official_histories: HashMap::new(),
            ball_latest: None,
            ball_history: VecDeque::new(),
        }
    }

    fn latest_for(&self, player_id: usize) -> Option<&PlayerPositionSample> {
        self.latest
            .iter()
            .find(|sample| sample.player_id == player_id)
    }

    fn official_latest_for(&self, official_id: usize) -> Option<&OfficialPositionSample> {
        self.official_latest
            .iter()
            .find(|sample| sample.official_id == official_id)
    }

    fn sync_from_players_and_ball(
        &mut self,
        players: &[PlayerAgent],
        officials: &[OfficialAgent],
        ball: &BallAgent,
        tick: u64,
        clock_seconds: f64,
    ) {
        self.latest = players
            .iter()
            .map(|p| PlayerPositionSample {
                player_id: p.id,
                tick,
                clock_seconds,
                position: p.position,
                velocity: p.velocity,
                acceleration: p.acceleration,
                jerk: p.jerk,
            })
            .collect();
        for sample in &self.latest {
            let history = self.histories.entry(sample.player_id).or_default();
            if history
                .back()
                .is_some_and(|last| last.tick == tick && last.clock_seconds == clock_seconds)
            {
                if let Some(last) = history.back_mut() {
                    *last = sample.clone();
                }
            } else {
                history.push_back(sample.clone());
            }
            while history.len() > self.capacity {
                history.pop_front();
            }
        }
        self.official_latest = officials
            .iter()
            .map(|official| OfficialPositionSample {
                official_id: official.id,
                kind: official.kind,
                tick,
                clock_seconds,
                position: official.position,
                velocity: official.velocity,
                acceleration: official.acceleration,
                jerk: official.jerk,
            })
            .collect();
        for sample in &self.official_latest {
            let history = self
                .official_histories
                .entry(sample.official_id)
                .or_default();
            if history
                .back()
                .is_some_and(|last| last.tick == tick && last.clock_seconds == clock_seconds)
            {
                if let Some(last) = history.back_mut() {
                    *last = sample.clone();
                }
            } else {
                history.push_back(sample.clone());
            }
            while history.len() > self.capacity {
                history.pop_front();
            }
        }
        let ball_sample = ball_position_sample_from_agent(ball, tick, clock_seconds);
        self.ball_latest = Some(ball_sample.clone());
        if self
            .ball_history
            .back()
            .is_some_and(|last| last.tick == tick && last.clock_seconds == clock_seconds)
        {
            if let Some(last) = self.ball_history.back_mut() {
                *last = ball_sample;
            }
        } else {
            self.ball_history.push_back(ball_sample);
        }
        while self.ball_history.len() > self.capacity {
            self.ball_history.pop_front();
        }
    }

    fn snapshot_with_current_players(
        &self,
        players: &[PlayerAgent],
        officials: &[OfficialAgent],
        ball: &BallAgent,
        tick: u64,
        clock_seconds: f64,
        dt_seconds: f64,
    ) -> SharedPlayerPositionSnapshot {
        let latest = players
            .iter()
            .map(|p| {
                let prev_velocity = self
                    .latest_for(p.id)
                    .map(|sample| sample.velocity)
                    .unwrap_or(p.velocity);
                let acceleration = if dt_seconds > 0.0 {
                    (p.velocity - prev_velocity) / dt_seconds
                } else {
                    p.acceleration
                };
                let prev_acceleration = self
                    .latest_for(p.id)
                    .map(|sample| sample.acceleration)
                    .unwrap_or(p.acceleration);
                let jerk = if dt_seconds > 0.0 {
                    (acceleration - prev_acceleration) / dt_seconds
                } else {
                    p.jerk
                };
                PlayerPositionSample {
                    player_id: p.id,
                    tick,
                    clock_seconds,
                    position: p.position,
                    velocity: p.velocity,
                    acceleration,
                    jerk,
                }
            })
            .collect::<Vec<_>>();

        let mut histories = self
            .histories
            .iter()
            .map(|(id, history)| (*id, history.iter().cloned().collect::<Vec<_>>()))
            .collect::<HashMap<_, _>>();

        for sample in &latest {
            let history = histories.entry(sample.player_id).or_default();
            if history.last().is_some_and(|last| last.tick == tick) {
                if let Some(last) = history.last_mut() {
                    *last = sample.clone();
                }
            } else {
                history.push(sample.clone());
            }
            while history.len() > self.capacity {
                history.remove(0);
            }
        }

        let official_latest = officials
            .iter()
            .map(|official| {
                let prev_velocity = self
                    .official_latest_for(official.id)
                    .map(|sample| sample.velocity)
                    .unwrap_or(official.velocity);
                let acceleration = if dt_seconds > 0.0 {
                    (official.velocity - prev_velocity) / dt_seconds
                } else {
                    official.acceleration
                };
                let prev_acceleration = self
                    .official_latest_for(official.id)
                    .map(|sample| sample.acceleration)
                    .unwrap_or(official.acceleration);
                let jerk = if dt_seconds > 0.0 {
                    (acceleration - prev_acceleration) / dt_seconds
                } else {
                    official.jerk
                };
                OfficialPositionSample {
                    official_id: official.id,
                    kind: official.kind,
                    tick,
                    clock_seconds,
                    position: official.position,
                    velocity: official.velocity,
                    acceleration,
                    jerk,
                }
            })
            .collect::<Vec<_>>();

        let mut official_histories = self
            .official_histories
            .iter()
            .map(|(id, history)| (*id, history.iter().cloned().collect::<Vec<_>>()))
            .collect::<HashMap<_, _>>();
        for sample in &official_latest {
            let history = official_histories.entry(sample.official_id).or_default();
            if history.last().is_some_and(|last| last.tick == tick) {
                if let Some(last) = history.last_mut() {
                    *last = sample.clone();
                }
            } else {
                history.push(sample.clone());
            }
            while history.len() > self.capacity {
                history.remove(0);
            }
        }

        let ball_sample = ball_position_sample_from_agent(ball, tick, clock_seconds);
        let mut ball_history = self.ball_history.iter().cloned().collect::<Vec<_>>();
        if ball_history.last().is_some_and(|last| last.tick == tick) {
            if let Some(last) = ball_history.last_mut() {
                *last = ball_sample.clone();
            }
        } else {
            ball_history.push(ball_sample.clone());
        }
        while ball_history.len() > self.capacity {
            ball_history.remove(0);
        }

        SharedPlayerPositionSnapshot {
            latest,
            histories,
            official_latest,
            official_histories,
            ball_latest: Some(ball_sample),
            ball_history,
        }
    }

    fn latest_snapshot_with_current_players(
        &self,
        players: &[PlayerAgent],
        officials: &[OfficialAgent],
        ball: &BallAgent,
        tick: u64,
        clock_seconds: f64,
        dt_seconds: f64,
    ) -> SharedPlayerPositionSnapshot {
        let latest = players
            .iter()
            .map(|p| {
                let prev_velocity = self
                    .latest_for(p.id)
                    .map(|sample| sample.velocity)
                    .unwrap_or(p.velocity);
                let acceleration = if dt_seconds > 0.0 {
                    (p.velocity - prev_velocity) / dt_seconds
                } else {
                    p.acceleration
                };
                let prev_acceleration = self
                    .latest_for(p.id)
                    .map(|sample| sample.acceleration)
                    .unwrap_or(p.acceleration);
                let jerk = if dt_seconds > 0.0 {
                    (acceleration - prev_acceleration) / dt_seconds
                } else {
                    p.jerk
                };
                PlayerPositionSample {
                    player_id: p.id,
                    tick,
                    clock_seconds,
                    position: p.position,
                    velocity: p.velocity,
                    acceleration,
                    jerk,
                }
            })
            .collect::<Vec<_>>();
        let official_latest = officials
            .iter()
            .map(|official| {
                let prev_velocity = self
                    .official_latest_for(official.id)
                    .map(|sample| sample.velocity)
                    .unwrap_or(official.velocity);
                let acceleration = if dt_seconds > 0.0 {
                    (official.velocity - prev_velocity) / dt_seconds
                } else {
                    official.acceleration
                };
                let prev_acceleration = self
                    .official_latest_for(official.id)
                    .map(|sample| sample.acceleration)
                    .unwrap_or(official.acceleration);
                let jerk = if dt_seconds > 0.0 {
                    (acceleration - prev_acceleration) / dt_seconds
                } else {
                    official.jerk
                };
                OfficialPositionSample {
                    official_id: official.id,
                    kind: official.kind,
                    tick,
                    clock_seconds,
                    position: official.position,
                    velocity: official.velocity,
                    acceleration,
                    jerk,
                }
            })
            .collect::<Vec<_>>();
        SharedPlayerPositionSnapshot {
            latest,
            histories: HashMap::new(),
            official_latest,
            official_histories: HashMap::new(),
            ball_latest: Some(ball_position_sample_from_agent(ball, tick, clock_seconds)),
            ball_history: Vec::new(),
        }
    }

    fn snapshot(&self) -> SharedPlayerPositionSnapshot {
        SharedPlayerPositionSnapshot {
            latest: self.latest.clone(),
            histories: self
                .histories
                .iter()
                .map(|(id, history)| (*id, history.iter().cloned().collect()))
                .collect(),
            official_latest: self.official_latest.clone(),
            official_histories: self
                .official_histories
                .iter()
                .map(|(id, history)| (*id, history.iter().cloned().collect()))
                .collect(),
            ball_latest: self.ball_latest.clone(),
            ball_history: self.ball_history.iter().cloned().collect(),
        }
    }
}

#[derive(Clone, Debug)]
pub struct SharedPlayerPositions {
    inner: Arc<RwLock<SharedPlayerPositionStore>>,
}

impl SharedPlayerPositions {
    pub fn with_capacity(capacity: usize) -> Self {
        SharedPlayerPositions {
            inner: Arc::new(RwLock::new(SharedPlayerPositionStore::with_capacity(
                capacity,
            ))),
        }
    }

    pub fn snapshot(&self) -> SharedPlayerPositionSnapshot {
        soccer_rwlock_read(&self.inner, "shared_player_positions").snapshot()
    }

    pub fn latest_for(&self, player_id: usize) -> Option<PlayerPositionSample> {
        soccer_rwlock_read(&self.inner, "shared_player_positions")
            .latest_for(player_id)
            .cloned()
    }

    pub fn history_for(&self, player_id: usize) -> Option<Vec<PlayerPositionSample>> {
        soccer_rwlock_read(&self.inner, "shared_player_positions")
            .histories
            .get(&player_id)
            .map(|history| history.iter().cloned().collect())
    }

    pub fn official_latest_for(&self, official_id: usize) -> Option<OfficialPositionSample> {
        soccer_rwlock_read(&self.inner, "shared_player_positions")
            .official_latest_for(official_id)
            .cloned()
    }

    pub fn official_history_for(&self, official_id: usize) -> Option<Vec<OfficialPositionSample>> {
        soccer_rwlock_read(&self.inner, "shared_player_positions")
            .official_histories
            .get(&official_id)
            .map(|history| history.iter().cloned().collect())
    }

    pub fn ball_latest(&self) -> Option<BallPositionSample> {
        soccer_rwlock_read(&self.inner, "shared_player_positions")
            .ball_latest
            .clone()
    }

    pub fn ball_history(&self) -> Vec<BallPositionSample> {
        soccer_rwlock_read(&self.inner, "shared_player_positions")
            .ball_history
            .iter()
            .cloned()
            .collect()
    }

    fn sync_from_players_and_ball(
        &self,
        players: &[PlayerAgent],
        officials: &[OfficialAgent],
        ball: &BallAgent,
        tick: u64,
        clock_seconds: f64,
    ) {
        soccer_rwlock_write(&self.inner, "shared_player_positions").sync_from_players_and_ball(
            players,
            officials,
            ball,
            tick,
            clock_seconds,
        );
    }

    fn snapshot_with_current_players(
        &self,
        players: &[PlayerAgent],
        officials: &[OfficialAgent],
        ball: &BallAgent,
        tick: u64,
        clock_seconds: f64,
        dt_seconds: f64,
    ) -> SharedPlayerPositionSnapshot {
        soccer_rwlock_read(&self.inner, "shared_player_positions").snapshot_with_current_players(
            players,
            officials,
            ball,
            tick,
            clock_seconds,
            dt_seconds,
        )
    }

    fn latest_snapshot_with_current_players(
        &self,
        players: &[PlayerAgent],
        officials: &[OfficialAgent],
        ball: &BallAgent,
        tick: u64,
        clock_seconds: f64,
        dt_seconds: f64,
    ) -> SharedPlayerPositionSnapshot {
        soccer_rwlock_read(&self.inner, "shared_player_positions")
            .latest_snapshot_with_current_players(
                players,
                officials,
                ball,
                tick,
                clock_seconds,
                dt_seconds,
            )
    }
}

impl Default for SharedPlayerPositions {
    fn default() -> Self {
        SharedPlayerPositions::with_capacity(PLAYER_POSITION_HISTORY_LIMIT)
    }
}

fn ball_agent_operation_order(
    tick: u64,
    action: &str,
    scheduled_index: Option<usize>,
) -> Vec<String> {
    let shot_weight = if matches!(action, "shot-blocked" | "save" | "keeper-parry" | "goal") {
        1.60
    } else {
        0.74
    };
    let holder_weight = if action == "held" { 1.72 } else { 0.82 };
    let boundary_weight = if restart_action_label(action).is_some() || action == "goal" {
        1.46
    } else {
        0.80
    };
    let control_weight = if matches!(action, "controlled" | "held") {
        1.36
    } else {
        0.92
    };
    let scheduled_bias = 1.0 + scheduled_index.unwrap_or(0) as f64 * 0.001;
    let tick_bias = 1.0 + (tick % 7) as f64 * 0.001;
    weighted_agentic_order(vec![
        ("sync-holder".to_string(), holder_weight * scheduled_bias),
        ("apply-curl".to_string(), 1.02),
        ("apply-resistance".to_string(), 1.18),
        ("advance-position".to_string(), 1.12 * tick_bias),
        ("resolve-shot".to_string(), shot_weight * tick_bias),
        ("resolve-boundary".to_string(), boundary_weight),
        ("resolve-control".to_string(), control_weight),
    ])
}

fn ball_sample_delta_seconds(
    a: &BallPositionSample,
    b: &BallPositionSample,
    fallback_dt_seconds: f64,
) -> Option<f64> {
    let sample_dt = b.clock_seconds - a.clock_seconds;
    if sample_dt.is_finite() && sample_dt > 0.0 {
        Some(sample_dt)
    } else if fallback_dt_seconds.is_finite() && fallback_dt_seconds > 0.0 {
        Some(fallback_dt_seconds)
    } else {
        None
    }
}

fn ball_sample_velocity_between(
    a: &BallPositionSample,
    b: &BallPositionSample,
    fallback_dt_seconds: f64,
) -> Option<Vec2> {
    let dt_seconds = ball_sample_delta_seconds(a, b, fallback_dt_seconds)?;
    Some((b.position - a.position) / dt_seconds)
}

fn ball_sample_acceleration_between(
    a: &BallPositionSample,
    b: &BallPositionSample,
    c: &BallPositionSample,
    fallback_dt_seconds: f64,
) -> Option<Vec2> {
    let dt_ab = ball_sample_delta_seconds(a, b, fallback_dt_seconds)?;
    let dt_bc = ball_sample_delta_seconds(b, c, fallback_dt_seconds)?;
    let velocity_ab = (b.position - a.position) / dt_ab;
    let velocity_bc = (c.position - b.position) / dt_bc;
    let midpoint_dt_seconds = ((dt_ab + dt_bc) * 0.5).max(1e-9);
    Some((velocity_bc - velocity_ab) / midpoint_dt_seconds)
}

fn ball_sample_jerk_between(
    a: &BallPositionSample,
    b: &BallPositionSample,
    c: &BallPositionSample,
    d: &BallPositionSample,
    fallback_dt_seconds: f64,
) -> Option<Vec2> {
    let dt_ab = ball_sample_delta_seconds(a, b, fallback_dt_seconds)?;
    let dt_bc = ball_sample_delta_seconds(b, c, fallback_dt_seconds)?;
    let dt_cd = ball_sample_delta_seconds(c, d, fallback_dt_seconds)?;
    let velocity_ab = (b.position - a.position) / dt_ab;
    let velocity_bc = (c.position - b.position) / dt_bc;
    let velocity_cd = (d.position - c.position) / dt_cd;
    let acceleration_ab_bc = (velocity_bc - velocity_ab) / ((dt_ab + dt_bc) * 0.5).max(1e-9);
    let acceleration_bc_cd = (velocity_cd - velocity_bc) / ((dt_bc + dt_cd) * 0.5).max(1e-9);
    let acceleration_midpoint_dt_seconds = ((dt_ab + 2.0 * dt_bc + dt_cd) * 0.25).max(1e-9);
    Some((acceleration_bc_cd - acceleration_ab_bc) / acceleration_midpoint_dt_seconds)
}

fn ball_position_sample_from_agent(
    ball: &BallAgent,
    tick: u64,
    clock_seconds: f64,
) -> BallPositionSample {
    BallPositionSample {
        tick,
        clock_seconds,
        position: ball.position,
        velocity: ball.velocity,
        acceleration: ball.acceleration,
        jerk: ball.jerk,
        curl_acceleration: ball.curl_acceleration,
        altitude_yards: ball.altitude_yards,
        resistance: ball.resistance,
        holder: ball.holder,
        last_touch_team: ball.last_touch_team,
    }
}

#[derive(Clone, Copy, Debug)]
struct CenterOfPlayCentroids {
    player_centroid: Vec2,
    live_play_centroid: Vec2,
    center_of_play: Vec2,
}

fn center_of_play_centroids(snapshot: &WorldSnapshot) -> CenterOfPlayCentroids {
    if snapshot.players.is_empty() {
        let center = Vec2::new(snapshot.field_width * 0.5, snapshot.field_length * 0.5);
        return CenterOfPlayCentroids {
            player_centroid: center,
            live_play_centroid: center,
            center_of_play: center,
        };
    }

    let mut player_sum = Vec2::zero();
    let mut live_play_sum = Vec2::zero();
    let mut live_play_weight = 0.0;
    for player in &snapshot.players {
        player_sum += player.position;
        let distance_to_ball = player.position.distance(snapshot.ball.position);
        let near_ball_weight = (1.0 - distance_to_ball / 42.0).clamp(0.0, 1.0);
        let holder_bonus = if snapshot.ball.holder == Some(player.id) {
            1.15
        } else {
            0.0
        };
        let weight = 0.28 + near_ball_weight * 1.72 + holder_bonus;
        live_play_sum += player.position * weight;
        live_play_weight += weight;
    }

    let player_centroid = player_sum / snapshot.players.len() as f64;
    let live_play_centroid = if live_play_weight > 0.0 {
        live_play_sum / live_play_weight
    } else {
        player_centroid
    };
    let center_of_play = (player_centroid * CENTER_REF_PLAYER_CENTROID_WEIGHT
        + live_play_centroid * CENTER_REF_LIVE_PLAY_CENTROID_WEIGHT
        + snapshot.ball.position * CENTER_REF_BALL_POSITION_WEIGHT)
        .clamp_to_pitch(snapshot.field_width, snapshot.field_length);
    CenterOfPlayCentroids {
        player_centroid,
        live_play_centroid,
        center_of_play,
    }
}

fn center_referee_play_centroid_target(snapshot: &WorldSnapshot) -> Vec2 {
    center_of_play_centroids(snapshot).center_of_play
}

fn official_clearance_target(
    kind: OfficialKind,
    target: Vec2,
    position: Vec2,
    snapshot: &WorldSnapshot,
) -> Vec2 {
    let clearance = match kind {
        OfficialKind::CenterReferee => CENTER_REF_BALL_CLEARANCE_YARDS,
        OfficialKind::AssistantRefereeNear | OfficialKind::AssistantRefereeFar => {
            ASSISTANT_REF_BALL_CLEARANCE_YARDS
        }
    };
    let fallback = official_clearance_fallback(kind, snapshot.ball.position, snapshot);
    let mut adjusted = point_with_clearance(target, snapshot.ball.position, fallback, clearance);

    if let Some(holder_position) = snapshot
        .ball
        .holder
        .and_then(|holder| snapshot.players.iter().find(|player| player.id == holder))
        .map(|player| player.position)
    {
        adjusted = point_with_clearance(adjusted, holder_position, fallback, clearance * 0.78);
    }

    let current_distance = position.distance(snapshot.ball.position);
    if current_distance < clearance {
        let away = if current_distance > 1e-6 {
            (position - snapshot.ball.position).normalized()
        } else {
            fallback
        };
        adjusted += away * (clearance - current_distance + 0.7);
    }

    adjusted.clamp_to_pitch(snapshot.field_width, snapshot.field_length)
}

fn point_with_clearance(point: Vec2, blocked: Vec2, fallback: Vec2, clearance: f64) -> Vec2 {
    let delta = point - blocked;
    let distance = delta.len();
    if distance >= clearance {
        point
    } else {
        let away = if distance > 1e-6 {
            delta.normalized()
        } else {
            fallback
        };
        blocked + away * clearance
    }
}

fn official_clearance_fallback(
    kind: OfficialKind,
    ball_position: Vec2,
    snapshot: &WorldSnapshot,
) -> Vec2 {
    match kind {
        OfficialKind::CenterReferee => {
            if ball_position.x <= snapshot.field_width * 0.5 {
                Vec2::new(1.0, 0.0)
            } else {
                Vec2::new(-1.0, 0.0)
            }
        }
        OfficialKind::AssistantRefereeNear | OfficialKind::AssistantRefereeFar => {
            if ball_position.y <= snapshot.field_length * 0.5 {
                Vec2::new(0.0, -1.0)
            } else {
                Vec2::new(0.0, 1.0)
            }
        }
    }
}

fn assistant_offside_line_snapshot(
    snapshot: &WorldSnapshot,
    kind: OfficialKind,
) -> Option<AssistantOffsideLineSnapshot> {
    let flank = match kind {
        OfficialKind::AssistantRefereeNear => AssistantFlank::Near,
        OfficialKind::AssistantRefereeFar => AssistantFlank::Far,
        OfficialKind::CenterReferee => return None,
    };
    let attacking_team = snapshot.possession_team()?;
    let defending_team = attacking_team.other();
    let mut defender_ys = snapshot
        .players
        .iter()
        .filter(|player| player.team == defending_team)
        .filter_map(|player| {
            snapshot
                .player_position(player.id)
                .map(|position| position.y)
        })
        .collect::<Vec<_>>();
    if defender_ys.len() < 2 {
        return None;
    }

    let halfway_y = snapshot.field_length * 0.5;
    let second_last_defender_y = match attacking_team {
        Team::Home => {
            defender_ys.sort_by(|a, b| b.partial_cmp(a).unwrap_or(std::cmp::Ordering::Equal));
            defender_ys[1]
        }
        Team::Away => {
            defender_ys.sort_by(|a, b| a.partial_cmp(b).unwrap_or(std::cmp::Ordering::Equal));
            defender_ys[1]
        }
    };
    let effective_line_y = match attacking_team {
        Team::Home => snapshot
            .ball
            .position
            .y
            .max(second_last_defender_y)
            .max(halfway_y),
        Team::Away => snapshot
            .ball
            .position
            .y
            .min(second_last_defender_y)
            .min(halfway_y),
    };
    let players_beyond_line = snapshot
        .players
        .iter()
        .filter(|player| player.team == attacking_team)
        .filter_map(|player| {
            let position = snapshot.player_position(player.id)?;
            if !assistant_flank_contains(flank, position, snapshot.field_width) {
                return None;
            }
            let beyond_line = match attacking_team {
                Team::Home => position.y > effective_line_y,
                Team::Away => position.y < effective_line_y,
            };
            beyond_line.then_some(player.id)
        })
        .collect();

    Some(AssistantOffsideLineSnapshot {
        flank,
        attacking_team,
        defending_team,
        second_last_defender_y,
        ball_y: snapshot.ball.position.y,
        halfway_y,
        effective_line_y,
        players_beyond_line,
    })
}

fn assistant_flank_contains(flank: AssistantFlank, position: Vec2, field_width: f64) -> bool {
    match flank {
        AssistantFlank::Near => position.x <= field_width * 0.5,
        AssistantFlank::Far => position.x > field_width * 0.5,
    }
}

#[derive(Clone, Debug, Serialize, Deserialize)]
#[serde(rename_all = "camelCase", default)]
pub struct SoccerTacticalLearningWeights {
    pub attack_spacing_delta_weight: f64,
    pub attack_spacing_score_weight: f64,
    pub attack_width_delta_weight: f64,
    pub attack_width_score_weight: f64,
    pub attack_flank_lane_weight: f64,
    pub shot_choice_learning_weight: f64,
    pub goal_entry_pass_learning_weight: f64,
    pub pressure_release_learning_weight: f64,
    pub pass_target_ranking_learning_weight: f64,
    pub defense_spacing_delta_weight: f64,
    pub defense_spacing_score_weight: f64,
    pub defense_contract_delta_weight: f64,
    pub defense_compactness_score_weight: f64,
    pub defense_ball_depth_score_weight: f64,
    pub defense_endline_soft_penalty_weight: f64,
    pub defense_endline_hard_penalty_weight: f64,
    pub defender_midfielder_press_weight: f64,
    pub midfielder_press_weight: f64,
    pub defensive_line_press_learning_weight: f64,
    pub formation_lp_alignment_weight: f64,
}

impl Default for SoccerTacticalLearningWeights {
    fn default() -> Self {
        SoccerTacticalLearningWeights {
            attack_spacing_delta_weight: 0.22,
            attack_spacing_score_weight: 0.06,
            attack_width_delta_weight: 0.68,
            attack_width_score_weight: 0.32,
            attack_flank_lane_weight: 0.50,
            shot_choice_learning_weight: 1.0,
            goal_entry_pass_learning_weight: 1.0,
            pressure_release_learning_weight: 1.0,
            pass_target_ranking_learning_weight: 1.0,
            defense_spacing_delta_weight: 0.08,
            defense_spacing_score_weight: 0.04,
            defense_contract_delta_weight: 0.42,
            defense_compactness_score_weight: 0.14,
            defense_ball_depth_score_weight: 0.22,
            defense_endline_soft_penalty_weight: 0.18,
            defense_endline_hard_penalty_weight: 0.90,
            defender_midfielder_press_weight: 0.18,
            midfielder_press_weight: 0.20,
            defensive_line_press_learning_weight: 1.0,
            formation_lp_alignment_weight: 0.16,
        }
    }
}

pub(crate) fn tactical_learning_weight_bias(weight: f64) -> f64 {
    (weight.clamp(0.0, 2.0) - 1.0).clamp(-1.0, 1.0)
}

pub(crate) fn tactical_learning_multiplier(weight: f64, span: f64) -> f64 {
    let span = span.max(0.0).min(1.0);
    (1.0 + tactical_learning_weight_bias(weight) * span).clamp(1.0 - span, 1.0 + span)
}

impl SoccerTacticalLearningWeights {
    fn validate(&self) -> Result<(), String> {
        for (name, value) in [
            ("attackSpacingDeltaWeight", self.attack_spacing_delta_weight),
            ("attackSpacingScoreWeight", self.attack_spacing_score_weight),
            ("attackWidthDeltaWeight", self.attack_width_delta_weight),
            ("attackWidthScoreWeight", self.attack_width_score_weight),
            ("attackFlankLaneWeight", self.attack_flank_lane_weight),
            ("shotChoiceLearningWeight", self.shot_choice_learning_weight),
            (
                "goalEntryPassLearningWeight",
                self.goal_entry_pass_learning_weight,
            ),
            (
                "pressureReleaseLearningWeight",
                self.pressure_release_learning_weight,
            ),
            (
                "passTargetRankingLearningWeight",
                self.pass_target_ranking_learning_weight,
            ),
            (
                "defenseSpacingDeltaWeight",
                self.defense_spacing_delta_weight,
            ),
            (
                "defenseSpacingScoreWeight",
                self.defense_spacing_score_weight,
            ),
            (
                "defenseContractDeltaWeight",
                self.defense_contract_delta_weight,
            ),
            (
                "defenseCompactnessScoreWeight",
                self.defense_compactness_score_weight,
            ),
            (
                "defenseBallDepthScoreWeight",
                self.defense_ball_depth_score_weight,
            ),
            (
                "defenseEndlineSoftPenaltyWeight",
                self.defense_endline_soft_penalty_weight,
            ),
            (
                "defenseEndlineHardPenaltyWeight",
                self.defense_endline_hard_penalty_weight,
            ),
            (
                "defenderMidfielderPressWeight",
                self.defender_midfielder_press_weight,
            ),
            ("midfielderPressWeight", self.midfielder_press_weight),
            (
                "defensiveLinePressLearningWeight",
                self.defensive_line_press_learning_weight,
            ),
            (
                "formationLpAlignmentWeight",
                self.formation_lp_alignment_weight,
            ),
        ] {
            if !value.is_finite() {
                return Err(format!("{name} must be finite"));
            }
            if !(-5.0..=5.0).contains(&value) {
                return Err(format!("{name} must be between -5.0 and 5.0"));
            }
        }
        Ok(())
    }
}

fn default_tactical_learning_weights() -> SoccerTacticalLearningWeights {
    SoccerTacticalLearningWeights::default()
}

