/// How the trained value head is combined with the tabular Q-policy at decision
/// time. The value head learns the continuous interactions the discretised Q-key
/// destroys (the "hidden variables" governing emergent shape); these modes pick
/// how much it is trusted over the proven tabular brain. `Off` by default, so the
/// net is trained but never consulted unless a run opts in — mirroring how
/// `exploration_epsilon` defaults to 0.
#[derive(Clone, Copy, Debug, PartialEq, Eq, Default, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub enum SoccerNeuralBlendMode {
    /// Decisions stay purely tabular; the value head is trained but not read.
    Off,
    /// `Q_eff(s,a) = Q_tab(s,a) + λ·V_net(s,a)` (both in Q units). The net nudges;
    /// the tabular value is the floor.
    ///
    /// DEFAULT: the tabular Q-state (`SoccerMdpState`) is a coarse grid/facing/phase key that
    /// aliases wildly different 22-player configurations onto the same bin, so it can't learn
    /// position-dependent decisions — the long-standing learning plateau. The neural value
    /// head, by contrast, conditions on the full canonical 22+ball motion vector
    /// (position/velocity/acceleration/jerk), so blending it in grounds the decision in the
    /// real kinematic state and de-aliases the bins. Inert until a neural learner is enabled
    /// AND warm (`effective_lambda` ramps 0→λ over `warmup_steps`), so this is a no-op for the
    /// tabular-only / non-neural runs and tests.
    #[default]
    Additive,
    /// The tabular ranking chooses; the net only re-orders candidates whose
    /// tabular values sit within `tie_epsilon` of the best — never promotes a
    /// clearly-worse action.
    TieBreak,
    /// Trust the net only where the tabular state-action is under-visited
    /// (`visits < min_confidence_visits`) — it fills the generalisation gaps the
    /// bins leave blank, tabular elsewhere.
    ConfidenceGated,
    /// The neural critic/actor owns the legal-action ranking. Tabular Q-values
    /// only supply the legal candidate set and a deterministic last-ditch tie
    /// breaker, so league/evolutionary policy fitness cannot overrule the net.
    Authoritative,
}

/// Decision-time coupling of the neural value head to the tabular policy.
#[derive(Clone, Copy, Debug, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct SoccerNeuralBlendConfig {
    #[serde(default)]
    pub mode: SoccerNeuralBlendMode,
    /// Peak weight on neural value (Q units) once the head is warmed up. Ramps
    /// 0 → `lambda` over `warmup_steps` training steps.
    #[serde(default = "default_soccer_neural_blend_lambda")]
    pub lambda: f64,
    /// Tabular-value window (Q units) treated as a tie in `TieBreak` mode.
    #[serde(default = "default_soccer_neural_blend_tie_epsilon")]
    pub tie_epsilon: f64,
    /// State-action visit count below which `ConfidenceGated` defers to the net.
    #[serde(default = "default_soccer_neural_blend_min_visits")]
    pub min_confidence_visits: u32,
    /// Top-N tabular candidates re-scored by the net per decision.
    #[serde(default = "default_soccer_neural_blend_candidates")]
    pub candidates: usize,
    /// Training steps over which λ ramps from 0 to `lambda`, so a cold/half-trained
    /// head can't yank decisions around before it has learned anything.
    #[serde(default = "default_soccer_neural_blend_warmup_steps")]
    pub warmup_steps: usize,
    /// Train and consult the neural **actor** `π(family|s)` (advantage
    /// policy-gradient from the critic). When on, the actor's log-probability
    /// biases action selection on top of the value blend. Off by default.
    #[serde(default)]
    pub actor_critic: bool,
    /// Train the learned **world model** `P̂(s'|s,a)` on the episode replay. Off
    /// by default. (Used for model-based value look-ahead / diagnostics; it does
    /// not alter action selection on its own.)
    #[serde(default)]
    pub world_model: bool,
    /// Budgeted neural-guided MCTS re-ranker over the already-legal MDP/POMDP
    /// action candidates. This is deliberately action-level only: no full match
    /// clone, no joint/team MPC, and no per-player MPC solve inside the tree.
    #[serde(default)]
    pub mcts_enabled: bool,
    /// Root simulations per decision. Kept tiny for live play; each simulation
    /// uses cached candidate value/actor/retrieval estimates.
    #[serde(default = "default_soccer_neural_mcts_simulations")]
    pub mcts_simulations: usize,
    /// Candidate cap searched by MCTS after the normal neural blend has scored
    /// legal actions.
    #[serde(default = "default_soccer_neural_mcts_candidates")]
    pub mcts_candidates: usize,
    /// Optional learned-world-model rollout depth. `1` means root-only (no world
    /// model); deeper values are clamped and only matter when `world_model` has a
    /// trained predictor available.
    #[serde(default = "default_soccer_neural_mcts_depth")]
    pub mcts_depth: usize,
    /// PUCT-style exploration constant used inside the small action tree.
    #[serde(default = "default_soccer_neural_mcts_exploration")]
    pub mcts_exploration: f64,
    /// Weight for optional world-model rollout value added to MCTS leaf scoring.
    #[serde(default = "default_soccer_neural_mcts_model_weight")]
    pub mcts_model_weight: f64,
}

fn default_soccer_neural_blend_lambda() -> f64 {
    0.5
}
fn default_soccer_neural_blend_tie_epsilon() -> f64 {
    0.05
}
fn default_soccer_neural_blend_min_visits() -> u32 {
    4
}
fn default_soccer_neural_blend_candidates() -> usize {
    // The value net is queried once PER candidate at decision time (per player, per tick),
    // so this is the dominant decision-phase cost. 4 keeps the best actions re-ranked while
    // trimming the per-tick neural work (smoother steps).
    4
}
fn default_soccer_neural_blend_warmup_steps() -> usize {
    200
}
fn default_soccer_neural_mcts_simulations() -> usize {
    8
}
fn default_soccer_neural_mcts_candidates() -> usize {
    4
}
fn default_soccer_neural_mcts_depth() -> usize {
    1
}
fn default_soccer_neural_mcts_exploration() -> f64 {
    1.25
}
fn default_soccer_neural_mcts_model_weight() -> f64 {
    0.35
}

impl Default for SoccerNeuralBlendConfig {
    fn default() -> Self {
        SoccerNeuralBlendConfig {
            // Additive (kinematic value head grounds decisions) once a neural learner is warm;
            // inert otherwise. See `SoccerNeuralBlendMode::Additive`.
            mode: SoccerNeuralBlendMode::Additive,
            lambda: default_soccer_neural_blend_lambda(),
            tie_epsilon: default_soccer_neural_blend_tie_epsilon(),
            min_confidence_visits: default_soccer_neural_blend_min_visits(),
            candidates: default_soccer_neural_blend_candidates(),
            warmup_steps: default_soccer_neural_blend_warmup_steps(),
            actor_critic: false,
            world_model: false,
            mcts_enabled: false,
            mcts_simulations: default_soccer_neural_mcts_simulations(),
            mcts_candidates: default_soccer_neural_mcts_candidates(),
            mcts_depth: default_soccer_neural_mcts_depth(),
            mcts_exploration: default_soccer_neural_mcts_exploration(),
            mcts_model_weight: default_soccer_neural_mcts_model_weight(),
        }
    }
}

impl SoccerNeuralBlendConfig {
    /// Readiness in [0, 1]: how much of `lambda` to apply given how far the value
    /// head has trained. 0 until the head has a finite loss and at least one step;
    /// ramps linearly to 1 at `warmup_steps`. Keeps an untrained net out of play.
    fn readiness(&self, training_steps: usize, average_loss: Option<f64>) -> f64 {
        if !matches!(average_loss, Some(loss) if loss.is_finite()) {
            return 0.0;
        }
        let warmup = self.warmup_steps.max(1) as f64;
        (training_steps as f64 / warmup).clamp(0.0, 1.0)
    }

    /// Effective λ after the warm-up ramp.
    fn effective_lambda(&self, training_steps: usize, average_loss: Option<f64>) -> f64 {
        if !self.lambda.is_finite() || self.lambda <= 0.0 {
            return 0.0;
        }
        self.lambda * self.readiness(training_steps, average_loss)
    }

    fn sanitized_mcts_simulations(&self) -> usize {
        self.mcts_simulations.clamp(1, 32)
    }

    fn sanitized_mcts_candidates(&self) -> usize {
        self.mcts_candidates.clamp(2, 16)
    }

    fn sanitized_mcts_depth(&self) -> usize {
        self.mcts_depth.clamp(1, 3)
    }

    fn sanitized_mcts_exploration(&self) -> f64 {
        if self.mcts_exploration.is_finite() {
            self.mcts_exploration.clamp(0.0, 4.0)
        } else {
            default_soccer_neural_mcts_exploration()
        }
    }

    fn sanitized_mcts_model_weight(&self) -> f64 {
        if self.mcts_model_weight.is_finite() {
            self.mcts_model_weight.clamp(0.0, 1.0)
        } else {
            default_soccer_neural_mcts_model_weight()
        }
    }
}

#[derive(Clone, Debug, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct SoccerNeuralLearningConfig {
    #[serde(default)]
    pub enabled: bool,
    #[serde(default)]
    pub backend: SoccerNeuralLearningBackend,
    #[serde(default = "default_soccer_neural_learning_rate")]
    pub learning_rate: f64,
    /// Classical SGD momentum for the value critic. This is an optimizer aid for
    /// Bellman/counterfactual learning, not a reward or promotion shortcut.
    #[serde(default = "default_soccer_neural_optimizer_momentum")]
    pub optimizer_momentum: f64,
    #[serde(default = "default_soccer_neural_batch_size")]
    pub batch_size: usize,
    #[serde(default = "default_soccer_neural_train_every_ticks")]
    pub train_every_ticks: usize,
    #[serde(default = "default_soccer_neural_max_batches_per_tick")]
    pub max_batches_per_tick: usize,
    #[serde(default = "default_soccer_neural_hidden_units")]
    pub hidden_units: usize,
    #[serde(default = "default_soccer_neural_target_scale")]
    pub target_scale: f64,
    #[serde(default = "default_soccer_neural_max_pending_batches")]
    pub max_pending_batches: usize,
    #[serde(default = "default_soccer_neural_replay_capacity")]
    pub replay_capacity: usize,
    #[serde(default = "default_soccer_neural_replay_samples_per_tick")]
    pub replay_samples_per_tick: usize,
    #[serde(default = "default_soccer_neural_target_clip")]
    pub target_clip: f64,
    /// PopArt target normalization for the value critic. When enabled, clipped
    /// target units are tracked with a running mean/std, the network trains on
    /// normalized labels, and output-layer affine weights are rescaled whenever
    /// stats move so unnormalized predictions remain stable.
    #[serde(default)]
    pub target_popart_enabled: bool,
    #[serde(default = "default_soccer_neural_snapshot_every_batches")]
    pub snapshot_every_batches: usize,
    /// When enabled, the gradient-trained critic feeds the formation LP: each
    /// team's most-recent transition value is squashed into an attack/defense
    /// contribution that routes through the existing (bounded) adversarial
    /// embedding channel of the LP objective. Off by default — opt-in so the
    /// live positioner is never silently steered by a half-trained net.
    #[serde(default)]
    pub lp_coupling_enabled: bool,
    /// Actor-critic coupling strength: the fraction of the critic's value
    /// estimate subtracted from the discrete Q reward as a control variate
    /// (advantage baseline). `0.0` (the default) leaves the tabular Q trainer
    /// untouched; raise cautiously, since the critic's full-game-return target
    /// units differ from the per-tick centered reward.
    #[serde(default)]
    pub critic_baseline_weight: f64,
    /// **MAPPO cooperative-credit share**: how much each agent's policy-gradient
    /// reward is replaced by its *team's* per-tick mean reward, before the
    /// existing zero-sum opponent centering. `0.0` (the default) is the fully
    /// individual-reward objective — byte-identical to the pre-MAPPO trainer.
    /// At `w` the per-transition reward becomes `(1-w)·rᵢ + w·r̄_team`, so a
    /// player begins optimising the shared team return (the centralized-critic
    /// advantage in `neural_policy_training_samples` then credits a teammate's
    /// later goal back to the off-ball work that set it up). `1.0` is a fully
    /// shared team reward (classic cooperative MARL). Clamped to `[0, 1]`.
    ///
    /// Complements the `marl_*` fields below: this share folds the team mean into
    /// the per-transition reward at capture time, while the `marl_*` weights shape
    /// the centralized critic/advantage during the MAPPO update.
    #[serde(default)]
    pub mappo_team_reward_share: f64,
    /// Multi-agent learning mode. MAPPO keeps one decentralized actor per player
    /// decision while shaping the critic/advantage with centralized team rewards.
    #[serde(default)]
    pub marl_algorithm: SoccerMarlAlgorithm,
    /// Weight on the cooperative team component: team average reward minus the
    /// opponent team's same-tick average reward.
    #[serde(default = "default_soccer_marl_team_reward_weight")]
    pub marl_team_reward_weight: f64,
    /// Weight on the actor's own dense/intermediate reward signal.
    #[serde(default = "default_soccer_marl_intermediate_reward_weight")]
    pub marl_intermediate_reward_weight: f64,
    /// PPO clip epsilon for MAPPO actor updates.
    #[serde(default = "default_soccer_mappo_clip_epsilon")]
    pub mappo_clip_epsilon: f64,
}

impl Default for SoccerNeuralLearningConfig {
    fn default() -> Self {
        SoccerNeuralLearningConfig {
            enabled: false,
            backend: SoccerNeuralLearningBackend::Inline,
            learning_rate: DEFAULT_SOCCER_NEURAL_LEARNING_RATE,
            optimizer_momentum: DEFAULT_SOCCER_NEURAL_OPTIMIZER_MOMENTUM,
            batch_size: DEFAULT_SOCCER_NEURAL_BATCH_SIZE,
            train_every_ticks: DEFAULT_SOCCER_NEURAL_TRAIN_EVERY_TICKS,
            max_batches_per_tick: DEFAULT_SOCCER_NEURAL_MAX_BATCHES_PER_TICK,
            hidden_units: DEFAULT_SOCCER_NEURAL_HIDDEN_UNITS,
            target_scale: DEFAULT_SOCCER_NEURAL_TARGET_SCALE,
            max_pending_batches: DEFAULT_SOCCER_NEURAL_MAX_PENDING_BATCHES,
            replay_capacity: DEFAULT_SOCCER_NEURAL_REPLAY_CAPACITY,
            replay_samples_per_tick: DEFAULT_SOCCER_NEURAL_REPLAY_SAMPLES_PER_TICK,
            target_clip: DEFAULT_SOCCER_NEURAL_TARGET_CLIP,
            target_popart_enabled: false,
            snapshot_every_batches: DEFAULT_SOCCER_NEURAL_SNAPSHOT_EVERY_BATCHES,
            lp_coupling_enabled: false,
            critic_baseline_weight: 0.0,
            mappo_team_reward_share: 0.0,
            marl_algorithm: SoccerMarlAlgorithm::Mappo,
            marl_team_reward_weight: DEFAULT_SOCCER_MARL_TEAM_REWARD_WEIGHT,
            marl_intermediate_reward_weight: DEFAULT_SOCCER_MARL_INTERMEDIATE_REWARD_WEIGHT,
            mappo_clip_epsilon: DEFAULT_SOCCER_MAPPO_CLIP_EPSILON,
        }
    }
}

impl SoccerNeuralLearningConfig {
    fn sanitized_batch_size(&self) -> usize {
        self.batch_size.clamp(1, MAX_SOCCER_NEURAL_BATCH_SIZE)
    }

    fn sanitized_train_every_ticks(&self) -> usize {
        self.train_every_ticks.max(1)
    }

    fn sanitized_max_batches_per_tick(&self) -> usize {
        self.max_batches_per_tick
            .clamp(1, MAX_SOCCER_NEURAL_MAX_BATCHES_PER_TICK)
    }

    fn sanitized_hidden_units(&self) -> usize {
        self.hidden_units.clamp(2, MAX_SOCCER_NEURAL_HIDDEN_UNITS)
    }

    fn sanitized_learning_rate(&self) -> f64 {
        soccer_sanitized_learning_rate(self.learning_rate, DEFAULT_SOCCER_NEURAL_LEARNING_RATE)
    }

    fn sanitized_optimizer_momentum(&self) -> f64 {
        if self.optimizer_momentum.is_finite() {
            self.optimizer_momentum
                .clamp(0.0, MAX_SOCCER_NEURAL_OPTIMIZER_MOMENTUM)
        } else {
            DEFAULT_SOCCER_NEURAL_OPTIMIZER_MOMENTUM
        }
    }

    fn sanitized_critic_baseline_weight(&self) -> f64 {
        if self.critic_baseline_weight.is_finite() {
            self.critic_baseline_weight.clamp(0.0, 1.0)
        } else {
            0.0
        }
    }

    /// MAPPO team-reward share, clamped to `[0, 1]`; a non-finite value falls
    /// back to the individual-reward objective (`0.0`).
    fn sanitized_mappo_team_reward_share(&self) -> f64 {
        if self.mappo_team_reward_share.is_finite() {
            self.mappo_team_reward_share.clamp(0.0, 1.0)
        } else {
            0.0
        }
    }

    fn sanitized_marl_team_reward_weight(&self) -> f64 {
        if self.marl_team_reward_weight.is_finite() {
            self.marl_team_reward_weight.clamp(0.0, 1.0)
        } else {
            DEFAULT_SOCCER_MARL_TEAM_REWARD_WEIGHT
        }
    }

    fn sanitized_marl_intermediate_reward_weight(&self) -> f64 {
        if self.marl_intermediate_reward_weight.is_finite() {
            self.marl_intermediate_reward_weight.clamp(0.0, 2.0)
        } else {
            DEFAULT_SOCCER_MARL_INTERMEDIATE_REWARD_WEIGHT
        }
    }

    fn sanitized_mappo_clip_epsilon(&self) -> f64 {
        if self.mappo_clip_epsilon.is_finite() {
            self.mappo_clip_epsilon.clamp(0.01, 1.0)
        } else {
            DEFAULT_SOCCER_MAPPO_CLIP_EPSILON
        }
    }

    fn marl_enabled(&self) -> bool {
        self.enabled && self.marl_algorithm != SoccerMarlAlgorithm::Off
    }

    fn mappo_enabled(&self) -> bool {
        self.enabled && self.marl_algorithm == SoccerMarlAlgorithm::Mappo
    }

    fn sanitized_target_scale(&self) -> f64 {
        if self.target_scale.is_finite() && self.target_scale.abs() > 1e-9 {
            self.target_scale.abs()
        } else {
            DEFAULT_SOCCER_NEURAL_TARGET_SCALE
        }
    }

    fn sanitized_max_pending_batches(&self) -> usize {
        self.max_pending_batches
            .clamp(1, MAX_SOCCER_NEURAL_MAX_PENDING_BATCHES)
    }

    fn sanitized_replay_capacity(&self) -> usize {
        self.replay_capacity.min(MAX_SOCCER_NEURAL_REPLAY_CAPACITY)
    }

    fn sanitized_replay_samples_per_tick(&self) -> usize {
        self.replay_samples_per_tick
            .min(MAX_SOCCER_NEURAL_REPLAY_SAMPLES_PER_TICK)
    }

    fn sanitized_target_clip(&self) -> f64 {
        if self.target_clip.is_finite() && self.target_clip > 0.0 {
            self.target_clip
        } else {
            DEFAULT_SOCCER_NEURAL_TARGET_CLIP
        }
    }

    fn sanitized_snapshot_every_batches(&self) -> usize {
        self.snapshot_every_batches
            .min(MAX_SOCCER_NEURAL_SNAPSHOT_EVERY_BATCHES)
    }
}

/// Model Predictive Control coupling. The learned MDP/POMDP policy and the
/// formation LP own the perennial decisions (which intent, which shape); MPC is a
/// short-horizon, real-time execution layer. Its base point-mass problem is the
/// clean linear/convex case (linear dynamics, quadratic tracking, convex accel
/// bound). Field-aware keep-outs add local soft obstacle penalties, so MPC remains
/// a deadline-bounded execution optimizer rather than a global multi-pass planner.
/// Everything is off by default, so a run that does not opt in behaves
/// byte-for-byte as before.
#[derive(Clone, Copy, Debug, Serialize, Deserialize, PartialEq)]
#[serde(rename_all = "camelCase")]
pub struct SoccerMpcConfig {
    /// Tier-2 per-player receding-horizon execution: the active subset (ball
    /// carrier + players contesting near the ball) has its arrival/acceleration
    /// speed profile planned by a 2-D point-mass MPC instead of the open-loop
    /// "head straight at the target at top speed" heuristic. Direction and
    /// collision-avoidance steering stay heuristic. Off by default.
    ///
    /// MPC is an INDIVIDUAL-player tool only — it controls one actor's own
    /// trajectory. There is deliberately no team/collective MPC layer: team shape
    /// is owned by the formation LP and each player's POMDP, never a joint
    /// multi-player optimizer.
    #[serde(default)]
    pub tier2_player_enabled: bool,
    /// Horizon length (ticks) for the per-player controller.
    #[serde(default = "default_soccer_mpc_player_horizon")]
    pub player_horizon: usize,
    /// Radius (yards) around the ball within which an off-ball player joins the
    /// Tier-2 active subset. The ball carrier is always included; players farther
    /// than this stay on the cheap analytic path so 22 × MPC never runs per tick.
    #[serde(default = "default_soccer_mpc_active_radius_yards")]
    pub active_radius_yards: f64,
    /// MDP↔MPC reconciliation. When on (requires `tier2_player_enabled`), the
    /// learned-policy/heuristic movement decision (the "MDP" side) and the MPC
    /// movement decision are computed independently, their divergence is recorded,
    /// and — *only when an average makes sense* (the two are not pulling in
    /// opposed directions) — the executed velocity is a weighted average of the
    /// two. When they contradict, the learned policy owns WHERE to go (no average)
    /// and the divergence is logged. Off by default.
    #[serde(default)]
    pub reconcile_enabled: bool,
    /// Weight on the MPC decision in the blend, in `[0, 1]` (0 = pure MDP,
    /// 1 = pure MPC). Only consulted while reconciling and the two agree enough.
    #[serde(default = "default_soccer_mpc_blend_alpha")]
    pub blend_alpha: f64,
    /// Minimum directional agreement (cosine of the angle between the MDP and MPC
    /// desired velocities) for an average to "make sense". At/above this the two
    /// are blended; below it (e.g. one says push forward, the other says brake or
    /// peel off) averaging would cancel into nonsense, so the policy decision is
    /// kept instead. Default 0.0 → blend whenever they are not actively opposed.
    #[serde(default = "default_soccer_mpc_blend_min_alignment")]
    pub blend_min_alignment: f64,
    /// Divergence (yards/second between the two desired velocities) above which a
    /// tick is counted as "deviating" in the reconciliation stats.
    #[serde(default = "default_soccer_mpc_deviation_threshold_yps")]
    pub deviation_threshold_yps: f64,
    /// Field awareness: when on (requires `tier2_player_enabled`), the per-player
    /// MPC keeps the controlled player as the point-mass state, then plans around
    /// every other player plus the ball as moving soft keep-outs. Obstacle centers
    /// and velocities are projected from position, velocity, and acceleration, so
    /// the planned path bends around where opponents/teammates/the ball will be.
    /// Off by default (the plan only tracks its target).
    #[serde(default)]
    pub field_aware_enabled: bool,
    /// Keep-out radius (yards) around each opponent the plan avoids.
    #[serde(default = "default_soccer_mpc_opponent_keepout_yards")]
    pub opponent_keepout_yards: f64,
    /// Keep-out radius (yards) around each teammate (smaller — just don't collide;
    /// shape/spacing is owned by the formation LP, not this layer).
    #[serde(default = "default_soccer_mpc_teammate_keepout_yards")]
    pub teammate_keepout_yards: f64,
    /// Soft-penalty weight on opponent incursion (per yard²). Teammates use a
    /// quarter of this.
    #[serde(default = "default_soccer_mpc_keepout_weight")]
    pub keepout_weight: f64,
    /// Feed learned, bounded outcome signals into the short-horizon MPC objective:
    /// pass-chain continuity, shot pressure, and goal pressure. These are hidden
    /// variables for execution only; the neural/MDP layer still chooses the action.
    /// Off by default.
    #[serde(default)]
    pub latent_objective_enabled: bool,
    /// Exponential update rate for each latent term when a relevant outcome lands.
    #[serde(default = "default_soccer_mpc_latent_learning_rate")]
    pub latent_learning_rate: f64,
    /// Max yards of attack-direction reference shaping applied by the latent terms.
    #[serde(default = "default_soccer_mpc_latent_reference_bias_yards")]
    pub latent_reference_bias_yards: f64,
    /// Max multiplier bump applied to positive quadratic tracking weights.
    #[serde(default = "default_soccer_mpc_latent_weight_boost")]
    pub latent_weight_boost: f64,
}

/// Runtime hidden variables that let outcome learning talk to the 3-second MPC
/// execution layer without making MPC decide a whole possession. Values are kept
/// in `[0, 1]` and only ever increase positive quadratic weights or nudge the
/// reference a bounded distance in the attacking direction, preserving the convex
/// base problem.
#[derive(Clone, Copy, Debug, Default, PartialEq, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct SoccerMpcLatentObjective {
    pub pass_chain_continuity: f64,
    pub shot_pressure: f64,
    pub goal_pressure: f64,
    /// Recent success rate of wall-passes (one-twos) / through-balls, learned from completed-pass
    /// events. Folds into `combined_pressure` so the MPC arrives more decisively forward when the
    /// team is combining well. `#[serde(default)]` keeps older persisted objectives loadable.
    #[serde(default)]
    pub wall_pass_intent: f64,
    #[serde(default)]
    pub through_ball_intent: f64,
}

impl SoccerMpcLatentObjective {
    fn sanitized(self) -> Self {
        SoccerMpcLatentObjective {
            pass_chain_continuity: finite_unit_interval(self.pass_chain_continuity),
            shot_pressure: finite_unit_interval(self.shot_pressure),
            goal_pressure: finite_unit_interval(self.goal_pressure),
            wall_pass_intent: finite_unit_interval(self.wall_pass_intent),
            through_ball_intent: finite_unit_interval(self.through_ball_intent),
        }
    }

    fn blended_with(self, target: SoccerMpcLatentObjective, rate: f64) -> Self {
        let current = self.sanitized();
        let target = target.sanitized();
        let rate = finite_unit_interval(rate);
        let blend = |a: f64, b: f64| a * (1.0 - rate) + b * rate;
        SoccerMpcLatentObjective {
            pass_chain_continuity: blend(
                current.pass_chain_continuity,
                target.pass_chain_continuity,
            ),
            shot_pressure: blend(current.shot_pressure, target.shot_pressure),
            goal_pressure: blend(current.goal_pressure, target.goal_pressure),
            wall_pass_intent: blend(current.wall_pass_intent, target.wall_pass_intent),
            through_ball_intent: blend(current.through_ball_intent, target.through_ball_intent),
        }
        .sanitized()
    }

    fn combined_pressure(self) -> f64 {
        let s = self.sanitized();
        // Weights sum to 1.0 so the result stays a unit interval; the pattern intents give the
        // forward-arrival bias a modest lift when the team is combining (one-twos / through-balls).
        (0.30 * s.pass_chain_continuity
            + 0.22 * s.shot_pressure
            + 0.26 * s.goal_pressure
            + 0.12 * s.wall_pass_intent
            + 0.10 * s.through_ball_intent)
            .clamp(0.0, 1.0)
    }
}

fn finite_unit_interval(value: f64) -> f64 {
    if value.is_finite() {
        value.clamp(0.0, 1.0)
    } else {
        0.0
    }
}

fn default_soccer_mpc_player_horizon() -> usize {
    // ~2.0 s of lookahead at the 15 Hz default tick (30 × 1/15). Long enough to
    // bend around nearby traffic and brake into a target, short enough that
    // receding-horizon execution reacts promptly instead of feeling delayed.
    30
}

