/// Running tally of how often the learned-policy ("MDP") movement decision and
/// the MPC movement decision diverged, and how the reconciliation resolved it.
/// Pure runtime telemetry — reset per match, never serialized into a frame.
#[derive(Clone, Copy, Debug, Default, PartialEq, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct SoccerMpcReconcileStats {
    /// Active-player ticks where both decisions were computed and compared.
    pub samples: u64,
    /// Of those, how many diverged by more than `deviation_threshold_yps`.
    pub deviating_samples: u64,
    /// How many were resolved by averaging the two (they agreed enough).
    pub blended_samples: u64,
    /// How many kept the policy decision because an average made no sense
    /// (the decisions were directionally opposed).
    pub deferred_to_policy_samples: u64,
    /// Sum of per-sample divergence (yards/second), for a running mean.
    pub sum_deviation_yps: f64,
    /// Largest single divergence (yards/second) seen this match.
    pub max_deviation_yps: f64,
}

impl SoccerMpcReconcileStats {
    /// Mean divergence (yards/second) across all compared samples.
    pub fn mean_deviation_yps(&self) -> f64 {
        if self.samples == 0 {
            return 0.0;
        }
        self.sum_deviation_yps / self.samples as f64
    }
}

fn default_retrieval_top_k() -> usize {
    100
}
fn default_retrieval_outcome_gamma() -> f64 {
    0.95
}
fn default_retrieval_outcome_horizon() -> usize {
    40
}
fn default_retrieval_prior_weight() -> f64 {
    0.5
}
fn default_retrieval_proximity_weight_enabled() -> bool {
    true
}
fn default_retrieval_proximity_tau_yards() -> f64 {
    14.0
}
fn default_retrieval_behind_ball_discount_enabled() -> bool {
    true
}
fn default_retrieval_behind_ball_yards() -> f64 {
    6.0
}
fn default_retrieval_opponent_end_fraction() -> f64 {
    0.5
}

/// Configuration for the retrieval-guided decision pipeline: capturing whole-field
/// configuration moments (the 22-player + ball [`SoccerConfigVector`] plus the
/// decision taken and its outcome) for cross-game vector search, and — at decision
/// time — folding retrieved neighbours' decisions into the MDP/POMDP action
/// ranking as a bounded prior. Everything is **off by default**, so play is
/// byte-identical until a consumer opts in.
#[derive(Clone, Debug, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct SoccerRetrievalConfig {
    /// Capture per-tick **carrier** config-moments (config vector + decision)
    /// onto the learning transitions so they can be persisted for retrieval.
    /// Off ⇒ no capture, no per-tick cost, identical play.
    #[serde(default)]
    pub capture_enabled: bool,
    /// At decision time, fold retrieved neighbour decisions into the action
    /// ranking as a bounded additive prior. Off ⇒ the policy decides unchanged.
    #[serde(default)]
    pub decision_prior_enabled: bool,
    /// Neighbours fetched per retrieval query ("find the N closest configs").
    #[serde(default = "default_retrieval_top_k")]
    pub top_k: usize,
    /// Discount γ for the n-step outcome return stored with each moment.
    #[serde(default = "default_retrieval_outcome_gamma")]
    pub outcome_gamma: f64,
    /// Horizon (this player's future transitions) for the n-step outcome return.
    #[serde(default = "default_retrieval_outcome_horizon")]
    pub outcome_horizon: usize,
    /// Bounded weight of the retrieval prior added to normalised action values.
    #[serde(default = "default_retrieval_prior_weight")]
    pub prior_weight: f64,
    /// Refine the top neighbours with a Hungarian player-alignment re-rank
    /// (permutation-exact distance) before aggregating. Off ⇒ cosine order only.
    #[serde(default)]
    pub hungarian_realign: bool,
    /// Down-weight players by distance from the ball when comparing configs, so
    /// the players around the ball dominate the similarity. Off ⇒ legacy
    /// equal-weight comparison.
    #[serde(default = "default_retrieval_proximity_weight_enabled")]
    pub proximity_weight_enabled: bool,
    /// Characteristic decay length (yards) for the proximity weight
    /// (`weight = exp(-distance / tau)`).
    #[serde(default = "default_retrieval_proximity_tau_yards")]
    pub proximity_tau_yards: f64,
    /// Fully discount players far behind the ball while the attacking team is in
    /// the opponent's end (they are out of the immediate play).
    #[serde(default = "default_retrieval_behind_ball_discount_enabled")]
    pub behind_ball_discount_enabled: bool,
    /// How far behind the ball (yards) a player must be to be discounted.
    #[serde(default = "default_retrieval_behind_ball_yards")]
    pub behind_ball_yards: f64,
    /// Fraction of pitch length past which the ball counts as the opponent's end.
    #[serde(default = "default_retrieval_opponent_end_fraction")]
    pub opponent_end_fraction: f64,
}

impl Default for SoccerRetrievalConfig {
    fn default() -> Self {
        SoccerRetrievalConfig {
            capture_enabled: false,
            decision_prior_enabled: false,
            top_k: default_retrieval_top_k(),
            outcome_gamma: default_retrieval_outcome_gamma(),
            outcome_horizon: default_retrieval_outcome_horizon(),
            prior_weight: default_retrieval_prior_weight(),
            hungarian_realign: false,
            proximity_weight_enabled: default_retrieval_proximity_weight_enabled(),
            proximity_tau_yards: default_retrieval_proximity_tau_yards(),
            behind_ball_discount_enabled: default_retrieval_behind_ball_discount_enabled(),
            behind_ball_yards: default_retrieval_behind_ball_yards(),
            opponent_end_fraction: default_retrieval_opponent_end_fraction(),
        }
    }
}

impl SoccerRetrievalConfig {
    /// Map these tunables into the [`ConfigWeightOptions`] consumed by
    /// [`SoccerConfigVector::from_snapshot_with`], so the corpus build and the
    /// live query share one source of truth for the weighting.
    pub fn weight_options(&self) -> ConfigWeightOptions {
        ConfigWeightOptions {
            proximity_enabled: self.proximity_weight_enabled,
            proximity_tau_yards: self.proximity_tau_yards,
            behind_ball_discount_enabled: self.behind_ball_discount_enabled,
            behind_ball_yards: self.behind_ball_yards,
            opponent_end_fraction: self.opponent_end_fraction,
            // The stored corpus weights by the ball point; an action-specific lane is supplied only
            // by the live capture/query that knows the planned trajectory.
            ball_path: None,
            ball_path_along_taper: 0.0,
        }
    }
}

#[derive(Clone, Debug, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct MatchConfig {
    pub dt_seconds: f64,
    pub duration_seconds: f64,
    #[serde(default = "default_match_halves")]
    pub halves: u8,
    #[serde(default = "default_half_duration_seconds")]
    pub half_duration_seconds: f64,
    #[serde(default = "default_halftime_fatigue_recovery")]
    pub halftime_fatigue_recovery: f64,
    #[serde(default = "default_period_count")]
    pub period_count: usize,
    #[serde(default = "default_period_break_recovery_seconds")]
    pub period_break_recovery_seconds: f64,
    pub field_length_yards: f64,
    pub field_width_yards: f64,
    pub goal_width_yards: f64,
    #[serde(default = "default_ball_drag_per_tick")]
    pub ball_drag_per_tick: f64,
    #[serde(default = "default_ball_air_resistance")]
    pub ball_air_resistance: f64,
    #[serde(default = "default_ball_grass_resistance_yps2")]
    pub ball_grass_resistance_yps2: f64,
    #[serde(default = "default_ball_stop_speed_yps")]
    pub ball_stop_speed_yps: f64,
    #[serde(default = "default_learning_enabled")]
    pub learning_enabled: bool,
    #[serde(default = "default_learning_logging_enabled")]
    pub learning_logging_enabled: bool,
    #[serde(default = "default_learning_interval_ticks")]
    pub learning_interval_ticks: usize,
    #[serde(default = "default_policy_train_max_transitions_per_tick")]
    pub policy_train_max_transitions_per_tick: usize,
    #[serde(default = "default_full_game_learning_enabled")]
    pub full_game_learning_enabled: bool,
    #[serde(default = "default_formation_lp_enabled")]
    pub formation_lp_enabled: bool,
    #[serde(default = "default_local_mpc_enabled")]
    pub local_mpc_enabled: bool,
    /// Off-ball pass-trajectory anticipation: both teams predict an in-flight pass's
    /// reception point and race to win it (the best-placed attacker supports the
    /// reception; the best-placed defender steps to intercept), with defenders gated
    /// by a position budget against their formation-LP/IPM ideal so they are not drawn
    /// out of shape. Off by default (play unchanged); on in `live_gameplay`.
    #[serde(default = "default_pass_anticipation_enabled")]
    pub pass_anticipation_enabled: bool,
    #[serde(default = "default_local_mpc_max_players_per_team")]
    pub local_mpc_max_players_per_team: usize,
    #[serde(default = "default_tactical_learning_weights")]
    pub tactical_learning: SoccerTacticalLearningWeights,
    #[serde(default = "default_spacing_params")]
    pub spacing: SoccerSpacingParams,
    #[serde(default = "default_neural_learning_config")]
    pub neural_learning: SoccerNeuralLearningConfig,
    /// Decision-time coupling of the trained neural value/actor to the tabular
    /// MDP/POMDP policy. Off by default (play unchanged); `live_gameplay` turns on an
    /// Additive + actor-critic blend so the nets integrate with the tabular policy.
    #[serde(default)]
    pub neural_blend: SoccerNeuralBlendConfig,
    /// Short-horizon real-time Model Predictive Control execution layer. Off by
    /// default; see [`SoccerMpcConfig`].
    #[serde(default)]
    pub mpc: SoccerMpcConfig,
    /// Retrieval-guided decision pipeline (vector search over whole-field
    /// configuration moments). Off by default; see [`SoccerRetrievalConfig`].
    #[serde(default)]
    pub retrieval: SoccerRetrievalConfig,
    #[serde(default = "default_adversarial_embedding_exploitation_enabled")]
    pub adversarial_embedding_exploitation_enabled: bool,
    #[serde(default = "default_adversarial_moment_memory_limit")]
    pub adversarial_embedding_memory_limit: usize,
    /// Deprecated compatibility field. Live-causal operation order is now semantic /
    /// state-scored rather than randomized, so this flag is intentionally ignored while
    /// remaining deserializable for older configs.
    #[serde(default)]
    pub disable_tick_order_shuffle: bool,
    /// Force the committed slide-tackle mechanic OFF for THIS match, independent of the
    /// process-wide `DD_SOCCER_DISABLE_SLIDE_TACKLE` env flag. Default `false` => slide
    /// tackles are live. Slide tackles only ever fire in genuine last-ditch windows (a
    /// fast carrier driving at goal that the defender can reach but not contain), so a
    /// disabled match is byte-identical to one where no such window arises.
    #[serde(default)]
    pub disable_slide_tackle: bool,
    /// Force the `xavi-turn` shielded-pirouette dribble move OFF for THIS match, independent
    /// of the process-wide `DD_SOCCER_DISABLE_XAVI_TURN` env flag. Default `false` => the move
    /// is live. When disabled the `xavi-turn` option is never offered, so no such action is
    /// ever produced and the match is byte-identical to one where it never arises. See
    /// [`xavi_turn_enabled`].
    #[serde(default)]
    pub disable_xavi_turn: bool,
    /// Enable obstacle-aware loose-ball intercept feasibility for THIS match, independent of the
    /// process-wide `DD_SOCCER_ENABLE_OBSTACLE_AWARE_INTERCEPT` env flag (either turns it on).
    /// Default `false` => the straight-line kinematic reach is used unchanged (byte-identical). When
    /// on, opponent bodies predicted (position + velocity + acceleration) into the dash corridor
    /// inflate the gap a chaser must cover, and the chosen intercept is MPC-confirmed reachable in
    /// time. See [`obstacle_aware_intercept_enabled`] and [`loose_ball_corridor_obstruction_yards`].
    #[serde(default)]
    pub enable_obstacle_aware_intercept: bool,
    /// Enable the lightweight Bayesian opponent-press belief: a per-player
    /// Beta-Bernoulli posterior over how readily each opponent steps into pass
    /// lanes, which shades the analytic pass-lane interception risk into a Bayesian
    /// posterior risk for pass selection. OFF by default; also forced on
    /// process-wide by `DD_SOCCER_OPPONENT_BELIEF`. Disabled => the belief map stays
    /// empty and lane risk is byte-identical to the analytic-only path. See
    /// [`opponent_belief_enabled`].
    #[serde(default)]
    pub opponent_belief_enabled: bool,
    pub max_human_players: usize,
    pub seed: u32,
}

