impl MatchConfig {
    pub fn playback_trace(duration_seconds: f64) -> Self {
        let duration_seconds = duration_seconds.max(0.0);
        MatchConfig {
            duration_seconds,
            half_duration_seconds: 0.0,
            period_count: 1,
            period_break_recovery_seconds: 0.0,
            learning_enabled: false,
            learning_logging_enabled: false,
            full_game_learning_enabled: false,
            formation_lp_enabled: false,
            local_mpc_enabled: false,
            neural_learning: SoccerNeuralLearningConfig {
                enabled: false,
                ..SoccerNeuralLearningConfig::default()
            },
            adversarial_embedding_exploitation_enabled: false,
            max_human_players: 0,
            ..MatchConfig::default()
        }
    }

    pub fn live_gameplay() -> Self {
        MatchConfig {
            learning_enabled: false,
            learning_logging_enabled: false,
            learning_interval_ticks: LIVE_GAMEPLAY_POLICY_LEARNING_INTERVAL_TICKS,
            policy_train_max_transitions_per_tick:
                LIVE_GAMEPLAY_POLICY_TRAIN_MAX_TRANSITIONS_PER_TICK,
            full_game_learning_enabled: false,
            formation_lp_enabled: true,
            local_mpc_enabled: true,
            pass_anticipation_enabled: true,
            local_mpc_max_players_per_team: DEFAULT_LOCAL_MPC_MAX_PLAYERS_PER_TEAM,
            // Live gameplay prioritizes responsiveness: no online backprop in the
            // frame loop, but an installed neural value/actor can still feed back into
            // selection (Additive blend + actor-critic), and the trained critic can
            // couple back to the LP (simplex/IPM) formation solver.
            neural_learning: SoccerNeuralLearningConfig {
                enabled: true,
                backend: SoccerNeuralLearningBackend::Threaded,
                train_every_ticks: LIVE_GAMEPLAY_NEURAL_TRAIN_EVERY_TICKS,
                max_batches_per_tick: 1,
                lp_coupling_enabled: true,
                marl_algorithm: SoccerMarlAlgorithm::Mappo,
                mappo_clip_epsilon: DEFAULT_SOCCER_MAPPO_CLIP_EPSILON,
                mappo_team_reward_share: DEFAULT_SOCCER_MAPPO_TEAM_REWARD_SHARE,
                ..SoccerNeuralLearningConfig::default()
            },
            neural_blend: SoccerNeuralBlendConfig {
                mode: SoccerNeuralBlendMode::Additive,
                actor_critic: true,
                mcts_enabled: true,
                mcts_simulations: 8,
                mcts_candidates: 4,
                mcts_depth: 1,
                ..SoccerNeuralBlendConfig::default()
            },
            mpc: SoccerMpcConfig {
                tier2_player_enabled: true,
                reconcile_enabled: true,
                field_aware_enabled: true,
                latent_objective_enabled: true,
                ..SoccerMpcConfig::default()
            },
            adversarial_embedding_exploitation_enabled: true,
            opponent_belief_enabled: true,
            max_human_players: 4,
            ..MatchConfig::default()
        }
    }

    pub fn sanitized_for_runtime(&self) -> Self {
        let mut config = self.clone();
        config.dt_seconds = sane_dt_seconds(config.dt_seconds, DEFAULT_DT_SECONDS);
        config.halves = config.halves.clamp(1, MAX_MATCH_HALVES);
        config.period_count = config.period_count.clamp(1, MAX_MATCH_PERIODS);
        if !config.duration_seconds.is_finite() || config.duration_seconds < 0.0 {
            config.duration_seconds = DEFAULT_DURATION_SECONDS;
        }
        // Cap the match length so `total_ticks()` (duration / dt) stays bounded even for a
        // pathological config — pure defense-in-depth; no real match approaches this.
        config.duration_seconds = config.duration_seconds.min(MAX_MATCH_DURATION_SECONDS);
        if !config.half_duration_seconds.is_finite() || config.half_duration_seconds < 0.0 {
            config.half_duration_seconds = DEFAULT_HALF_DURATION_SECONDS;
        }
        if config.half_duration_seconds > 0.0 {
            let max_half_duration = MAX_MATCH_DURATION_SECONDS / f64::from(config.half_count());
            config.half_duration_seconds = config.half_duration_seconds.min(max_half_duration);
        }
        if !config.halftime_fatigue_recovery.is_finite() || config.halftime_fatigue_recovery < 0.0 {
            config.halftime_fatigue_recovery = DEFAULT_HALFTIME_FATIGUE_RECOVERY;
        }
        if !config.period_break_recovery_seconds.is_finite()
            || config.period_break_recovery_seconds < 0.0
        {
            config.period_break_recovery_seconds = 0.0;
        }

        let (field_width, field_length) =
            sane_pitch_dimensions(config.field_width_yards, config.field_length_yards);
        config.field_width_yards = field_width;
        config.field_length_yards = field_length;
        if !config.goal_width_yards.is_finite() || config.goal_width_yards <= 0.0 {
            config.goal_width_yards = DEFAULT_GOAL_WIDTH_YARDS.min(field_width * 0.5);
        } else {
            config.goal_width_yards = config.goal_width_yards.clamp(1.0, field_width * 0.8);
        }

        config.ball_drag_per_tick = if config.ball_drag_per_tick.is_finite() {
            config.ball_drag_per_tick.clamp(0.0, 0.95)
        } else {
            DEFAULT_BALL_DRAG_PER_TICK
        };
        config.ball_air_resistance = if config.ball_air_resistance.is_finite() {
            config.ball_air_resistance.clamp(0.0, 0.10)
        } else {
            DEFAULT_BALL_AIR_RESISTANCE
        };
        config.ball_grass_resistance_yps2 = if config.ball_grass_resistance_yps2.is_finite() {
            config.ball_grass_resistance_yps2.clamp(0.0, 5.0)
        } else {
            DEFAULT_BALL_GRASS_RESISTANCE_YPS2
        };
        config.ball_stop_speed_yps = if config.ball_stop_speed_yps.is_finite() {
            config.ball_stop_speed_yps.clamp(0.0, 20.0)
        } else {
            DEFAULT_BALL_STOP_SPEED_YPS
        };
        config.max_human_players = config
            .max_human_players
            .min(SOCCER_MAX_HUMAN_CONTROLLER_SLOTS);

        config
    }

    pub fn half_count(&self) -> u8 {
        self.halves.clamp(1, MAX_MATCH_HALVES)
    }

    pub fn effective_duration_seconds(&self) -> f64 {
        if self.half_duration_seconds.is_finite() && self.half_duration_seconds > 0.0 {
            let half_count = f64::from(self.half_count());
            self.half_duration_seconds
                .min(MAX_MATCH_DURATION_SECONDS / half_count)
                * half_count
        } else if self.duration_seconds.is_finite() {
            self.duration_seconds.clamp(0.0, MAX_MATCH_DURATION_SECONDS)
        } else {
            0.0
        }
    }

    pub fn effective_half_duration_seconds(&self) -> f64 {
        if self.half_duration_seconds.is_finite() && self.half_duration_seconds > 0.0 {
            self.half_duration_seconds
                .min(MAX_MATCH_DURATION_SECONDS / f64::from(self.half_count()))
        } else {
            self.effective_duration_seconds() / f64::from(self.half_count())
        }
    }

    pub fn total_ticks(&self) -> u64 {
        bounded_tick_count(self.effective_duration_seconds(), self.dt_seconds)
    }

    pub fn half_ticks(&self) -> u64 {
        bounded_tick_count(self.effective_half_duration_seconds(), self.dt_seconds)
    }

    pub fn is_half_boundary_tick(&self, tick: u64) -> bool {
        let half_ticks = self.half_ticks();
        self.half_count() > 1
            && half_ticks > 0
            && tick > 0
            && tick < self.total_ticks()
            && tick % half_ticks == 0
    }

    pub fn periods(&self) -> usize {
        self.period_count.clamp(1, MAX_MATCH_PERIODS)
    }

    pub fn period_start_after_tick(&self, tick: u64) -> Option<usize> {
        let periods = self.periods();
        let total_ticks = self.total_ticks();
        for completed_periods in 1..periods {
            let boundary_tick =
                total_ticks.saturating_mul(completed_periods as u64) / periods as u64;
            if boundary_tick > 0 && boundary_tick < total_ticks && boundary_tick == tick {
                return Some(completed_periods + 1);
            }
        }
        None
    }

    pub fn human_slots(&self) -> usize {
        self.max_human_players
            .min(SOCCER_MAX_HUMAN_CONTROLLER_SLOTS)
    }
}

fn kickoff_team_for_period(period_number: usize) -> Team {
    if period_number % 2 == 0 {
        Team::Away
    } else {
        Team::Home
    }
}

fn validate_ball_surface(
    ball_drag_per_tick: f64,
    ball_air_resistance: f64,
    ball_grass_resistance_yps2: f64,
    ball_stop_speed_yps: f64,
) -> Result<(), String> {
    if !ball_drag_per_tick.is_finite() {
        return Err("ballDragPerTick must be finite".to_string());
    }
    if !(0.0..=0.95).contains(&ball_drag_per_tick) {
        return Err("ballDragPerTick must be between 0.0 and 0.95".to_string());
    }
    if !ball_air_resistance.is_finite() {
        return Err("ballAirResistance must be finite".to_string());
    }
    if !(0.0..=0.10).contains(&ball_air_resistance) {
        return Err("ballAirResistance must be between 0.0 and 0.10".to_string());
    }
    if !ball_grass_resistance_yps2.is_finite() {
        return Err("ballGrassResistanceYps2 must be finite".to_string());
    }
    if !(0.0..=5.0).contains(&ball_grass_resistance_yps2) {
        return Err("ballGrassResistanceYps2 must be between 0.0 and 5.0".to_string());
    }
    if !ball_stop_speed_yps.is_finite() {
        return Err("ballStopSpeedYps must be finite".to_string());
    }
    if !(0.0..=20.0).contains(&ball_stop_speed_yps) {
        return Err("ballStopSpeedYps must be between 0.0 and 20.0".to_string());
    }
    Ok(())
}

