/// Learning-progress pass metrics for one match, aggregated over BOTH teams (self-play uses
/// one policy, so the team split is not meaningful for tracking how the policy is learning).
/// These roll up per git commit in `des_soccer_learning_pass_metrics`.
#[derive(Clone, Copy, Debug, Default, PartialEq, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct SoccerPassLearningMetrics {
    pub passes_attempted: u64,
    pub passes_completed: u64,
    /// Sum of per-pass forward yards over completed passes (can be negative). Divide by
    /// `passes_completed` for the average yards gained per pass.
    pub completed_pass_gain_yards: f64,
    /// Consecutive-completed-pass chains (>= 2 passes, no turnover between them).
    pub pass_chains: u64,
    /// Total gained yards across those chains.
    pub pass_chain_gain_yards: f64,
    /// Chains that ended in a NET yards loss (sequences that went backwards overall).
    pub pass_chains_net_loss: u64,
    pub shots_on_target: u64,
    /// Shots on target preceded by at least one completed pass in the same possession.
    pub shots_after_pass: u64,
}

impl SoccerPassLearningMetrics {
    /// Pass completion rate in [0, 1], or 0 when no passes were attempted.
    pub fn completion_rate(&self) -> f64 {
        if self.passes_attempted == 0 {
            0.0
        } else {
            self.passes_completed as f64 / self.passes_attempted as f64
        }
    }

    /// Average yards gained per completed pass, or 0 when none completed.
    pub fn average_yards_per_completed_pass(&self) -> f64 {
        if self.passes_completed == 0 {
            0.0
        } else {
            self.completed_pass_gain_yards / self.passes_completed as f64
        }
    }

    /// Add another match's metrics into this running total (for a per-batch / per-commit roll-up).
    pub fn accumulate(&mut self, other: &Self) {
        self.passes_attempted += other.passes_attempted;
        self.passes_completed += other.passes_completed;
        self.completed_pass_gain_yards += other.completed_pass_gain_yards;
        self.pass_chains += other.pass_chains;
        self.pass_chain_gain_yards += other.pass_chain_gain_yards;
        self.pass_chains_net_loss += other.pass_chains_net_loss;
        self.shots_on_target += other.shots_on_target;
        self.shots_after_pass += other.shots_after_pass;
    }
}

impl MatchStats {
    /// Fold a finished consecutive-pass chain (the [`PassChainMeter`] state) into the chain
    /// counters. A chain counts only with two or more completed passes; it contributes its
    /// total gained yards and is flagged when that total is a net loss. Shared by the live
    /// finalize path and the non-destructive end-of-match summary fold.
    pub(crate) fn fold_pass_chain(&mut self, meter: &PassChainMeter) {
        let Some(team) = meter.team else {
            return;
        };
        if meter.passes < 2 {
            return;
        }
        match team {
            Team::Home => {
                self.pass_chains_home += 1;
                self.pass_chain_gain_yards_home += meter.gain_yards;
                if meter.gain_yards < 0.0 {
                    self.pass_chains_net_loss_home += 1;
                }
            }
            Team::Away => {
                self.pass_chains_away += 1;
                self.pass_chain_gain_yards_away += meter.gain_yards;
                if meter.gain_yards < 0.0 {
                    self.pass_chains_net_loss_away += 1;
                }
            }
        }
    }

    pub fn planning_validation_stats(&self) -> SoccerPlanningValidationStats {
        let decisions = self.planning_decisions.max(1);
        let neural_mcts_candidates = self.neural_mcts_candidates.max(1);
        SoccerPlanningValidationStats {
            decisions: self.planning_decisions,
            neural_mcts_selections: self.neural_mcts_selections,
            neural_mcts_selection_rate: self.neural_mcts_selections as f64 / decisions as f64,
            neural_mcts_discretized_kick_selections: self.neural_mcts_discretized_kick_selections,
            neural_mcts_discretized_kick_selection_rate: self
                .neural_mcts_discretized_kick_selections
                as f64
                / decisions as f64,
            neural_mcts_candidate_sets: self.neural_mcts_candidate_sets,
            neural_mcts_candidates: self.neural_mcts_candidates,
            neural_mcts_discretized_kick_candidates: self.neural_mcts_discretized_kick_candidates,
            neural_mcts_root_discretized_kick_candidates: self
                .neural_mcts_root_discretized_kick_candidates,
            neural_mcts_discretized_kick_candidate_share: self
                .neural_mcts_discretized_kick_candidates
                as f64
                / neural_mcts_candidates as f64,
            neural_mcts_root_discretized_kick_candidate_share: self
                .neural_mcts_root_discretized_kick_candidates
                as f64
                / neural_mcts_candidates as f64,
            learned_mpc_replans: self.learned_mpc_replans,
            learned_mpc_replan_rate: self.learned_mpc_replans as f64 / decisions as f64,
            policy_priority_samples: self.policy_priority_samples,
            policy_priority_sample_rate: self.policy_priority_samples as f64 / decisions as f64,
            mean_policy_priority_weight: self.policy_priority_weight_sum
                / self.policy_priority_samples.max(1) as f64,
            neural_mcts_distillation_samples: self.neural_mcts_distillation_samples,
            neural_mcts_distillation_rate: self.neural_mcts_distillation_samples as f64
                / decisions as f64,
            mean_neural_mcts_distillation_weight: self.neural_mcts_distillation_weight_sum
                / self.neural_mcts_distillation_samples.max(1) as f64,
            mean_policy_entropy: self.policy_entropy_sum / decisions as f64,
        }
    }

    /// Roll this match's per-team counters up into the both-teams [`SoccerPassLearningMetrics`].
    pub fn pass_learning_metrics(&self) -> SoccerPassLearningMetrics {
        SoccerPassLearningMetrics {
            passes_attempted: u64::from(self.passes_attempted_home)
                + u64::from(self.passes_attempted_away),
            passes_completed: u64::from(self.passes_completed_home)
                + u64::from(self.passes_completed_away),
            completed_pass_gain_yards: self.completed_pass_gain_yards_home
                + self.completed_pass_gain_yards_away,
            pass_chains: u64::from(self.pass_chains_home) + u64::from(self.pass_chains_away),
            pass_chain_gain_yards: self.pass_chain_gain_yards_home
                + self.pass_chain_gain_yards_away,
            pass_chains_net_loss: u64::from(self.pass_chains_net_loss_home)
                + u64::from(self.pass_chains_net_loss_away),
            shots_on_target: u64::from(self.shots_on_target_home)
                + u64::from(self.shots_on_target_away),
            shots_after_pass: u64::from(self.shots_after_pass_home)
                + u64::from(self.shots_after_pass_away),
        }
    }
}

#[derive(Clone, Debug)]
pub(crate) struct PendingPass {
    team: Team,
    from: usize,
    target: Option<usize>,
    flight: PassFlight,
    is_cross: bool,
    launch_tick: u64,
    origin: Vec2,
    intended_target: Vec2,
    distance_yards: f64,
    receiver_openness: f64,
    passer_skill: f64,
    launch_speed_yps: f64,
    receiver_position_at_launch: Option<Vec2>,
    receiver_velocity_at_launch: Option<Vec2>,
    /// Offside phase of the INTENDED target at the moment the ball was played (display /
    /// snapshot). Enforcement uses `offside_candidates`, which assesses every attacker.
    offside: Option<PendingOffside>,
    /// Every teammate of the passer who was in an offside position at the moment the ball
    /// was played — not just the intended target. Whichever of them first interferes with
    /// play (controls the ball, or comes within the interference radius of it) is flagged,
    /// matching the Laws: any player in an offside position who becomes involved is
    /// penalised, regardless of who the pass was "meant" for.
    offside_candidates: Vec<PendingOffside>,
    /// Captured AT LAUNCH for the learned pass-completion model: the canonical 22-player+ball
    /// config embedding (perspective = the passing team) concatenated with this pass's own
    /// features (distance / forward / lateral / pressure / receiver openness / aerial). When the
    /// pass resolves it is emitted as a `SoccerPassOutcomeSample` with the completed/intercepted
    /// label, so the model learns "from THIS whole-field configuration, does THIS pass complete?".
    /// Empty ⇒ not captured (no learning sample emitted).
    learn_features: Vec<f32>,
}

/// A goal counts as assisted only when the setting-up completed pass landed within this many
/// seconds of the goal (so a stale earlier ball isn't credited).
const ASSIST_RECENCY_SECONDS: f64 = 6.0;

/// Running tally of the current consecutive-completed-pass chain for the learning-progress
/// metrics. A "chain" is two or more completed passes in a row by the same team without a
/// turnover. `gain_yards` is the sum of the per-pass forward yards (the chain's total gained
/// yards, which can be negative). Finalised into [`MatchStats`] when the chain ends.
#[derive(Clone, Copy, Debug, Default)]
pub(crate) struct PassChainMeter {
    pub(crate) team: Option<Team>,
    pub(crate) passes: u32,
    pub(crate) gain_yards: f64,
}

#[derive(Clone, Debug)]
pub(crate) struct CompletedPassChainEntry {
    team: Team,
    from: usize,
    to: usize,
    direction: PassDirectionBucket,
    receiver_openness: f64,
    target_forward_yards: f64,
    /// Ball position where the pass was launched and where it was brought under control.
    /// Used to detect sterile sequences that never escape a tight radius.
    origin: Vec2,
    end: Vec2,
    tick: u64,
    clock_seconds: f64,
    continuation_rewarded: bool,
}

#[derive(Clone, Debug)]
pub(crate) struct PossessionProgressTracker {
    team: Team,
    start_y: f64,
    start_clock_seconds: f64,
    best_gain_yards: f64,
    best_completed_pass_chain_gain_yards: f64,
    completed_passes: usize,
    rewarded_milestones: usize,
}

impl PossessionProgressTracker {
    fn new(team: Team, start_position: Vec2) -> Self {
        Self::new_at(team, start_position, 0.0)
    }

    fn new_at(team: Team, start_position: Vec2, clock_seconds: f64) -> Self {
        Self {
            team,
            start_y: start_position.y,
            start_clock_seconds: clock_seconds.max(0.0),
            best_gain_yards: 0.0,
            best_completed_pass_chain_gain_yards: 0.0,
            completed_passes: 0,
            rewarded_milestones: 0,
        }
    }

    fn update_gain(&mut self, ball_position: Vec2) {
        let gain = ((ball_position.y - self.start_y) * self.team.attack_dir()).max(0.0);
        self.best_gain_yards = self.best_gain_yards.max(gain);
    }

    fn update_completed_pass_chain_gain(&mut self, controlled_end: Vec2) {
        let gain = ((controlled_end.y - self.start_y) * self.team.attack_dir()).max(0.0);
        self.best_completed_pass_chain_gain_yards =
            self.best_completed_pass_chain_gain_yards.max(gain);
    }

    fn qualifies_for_stall_penalty(&self) -> bool {
        self.completed_passes >= POSSESSION_STALL_PASS_THRESHOLD
            && self.best_completed_pass_chain_gain_yards < POSSESSION_STALL_MIN_GAIN_YARDS
    }

    fn elapsed_seconds(&self, clock_seconds: f64) -> f64 {
        (clock_seconds - self.start_clock_seconds).max(0.0)
    }
}

/// Tracks the CURRENT ball-carrier's continuous forward dribble to pay the SUSTAINED-dribble MARL
/// reward (gated by `DD_SOCCER_ENABLE_PROGRESSIVE_CARRY_REWARD`): each forward segment past the
/// first in one continuous carry, at both a 1-yard ("a yard followed by another yard") and a 2-yard
/// ("2 yards followed by 2 more") cadence (`fold_tick`/`sustained_reward_points`, emitted per tick
/// while the player keeps driving forward). The complementary PRODUCTIVE carry-into-pass/shot reward
/// is handled separately by `record_progressive_carry_outcome_reward`. "Forward" is Δy·attack toward
/// the opponent goal; lateral (x) movement is free — only the forward component is accumulated. A
/// single carrier holds the ball at a time, so the match keeps one `Option<ForwardCarryTracker>`,
/// reset when the holder changes / possession is lost. The segment accounting is pure (no env, no
/// world access) so it is unit-tested directly.
/// New sustained-dribble segments completed this tick, at BOTH cadences: `fine` = 1-yard segments
/// ("a yard followed by another yard"), `coarse` = 2-yard segments ("2 yards followed by 2 more").
/// Both are rewarded (the user asked for both); the coarse cadence is an extra bonus that escalates
/// with a longer continuous run.
#[derive(Clone, Copy, Debug, Default, PartialEq, Eq)]
pub(crate) struct SustainedDribbleSegments {
    pub(crate) fine: u32,
    pub(crate) coarse: u32,
}

impl SustainedDribbleSegments {
    fn is_empty(self) -> bool {
        self.fine == 0 && self.coarse == 0
    }
}

/// Number of NEW sustained segments to reward this tick at `segment_yards` granularity: whole
/// segments completed PAST THE FIRST (so "one segment followed by another"), capped, minus those
/// already rewarded (advanced in place). Pure.
fn advance_sustained_segments(
    carry_yards: f64,
    segment_yards: f64,
    cap: u32,
    already_rewarded: &mut u32,
) -> u32 {
    let total = (carry_yards / segment_yards).floor() as u32;
    let rewardable = total.saturating_sub(1).min(cap);
    if rewardable > *already_rewarded {
        let new = rewardable - *already_rewarded;
        *already_rewarded = rewardable;
        new
    } else {
        0
    }
}

#[derive(Clone, Copy, Debug)]
pub(crate) struct ForwardCarryTracker {
    pub(crate) carrier_id: usize,
    pub(crate) team: Team,
    pub(crate) last_ball_y: f64,
    forward_carry_yards: f64,
    fine_rewarded_segments: u32,
    coarse_rewarded_segments: u32,
}

impl ForwardCarryTracker {
    fn new_at(carrier_id: usize, team: Team, ball_y: f64) -> Self {
        Self {
            carrier_id,
            team,
            last_ball_y: ball_y,
            forward_carry_yards: 0.0,
            fine_rewarded_segments: 0,
            coarse_rewarded_segments: 0,
        }
    }

    /// Fold one tick of carry into the run. `forward_delta` is this tick's Δy·attack (positive =
    /// toward the opponent goal). A meaningful backward move breaks the run (resets the accumulated
    /// carry and BOTH rewarded-segment counters). Returns the NEW sustained segments to reward this
    /// tick at both the 1-yard (`fine`) and 2-yard (`coarse`) cadences — segments PAST THE FIRST in
    /// the continuous run ("a yard followed by another yard" / "2 yards followed by 2 more"), each
    /// capped. Pure.
    fn fold_tick(&mut self, forward_delta: f64) -> SustainedDribbleSegments {
        if !forward_delta.is_finite() {
            return SustainedDribbleSegments::default();
        }
        if forward_delta <= -FORWARD_CARRY_BACKWARD_RESET_YARDS {
            self.forward_carry_yards = 0.0;
            self.fine_rewarded_segments = 0;
            self.coarse_rewarded_segments = 0;
            return SustainedDribbleSegments::default();
        }
        self.forward_carry_yards = (self.forward_carry_yards + forward_delta).max(0.0);
        let fine = advance_sustained_segments(
            self.forward_carry_yards,
            FORWARD_CARRY_FINE_SEGMENT_YARDS,
            FORWARD_CARRY_MAX_REWARDED_FINE_SEGMENTS,
            &mut self.fine_rewarded_segments,
        );
        let coarse = advance_sustained_segments(
            self.forward_carry_yards,
            FORWARD_CARRY_SEGMENT_YARDS,
            FORWARD_CARRY_MAX_REWARDED_SEGMENTS,
            &mut self.coarse_rewarded_segments,
        );
        SustainedDribbleSegments { fine, coarse }
    }

    /// Reward points to emit this tick for the sustained-dribble segments (both cadences), summed.
    fn sustained_reward_points(&mut self, forward_delta: f64) -> f64 {
        let seg = self.fold_tick(forward_delta);
        if seg.is_empty() {
            return 0.0;
        }
        seg.fine as f64 * SUSTAINED_FORWARD_DRIBBLE_FINE_SEGMENT_REWARD_POINTS
            + seg.coarse as f64 * SUSTAINED_FORWARD_DRIBBLE_SEGMENT_REWARD_POINTS
    }
}

