/// Legacy pass-specific scalar feature count: distance, forward progress, lateral, passer pressure,
/// receiver openness, aerial flag.
pub const SOCCER_PASS_COMPLETION_PASS_FEATURES_V1: usize = 6;
pub const SOCCER_PASS_COMPLETION_FEATURE_DIM_V1: usize =
    SOCCER_MOMENT_EMBEDDING_DIM + SOCCER_PASS_COMPLETION_PASS_FEATURES_V1;
/// Number of pass-specific scalar features appended to the 256-d config embedding for the learned
/// pass-completion model: the legacy six plus long-aerial boundary risk, in-play margin, and
/// inward correction.
pub const SOCCER_PASS_COMPLETION_PASS_FEATURES: usize = 9;
/// Total input width of the learned pass-completion model.
pub const SOCCER_PASS_COMPLETION_FEATURE_DIM: usize =
    SOCCER_MOMENT_EMBEDDING_DIM + SOCCER_PASS_COMPLETION_PASS_FEATURES;
const SOCCER_PASS_COMPLETION_HIDDEN_UNITS: usize = 32;
/// Cap on retained pass-outcome training samples (a rolling window; the cluster learner drains
/// them to Postgres + the model each learning pass).
const SOCCER_PASS_OUTCOME_SAMPLE_CAP: usize = 4096;

/// One training example for the learned pass-completion model: the whole-field configuration +
/// pass features captured AT LAUNCH, labelled with whether the pass was completed. This is the
/// substrate that lets passing LEARN from the 22-player+ball config (persisted to Postgres by the
/// cluster learner; see [`SoccerPassCompletionHead`]).
#[derive(Clone, Debug, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct SoccerPassOutcomeSample {
    /// `SOCCER_PASS_COMPLETION_FEATURE_DIM` features (config embedding ++ pass features).
    pub features: Vec<f32>,
    /// `true` = the pass was received by a team-mate; `false` = intercepted / lost.
    pub completed: bool,
    /// Whether the pass was played from the passing team's own half (stratified reporting).
    pub own_half: bool,
}

/// Learned pass-completion model: an MLP over the whole-field config embedding + pass features that
/// predicts P(complete). Mirrors [`SoccerPolicyHead`]'s use of the shared `FeedForwardNetwork`
/// (live net not serde; round-tripped through [`SoccerNeuralNetworkSnapshot`] for Postgres). It is
/// the learned replacement for the analytic completion estimate and the hand-scored MPC pass
/// weights — trained on [`SoccerPassOutcomeSample`]s, conditioned on the 22+ball config.
#[derive(Clone, Debug)]
pub struct SoccerPassCompletionHead {
    network: FeedForwardNetwork,
    training_steps: usize,
    last_loss: Option<f64>,
}

impl SoccerPassCompletionHead {
    pub fn new(seed: u32) -> Self {
        let mut rng = mulberry32(seed ^ 0x5F37_2C1B);
        let network = FeedForwardNetwork::random(
            &RandomNetworkSpec {
                input_dim: SOCCER_PASS_COMPLETION_FEATURE_DIM,
                hidden_layers: vec![SOCCER_PASS_COMPLETION_HIDDEN_UNITS],
                output_dim: 1,
                hidden_activation: ActivationName::Relu,
                // Sigmoid output = a probability in (0, 1).
                output_activation: ActivationName::Sigmoid,
                weight_scale: None,
            },
            &mut rng,
        );
        SoccerPassCompletionHead {
            network,
            training_steps: 0,
            last_loss: None,
        }
    }

    /// P(complete) for a captured feature vector, or `None` on malformed input.
    pub(crate) fn predict(&self, features: &[f32]) -> Option<f64> {
        let normalized = normalize_pass_completion_features(features)?;
        let input: Vec<f64> = normalized.iter().map(|&v| v as f64).collect();
        let out = self.network.predict(&input);
        out.first().copied().filter(|p| p.is_finite())
    }

    /// One SGD epoch over `samples` (binary cross-entropy via the clipped MSE step on a sigmoid
    /// output is adequate here). Returns the mean step loss.
    pub fn train(&mut self, samples: &[SoccerPassOutcomeSample], learning_rate: f64) -> f64 {
        let mut total = 0.0;
        let mut applied = 0usize;
        for sample in samples {
            let Some(normalized) = normalize_pass_completion_features(&sample.features) else {
                continue;
            };
            let input: Vec<f64> = normalized.iter().map(|&v| v as f64).collect();
            let target = [if sample.completed { 1.0 } else { 0.0 }];
            let result = self
                .network
                .train_sample_clipped(&input, &target, learning_rate, 4.0);
            if result.applied && result.loss.is_finite() {
                total += result.loss;
                applied += 1;
                self.training_steps += 1;
            }
        }
        let mean = if applied > 0 {
            total / applied as f64
        } else {
            0.0
        };
        self.last_loss = Some(mean);
        mean
    }

    pub fn training_steps(&self) -> usize {
        self.training_steps
    }

    /// Mean prediction accuracy over `samples` at a 0.5 decision threshold — a quick read on
    /// whether the head has actually learned the corpus (used by the training report).
    pub(crate) fn accuracy(&self, samples: &[SoccerPassOutcomeSample]) -> f64 {
        let mut correct = 0usize;
        let mut scored = 0usize;
        for sample in samples {
            if let Some(p) = self.predict(&sample.features) {
                scored += 1;
                if (p >= 0.5) == sample.completed {
                    correct += 1;
                }
            }
        }
        if scored == 0 {
            0.0
        } else {
            correct as f64 / scored as f64
        }
    }
}

/// Minimum SGD steps a [`SoccerPassCompletionHead`] must have taken before the live pass-quality
/// assessor will blend its prediction into `expected_completion`. Below this the head is still
/// noisy, so the analytic estimate stands alone (mirrors [`LINE_DEPTH_HEAD_MIN_TRAINING_STEPS`]).
pub const PASS_COMPLETION_HEAD_MIN_TRAINING_STEPS: usize = 200;

/// Weight given to the learned head's P(complete) when blended with the analytic completion
/// estimate (the rest stays analytic). Conservative: the head nudges, it does not replace.
const PASS_COMPLETION_HEAD_BLEND_WEIGHT: f64 = 0.5;

fn pass_completion_head_blend_weight() -> f64 {
    #[cfg(test)]
    {
        pass_completion_head_blend_weight_from_env()
    }
    #[cfg(not(test))]
    {
        use std::sync::OnceLock;
        static WEIGHT: OnceLock<f64> = OnceLock::new();
        *WEIGHT.get_or_init(pass_completion_head_blend_weight_from_env)
    }
}

fn pass_completion_head_blend_weight_from_env() -> f64 {
    let raw = std::env::var("SOCCER_PASS_COMPLETION_HEAD_BLEND_WEIGHT")
        .ok()
        .or_else(|| std::env::var("DD_SOCCER_PASS_COMPLETION_HEAD_BLEND_WEIGHT").ok());
    let Some(raw) = raw else {
        return PASS_COMPLETION_HEAD_BLEND_WEIGHT;
    };
    match raw.trim().parse::<f64>() {
        Ok(value) if value.is_finite() => value.clamp(0.0, 1.0),
        _ => {
            eprintln!(
                "soccer: invalid pass-completion blend weight {:?}; using default {:.3}",
                raw, PASS_COMPLETION_HEAD_BLEND_WEIGHT
            );
            PASS_COMPLETION_HEAD_BLEND_WEIGHT
        }
    }
}

/// Env flag enabling live consumption of the learned pass-completion head in
/// `pass_target_quality_for_snapshot`. Off ⇒ the analytic completion estimate stands alone
/// (byte-identical to the pre-wiring behaviour). Read once per process.
pub fn learned_pass_completion_enabled() -> bool {
    #[cfg(test)]
    {
        soccer_env_flag_enabled("DD_SOCCER_ENABLE_LEARNED_PASS_COMPLETION")
    }
    #[cfg(not(test))]
    {
        use std::sync::OnceLock;
        static ENABLED: OnceLock<bool> = OnceLock::new();
        *ENABLED.get_or_init(|| soccer_env_flag_enabled("DD_SOCCER_ENABLE_LEARNED_PASS_COMPLETION"))
    }
}

fn soccer_env_flag_enabled(name: &str) -> bool {
    std::env::var(name)
        .map(|raw| {
            let v = raw.trim().to_ascii_lowercase();
            matches!(v.as_str(), "1" | "true" | "yes" | "on")
        })
        .unwrap_or(false)
}

impl SoccerMatch {
    /// Install the trained pass-completion head for live consumption. The learner carries +
    /// trains it across games (seeded from the Postgres corpus) and re-installs it each game;
    /// wrapped in `Arc` so every per-tick snapshot shares it cheaply. Consumed in
    /// `pass_target_quality_for_snapshot` once it clears
    /// [`PASS_COMPLETION_HEAD_MIN_TRAINING_STEPS`] and the gate is on.
    pub fn set_pass_completion_head(&mut self, head: SoccerPassCompletionHead) {
        self.pass_completion_head = Some(std::sync::Arc::new(head));
    }
}

fn normalize_pass_completion_features(features: &[f32]) -> Option<Vec<f32>> {
    if features.iter().any(|v| !v.is_finite()) {
        return None;
    }
    match features.len() {
        SOCCER_PASS_COMPLETION_FEATURE_DIM => Some(features.to_vec()),
        SOCCER_PASS_COMPLETION_FEATURE_DIM_V1 => {
            let mut migrated = Vec::with_capacity(SOCCER_PASS_COMPLETION_FEATURE_DIM);
            migrated.extend_from_slice(features);
            migrated.resize(SOCCER_PASS_COMPLETION_FEATURE_DIM, 0.0);
            Some(migrated)
        }
        _ => None,
    }
}

/// Outcome of training the learned pass-completion head on a corpus loaded from Postgres
/// (`SoccerStore::load_pass_outcome_samples`). Logged by the learning runner so an operator can
/// see the persisted training data is actually being loaded and learned from.
#[derive(Clone, Debug, Default, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct SoccerPassCompletionTrainingReport {
    /// Samples loaded from Postgres and trained on.
    pub samples: usize,
    /// SGD steps actually applied across all epochs.
    pub training_steps: usize,
    /// Number of epochs run over the corpus.
    pub epochs: usize,
    /// Mean loss of the final epoch.
    pub final_loss: f64,
    /// Post-training accuracy over the corpus (0.5 threshold).
    pub accuracy: f64,
}

/// Load-and-train entry for the learned pass-completion model: given a corpus of
/// [`SoccerPassOutcomeSample`]s (in practice loaded from Postgres by the cluster learner — see
/// [`SoccerPassOutcomeSample`] and `SoccerStore::load_pass_outcome_samples`), build a fresh
/// [`SoccerPassCompletionHead`] and run `epochs` SGD passes over it. Returns the trained head
/// plus a [`SoccerPassCompletionTrainingReport`], or `None` if no usable samples were supplied
/// (so the runner can skip cleanly rather than persist an untrained net).
pub fn train_soccer_pass_completion_head(
    samples: &[SoccerPassOutcomeSample],
    seed: u32,
    epochs: usize,
    learning_rate: f64,
) -> Option<(SoccerPassCompletionHead, SoccerPassCompletionTrainingReport)> {
    let usable = samples
        .iter()
        .filter(|s| normalize_pass_completion_features(&s.features).is_some())
        .count();
    if usable == 0 || epochs == 0 {
        return None;
    }
    let learning_rate =
        soccer_sanitized_learning_rate(learning_rate, DEFAULT_SOCCER_PASS_COMPLETION_LEARNING_RATE);
    let mut head = SoccerPassCompletionHead::new(seed);
    let mut final_loss = 0.0;
    for _ in 0..epochs {
        final_loss = head.train(samples, learning_rate);
    }
    let report = SoccerPassCompletionTrainingReport {
        samples: usable,
        training_steps: head.training_steps(),
        epochs,
        final_loss,
        accuracy: head.accuracy(samples),
    };
    Some((head, report))
}

/// Public wrapper that returns ONLY the training report (the head type is engine-internal). The
/// learning runner uses this to load the Postgres pass-outcome corpus and verify it trains.
pub fn report_soccer_pass_completion_training(
    samples: &[SoccerPassOutcomeSample],
    seed: u32,
    epochs: usize,
    learning_rate: f64,
) -> Option<SoccerPassCompletionTrainingReport> {
    train_soccer_pass_completion_head(samples, seed, epochs, learning_rate)
        .map(|(_, report)| report)
}

