pub fn write_soccer_artifacts() {
    match try_write_soccer_artifacts() {
        Ok(paths) => print_soccer_artifact_paths(&paths),
        Err(err) => eprintln!("main_soccer: failed to write soccer artifacts: {err}"),
    }
}

fn tracking_home_positions(tracking: &SoccerTrackingDataset) -> HashMap<usize, Vec2> {
    let mut positions = HashMap::new();
    for frame in &tracking.frames {
        for player in &frame.players {
            positions
                .entry(player.id)
                .or_insert(player.home_position.unwrap_or(player.position));
        }
    }
    positions
}

fn tracking_frames_with_inferred_kinematics(
    tracking: &SoccerTrackingDataset,
) -> Vec<SoccerTrackingFrame> {
    tracking_frames_with_inferred_kinematics_from_slice(&tracking.frames, &tracking.config)
}

fn tracking_frames_need_kinematics_inference(frames: &[SoccerTrackingFrame]) -> bool {
    frames.iter().any(|frame| {
        frame.ball_velocity.is_none()
            || frame.ball_acceleration.is_none()
            || frame.ball_jerk.is_none()
            || frame.ball_curl_acceleration.is_none()
            || frame.players.iter().any(|player| {
                player.velocity.is_none()
                    || player.motion_acceleration.is_none()
                    || player.motion_jerk.is_none()
            })
    })
}

fn tracking_frames_with_inferred_kinematics_from_slice(
    original: &[SoccerTrackingFrame],
    config: &MatchConfig,
) -> Vec<SoccerTrackingFrame> {
    let mut frames = original.to_vec();
    for idx in 0..frames.len() {
        frames[idx].ball_velocity = Some(tracking_ball_velocity_at(original, idx, config));
        frames[idx].ball_acceleration = Some(tracking_ball_acceleration_at(original, idx, config));
        frames[idx].ball_jerk = Some(tracking_ball_jerk_at(original, idx, config));
        if frames[idx].ball_curl_acceleration.is_none() {
            frames[idx].ball_curl_acceleration = Some(Vec2::zero());
        }

        let player_ids = frames[idx]
            .players
            .iter()
            .map(|player| player.id)
            .collect::<Vec<_>>();
        for (player, player_id) in frames[idx].players.iter_mut().zip(player_ids) {
            player.velocity = Some(tracking_player_velocity_at(
                original, idx, player_id, config,
            ));
            player.motion_acceleration = Some(tracking_player_acceleration_at(
                original, idx, player_id, config,
            ));
            player.motion_jerk = Some(tracking_player_jerk_at(original, idx, player_id, config));
        }
    }
    infer_tracking_possession_from_positions(&mut frames);
    frames
}

fn infer_tracking_possession_from_positions(frames: &mut [SoccerTrackingFrame]) {
    let mut previous_holder = None::<usize>;
    let mut previous_last_touch_team = None::<Team>;

    for frame in frames {
        if let Some(holder) = frame.ball_holder {
            let holder_team = tracking_player_sample(frame, holder).map(|player| player.team);
            if frame.last_touch_team.is_none() {
                frame.last_touch_team = holder_team.or(previous_last_touch_team);
            }
            previous_holder = Some(holder);
            previous_last_touch_team = frame
                .last_touch_team
                .or(holder_team)
                .or(previous_last_touch_team);
            continue;
        }

        if let Some(holder) = infer_tracking_ball_holder_from_position(frame, previous_holder) {
            frame.ball_holder = Some(holder);
            let holder_team = tracking_player_sample(frame, holder).map(|player| player.team);
            if frame.last_touch_team.is_none() {
                frame.last_touch_team = holder_team.or(previous_last_touch_team);
            }
            previous_holder = Some(holder);
            previous_last_touch_team = frame
                .last_touch_team
                .or(holder_team)
                .or(previous_last_touch_team);
        } else {
            if frame.last_touch_team.is_none() {
                frame.last_touch_team = previous_last_touch_team;
            } else {
                previous_last_touch_team = frame.last_touch_team;
            }
            previous_holder = None;
        }
    }
}

fn infer_tracking_ball_holder_from_position(
    frame: &SoccerTrackingFrame,
    previous_holder: Option<usize>,
) -> Option<usize> {
    if frame.ball_altitude_yards.unwrap_or(0.0).max(0.0)
        > TRACKING_INFERRED_HOLDER_MAX_ALTITUDE_YARDS
    {
        return None;
    }

    let mut best = None::<(f64, usize)>;
    for player in &frame.players {
        let radius = if previous_holder == Some(player.id) {
            TRACKING_INFERRED_HOLDER_STICKY_RADIUS_YARDS
        } else {
            TRACKING_INFERRED_HOLDER_RADIUS_YARDS
        };
        let distance = player.position.distance(frame.ball_position);
        if distance > radius {
            continue;
        }
        let score = if previous_holder == Some(player.id) {
            distance - 0.18
        } else {
            distance
        };
        match best {
            Some((best_score, best_id))
                if score > best_score + 1e-9
                    || ((score - best_score).abs() <= 1e-9 && player.id >= best_id) => {}
            _ => best = Some((score, player.id)),
        }
    }
    best.map(|(_, player_id)| player_id)
}

fn tracking_frame_dt(
    config: &MatchConfig,
    before: &SoccerTrackingFrame,
    after: &SoccerTrackingFrame,
) -> f64 {
    let clock_dt = after.clock_seconds - before.clock_seconds;
    if clock_dt.is_finite() && clock_dt > 1e-6 {
        clock_dt
    } else {
        let tick_dt = after.tick.saturating_sub(before.tick) as f64 * config.dt_seconds;
        if tick_dt.is_finite() && tick_dt > 1e-6 {
            tick_dt
        } else {
            config.dt_seconds.max(1e-6)
        }
    }
}

fn tracking_player_sample<'a>(
    frame: &'a SoccerTrackingFrame,
    player_id: usize,
) -> Option<&'a SoccerTrackingPlayerSample> {
    frame.players.iter().find(|player| player.id == player_id)
}

fn tracking_player_velocity_at(
    frames: &[SoccerTrackingFrame],
    idx: usize,
    player_id: usize,
    config: &MatchConfig,
) -> Vec2 {
    let Some(current) = frames
        .get(idx)
        .and_then(|frame| tracking_player_sample(frame, player_id))
    else {
        return Vec2::zero();
    };
    if let Some(velocity) = current.velocity {
        return velocity;
    }
    if idx > 0 {
        if let (Some(previous_frame), Some(current_frame)) = (frames.get(idx - 1), frames.get(idx))
        {
            if let Some(previous) = tracking_player_sample(previous_frame, player_id) {
                let dt = tracking_frame_dt(config, previous_frame, current_frame);
                return (current.position - previous.position) / dt;
            }
        }
    }
    if let (Some(current_frame), Some(next_frame)) = (frames.get(idx), frames.get(idx + 1)) {
        if let Some(next) = tracking_player_sample(next_frame, player_id) {
            let dt = tracking_frame_dt(config, current_frame, next_frame);
            return (next.position - current.position) / dt;
        }
    }
    Vec2::zero()
}

fn tracking_player_acceleration_at(
    frames: &[SoccerTrackingFrame],
    idx: usize,
    player_id: usize,
    config: &MatchConfig,
) -> Vec2 {
    let Some(current) = frames
        .get(idx)
        .and_then(|frame| tracking_player_sample(frame, player_id))
    else {
        return Vec2::zero();
    };
    if let Some(acceleration) = current.motion_acceleration {
        return acceleration;
    }
    let current_velocity = tracking_player_velocity_at(frames, idx, player_id, config);
    if idx > 0 {
        if let (Some(previous_frame), Some(current_frame)) = (frames.get(idx - 1), frames.get(idx))
        {
            if tracking_player_sample(previous_frame, player_id).is_some() {
                let previous_velocity =
                    tracking_player_velocity_at(frames, idx - 1, player_id, config);
                let dt = tracking_frame_dt(config, previous_frame, current_frame);
                return (current_velocity - previous_velocity) / dt;
            }
        }
    }
    if let (Some(current_frame), Some(next_frame)) = (frames.get(idx), frames.get(idx + 1)) {
        if tracking_player_sample(next_frame, player_id).is_some() {
            let next_velocity = tracking_player_velocity_at(frames, idx + 1, player_id, config);
            let dt = tracking_frame_dt(config, current_frame, next_frame);
            return (next_velocity - current_velocity) / dt;
        }
    }
    Vec2::zero()
}

fn tracking_player_jerk_at(
    frames: &[SoccerTrackingFrame],
    idx: usize,
    player_id: usize,
    config: &MatchConfig,
) -> Vec2 {
    let Some(current) = frames
        .get(idx)
        .and_then(|frame| tracking_player_sample(frame, player_id))
    else {
        return Vec2::zero();
    };
    if let Some(jerk) = current.motion_jerk {
        return jerk;
    }
    let current_acceleration = tracking_player_acceleration_at(frames, idx, player_id, config);
    if idx > 0 {
        if let (Some(previous_frame), Some(current_frame)) = (frames.get(idx - 1), frames.get(idx))
        {
            if tracking_player_sample(previous_frame, player_id).is_some() {
                let previous_acceleration =
                    tracking_player_acceleration_at(frames, idx - 1, player_id, config);
                let dt = tracking_frame_dt(config, previous_frame, current_frame);
                return (current_acceleration - previous_acceleration) / dt;
            }
        }
    }
    if let (Some(current_frame), Some(next_frame)) = (frames.get(idx), frames.get(idx + 1)) {
        if tracking_player_sample(next_frame, player_id).is_some() {
            let next_acceleration =
                tracking_player_acceleration_at(frames, idx + 1, player_id, config);
            let dt = tracking_frame_dt(config, current_frame, next_frame);
            return (next_acceleration - current_acceleration) / dt;
        }
    }
    Vec2::zero()
}

fn tracking_ball_velocity_at(
    frames: &[SoccerTrackingFrame],
    idx: usize,
    config: &MatchConfig,
) -> Vec2 {
    let Some(current_frame) = frames.get(idx) else {
        return Vec2::zero();
    };
    if let Some(velocity) = current_frame.ball_velocity {
        return velocity;
    }
    if idx > 0 {
        if let Some(previous_frame) = frames.get(idx - 1) {
            let dt = tracking_frame_dt(config, previous_frame, current_frame);
            return (current_frame.ball_position - previous_frame.ball_position) / dt;
        }
    }
    if let Some(next_frame) = frames.get(idx + 1) {
        let dt = tracking_frame_dt(config, current_frame, next_frame);
        return (next_frame.ball_position - current_frame.ball_position) / dt;
    }
    Vec2::zero()
}

fn tracking_ball_acceleration_at(
    frames: &[SoccerTrackingFrame],
    idx: usize,
    config: &MatchConfig,
) -> Vec2 {
    let Some(current_frame) = frames.get(idx) else {
        return Vec2::zero();
    };
    if let Some(acceleration) = current_frame.ball_acceleration {
        return acceleration;
    }
    let current_velocity = tracking_ball_velocity_at(frames, idx, config);
    if idx > 0 {
        if let Some(previous_frame) = frames.get(idx - 1) {
            let previous_velocity = tracking_ball_velocity_at(frames, idx - 1, config);
            let dt = tracking_frame_dt(config, previous_frame, current_frame);
            return (current_velocity - previous_velocity) / dt;
        }
    }
    if let Some(next_frame) = frames.get(idx + 1) {
        let next_velocity = tracking_ball_velocity_at(frames, idx + 1, config);
        let dt = tracking_frame_dt(config, current_frame, next_frame);
        return (next_velocity - current_velocity) / dt;
    }
    Vec2::zero()
}

fn tracking_ball_jerk_at(frames: &[SoccerTrackingFrame], idx: usize, config: &MatchConfig) -> Vec2 {
    let Some(current_frame) = frames.get(idx) else {
        return Vec2::zero();
    };
    if let Some(jerk) = current_frame.ball_jerk {
        return jerk;
    }
    let current_acceleration = tracking_ball_acceleration_at(frames, idx, config);
    if idx > 0 {
        if let Some(previous_frame) = frames.get(idx - 1) {
            let previous_acceleration = tracking_ball_acceleration_at(frames, idx - 1, config);
            let dt = tracking_frame_dt(config, previous_frame, current_frame);
            return (current_acceleration - previous_acceleration) / dt;
        }
    }
    if let Some(next_frame) = frames.get(idx + 1) {
        let next_acceleration = tracking_ball_acceleration_at(frames, idx + 1, config);
        let dt = tracking_frame_dt(config, current_frame, next_frame);
        return (next_acceleration - current_acceleration) / dt;
    }
    Vec2::zero()
}

