fn csv_required_pitch_point(
    row: &[String],
    header: &HashMap<String, usize>,
    aliases: TrackingCsvPitchPointAliases,
    config: &MatchConfig,
    line_no: usize,
) -> Result<Vec2, String> {
    csv_optional_pitch_point(row, header, aliases, config, line_no)?.ok_or_else(|| {
        format!(
            "csv line {line_no} missing required position columns {}, {}, or {}",
            aliases.direct_x[0], aliases.normalized_x[0], aliases.pixel_x[0]
        )
    })
}

fn csv_optional_pitch_point(
    row: &[String],
    header: &HashMap<String, usize>,
    aliases: TrackingCsvPitchPointAliases,
    config: &MatchConfig,
    line_no: usize,
) -> Result<Option<Vec2>, String> {
    if let Some(point) =
        csv_optional_vec2(row, header, aliases.direct_x, aliases.direct_y, line_no)?
    {
        return Ok(Some(point));
    }
    let calibration = TrackingCsvCoordinateCalibration::from_row(row, header, line_no)?;
    if let Some(point) = csv_optional_vec2(
        row,
        header,
        aliases.normalized_x,
        aliases.normalized_y,
        line_no,
    )? {
        return Ok(Some(calibration.map_normalized(point, config)));
    }

    let pixel = csv_optional_vec2(row, header, aliases.pixel_x, aliases.pixel_y, line_no)?;
    let Some(pixel) = pixel else {
        return Ok(None);
    };
    let image_dimensions = csv_required_image_dimensions(row, header, line_no)?;
    Ok(Some(calibration.map_pixel(pixel, image_dimensions, config)))
}

fn csv_required_image_dimensions(
    row: &[String],
    header: &HashMap<String, usize>,
    line_no: usize,
) -> Result<Vec2, String> {
    let dimensions = csv_optional_vec2(
        row,
        header,
        &[
            "image_width",
            "imagewidth",
            "frame_width",
            "framewidth",
            "video_width",
            "videowidth",
            "width",
        ],
        &[
            "image_height",
            "imageheight",
            "frame_height",
            "frameheight",
            "video_height",
            "videoheight",
            "height",
        ],
        line_no,
    )?;
    let Some(dimensions) = dimensions else {
        return Err(format!(
            "csv line {line_no} pixel coordinates require image_width and image_height"
        ));
    };
    if dimensions.x <= 0.0 || dimensions.y <= 0.0 {
        return Err(format!(
            "csv line {line_no} image dimensions must be positive"
        ));
    }
    Ok(dimensions)
}

fn csv_optional_skill_score(
    row: &[String],
    header: &HashMap<String, usize>,
    aliases: &[&str],
    line_no: usize,
) -> Result<Option<f64>, String> {
    csv_optional_f64(row, header, aliases, line_no).map(|value| value.map(ability_score))
}

fn tracking_csv_skill_profile(
    row: &[String],
    header: &HashMap<String, usize>,
    role: PlayerRole,
    line_no: usize,
) -> Result<Option<SkillProfile>, String> {
    let mut skills = neutral_tracking_skill_profile(role);
    let mut found = false;

    macro_rules! apply_skill {
        ($field:ident, [$($alias:expr),+ $(,)?]) => {
            if let Some(score) = csv_optional_skill_score(row, header, &[$($alias),+], line_no)? {
                skills.$field = score;
                found = true;
            }
        };
    }

    macro_rules! apply_positive_raw {
        ($field:ident, [$($alias:expr),+ $(,)?]) => {
            if let Some(value) = csv_optional_f64(row, header, &[$($alias),+], line_no)? {
                if !value.is_finite() || value <= 0.0 {
                    return Err(format!(
                        "csv line {line_no} {} must be a positive finite number",
                        stringify!($field)
                    ));
                }
                skills.$field = value;
                found = true;
            }
        };
    }

    apply_skill!(
        top_speed,
        [
            "top_speed",
            "topSpeed",
            "top_speed_yps",
            "topSpeedYps",
            "skill_top_speed",
            "speed"
        ]
    );
    apply_skill!(
        acceleration,
        [
            "acceleration",
            "acceleration_yps2",
            "accelerationYps2",
            "skill_acceleration"
        ]
    );
    apply_skill!(strength, ["strength", "skill_strength"]);
    apply_skill!(height, ["height", "skill_height"]);
    apply_positive_raw!(
        weight_pounds,
        [
            "weight",
            "weight_pounds",
            "weightPounds",
            "weight_lbs",
            "weightLbs",
            "body_weight",
            "bodyWeight",
            "body_weight_pounds",
            "bodyWeightPounds"
        ]
    );
    apply_skill!(shooting, ["shooting", "shooting_ability", "skill_shooting"]);
    apply_skill!(
        right_foot_shot_power,
        [
            "right_foot_shot_power",
            "rightFootShotPower",
            "right_shot",
            "skill_right_foot_shot_power"
        ]
    );
    apply_skill!(
        left_foot_shot_power,
        [
            "left_foot_shot_power",
            "leftFootShotPower",
            "left_shot",
            "skill_left_foot_shot_power"
        ]
    );
    apply_skill!(passing, ["passing", "passing_ability", "skill_passing"]);
    apply_skill!(
        passing_completion_rate,
        [
            "passing_completion_rate",
            "passingCompletionRate",
            "pass_completion",
            "pass_completion_rate",
            "skill_passing_completion_rate"
        ]
    );
    apply_skill!(
        flair_passing,
        [
            "flair_passing",
            "flairPassing",
            "flair",
            "skill_flair_passing"
        ]
    );
    apply_skill!(
        crossing_left,
        [
            "crossing_left",
            "crossingLeft",
            "left_crossing",
            "leftFootCrossingAbility",
            "crossingAbilityWithLeftRoot",
            "skill_crossing_left"
        ]
    );
    apply_skill!(
        crossing_right,
        [
            "crossing_right",
            "crossingRight",
            "right_crossing",
            "rightFootCrossingAbility",
            "skill_crossing_right"
        ]
    );
    apply_skill!(
        dribbling,
        ["dribbling", "dribbling_ability", "skill_dribbling"]
    );
    apply_skill!(
        first_touch,
        [
            "first_touch",
            "firstTouch",
            "control_touch",
            "skill_first_touch"
        ]
    );
    apply_skill!(
        defending,
        [
            "defending",
            "defensive_ability",
            "defensiveAbility",
            "skill_defending"
        ]
    );
    apply_skill!(
        goalkeeping,
        [
            "goalkeeping",
            "gk_strength",
            "ability_in_goal",
            "abilityInGoal",
            "skill_goalkeeping"
        ]
    );
    apply_skill!(
        defensive_tracking,
        [
            "defensive_tracking",
            "defensiveTracking",
            "tracking_back",
            "trackingBack",
            "skill_defensive_tracking"
        ]
    );
    apply_skill!(stamina, ["stamina", "skill_stamina"]);
    apply_skill!(vision, ["vision", "skill_vision"]);
    apply_skill!(aggression, ["aggression", "skill_aggression"]);

    if let Some(noise) = csv_optional_f64(
        row,
        header,
        &["decision_noise", "decisionNoise", "skill_decision_noise"],
        line_no,
    )? {
        skills.decision_noise = if noise.is_finite() {
            noise.clamp(0.0, 1.0)
        } else {
            skills.decision_noise
        };
        found = true;
    }

    Ok(found.then_some(skills))
}

fn parse_tracking_team(raw: &str, line_no: usize) -> Result<Team, String> {
    match raw.trim().to_ascii_lowercase().as_str() {
        "home" | "h" | "1" => Ok(Team::Home),
        "away" | "a" | "2" => Ok(Team::Away),
        _ => Err(format!("csv line {line_no} unknown team {raw}")),
    }
}

fn parse_tracking_role(raw: &str, line_no: usize) -> Result<PlayerRole, String> {
    match raw.trim().to_ascii_lowercase().as_str() {
        "goalkeeper" | "keeper" | "gk" | "g" => Ok(PlayerRole::Goalkeeper),
        "defender" | "defence" | "defense" | "def" | "d" => Ok(PlayerRole::Defender),
        "midfielder" | "midfield" | "mid" | "m" => Ok(PlayerRole::Midfielder),
        "forward" | "striker" | "winger" | "fw" | "st" | "f" => Ok(PlayerRole::Forward),
        _ => Err(format!("csv line {line_no} unknown role {raw}")),
    }
}

fn parse_tracking_pass_flight(raw: &str, line_no: usize) -> Result<PassFlight, String> {
    let normalized = normalize_csv_header(raw);
    if KILLER_PASS_OVER_TOP_PASS_FLIGHT_ALIASES.contains(&normalized.as_str()) {
        return Ok(PassFlight::OverTop);
    }
    match normalized.as_str() {
        "floor" | "ground" | "groundpass" | "grounded" | "low" | "rolling" | "roll" | "0" => {
            Ok(PassFlight::Floor)
        }
        "aerial" | "air" | "airborne" | "aerialpass" | "aerialcross" | "chipped" | "chip"
        | "high" | "lob" | "lofted" | "longball" | "1" => Ok(PassFlight::Aerial),
        _ => Err(format!("csv line {line_no} unknown pass flight {raw}")),
    }
}

fn parse_tracking_facing_bucket(raw: &str) -> Result<FacingBucket, String> {
    let trimmed = raw.trim();
    if trimmed.is_empty() {
        return Ok(FacingBucket::Unknown);
    }
    let numeric = trimmed
        .trim_end_matches('°')
        .trim_end_matches("degrees")
        .trim_end_matches("degree")
        .trim_end_matches("deg")
        .trim();
    if let Ok(degrees) = numeric.parse::<f64>() {
        return Ok(facing_bucket_from_degrees(degrees));
    }
    match normalize_csv_header(trimmed).as_str() {
        "unknown" | "none" | "na" | "null" | "notavailable" => Ok(FacingBucket::Unknown),
        "north" | "n" | "up" => Ok(FacingBucket::North),
        "northeast" | "ne" | "upperright" => Ok(FacingBucket::NorthEast),
        "east" | "e" | "right" => Ok(FacingBucket::East),
        "southeast" | "se" | "lowerright" => Ok(FacingBucket::SouthEast),
        "south" | "s" | "down" => Ok(FacingBucket::South),
        "southwest" | "sw" | "lowerleft" => Ok(FacingBucket::SouthWest),
        "west" | "w" | "left" => Ok(FacingBucket::West),
        "northwest" | "nw" | "upperleft" => Ok(FacingBucket::NorthWest),
        _ => Err("expected facing bucket name or degrees".to_string()),
    }
}

fn parse_tracking_ball_action(raw: &str, line_no: usize) -> Result<Option<String>, String> {
    normalize_tracking_ball_action(raw)
        .map_err(|err| format!("csv line {line_no} unknown ball action {raw}: {err}"))
}

fn normalize_tracking_ball_action(raw: &str) -> Result<Option<String>, String> {
    let trimmed = raw.trim();
    if trimmed.is_empty() {
        return Ok(None);
    }
    let compact = normalize_csv_header(trimmed);
    let action = match compact.as_str() {
        "none" | "na" | "null" | "noaction" => return Ok(None),
        "groundpass" | "floorpass" | "shortpass" => "pass",
        "killer"
        | "killerpass"
        | "throughpass"
        | "threadedpass"
        | "splitpass"
        | "splittingpass"
        | "linebreakingpass"
        | "defensesplittingpass" => "killer-pass",
        "lowcross" | "flanklowcross" | "downflanklowcross" | "playdownflanklowcross" => {
            "flank-low-cross"
        }
        "aerial" | "aerialpass" | "chippedpass" | "loftedpass" | "cross" | "aerialcross" => {
            "aerial-pass"
        }
        "highcross"
        | "crossforheader"
        | "highcrossheader"
        | "flankhighcross"
        | "flankhighcrossheader"
        | "downflankhighcross"
        | "playdownflankhighcross" => "flank-high-cross",
        "shot" => "shoot",
        "routeone" | "route1" | "longball" | "longpass" | "directball" => "route-one",
        "clear" | "clearance" | "hoof" | "hoofedclearance" => "clearance",
        "firsttimepass" => "first-time-pass",
        "firsttimeshot" => "first-time-shot",
        "firsttimeheader" | "header" => "first-time-header",
        "control" | "trap" | "chestcontrol" => "control-touch",
        "sidestep" | "sidestepdribble" | "sidestepmove" => "side-step",
        "carry" | "carryforward" | "dribbleforward" => "carry-forward",
        "carryout" | "dribbleout" => "carry-out-left",
        "carryoutleft" | "carryleft" => "carry-out-left",
        "carryoutright" | "carryright" => "carry-out-right",
        "protect" | "protectball" | "shield" | "shieldball" => "protect-ball",
        "leftcut" | "leftcutdribble" | "cutleft" => "left-cut",
        "rightcut" | "rightcutdribble" | "cutright" => "right-cut",
        "nutmeg" | "nutmegged" | "meg" => "nutmeg",
        "fakeleftcutright" | "fakelefttoright" => "fake-left-cut-right",
        "fakerightcutleft" | "fakerighttoleft" => "fake-right-cut-left",
        "freekick" => "free-kick",
        "goalkick" => "goal-kick",
        "cornerkick" => "corner-kick",
        "throwin" => "throw-in",
        "supportshape" => "support-shape",
        "supportroam" => "support-roam",
        "checktoball" | "checkrun" => "check-to-ball",
        "runinbehind" | "inbehind" => "run-in-behind",
        "exploitspace" | "exploitspacerun" | "spacerun" => "exploit-space-run",
        "wideoutlet" | "touchlineoutlet" => "wide-outlet",
        "shotcreationrun" | "shootingrun" => "shot-creation-run",
        "overlap" | "overlaprun" => "overlap-run",
        "supportpushup" | "pushup" => "support-push-up",
        "supportscreen" | "screenrun" => "support-screen",
        "giveandgo" | "wallpass" | "onetwopass" => "wall-pass",
        "cornerflagcross" | "bylinecross" | "penaltyspotcross" => "corner-flag-cross",
        "verticalattack" | "attackvertical" | "driveforward" => "vertical-attack",
        "vacatespace" | "createspacerun" | "decoyrun" => "vacate-space",
        "surprisepass" | "backheelpass" | "backheel" | "scooppass" => "surprise-pass",
        "flickon" | "headerflick" => "flick-on",
        "turnoverburst" | "transitionburst" | "counterburst" => "turnover-burst",
        other => normalize_soccer_action_label(other),
    };
    match action {
        "pass"
        | "aerial-pass"
        | "flank-low-cross"
        | "flank-high-cross"
        | "killer-pass"
        | "first-time-pass"
        | "wall-pass"
        | "corner-flag-cross"
        | "surprise-pass"
        | "flick-on"
        | "clearance"
        | "route-one"
        | "shoot"
        | "first-time-shot"
        | "first-time-header"
        | "control-touch"
        | "dribble"
        | "carry-forward"
        | "carry-out-left"
        | "carry-out-right"
        | "protect-ball"
        | "side-step"
        | "left-cut"
        | "right-cut"
        | "nutmeg"
        | "fake-left-cut-right"
        | "fake-right-cut-left"
        | "vertical-attack"
        | "turnover-burst"
        | "set-play-run"
        | "space"
        | "support-shape"
        | "support-roam"
        | "check-to-ball"
        | "run-in-behind"
        | "one-two-run"
        | "exploit-space-run"
        | "wide-outlet"
        | "shot-creation-run"
        | "pinch-cross-arrival"
        | "overlap-run"
        | "dummy-clear-lane"
        | "dummy-let-run"
        | "lane-yield"
        | "support-push-up"
        | "support-screen"
        | "vacate-space"
        | "buildup-receive"
        | "defend"
        | "defend-shape"
        | "defend-roam"
        | "tackle"
        | "slide-tackle"
        | "blindside-steal"
        | "recover"
        | "hold"
        | "kickoff"
        | "throw-in"
        | "goal-kick"
        | "corner-kick"
        | "free-kick"
        | "offside"
        | "goal"
        | "save"
        | "shot-blocked" => Ok(Some(action.to_string())),
        _ => Err("expected a known soccer action label".to_string()),
    }
}

fn known_tracking_facing(facing: Option<FacingBucket>) -> Option<FacingBucket> {
    facing.filter(|bucket| *bucket != FacingBucket::Unknown)
}

fn tracking_velocity_facing(sample: &SoccerTrackingPlayerSample) -> Option<FacingBucket> {
    let facing = facing_bucket_from_vector(sample.velocity.unwrap_or_default());
    (facing != FacingBucket::Unknown).then_some(facing)
}

fn tracking_player_receive_facing(sample: &SoccerTrackingPlayerSample) -> FacingBucket {
    known_tracking_facing(sample.receive_facing)
        .or_else(|| known_tracking_facing(sample.facing))
        .or_else(|| tracking_velocity_facing(sample))
        .unwrap_or(FacingBucket::Unknown)
}

fn tracking_player_action_facing(sample: &SoccerTrackingPlayerSample) -> FacingBucket {
    known_tracking_facing(sample.action_facing)
        .or_else(|| known_tracking_facing(sample.facing))
        .or_else(|| tracking_velocity_facing(sample))
        .unwrap_or_else(|| default_team_facing(sample.team))
}

fn tracking_frame_to_world_snapshot(
    config: &MatchConfig,
    frame: &SoccerTrackingFrame,
    home_positions: &HashMap<usize, Vec2>,
) -> WorldSnapshot {
    let holder_team = frame
        .ball_holder
        .and_then(|holder| frame.players.iter().find(|p| p.id == holder))
        .map(|p| p.team);
    let last_touch_team = frame.last_touch_team.or(holder_team);
    let players = frame
        .players
        .iter()
        .map(|p| {
            let skills = p
                .skills
                .clone()
                .unwrap_or_else(|| neutral_tracking_skill_profile(p.role));
            let home_position = home_positions
                .get(&p.id)
                .copied()
                .unwrap_or(p.home_position.unwrap_or(p.position));
            let assigned_position = soccer_assigned_position_for(
                p.role,
                home_position,
                config.field_width_yards,
                config.field_length_yards,
                p.team,
            );
            PlayerSnapshot {
                id: p.id,
                name: p
                    .name
                    .clone()
                    .unwrap_or_else(|| format!("Tracking {}", p.id)),
                team: p.team,
                role: p.role,
                assigned_position,
                shirt: p.shirt.unwrap_or((p.id % 100).max(1) as u8),
                position: p.position,
                position_history: vec![p.position],
                velocity: p.velocity.unwrap_or_default(),
                movement_gait: MovementGait::Stand,
                receive_facing: tracking_player_receive_facing(p),
                action_facing: tracking_player_action_facing(p),
                facing_yaw: facing_bucket_to_vector(tracking_player_action_facing(p))
                    .map(|v| v.y.atan2(v.x))
                    .unwrap_or(0.0),
                incoming_ball: None,
                vision_range_yards: vision_range_yards(skills.vision),
                field_of_view_degrees: field_of_view_degrees(skills.vision),
                skill_bands: soccer_playback_skill_bands(&skills),
                skills,
                fatigue: 0.0,
                anaerobic_load: 0.0,
                home_position,
                controller_slot: None,
                scheduled_index: None,
                preferences: AgentPreferences::default(),
                acceleration: p.motion_acceleration.unwrap_or_default(),
                jerk: p.motion_jerk.unwrap_or_default(),
                last_decision: None,
                learned_policy: None,
                recent_reward: None,
                one_two: None,
                runaround: None,
                hold_for_support: None,
                same_team_proximity_dwell_lt7_seconds: 0.0,
                same_team_proximity_dwell_lt6_seconds: 0.0,
                same_team_proximity_dwell_lt5_seconds: 0.0,
                slide_recovery_seconds: 0.0,
            }
        })
        .collect::<Vec<_>>();
    let shared_positions = SharedPlayerPositionSnapshot::from_player_snapshots(
        &players,
        frame.tick,
        frame.clock_seconds,
    );
    let phase = tracking_phase(config, frame, last_touch_team);
    let score_home = frame.score_home.unwrap_or(0);
    let score_away = frame.score_away.unwrap_or(0);
    let score_diff_home = score_home as i32 - score_away as i32;
    WorldSnapshot {
        tick: frame.tick,
        decision_seed: config.seed as u64,
        keeper_commit_bias: [0.0, 0.0],
        ranked_floor_pass_cache: std::cell::RefCell::new(std::collections::HashMap::new()),
        ranked_aerial_pass_cache: std::cell::RefCell::new(std::collections::HashMap::new()),
        pass_target_quality_cache: std::cell::RefCell::new(std::collections::HashMap::new()),
        support_decision_feature_cache: std::cell::RefCell::new(std::collections::HashMap::new()),
        support_open_space_target_cache: std::cell::RefCell::new(std::collections::HashMap::new()),
        loose_ball_contest_target_cache: std::cell::RefCell::new(std::collections::HashMap::new()),
        loose_ball_on_path_intercept_cache: std::cell::RefCell::new(
            std::collections::HashMap::new(),
        ),
        loose_ball_intercept_solution_cache: std::cell::RefCell::new(
            std::collections::HashMap::new(),
        ),
        loose_ball_retrieval_score_cache: std::cell::RefCell::new(std::collections::HashMap::new()),
        loose_ball_attack_profile_cache: std::cell::RefCell::new(std::collections::HashMap::new()),
        loose_ball_committed_chaser_cache: std::cell::RefCell::new(std::collections::HashMap::new()),
        line_depth_head: None,
        defender_line_head: None,
        back_four_line_latch_centre_depth: [None, None],
        pass_completion_head: None,
        loose_ball_commit_head: None,
        receive_approach_head: None,
        lane_affinity_head: None,
        goal_side_recovery_head: None,
        winger_pinch_head: None,
        separation_floor_head: None,
        pass_lane_yield_head: None,
        head_scan_head: None,
        crash_box_head: None,
        run_prediction_head: None,
        slip_break_head: None,
        onside_support_head: None,
        long_pass_run_head: None,
        give_and_go_head: None,
        attack_spacing_head: None,
        support_scorer_head: None,
        aerial_reception_head: None,
        shot_trigger_head: None,
        loose_ball_uncontested_since_tick: None,
        home_genome: crate::des::general::soccer_genome::SoccerTeamGenome::default(),
        away_genome: crate::des::general::soccer_genome::SoccerTeamGenome::default(),
        clock_seconds: frame.clock_seconds,
        dt_seconds: config.dt_seconds,
        field_length: config.field_length_yards,
        field_width: config.field_width_yards,
        goal_width: config.goal_width_yards,
        spacing_params: config.spacing,
        tactical_learning: config.tactical_learning.clone(),
        ball_drag_per_tick: config.ball_drag_per_tick,
        ball_air_resistance: config.ball_air_resistance,
        ball_grass_resistance_yps2: config.ball_grass_resistance_yps2,
        ball_stop_speed_yps: config.ball_stop_speed_yps,
        ball: BallState {
            position: frame.ball_position,
            velocity: frame.ball_velocity.unwrap_or_default(),
            acceleration: frame.ball_acceleration.unwrap_or_default(),
            jerk: frame.ball_jerk.unwrap_or_default(),
            curl_acceleration: frame.ball_curl_acceleration.unwrap_or_default(),
            altitude_yards: frame.ball_altitude_yards.unwrap_or(0.0).max(0.0),
            decision_speed_yps: frame.ball_velocity.unwrap_or_default().len(),
            decision_altitude_yards: frame.ball_altitude_yards.unwrap_or(0.0).max(0.0),
            decision_curl_yps2: frame.ball_curl_acceleration.unwrap_or_default().len(),
            resistance: BallResistanceFrame::default(),
            holder: frame.ball_holder,
            last_touch_team,
            last_touch_player: frame.ball_holder,
            scheduled_index: None,
            last_decision: frame
                .ball_action
                .as_deref()
                .and_then(|action| normalize_tracking_ball_action(action).ok().flatten())
                .map(|action| {
                    let scheduled_index = None;
                    BallDecisionTrace {
                        tick: frame.tick,
                        operation_order: ball_agent_operation_order(
                            frame.tick,
                            &action,
                            scheduled_index,
                        ),
                        action,
                        position: frame.ball_position,
                        velocity: frame.ball_velocity.unwrap_or_default(),
                        acceleration: frame.ball_acceleration.unwrap_or_default(),
                        jerk: frame.ball_jerk.unwrap_or_default(),
                        curl_acceleration: frame.ball_curl_acceleration.unwrap_or_default(),
                        altitude_yards: frame.ball_altitude_yards.unwrap_or(0.0).max(0.0),
                        holder: frame.ball_holder,
                        scheduled_index,
                    }
                }),
        },
        ball_history: vec![BallPositionSample {
            tick: frame.tick,
            clock_seconds: frame.clock_seconds,
            position: frame.ball_position,
            velocity: frame.ball_velocity.unwrap_or_default(),
            acceleration: frame.ball_acceleration.unwrap_or_default(),
            jerk: frame.ball_jerk.unwrap_or_default(),
            curl_acceleration: frame.ball_curl_acceleration.unwrap_or_default(),
            altitude_yards: frame.ball_altitude_yards.unwrap_or(0.0).max(0.0),
            resistance: BallResistanceFrame::default(),
            holder: frame.ball_holder,
            last_touch_team,
        }],
        pending_pass: None,
        pending_rebound: None,
        active_set_play: None,
        players,
        offside_clocks: HashMap::new(),
        shared_positions,
        agent_schedule: Vec::new(),
        schedule_index_lookup: AgentScheduleIndexLookup::default(),
        score_home,
        score_away,
        phase,
        home_directive: tactical_directive_for_team(
            Team::Home,
            phase,
            last_touch_team,
            frame.ball_position,
            score_diff_home,
            config.field_width_yards,
            config.field_length_yards,
            DefensiveCoverProfile::default(),
            AttackingOverloadProfile::default(),
            false,
            &config.tactical_learning,
        ),
        away_directive: tactical_directive_for_team(
            Team::Away,
            phase,
            last_touch_team,
            frame.ball_position,
            -score_diff_home,
            config.field_width_yards,
            config.field_length_yards,
            DefensiveCoverProfile::default(),
            AttackingOverloadProfile::default(),
            false,
            &config.tactical_learning,
        ),
        formation_lp_enabled: config.formation_lp_enabled,
        local_mpc_enabled: config.local_mpc_enabled,
        trace_mdp_mpc_comparison: true,
        slide_tackle_enabled: slide_tackle_enabled(config),
        xavi_turn_enabled: xavi_turn_enabled(config),
        obstacle_aware_intercept_enabled: obstacle_aware_intercept_enabled(config),
        pass_anticipation_enabled: config.pass_anticipation_enabled,
        local_mpc_max_players_per_team: config.local_mpc_max_players_per_team,
        home_team_possession_seconds: if last_touch_team == Some(Team::Home) {
            frame.clock_seconds.max(0.0)
        } else {
            0.0
        },
        away_team_possession_seconds: if last_touch_team == Some(Team::Away) {
            frame.clock_seconds.max(0.0)
        } else {
            0.0
        },
        ball_holder_possession_seconds: if frame.ball_holder.is_some() {
            frame.clock_seconds.max(0.0)
        } else {
            0.0
        },
        gk_handling_since_clock: None,
        formation_lp_guidance: Vec::new(),
        formation_lp_teams: Vec::new(),
        teammate_spacing_notices: Vec::new(),
        back_four_anchor_pivots: [None, None],
        // A tracking-frame reconstruction has no completed-pass chain, so there is no
        // recycled-possession history to derive urgency from.
        home_recycle_urgency: 0.0,
        away_recycle_urgency: 0.0,
        home_recycle_participants: Vec::new(),
        away_recycle_participants: Vec::new(),
        // A tracking-frame reconstruction has no per-tick belief history; an empty map
        // means the analytic pass-lane risk is used unchanged.
        opponent_press_tendency: HashMap::new(),
        // Tracking-frame snapshots are paired externally, not advanced through
        // `run_time_step`, so they intentionally carry no live tick memory.
        player_tick_carryover: HashMap::new(),
    }
}

fn tracking_frame_to_world_snapshot_with_history(
    config: &MatchConfig,
    frames: &[SoccerTrackingFrame],
    frame_idx: usize,
    home_positions: &HashMap<usize, Vec2>,
) -> WorldSnapshot {
    debug_assert!(!frames.is_empty());
    let frame = &frames[frame_idx.min(frames.len().saturating_sub(1))];
    let mut snapshot = tracking_frame_to_world_snapshot(config, frame, home_positions);
    let mut shared_player_histories = Vec::new();
    for player in &mut snapshot.players {
        let history = tracking_player_position_history_at(frames, frame_idx, player.id);
        if !history.is_empty() {
            player.position_history = history;
        }
        let sample_history =
            tracking_player_position_sample_history_at(frames, frame_idx, player.id);
        if !sample_history.is_empty() {
            shared_player_histories.push((player.id, sample_history));
        }
    }
    for (player_id, sample_history) in shared_player_histories {
        if let Some(latest) = sample_history.last().cloned() {
            if let Some(existing) = snapshot
                .shared_positions
                .latest
                .iter_mut()
                .find(|sample| sample.player_id == player_id)
            {
                *existing = latest;
            } else {
                snapshot.shared_positions.latest.push(latest);
            }
        }
        snapshot
            .shared_positions
            .histories
            .insert(player_id, sample_history);
    }
    let ball_history = tracking_ball_position_history_at(frames, frame_idx);
    if !ball_history.is_empty() {
        snapshot.ball_history = ball_history;
    }
    annotate_tracking_incoming_ball_contexts(&mut snapshot, frames, frame_idx);
    snapshot
}

fn tracking_pass_flight_from_frames(
    before_frame: &SoccerTrackingFrame,
    after_frame: &SoccerTrackingFrame,
) -> PassFlight {
    after_frame
        .pass_flight
        .or(before_frame.pass_flight)
        .unwrap_or_else(|| {
            let before_altitude = before_frame.ball_altitude_yards.unwrap_or(0.0);
            let after_altitude = after_frame.ball_altitude_yards.unwrap_or(0.0);
            if before_altitude.max(after_altitude) > 0.35 {
                PassFlight::Aerial
            } else {
                PassFlight::Floor
            }
        })
}

fn tracking_first_touch_action_label(action: &str) -> Option<&'static str> {
    match normalize_tracking_ball_action(action)
        .ok()
        .flatten()?
        .as_str()
    {
        "first-time-pass" => Some("first-time-pass"),
        "first-time-shot" => Some("first-time-shot"),
        "first-time-header" => Some("first-time-header"),
        "control-touch" => Some("control-touch"),
        _ => None,
    }
}

fn tracking_incoming_context_from_frames(
    before_frame: &SoccerTrackingFrame,
    after_frame: &SoccerTrackingFrame,
    target: &PlayerSnapshot,
    from_player: Option<usize>,
    received_tick: u64,
    force_aerial: bool,
    field_width: f64,
    field_length: f64,
) -> IncomingBallContext {
    let mut flight = tracking_pass_flight_from_frames(before_frame, after_frame);
    if force_aerial {
        flight = PassFlight::Aerial;
    }
    let origin = before_frame.ball_position;
    let intended_target = target.position;
    let distance_yards = origin.distance(intended_target);
    let frame_dt = (after_frame.clock_seconds - before_frame.clock_seconds).max(0.0);
    let inferred_velocity = if frame_dt > 1e-6 {
        (after_frame.ball_position - before_frame.ball_position) / frame_dt
    } else {
        Vec2::zero()
    };
    let speed_yps = after_frame
        .ball_velocity
        .or(before_frame.ball_velocity)
        .unwrap_or(inferred_velocity)
        .len();
    let is_cross = pass_would_be_cross(
        origin,
        intended_target,
        target.team,
        field_width,
        field_length,
    );
    IncomingBallContext {
        from_player,
        target_player: Some(target.id),
        team: Some(target.team),
        kind: match (flight, is_cross) {
            (PassFlight::Floor, false) => IncomingBallKind::GroundPass,
            (PassFlight::Aerial, false) | (PassFlight::Scoop, _) | (PassFlight::OverTop, false) => {
                IncomingBallKind::AerialPass
            }
            (PassFlight::Floor, true) => IncomingBallKind::Cross,
            (PassFlight::Aerial, true) | (PassFlight::OverTop, true) => {
                IncomingBallKind::AerialCross
            }
        },
        origin: Some(origin),
        intended_target: Some(intended_target),
        speed_yps,
        distance_yards,
        received_tick,
        is_cross,
        is_aerial: flight.is_aerial(),
    }
}

fn annotate_tracking_incoming_ball_contexts(
    snapshot: &mut WorldSnapshot,
    frames: &[SoccerTrackingFrame],
    frame_idx: usize,
) {
    if frames.is_empty() {
        return;
    }
    let idx = frame_idx.min(frames.len() - 1);
    let frame = &frames[idx];

    if idx > 0 {
        let previous = &frames[idx - 1];
        if let Some(holder_id) = frame.ball_holder {
            if previous.ball_holder != Some(holder_id) {
                if let Some(player) = snapshot.players.iter_mut().find(|p| p.id == holder_id) {
                    let from_player = previous.ball_holder.filter(|from| *from != holder_id);
                    player.incoming_ball = Some(tracking_incoming_context_from_frames(
                        previous,
                        frame,
                        player,
                        from_player,
                        frame.tick,
                        false,
                        snapshot.field_width,
                        snapshot.field_length,
                    ));
                }
            }
        }
    }

    let Some(next_frame) = frames.get(idx + 1) else {
        return;
    };
    let Some(raw_action) = next_frame
        .ball_action
        .as_deref()
        .or(frame.ball_action.as_deref())
    else {
        return;
    };
    let Some(first_touch_action) = tracking_first_touch_action_label(raw_action) else {
        return;
    };
    let Some(action_player) = next_frame.action_player.or(frame.action_player) else {
        return;
    };
    if let Some(player) = snapshot
        .players
        .iter_mut()
        .find(|player| player.id == action_player)
    {
        let from_player = frame
            .ball_holder
            .filter(|holder| *holder != action_player)
            .or_else(|| {
                idx.checked_sub(1)
                    .and_then(|previous_idx| frames[previous_idx].ball_holder)
                    .filter(|holder| *holder != action_player)
            });
        player.incoming_ball = Some(tracking_incoming_context_from_frames(
            frame,
            next_frame,
            player,
            from_player,
            frame.tick,
            first_touch_action == "first-time-header",
            snapshot.field_width,
            snapshot.field_length,
        ));
    }
}

fn tracking_player_position_history_at(
    frames: &[SoccerTrackingFrame],
    frame_idx: usize,
    player_id: usize,
) -> Vec<Vec2> {
    if frames.is_empty() {
        return Vec::new();
    }
    let end = frame_idx.min(frames.len() - 1);
    let start = (end + 1).saturating_sub(PLAYER_POSITION_HISTORY_LIMIT);
    frames[start..=end]
        .iter()
        .filter_map(|frame| {
            frame
                .players
                .iter()
                .find(|player| player.id == player_id)
                .map(|player| player.position)
        })
        .collect()
}

fn tracking_player_position_sample_history_at(
    frames: &[SoccerTrackingFrame],
    frame_idx: usize,
    player_id: usize,
) -> Vec<PlayerPositionSample> {
    if frames.is_empty() {
        return Vec::new();
    }
    let end = frame_idx.min(frames.len() - 1);
    let start = (end + 1).saturating_sub(PLAYER_POSITION_HISTORY_LIMIT);
    frames[start..=end]
        .iter()
        .filter_map(|frame| {
            frame
                .players
                .iter()
                .find(|player| player.id == player_id)
                .map(|player| PlayerPositionSample {
                    player_id,
                    tick: frame.tick,
                    clock_seconds: frame.clock_seconds,
                    position: player.position,
                    velocity: player.velocity.unwrap_or_default(),
                    acceleration: player.motion_acceleration.unwrap_or_default(),
                    jerk: player.motion_jerk.unwrap_or_default(),
                })
        })
        .collect()
}

fn tracking_ball_position_history_at(
    frames: &[SoccerTrackingFrame],
    frame_idx: usize,
) -> Vec<BallPositionSample> {
    if frames.is_empty() {
        return Vec::new();
    }
    let end = frame_idx.min(frames.len() - 1);
    let start = (end + 1).saturating_sub(BALL_POSITION_HISTORY_LIMIT);
    frames[start..=end]
        .iter()
        .map(|frame| BallPositionSample {
            tick: frame.tick,
            clock_seconds: frame.clock_seconds,
            position: frame.ball_position,
            velocity: frame.ball_velocity.unwrap_or_default(),
            acceleration: frame.ball_acceleration.unwrap_or_default(),
            jerk: frame.ball_jerk.unwrap_or_default(),
            curl_acceleration: frame.ball_curl_acceleration.unwrap_or_default(),
            altitude_yards: frame.ball_altitude_yards.unwrap_or(0.0).max(0.0),
            resistance: BallResistanceFrame::default(),
            holder: frame.ball_holder,
            last_touch_team: frame.last_touch_team,
        })
        .collect()
}

fn tracking_phase(
    config: &MatchConfig,
    frame: &SoccerTrackingFrame,
    possession_team: Option<Team>,
) -> TacticalPhase {
    let y = frame.ball_position.y;
    match possession_team {
        Some(Team::Home) if y > config.field_length_yards * 0.68 => TacticalPhase::HomeAttack,
        Some(Team::Home) => TacticalPhase::HomeBuildUp,
        Some(Team::Away) if y < config.field_length_yards * 0.32 => TacticalPhase::AwayAttack,
        Some(Team::Away) => TacticalPhase::AwayBuildUp,
        None if frame.tick < 5 => TacticalPhase::Kickoff,
        None => TacticalPhase::Transition,
    }
}

fn infer_tracking_action(
    player: &PlayerSnapshot,
    before: &WorldSnapshot,
    after: &WorldSnapshot,
    before_frame: &SoccerTrackingFrame,
    after_frame: &SoccerTrackingFrame,
) -> String {
    let Some(next_player) = after.players.iter().find(|p| p.id == player.id) else {
        return SoccerActionLabel::Hold.as_str().to_string();
    };
    let tun = &tunables().tracking;
    let before_obs = before.observation_for(player.id);
    let after_obs = after.observation_for(player.id);
    let moved = player.position.distance(next_player.position);

    if before.ball.holder != Some(player.id) {
        if let Some(action) =
            tracking_explicit_off_ball_action(player.id, before_frame, after_frame)
        {
            return action;
        }
    }

    if before.ball.holder == Some(player.id) {
        if let Some(action) =
            tracking_explicit_holder_action(player.id, before_frame, after_frame, before, after)
        {
            return action;
        }
        if tracking_goal_line_scoring_team(before, after) == Some(player.team) {
            return SoccerActionLabel::Shoot.as_str().to_string();
        }
        if let Some(holder) = after.ball.holder {
            if holder != player.id
                && after
                    .players
                    .iter()
                    .find(|p| p.id == holder)
                    .is_some_and(|p| p.team == player.team)
            {
                return tracking_pass_label(before_frame, after_frame, before, after).to_string();
            }
        }
        if tracking_ball_near_teammate(after, player.id, player.team)
            && after.ball.holder != Some(player.id)
        {
            return tracking_pass_label(before_frame, after_frame, before, after).to_string();
        }
        if before_obs.shot_lane_open
            && before_obs.yards_to_goal <= tun.shot_lane_max_yards_to_goal
            && tracking_ball_moved_toward_goal(before, after, player.team)
        {
            return SoccerActionLabel::Shoot.as_str().to_string();
        }
        if moved > before.dt_seconds * tun.moved_dt_multiplier {
            return SoccerActionLabel::Dribble.as_str().to_string();
        }
        return SoccerActionLabel::Hold.as_str().to_string();
    }

    if before.possession_team() == Some(player.team.other())
        && after.ball.holder == Some(player.id)
        && player.position.distance(before.ball.position) < tun.tackle_recover_max_distance_yards
    {
        return SoccerActionLabel::Tackle.as_str().to_string();
    }

    let before_ball_distance = player.position.distance(before.ball.position);
    let after_ball_distance = next_player.position.distance(after.ball.position);
    if before.possession_team() == Some(player.team.other())
        && after_ball_distance + tun.defend_closing_margin_yards < before_ball_distance
    {
        return SoccerActionLabel::Defend.as_str().to_string();
    }

    if before.possession_team() == Some(player.team)
        && (after_obs.open_space_score
            > before_obs.open_space_score + tun.space_improvement_threshold
            || moved > before.dt_seconds * tun.moved_dt_multiplier)
    {
        let support =
            infer_tracking_support_action(player, next_player, before, after, &before_obs);
        return support
            .map(str::to_string)
            .unwrap_or_else(|| SoccerActionLabel::Space.as_str().to_string());
    }

    if moved > before.dt_seconds * tun.moved_dt_multiplier {
        if before.possession_team() == Some(player.team.other()) {
            SoccerActionLabel::Defend.as_str().to_string()
        } else {
            SoccerActionLabel::Space.as_str().to_string()
        }
    } else {
        SoccerActionLabel::Hold.as_str().to_string()
    }
}

fn tracking_explicit_off_ball_action(
    player_id: usize,
    before_frame: &SoccerTrackingFrame,
    after_frame: &SoccerTrackingFrame,
) -> Option<String> {
    let (raw_action, action_player) = after_frame
        .ball_action
        .as_deref()
        .map(|action| (action, after_frame.action_player))
        .or_else(|| {
            before_frame
                .ball_action
                .as_deref()
                .map(|action| (action, before_frame.action_player))
        })?;
    if action_player != Some(player_id) {
        return None;
    }
    let action = normalize_tracking_ball_action(raw_action).ok().flatten()?;
    match action.as_str() {
        "space"
        | "support-shape"
        | "support-roam"
        | "check-to-ball"
        | "run-in-behind"
        | "one-two-run"
        | "exploit-space-run"
        | "wide-outlet"
        | "shot-creation-run"
        | "pinch-cross-arrival"
        | "overlap-run"
        | "dummy-clear-lane"
        | "dummy-let-run"
        | "lane-yield"
        | "support-push-up"
        | "support-screen"
        | "vacate-space"
        | "buildup-receive"
        | "defend"
        | "defend-shape"
        | "defend-roam"
        | "tackle"
        | "slide-tackle"
        | "blindside-steal"
        | "recover"
        | "hold" => Some(action),
        _ => None,
    }
}

fn infer_tracking_support_action(
    player: &PlayerSnapshot,
    next_player: &PlayerSnapshot,
    before: &WorldSnapshot,
    after: &WorldSnapshot,
    before_observation: &SoccerPomdpObservation,
) -> Option<&'static str> {
    if before.possession_team() != Some(player.team) || before.ball.holder == Some(player.id) {
        return None;
    }
    let movement = next_player.position - player.position;
    let moved = movement.len();
    if moved <= before.dt_seconds.max(DEFAULT_DT_SECONDS) * 1.2 {
        return None;
    }
    let forward = movement.y * player.team.attack_dir();
    let center_x = before.field_width * 0.5;
    let current_width = (player.position.x - center_x).abs();
    let next_width = (next_player.position.x - center_x).abs();
    let lateral = (next_player.position.x - player.position.x).abs();
    let before_ball_distance = player.position.distance(before.ball.position);
    let after_ball_distance = next_player.position.distance(after.ball.position);
    let checked_to_ball_yards = before_ball_distance - after_ball_distance;
    let nearest_pressure = before_observation
        .nearest_opponent_distance
        .min(after.nearest_opponent_distance_at(player.team, next_player.position));

    if checked_to_ball_yards > (0.65 + moved * 0.25)
        && nearest_pressure <= 7.0
        && forward < moved * 0.45
    {
        return Some("check-to-ball");
    }

    if matches!(player.role, PlayerRole::Midfielder | PlayerRole::Forward)
        && next_width > current_width + 2.0
        && lateral >= moved * 0.52
        && forward >= -0.25
        && (next_width / center_x.max(1.0)) >= 0.62
    {
        return Some("wide-outlet");
    }

    let yards_to_goal_before = (player.team.goal_y(before.field_length) - player.position.y).abs();
    let yards_to_goal_after =
        (player.team.goal_y(after.field_length) - next_player.position.y).abs();
    if matches!(player.role, PlayerRole::Forward | PlayerRole::Midfielder)
        && forward >= moved * 0.58
        && forward >= 3.0
        && yards_to_goal_after + 1.5 < yards_to_goal_before
    {
        return Some("run-in-behind");
    }

    None
}

fn tracking_explicit_holder_action(
    player_id: usize,
    before_frame: &SoccerTrackingFrame,
    after_frame: &SoccerTrackingFrame,
    before: &WorldSnapshot,
    after: &WorldSnapshot,
) -> Option<String> {
    let (raw_action, action_player) = after_frame
        .ball_action
        .as_deref()
        .map(|action| (action, after_frame.action_player))
        .or_else(|| {
            before_frame
                .ball_action
                .as_deref()
                .map(|action| (action, before_frame.action_player))
        })?;
    if action_player.is_some_and(|id| id != player_id) {
        return None;
    }
    let action = normalize_tracking_ball_action(raw_action).ok().flatten()?;
    match action.as_str() {
        "pass" => Some(tracking_pass_label(before_frame, after_frame, before, after).to_string()),
        "aerial-pass" | "flank-low-cross" | "flank-high-cross" | "killer-pass"
        | "first-time-pass" | "clearance" | "route-one" | "shoot" | "first-time-shot"
        | "first-time-header" | "control-touch" => Some(action),
        action if is_dribble_action_label(action) => Some(action.to_string()),
        _ => None,
    }
}

fn tracking_pass_label(
    before_frame: &SoccerTrackingFrame,
    after_frame: &SoccerTrackingFrame,
    before: &WorldSnapshot,
    after: &WorldSnapshot,
) -> &'static str {
    let flight = tracking_pass_flight_between(before_frame, after_frame, before, after);
    if flight.is_aerial() {
        "aerial-pass"
    } else if tracking_floor_pass_is_killer_pass(before, after, flight) {
        "killer-pass"
    } else {
        "pass"
    }
}

fn tracking_floor_pass_is_killer_pass(
    before: &WorldSnapshot,
    after: &WorldSnapshot,
    flight: PassFlight,
) -> bool {
    if flight.is_aerial() {
        return false;
    }
    let Some(passer_id) = before.ball.holder else {
        return false;
    };
    let Some(passer) = before.players.iter().find(|player| player.id == passer_id) else {
        return false;
    };
    let Some(receiver_id) = after
        .ball
        .holder
        .filter(|receiver_id| *receiver_id != passer_id)
        .or_else(|| infer_tracking_pass_receiver(passer, before, after))
    else {
        return false;
    };
    let Some(receiver) = after
        .players
        .iter()
        .find(|player| player.id == receiver_id && player.team == passer.team)
    else {
        return false;
    };
    if receiver.role == PlayerRole::Goalkeeper
        || before
            .pending_offside_for_pass(passer_id, receiver_id)
            .is_some()
    {
        return false;
    }

    let origin = before.ball.position;
    let target = after
        .player_position(receiver_id)
        .unwrap_or(after.ball.position)
        .clamp_to_pitch(before.field_width, before.field_length);
    let is_cross = pass_would_be_cross(
        origin,
        target,
        passer.team,
        before.field_width,
        before.field_length,
    );
    if is_cross || !before.clear_line(origin, target, passer.team.other(), 1.35) {
        return false;
    }

    let nearest_opponent = after.nearest_opponent_distance_at(passer.team, target);
    let receiver_openness = (nearest_opponent / 12.0).clamp(0.0, 1.0);
    let receiver_velocity = after
        .player_velocity(receiver_id)
        .or_else(|| before.player_velocity(receiver_id))
        .unwrap_or(receiver.velocity);
    let pass_vector = target - origin;
    let stride_fit = if pass_vector.len() > 1e-6 {
        let pass_dir = pass_vector.normalized();
        let forward_stride = receiver_velocity.dot(pass_dir).max(0.0);
        (0.34 + (forward_stride / 8.0).clamp(0.0, 1.0) * 0.66).clamp(0.0, 1.0)
    } else {
        0.0
    };
    completed_killer_pass_reward_from_parts(
        passer.team,
        flight,
        is_cross,
        origin,
        target,
        receiver.role,
        &receiver.skills,
        before.field_width,
        before.field_length,
        receiver_openness,
        stride_fit,
    ) > 0.0
}

fn tracking_pass_flight_between(
    before_frame: &SoccerTrackingFrame,
    after_frame: &SoccerTrackingFrame,
    before: &WorldSnapshot,
    after: &WorldSnapshot,
) -> PassFlight {
    after_frame
        .pass_flight
        .or(before_frame.pass_flight)
        .unwrap_or_else(|| {
            let before_altitude = before_frame
                .ball_altitude_yards
                .unwrap_or(before.ball.altitude_yards);
            let after_altitude = after_frame
                .ball_altitude_yards
                .unwrap_or(after.ball.altitude_yards);
            if before_altitude.max(after_altitude) > 0.35 {
                PassFlight::Aerial
            } else {
                PassFlight::Floor
            }
        })
}

fn tracking_action_target_trace(
    player: &PlayerSnapshot,
    before: &WorldSnapshot,
    after: &WorldSnapshot,
    action: &str,
) -> Option<AgentActionTargetTrace> {
    let next_player = after.players.iter().find(|p| p.id == player.id);
    let goal = Vec2::new(
        before.field_width * 0.5,
        player.team.goal_y(before.field_length),
    );
    let normalized = normalize_soccer_action_label(action);
    let (point, target_player) = if is_pass_like_action(normalized) {
        let holder_teammate = after.ball.holder.and_then(|holder| {
            after
                .players
                .iter()
                .find(|p| p.id == holder && p.team == player.team && p.id != player.id)
                .map(|p| (p.position, Some(p.id)))
        });
        holder_teammate.unwrap_or_else(|| {
            (
                after.ball.position,
                infer_tracking_pass_receiver(player, before, after),
            )
        })
    } else {
        use SoccerActionLabel::*;
        match SoccerActionLabel::classify(normalized) {
            Some(Clearance | RouteOne) => (after.ball.position, None),
            Some(Shoot | FirstTimeShot | FirstTimeHeader) => (goal, None),
            Some(
                Dribble | CarryForward | CarryOutLeft | CarryOutRight | ProtectBall | SideStep
                | LeftCut | RightCut | Nutmeg | XaviTurn | FakeLeftCutRight | FakeRightCutLeft
                | OpenPassLane | ControlTouch | Space | SupportShape | SupportRoam | CheckToBall
                | RunInBehind | ExploitSpaceRun | WideOutlet | ShotCreationRun | PinchCrossArrival
                | OverlapRun | SupportScreen | SupportPushUp | VacateSpace | Defend,
            ) => (
                next_player.map(|p| p.position).unwrap_or(player.position),
                None,
            ),
            Some(Tackle) => {
                let target_player = before.ball.holder.or(after.ball.holder);
                let point = target_player
                    .and_then(|id| {
                        before
                            .player_position(id)
                            .or_else(|| after.player_position(id))
                    })
                    .unwrap_or(before.ball.position);
                (point, target_player)
            }
            Some(Hold) => (player.home_position, None),
            _ => return None,
        }
    };
    let point = point.clamp_to_pitch(before.field_width, before.field_length);
    let dribble_touch = if is_dribble_action_label(action) {
        tracking_dribble_touch_from_positions(player.team, player.position, point)
    } else {
        None
    };
    Some(AgentActionTargetTrace {
        point: Some(point),
        player_id: target_player,
        grid: Some(pitch_grid_address(
            point,
            before.field_width,
            before.field_length,
        )),
        facing: facing_bucket_from_vector(point - player.position),
        dribble_touch,
    })
}

fn tracking_dribble_touch_from_positions(
    team: Team,
    origin: Vec2,
    target: Vec2,
) -> Option<DribbleTouchDecision> {
    let delta = target - origin;
    let distance = delta.len();
    if distance <= 1e-6 {
        return None;
    }
    let direction = delta.normalized();
    let lateral = direction.x * team.attack_dir();
    let forward = direction.y * team.attack_dir();
    let mut angle_degrees = lateral.atan2(forward).to_degrees();
    if angle_degrees < 0.0 {
        angle_degrees += 360.0;
    }
    let bucket = ((angle_degrees / DRIBBLE_TOUCH_BUCKET_DEGREES).round() as u8)
        % DRIBBLE_TOUCH_ANGLE_BUCKETS;
    Some(DribbleTouchDecision::new(bucket, distance))
}

fn infer_tracking_pass_receiver(
    player: &PlayerSnapshot,
    before: &WorldSnapshot,
    after: &WorldSnapshot,
) -> Option<usize> {
    let pass_vector = after.ball.position - before.ball.position;
    if pass_vector.len() < 1.0 {
        return None;
    }
    let pass_dir = pass_vector.normalized();
    let mut candidates = after
        .players
        .iter()
        .filter(|candidate| candidate.team == player.team && candidate.id != player.id)
        .filter_map(|candidate| {
            let position = after
                .player_position(candidate.id)
                .unwrap_or(candidate.position);
            let distance_to_ball = position.distance(after.ball.position);
            let lane_distance =
                distance_to_segment(position, before.ball.position, after.ball.position);
            if distance_to_ball > 18.0 && lane_distance > 5.5 {
                return None;
            }
            let velocity = after
                .player_velocity(candidate.id)
                .or_else(|| before.player_velocity(candidate.id))
                .unwrap_or(candidate.velocity);
            let to_ball = after.ball.position - position;
            let closing_speed = if to_ball.len() > 1e-6 {
                velocity.dot(to_ball.normalized()).max(0.0)
            } else {
                0.0
            };
            let stride_speed = velocity.dot(pass_dir).max(0.0);
            let forward_ball = pass_vector.y * player.team.attack_dir();
            let candidate_forward = (position.y - player.position.y) * player.team.attack_dir();
            let forward_fit = if forward_ball > 0.5 && candidate_forward > -2.0 {
                1.0
            } else {
                0.0
            };
            let score = distance_to_ball + lane_distance * 0.38
                - closing_speed * 0.58
                - stride_speed * 0.34
                - forward_fit * 0.65;
            Some((score, candidate.id))
        })
        .collect::<Vec<_>>();
    candidates.sort_by(|a, b| {
        a.0.partial_cmp(&b.0)
            .unwrap_or(std::cmp::Ordering::Equal)
            .then_with(|| a.1.cmp(&b.1))
    });
    candidates.first().map(|(_, id)| *id)
}

fn tracking_team_scored(team: Team, before: &WorldSnapshot, after: &WorldSnapshot) -> bool {
    match team {
        Team::Home => after.score_home > before.score_home,
        Team::Away => after.score_away > before.score_away,
    }
}

fn tracking_goal_line_scoring_team(before: &WorldSnapshot, after: &WorldSnapshot) -> Option<Team> {
    if tracking_team_scored(Team::Home, before, after) {
        return Some(Team::Home);
    }
    if tracking_team_scored(Team::Away, before, after) {
        return Some(Team::Away);
    }
    let crossing_fraction = boundary_crossing_fraction(
        before.ball.position.y,
        after.ball.position.y,
        0.0,
        before.field_length,
    )?;
    let scoring_team = if after.ball.position.y > before.field_length {
        Team::Home
    } else if after.ball.position.y < 0.0 {
        Team::Away
    } else {
        return None;
    };
    let crossing_x = before.ball.position.x
        + (after.ball.position.x - before.ball.position.x) * crossing_fraction;
    let goal_x = before.field_width * 0.5;
    ((crossing_x - goal_x).abs() <= before.goal_width * 0.5).then_some(scoring_team)
}

fn tracking_ball_moved_toward_goal(
    before: &WorldSnapshot,
    after: &WorldSnapshot,
    team: Team,
) -> bool {
    (after.ball.position.y - before.ball.position.y) * team.attack_dir() > 3.0
}

fn tracking_ball_near_teammate(after: &WorldSnapshot, player_id: usize, team: Team) -> bool {
    after
        .players
        .iter()
        .filter(|p| p.team == team && p.id != player_id)
        .any(|p| p.position.distance(after.ball.position) < 4.0)
}

fn tracking_goal_events(
    before: &WorldSnapshot,
    after: &WorldSnapshot,
    events: &mut Vec<MatchEvent>,
) {
    if after.score_home > before.score_home {
        events.push(MatchEvent {
            tick: after.tick,
            clock_seconds: after.clock_seconds,
            kind: "goal".to_string(),
            team: Some(Team::Home),
            player_id: before.ball.holder,
            description: "Home goal from tracking data".to_string(),
            ..MatchEvent::default()
        });
    }
    if after.score_away > before.score_away {
        events.push(MatchEvent {
            tick: after.tick,
            clock_seconds: after.clock_seconds,
            kind: "goal".to_string(),
            team: Some(Team::Away),
            player_id: before.ball.holder,
            description: "Away goal from tracking data".to_string(),
            ..MatchEvent::default()
        });
    }
    if after.score_home == before.score_home && after.score_away == before.score_away {
        if let Some(team) = tracking_goal_line_scoring_team(before, after) {
            events.push(MatchEvent {
                tick: after.tick,
                clock_seconds: after.clock_seconds,
                kind: "goal".to_string(),
                team: Some(team),
                player_id: before.ball.holder,
                description: format!("{team:?} goal inferred from tracking goal-line crossing"),
                ..MatchEvent::default()
            });
        }
    }
}

fn soccer_moment_replay_action_for_label(label: &str) -> Option<&'static str> {
    match label {
        "great_shot_to_goal" => Some("shoot"),
        "great_pass_to_goal" => Some("pass"),
        "great_dribble_to_goal" => Some("dribble"),
        _ => None,
    }
}

fn soccer_moment_replay_reward_for_label(label: &str) -> Option<f64> {
    match label {
        "great_shot_to_goal" => Some(SOCCER_MOMENT_REPLAY_SHOT_REWARD),
        "great_pass_to_goal" => Some(SOCCER_MOMENT_REPLAY_PASS_REWARD),
        "great_dribble_to_goal" => Some(SOCCER_MOMENT_REPLAY_DRIBBLE_REWARD),
        _ => None,
    }
}

fn soccer_moment_action_matches_label(action: &SoccerMomentActionMarker, label: &str) -> bool {
    let action = normalize_soccer_action_label(&action.action);
    match label {
        "great_shot_to_goal" => matches!(action, "shoot" | "first-time-shot"),
        "great_pass_to_goal" => is_pass_like_action(action),
        "great_dribble_to_goal" => is_dribble_action_label(action),
        _ => false,
    }
}

fn soccer_moment_replay_marker(
    actions: &[SoccerMomentActionMarker],
    label: &str,
    player_id: Option<usize>,
) -> Option<SoccerMomentActionMarker> {
    actions
        .iter()
        .rev()
        .filter(|action| soccer_moment_action_matches_label(action, label))
        .find(|action| player_id.map(|id| id == action.player_id).unwrap_or(true))
        .or_else(|| {
            actions
                .iter()
                .rev()
                .find(|action| soccer_moment_action_matches_label(action, label))
        })
        .cloned()
}

fn soccer_moment_frame_pair_for_tick(
    frames: &[SoccerTrackingFrame],
    tick: u64,
) -> Option<(&SoccerTrackingFrame, &SoccerTrackingFrame)> {
    if frames.len() < 2 {
        return None;
    }
    for pair in frames.windows(2) {
        let before = &pair[0];
        let after = &pair[1];
        if before.tick <= tick && tick <= after.tick {
            return Some((before, after));
        }
    }
    if tick < frames[0].tick {
        Some((&frames[0], &frames[1]))
    } else {
        let last = frames.len() - 1;
        Some((&frames[last - 1], &frames[last]))
    }
}

fn soccer_moment_action_target_trace(
    marker: Option<&SoccerMomentActionMarker>,
    action: &str,
    player: &PlayerSnapshot,
    before: &WorldSnapshot,
    after: &WorldSnapshot,
) -> Option<AgentActionTargetTrace> {
    let normalized = normalize_soccer_action_label(action);
    let next_player = after.players.iter().find(|p| p.id == player.id);
    let goal = Vec2::new(
        before.field_width * 0.5,
        player.team.goal_y(before.field_length),
    );
    let marker_target = marker.and_then(|marker| marker.target_player);
    let (point, target_player) = match normalized {
        action if is_pass_like_action(action) => {
            let target_player = marker_target.or(after.ball.holder);
            let point = target_player
                .and_then(|id| {
                    after
                        .player_position(id)
                        .or_else(|| before.player_position(id))
                })
                .unwrap_or(after.ball.position);
            (point, target_player)
        }
        "shoot" | "first-time-shot" | "first-time-header" => (goal, None),
        "dribble"
        | "carry-forward"
        | "carry-out-left"
        | "carry-out-right"
        | "protect-ball"
        | "side-step"
        | "left-cut"
        | "right-cut"
        | "nutmeg"
        | "fake-left-cut-right"
        | "fake-right-cut-left"
        | "control-touch"
        | "space"
        | "support-shape"
        | "support-roam"
        | "check-to-ball"
        | "run-in-behind"
        | "one-two-run"
        | "exploit-space-run"
        | "wide-outlet"
        | "shot-creation-run"
        | "pinch-cross-arrival"
        | "overlap-run"
        | "dummy-clear-lane"
        | "dummy-let-run"
        | "lane-yield"
        | "support-push-up"
        | "support-screen"
        | "vacate-space"
        | "buildup-receive"
        | "defend"
        | "defend-shape"
        | "defend-roam" => (
            next_player.map(|p| p.position).unwrap_or(player.position),
            None,
        ),
        "tackle" | "slide-tackle" | "blindside-steal" => {
            let target_player = before.ball.holder.or(after.ball.holder);
            let point = target_player
                .and_then(|id| {
                    before
                        .player_position(id)
                        .or_else(|| after.player_position(id))
                })
                .unwrap_or(before.ball.position);
            (point, target_player)
        }
        _ => return None,
    };
    let point = point.clamp_to_pitch(before.field_width, before.field_length);
    let dribble_touch = if is_dribble_action_label(normalized) {
        tracking_dribble_touch_from_positions(player.team, player.position, point)
    } else {
        None
    };
    Some(AgentActionTargetTrace {
        point: Some(point),
        player_id: target_player,
        grid: Some(pitch_grid_address(
            point,
            before.field_width,
            before.field_length,
        )),
        facing: facing_bucket_from_vector(point - player.position),
        dribble_touch,
    })
}

fn soccer_moment_replay_transition(
    record: &SoccerMomentStorageRecord,
    config: &MatchConfig,
    reward_scale: f64,
) -> Result<Option<SoccerLearningTransition>, String> {
    let label = record.window.summary.label.as_str();
    let Some(default_action) = soccer_moment_replay_action_for_label(label) else {
        return Ok(None);
    };
    let Some(base_reward) = soccer_moment_replay_reward_for_label(label) else {
        return Ok(None);
    };
    if record.window.frames.len() < 2 {
        return Ok(None);
    }

    let marker = soccer_moment_replay_marker(
        &record.window.actions,
        label,
        record.window.summary.player_id,
    );
    let action = marker
        .as_ref()
        .map(|marker| normalize_soccer_action_label(&marker.action).to_string())
        .unwrap_or_else(|| default_action.to_string());
    let tick = marker
        .as_ref()
        .map(|marker| marker.tick)
        .unwrap_or(record.window.summary.event_tick);
    let player_id = marker
        .as_ref()
        .map(|marker| marker.player_id)
        .or(record.window.summary.player_id);
    let Some(player_id) = player_id else {
        return Ok(None);
    };

    let tracking = SoccerTrackingDataset {
        source: format!("moment-replay:{}", record.window.summary.id),
        config: config.clone(),
        frames: record.window.frames.clone(),
    };
    tracking.validate()?;
    let frames = tracking_frames_with_inferred_kinematics(&tracking);
    let home_positions = tracking_home_positions(&tracking);
    let Some((before_frame, after_frame)) = soccer_moment_frame_pair_for_tick(&frames, tick) else {
        return Ok(None);
    };
    let before = tracking_frame_to_world_snapshot(config, before_frame, &home_positions);
    let after = tracking_frame_to_world_snapshot(config, after_frame, &home_positions);
    let Some(player) = before.players.iter().find(|player| player.id == player_id) else {
        return Ok(None);
    };

    let observation = before.observation_for(player_id);
    let action_target =
        soccer_moment_action_target_trace(marker.as_ref(), &action, player, &before, &after);
    let marker_reward = marker
        .as_ref()
        .map(|marker| marker.reward)
        .filter(|reward| reward.is_finite())
        .unwrap_or(0.0);
    let reward = marker_reward + base_reward * reward_scale;
    let mut decision_context = soccer_decision_context_with_trace(
        player_id,
        player.team,
        &AgentDecisionTrace {
            mdp_state: before.mdp_state_for_player(player_id),
            observation: observation.clone(),
            belief: belief_from_observation(&observation),
            operation_order: vec!["moment-replay".to_string()],
            scheduled_index: None,
            action_options: single_action_option(&action),
            action_target: action_target.clone(),
            mdp_mpc_comparison: None,
            learned_mpc_replan: None,
            behavior_policy_probability: None,
            neural_mcts_selected: false,
            neural_mcts_candidate_count: 0,
            neural_mcts_discretized_kick_candidate_count: 0,
            neural_mcts_root_discretized_kick_candidate_count: 0,
            action: action.clone(),
        },
        &before,
        &after,
    );
    decision_context.tracking_source_frame_id = before_frame.source_frame_id.clone();
    decision_context.next_tracking_source_frame_id = after_frame.source_frame_id.clone();
    let before_pos = before.player_position(player_id).unwrap_or(player.position);
    let after_pos = after.player_position(player_id).unwrap_or(before_pos);

    Ok(Some(SoccerLearningTransition {
        tick,
        player_id,
        team: player.team,
        role: player.role,
        state: before.mdp_state_for_player(player_id),
        observation: observation.clone(),
        belief: belief_from_observation(&observation),
        action,
        action_target,
        decision_context,
        tactical_trace: tactical_shape_trace_for_snapshots(
            player_id,
            player.team,
            player.role,
            &before,
            &after,
            before_pos,
            after_pos,
            &config.tactical_learning,
        ),
        reward,
        next_state: after.mdp_state_for_player(player_id),
        next_observation: after.observation_for(player_id),
        done: after_frame.tick
            == frames
                .last()
                .map(|frame| frame.tick)
                .unwrap_or(after_frame.tick),
    }))
}

fn player_agent_from_snapshot(player: &PlayerSnapshot) -> PlayerAgent {
    let mut position_history = player
        .position_history
        .iter()
        .copied()
        .collect::<VecDeque<_>>();
    if position_history.is_empty() {
        position_history.push_back(player.position);
    }
    while position_history.len() > PLAYER_POSITION_HISTORY_LIMIT {
        position_history.pop_front();
    }
    PlayerAgent {
        id: player.id,
        name: player.name.clone(),
        team: player.team,
        role: player.role,
        shirt: player.shirt,
        home_position: player.home_position,
        position: player.position,
        velocity: player.velocity,
        acceleration: player.acceleration,
        jerk: player.jerk,
        movement_gait: player.movement_gait,
        locomotion: LocomotionCommitment::default(),
        position_history,
        receive_facing: player.receive_facing,
        action_facing: player.action_facing,
        facing_yaw: 0.0,
        yaw_rate: 0.0,
        dizziness: 0.0,
        anaerobic_load: 0.0,
        last_tick_locomotion_joules: 0.0,
        sustained_sprint_seconds: 0.0,
        sustained_sprint_distance_yards: 0.0,
        same_team_proximity_dwell_lt7_seconds: player.same_team_proximity_dwell_lt7_seconds,
        same_team_proximity_dwell_lt6_seconds: player.same_team_proximity_dwell_lt6_seconds,
        same_team_proximity_dwell_lt5_seconds: player.same_team_proximity_dwell_lt5_seconds,
        incoming_ball: player.incoming_ball.clone(),
        skills: player.skills.clone(),
        fatigue: player.fatigue.clamp(0.0, 1.0),
        controller_slot: None,
        preferences: player.preferences.clone(),
        last_decision: None,
        pending_policy_behavior_probability: None,
        decision_confidence: 1.0,
        one_two: player.one_two,
        runaround: player.runaround,
        hold_for_support: player.hold_for_support.clone(),
        slide_recovery_seconds: player.slide_recovery_seconds,
        decision_commit_ticks: VecDeque::new(),
        last_intent: None,
    }
}

fn neutral_tracking_skill_profile(role: PlayerRole) -> SkillProfile {
    let shooting = match role {
        PlayerRole::Forward => 7.8,
        PlayerRole::Midfielder => 6.6,
        PlayerRole::Defender => 5.0,
        PlayerRole::Goalkeeper => 4.0,
    };
    SkillProfile {
        top_speed: 7.4,
        acceleration: 7.1,
        strength: match role {
            PlayerRole::Goalkeeper => 7.8,
            PlayerRole::Defender => 8.0,
            PlayerRole::Midfielder => 6.6,
            PlayerRole::Forward => 7.4,
        },
        height: match role {
            PlayerRole::Goalkeeper => 8.6,
            PlayerRole::Defender => 7.6,
            PlayerRole::Midfielder => 6.0,
            PlayerRole::Forward => 7.0,
        },
        weight_pounds: default_player_weight_for_traits(
            role,
            match role {
                PlayerRole::Goalkeeper => 7.8,
                PlayerRole::Defender => 8.0,
                PlayerRole::Midfielder => 6.6,
                PlayerRole::Forward => 7.4,
            },
            match role {
                PlayerRole::Goalkeeper => 8.6,
                PlayerRole::Defender => 7.6,
                PlayerRole::Midfielder => 6.0,
                PlayerRole::Forward => 7.0,
            },
            0.0,
        ),
        shooting,
        right_foot_shot_power: (shooting + 0.6).clamp(1.0, 10.0),
        left_foot_shot_power: (shooting - 0.8).clamp(1.0, 10.0),
        passing: 7.2,
        passing_completion_rate: 7.2,
        flair_passing: 4.2,
        crossing_left: 6.6,
        crossing_right: 7.0,
        dribbling: 6.8,
        first_touch: 7.0,
        defending: 6.8,
        goalkeeping: if role == PlayerRole::Goalkeeper {
            8.8
        } else {
            1.6
        },
        defensive_tracking: 6.8,
        stamina: 8.2,
        vision: DEFAULT_PLAYER_VISION_SKILL,
        decision_noise: 0.05,
        aggression: 5.8,
    }
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum DefenderDribbleResponse {
    HoldUp,
    Commit,
}

fn dribble_dispossession_probability(
    defender: &SkillProfile,
    attacker: &SkillProfile,
    response: DefenderDribbleResponse,
) -> f64 {
    let base = match response {
        DefenderDribbleResponse::HoldUp => HOLD_UP_DISPOSSESSION_PROBABILITY,
        DefenderDribbleResponse::Commit => COMMIT_DISPOSSESSION_PROBABILITY,
    };
    let ball_control =
        ability01(attacker.dribbling) * 0.70 + ability01(attacker.first_touch) * 0.30;
    let defensive_pressure =
        ability01(defender.defending) * 0.82 + ability01(defender.aggression) * 0.18;
    let skill_edge = defensive_pressure - ball_control;
    match response {
        DefenderDribbleResponse::HoldUp => (base + skill_edge * 0.16).clamp(0.06, 0.42),
        DefenderDribbleResponse::Commit => (base + skill_edge * 0.22).clamp(0.24, 0.76),
    }
}

fn dribble_beat_probability(
    kind: DribbleMoveKind,
    attacker: &SkillProfile,
    defender: &SkillProfile,
    response: DefenderDribbleResponse,
) -> f64 {
    let attacker_evasion = ability01(attacker.dribbling) * 0.52
        + ability01(attacker.acceleration) * 0.28
        + ability01(attacker.first_touch) * 0.20;
    let defender_balance =
        ability01(defender.defending) * 0.68 + ability01(defender.aggression) * 0.32;
    let kind_multiplier = match kind {
        DribbleMoveKind::CarryForward => 0.72,
        DribbleMoveKind::CarryOutLeft | DribbleMoveKind::CarryOutRight => 0.84,
        DribbleMoveKind::ProtectBall => 0.46,
        DribbleMoveKind::LeftCut | DribbleMoveKind::RightCut => 1.0,
        DribbleMoveKind::Nutmeg => 0.82,
        DribbleMoveKind::FakeLeftCutRight | DribbleMoveKind::FakeRightCutLeft => 1.05,
        // Turning a committed defender with a shielded pirouette beats them cleanly more
        // often than not — they are wrong-footed by the long way around.
        DribbleMoveKind::XaviTurn => 0.96,
    };
    let response_multiplier = match response {
        DefenderDribbleResponse::HoldUp => 1.0,
        DefenderDribbleResponse::Commit => COMMIT_DRIBBLE_BEAT_MULTIPLIER,
    };
    let raw = attacker_evasion / (attacker_evasion + defender_balance * 0.94);
    (raw * kind_multiplier * response_multiplier).clamp(0.10, 0.88)
}

fn dribble_beat_geometry_is_valid(
    attacking_team: Team,
    attacker_before: Vec2,
    attacker_after: Vec2,
    defender_before: Vec2,
    defender_after: Vec2,
) -> bool {
    let challenge_distance = attacker_before.distance(defender_before);
    if challenge_distance > DRIBBLE_BEAT_CONTACT_RADIUS_YARDS {
        return false;
    }
    let attack_dir = attacking_team.attack_dir();
    let before_gap = (attacker_before.y - defender_before.y) * attack_dir;
    let after_gap = (attacker_after.y - defender_after.y) * attack_dir;
    let forward_progress = (attacker_after.y - attacker_before.y) * attack_dir;
    let after_lateral_gap = (attacker_after.x - defender_after.x).abs();
    before_gap <= DRIBBLE_BEAT_FRONT_LINE_TOLERANCE_YARDS
        && after_gap >= DRIBBLE_BEAT_BEHIND_LINE_TOLERANCE_YARDS
        && forward_progress >= 0.25
        && after_lateral_gap <= 6.0
}

fn dribble_dispossession_kind_multiplier(kind: DribbleMoveKind) -> f64 {
    match kind {
        DribbleMoveKind::ProtectBall => 0.58,
        // Even more secure than a static shield: the body stays between defender and ball
        // through the whole turn. (The hard 10% ceiling is applied separately.)
        DribbleMoveKind::XaviTurn => 0.40,
        DribbleMoveKind::CarryForward => 0.86,
        DribbleMoveKind::CarryOutLeft | DribbleMoveKind::CarryOutRight => 0.78,
        DribbleMoveKind::FakeLeftCutRight | DribbleMoveKind::FakeRightCutLeft => 0.92,
        DribbleMoveKind::LeftCut | DribbleMoveKind::RightCut => 1.0,
        DribbleMoveKind::Nutmeg => 1.12,
    }
}

fn tackle_success_probability(defender: &SkillProfile, attacker: &SkillProfile) -> f64 {
    dribble_dispossession_probability(defender, attacker, DefenderDribbleResponse::Commit)
}

/// Probability that a committed SLIDE tackle wins the ball cleanly — the standing
/// steal chance, boosted (a full-stretch lunge takes the ball more often than a
/// standing poke). Capped below 1 so a slide is never a certainty.
fn slide_tackle_success_probability(defender: &SkillProfile, attacker: &SkillProfile) -> f64 {
    (tackle_success_probability(defender, attacker) * SLIDE_TACKLE_SUCCESS_BOOST).clamp(0.0, 0.97)
}

/// Probability a slide tackle is a foul — the standing-tackle foul model scaled up,
/// because leaving the feet is intrinsically mistimable. (No-op while fouls are
/// disabled via `FOUL_PROBABILITY_SCALE`, but kept correct for when they are on.)
fn slide_tackle_foul_probability(
    defender: &SkillProfile,
    attacker: &SkillProfile,
    contact_distance: f64,
    contact_speed: f64,
) -> f64 {
    (tackle_foul_probability(defender, attacker, contact_distance, contact_speed)
        * SLIDE_TACKLE_FOUL_BOOST)
        .clamp(0.0, 0.97)
}

/// Whether a defender at `defender_pos` is BEHIND the ball-carrier — in the rear
/// hemisphere relative to where the ball is being carried (the holder→ball lead, or the
/// holder's motion when the ball is at the feet). The ball is led in front of the body,
/// so a trailing defender cannot poke it cleanly from there: standing/passive steals are
/// blocked, while a committed slide must pass a separate ball-reach gate. Returns
/// `false` when front cannot be determined (a stationary holder with the ball at its
/// feet) — that case is governed by the body-shield test instead.
fn carried_ball_behind_defender(
    holder_pos: Vec2,
    holder_velocity: Vec2,
    ball_pos: Vec2,
    defender_pos: Vec2,
) -> bool {
    let lead = ball_pos - holder_pos;
    let front = if lead.len() > 0.4 {
        lead
    } else if holder_velocity.len() > 0.5 {
        holder_velocity
    } else {
        return false;
    };
    let to_def = defender_pos - holder_pos;
    if to_def.len() < 1e-3 {
        return false;
    }
    to_def.normalized().dot(front.normalized()) < TACKLE_BEHIND_CARRIER_DOT
}

fn dd_soccer_disable_slide_tackle() -> bool {
    use std::sync::OnceLock;
    static V: OnceLock<bool> = OnceLock::new();
    *V.get_or_init(|| std::env::var("DD_SOCCER_DISABLE_SLIDE_TACKLE").is_ok())
}

/// `DD_SOCCER_ENABLE_BLINDSIDE_STEAL` controls the "surprise steal from behind".
/// A defender that has crept into the blind arc of an opponent dribbling *forward and
/// slowly* (walk/jog/skip) — and that believes it can actually catch the carrier (a real
/// closing-speed margin) — can nick the ball from behind before the carrier reacts; the
/// carrier in turn glances to its blind side (a head-scan with a real control-drift cost)
/// to RECOGNIZE the threat and break away. Production is default-on and can be killed with
/// `DD_SOCCER_ENABLE_BLINDSIDE_STEAL=0`; tests remain default-off for stable A/B coverage.
fn dd_soccer_enable_blindside_steal() -> bool {
    #[cfg(test)]
    {
        // Read fresh under test so a single process can A/B the gate per test.
        soccer_env_flag_enabled("DD_SOCCER_ENABLE_BLINDSIDE_STEAL")
    }
    #[cfg(not(test))]
    {
        use std::sync::OnceLock;
        static V: OnceLock<bool> = OnceLock::new();
        // Default ON in production (kill with DD_SOCCER_ENABLE_BLINDSIDE_STEAL=0): defenders steal
        // from behind a blind dribbler when they believe they can win it; the carrier glances to
        // recognize the threat. Tests stay default-OFF (suite stable).
        *V.get_or_init(|| gate_default_on("DD_SOCCER_ENABLE_BLINDSIDE_STEAL"))
    }
}

