/// Whether the Bayesian opponent-press belief is live for this match: off unless the
/// per-match config opts in or the process-wide `DD_SOCCER_OPPONENT_BELIEF` env flag is
/// set. Defined on the parent module so both the per-tick update and the consuming
/// pass-lane risk (`world`) read one source of truth.
fn opponent_belief_enabled(config: &MatchConfig) -> bool {
    dd_soccer_opponent_belief_enabled() || config.opponent_belief_enabled
}

/// Convert a posterior press tendency theta-hat in [0,1] into a multiplicative factor on the
/// analytic pass-lane interception risk: the prior-mean tendency (0.5) maps to 1.0 (no
/// change), a passive defender discounts the priced risk, a proven aggressor amplifies it.
/// Bounded so the belief shades the geometric estimate without ever dominating it.
fn opponent_press_risk_modulation(tendency: f64) -> f64 {
    if !tendency.is_finite() {
        return 1.0;
    }
    (tendency / OPPONENT_PRESS_NEUTRAL_TENDENCY).clamp(
        OPPONENT_PRESS_RISK_MODULATION_FLOOR,
        OPPONENT_PRESS_RISK_MODULATION_CEIL,
    )
}

fn tackle_foul_probability(
    defender: &SkillProfile,
    attacker: &SkillProfile,
    contact_distance: f64,
    contact_speed: f64,
) -> f64 {
    let timing_risk = (1.0 - ability01(defender.defending)) * 0.34;
    let aggression_risk = ability01(defender.aggression) * 0.24;
    let control_risk =
        (ability01(attacker.dribbling) * 0.55 + ability01(attacker.first_touch) * 0.45) * 0.12;
    let speed_risk = (contact_speed / 10.0).clamp(0.0, 1.0) * 0.18;
    let reach_risk = (contact_distance / 2.2).clamp(0.0, 1.0) * 0.10;
    // Fouls/free kicks are currently disabled: keep the model intact but scale the
    // probability to effectively zero so they essentially never fire.
    (0.02 + timing_risk + aggression_risk + control_risk + speed_risk + reach_risk)
        .clamp(0.03, 0.78)
        * FOUL_PROBABILITY_SCALE
}

fn carried_ball_lead(player: &PlayerAgent) -> Vec2 {
    // Keep the ball in front of the body (the way the player is facing), not in the raw
    // direction of travel — the latter flips the ball to the other side the instant the
    // player's velocity changes sign. `facing_yaw` rotates smoothly under the yaw-rate
    // cap (tighter still in possession), so the ball tracks the front foot cleanly.
    let facing = Vec2::new(player.facing_yaw.cos(), player.facing_yaw.sin());
    let facing = if facing.len() > 1e-6 {
        facing.normalized()
    } else {
        Vec2::new(0.0, player.team.attack_dir())
    };
    facing * DRIBBLE_TOUCH_LEAD_YARDS
}

/// The unit tangent a `xavi-turn` carrier wheels along — perpendicular to the
/// defender→carrier line, committed to ONE rotational side so the ~290° pirouette never
/// reverses partway through (which would unwind the turn and briefly swing the ball back
/// toward the defender).
///
/// `away` is the unit vector from the defender to the carrier (the shielded side). The
/// rotational sense is taken from the carrier's existing angular momentum about the
/// defender (`cross(away, velocity)`): once it is wheeling, it keeps wheeling that way
/// regardless of how far the defender's bearing has swept — this is what a per-tick
/// geometric test cannot guarantee, since `away` rotates a full circle through the turn.
/// Before it has tangential momentum (just initiating, or moving radially) the sense is
/// seeded toward the open middle of the pitch — a flip-resistant choice that also curls the
/// carrier away from the touchline rather than into it — and leans goalward when there is no
/// lateral preference (defender square to the carrier, or the carrier on the halfway line).
fn xavi_turn_wheel_tangent(
    away: Vec2,
    velocity: Vec2,
    current_x: f64,
    field_center_x: f64,
    attack_dir: f64,
) -> Vec2 {
    // +90° (counter-clockwise) rotation of `away`.
    let base = Vec2::new(-away.y, away.x);
    if base.len() <= 1e-9 {
        return Vec2::new(0.0, attack_dir.signum());
    }
    // cross(away, velocity) > 0 ⇒ the carrier is already orbiting counter-clockwise ⇒ +base.
    let angular_momentum = away.x * velocity.y - away.y * velocity.x;
    let sense = if angular_momentum.abs() > XAVI_TURN_WHEEL_MOMENTUM_EPS_YPS {
        angular_momentum
    } else {
        let toward_center = field_center_x - current_x;
        if base.x.abs() > 1e-6 && toward_center.abs() > 0.5 {
            base.x * toward_center
        } else {
            base.y * attack_dir
        }
    };
    if sense >= 0.0 {
        base
    } else {
        base * -1.0
    }
}

/// Where the carrier wants the ball this tick — the resting spot the orbital
/// model eases toward. Returns `(desired_world_dir, desired_radius, allow_through_body,
/// prefer_long_orbit, winding_cap_rad, max_orbit_rate_rad_s)`.
///
/// - Direction is derived from the body facing and the active dribble move: an
///   ordinary carry keeps the ball ahead; carry-outs nudge it to a front-side; cuts
///   / fakes / nutmegs swing it hard across (and may take it THROUGH the body line).
/// - Radius is close control: ~0.25 yd under tight pressure out to ~1.0 yd in space
///   (tighter the nearer the closest opponent).
/// - Only special moves set `allow_through_body` (ordinary play arcs AROUND the body).
/// - The Xavi turn deliberately takes the long way around the carrier (280-300 deg)
///   while keeping the ball on the defender's far side.
fn carried_ball_orbit_command(
    facing_yaw: f64,
    move_kind: Option<DribbleMoveKind>,
    nearest_opponent_distance: f64,
    // Unit vector from the carrier TOWARD the nearest opponent (None if none/degenerate).
    // Used to shield: the protected ball is held on the OPPOSITE side of the body.
    nearest_opponent_dir: Option<Vec2>,
) -> (Vec2, f64, bool, bool, f64, f64) {
    let facing_yaw = if facing_yaw.is_finite() {
        facing_yaw
    } else {
        std::f64::consts::FRAC_PI_2
    };
    let tightness = if nearest_opponent_distance.is_finite() {
        ((CARRY_TIGHT_CONTROL_RANGE_YARDS - nearest_opponent_distance)
            / (CARRY_TIGHT_CONTROL_RANGE_YARDS - 1.0).max(1e-6))
        .clamp(0.0, 1.0)
    } else {
        0.0
    };
    let radius = CARRY_LOOSE_RADIUS_YARDS
        + (CARRY_TIGHT_RADIUS_YARDS - CARRY_LOOSE_RADIUS_YARDS) * tightness;
    let dir_at = |relative_degrees: f64| {
        let angle = facing_yaw + relative_degrees.to_radians();
        Vec2::new(angle.cos(), angle.sin())
    };
    let shield_dir = nearest_opponent_dir
        .filter(|toward| toward.len() > 1e-6)
        .map(|toward| toward.normalized() * -1.0);
    let xavi_turn_dir = || {
        let fallback = dir_at(280.0);
        let Some(shield_dir) = shield_dir else {
            return fallback;
        };
        let mut best = fallback.normalized();
        let mut best_dot = best.dot(shield_dir);
        for candidate in [dir_at(280.0), dir_at(300.0), dir_at(-280.0), dir_at(-300.0)] {
            let candidate = candidate.normalized();
            let score = candidate.dot(shield_dir);
            if score > best_dot {
                best = candidate;
                best_dot = score;
            }
        }
        if best_dot >= 0.40 {
            best
        } else {
            shield_dir
        }
    };
    let (base_dir, allow_through, prefer_long_orbit, winding_cap, rate) = match move_kind {
        Some(DribbleMoveKind::CarryOutLeft) => (
            dir_at(32.0),
            false,
            false,
            CARRY_ORBIT_POSSESSION_SOFT_CAP_RAD,
            CARRY_ORBIT_NORMAL_RATE_RAD_S,
        ),
        Some(DribbleMoveKind::CarryOutRight) => (
            dir_at(-32.0),
            false,
            false,
            CARRY_ORBIT_POSSESSION_SOFT_CAP_RAD,
            CARRY_ORBIT_NORMAL_RATE_RAD_S,
        ),
        Some(DribbleMoveKind::LeftCut) => (
            dir_at(78.0),
            true,
            false,
            CARRY_ORBIT_POSSESSION_SOFT_CAP_RAD,
            CARRY_ORBIT_SPECIAL_RATE_RAD_S,
        ),
        Some(DribbleMoveKind::RightCut) => (
            dir_at(-78.0),
            true,
            false,
            CARRY_ORBIT_POSSESSION_SOFT_CAP_RAD,
            CARRY_ORBIT_SPECIAL_RATE_RAD_S,
        ),
        Some(DribbleMoveKind::FakeLeftCutRight) => (
            dir_at(-72.0),
            true,
            false,
            CARRY_ORBIT_POSSESSION_SOFT_CAP_RAD,
            CARRY_ORBIT_SPECIAL_RATE_RAD_S,
        ),
        Some(DribbleMoveKind::FakeRightCutLeft) => (
            dir_at(72.0),
            true,
            false,
            CARRY_ORBIT_POSSESSION_SOFT_CAP_RAD,
            CARRY_ORBIT_SPECIAL_RATE_RAD_S,
        ),
        // A nutmeg pushes the ball straight through the gap — close and through.
        Some(DribbleMoveKind::Nutmeg) => (
            dir_at(0.0),
            true,
            false,
            CARRY_ORBIT_POSSESSION_SOFT_CAP_RAD,
            CARRY_ORBIT_SPECIAL_RATE_RAD_S,
        ),
        // SHIELD: protecting the ball means keeping it on the FAR side of the body from the
        // nearest defender — the carrier's body is the barrier between defender and ball,
        // which is what `carrier_shields_ball_from_defender` rewards with a near-zero steal.
        // Aim the ball directly away from that defender (tight, close control). With no
        // defender to shield from, fall back to keeping it ahead of the body.
        Some(DribbleMoveKind::ProtectBall) => {
            let shield_dir = shield_dir.unwrap_or_else(|| dir_at(0.0));
            (
                shield_dir,
                false,
                false,
                CARRY_ORBIT_POSSESSION_SOFT_CAP_RAD,
                CARRY_ORBIT_NORMAL_RATE_RAD_S,
            )
        }
        // XAVI TURN: like the shield, the ball is held on the FAR side of the defender —
        // but swept a touch faster so it tracks the body as the carrier wheels ~290° the
        // long way around. It arcs AROUND the body (never through, the `true` long-orbit
        // flag), capped at the 300° max orbit, and the long protective path emerges as the
        // carrier's pivot keeps rotating the shield bearing.
        Some(DribbleMoveKind::XaviTurn) => (
            xavi_turn_dir(),
            false,
            true,
            XAVI_TURN_MAX_ORBIT_RAD,
            CARRY_ORBIT_XAVI_RATE_RAD_S,
        ),
        // Carry-forward, plain hold: keep the ball ahead of the body.
        _ => (
            dir_at(0.0),
            false,
            false,
            CARRY_ORBIT_POSSESSION_SOFT_CAP_RAD,
            CARRY_ORBIT_NORMAL_RATE_RAD_S,
        ),
    };
    let shield_blend = match move_kind {
        Some(DribbleMoveKind::ProtectBall)
        | Some(DribbleMoveKind::XaviTurn)
        | Some(DribbleMoveKind::Nutmeg) => 0.0,
        Some(DribbleMoveKind::LeftCut)
        | Some(DribbleMoveKind::RightCut)
        | Some(DribbleMoveKind::FakeLeftCutRight)
        | Some(DribbleMoveKind::FakeRightCutLeft) => (tightness * 0.86).clamp(0.0, 0.86),
        _ => (tightness * 0.78).clamp(0.0, 0.78),
    };
    let dir = if let Some(shield_dir) = shield_dir {
        let shielded = base_dir * (1.0 - shield_blend) + shield_dir * shield_blend;
        if shielded.len() > 1e-6 {
            shielded.normalized()
        } else {
            base_dir
        }
    } else {
        base_dir
    };
    let radius = if matches!(move_kind, Some(DribbleMoveKind::XaviTurn)) {
        (radius + 0.18 + tightness * 0.12)
            .clamp(CARRY_TIGHT_RADIUS_YARDS, CARRY_MAX_ORBIT_RADIUS_YARDS)
    } else {
        radius
    };
    (
        dir.normalized(),
        radius,
        allow_through,
        prefer_long_orbit,
        winding_cap,
        rate,
    )
}

fn dribble_heavy_touch_probability(player: &PlayerAgent, pressure: f64) -> f64 {
    let control = ability01(player.skills.dribbling) * 0.58
        + ability01(player.skills.first_touch) * 0.30
        + ability01(player.skills.stamina) * 0.12;
    let fatigue_risk = player.fatigue.clamp(0.0, 1.0) * 0.05;
    let pressure = pressure.clamp(0.0, 1.0);
    (0.004 + pressure * (1.0 - control).clamp(0.0, 1.0) * 0.42 + fatigue_risk).clamp(0.004, 0.36)
}

fn pressure_from_observation(observation: &SoccerPomdpObservation) -> f64 {
    soccer_lp_unit(observation.perceived_pressure)
}

fn pressure_from_nearest_distance(nearest_opponent_distance: f64) -> f64 {
    if nearest_opponent_distance.is_finite() {
        (1.0 - nearest_opponent_distance / 18.0).clamp(0.0, 1.0)
    } else {
        0.0
    }
}

fn dribble_comfort_space_yards_for_state(role: PlayerRole, own_half: bool) -> f64 {
    let base = match role {
        PlayerRole::Defender => DEFENDER_DRIBBLE_COMFORT_SPACE_YARDS,
        _ => DRIBBLE_OPPONENT_MIN_SPACE_YARDS,
    };
    if own_half {
        base.max(DRIBBLE_OWN_HALF_MIN_SPACE_YARDS)
    } else {
        base
    }
}

fn dribble_comfort_space_yards_for_role(role: PlayerRole) -> f64 {
    dribble_comfort_space_yards_for_state(role, false)
}

fn dribble_comfort_space_yards_for_position(
    role: PlayerRole,
    team: Team,
    position: Vec2,
    field_length: f64,
) -> f64 {
    dribble_comfort_space_yards_for_state(
        role,
        pass_origin_in_own_half(team, position, field_length),
    )
}

fn dribble_own_half_from_distances(yards_to_goal: f64, yards_to_own_goal: f64) -> bool {
    yards_to_goal.is_finite() && yards_to_own_goal.is_finite() && yards_to_own_goal < yards_to_goal
}

fn dribble_moving_away_relief_from_closing_rate(closing_rate_yps: f64) -> f64 {
    if closing_rate_yps.is_finite() && closing_rate_yps < 0.0 {
        ((-closing_rate_yps) / DRIBBLE_MOVING_AWAY_FULL_RELIEF_YPS).clamp(0.0, 1.0)
            * DRIBBLE_MOVING_AWAY_MAX_RELIEF
    } else {
        0.0
    }
}

fn dribble_spacing_pressure_for_state(
    role: PlayerRole,
    own_half: bool,
    nearest_opponent_distance: f64,
    nearest_opponent_closing_rate_yps: f64,
) -> f64 {
    if nearest_opponent_distance.is_finite() {
        let comfort_space = dribble_comfort_space_yards_for_state(role, own_half);
        let static_pressure = (1.0 - nearest_opponent_distance / comfort_space).clamp(0.0, 1.0);
        let moving_away_relief =
            dribble_moving_away_relief_from_closing_rate(nearest_opponent_closing_rate_yps);
        (static_pressure * (1.0 - moving_away_relief)).clamp(0.0, 1.0)
    } else {
        0.0
    }
}

fn dribble_closing_rate_toward_point(
    source_position: Vec2,
    source_velocity: Vec2,
    point: Vec2,
) -> f64 {
    let to_point = point - source_position;
    if to_point.len() > 1e-6 && source_velocity.x.is_finite() && source_velocity.y.is_finite() {
        source_velocity.dot(to_point.normalized())
    } else {
        0.0
    }
}

fn dribble_comfort_adjusted_gap(
    gap_yards: f64,
    closing_rate_yps: f64,
    comfort_space_yards: f64,
) -> f64 {
    if gap_yards.is_finite() {
        gap_yards
            + dribble_moving_away_relief_from_closing_rate(closing_rate_yps) * comfort_space_yards
    } else {
        f64::INFINITY
    }
}

fn dribble_comfort_path_margin_yards(
    clearance_yards: f64,
    role: PlayerRole,
    team: Team,
    current: Vec2,
    target: Vec2,
    field_length: f64,
) -> f64 {
    let comfort_space =
        dribble_comfort_space_yards_for_position(role, team, current, field_length).max(
            dribble_comfort_space_yards_for_position(role, team, target, field_length),
        );
    if clearance_yards.is_finite() {
        clearance_yards - comfort_space
    } else {
        8.0
    }
}

fn dribble_spacing_pressure_for_role(role: PlayerRole, nearest_opponent_distance: f64) -> f64 {
    if nearest_opponent_distance.is_finite() {
        (1.0 - nearest_opponent_distance / dribble_comfort_space_yards_for_role(role))
            .clamp(0.0, 1.0)
    } else {
        0.0
    }
}

fn perceived_pressure_for_player(
    player: &PlayerSnapshot,
    real_pressure: f64,
    visible_opponents: usize,
) -> f64 {
    let vision_relief = (ability01(player.skills.vision) - 0.55).clamp(-0.25, 0.35) * 0.22;
    let crowding = (visible_opponents as f64 / 8.0).clamp(0.0, 1.0) * 0.12;
    (real_pressure + crowding - vision_relief).clamp(0.0, 1.0)
}

fn time_on_ball_seconds(pressure: f64) -> f64 {
    (2.8 - pressure.clamp(0.0, 1.0) * 2.35).clamp(0.25, 3.0)
}

/// Granular pressure in [0, 1] built from the nearest opponent's LOCATION (proximity),
/// VELOCITY (closing rate) and ACCELERATION (closing accel) — a disambiguated pressure,
/// not just static distance. A man 8yd off sprinting and still accelerating reads much
/// higher than one 8yd off jogging or already braking. The dynamic terms are gated by
/// proximity so a distant burst doesn't spike it. Drives run-vs-sprint pace decisions.
fn granular_pressure_signal(observation: &SoccerPomdpObservation) -> f64 {
    let proximity = pressure_from_nearest_distance(observation.nearest_opponent_distance);
    let closing = (observation
        .neural_extended
        .nearest_opponent_closing_rate_yps
        / PRESSURE_RISING_REF_CLOSING_YPS)
        .clamp(0.0, 1.0);
    let accel = (observation
        .neural_extended
        .nearest_opponent_closing_accel_yps2
        / GRANULAR_PRESSURE_REF_ACCEL_YPS2)
        .clamp(-1.0, 1.0);
    let engage = (1.0 - observation.nearest_opponent_distance / PRESSURE_RISING_ENGAGE_YARDS)
        .clamp(0.0, 1.0);
    return (proximity + engage * (closing * 0.45 + accel * 0.20)).clamp(0.0, 1.0);
}

/// Rate-of-change of pressure: how fast the nearest opponent is closing the holder
/// down, normalised to [0, 1] -- the "pressure is increasing per unit time"
/// (d(pressure)/dt) signal the holder reacts to *before* the gap is already tiny.
/// A defender sprinting in raises urgency to release the ball sooner and to body-
/// shield, even while the current static pressure still reads moderate. Gated by
/// proximity so a distant chaser does not spike it.
fn pressure_rising_signal(observation: &SoccerPomdpObservation) -> f64 {
    let closing = observation
        .neural_extended
        .nearest_opponent_closing_rate_yps
        .max(0.0);
    if closing <= 0.0 {
        return 0.0;
    }
    let closing01 = (closing / PRESSURE_RISING_REF_CLOSING_YPS).clamp(0.0, 1.0);
    let proximity = (1.0 - observation.nearest_opponent_distance / PRESSURE_RISING_ENGAGE_YARDS)
        .clamp(0.0, 1.0);
    return (closing01 * proximity).clamp(0.0, 1.0);
}

/// Positional "take-a-man-on" appetite from forward rank. `teammates_ahead` counts
/// outfield team-mates closer to the opponent goal, so 0..=2 are the three most-forward
/// players on the team — the only ones for whom dribbling INTO pressure should be
/// worthwhile. The appetite fades from rank 1 (none ahead) to rank 3 and is zero for
/// anyone deeper, who should move the ball rather than carry it into the tackle. Single
/// source of truth so the live policy and the learning-reward shaping cannot drift apart.
pub(crate) fn advanced_dribbler_fit_from_rank(teammates_ahead: usize) -> f64 {
    match teammates_ahead {
        0 => 1.0,
        1 => 0.74,
        2 => 0.48,
        _ => 0.0,
    }
}

fn dribble_hold_base_seconds(dribbling: f64) -> f64 {
    let dribbling = dribbling.clamp(0.0, 1.0);
    let elite_hold_start = 0.86;
    let elite_fit = ((dribbling - elite_hold_start)
        / (NON_ELITE_DRIBBLE_HOLD_SKILL_CUTOFF - elite_hold_start))
        .clamp(0.0, 1.0);
    NON_ELITE_DRIBBLE_HOLD_BASE_SECONDS
        + (ELITE_DRIBBLE_HOLD_BASE_SECONDS - NON_ELITE_DRIBBLE_HOLD_BASE_SECONDS) * elite_fit
}

fn excessive_hold_pressure_from_parts(
    actual_time_on_ball_seconds: f64,
    pressure_urgency: f64,
    defensive_urgency: f64,
    perceived_pressure: f64,
    immediate_dispossession_risk: f64,
    dribbling: f64,
    pressure_rising: f64,
) -> f64 {
    let actual_hold = actual_time_on_ball_seconds.max(0.0);
    if actual_hold <= 0.0 {
        return 0.0;
    }
    let urgency = pressure_urgency
        .max(defensive_urgency)
        .max(perceived_pressure)
        .clamp(0.0, 1.0);
    // The comfortable on-ball window shrinks ADDITIVELY with pressure (each signal trims
    // absolute seconds). Additive — not multiplicative — so an ELITE carrier's much
    // longer base hold survives the same pressure (they keep more time than a journeyman),
    // and a slightly stronger urgency coefficient than before means MEDIUM pressure
    // already trims the window so the release comes sooner. A soft floor keeps it sane
    // without being the behavioural cliff (the anticipatory smoothstep below is what
    // removes the cliff).
    let base = dribble_hold_base_seconds(dribbling);
    let comfortable = (base
        - urgency * 1.7
        - immediate_dispossession_risk.clamp(0.0, 1.0) * 1.1
        - pressure_rising.clamp(0.0, 1.0) * 1.4)
        .max(EXCESSIVE_HOLD_SOFT_FLOOR_SECONDS);
    // SMOOTH ramp (smoothstep, no kink): once the comfortable window is reached the urge
    // to release rises gently — slowly at first (smoothstep's soft onset gives the
    // anticipatory feel) then building over SPAN — instead of snapping on at a hard
    // threshold. With `comfortable` itself shrinking as pressure mounts, the release urge
    // arrives SOONER and more SMOOTHLY under medium-and-up pressure, so the carrier moves
    // the ball on a good option rather than dwelling to a cliff and forcing a panic pass.
    smoothstep_unit((actual_hold - comfortable) / EXCESSIVE_HOLD_RAMP_SPAN_SECONDS)
}

fn slow_holder_ideal_forward_pass_pressure(observation: &SoccerPomdpObservation) -> f64 {
    if !observation.has_ball || observation.visible_forward_pass_options == 0 {
        return 0.0;
    }
    let forward_yards = if observation
        .nearest_forward_teammate_forward_yards
        .is_finite()
        && observation.nearest_forward_teammate_forward_yards > 0.0
    {
        observation.nearest_forward_teammate_forward_yards
    } else {
        observation.nearest_forward_teammate_distance_yards
    };
    if !forward_yards.is_finite() || forward_yards <= 0.0 {
        return 0.0;
    }
    let distance_fit = if forward_yards < SLOW_HOLDER_RELEASE_PASS_MIN_YARDS {
        (forward_yards / SLOW_HOLDER_RELEASE_PASS_MIN_YARDS).clamp(0.0, 1.0) * 0.82
    } else if forward_yards <= SLOW_HOLDER_RELEASE_PASS_IDEAL_MAX_YARDS {
        1.0
    } else {
        (1.0 - (forward_yards - SLOW_HOLDER_RELEASE_PASS_IDEAL_MAX_YARDS)
            / SLOW_HOLDER_RELEASE_PASS_TAPER_YARDS)
            .clamp(0.0, 1.0)
    };
    if distance_fit <= 0.0 {
        return 0.0;
    }
    let option_quality = observation
        .quick_forward_pass_value
        .clamp(0.0, 1.0)
        .max(observation.best_forward_pass_option_quality.clamp(0.0, 1.0))
        .max(
            observation
                .best_forward_pass_receiver_openness
                .clamp(0.0, 1.0),
        )
        .max(observation.expected_pass_completion.clamp(0.0, 1.0) * 0.90)
        .max(observation.floor_pass_lane_score.clamp(0.0, 1.0) * 0.84);
    if option_quality < SLOW_HOLDER_RELEASE_MIN_OPTION_QUALITY {
        return 0.0;
    }
    let gait_slow_fit: f64 = match observation.movement_gait {
        MovementGait::Stand => 1.0,
        MovementGait::Walk | MovementGait::BackWalk => 0.82,
        _ => 0.0,
    };
    let speed_slow_fit =
        (1.0 - observation.actor_speed_yps / SLOW_HOLDER_RELEASE_MAX_SPEED_YPS).clamp(0.0, 1.0);
    let forward_progress_relief = (observation.ball_forward_velocity_yps.max(0.0)
        / SLOW_HOLDER_FORWARD_PROGRESS_RELIEF_YPS)
        .clamp(0.0, 1.0);
    let slow_static_fit = gait_slow_fit.max(speed_slow_fit) * (1.0 - forward_progress_relief);
    if slow_static_fit <= 0.0 {
        return 0.0;
    }
    let hold_seconds = observation
        .actual_time_on_ball_seconds
        .max(observation.perceived_time_on_ball_seconds)
        .max(0.0);
    let dwell_fit = smoothstep_unit(
        (hold_seconds - SLOW_HOLDER_RELEASE_START_SECONDS)
            / (SLOW_HOLDER_RELEASE_FULL_SECONDS - SLOW_HOLDER_RELEASE_START_SECONDS).max(1e-6),
    );
    (slow_static_fit * dwell_fit * distance_fit * option_quality).clamp(0.0, 1.0)
}

fn excessive_hold_pressure(observation: &SoccerPomdpObservation, dribbling: f64) -> f64 {
    // Fold rising pressure (a fast-closing defender) into the urgency so the allowed
    // hold window shrinks as the defender bears down — release before it's too late
    // instead of dwelling and being forced into a desperate pass.
    let closing_fit = (observation
        .neural_extended
        .nearest_opponent_closing_rate_yps
        / RISING_PRESSURE_CLOSING_RATE_YPS)
        .clamp(0.0, 1.0);
    let pressure_hold = excessive_hold_pressure_from_parts(
        observation.actual_time_on_ball_seconds,
        observation.pressure_urgency.max(closing_fit),
        observation.defensive_urgency,
        observation.perceived_pressure,
        observation.immediate_dispossession_risk,
        dribbling,
        pressure_rising_signal(observation),
    );
    pressure_hold.max(slow_holder_ideal_forward_pass_pressure(observation))
}

fn stale_dribble_release_option_quality(observation: &SoccerPomdpObservation) -> f64 {
    let floor_quality = observation
        .best_forward_pass_option_quality
        .max(observation.best_forward_pass_receiver_openness)
        .max(observation.best_pass_receiver_openness)
        .max(observation.expected_pass_completion * 0.88);
    let aerial_quality = observation
        .best_aerial_pass_receiver_openness
        .max(observation.expected_aerial_pass_completion * 0.72)
        .max(observation.aerial_pass_bypass_score * 0.66);
    let support_quality = (observation.open_support_outlets as f64 / 3.0)
        .clamp(0.0, 1.0)
        .max((observation.visible_pass_options as f64 / 4.0).clamp(0.0, 1.0) * 0.72);
    floor_quality
        .max(aerial_quality)
        .max(support_quality)
        .clamp(0.0, 1.0)
}

fn stale_dribble_pressure_context(observation: &SoccerPomdpObservation) -> f64 {
    observation
        .pressure_urgency
        .max(observation.perceived_pressure)
        .max(observation.immediate_dispossession_risk)
        .max(
            observation
                .neural_extended
                .surprise_behind_steal_escape_pressure,
        )
        .clamp(0.0, 1.0)
}

fn stale_dribble_steal_risk(observation: &SoccerPomdpObservation, dribbling: f64) -> f64 {
    if !observation.has_ball {
        return 0.0;
    }
    let hold_pressure = observation
        .excessive_hold_pressure
        .max(excessive_hold_pressure(observation, dribbling))
        .clamp(0.0, 1.0);
    if hold_pressure <= 0.0 {
        return 0.0;
    }
    let danger_pressure = stale_dribble_pressure_context(observation);
    let release_quality = stale_dribble_release_option_quality(observation);
    let outlet_blame = 0.58 + release_quality * 0.42;
    (hold_pressure * (0.36 + danger_pressure * 0.64) * outlet_blame).clamp(0.0, 1.0)
}

fn stale_dribble_steal_turnover_penalty_points(transition: &SoccerLearningTransition) -> f64 {
    if !is_dribble_action_label(normalize_soccer_action_label(&transition.action)) {
        return 0.0;
    }
    let observation = &transition.observation;
    let risk = observation
        .stale_dribble_steal_risk
        .max(stale_dribble_steal_risk(
            observation,
            ability01(observation.skill_dribbling),
        ));
    if risk < 0.08 {
        return 0.0;
    }
    let release_quality = observation
        .stale_dribble_release_quality
        .max(stale_dribble_release_option_quality(observation));
    let pressure_context = observation
        .stale_dribble_pressure_context
        .max(stale_dribble_pressure_context(observation));
    let position_multiplier = match observation.teammates_ahead {
        0 | 1 => 0.90,
        2 => 1.05,
        _ => 1.24,
    };
    STALE_DRIBBLE_STEAL_EXTRA_PENALTY_POINTS
        * risk.clamp(0.0, 1.0)
        * (0.72 + pressure_context.clamp(0.0, 1.0) * 0.28)
        * (0.82 + release_quality.clamp(0.0, 1.0) * 0.34)
        * position_multiplier
}

fn dribble_hold_score_multiplier(observation: &SoccerPomdpObservation, dribbling: f64) -> f64 {
    let hold_pressure = excessive_hold_pressure(observation, dribbling);
    if hold_pressure <= 0.0 {
        return 1.0;
    }
    let slow_release_pressure = slow_holder_ideal_forward_pass_pressure(observation);
    let non_elite_fit =
        ((NON_ELITE_DRIBBLE_HOLD_SKILL_CUTOFF - dribbling.clamp(0.0, 1.0)) / 0.34).clamp(0.0, 1.0);
    let pressure_fit = observation
        .pressure_urgency
        .max(observation.perceived_pressure)
        .max(observation.immediate_dispossession_risk)
        .clamp(0.0, 1.0);
    let penalty_scale = 1.0 + slow_release_pressure * (SLOW_HOLDER_HOLD_PENALTY_MULTIPLIER - 1.0);
    (1.0 - hold_pressure * (0.38 + non_elite_fit * 0.86 + pressure_fit * 0.36) * penalty_scale)
        .clamp(
            if slow_release_pressure > 0.0 {
                if dribbling >= NON_ELITE_DRIBBLE_HOLD_SKILL_CUTOFF {
                    0.18
                } else {
                    0.03
                }
            } else if dribbling >= NON_ELITE_DRIBBLE_HOLD_SKILL_CUTOFF {
                0.66
            } else {
                0.06
            },
            1.0,
        )
}

fn release_after_hold_multiplier(observation: &SoccerPomdpObservation, dribbling: f64) -> f64 {
    let hold_pressure = excessive_hold_pressure(observation, dribbling);
    if hold_pressure <= 0.0 {
        return 1.0;
    }
    let slow_release_pressure = slow_holder_ideal_forward_pass_pressure(observation);
    let non_elite_fit =
        ((NON_ELITE_DRIBBLE_HOLD_SKILL_CUTOFF - dribbling.clamp(0.0, 1.0)) / 0.34).clamp(0.0, 1.0);
    let urgency_fit = observation
        .pressure_urgency
        .max(observation.defensive_urgency)
        .max(observation.immediate_dispossession_risk)
        .clamp(0.0, 1.0);
    (1.0 + hold_pressure * (0.58 + non_elite_fit * 0.86 + urgency_fit * 0.68)
        + slow_release_pressure
            * (1.05 + observation.quick_forward_pass_value.clamp(0.0, 1.0) * 0.55))
        .clamp(1.0, 4.20)
}

fn excessive_hold_penalty_points(observation: &SoccerPomdpObservation, dribbling: f64) -> f64 {
    let hold_pressure = excessive_hold_pressure(observation, dribbling);
    if hold_pressure <= 0.0 {
        return 0.0;
    }
    let non_elite_fit =
        ((NON_ELITE_DRIBBLE_HOLD_SKILL_CUTOFF - dribbling.clamp(0.0, 1.0)) / 0.34).clamp(0.0, 1.0);
    let urgency_fit = observation
        .pressure_urgency
        .max(observation.defensive_urgency)
        .max(observation.immediate_dispossession_risk)
        .clamp(0.0, 1.0);
    // Holding under pressure is penalized increasingly as pressure rises — but
    // that escalation is gated by `non_elite_fit`, so an elite dribbler (9-10/10)
    // stays exempt from the pressure-scaling and only carries the small base.
    (EXCESSIVE_HOLD_PENALTY_POINTS
        * hold_pressure
        * (0.35 + non_elite_fit * (0.52 + urgency_fit * 0.55)))
        .clamp(0.0, EXCESSIVE_HOLD_PENALTY_POINTS * 1.6)
}

fn pressured_stale_dribble_learning_penalty_points(
    observation: &SoccerPomdpObservation,
    dribbling: f64,
    ball_forward_yards: f64,
    player_forward_yards: f64,
    retained_team_possession: bool,
) -> f64 {
    let hold_pressure = excessive_hold_pressure(observation, dribbling);
    let danger_pressure = observation
        .pressure_urgency
        .max(observation.perceived_pressure)
        .max(observation.immediate_dispossession_risk)
        .clamp(0.0, 1.0);
    if hold_pressure < 0.12 || danger_pressure < 0.38 {
        return 0.0;
    }

    let progress = ball_forward_yards.max(player_forward_yards);
    let progress_relief = (progress / 7.0).clamp(0.0, 1.0);
    if dribbling >= NON_ELITE_DRIBBLE_HOLD_SKILL_CUTOFF
        && (hold_pressure < 0.70 || progress_relief >= 0.35)
    {
        return 0.0;
    }

    let non_elite_fit =
        ((NON_ELITE_DRIBBLE_HOLD_SKILL_CUTOFF - dribbling.clamp(0.0, 1.0)) / 0.34).clamp(0.0, 1.0);
    let skill_multiplier = if dribbling >= NON_ELITE_DRIBBLE_HOLD_SKILL_CUTOFF {
        0.18
    } else {
        0.42 + non_elite_fit * 0.72
    };
    let possession_multiplier = if retained_team_possession { 0.78 } else { 1.12 };
    // A deep carrier (not one of the three most-forward outfielders) who keeps dribbling
    // under sustained pressure is penalized HARDER — they should release sooner the longer
    // the pressure persists. The most-forward players keep the baseline discipline (no
    // reduction: even a striker shouldn't dwell while about to be dispossessed); only
    // deeper players get the escalating extra weight. `teammates_ahead` counts team-mates
    // closer to goal, so 0..=2 are the three most-forward players.
    let position_multiplier = match observation.teammates_ahead {
        0 | 1 => 1.0,
        2 => 1.10,
        _ => 1.30,
    };
    (EXCESSIVE_HOLD_PENALTY_POINTS
        * hold_pressure
        * (0.44 + danger_pressure * 0.56)
        * skill_multiplier
        * possession_multiplier
        * position_multiplier
        * (1.0 - progress_relief * 0.74).clamp(0.20, 1.0))
    .clamp(0.0, EXCESSIVE_HOLD_PENALTY_POINTS * 1.6)
}

fn immediate_dispossession_risk_for_player(
    player: &PlayerSnapshot,
    nearest_opponent_distance: f64,
    perceived_pressure: f64,
    perceived_time_on_ball_seconds: f64,
) -> f64 {
    let close_risk =
        (1.0 - (nearest_opponent_distance - PLAYER_CONTROL_RADIUS_YARDS) / 4.4).clamp(0.0, 1.0);
    let control_skill = ability01(player.skills.dribbling) * 0.52
        + ability01(player.skills.first_touch) * 0.30
        + ability01(player.skills.strength) * 0.18;
    let skill_risk = (1.0 - control_skill).clamp(0.0, 1.0);
    let clock_risk = (1.0 - perceived_time_on_ball_seconds / 2.8).clamp(0.0, 1.0);
    (perceived_pressure.clamp(0.0, 1.0) * 0.42
        + close_risk * 0.32
        + clock_risk * 0.16
        + skill_risk * 0.16
        + player.fatigue.clamp(0.0, 1.0) * 0.10)
        .clamp(0.0, 1.0)
}

fn goal_attack_window_score_for_role(
    role: PlayerRole,
    has_ball: bool,
    yards_to_goal: f64,
    shot_lane_open: bool,
    shot_block_probability: f64,
    shot_on_frame_probability: f64,
    shot_beat_goalkeeper_probability: f64,
    opponent_goal_angle_degrees: f64,
    forward_dribble_space_yards: f64,
    facing_goal_score: f64,
) -> f64 {
    if !has_ball || role == PlayerRole::Goalkeeper || yards_to_goal <= 0.0 {
        return 0.0;
    }
    let window_yards = match role {
        PlayerRole::Forward => ATTACKING_DRIBBLE_GOAL_DRIVE_YARDS,
        PlayerRole::Midfielder => TEAMMATE_MUST_SHOOT_YARDS + 6.0,
        PlayerRole::Defender => TEAMMATE_MUST_SHOOT_YARDS + 3.0,
        PlayerRole::Goalkeeper => return 0.0,
    }
    .min(SPECULATIVE_LONG_SHOT_MAX_YARDS);
    if yards_to_goal > window_yards {
        return 0.0;
    }

    let mut distance_fit = ((window_yards - yards_to_goal) / window_yards).clamp(0.0, 1.0);
    if yards_to_goal > LONG_SHOT_DISCOURAGED_YARDS {
        distance_fit *= 0.45;
    }
    if role == PlayerRole::Forward
        && yards_to_goal
            <= tunables()
                .shooting
                .striker_shot_window_yards
                .min(SPECULATIVE_LONG_SHOT_MAX_YARDS)
    {
        distance_fit = distance_fit.max(0.30);
    }
    if yards_to_goal <= TEAMMATE_MUST_SHOOT_YARDS {
        distance_fit = distance_fit.max(0.48);
    }

    let block_fit = (1.0 - shot_block_probability.clamp(0.0, 1.0)).clamp(0.0, 1.0);
    let shot_fit = (shot_on_frame_probability.clamp(0.0, 1.0) * 0.36
        + shot_beat_goalkeeper_probability.clamp(0.0, 1.0) * 0.28
        + block_fit * 0.24
        + (opponent_goal_angle_degrees / 42.0).clamp(0.0, 1.0) * 0.12)
        .clamp(0.0, 1.0);
    let carry_space_fit = (forward_dribble_space_yards / 12.0).clamp(0.0, 1.0);
    let lane_fit = if shot_lane_open {
        0.50 + shot_fit * 0.32
    } else {
        carry_space_fit * 0.38 + block_fit * 0.10
    };
    let role_fit = match role {
        PlayerRole::Forward => 1.14,
        PlayerRole::Midfielder => 0.94,
        PlayerRole::Defender => 0.64,
        PlayerRole::Goalkeeper => 0.0,
    };

    (distance_fit
        * (0.22 + lane_fit + carry_space_fit * 0.16 + facing_goal_score.clamp(0.0, 1.0) * 0.16)
        * role_fit)
        .clamp(0.0, 1.0)
}

/// HARD distance gate for a shot, merging the two shot-discipline philosophies. Both agree the
/// 30yd ceiling (`SPECULATIVE_LONG_SHOT_MAX_YARDS`) is absolute. Inside it:
/// - up to the keeper-dependent range (`LONG_SHOT_KEEPER_DEPENDENT_YARDS`, ~26yd) the shot stays
///   LEGAL — the user's item-5 spec is to PENALISE shots beyond ~20yd, not forbid them (the
///   discouragement, and its relief when the keeper is out of position, live in the decision-time
///   reward shaping), so a clear ~22-26yd effort is still a legal option;
/// - a genuinely speculative 26-30yd effort (origin/alex-1's MARL gate) is legal only with the
///   keeper clearly out of position.
fn long_shot_distance_is_allowed(observation: &SoccerPomdpObservation) -> bool {
    let distance = observation.yards_to_goal;
    if distance <= LONG_SHOT_KEEPER_DEPENDENT_YARDS {
        return true;
    }
    if distance > SPECULATIVE_LONG_SHOT_MAX_YARDS {
        return false;
    }
    observation
        .opposing_goalkeeper_out_of_position
        .clamp(0.0, 1.0)
        >= LONG_SHOT_GK_TOTALLY_OUT
}

/// Keeper-dependent discipline for whether the AI should VOLUNTEER a speculative long shot (vs the
/// basic legality in `long_shot_distance_is_allowed`). This is the stricter of the two and is NOT
/// about legality: a ~20-30yd shot stays legal (so a forced/human shot is never blocked), but the
/// long-shot heuristic only offers one when the keeper is sufficiently off his line — beyond the
/// `LONG_SHOT_KEEPER_DEPENDENT_YARDS` (~26yd) range that means CLEARLY stranded
/// (`LONG_SHOT_GK_TOTALLY_OUT`), and in the ~20-26yd band merely off position
/// (`LONG_SHOT_GK_OUT_OF_POSITION`). Nothing inside ~20yd is gated; nothing beyond 30yd qualifies.
fn speculative_long_shot_keeper_gate(observation: &SoccerPomdpObservation) -> bool {
    let distance = observation.yards_to_goal;
    if distance <= LONG_SHOT_DISCOURAGED_YARDS {
        return true;
    }
    if distance > SPECULATIVE_LONG_SHOT_MAX_YARDS {
        return false;
    }
    let keeper_out = observation
        .opposing_goalkeeper_out_of_position
        .clamp(0.0, 1.0);
    if distance > LONG_SHOT_KEEPER_DEPENDENT_YARDS {
        keeper_out >= LONG_SHOT_GK_TOTALLY_OUT
    } else {
        keeper_out >= LONG_SHOT_GK_OUT_OF_POSITION
    }
}

fn shot_decision_is_qualified(observation: &SoccerPomdpObservation) -> bool {
    if !observation.shot_lane_open || observation.yards_to_goal > SPECULATIVE_LONG_SHOT_MAX_YARDS {
        return false;
    }
    if !long_shot_distance_is_allowed(observation) {
        return false;
    }
    let block_risk = observation.shot_block_probability.clamp(0.0, 1.0);
    let quality_shot = block_risk <= SHOT_BLOCK_DECISION_MAX_PROBABILITY
        && observation.shot_on_frame_probability
            >= tunables().shooting.shot_on_frame_min_probability
        && observation.shot_beat_goalkeeper_probability >= SHOT_KEEPER_BEAT_MIN_PROBABILITY;
    let pressure_bailout = block_risk <= tunables().shooting.shot_block_bailout_max_probability
        && observation.yards_to_goal <= SHOT_BAILOUT_NEAR_GOAL_YARDS
        && observation.immediate_dispossession_risk >= SHOT_BAILOUT_DISPOSSESSION_RISK
        && observation.shot_on_frame_probability >= SHOT_BAILOUT_ON_FRAME_PROBABILITY;
    let goal_urgency_bailout = observation.offensive_urgency >= 0.58
        && block_risk <= 0.62
        && observation.shot_on_frame_probability >= 0.18
        && observation.shot_beat_goalkeeper_probability >= 0.12;
    quality_shot || pressure_bailout || goal_urgency_bailout
}

fn shot_decision_is_qualified_for_role(
    observation: &SoccerPomdpObservation,
    role: PlayerRole,
) -> bool {
    // Hard 30yd ceiling only (item-5: >30yd is never a shot). The keeper-dependent 26-30yd
    // discipline is NOT applied as a blanket role gate — that would also forbid a STRIKER from
    // attempting inside his shot window (legal but reward-penalised), which main / item-5 allow.
    // Each branch below carries its own discipline: the generic `shot_decision_is_qualified` stays
    // keeper-dependent, while `striker_shot_window_is_qualified` lets a forward shoot up to 30yd.
    if observation.yards_to_goal > SPECULATIVE_LONG_SHOT_MAX_YARDS {
        return false;
    }
    shot_decision_is_qualified(observation)
        || attacking_goal_pressure_shot_is_qualified(observation, role)
        || clean_twenty_yard_shot_is_qualified(observation, role)
        || teammate_near_goal_shot_is_qualified(observation, role)
        || striker_shot_window_is_qualified(observation, role)
}

fn attacking_goal_pressure_shot_is_qualified(
    observation: &SoccerPomdpObservation,
    role: PlayerRole,
) -> bool {
    if role == PlayerRole::Goalkeeper
        || !observation.shot_lane_open
        || !long_shot_distance_is_allowed(observation)
    {
        return false;
    }
    observation.yards_to_goal <= ATTACKING_GOAL_PRESSURE_SHOT_YARDS
        && observation.shot_block_probability.clamp(0.0, 1.0) <= SHOT_BLOCK_DECISION_MAX_PROBABILITY
        && observation.shot_on_frame_probability >= STRIKER_SHOT_MIN_ON_FRAME_PROBABILITY
        && observation.shot_beat_goalkeeper_probability >= STRIKER_SHOT_MIN_KEEPER_BEAT_PROBABILITY
        && observation.opponent_goal_angle_degrees >= 8.0
}

fn attacking_goal_pressure_shot_attempt_probability(
    observation: &SoccerPomdpObservation,
    role: PlayerRole,
    shooting_skill: f64,
) -> f64 {
    if !attacking_goal_pressure_shot_is_qualified(observation, role) {
        return 0.0;
    }
    let range_fit = ((ATTACKING_GOAL_PRESSURE_SHOT_YARDS - observation.yards_to_goal)
        / (ATTACKING_GOAL_PRESSURE_SHOT_YARDS - TEAMMATE_MUST_SHOOT_YARDS).max(1e-6))
    .clamp(0.0, 1.0);
    let role_bonus = match role {
        PlayerRole::Forward => 0.18,
        PlayerRole::Midfielder => 0.11,
        PlayerRole::Defender => 0.04,
        PlayerRole::Goalkeeper => 0.0,
    };
    (0.10
        + role_bonus
        + shooting_skill.clamp(0.0, 1.0) * 0.10
        + range_fit * 0.22
        + observation.offensive_urgency.clamp(0.0, 1.0) * 0.12
        + observation.goal_attack_window_score.clamp(0.0, 1.0) * 0.08
        + observation.shot_on_frame_probability.clamp(0.0, 1.0) * 0.08)
        .clamp(0.0, 0.66)
}

fn speculative_long_shot_is_qualified(
    observation: &SoccerPomdpObservation,
    role: PlayerRole,
    shooting_skill: f64,
) -> bool {
    if role == PlayerRole::Goalkeeper || !observation.shot_lane_open {
        return false;
    }
    let distance = observation.yards_to_goal;
    if !(TEAMMATE_MUST_SHOOT_YARDS..=SPECULATIVE_LONG_SHOT_MAX_YARDS).contains(&distance) {
        return false;
    }
    // Distance discipline: 20+ yds is discouraged and keeper-dependent (20-26 yds needs the
    // keeper off position, 26-30 yds needs him stranded), and >30 yds is blocked by the range
    // guard above. This is the AI's "should I volunteer a speculative long shot" gate, stricter
    // than the basic `long_shot_distance_is_allowed` legality (a forced/human shot stays legal).
    if !speculative_long_shot_keeper_gate(observation) {
        return false;
    }
    if observation.shot_block_probability.clamp(0.0, 1.0)
        > SPECULATIVE_LONG_SHOT_MAX_BLOCK_PROBABILITY
    {
        return false;
    }
    if observation.shot_on_frame_probability < SPECULATIVE_LONG_SHOT_MIN_ON_FRAME_PROBABILITY {
        return false;
    }
    let urgency = observation
        .offensive_urgency
        .max(observation.decision_urgency)
        .max(observation.pressure_urgency * 0.72)
        .clamp(0.0, 1.0);
    let role_floor = match role {
        PlayerRole::Forward => 0.06,
        PlayerRole::Midfielder => 0.03,
        PlayerRole::Defender | PlayerRole::Goalkeeper => 0.0,
    };
    return shooting_skill >= SPECULATIVE_LONG_SHOT_SKILL_GATE
        || urgency >= 0.48
        || observation.goal_attack_window_score >= 0.18
        || role_floor > 0.0 && observation.offensive_urgency >= 0.36;
}

fn speculative_long_shot_attempt_probability(
    observation: &SoccerPomdpObservation,
    role: PlayerRole,
    shooting_skill: f64,
) -> f64 {
    if !speculative_long_shot_is_qualified(observation, role, shooting_skill) {
        return 0.0;
    }
    let distance_fit = ((SPECULATIVE_LONG_SHOT_MAX_YARDS - observation.yards_to_goal)
        / (SPECULATIVE_LONG_SHOT_MAX_YARDS - TEAMMATE_MUST_SHOOT_YARDS).max(1e-6))
    .clamp(0.0, 1.0);
    let lane_fit = (1.0
        - observation.shot_block_probability.clamp(0.0, 1.0)
            / SPECULATIVE_LONG_SHOT_MAX_BLOCK_PROBABILITY.max(1e-6))
    .clamp(0.0, 1.0);
    let urgency = observation
        .offensive_urgency
        .max(observation.decision_urgency)
        .max(observation.pressure_urgency * 0.72)
        .clamp(0.0, 1.0);
    let role_bonus = match role {
        PlayerRole::Forward => 0.060,
        PlayerRole::Midfielder => 0.034,
        PlayerRole::Defender => 0.004,
        PlayerRole::Goalkeeper => 0.0,
    };
    // (Long-shot distance discipline — only firing from 25yd+ when the keeper is out of
    // position — is enforced separately via the LONG_SHOT_* distance bands and the
    // `opposing_goalkeeper_out_of_position` signal, not scaled in here.)
    return (0.030
        + role_bonus
        + shooting_skill.clamp(0.0, 1.0) * 0.082
        + urgency * 0.070
        + distance_fit * 0.052
        + lane_fit * 0.042
        + observation.shot_on_frame_probability.clamp(0.0, 1.0) * 0.036)
        .clamp(0.0, 0.34);
}

fn contested_final_third_shot_is_qualified(
    observation: &SoccerPomdpObservation,
    role: PlayerRole,
    shooting_skill: f64,
) -> bool {
    if role == PlayerRole::Goalkeeper
        || !long_shot_distance_is_allowed(observation)
        || observation.yards_to_goal < TEAMMATE_MUST_SHOOT_YARDS
        || observation.opponent_goal_angle_degrees < 10.0
    {
        return false;
    }
    let block_risk = observation.shot_block_probability.clamp(0.0, 1.0);
    if block_risk > 0.74 || observation.shot_on_frame_probability < 0.075 {
        return false;
    }
    let outlet_quality = observation
        .best_forward_pass_receiver_openness
        .max(observation.best_pass_receiver_openness * 0.72)
        .clamp(0.0, 1.0);
    let urgency = observation
        .offensive_urgency
        .max(observation.decision_urgency)
        .max(observation.pressure_urgency * 0.78)
        .clamp(0.0, 1.0);
    let role_floor = match role {
        PlayerRole::Forward => 0.48,
        PlayerRole::Midfielder => 0.58,
        PlayerRole::Defender => 0.76,
        PlayerRole::Goalkeeper => 1.0,
    };
    shooting_skill >= role_floor
        && (urgency >= 0.30
            || observation.goal_attack_window_score >= 0.12
            || outlet_quality <= 0.42
            || observation.visible_forward_pass_options == 0)
}

fn contested_final_third_shot_attempt_probability(
    observation: &SoccerPomdpObservation,
    role: PlayerRole,
    shooting_skill: f64,
) -> f64 {
    if !contested_final_third_shot_is_qualified(observation, role, shooting_skill) {
        return 0.0;
    }
    let distance_fit = ((SPECULATIVE_LONG_SHOT_MAX_YARDS - observation.yards_to_goal)
        / (SPECULATIVE_LONG_SHOT_MAX_YARDS - TEAMMATE_MUST_SHOOT_YARDS).max(1e-6))
    .clamp(0.0, 1.0);
    let block_fit = (1.0 - observation.shot_block_probability.clamp(0.0, 1.0)).clamp(0.0, 1.0);
    let on_frame_fit = (observation.shot_on_frame_probability
        / SPECULATIVE_LONG_SHOT_MIN_ON_FRAME_PROBABILITY)
        .clamp(0.0, 1.25);
    let urgency = observation
        .offensive_urgency
        .max(observation.decision_urgency)
        .max(observation.pressure_urgency * 0.78)
        .clamp(0.0, 1.0);
    let role_floor = match role {
        PlayerRole::Forward => 0.18,
        PlayerRole::Midfielder => 0.12,
        PlayerRole::Defender => 0.04,
        PlayerRole::Goalkeeper => 0.0,
    };
    (role_floor
        + distance_fit * 0.16
        + block_fit * 0.10
        + on_frame_fit * 0.08
        + shooting_skill.clamp(0.0, 1.0) * 0.08
        + urgency * 0.08)
        .clamp(0.0, 0.52)
}

fn goal_proximity_shot_pressure_score(
    observation: &SoccerPomdpObservation,
    role: PlayerRole,
    shooting_skill: f64,
) -> f64 {
    if role == PlayerRole::Goalkeeper
        || !observation.shot_lane_open
        || !long_shot_distance_is_allowed(observation)
    {
        return 0.0;
    }
    let window_yards = match role {
        PlayerRole::Forward => SPECULATIVE_LONG_SHOT_MAX_YARDS,
        PlayerRole::Midfielder => SPECULATIVE_LONG_SHOT_MAX_YARDS - 5.0,
        PlayerRole::Defender => TEAMMATE_MUST_SHOOT_YARDS + 5.0,
        PlayerRole::Goalkeeper => return 0.0,
    };
    if observation.yards_to_goal > window_yards {
        return 0.0;
    }
    let block_risk = observation.shot_block_probability.clamp(0.0, 1.0);
    let lane_fit =
        (1.0 - block_risk / STRIKER_SHOT_MAX_BLOCK_PROBABILITY.max(1e-6)).clamp(0.0, 1.0);
    let distance_fit = ((window_yards - observation.yards_to_goal) / window_yards)
        .clamp(0.0, 1.0)
        .powf(0.72);
    let close_goal_fit = ((GOAL_URGENCY_MAX_YARDS - observation.yards_to_goal)
        / (GOAL_URGENCY_MAX_YARDS - GOAL_URGENCY_KEEPER_CROWD_YARDS).max(1.0))
    .clamp(0.0, 1.0)
    .powf(0.58);
    let quality_fit = (observation.shot_on_frame_probability.clamp(0.0, 1.0) * 0.42
        + observation.shot_beat_goalkeeper_probability.clamp(0.0, 1.0) * 0.24
        + lane_fit * 0.22
        + (observation.opponent_goal_angle_degrees / 42.0).clamp(0.0, 1.0) * 0.12)
        .clamp(0.0, 1.0);
    let role_fit = match role {
        PlayerRole::Forward => 1.12,
        PlayerRole::Midfielder => 0.92,
        PlayerRole::Defender => 0.54,
        PlayerRole::Goalkeeper => 0.0,
    };
    (distance_fit * 0.42
        + quality_fit * 0.24
        + observation.goal_attack_window_score.clamp(0.0, 1.0) * 0.18
        + observation.offensive_urgency.clamp(0.0, 1.0) * 0.10
        + shooting_skill.clamp(0.0, 1.0) * 0.06
        + close_goal_fit * 0.18)
        .mul_add(role_fit, 0.0)
        .clamp(0.0, 1.0)
}

fn goal_proximity_shot_pressure_floor(
    observation: &SoccerPomdpObservation,
    role: PlayerRole,
    shooting_skill: f64,
) -> f64 {
    if role == PlayerRole::Goalkeeper
        || !(shot_decision_is_qualified_for_role(observation, role)
            || speculative_long_shot_is_qualified(observation, role, shooting_skill))
    {
        return 0.0;
    }
    let pressure = goal_proximity_shot_pressure_score(observation, role, shooting_skill);
    if pressure <= 0.0 {
        return 0.0;
    }
    let role_floor = match role {
        PlayerRole::Forward => 0.06,
        PlayerRole::Midfielder => 0.04,
        PlayerRole::Defender => 0.015,
        PlayerRole::Goalkeeper => 0.0,
    };
    (role_floor
        + pressure * 0.34
        + observation.goal_attack_window_score.clamp(0.0, 1.0) * 0.08
        + observation.offensive_urgency.clamp(0.0, 1.0) * 0.04)
        .clamp(0.0, 0.56)
}

fn pressured_shot_release_urgency(
    observation: &SoccerPomdpObservation,
    role: PlayerRole,
    shooting_skill: f64,
) -> f64 {
    if role == PlayerRole::Goalkeeper
        || !observation.shot_lane_open
        || !shot_decision_is_qualified_for_role(observation, role)
    {
        return 0.0;
    }
    let pressure_context = observation
        .pressure_urgency
        .max(observation.decision_urgency)
        .max(observation.immediate_dispossession_risk)
        .max(observation.perceived_pressure)
        .clamp(0.0, 1.0);
    if pressure_context < 0.32 {
        return 0.0;
    }
    let block_risk = observation.shot_block_probability.clamp(0.0, 1.0);
    let max_block_risk = CLEAN_SHOT_MAX_BLOCK_PROBABILITY
        .max(tunables().shooting.shot_block_bailout_max_probability);
    if block_risk > max_block_risk {
        return 0.0;
    }
    let pressure_shot_window =
        (CLEAN_SHOT_MUST_SHOOT_YARDS + 4.0).min(SPECULATIVE_LONG_SHOT_MAX_YARDS);
    if observation.yards_to_goal > pressure_shot_window {
        return 0.0;
    }
    let range_fit = ((pressure_shot_window - observation.yards_to_goal)
        / (pressure_shot_window - TEAMMATE_MUST_SHOOT_YARDS).max(1.0))
    .clamp(0.0, 1.0);
    let lane_fit = (1.0 - block_risk / max_block_risk.max(1e-6)).clamp(0.0, 1.0);
    let quality_fit = (observation.shot_on_frame_probability.clamp(0.0, 1.0) * 0.48
        + observation.shot_beat_goalkeeper_probability.clamp(0.0, 1.0) * 0.30
        + (observation.opponent_goal_angle_degrees / 42.0).clamp(0.0, 1.0) * 0.14
        + lane_fit * 0.18)
        .clamp(0.0, 1.0);
    let role_fit = match role {
        PlayerRole::Forward => 1.10,
        PlayerRole::Midfielder => 0.94,
        PlayerRole::Defender => 0.64,
        PlayerRole::Goalkeeper => 0.0,
    };
    (pressure_context * 0.34
        + range_fit * 0.24
        + quality_fit * 0.26
        + lane_fit * 0.12
        + shooting_skill.clamp(0.0, 1.0) * 0.10)
        .mul_add(role_fit, 0.0)
        .clamp(0.0, 1.0)
}

fn clean_twenty_yard_shot_is_qualified(
    observation: &SoccerPomdpObservation,
    role: PlayerRole,
) -> bool {
    if role == PlayerRole::Goalkeeper || !observation.shot_lane_open {
        return false;
    }
    observation.yards_to_goal <= CLEAN_SHOT_MUST_SHOOT_YARDS
        && observation.shot_block_probability.clamp(0.0, 1.0) <= CLEAN_SHOT_MAX_BLOCK_PROBABILITY
        && observation.shot_on_frame_probability >= CLEAN_SHOT_MIN_ON_FRAME_PROBABILITY
        && observation.shot_beat_goalkeeper_probability >= CLEAN_SHOT_MIN_KEEPER_BEAT_PROBABILITY
        && (observation.forward_dribble_space_yards >= 1.5
            || observation.shot_block_probability <= CLEAN_SHOT_MAX_BLOCK_PROBABILITY * 0.52)
}

fn teammate_near_goal_shot_is_qualified(
    observation: &SoccerPomdpObservation,
    role: PlayerRole,
) -> bool {
    let _ = role;
    let block_risk = observation.shot_block_probability.clamp(0.0, 1.0);
    observation.yards_to_goal <= TEAMMATE_MUST_SHOOT_YARDS
        && observation.shot_lane_open
        && block_risk <= STRIKER_SHOT_MAX_BLOCK_PROBABILITY
        && observation.shot_on_frame_probability >= STRIKER_SHOT_MIN_ON_FRAME_PROBABILITY
        && observation.shot_beat_goalkeeper_probability >= STRIKER_SHOT_MIN_KEEPER_BEAT_PROBABILITY
}

fn striker_shot_window_is_qualified(
    observation: &SoccerPomdpObservation,
    role: PlayerRole,
) -> bool {
    if role != PlayerRole::Forward {
        return false;
    }
    let block_risk = observation.shot_block_probability.clamp(0.0, 1.0);
    let striker_window_yards = tunables()
        .shooting
        .striker_shot_window_yards
        .min(SPECULATIVE_LONG_SHOT_MAX_YARDS);
    // A striker may attempt anywhere inside his shot window up to the hard 30yd cap (already folded
    // into `striker_window_yards`); the 20-30yd range is legal but reward-penalised (item-5), not
    // keeper-gated like a generic speculative shot — a striker backs himself.
    observation.yards_to_goal <= striker_window_yards
        && observation.shot_lane_open
        && block_risk <= STRIKER_SHOT_MAX_BLOCK_PROBABILITY
        && observation.shot_on_frame_probability >= STRIKER_SHOT_MIN_ON_FRAME_PROBABILITY
        && observation.shot_beat_goalkeeper_probability >= STRIKER_SHOT_MIN_KEEPER_BEAT_PROBABILITY
}

fn striker_must_shoot(observation: &SoccerPomdpObservation, role: PlayerRole) -> bool {
    must_shoot_near_goal(observation, role)
}

fn must_shoot_near_goal(observation: &SoccerPomdpObservation, role: PlayerRole) -> bool {
    teammate_near_goal_shot_is_qualified(observation, role)
        || clean_twenty_yard_shot_is_qualified(observation, role)
}

fn goal_attack_shot_is_required(observation: &SoccerPomdpObservation, role: PlayerRole) -> bool {
    if role == PlayerRole::Goalkeeper {
        return false;
    }
    must_shoot_near_goal(observation, role) || striker_shot_window_is_qualified(observation, role)
}

fn goal_attack_shot_can_yield_to_support(
    observation: &SoccerPomdpObservation,
    role: PlayerRole,
) -> bool {
    if role == PlayerRole::Goalkeeper
        || !goal_attack_shot_is_required(observation, role)
        || clean_twenty_yard_shot_is_qualified(observation, role)
        || observation.yards_to_goal <= SUPPORT_RELAX_FORCED_SHOT_MIN_YARDS
    {
        return false;
    }
    let nearby_support = observation.open_support_outlets > 0
        || observation.nearest_teammate_distance <= SUPPORT_RELAX_FORCED_SHOT_NEARBY_YARDS
        || observation.neural_extended.nearest_teammate_distance
            <= SUPPORT_RELAX_FORCED_SHOT_NEARBY_YARDS;
    if !nearby_support {
        return false;
    }
    let floor_quality = pass_quality_for_patience(observation, PassFlight::Floor);
    let aerial_quality = pass_quality_for_patience(observation, PassFlight::Aerial);
    let forward_support = observation.visible_forward_pass_options > 0
        && observation.best_forward_pass_receiver_openness
            >= SUPPORT_RELAX_FORCED_SHOT_MIN_OPENNESS
        && observation.floor_pass_lane_score >= 0.44;
    let floor_support = observation.visible_pass_options > 0
        && floor_quality >= SUPPORT_RELAX_FORCED_SHOT_MIN_FLOOR_QUALITY;
    let aerial_support = observation.visible_aerial_pass_options > 0
        && aerial_quality >= SUPPORT_RELAX_FORCED_SHOT_MIN_AERIAL_QUALITY;
    let threaded_support = observation.threaded_goal_pass_available
        && threaded_goal_pass_quality_fit(observation)
            >= SUPPORT_RELAX_FORCED_SHOT_MIN_FLOOR_QUALITY;
    floor_support || forward_support || aerial_support || threaded_support
}

fn goal_attack_shot_blocks_alternatives(
    observation: &SoccerPomdpObservation,
    role: PlayerRole,
) -> bool {
    goal_attack_shot_is_required(observation, role)
        && !goal_attack_shot_can_yield_to_support(observation, role)
}

fn near_goal_no_shot_penalty_points(observation: &SoccerPomdpObservation, role: PlayerRole) -> f64 {
    if role == PlayerRole::Goalkeeper
        || !must_shoot_near_goal(observation, role)
        || goal_attack_shot_can_yield_to_support(observation, role)
    {
        return 0.0;
    }
    let role_multiplier = match role {
        PlayerRole::Forward => 1.25,
        PlayerRole::Midfielder => 1.0,
        PlayerRole::Defender => 0.62,
        PlayerRole::Goalkeeper => 0.0,
    };
    let close_fit = ((TEAMMATE_MUST_SHOOT_YARDS - observation.yards_to_goal)
        / TEAMMATE_MUST_SHOOT_YARDS)
        .clamp(0.0, 1.0);
    let shot_quality = (observation.shot_on_frame_probability.clamp(0.0, 1.0) * 0.48
        + observation.shot_beat_goalkeeper_probability.clamp(0.0, 1.0) * 0.32
        + (1.0 - observation.shot_block_probability.clamp(0.0, 1.0)) * 0.20)
        .clamp(0.0, 1.0);
    (NEAR_GOAL_NO_SHOT_PENALTY_POINTS
        * role_multiplier
        * (0.72 + close_fit * 0.58 + shot_quality * 0.42))
        .clamp(0.0, 8.0)
}

fn striker_legal_shot_attempt_bonus(observation: &SoccerPomdpObservation, role: PlayerRole) -> f64 {
    let window_qualified = striker_shot_window_is_qualified(observation, role)
        || teammate_near_goal_shot_is_qualified(observation, role);
    if !window_qualified {
        return 0.0;
    }
    let window_yards = if role == PlayerRole::Forward {
        tunables()
            .shooting
            .striker_shot_window_yards
            .min(SPECULATIVE_LONG_SHOT_MAX_YARDS)
    } else {
        TEAMMATE_MUST_SHOOT_YARDS
    };
    let range_fit = ((window_yards - observation.yards_to_goal) / window_yards).clamp(0.0, 1.0);
    let lane_fit = (1.0
        - observation.shot_block_probability.clamp(0.0, 1.0)
            / STRIKER_SHOT_MAX_BLOCK_PROBABILITY.max(1e-6))
    .clamp(0.0, 1.0);
    let on_frame_fit = (observation.shot_on_frame_probability
        / tunables().shooting.shot_on_frame_min_probability.max(1e-6))
    .clamp(0.0, 1.4);
    let keeper_fit = (observation.shot_beat_goalkeeper_probability
        / SHOT_KEEPER_BEAT_MIN_PROBABILITY.max(1e-6))
    .clamp(0.0, 1.4);
    let space_fit = (observation.forward_dribble_space_yards / 12.0).clamp(0.0, 1.0);
    let urgency = observation
        .offensive_urgency
        .max(observation.decision_urgency)
        .max(observation.pressure_urgency * 0.75)
        .clamp(0.0, 1.0);
    (0.08
        + range_fit * 0.14
        + lane_fit * 0.06
        + on_frame_fit * 0.05
        + keeper_fit * 0.04
        + space_fit * 0.04
        + urgency * 0.06)
        .clamp(0.0, 0.34)
}

fn near_goal_shot_pressure_floor(
    observation: &SoccerPomdpObservation,
    role: PlayerRole,
    shooting_skill: f64,
) -> f64 {
    if role == PlayerRole::Goalkeeper || !shot_decision_is_qualified_for_role(observation, role) {
        return 0.0;
    }
    let window_yards = match role {
        PlayerRole::Forward => tunables()
            .shooting
            .striker_shot_window_yards
            .min(SPECULATIVE_LONG_SHOT_MAX_YARDS),
        PlayerRole::Midfielder | PlayerRole::Defender => TEAMMATE_MUST_SHOOT_YARDS,
        PlayerRole::Goalkeeper => return 0.0,
    };
    if observation.yards_to_goal > window_yards {
        return 0.0;
    }
    let range_fit = ((window_yards - observation.yards_to_goal) / window_yards)
        .clamp(0.0, 1.0)
        .sqrt();
    let lane_fit = (1.0
        - observation.shot_block_probability.clamp(0.0, 1.0)
            / STRIKER_SHOT_MAX_BLOCK_PROBABILITY.max(1e-6))
    .clamp(0.0, 1.0);
    let shot_quality = (observation.shot_on_frame_probability.clamp(0.0, 1.0) * 0.42
        + observation.shot_beat_goalkeeper_probability.clamp(0.0, 1.0) * 0.34
        + lane_fit * 0.24)
        .clamp(0.0, 1.0);
    let role_floor = match role {
        PlayerRole::Forward => 0.16,
        PlayerRole::Midfielder => 0.11,
        PlayerRole::Defender => 0.07,
        PlayerRole::Goalkeeper => 0.0,
    };
    let must_shoot_bonus = if goal_attack_shot_is_required(observation, role) {
        0.26
    } else {
        0.0
    };
    (role_floor
        + range_fit * 0.39
        + shot_quality * 0.15
        + shooting_skill.clamp(0.0, 1.0) * 0.08
        + observation.goal_attack_window_score.clamp(0.0, 1.0) * 0.13
        + observation.offensive_urgency.clamp(0.0, 1.0) * 0.08
        + must_shoot_bonus)
        .clamp(0.0, 0.88)
}

fn killer_pass_goal_range_fit(observation: &SoccerPomdpObservation) -> f64 {
    if observation.yards_to_goal > KILLER_PASS_MAX_YARDS_TO_GOAL {
        0.0
    } else {
        ((KILLER_PASS_MAX_YARDS_TO_GOAL - observation.yards_to_goal)
            / KILLER_PASS_MAX_YARDS_TO_GOAL)
            .clamp(0.0, 1.0)
    }
}

fn threaded_goal_channel_fit_for_reception(
    team: Team,
    reception: Vec2,
    field_width: f64,
    field_length: f64,
    goal_width: f64,
) -> f64 {
    let center_x = field_width * 0.5;
    let goal_y = team.goal_y(field_length);
    let yards_to_goal = (goal_y - reception.y).abs();
    let max_channel_half_width = (field_width * 0.32).max(1.0);
    let min_channel_half_width = 10.0_f64.min(max_channel_half_width);
    let channel_half_width =
        (goal_width * 2.25).clamp(min_channel_half_width, max_channel_half_width);
    let central_fit = (1.0 - (reception.x - center_x).abs() / channel_half_width).clamp(0.0, 1.0);
    let range_fit = ((KILLER_PASS_MAX_YARDS_TO_GOAL - yards_to_goal)
        / KILLER_PASS_MAX_YARDS_TO_GOAL)
        .clamp(0.0, 1.0);
    let goalmouth_fit = ((TEAMMATE_MUST_SHOOT_YARDS - yards_to_goal)
        / (TEAMMATE_MUST_SHOOT_YARDS - GOAL_URGENCY_KEEPER_CROWD_YARDS).max(1.0))
    .clamp(0.0, 1.0);
    (central_fit * 0.58 + range_fit * 0.20 + goalmouth_fit * 0.22).clamp(0.0, 1.0)
}

fn threaded_goal_pass_quality_fit(observation: &SoccerPomdpObservation) -> f64 {
    if !observation.threaded_goal_pass_available {
        return 0.0;
    }
    let explicit_quality = (observation
        .threaded_goal_pass_receiver_openness
        .clamp(0.0, 1.0)
        * 0.22
        + observation
            .threaded_goal_pass_expected_completion
            .clamp(0.0, 1.0)
            * 0.18
        + observation.threaded_goal_pass_stride_fit.clamp(0.0, 1.0) * 0.18
        + observation
            .threaded_goal_pass_reception_window_score
            .clamp(0.0, 1.0)
            * 0.22
        + (observation.threaded_goal_pass_goal_gain_yards / 22.0).clamp(0.0, 1.0) * 0.12
        + (observation.threaded_goal_pass_forward_yards / 26.0).clamp(0.0, 1.0) * 0.08)
        .clamp(0.0, 1.0);
    if explicit_quality > 0.0 {
        explicit_quality
    } else {
        (observation
            .best_forward_pass_receiver_openness
            .clamp(0.0, 1.0)
            * 0.36
            + observation.best_pass_stride_fit.clamp(0.0, 1.0) * 0.30
            + observation.floor_pass_lane_score.clamp(0.0, 1.0) * 0.34)
            .clamp(0.0, 1.0)
    }
}

fn goal_entry_decisive_pressure_score(observation: &SoccerPomdpObservation) -> f64 {
    if observation.yards_to_goal > GOAL_URGENCY_MAX_YARDS {
        return 0.0;
    }
    let entry_fit = ((GOAL_URGENCY_MAX_YARDS - observation.yards_to_goal)
        / (GOAL_URGENCY_MAX_YARDS - GOAL_URGENCY_KEEPER_CROWD_YARDS).max(1.0))
    .clamp(0.0, 1.0)
    .powf(0.72);
    let crowded_keeper_fit = if observation.yards_to_goal < GOAL_URGENCY_KEEPER_CROWD_YARDS {
        (observation.yards_to_goal / GOAL_URGENCY_KEEPER_CROWD_YARDS).clamp(0.42, 1.0)
    } else {
        1.0
    };
    (entry_fit * crowded_keeper_fit).clamp(0.0, 1.0)
}

fn killer_pass_goal_pressure_score(observation: &SoccerPomdpObservation) -> f64 {
    if !observation.threaded_goal_pass_available || observation.visible_forward_pass_options == 0 {
        return 0.0;
    }
    let range_fit = killer_pass_goal_range_fit(observation);
    if range_fit <= 0.0 {
        return 0.0;
    }
    let goal_entry_fit = goal_entry_decisive_pressure_score(observation);
    let close_goal_fit = ((GOAL_URGENCY_MAX_YARDS - observation.yards_to_goal)
        / (GOAL_URGENCY_MAX_YARDS - GOAL_URGENCY_KEEPER_CROWD_YARDS).max(1.0))
    .clamp(0.0, 1.0)
    .powf(0.60);
    let final_third_fit = ((42.0 - observation.yards_to_goal) / 24.0).clamp(0.0, 1.0);
    let receiver_lane_fit = threaded_goal_pass_quality_fit(observation).max(
        (observation
            .best_forward_pass_receiver_openness
            .clamp(0.0, 1.0)
            * 0.42
            + observation.best_pass_stride_fit.clamp(0.0, 1.0) * 0.30
            + observation.floor_pass_lane_score.clamp(0.0, 1.0) * 0.28)
            .clamp(0.0, 1.0),
    );
    (range_fit.powf(0.55) * 0.34
        + final_third_fit * 0.25
        + receiver_lane_fit * 0.27
        + observation.goal_attack_window_score.clamp(0.0, 1.0) * 0.10
        + observation.offensive_urgency.clamp(0.0, 1.0) * 0.04
        + close_goal_fit * 0.16
        + goal_entry_fit * 0.12)
        .clamp(0.0, 1.0)
}

fn single_pass_goal_thread_pressure_score(observation: &SoccerPomdpObservation) -> f64 {
    if !observation.threaded_goal_pass_available
        || observation.visible_forward_pass_options == 0
        || observation.yards_to_goal > KILLER_PASS_MAX_YARDS_TO_GOAL
    {
        return 0.0;
    }
    let range_fit = killer_pass_goal_range_fit(observation).powf(0.48);
    let goal_entry_fit = goal_entry_decisive_pressure_score(observation);
    let close_goal_fit = ((GOAL_URGENCY_MAX_YARDS - observation.yards_to_goal)
        / (GOAL_URGENCY_MAX_YARDS - GOAL_URGENCY_KEEPER_CROWD_YARDS).max(1.0))
    .clamp(0.0, 1.0)
    .powf(0.58);
    let final_third_fit = ((42.0 - observation.yards_to_goal) / 24.0).clamp(0.0, 1.0);
    let receiver_lane_fit = threaded_goal_pass_quality_fit(observation).max(
        (observation
            .best_forward_pass_receiver_openness
            .clamp(0.0, 1.0)
            * 0.36
            + observation.best_pass_stride_fit.clamp(0.0, 1.0) * 0.30
            + observation.floor_pass_lane_score.clamp(0.0, 1.0) * 0.34)
            .clamp(0.0, 1.0),
    );
    let blocked_shot_invitation = if observation.shot_lane_open {
        ((observation.shot_block_probability.clamp(0.0, 1.0) - 0.24) / 0.56).clamp(0.0, 1.0)
    } else {
        0.78
    };
    (range_fit * 0.23
        + final_third_fit * 0.20
        + receiver_lane_fit * 0.36
        + blocked_shot_invitation * 0.12
        + observation.goal_attack_window_score.clamp(0.0, 1.0) * 0.04
        + close_goal_fit * 0.17
        + goal_entry_fit * 0.16)
        .clamp(0.0, 1.0)
}

fn killer_pass_goal_pressure_floor(observation: &SoccerPomdpObservation) -> f64 {
    let pressure = killer_pass_goal_pressure_score(observation);
    if pressure <= 0.0 {
        return 0.0;
    }
    let danger_zone_fit = ((36.0 - observation.yards_to_goal) / 24.0).clamp(0.0, 1.0);
    let goal_entry_fit = goal_entry_decisive_pressure_score(observation);
    let close_goal_fit = ((GOAL_URGENCY_MAX_YARDS - observation.yards_to_goal)
        / (GOAL_URGENCY_MAX_YARDS - GOAL_URGENCY_KEEPER_CROWD_YARDS).max(1.0))
    .clamp(0.0, 1.0);
    (0.08
        + pressure * 0.30
        + danger_zone_fit * 0.10
        + goal_entry_fit * 0.08
        + close_goal_fit * 0.08
        + observation
            .best_forward_pass_receiver_openness
            .clamp(0.0, 1.0)
            * 0.08
        + observation.floor_pass_lane_score.clamp(0.0, 1.0) * 0.06)
        .clamp(0.12, 0.72)
}

fn threaded_goal_pass_can_override_forced_shot(
    observation: &SoccerPomdpObservation,
    role: PlayerRole,
) -> bool {
    if role == PlayerRole::Goalkeeper
        || !observation.threaded_goal_pass_available
        || observation.visible_forward_pass_options == 0
        || observation.yards_to_goal > KILLER_PASS_MAX_YARDS_TO_GOAL
        || clean_twenty_yard_shot_is_qualified(observation, role)
    {
        return false;
    }
    let threaded_lane = threaded_goal_pass_quality_fit(observation).max(
        (observation
            .best_forward_pass_receiver_openness
            .clamp(0.0, 1.0)
            * 0.34
            + observation.best_pass_stride_fit.clamp(0.0, 1.0) * 0.30
            + observation.floor_pass_lane_score.clamp(0.0, 1.0) * 0.36)
            .clamp(0.0, 1.0),
    );
    if threaded_lane < 0.66 || killer_pass_goal_pressure_score(observation) < 0.48 {
        return false;
    }
    let shot_lane = if observation.shot_lane_open {
        ((1.0 - observation.shot_block_probability.clamp(0.0, 1.0)) * 0.34
            + observation.shot_on_frame_probability.clamp(0.0, 1.0) * 0.36
            + observation.shot_beat_goalkeeper_probability.clamp(0.0, 1.0) * 0.24
            + (observation.opponent_goal_angle_degrees / 42.0).clamp(0.0, 1.0) * 0.06)
            .clamp(0.0, 1.0)
    } else {
        0.0
    };
    let close_shot_fit = ((TEAMMATE_MUST_SHOOT_YARDS - observation.yards_to_goal)
        / TEAMMATE_MUST_SHOOT_YARDS)
        .clamp(0.0, 1.0);
    let true_sitter = observation.shot_lane_open
        && observation.yards_to_goal <= CLEAN_SHOT_MUST_SHOOT_YARDS
        && observation.shot_block_probability.clamp(0.0, 1.0) <= 0.18
        && observation.shot_on_frame_probability >= 0.50
        && observation.shot_beat_goalkeeper_probability >= 0.26;
    !true_sitter && (threaded_lane > shot_lane + 0.10 || close_shot_fit < 0.38 || shot_lane < 0.58)
}

fn near_goal_decisive_action_pressure_score(
    observation: &SoccerPomdpObservation,
    role: PlayerRole,
) -> f64 {
    if role == PlayerRole::Goalkeeper || observation.yards_to_goal > KILLER_PASS_MAX_YARDS_TO_GOAL {
        return 0.0;
    }
    let range_fit = ((KILLER_PASS_MAX_YARDS_TO_GOAL - observation.yards_to_goal)
        / KILLER_PASS_MAX_YARDS_TO_GOAL)
        .clamp(0.0, 1.0)
        .powf(0.62);
    let close_goal_fit = ((GOAL_URGENCY_MAX_YARDS - observation.yards_to_goal)
        / (GOAL_URGENCY_MAX_YARDS - GOAL_URGENCY_KEEPER_CROWD_YARDS).max(1.0))
    .clamp(0.0, 1.0)
    .powf(0.58);
    let final_third_fit = ((42.0 - observation.yards_to_goal) / 24.0).clamp(0.0, 1.0);
    let shot_lane_fit = if observation.shot_lane_open {
        ((1.0 - observation.shot_block_probability.clamp(0.0, 1.0)) * 0.38
            + observation.shot_on_frame_probability.clamp(0.0, 1.0) * 0.34
            + observation.shot_beat_goalkeeper_probability.clamp(0.0, 1.0) * 0.22
            + (observation.opponent_goal_angle_degrees / 42.0).clamp(0.0, 1.0) * 0.06)
            .clamp(0.0, 1.0)
    } else {
        0.0
    };
    let threaded_lane_fit = if observation.threaded_goal_pass_available
        && observation.visible_forward_pass_options > 0
    {
        threaded_goal_pass_quality_fit(observation).max(
            (observation
                .best_forward_pass_receiver_openness
                .clamp(0.0, 1.0)
                * 0.36
                + observation.best_pass_stride_fit.clamp(0.0, 1.0) * 0.30
                + observation.floor_pass_lane_score.clamp(0.0, 1.0) * 0.34)
                .clamp(0.0, 1.0),
        )
    } else {
        0.0
    };
    let single_thread_fit = single_pass_goal_thread_pressure_score(observation);
    let shooting_skill = ability01(observation.skill_shooting);
    let shot_pressure_fit = goal_proximity_shot_pressure_score(observation, role, shooting_skill);
    let killer_pressure_fit = killer_pass_goal_pressure_score(observation).max(single_thread_fit);
    let role_fit = match role {
        PlayerRole::Forward => 1.12,
        PlayerRole::Midfielder => 0.98,
        PlayerRole::Defender => 0.62,
        PlayerRole::Goalkeeper => 0.0,
    };

    let goal_entry_fit = goal_entry_decisive_pressure_score(observation);

    ((range_fit * 0.34
        + final_third_fit * 0.19
        + shot_lane_fit.max(threaded_lane_fit) * 0.24
        + observation.goal_attack_window_score.clamp(0.0, 1.0) * 0.13
        + observation.offensive_urgency.clamp(0.0, 1.0) * 0.07
        + single_thread_fit * 0.12
        + shot_pressure_fit * 0.13
        + killer_pressure_fit * 0.11
        + close_goal_fit * 0.09
        + goal_entry_fit * 0.09)
        * role_fit)
        .clamp(0.0, 1.0)
}

fn killer_pass_forced_by_goal_pressure(
    observation: &SoccerPomdpObservation,
    role: PlayerRole,
) -> bool {
    if role == PlayerRole::Goalkeeper
        || !observation.threaded_goal_pass_available
        || observation.visible_forward_pass_options == 0
        || observation.yards_to_goal > 42.0
    {
        return false;
    }
    let shot_not_clean = !shot_decision_is_qualified_for_role(observation, role)
        || observation.shot_block_probability.clamp(0.0, 1.0) >= 0.48;
    let threaded_quality = threaded_goal_pass_quality_fit(observation);
    let threaded_lane = threaded_quality >= 0.42
        || (observation.floor_pass_lane_score.clamp(0.0, 1.0) >= 0.44
            && observation
                .best_forward_pass_receiver_openness
                .clamp(0.0, 1.0)
                >= 0.42);
    (shot_not_clean || threaded_goal_pass_can_override_forced_shot(observation, role))
        && threaded_lane
        && killer_pass_goal_pressure_score(observation) >= 0.46
}

fn final_third_killer_pass_preemption_probability(
    observation: &SoccerPomdpObservation,
    role: PlayerRole,
    options: &[AgentActionOptionTrace],
) -> f64 {
    if !killer_pass_forced_by_goal_pressure(observation, role)
        || (goal_attack_shot_blocks_alternatives(observation, role)
            && !threaded_goal_pass_can_override_forced_shot(observation, role))
    {
        return 0.0;
    }
    let Some(killer_option) = options.iter().find(|option| {
        option.legal
            && SoccerActionLabel::classify(&option.label) == Some(SoccerActionLabel::KillerPass)
    }) else {
        return 0.0;
    };
    let range_fit = ((42.0 - observation.yards_to_goal) / 24.0).clamp(0.0, 1.0);
    let lane_fit = threaded_goal_pass_quality_fit(observation).max(
        (observation
            .best_forward_pass_receiver_openness
            .clamp(0.0, 1.0)
            * 0.34
            + observation.best_pass_stride_fit.clamp(0.0, 1.0) * 0.30
            + observation.floor_pass_lane_score.clamp(0.0, 1.0) * 0.36)
            .clamp(0.0, 1.0),
    );
    let shot_block_fit =
        ((observation.shot_block_probability.clamp(0.0, 1.0) - 0.34) / 0.46).clamp(0.0, 1.0);
    let shot_quality_gap = if observation.shot_lane_open {
        (0.62
            - (observation.shot_on_frame_probability.clamp(0.0, 1.0) * 0.44
                + observation.shot_beat_goalkeeper_probability.clamp(0.0, 1.0) * 0.34
                + (1.0 - observation.shot_block_probability.clamp(0.0, 1.0)) * 0.22))
            .clamp(0.0, 0.62)
            / 0.62
    } else {
        1.0
    };
    (0.10
        + range_fit * 0.24
        + lane_fit * 0.16
        + shot_block_fit * 0.14
        + shot_quality_gap * 0.12
        + killer_option.probability.clamp(0.0, 1.0) * 0.34
        + observation
            .decisive_goal_action_pressure
            .max(near_goal_decisive_action_pressure_score(observation, role))
            .clamp(0.0, 1.0)
            * 0.12)
        .clamp(0.0, 0.78)
}

fn near_goal_pass_release_multiplier(
    observation: &SoccerPomdpObservation,
    role: PlayerRole,
) -> f64 {
    if goal_attack_shot_blocks_alternatives(observation, role) {
        0.08
    } else {
        1.0
    }
}

fn low_pressure_patience_factor(observation: &SoccerPomdpObservation) -> f64 {
    let urgency = observation
        .perceived_pressure
        .max(observation.pressure_urgency)
        .max(observation.immediate_dispossession_risk * 0.55)
        .clamp(0.0, 1.0);
    ((0.42 - urgency) / 0.42).clamp(0.0, 1.0)
}

fn pass_quality_for_patience(observation: &SoccerPomdpObservation, flight: PassFlight) -> f64 {
    match flight {
        PassFlight::Floor => (observation.expected_pass_completion.clamp(0.0, 1.0) * 0.50
            + observation.best_pass_receiver_openness.clamp(0.0, 1.0) * 0.32
            + observation.floor_pass_lane_score.clamp(0.0, 1.0) * 0.18)
            .clamp(0.0, 1.0),
        PassFlight::Aerial | PassFlight::Scoop | PassFlight::OverTop => {
            let base = (observation.expected_aerial_pass_completion.clamp(0.0, 1.0) * 0.46
                + observation
                    .best_aerial_pass_receiver_openness
                    .clamp(0.0, 1.0)
                    * 0.24
                + observation.aerial_pass_bypass_score.clamp(0.0, 1.0) * 0.20
                + (1.0 - observation.aerial_pass_interception_risk.clamp(0.0, 1.0)) * 0.06
                + (1.0 - observation.long_aerial_bounds_risk.clamp(0.0, 1.0)) * 0.04)
                .clamp(0.0, 1.0);
            // POMDP side of the aerial-OOB loop: a loft whose projected landing sits on/over a
            // boundary reads as a POOR pass, so the patience logic prefers carrying / a safer
            // outlet over blazing it out of play. Gate OFF ⇒ safety factor ignored (the field
            // defaults to 1.0 anyway), so this is byte-identical to baseline.
            if dd_soccer_enable_aerial_pass_oob_discipline() {
                (base * observation.aerial_pass_landing_safety.clamp(0.0, 1.0)).clamp(0.0, 1.0)
            } else {
                base
            }
        }
    }
}

fn low_pressure_pass_release_multiplier(
    observation: &SoccerPomdpObservation,
    flight: PassFlight,
) -> f64 {
    let patience = low_pressure_patience_factor(observation);
    if patience <= 0.0 {
        return 1.0;
    }
    let quality = pass_quality_for_patience(observation, flight);
    let poor_pass = (1.0 - quality).clamp(0.0, 1.0);
    let carry_space = (observation.forward_dribble_space_yards / 18.0).clamp(0.0, 1.0);
    (1.0 - patience * poor_pass * (1.02 + carry_space * 0.34)).clamp(0.18, 1.0)
}

fn low_pressure_patient_carry_multiplier(observation: &SoccerPomdpObservation) -> f64 {
    let patience = low_pressure_patience_factor(observation);
    if patience <= 0.0 {
        return 1.0;
    }
    let poor_floor_pass =
        (1.0 - pass_quality_for_patience(observation, PassFlight::Floor)).clamp(0.0, 1.0);
    let carry_space = (observation.forward_dribble_space_yards / 18.0).clamp(0.0, 1.0);
    (1.0 + patience * poor_floor_pass * (0.72 + carry_space * 0.96)).clamp(1.0, 2.10)
}

fn low_pressure_patient_carry_preferred(observation: &SoccerPomdpObservation) -> bool {
    low_pressure_patience_factor(observation) >= 0.45
        && pass_quality_for_patience(observation, PassFlight::Floor) <= 0.76
        && observation.forward_dribble_space_yards >= 2.0
}

fn low_pressure_forced_pass_penalty_points(
    observation: &SoccerPomdpObservation,
    context: &SoccerDecisionContext,
    flight: PassFlight,
    retained_possession: bool,
) -> f64 {
    if !low_pressure_patient_carry_preferred(observation) {
        return 0.0;
    }
    let quality = pass_quality_for_patience(observation, flight);
    let poor_pass = (1.0 - quality).clamp(0.0, 1.0);
    if poor_pass <= 0.0 {
        return 0.0;
    }

    let patience = low_pressure_patience_factor(observation);
    let carry_space = (observation.forward_dribble_space_yards / 18.0).clamp(0.0, 1.0);
    let direction_cost = if context.target_forward_yards < -1.25 {
        0.58
    } else if context.target_forward_yards <= 1.25 {
        0.30
    } else {
        0.0
    };
    let outcome_cost = if retained_possession { 0.36 } else { 1.0 };

    (tunables().reward.low_pressure_forced_pass_penalty_points
        * patience
        * poor_pass
        * (0.55 + carry_space * 0.45)
        * (outcome_cost + direction_cost))
        .clamp(0.0, 2.65)
}

fn goal_approach_carry_window_yards(role: PlayerRole) -> f64 {
    match role {
        PlayerRole::Goalkeeper => 0.0,
        PlayerRole::Defender => ATTACKING_DRIBBLE_GOAL_DRIVE_YARDS,
        PlayerRole::Midfielder | PlayerRole::Forward => {
            tunables().shooting.goal_approach_carry_yards
        }
    }
}

fn goal_approach_drive_candidate(observation: &SoccerPomdpObservation, role: PlayerRole) -> bool {
    let goal_approach_window = goal_approach_carry_window_yards(role);
    observation.has_ball
        && !goal_attack_shot_is_required(observation, role)
        && observation.yards_to_goal <= goal_approach_window
        && (matches!(role, PlayerRole::Forward | PlayerRole::Midfielder)
            || observation.offensive_urgency >= 0.24
            || shot_creation_carry_multiplier(observation) >= 1.10)
}

fn goal_approach_carry_preferred(observation: &SoccerPomdpObservation, role: PlayerRole) -> bool {
    goal_approach_drive_candidate(observation, role)
        && observation.forward_dribble_space_yards >= 1.2
}

fn goal_approach_forces_goalmouth_carry(
    observation: &SoccerPomdpObservation,
    role: PlayerRole,
) -> bool {
    goal_approach_drive_candidate(observation, role)
}

fn goal_approach_dribble_kind(
    kind: DribbleMoveKind,
    observation: &SoccerPomdpObservation,
    role: PlayerRole,
) -> DribbleMoveKind {
    if goal_approach_forces_goalmouth_carry(observation, role)
        && !matches!(
            dribble_final_cut_kind(kind),
            DribbleMoveKind::FakeLeftCutRight | DribbleMoveKind::FakeRightCutLeft
        )
    {
        DribbleMoveKind::CarryForward
    } else {
        kind
    }
}

fn attacking_dribble_shooting_pocket_depth(yards_to_goal: f64) -> f64 {
    if yards_to_goal <= ATTACKING_DRIBBLE_SHOOTING_POCKET_YARDS {
        10.0
    } else if yards_to_goal <= TEAMMATE_MUST_SHOOT_YARDS {
        11.0
    } else {
        13.0
    }
}

fn close_clear_shot_attempt_probability(
    observation: &SoccerPomdpObservation,
    role: PlayerRole,
    shooting_skill: f64,
) -> f64 {
    if !shot_decision_is_qualified_for_role(observation, role) {
        return 0.0;
    }
    let (window_yards, ramp_yards) = match role {
        PlayerRole::Forward => (
            tunables()
                .shooting
                .striker_shot_window_yards
                .min(SPECULATIVE_LONG_SHOT_MAX_YARDS),
            18.0,
        ),
        _ => (TEAMMATE_MUST_SHOOT_YARDS, 16.0),
    };
    let mut close_fit = ((window_yards - observation.yards_to_goal) / ramp_yards).clamp(0.0, 1.0);
    if role == PlayerRole::Forward && observation.yards_to_goal <= window_yards {
        close_fit = close_fit.max(0.24);
    }
    if striker_must_shoot(observation, role) {
        close_fit = close_fit.max(0.88);
    }
    if close_fit <= 0.0 {
        return 0.0;
    }
    let lane_fit = (1.0
        - observation.shot_block_probability.clamp(0.0, 1.0)
            / SHOT_BLOCK_DECISION_MAX_PROBABILITY.max(1e-6))
    .clamp(0.0, 1.0);
    let on_frame_fit = (observation.shot_on_frame_probability
        / tunables().shooting.shot_on_frame_min_probability)
        .clamp(0.0, 1.35);
    let keeper_fit = (observation.shot_beat_goalkeeper_probability
        / SHOT_KEEPER_BEAT_MIN_PROBABILITY)
        .clamp(0.0, 1.35);
    let urgency = observation
        .offensive_urgency
        .max(observation.decision_urgency)
        .clamp(0.0, 1.0);
    let role_bonus = match role {
        PlayerRole::Forward => 0.24,
        PlayerRole::Midfielder => 0.08,
        PlayerRole::Defender => 0.02,
        PlayerRole::Goalkeeper => 0.0,
    };
    let striker_window_bonus = if role == PlayerRole::Forward {
        let striker_shot_window_yards = tunables()
            .shooting
            .striker_shot_window_yards
            .min(SPECULATIVE_LONG_SHOT_MAX_YARDS);
        let window_fit = ((striker_shot_window_yards - observation.yards_to_goal)
            / (striker_shot_window_yards - STRIKER_MUST_SHOOT_YARDS).max(1e-6))
        .clamp(0.0, 1.0);
        0.18 + window_fit * 0.22
    } else {
        0.0
    };

    (0.22
        + close_fit * 0.32
        + lane_fit * 0.16
        + on_frame_fit * 0.13
        + keeper_fit * 0.11
        + shooting_skill.clamp(0.0, 1.0) * 0.10
        + urgency * 0.10
        + role_bonus
        + striker_window_bonus)
        .clamp(
            0.30,
            if role == PlayerRole::Forward {
                0.99
            } else {
                0.92
            },
        )
}

fn first_time_shot_decision_is_qualified(observation: &SoccerPomdpObservation) -> bool {
    observation.first_time_shot_score > 0.0 && shot_decision_is_qualified(observation)
}

fn first_time_shot_decision_is_qualified_for_role(
    observation: &SoccerPomdpObservation,
    role: PlayerRole,
) -> bool {
    observation.first_time_shot_score > 0.0
        && shot_decision_is_qualified_for_role(observation, role)
}

fn aerial_duel_skill_from_snapshot(player: &PlayerSnapshot) -> f64 {
    let height = ability01(player.skills.height);
    (height * 0.36
        + ability01(player.skills.strength) * 0.26
        + ability01(player.skills.aggression) * 0.18
        + ability01(player.skills.first_touch) * 0.20)
        .clamp(0.0, 1.0)
}

fn aerial_duel_skill_from_agent(player: &PlayerAgent) -> f64 {
    let height = ability01(player.skills.height);
    (height * 0.36
        + ability01(player.skills.strength) * 0.26
        + ability01(player.skills.aggression) * 0.18
        + ability01(player.skills.first_touch) * 0.20)
        .clamp(0.0, 1.0)
}

fn first_time_shot_score_for_player(
    player: &PlayerSnapshot,
    incoming_kind: IncomingBallKind,
    shot_block_probability: f64,
    yards_to_goal: f64,
    goal_angle_degrees: f64,
    pressure: f64,
) -> f64 {
    if shot_block_probability > tunables().shooting.shot_block_bailout_max_probability {
        return 0.0;
    }
    let foot_power = (ability01(
        player
            .skills
            .right_foot_shot_power
            .max(player.skills.left_foot_shot_power),
    ) * 0.70
        + ability01(player.skills.shooting) * 0.30)
        .clamp(0.0, 1.0);
    let aerial_finish = aerial_duel_skill_from_snapshot(player);
    let strike_skill = match incoming_kind {
        IncomingBallKind::AerialCross | IncomingBallKind::AerialPass => {
            foot_power * 0.45 + aerial_finish * 0.55
        }
        IncomingBallKind::Cross => foot_power * 0.78 + ability01(player.skills.first_touch) * 0.22,
        _ => foot_power * 0.70 + ability01(player.skills.first_touch) * 0.30,
    };
    let geometry = ((1.0 - yards_to_goal / 34.0).clamp(0.0, 1.0) * 0.58
        + (goal_angle_degrees / 42.0).clamp(0.0, 1.0) * 0.42)
        .clamp(0.0, 1.0);
    let quick_release_block_discount =
        (1.0 - shot_block_probability.clamp(0.0, 1.0) * 0.46).clamp(0.46, 1.0);
    ((strike_skill * 0.62 + geometry * 0.38 + pressure.clamp(0.0, 1.0) * 0.14)
        * quick_release_block_discount)
        .clamp(0.0, 1.0)
}

fn first_time_pass_score_for_player(
    player: &PlayerSnapshot,
    incoming_kind: IncomingBallKind,
    pressure: f64,
) -> f64 {
    let flair_bonus = match incoming_kind {
        IncomingBallKind::AerialCross | IncomingBallKind::AerialPass => 0.08,
        IncomingBallKind::Cross => 0.05,
        _ => 0.0,
    };
    (ability01(player.skills.passing_completion_rate) * 0.50
        + ability01(player.skills.first_touch) * 0.24
        + ability01(player.skills.flair_passing) * 0.18
        + pressure.clamp(0.0, 1.0) * 0.12
        + flair_bonus)
        .clamp(0.0, 1.0)
}

fn control_touch_score_for_player(
    player: &PlayerSnapshot,
    incoming_kind: IncomingBallKind,
    incoming_speed_yps: f64,
    pressure: f64,
) -> f64 {
    let aerial_control = if matches!(
        incoming_kind,
        IncomingBallKind::AerialCross | IncomingBallKind::AerialPass
    ) {
        aerial_duel_skill_from_snapshot(player) * 0.26
    } else {
        0.0
    };
    let speed_penalty = (incoming_speed_yps / 36.0).clamp(0.0, 1.0) * 0.20;
    (ability01(player.skills.first_touch) * 0.42
        + ability01(player.skills.strength) * 0.22
        + ability01(player.skills.dribbling) * 0.16
        + aerial_control
        - pressure.clamp(0.0, 1.0) * 0.18
        - speed_penalty)
        .clamp(0.0, 1.0)
}

// --- One-touch contact feasibility (the "is this one-touch on, or a coin flip?" gate) -
// The MDP/POMDP scores first-time pass/shot on skill + pressure but is blind to the
// PHYSICS of meeting the ball: its height at contact, its pace, and how far you must
// turn it. These factors give a physically-grounded success probability in [0, 1] that
// scales the one-touch option scores and vetoes the option when it is too low (so the
// policy falls back to a controlling touch). Pitch wetness is a hook for a future
// surface-condition input; it defaults to dry (no effect) for now.
const ONE_TOUCH_DEFAULT_PITCH_WETNESS: f64 = 0.0;
// Below this feasibility a one-touch is a coin-flip — hard-suppress it so a settling
// touch wins. Tuned so a normal ground ball at a comfortable pace stays ~1.0 (the gate
// is near-identity for routine contacts and only bites awkward/fast/aerial/reverse ones).
const ONE_TOUCH_VETO_FEASIBILITY: f64 = 0.30;
const ONE_TOUCH_VETO_SUPPRESSION: f64 = 0.12;

fn one_touch_feasibility_default() -> f64 {
    1.0
}

/// Physical feasibility (0..1) of cleanly redirecting an incoming ball with ONE touch.
/// Grounded in contact geometry rather than skill alone: the ball's pace and height at
/// contact, plus (for a strike, where the target is unambiguous) the angle you must turn
/// it through to hit the goal. First-touch skill widens every tolerance; pressure and a
/// wet surface tighten them. `aerial_strike` = a volley/header that tolerates height
/// (vs. a controlled ground pass that does not). `redirect_radians` is `None` when the
/// outgoing direction is ambiguous (a pass could go many ways) and `Some(theta)` for a
/// shot. A near-stationary ball at the feet is trivial — returns ~1.0.
fn one_touch_contact_feasibility(
    incoming_speed_yps: f64,
    contact_height_yards: f64,
    redirect_radians: Option<f64>,
    first_touch_skill01: f64,
    pressure01: f64,
    wetness01: f64,
    aerial_strike: bool,
) -> f64 {
    let skill = first_touch_skill01.clamp(0.0, 1.0);
    let pressure = pressure01.clamp(0.0, 1.0);
    let wetness = wetness01.clamp(0.0, 1.0);
    // Pace: comfortable up to a skill-dependent threshold, then falls off. Skill in
    // [0,1] lifts the comfortable pace ~10→18 yps and softens the decay.
    let comfortable = 10.0 + 8.0 * skill;
    let pace_excess = (incoming_speed_yps - comfortable).max(0.0);
    let speed_factor = (1.0 - pace_excess / (30.0 + 22.0 * skill)).clamp(0.28, 1.0);
    // Height: a controlled ground touch wants the ball low; a volley/header tolerates
    // height. Measured from a knee-high ~0.3yd "free" band.
    let height_excess = (contact_height_yards - 0.3).max(0.0);
    let height_factor = if aerial_strike {
        (1.0 - height_excess * 0.12).clamp(0.65, 1.0)
    } else {
        (1.0 - height_excess / (1.5 + 1.6 * skill)).clamp(0.12, 1.0)
    };
    // Turn angle (shots only): straight-on is free, reversing it is very hard.
    let angle_factor = match redirect_radians {
        Some(theta) => {
            let turn = (theta.abs() / std::f64::consts::PI).clamp(0.0, 1.0);
            (1.0 - turn * (1.0 - 0.45 * skill)).clamp(0.10, 1.0)
        }
        None => 1.0,
    };
    let pressure_factor = 1.0 - pressure * 0.12;
    let wetness_factor = 1.0 - wetness * 0.15;
    (speed_factor * height_factor * angle_factor * pressure_factor * wetness_factor).clamp(0.0, 1.0)
}

fn angle_between_vectors_degrees(a: Vec2, b: Vec2) -> f64 {
    let al = a.len();
    let bl = b.len();
    if al <= 1e-9 || bl <= 1e-9 {
        return 0.0;
    }
    let cos = (a.dot(b) / (al * bl)).clamp(-1.0, 1.0);
    cos.acos().to_degrees()
}

/// Whether an UNTARGETED pass (one with no resolved receiver) is a legitimate ball into
/// open space rather than a giveaway. It qualifies only when played FORWARD — within
/// `PASS_TO_NOBODY_MAX_CONE_DEGREES` of the line from the passer to the centre of the
/// opponent's goal — AND travelling more than `PASS_TO_NOBODY_MIN_YARDS`. A shorter, lateral,
/// or backward ball aimed at nobody is disallowed (the carrier should keep possession). Passes
/// played TO a specific teammate are never gated by this — only receiver-less balls.
fn pass_to_nobody_is_legal(
    origin: Vec2,
    aim: Vec2,
    team: Team,
    field_width: f64,
    field_length: f64,
) -> bool {
    let pass_vector = aim - origin;
    if pass_vector.len() <= PASS_TO_NOBODY_MIN_YARDS {
        return false;
    }
    let goal = Vec2::new(field_width * 0.5, team.goal_y(field_length));
    let to_goal = goal - origin;
    if to_goal.len() <= 1e-6 {
        // Standing on the opponent's goal line — any onward ball is effectively at goal.
        return true;
    }
    angle_between_vectors_degrees(pass_vector, to_goal) <= PASS_TO_NOBODY_MAX_CONE_DEGREES
}

fn vision_range_yards(vision: f64) -> f64 {
    PLAYER_BASE_VISION_RANGE_YARDS + ability01(vision) * PLAYER_VISION_RANGE_BONUS_YARDS
}

fn field_of_view_degrees(vision: f64) -> f64 {
    PLAYER_BASE_FIELD_OF_VIEW_DEGREES + ability01(vision) * PLAYER_FIELD_OF_VIEW_BONUS_DEGREES
}

fn player_vision_range(player: &PlayerSnapshot) -> f64 {
    if player.vision_range_yards.is_finite() && player.vision_range_yards > 0.0 {
        player.vision_range_yards
    } else {
        vision_range_yards(DEFAULT_PLAYER_VISION_SKILL)
    }
}

fn player_field_of_view(player: &PlayerSnapshot) -> f64 {
    if player.field_of_view_degrees.is_finite() && player.field_of_view_degrees > 0.0 {
        player.field_of_view_degrees
    } else {
        field_of_view_degrees(DEFAULT_PLAYER_VISION_SKILL)
    }
}

fn ball_holder_shoulder_scan_limit_degrees() -> f64 {
    tunables()
        .pomdp_perception
        .ball_holder_shoulder_scan_limit_degrees()
}

fn ball_holder_head_scan_fraction(angle_degrees: f64) -> f64 {
    let shoulder_limit = ball_holder_shoulder_scan_limit_degrees();
    let span = (180.0 - shoulder_limit).max(1.0);
    ((angle_degrees - shoulder_limit) / span).clamp(0.0, 1.0)
}

fn ball_holder_head_scan_delay_seconds(angle_degrees: f64, vision: f64) -> f64 {
    if angle_degrees <= ball_holder_shoulder_scan_limit_degrees() {
        return 0.0;
    }
    let perception = &tunables().pomdp_perception;
    let scan = ball_holder_head_scan_fraction(angle_degrees);
    let max_seconds = perception.ball_holder_head_scan_max_seconds
        - ability01(vision) * perception.ball_holder_head_scan_vision_relief_seconds;
    (perception.ball_holder_head_scan_min_seconds
        + scan * (max_seconds - perception.ball_holder_head_scan_min_seconds).max(0.0))
    .clamp(
        perception.ball_holder_head_scan_min_seconds,
        perception.ball_holder_head_scan_max_seconds,
    )
}

fn ball_holder_head_scan_position_confidence(angle_degrees: f64, vision: f64) -> f64 {
    let perception = &tunables().pomdp_perception;
    if angle_degrees <= perception.ball_holder_core_degrees * 0.5 {
        perception.ball_holder_core_confidence
    } else if angle_degrees <= ball_holder_shoulder_scan_limit_degrees() {
        perception.ball_holder_shoulder_confidence
    } else {
        let scan = ball_holder_head_scan_fraction(angle_degrees);
        let base = perception.ball_holder_side_scan_confidence
            + (perception.ball_holder_rear_scan_confidence
                - perception.ball_holder_side_scan_confidence)
                * scan;
        (base + ability01(vision) * perception.ball_holder_scan_confidence_vision_bonus).clamp(
            perception.ball_holder_rear_scan_confidence,
            perception.ball_holder_scan_confidence_cap,
        )
    }
}

fn ball_holder_surprise_facing_vector(
    team: Team,
    action_facing: FacingBucket,
    holder_velocity: Vec2,
) -> Vec2 {
    facing_bucket_to_vector(action_facing)
        .or_else(|| (holder_velocity.len() > 0.35).then(|| holder_velocity.normalized()))
        .unwrap_or_else(|| Vec2::new(0.0, team.attack_dir()))
}

fn side_glance_threat_metrics(
    holder_team: Team,
    holder_position: Vec2,
    holder_velocity: Vec2,
    holder_action_facing: FacingBucket,
    holder_vision: f64,
    possession_seconds: f64,
    threat_position: Vec2,
    threat_proximity: f64,
) -> SideGlanceThreatMetrics {
    let to_threat = threat_position - holder_position;
    if to_threat.len() <= 1e-6 {
        return SideGlanceThreatMetrics {
            active: true,
            recognition: 1.0,
            ..SideGlanceThreatMetrics::default()
        };
    }
    let facing =
        ball_holder_surprise_facing_vector(holder_team, holder_action_facing, holder_velocity);
    let angle = angle_between_vectors_degrees(facing, to_threat);
    let side_scan_start = tunables().pomdp_perception.ball_holder_core_degrees * 0.5;
    if angle <= side_scan_start {
        return SideGlanceThreatMetrics {
            recognition: 1.0,
            ..SideGlanceThreatMetrics::default()
        };
    }

    let scan_seconds = finite_metric(possession_seconds).max(0.0);
    let scan_delay =
        ball_holder_head_scan_delay_seconds(angle, holder_vision).max(DEFAULT_DT_SECONDS);
    let delay_fit = (scan_seconds / scan_delay).clamp(0.0, 1.0);
    let fov_half = ball_holder_shoulder_scan_limit_degrees().to_radians();
    let coverage = scan_coverage(
        angle.to_radians(),
        fov_half,
        scan_seconds.max(DEFAULT_DT_SECONDS),
        ability01(holder_vision),
    )
    .clamp(0.0, 1.0);
    let proximity = finite_metric(threat_proximity).clamp(0.0, 1.0);
    let recognition = (0.10 + coverage * 0.62 + delay_fit * 0.18 + ability01(holder_vision) * 0.10)
        .clamp(0.0, 0.96);
    let scan_rate_hz = (0.28 + proximity * 0.54 + (1.0 - recognition) * 0.24).clamp(0.0, 1.35);
    let control_cost = (0.014 + scan_rate_hz * 0.040 + (1.0 - ability01(holder_vision)) * 0.012)
        .clamp(0.0, SURPRISE_BEHIND_STEAL_MAX_GLANCE_CONTROL_COST);

    SideGlanceThreatMetrics {
        active: true,
        scan_rate_hz,
        recognition,
        control_cost,
    }
}

fn surprise_holder_gait_fit(gait: MovementGait) -> f64 {
    match gait {
        MovementGait::Stand => 0.74,
        MovementGait::Walk | MovementGait::BackWalk => 1.0,
        MovementGait::Jog | MovementGait::BackJog | MovementGait::Skip | MovementGait::BackSkip => {
            0.92
        }
        MovementGait::SideStep => 0.82,
        MovementGait::Run => 0.48,
        MovementGait::Sprint => 0.22,
    }
}

#[allow(clippy::too_many_arguments)]
pub(crate) fn surprise_behind_steal_profile_from_kinematics(
    defender_team: Team,
    defender_role: PlayerRole,
    defender_position: Vec2,
    defender_velocity: Vec2,
    defender_skills: &SkillProfile,
    defender_fatigue: f64,
    holder_team: Team,
    holder_role: PlayerRole,
    holder_position: Vec2,
    holder_velocity: Vec2,
    holder_gait: MovementGait,
    holder_action_facing: FacingBucket,
    holder_skills: &SkillProfile,
    holder_fatigue: f64,
    holder_possession_seconds: f64,
) -> SurpriseBehindStealProfile {
    if defender_team == holder_team || defender_role == PlayerRole::Goalkeeper {
        return SurpriseBehindStealProfile::default();
    }
    let holder_attack_dir = holder_team.attack_dir();
    let to_defender = defender_position - holder_position;
    let behind_yards = -(to_defender.y * holder_attack_dir);
    let lateral_yards = to_defender.x.abs();
    let distance = defender_position.distance(holder_position);
    let holder_forward_speed = holder_velocity.y * holder_attack_dir;
    let holder_speed = holder_velocity.len();
    if behind_yards < SURPRISE_BEHIND_STEAL_MIN_BEHIND_YARDS
        || lateral_yards > SURPRISE_BEHIND_STEAL_MAX_LATERAL_YARDS
        || distance > SURPRISE_BEHIND_STEAL_MAX_DISTANCE_YARDS
        || holder_forward_speed < SURPRISE_BEHIND_STEAL_MIN_FORWARD_YPS
        || holder_speed > SURPRISE_BEHIND_STEAL_MAX_HOLDER_SPEED_YPS
    {
        return SurpriseBehindStealProfile::default();
    }

    let distance_fit = (1.0
        - (distance - DEFENSIVE_IMMEDIATE_STEAL_CLEAN_RADIUS_YARDS).max(0.0)
            / (SURPRISE_BEHIND_STEAL_MAX_DISTANCE_YARDS
                - DEFENSIVE_IMMEDIATE_STEAL_CLEAN_RADIUS_YARDS)
                .max(1e-6))
    .clamp(0.0, 1.0);
    let behind_fit =
        ((behind_yards - SURPRISE_BEHIND_STEAL_MIN_BEHIND_YARDS) / 4.8).clamp(0.0, 1.0);
    let lateral_fit =
        (1.0 - lateral_yards / SURPRISE_BEHIND_STEAL_MAX_LATERAL_YARDS).clamp(0.0, 1.0);
    let speed_fit = (1.0
        - (holder_speed / SURPRISE_BEHIND_STEAL_MAX_HOLDER_SPEED_YPS).powi(2) * 0.68)
        .clamp(0.18, 1.0)
        * surprise_holder_gait_fit(holder_gait);
    let threat_proximity =
        (distance_fit * 0.55 + behind_fit * 0.25 + lateral_fit * 0.20).clamp(0.0, 1.0);
    let glance = side_glance_threat_metrics(
        holder_team,
        holder_position,
        holder_velocity,
        holder_action_facing,
        holder_skills.vision,
        holder_possession_seconds,
        defender_position,
        threat_proximity,
    );
    let blind_spot = (1.0 - glance.recognition * 0.86).clamp(0.05, 1.0);

    let axis = (holder_position - defender_position).normalized();
    let closing_rate = if axis.len() > 1e-6 {
        (defender_velocity - holder_velocity).dot(axis).max(0.0)
    } else {
        0.0
    };
    let defender_fatigue_factor = fatigue_speed_factor(defender_skills.stamina, defender_fatigue);
    let holder_fatigue_factor = fatigue_speed_factor(holder_skills.stamina, holder_fatigue);
    let defender_chase_speed = (player_top_speed_yps(defender_role, defender_skills)
        * defender_fatigue_factor
        * MovementGait::Sprint.speed_multiplier()
        * (1.0 + ability01(defender_skills.acceleration) * 0.08)
        + closing_rate * 0.35)
        .max(0.45);
    let holder_escape_speed = (player_top_speed_yps(holder_role, holder_skills)
        * holder_fatigue_factor
        * MovementGait::Run.speed_multiplier()
        * (1.0 - glance.control_cost))
        .max(holder_speed);
    let relative_catch_speed = (defender_chase_speed - holder_escape_speed * 0.58).max(0.18);
    let gap_to_steal = (distance - SURPRISE_BEHIND_STEAL_BALL_REACH_YARDS).max(0.0);
    let defender_catch_time_seconds = gap_to_steal / relative_catch_speed;
    let scan_delay =
        ball_holder_head_scan_delay_seconds(180.0, holder_skills.vision).max(DEFAULT_DT_SECONDS);
    let holder_reaction_seconds = (player_pomdp_reaction_delay_seconds(
        holder_skills.vision.max(holder_skills.first_touch),
        holder_fatigue,
    ) + scan_delay * (1.0 - glance.recognition) * 0.65)
        .clamp(0.08, 2.2);
    let catch_margin_seconds = holder_reaction_seconds + SURPRISE_BEHIND_STEAL_CATCH_GRACE_SECONDS
        - defender_catch_time_seconds;
    let catch_fit = ((catch_margin_seconds + 0.18) / 1.05).clamp(0.0, 1.0);

    let defender_steal_skill = ability01(defender_skills.defending) * 0.42
        + ability01(defender_skills.aggression) * 0.22
        + ability01(defender_skills.acceleration) * 0.22
        + ability01(defender_skills.top_speed) * 0.14;
    let holder_security = ability01(holder_skills.dribbling) * 0.36
        + ability01(holder_skills.first_touch) * 0.24
        + ability01(holder_skills.acceleration) * 0.20
        + ability01(holder_skills.vision) * 0.12
        + ability01(holder_skills.strength) * 0.08;
    let skill_edge = ((defender_steal_skill - holder_security + 0.42) / 0.84).clamp(0.0, 1.0);
    let score = (distance_fit * 0.16
        + behind_fit * 0.12
        + lateral_fit * 0.12
        + speed_fit * 0.15
        + catch_fit * 0.22
        + blind_spot * 0.15
        + skill_edge * 0.08)
        .clamp(0.0, 1.0);
    let available = score >= SURPRISE_BEHIND_STEAL_MIN_SCORE
        && catch_fit >= 0.24
        && catch_margin_seconds >= -0.18;
    let escape_pressure =
        (score * (0.32 + glance.recognition * 0.62) + catch_fit * 0.12).clamp(0.0, 1.0);

    SurpriseBehindStealProfile {
        available,
        score,
        catch_margin_seconds,
        defender_catch_time_seconds,
        holder_reaction_seconds,
        holder_blind_spot: blind_spot,
        holder_glance_scan_rate_hz: glance.scan_rate_hz,
        holder_glance_recognition: glance.recognition,
        holder_glance_control_cost: glance.control_cost,
        escape_pressure,
    }
}

fn perception_latency_upper_bound_seconds() -> f64 {
    tunables()
        .pomdp_perception
        .perception_latency_upper_bound_seconds()
}

fn average_player_position_confidence<I>(
    snapshot: &WorldSnapshot,
    observer_id: usize,
    player_ids: I,
) -> f64
where
    I: IntoIterator<Item = usize>,
{
    let mut total = 0.0;
    let mut count = 0usize;
    for player_id in player_ids {
        if let Some(position) = snapshot.player_position(player_id) {
            if let Some(confidence) =
                snapshot.player_position_confidence_for_point(observer_id, position)
            {
                total += confidence;
                count += 1;
            }
        }
    }
    if count == 0 {
        0.0
    } else {
        total / count as f64
    }
}

fn average_player_position_confidence_entries(
    entries: &[PlayerPositionConfidence],
    team: Team,
) -> f64 {
    let mut total = 0.0;
    let mut count = 0usize;
    for entry in entries.iter().filter(|entry| entry.team == team) {
        total += finite_metric(entry.confidence).clamp(0.0, 1.0);
        count += 1;
    }
    if count == 0 {
        0.0
    } else {
        total / count as f64
    }
}

fn look_behind_scan_context_for_observer(
    tick: u64,
    dt_seconds: f64,
    observer: &PlayerSnapshot,
    observer_position: Vec2,
    ball_position: Vec2,
    ball_speed_yps: f64,
) -> LookBehindScanContext {
    let to_ball = ball_position - observer_position;
    if to_ball.len() <= PLAYER_CONTROL_RADIUS_YARDS * 0.6 {
        return LookBehindScanContext::default();
    }
    let Some(action_facing) = facing_bucket_to_vector(observer.action_facing) else {
        return LookBehindScanContext::default();
    };
    let ball_facing = to_ball.normalized();
    if action_facing.normalized().dot(ball_facing) > -0.25 {
        return LookBehindScanContext::default();
    }

    let dt = sane_dt_seconds(dt_seconds, DEFAULT_DT_SECONDS);
    let last_tick = observer
        .last_decision
        .as_ref()
        .map(|decision| decision.mdp_state.tick)
        .unwrap_or(tick.saturating_sub(1));
    let elapsed_ticks = tick.saturating_sub(last_tick).max(1);
    let duration_seconds = (elapsed_ticks as f64 * dt).clamp(dt, 4.0);
    let confidence_bonus = (0.18 + duration_seconds.min(1.2) / 1.2 * 0.24).clamp(0.0, 0.42);
    let moving_ball_risk = (finite_metric(ball_speed_yps).max(0.0) / 14.0).clamp(0.0, 0.65);
    let drift_risk =
        ((duration_seconds / 2.5).clamp(0.0, 1.0) * (0.35 + moving_ball_risk)).clamp(0.0, 1.0);

    LookBehindScanContext {
        active: true,
        duration_seconds,
        confidence_bonus,
        drift_risk,
    }
}

fn position_confidence_for_observer(
    observer: &PlayerSnapshot,
    observer_position: Vec2,
    point: Vec2,
    facing: Option<Vec2>,
    observer_has_ball: bool,
    // Carrier's continuous time on the ball (seconds) for the head-scan confidence
    // lift; `0.0` for non-holders. Inert unless `DD_SOCCER_ENABLE_HEAD_SCAN` is on,
    // so callers passing `0.0` (or the gate being off) keep the flat blind-side floor.
    scan_seconds: f64,
) -> f64 {
    let to_point = point - observer_position;
    let distance = to_point.len();
    if distance <= PLAYER_CONTROL_RADIUS_YARDS * 3.0 {
        return 1.0;
    }

    let range = player_vision_range(observer).max(1.0);
    let distance_confidence = (1.0 - (distance / range).clamp(0.0, 1.8) * 0.52).clamp(0.06, 1.0);
    let facing_confidence = if let Some(facing) = facing {
        let facing = facing.normalized();
        if facing.len() <= 1e-9 || distance <= 1e-9 {
            0.72
        } else {
            let dot = facing.dot(to_point.normalized());
            if observer_has_ball {
                let angle = dot.clamp(-1.0, 1.0).acos().to_degrees();
                // Main's always-on tunables rear/shoulder/core confidence is the
                // base. With head-scan gated on (OFF ⇒ identical), a rear bearing
                // the carrier has had time on the ball to sweep is read more
                // confidently — a glance lifts (never lowers) the base, still
                // capped below a clean shoulder-check.
                let base = ball_holder_head_scan_position_confidence(angle, observer.skills.vision);
                if head_scan_enabled()
                    && scan_seconds > 0.0
                    && angle > ball_holder_shoulder_scan_limit_degrees()
                {
                    let fov_half = ball_holder_shoulder_scan_limit_degrees().to_radians();
                    let coverage = scan_coverage(
                        angle.to_radians(),
                        fov_half,
                        scan_seconds,
                        ability01(observer.skills.vision),
                    );
                    scanned_confidence(coverage, base)
                } else {
                    base
                }
            } else {
                let half_fov_cos = (player_field_of_view(observer).to_radians() * 0.5).cos();
                if dot >= half_fov_cos {
                    1.0
                } else if dot >= 0.0 {
                    0.74
                } else {
                    0.50
                }
            }
        }
    } else {
        0.72
    };

    let confidence = (distance_confidence * facing_confidence).clamp(0.0, 1.0);
    if observer_has_ball && distance <= range {
        confidence.max(facing_confidence)
    } else {
        confidence
    }
}

fn kalman_perception_position_confidence(
    measurement_confidence: f64,
    target_position: Vec2,
    target_velocity: Vec2,
    target_history: &[Vec2],
    dt_seconds: f64,
    in_front: bool,
    observer_has_ball: bool,
) -> f64 {
    let measurement = finite_metric(measurement_confidence).clamp(0.0, 1.0);
    // Escape hatch: when disabled, fall back to the raw (finite-guarded) measurement so the
    // whole filter can be turned off in prod without a rebuild. Default on.
    if !kalman_perception_enabled() {
        return measurement;
    }
    let perception = &tunables().pomdp_perception;
    if target_history.len() < perception.kalman_min_history_samples {
        return measurement;
    }

    let latest = target_history[target_history.len() - 1];
    let previous = target_history[target_history.len() - 2];
    if !latest.x.is_finite()
        || !latest.y.is_finite()
        || !previous.x.is_finite()
        || !previous.y.is_finite()
        || !target_position.x.is_finite()
        || !target_position.y.is_finite()
    {
        return measurement;
    }

    let dt = sane_dt_seconds(dt_seconds, DEFAULT_DT_SECONDS);
    let history_velocity = (latest - previous) / dt;
    if !history_velocity.x.is_finite() || !history_velocity.y.is_finite() {
        return measurement;
    }
    let target_velocity = finite_vec2(target_velocity, history_velocity);
    let blended_velocity = history_velocity * 0.65 + target_velocity * 0.35;
    let prediction =
        if latest.distance(target_position) <= perception.kalman_current_sample_epsilon_yards {
            previous + history_velocity * dt
        } else {
            latest + blended_velocity * dt
        };
    let innovation_yards = prediction.distance(target_position);
    let velocity_disagreement = history_velocity.distance(target_velocity);
    let sigma_yards = (perception.kalman_base_sigma_yards
        + history_velocity.len().clamp(0.0, 12.0) * perception.kalman_speed_sigma_per_yps * dt
        + velocity_disagreement.clamp(0.0, 12.0)
            * perception.kalman_velocity_disagreement_sigma_yards
            * dt)
        .clamp(0.55, 5.0);
    let prediction_fit = (1.0 / (1.0 + (innovation_yards / sigma_yards).powi(2))).clamp(0.0, 1.0);
    if prediction_fit <= 0.0 {
        return measurement;
    }

    let prediction_cap = if measurement >= perception.ball_holder_shoulder_confidence {
        perception.kalman_visible_max_confidence
    } else if in_front {
        perception.kalman_front_max_confidence
    } else if observer_has_ball {
        perception.kalman_ball_holder_occluded_max_confidence
    } else {
        perception.kalman_occluded_max_confidence
    };
    let predicted_confidence = prediction_fit.min(prediction_cap);
    let prediction_uncertainty = (1.0 - predicted_confidence).clamp(0.04, 0.96);
    let measurement_uncertainty = (1.0 - measurement).clamp(0.04, 0.96);
    let kalman_gain =
        prediction_uncertainty / (prediction_uncertainty + measurement_uncertainty).max(1e-9);
    let posterior = predicted_confidence + kalman_gain * (measurement - predicted_confidence);

    posterior.max(measurement).clamp(0.0, 1.0)
}

fn pass_would_be_cross(
    from: Vec2,
    target: Vec2,
    team: Team,
    field_width: f64,
    field_length: f64,
) -> bool {
    let attacking_third = match team {
        Team::Home => from.y > field_length * 0.58 && target.y > field_length * 0.70,
        Team::Away => from.y < field_length * 0.42 && target.y < field_length * 0.30,
    };
    let wide_channel = from.x < field_width * 0.28 || from.x > field_width * 0.72;
    let target_central = target.x > field_width * 0.28 && target.x < field_width * 0.72;
    attacking_third && wide_channel && target_central
}

fn floor_pass_lane_score_for_snapshot(
    snapshot: &WorldSnapshot,
    player: &PlayerSnapshot,
    player_position: Vec2,
    targets: &[usize],
) -> f64 {
    if targets.is_empty() {
        return 0.0;
    }
    let mut total = 0.0;
    let mut count = 0usize;
    for target_id in targets {
        let Some(target) = snapshot.players.iter().find(|p| p.id == *target_id) else {
            continue;
        };
        let target_position = snapshot
            .player_position(target.id)
            .unwrap_or(target.position);
        let distance = player_position.distance(target_position);
        let confidence = snapshot
            .player_position_confidence_for_point(player.id, target_position)
            .unwrap_or(0.0);
        let forward = ((target_position.y - player_position.y) * player.team.attack_dir() / 28.0)
            .clamp(-0.25, 1.0);
        let distance_fit = (1.0 - (distance - 18.0).abs() / 32.0).clamp(0.0, 1.0);
        total += (0.30 + confidence * 0.34 + distance_fit * 0.22 + forward.max(0.0) * 0.14)
            .clamp(0.0, 1.0);
        count += 1;
    }
    if count == 0 {
        0.0
    } else {
        (total / count as f64).clamp(0.0, 1.0)
    }
}

fn aerial_pass_bypass_score_for_snapshot(
    snapshot: &WorldSnapshot,
    player: &PlayerSnapshot,
    player_position: Vec2,
    targets: &[usize],
) -> f64 {
    if targets.is_empty() {
        return 0.0;
    }
    let mut total = 0.0;
    let mut count = 0usize;
    for target_id in targets {
        let Some(target) = snapshot.players.iter().find(|p| p.id == *target_id) else {
            continue;
        };
        let target_position = snapshot
            .player_position(target.id)
            .unwrap_or(target.position);
        let floor_blocked =
            !snapshot.clear_line(player_position, target_position, player.team.other(), 2.5);
        let forward = ((target_position.y - player_position.y) * player.team.attack_dir() / 30.0)
            .clamp(-0.20, 1.0);
        let cross_bonus = if pass_would_be_cross(
            player_position,
            target_position,
            player.team,
            snapshot.field_width,
            snapshot.field_length,
        ) {
            0.18
        } else {
            0.0
        };
        let receiver_air = aerial_duel_skill_from_snapshot(target) * 0.30
            + ability01(target.skills.first_touch) * 0.12;
        let blocked_bonus = if floor_blocked { 0.44 } else { 0.08 };
        total +=
            (blocked_bonus + forward.max(0.0) * 0.18 + receiver_air + cross_bonus).clamp(0.0, 1.0);
        count += 1;
    }
    if count == 0 {
        0.0
    } else {
        (total / count as f64).clamp(0.0, 1.0)
    }
}

fn aerial_pass_interception_risk_for_snapshot(
    snapshot: &WorldSnapshot,
    player: &PlayerSnapshot,
    player_position: Vec2,
    targets: &[usize],
) -> f64 {
    if targets.is_empty() {
        return 0.0;
    }
    let mut total = 0.0;
    let mut count = 0usize;
    for target_id in targets {
        let Some(target) = snapshot.players.iter().find(|p| p.id == *target_id) else {
            continue;
        };
        let target_position = snapshot
            .player_position(target.id)
            .unwrap_or(target.position);
        let distance = player_position.distance(target_position);
        let nearest = snapshot
            .players
            .iter()
            .filter(|p| p.team != player.team)
            .map(|p| {
                snapshot
                    .player_position(p.id)
                    .unwrap_or(p.position)
                    .distance(target_position)
            })
            .fold(f64::INFINITY, f64::min);
        let nearby = snapshot
            .players
            .iter()
            .filter(|p| p.team != player.team)
            .filter(|p| {
                snapshot
                    .player_position(p.id)
                    .unwrap_or(p.position)
                    .distance(target_position)
                    <= 8.5
            })
            .count() as f64;
        let floor_like_risk =
            (0.05 + (1.0 - nearest / 16.0).clamp(0.0, 1.0) * 0.22 + nearby.min(4.0) * 0.045)
                .clamp(0.0, 0.45);
        let air_multiplier = if nearest <= 8.5 { 2.6 } else { 2.0 };
        let receiver_air = aerial_duel_skill_from_snapshot(target) * 0.62
            + ability01(target.skills.first_touch) * 0.20;
        let distance_risk = (distance / 48.0).clamp(0.0, 1.0) * 0.12;
        total += (floor_like_risk * air_multiplier + (1.0 - receiver_air) * 0.16 + distance_risk)
            .clamp(0.0, 1.0);
        count += 1;
    }
    if count == 0 {
        0.0
    } else {
        (total / count as f64).clamp(0.0, 1.0)
    }
}

/// POMDP signal for the aerial-OOB loop: how safely a lofted ball to `target_id` would land
/// inside the pitch. The aerial calibration lands the ball ~on the target, so the landing is
/// the receiver's point nudged a little further along the pass line (the natural firm-up /
/// drag overhit — exactly the ball that sails out). Returns 1.0 when that point sits a
/// comfortable margin inside every boundary, ramping to 0.0 as it reaches a touchline /
/// byline. Cheap geometry; missing target ⇒ 1.0 so no aerial is suppressed by accident.
pub(crate) fn aerial_pass_landing_safety_for_snapshot(
    snapshot: &WorldSnapshot,
    origin: Vec2,
    target_id: usize,
) -> f64 {
    let Some(target) = snapshot.players.iter().find(|p| p.id == target_id) else {
        return 1.0;
    };
    let target_position = snapshot
        .player_position(target_id)
        .unwrap_or(target.position);
    let to_target = target_position - origin;
    if to_target.len() <= 1e-6 {
        return 1.0;
    }
    let landing =
        target_position + to_target.normalized() * AERIAL_PASS_OOB_LANDING_SAFETY_MARGIN_YARDS;
    let margin = landing
        .x
        .min(snapshot.field_width - landing.x)
        .min(landing.y)
        .min(snapshot.field_length - landing.y);
    // A landing on/over a boundary is 0 (max risk); a few yards inside is fully safe.
    let ramp = (AERIAL_PASS_OOB_LANDING_SAFETY_MARGIN_YARDS * 2.4).max(1.0);
    (margin / ramp).clamp(0.0, 1.0)
}

/// MPC/execution guard for the aerial-OOB feature: cap a lofted ball's launch SPEED so its
/// gravity-fixed carry lands at least `AERIAL_PASS_OOB_LANDING_SAFETY_MARGIN_YARDS` inside the
/// nearest pitch boundary along the launch direction. The aim point (already clamped to the
/// pitch by the caller) and thus the pass DIRECTION are preserved; only an over-cooked pace
/// that would sail the ball out is trimmed. Returns the speed unchanged when the natural
/// landing is already safely in-field, when the geometry is degenerate, or for a ball struck
/// from the boundary back into the field. Gate-checked by the caller.
pub(crate) fn aerial_pass_in_bounds_launch_speed(
    origin: Vec2,
    aim: Vec2,
    speed_yps: f64,
    reference_distance_yards: f64,
    flight: PassFlight,
    field_width: f64,
    field_length: f64,
) -> f64 {
    if !speed_yps.is_finite() || speed_yps <= 0.0 {
        return speed_yps;
    }
    let dir = aim - origin;
    if dir.len() <= 1e-6 {
        return speed_yps;
    }
    let dir = dir.normalized();
    let apex = if flight.is_over_top() {
        tunables().killer_pass_over_top.height_yards
    } else {
        lofted_pass_apex_yards(reference_distance_yards.max(0.1))
    };
    let hang_time = 2.0 * (2.0 * apex / GRAVITY_YPS2).sqrt();
    if hang_time <= 1e-3 {
        return speed_yps;
    }
    let margin = AERIAL_PASS_OOB_LANDING_SAFETY_MARGIN_YARDS;
    let max_x = (field_width - margin).max(margin);
    let max_y = (field_length - margin).max(margin);
    let min_x = margin.min(max_x);
    let min_y = margin.min(max_y);
    // Distance along `dir` until the launch ray reaches the inset rectangle edge.
    let mut max_carry = f64::INFINITY;
    if dir.x > 1e-9 {
        max_carry = max_carry.min((max_x - origin.x) / dir.x);
    } else if dir.x < -1e-9 {
        max_carry = max_carry.min((min_x - origin.x) / dir.x);
    }
    if dir.y > 1e-9 {
        max_carry = max_carry.min((max_y - origin.y) / dir.y);
    } else if dir.y < -1e-9 {
        max_carry = max_carry.min((min_y - origin.y) / dir.y);
    }
    if !max_carry.is_finite() || max_carry <= 0.0 {
        return speed_yps;
    }
    // Invert the landing calibration (`land_at_target = distance / hang_time * drag_comp`):
    // the pace whose gravity-fixed carry lands at `max_carry`.
    let speed_cap = max_carry * AERIAL_LAND_AT_TARGET_DRAG_COMP / hang_time;
    if !speed_cap.is_finite() {
        return speed_yps;
    }
    speed_yps.min(speed_cap.max(0.0))
}

#[derive(Clone, Copy, Debug, Default)]
pub(crate) struct PassLaneInterceptionRisk {
    pub(crate) risk: f64,
    pub(crate) clear_now: bool,
    pub(crate) clear_next_seconds: bool,
    pub(crate) nearest_lane_margin_yards: f64,
    pub(crate) earliest_arrival_margin_seconds: f64,
}

#[derive(Clone, Copy, Debug, Default)]
pub(crate) struct LongAerialBoundsRisk {
    pub(crate) risk: f64,
    pub(crate) margin_yards: f64,
    pub(crate) inward_correction_yards: f64,
}

pub(crate) fn long_aerial_safe_in_bounds_target(
    target: Vec2,
    field_width: f64,
    field_length: f64,
) -> Vec2 {
    let width = field_width.max(1.0);
    let length = field_length.max(1.0);
    let touch_margin = LONG_AERIAL_BOUNDS_SAFE_TOUCHLINE_MARGIN_YARDS.min(width * 0.45);
    let byline_margin = LONG_AERIAL_BOUNDS_SAFE_BYLINE_MARGIN_YARDS.min(length * 0.45);
    Vec2::new(
        target.x.clamp(touch_margin, width - touch_margin),
        target.y.clamp(byline_margin, length - byline_margin),
    )
}

pub(crate) fn long_aerial_bounds_risk_for_target(
    origin: Vec2,
    target: Vec2,
    field_width: f64,
    field_length: f64,
    flight: PassFlight,
) -> LongAerialBoundsRisk {
    if !flight.is_aerial() {
        return LongAerialBoundsRisk::default();
    }
    let distance = origin.distance(target);
    if distance < LONG_AERIAL_BOUNDS_MIN_DISTANCE_YARDS {
        return LongAerialBoundsRisk::default();
    }
    let width = field_width.max(1.0);
    let length = field_length.max(1.0);
    let killer_pass_over_top = tunables().killer_pass_over_top;
    let safe_touchline_margin = if flight.is_over_top() {
        killer_pass_over_top
            .touchline_margin_yards
            .min(width * KILLER_PASS_OVER_TOP_PITCH_MARGIN_CAP_FACTOR)
    } else {
        LONG_AERIAL_BOUNDS_SAFE_TOUCHLINE_MARGIN_YARDS.min(width * 0.45)
    };
    let safe_byline_margin = if flight.is_over_top() {
        killer_pass_over_top
            .byline_margin_yards
            .min(length * KILLER_PASS_OVER_TOP_PITCH_MARGIN_CAP_FACTOR)
    } else {
        LONG_AERIAL_BOUNDS_SAFE_BYLINE_MARGIN_YARDS.min(length * 0.45)
    };
    let x_margin = target.x.min(width - target.x);
    let y_margin = target.y.min(length - target.y);
    let margin_yards = x_margin.min(y_margin);
    let safe_target = Vec2::new(
        target
            .x
            .clamp(safe_touchline_margin, width - safe_touchline_margin),
        target
            .y
            .clamp(safe_byline_margin, length - safe_byline_margin),
    );
    let inward_correction_yards = target.distance(safe_target);
    let touch_deficit =
        ((safe_touchline_margin - x_margin) / safe_touchline_margin.max(1e-6)).clamp(0.0, 1.0);
    let byline_deficit =
        ((safe_byline_margin - y_margin) / safe_byline_margin.max(1e-6)).clamp(0.0, 1.0);
    let distance_fit = ((distance - LONG_AERIAL_BOUNDS_MIN_DISTANCE_YARDS)
        / (LONG_AERIAL_BOUNDS_REFERENCE_DISTANCE_YARDS - LONG_AERIAL_BOUNDS_MIN_DISTANCE_YARDS)
            .max(1.0))
    .clamp(0.0, 1.0);
    let risk = touch_deficit
        .max(byline_deficit)
        .max((inward_correction_yards / LONG_AERIAL_BOUNDS_REFERENCE_MARGIN_YARDS).clamp(0.0, 1.0))
        * (0.35 + distance_fit * 0.65);
    LongAerialBoundsRisk {
        risk: risk.clamp(0.0, 1.0),
        margin_yards,
        inward_correction_yards,
    }
}

#[derive(Clone, Copy, Debug, Default)]
pub(crate) struct PassTargetQuality {
    receiver_openness: f64,
    expected_completion: f64,
    stride_fit: f64,
    /// Dynamic lane-interception risk AT the speed the velocity plan chose (0 clear … 1
    /// blocked). With the learnable-velocity layer ON this is the risk of a ball struck at
    /// `chosen_speed_yps`, so a lane that only a driven ball threads reads as lower risk
    /// here than the legacy fixed-0.68 evaluation did.
    lane_interception_risk: f64,
    /// Launch speed (yps) the value trade-off picked for this pass (see
    /// [`pass_velocity_plan_for_snapshot`]). Equals the legacy nominal (0.68 power) speed
    /// when the learnable layer is disabled.
    chosen_speed_yps: f64,
    /// MPC feasibility floor: the slowest pace that actually clears the corridor. The
    /// execution layer firms a contested ball up to this so the struck pass matches the
    /// decision.
    min_clearing_speed_yps: f64,
    backward_path_opponent_count: usize,
    backward_path_traffic_risk: f64,
    backward_path_traffic_penalty: f64,
    mpc_receipt_probability: f64,
    mpc_receipt_race_advantage_seconds: f64,
    mpc_receipt_qp_accel_fit: f64,
    long_aerial_bounds_risk: f64,
    long_aerial_bounds_margin_yards: f64,
    long_aerial_bounds_inward_correction_yards: f64,
    /// Straight-line passer→receiver distance (yards) for this target. Carried so the
    /// observation can expose the LENGTH of the best floor pass (the `max_by` on
    /// `expected_completion` keeps this for the selected target), letting the own-half
    /// short-pass discipline tell a short square ball from a progressive one at decision
    /// time. `0.0` on a default/no-pass quality.
    distance_yards: f64,
}

#[derive(Clone, Copy, Debug, Default)]
struct BackwardPassPathTraffic {
    opponent_count: usize,
    risk: f64,
    score_penalty: f64,
}

fn backward_pass_path_traffic_for_snapshot(
    snapshot: &WorldSnapshot,
    passer: &PlayerSnapshot,
    passer_position: Vec2,
    target_point: Vec2,
) -> BackwardPassPathTraffic {
    let forward_yards = (target_point.y - passer_position.y) * passer.team.attack_dir();
    if !forward_yards.is_finite() || forward_yards >= -BACKWARD_PASS_MIN_FORWARD_YARDS {
        return BackwardPassPathTraffic::default();
    }
    let priced_risk_units = (backward_pass_distance_risk_units(forward_yards)
        - backward_pass_distance_risk_units(-BACKWARD_PASS_PATH_TRAFFIC_FREE_YARDS))
    .max(0.0);
    if priced_risk_units <= 0.0 {
        return BackwardPassPathTraffic::default();
    }
    if passer_position.distance(target_point) <= 1e-6 {
        return BackwardPassPathTraffic::default();
    }
    let opponent_count = snapshot
        .players
        .iter()
        .filter(|player| player.team == passer.team.other())
        .filter(|player| {
            let position = snapshot
                .player_position(player.id)
                .unwrap_or(player.position);
            let along = segment_projection_factor(passer_position, target_point, position);
            (BACKWARD_PASS_PATH_TRAFFIC_ENDPOINT_FRACTION
                ..=(1.0 - BACKWARD_PASS_PATH_TRAFFIC_ENDPOINT_FRACTION))
                .contains(&along)
                && segment_distance_to_point(passer_position, target_point, position)
                    <= BACKWARD_PASS_PATH_TRAFFIC_RADIUS_YARDS
        })
        .count();
    if opponent_count == 0 {
        return BackwardPassPathTraffic::default();
    }
    let scaled = opponent_count as f64 * priced_risk_units;
    BackwardPassPathTraffic {
        opponent_count,
        risk: (scaled * BACKWARD_PASS_PATH_TRAFFIC_RISK_PER_OPPONENT_RISK_UNIT).clamp(0.0, 0.95),
        score_penalty: scaled * BACKWARD_PASS_PATH_TRAFFIC_SCORE_PENALTY_PER_OPPONENT_RISK_UNIT,
    }
}

#[derive(Clone, Copy, Debug, Default)]
struct PassMpcReceiptEstimate {
    probability: f64,
    race_advantage_seconds: f64,
    qp_accel_fit: f64,
}

const PASS_PERCEPTION_OPPONENT_LANE_RADIUS_YARDS: f64 = 8.0;
const PASS_PERCEPTION_OPPONENT_TARGET_RADIUS_YARDS: f64 = 12.0;
const PASS_PERCEPTION_DISTANCE_FULL_DEGRADE_YARDS: f64 = 62.0;
const PASS_PERCEPTION_LATENCY_FULL_DEGRADE_SECONDS: f64 = 0.28;

#[derive(Clone, Copy, Debug)]
struct PassPerceptionExecutionContext {
    receiver_confidence: f64,
    opponent_uncertainty: f64,
    occlusion_score: f64,
    noise_yards: f64,
    latency_seconds: f64,
    distance_yards: f64,
}

fn pass_perception_execution_context(
    snapshot: &WorldSnapshot,
    passer: &PlayerSnapshot,
    passer_position: Vec2,
    target: &PlayerSnapshot,
    target_position: Vec2,
    target_point: Vec2,
) -> PassPerceptionExecutionContext {
    let receiver_entry = snapshot.player_position_confidence_entry(passer.id, target);
    let receiver_confidence = receiver_entry
        .as_ref()
        .map(|entry| entry.confidence)
        .or_else(|| snapshot.player_position_confidence_for_point(passer.id, target_position))
        .unwrap_or(1.0)
        .clamp(0.0, 1.0);
    let mut occlusion_score = receiver_entry
        .as_ref()
        .map(|entry| entry.occlusion_score)
        .unwrap_or(0.0)
        .clamp(0.0, 1.0);
    let mut noise_yards = receiver_entry
        .as_ref()
        .map(|entry| entry.noise_yards)
        .unwrap_or(0.0)
        .max(0.0);
    let mut latency_seconds = receiver_entry
        .as_ref()
        .map(|entry| entry.latency_seconds)
        .unwrap_or(PERCEPTION_LATENCY_BASE_SECONDS)
        .max(PERCEPTION_LATENCY_BASE_SECONDS);
    let mut opponent_uncertainty = 0.0_f64;

    for opponent in snapshot
        .players
        .iter()
        .filter(|player| player.team == passer.team.other())
    {
        let position = snapshot
            .player_position(opponent.id)
            .unwrap_or(opponent.position);
        let along = segment_projection_factor(passer_position, target_point, position);
        let lane_gap = segment_distance_to_point(passer_position, target_point, position);
        let lane_weight = if (0.0..=1.0).contains(&along) {
            (1.0 - lane_gap / PASS_PERCEPTION_OPPONENT_LANE_RADIUS_YARDS).clamp(0.0, 1.0)
        } else {
            0.0
        };
        let target_weight = (1.0
            - position.distance(target_point) / PASS_PERCEPTION_OPPONENT_TARGET_RADIUS_YARDS)
            .clamp(0.0, 1.0)
            * 0.85;
        let proximity = lane_weight.max(target_weight);
        if proximity <= 1e-9 {
            continue;
        }
        if let Some(entry) = snapshot.player_position_confidence_entry(passer.id, opponent) {
            let uncertainty = (1.0 - entry.confidence.clamp(0.0, 1.0)) * proximity;
            opponent_uncertainty = opponent_uncertainty.max(uncertainty);
            occlusion_score =
                occlusion_score.max(entry.occlusion_score.clamp(0.0, 1.0) * proximity);
            noise_yards = noise_yards.max(entry.noise_yards.max(0.0) * proximity);
            latency_seconds = latency_seconds.max(entry.latency_seconds.max(0.0) * proximity);
        }
    }

    PassPerceptionExecutionContext {
        receiver_confidence,
        opponent_uncertainty: opponent_uncertainty.clamp(0.0, 1.0),
        occlusion_score,
        noise_yards,
        latency_seconds,
        distance_yards: passer_position.distance(target_point).max(0.0),
    }
}

fn pass_perception_execution_gate(context: &PassPerceptionExecutionContext) -> f64 {
    let receiver_uncertainty = (1.0 - context.receiver_confidence.clamp(0.0, 1.0)).clamp(0.0, 1.0);
    let distance =
        (context.distance_yards / PASS_PERCEPTION_DISTANCE_FULL_DEGRADE_YARDS).clamp(0.0, 1.0);
    let noise = (context.noise_yards / PERCEPTION_NOISE_MAX_YARDS).clamp(0.0, 1.0);
    let latency = ((context.latency_seconds - PERCEPTION_LATENCY_BASE_SECONDS)
        / PASS_PERCEPTION_LATENCY_FULL_DEGRADE_SECONDS)
        .clamp(0.0, 1.0);
    let degradation = receiver_uncertainty * (0.24 + distance * 0.18)
        + context.opponent_uncertainty.clamp(0.0, 1.0) * 0.24
        + context.occlusion_score.clamp(0.0, 1.0) * 0.12
        + noise * 0.16
        + latency * 0.12;
    (1.0 - degradation).clamp(0.42, 1.0)
}

fn pass_perception_completion_gate(context: &PassPerceptionExecutionContext) -> f64 {
    (0.55 + pass_perception_execution_gate(context) * 0.45).clamp(0.55, 1.0)
}

