#[derive(Clone, Copy, Debug, Default)]
pub(crate) struct MpcBallControlExecutionFit {
    pub(crate) probability: f64,
    pub(crate) qp_accel_fit: f64,
    pub(crate) velocity_match: f64,
    pub(crate) facing_fit: f64,
    pub(crate) miscontrol_risk: f64,
}

#[derive(Clone, Copy, Debug, Default)]
pub(crate) struct LooseBallControlDecision {
    pub(crate) trap_now: bool,
    pub(crate) target: Vec2,
    pub(crate) trap_now_score: f64,
    pub(crate) let_run_score: f64,
    pub(crate) mpc_control_probability: f64,
    pub(crate) miscontrol_risk: f64,
}

fn bounded_accel_qp_control_fit(
    position: Vec2,
    velocity: Vec2,
    target_point: Vec2,
    horizon_seconds: f64,
    acceleration_cap_yps2: f64,
    control_radius_yards: f64,
    effort_weight: f64,
) -> f64 {
    let horizon = horizon_seconds.clamp(0.10, 3.5);
    let accel_cap = acceleration_cap_yps2.clamp(0.5, 16.0);
    let control_radius = control_radius_yards.clamp(0.35, 3.2);
    let effort_weight = effort_weight.clamp(0.0, 0.35);
    let drift = position + velocity * horizon;
    let error = drift - target_point;
    if error.len() <= control_radius * 0.65 {
        return 1.0;
    }
    let coeff = 0.5 * horizon * horizon;
    let quad = 2.0 * (coeff * coeff + effort_weight);
    let program = QuadraticProgram {
        q: vec![vec![quad, 0.0], vec![0.0, quad]],
        c: vec![2.0 * coeff * error.x, 2.0 * coeff * error.y],
        lb: Some(vec![Some(-accel_cap), Some(-accel_cap)]),
        ub: Some(vec![Some(accel_cap), Some(accel_cap)]),
        var_names: Some(vec!["ax".to_string(), "ay".to_string()]),
        ..QuadraticProgram::default()
    };
    let solution = solve_qp_active_set(
        &program,
        QPOptions {
            tol: 1e-7,
            max_active_sets: 64,
        },
    );
    let accel = if solution.status == QPStatus::Optimal && solution.x.len() >= 2 {
        Vec2::new(solution.x[0], solution.x[1])
    } else {
        let needed = (target_point - drift) * (1.0 / coeff.max(1e-6));
        limit_vec2_len(needed, accel_cap)
    };
    let solved_position = drift + accel * coeff;
    let miss_yards = solved_position.distance(target_point);
    let position_fit = (1.0 - miss_yards / (control_radius * 2.2).max(1.0)).clamp(0.0, 1.0);
    let accel_economy = (1.0 - accel.len() / (accel_cap * 1.414).max(1.0)).clamp(0.0, 1.0);
    (position_fit * 0.74 + accel_economy * 0.26).clamp(0.0, 1.0)
}

pub(crate) fn mpc_ball_control_execution_fit(
    role: PlayerRole,
    skills: &SkillProfile,
    fatigue: f64,
    position: Vec2,
    velocity: Vec2,
    facing_fit: f64,
    control_point: Vec2,
    ball_velocity: Vec2,
    ball_time_seconds: f64,
    control_radius_yards: f64,
) -> MpcBallControlExecutionFit {
    let fatigue_factor = fatigue_speed_factor(skills.stamina, fatigue);
    let top_speed = (player_top_speed_yps(role, skills) * fatigue_factor).max(0.85);
    let distance = position.distance(control_point);
    let horizon = ball_time_seconds
        .max(distance / (top_speed * MovementGait::Sprint.speed_multiplier()).max(0.85))
        .clamp(DEFAULT_DT_SECONDS, 0.90);
    let accel_cap = acceleration_yps2_from_score(skills.acceleration) * fatigue_factor;
    let control_radius =
        control_radius_yards.clamp(0.45, REACTIVE_GROUND_PASS_CONTROL_RADIUS_YARDS);
    let qp_accel_fit = bounded_accel_qp_control_fit(
        position,
        velocity,
        control_point,
        horizon,
        accel_cap,
        control_radius,
        0.055,
    );
    let to_control = control_point - position;
    let closing_fit = if to_control.len() > 1e-6 {
        ((velocity.dot(to_control.normalized()) + 4.0) / 14.0).clamp(0.0, 1.0)
    } else {
        1.0
    };
    let velocity_match =
        (1.0 - ((velocity - ball_velocity).len() / 30.0).clamp(0.0, 1.0)).clamp(0.0, 1.0);
    let skill_fit = (ability01(skills.first_touch) * 0.42
        + ability01(skills.dribbling) * 0.18
        + ability01(skills.acceleration) * 0.26
        + ability01(skills.strength) * 0.14)
        .clamp(0.0, 1.0);
    let probability = (0.04
        + qp_accel_fit * 0.46
        + skill_fit * 0.16
        + facing_fit.clamp(0.0, 1.0) * 0.14
        + velocity_match * 0.13
        + closing_fit * 0.07)
        .clamp(0.0, 0.99);
    MpcBallControlExecutionFit {
        probability,
        qp_accel_fit,
        velocity_match,
        facing_fit: facing_fit.clamp(0.0, 1.0),
        miscontrol_risk: (1.0 - probability).clamp(0.0, 1.0),
    }
}

pub(crate) fn pomdp_loose_ball_control_decision(
    skills: &SkillProfile,
    decision_confidence: f64,
    position: Vec2,
    control_point: Vec2,
    run_on_target: Vec2,
    ball_velocity: Vec2,
    nearest_opponent_distance: f64,
    mpc_fit: MpcBallControlExecutionFit,
    force_trap_urgent: bool,
) -> LooseBallControlDecision {
    let ball_speed = ball_velocity.len();
    if force_trap_urgent || ball_speed <= REACTIVE_GROUND_PASS_MIN_SPEED_YPS {
        return LooseBallControlDecision {
            trap_now: true,
            target: control_point,
            trap_now_score: 1.0,
            let_run_score: 0.0,
            mpc_control_probability: mpc_fit.probability,
            miscontrol_risk: mpc_fit.miscontrol_risk,
        };
    }

    let ball_dir = ball_velocity.normalized();
    let ahead = (run_on_target - control_point).dot(ball_dir);
    let lateral = ((run_on_target - control_point) - ball_dir * ahead).len();
    let run_ahead_fit = ((ahead - POMDP_BALL_CONTROL_LET_RUN_MIN_AHEAD_YARDS)
        / (POMDP_BALL_CONTROL_LET_RUN_AHEAD_FULL_YARDS
            - POMDP_BALL_CONTROL_LET_RUN_MIN_AHEAD_YARDS)
            .max(1e-6))
    .clamp(0.0, 1.0);
    let run_line_fit = (1.0 - lateral / REACTIVE_GROUND_PASS_CONTROL_RADIUS_YARDS).clamp(0.0, 1.0);
    let run_intent = run_ahead_fit * run_line_fit;
    let my_distance = position.distance(control_point);
    let opponent_urgency = if nearest_opponent_distance.is_finite() {
        (1.0 - ((nearest_opponent_distance - my_distance
            + POMDP_BALL_CONTROL_LET_RUN_PRESSURE_MARGIN_YARDS)
            / POMDP_BALL_CONTROL_TRAP_URGENCY_OPPONENT_YARDS)
            .clamp(0.0, 1.0))
        .clamp(0.0, 1.0)
    } else {
        0.0
    };
    let first_touch_risk = 1.0 - ability01(skills.first_touch);
    let confidence = decision_confidence.clamp(0.2, 1.0);
    let let_run_score = (run_intent
        * (mpc_fit.miscontrol_risk * 0.54
            + first_touch_risk * 0.24
            + (ball_speed / 24.0).clamp(0.0, 1.0) * 0.22)
        * (1.0 - opponent_urgency * 0.82)
        * (0.70 + confidence * 0.30))
        .clamp(0.0, 1.0);
    let trap_now_score = (mpc_fit.probability * 0.66
        + opponent_urgency * 0.42
        + ability01(skills.first_touch) * 0.12
        + confidence * 0.10)
        .clamp(0.0, 1.0);
    let trap_now = trap_now_score + POMDP_BALL_CONTROL_TRAP_SCORE_MARGIN >= let_run_score;
    LooseBallControlDecision {
        trap_now,
        target: if trap_now {
            control_point
        } else {
            run_on_target
        },
        trap_now_score,
        let_run_score,
        mpc_control_probability: mpc_fit.probability,
        miscontrol_risk: mpc_fit.miscontrol_risk,
    }
}

fn dribble_mpc_control_estimate_for_snapshot(
    snapshot: &WorldSnapshot,
    _player_id: usize,
    team: Team,
    role: PlayerRole,
    skills: &SkillProfile,
    fatigue: f64,
    current: Vec2,
    velocity: Vec2,
    target: Vec2,
    touch_distance_yards: f64,
) -> DribbleMpcControlEstimate {
    let target = target.clamp_to_pitch(snapshot.field_width, snapshot.field_length);
    let distance = current.distance(target);
    let fatigue_factor = fatigue_speed_factor(skills.stamina, fatigue);
    let top_speed = (player_top_speed_yps(role, skills) * fatigue_factor).max(0.85);
    let accel_cap = acceleration_yps2_from_score(skills.acceleration) * fatigue_factor;
    let horizon = (distance / (top_speed * 0.92).max(0.85)).clamp(0.16, 0.92);
    let control_radius = (PLAYER_CONTROL_RADIUS_YARDS
        * (1.0 + ability01(skills.first_touch) * 0.42 + ability01(skills.dribbling) * 0.18))
        .clamp(0.85, 2.35);
    let qp_accel_fit = bounded_accel_qp_control_fit(
        current,
        velocity,
        target,
        horizon,
        accel_cap,
        control_radius,
        0.045,
    );
    let comfort_space_yards =
        dribble_comfort_space_yards_for_position(role, team, current, snapshot.field_length).max(
            dribble_comfort_space_yards_for_position(role, team, target, snapshot.field_length),
        );
    let mut nearest_target_gap = f64::INFINITY;
    let mut nearest_path_gap = f64::INFINITY;
    let mut opponent_time = f64::INFINITY;
    for opponent in snapshot
        .players
        .iter()
        .filter(|player| player.team == team.other())
    {
        let opponent_position = snapshot
            .player_position(opponent.id)
            .unwrap_or(opponent.position);
        let opponent_velocity = snapshot
            .player_velocity(opponent.id)
            .unwrap_or(opponent.velocity);
        let target_closing =
            dribble_closing_rate_toward_point(opponent_position, opponent_velocity, target);
        let path_projection = segment_projection_factor(current, target, opponent_position);
        let path_point = current + (target - current) * path_projection;
        let path_closing =
            dribble_closing_rate_toward_point(opponent_position, opponent_velocity, path_point);
        nearest_target_gap = nearest_target_gap.min(dribble_comfort_adjusted_gap(
            opponent_position.distance(target),
            target_closing,
            comfort_space_yards,
        ));
        nearest_path_gap = nearest_path_gap.min(dribble_comfort_adjusted_gap(
            segment_distance_to_point(current, target, opponent_position),
            path_closing,
            comfort_space_yards,
        ));
        let opponent_speed = (player_top_speed_yps(opponent.role, &opponent.skills)
            * fatigue_speed_factor(opponent.skills.stamina, opponent.fatigue)
            * MovementGait::Sprint.speed_multiplier())
        .max(0.85);
        opponent_time = opponent_time.min(opponent_position.distance(target) / opponent_speed);
    }
    let nearest_current_gap = snapshot
        .players
        .iter()
        .filter(|player| player.team == team.other())
        .map(|opponent| {
            snapshot
                .player_position(opponent.id)
                .unwrap_or(opponent.position)
                .distance(current)
        })
        .fold(f64::INFINITY, f64::min);
    let pressure = pressure_from_nearest_distance(nearest_current_gap);
    let clearance = nearest_target_gap.min(nearest_path_gap + 0.75);
    let space_margin_yards = dribble_comfort_path_margin_yards(
        clearance,
        role,
        team,
        current,
        target,
        snapshot.field_length,
    );
    let space_fit = ((space_margin_yards + 0.45) / 5.10).clamp(0.0, 1.0);
    let player_time = distance / (top_speed * MovementGait::Sprint.speed_multiplier()).max(0.85);
    let race_advantage = if opponent_time.is_finite() {
        opponent_time - player_time
    } else {
        1.8
    };
    let race_fit = ((race_advantage + 0.22) / 1.55).clamp(0.0, 1.0);
    let touch_fit =
        (1.0 - (touch_distance_yards.max(distance) - distance).abs() / 3.8).clamp(0.25, 1.0);
    let control_skill = (ability01(skills.dribbling) * 0.46
        + ability01(skills.first_touch) * 0.22
        + ability01(skills.acceleration) * 0.22
        + ability01(skills.strength) * 0.10)
        .clamp(0.0, 1.0);
    let control_probability = (0.05
        + qp_accel_fit * 0.34
        + space_fit * 0.25
        + race_fit * 0.16
        + control_skill * 0.17
        + touch_fit * 0.08
        - pressure * 0.18)
        .clamp(0.0, 0.99);
    DribbleMpcControlEstimate {
        control_probability,
        qp_accel_fit,
        space_margin_yards: finite_metric(space_margin_yards),
    }
}

fn pass_receipt_qp_accel_fit(
    receiver_position: Vec2,
    receiver_velocity: Vec2,
    target_point: Vec2,
    ball_time_seconds: f64,
    acceleration_cap_yps2: f64,
) -> f64 {
    let horizon = ball_time_seconds.clamp(0.12, 3.5);
    let accel_cap = acceleration_cap_yps2.clamp(0.5, 16.0);
    let drift = receiver_position + receiver_velocity * horizon;
    let error = drift - target_point;
    if error.len() <= PLAYER_CONTROL_RADIUS_YARDS * 0.65 {
        return 1.0;
    }
    let coeff = 0.5 * horizon * horizon;
    let position_weight = 1.0;
    let effort_weight = 0.035;
    let quad = 2.0 * (position_weight * coeff * coeff + effort_weight);
    let program = QuadraticProgram {
        q: vec![vec![quad, 0.0], vec![0.0, quad]],
        c: vec![
            2.0 * position_weight * coeff * error.x,
            2.0 * position_weight * coeff * error.y,
        ],
        lb: Some(vec![Some(-accel_cap), Some(-accel_cap)]),
        ub: Some(vec![Some(accel_cap), Some(accel_cap)]),
        var_names: Some(vec!["ax".to_string(), "ay".to_string()]),
        ..QuadraticProgram::default()
    };
    let solution = solve_qp_active_set(
        &program,
        QPOptions {
            tol: 1e-7,
            max_active_sets: 64,
        },
    );
    let accel = if solution.status == QPStatus::Optimal && solution.x.len() >= 2 {
        Vec2::new(solution.x[0], solution.x[1])
    } else {
        let needed = (target_point - drift) * (1.0 / coeff.max(1e-6));
        limit_vec2_len(needed, accel_cap)
    };
    let solved_position = drift + accel * coeff;
    let miss_yards = solved_position.distance(target_point);
    let position_fit =
        (1.0 - miss_yards / (PLAYER_CONTROL_RADIUS_YARDS * 2.2).max(1.0)).clamp(0.0, 1.0);
    let accel_economy = (1.0 - accel.len() / (accel_cap * 1.414).max(1.0)).clamp(0.0, 1.0);
    (position_fit * 0.76 + accel_economy * 0.24).clamp(0.0, 1.0)
}

fn pass_mpc_receipt_estimate_for_snapshot(
    snapshot: &WorldSnapshot,
    passer: &PlayerSnapshot,
    passer_position: Vec2,
    target: &PlayerSnapshot,
    target_position: Vec2,
    flight: PassFlight,
    pass_speed_yps: f64,
    target_point: Vec2,
) -> PassMpcReceiptEstimate {
    let distance = passer_position.distance(target_point);
    let ball_time_seconds = if flight.is_aerial() {
        Some(distance / pass_speed_yps.max(1.0))
    } else {
        snapshot.ball_ground_travel_time(distance, pass_speed_yps)
    };
    let Some(ball_time_seconds) = ball_time_seconds else {
        return PassMpcReceiptEstimate {
            probability: 0.0,
            race_advantage_seconds: -2.0,
            qp_accel_fit: 0.0,
        };
    };
    let receiver_velocity = snapshot
        .player_velocity(target.id)
        .unwrap_or(target.velocity);
    let receiver_accel_cap = acceleration_yps2_from_score(target.skills.acceleration)
        * fatigue_speed_factor(target.skills.stamina, target.fatigue);
    let qp_accel_fit = pass_receipt_qp_accel_fit(
        target_position,
        receiver_velocity,
        target_point,
        ball_time_seconds,
        receiver_accel_cap,
    );
    let receiver_sprint_speed = (player_top_speed_yps(target.role, &target.skills)
        * fatigue_speed_factor(target.skills.stamina, target.fatigue)
        * MovementGait::Sprint.speed_multiplier())
    .max(1.0);
    let receiver_time = target_position.distance(target_point) / receiver_sprint_speed;
    let opponent_time = snapshot
        .players
        .iter()
        .filter(|player| player.team == passer.team.other())
        .map(|opponent| {
            let position = snapshot
                .player_position(opponent.id)
                .unwrap_or(opponent.position);
            let sprint_speed = (player_top_speed_yps(opponent.role, &opponent.skills)
                * fatigue_speed_factor(opponent.skills.stamina, opponent.fatigue)
                * MovementGait::Sprint.speed_multiplier())
            .max(1.0);
            position.distance(target_point) / sprint_speed
        })
        .fold(f64::INFINITY, f64::min);
    let race_advantage_seconds = if opponent_time.is_finite() {
        opponent_time - receiver_time
    } else {
        2.0
    };
    let race_fit = ((race_advantage_seconds + 0.30) / 1.80).clamp(0.0, 1.0);
    let receiver_late_seconds = receiver_time - ball_time_seconds;
    let meet_fit = if receiver_late_seconds <= 0.20 {
        (1.0 - (-receiver_late_seconds - 2.0).max(0.0) / 4.0).clamp(0.55, 1.0)
    } else {
        (1.0 - (receiver_late_seconds - 0.20) / 1.35).clamp(0.0, 1.0)
    };
    let aerial_control = if flight.is_aerial() {
        aerial_duel_skill_from_snapshot(target) * 0.36 + ability01(target.skills.first_touch) * 0.20
    } else {
        ability01(target.skills.first_touch) * 0.22
    };
    let direct_opponent_control_risk = if flight.is_aerial() {
        0.0
    } else {
        snapshot.pass_point_direct_opponent_control_risk(
            passer.team,
            target_position,
            passer_position,
            target_point,
            pass_speed_yps,
        )
    };
    let opponent_control_gate = (1.0 - direct_opponent_control_risk * 0.58).clamp(0.34, 1.0);
    let perception_context = pass_perception_execution_context(
        snapshot,
        passer,
        passer_position,
        target,
        target_position,
        target_point,
    );
    let perception_execution_gate = pass_perception_execution_gate(&perception_context);
    let probability =
        (0.06 + qp_accel_fit * 0.38 + meet_fit * 0.22 + race_fit * 0.24 + aerial_control)
            .clamp(0.0, 0.99)
            * opponent_control_gate
            * perception_execution_gate;
    PassMpcReceiptEstimate {
        probability: probability.clamp(0.0, 0.99),
        race_advantage_seconds: finite_metric(
            race_advantage_seconds
                - perception_context.latency_seconds * 0.35
                - perception_context.noise_yards * 0.025,
        ),
        qp_accel_fit: (qp_accel_fit * perception_execution_gate).clamp(0.0, 1.0),
    }
}

/// Whether the learnable pass-velocity layer is live (ON unless disabled by env). When OFF
/// the engine falls back to the legacy single fixed-power (0.68) pass evaluation and
/// execution speed, reproducing the prior behavior byte-for-byte. Set
/// `DD_SOCCER_DISABLE_LEARNABLE_PASS_VELOCITY=1` to disable.
fn dd_soccer_disable_learnable_pass_velocity() -> bool {
    use std::sync::OnceLock;
    static V: OnceLock<bool> = OnceLock::new();
    *V.get_or_init(|| std::env::var("DD_SOCCER_DISABLE_LEARNABLE_PASS_VELOCITY").is_ok())
}

/// Default-on POMDP pass-safety hardening: when the lane, endpoint, or MPC receipt model says a
/// floor pass is likely a direct turnover, compress its policy-facing completion estimate so carry
/// / hold / safer outlets can win. Set `DD_SOCCER_DISABLE_PASS_TURNOVER_SAFETY_HARDENING=1` for A/B.
fn dd_soccer_disable_pass_turnover_safety_hardening() -> bool {
    use std::sync::OnceLock;
    static V: OnceLock<bool> = OnceLock::new();
    *V.get_or_init(|| std::env::var("DD_SOCCER_DISABLE_PASS_TURNOVER_SAFETY_HARDENING").is_ok())
}

/// The power buckets the policy considers for a ground/driven pass, weakest→hardest. A
/// weighted ball (low power) is easy to control but lingers in the lane (high interception
/// risk); a driven ball (high power) threads a contested corridor but is harder to receive.
/// The value trade-off in [`pass_velocity_plan_for_snapshot`] is what the MDP/POMDP value
/// head then learns to weight per situation — the engine never *forbids* a ball through an
/// occupied lane, it prices the speed needed to thread it.
const PASS_VELOCITY_POWER_BUCKETS: [f64; 6] = [0.38, 0.50, 0.62, 0.74, 0.86, 1.0];
/// Below this lane-interception risk a pass is treated as uncontested: the weighted-ball
/// fast path is taken and no speed sweep runs. Small enough that any genuinely threatened
/// lane still sweeps and can be driven.
const PASS_VELOCITY_OPEN_LANE_RISK_EPSILON: f64 = 0.02;

#[derive(Clone, Copy, Debug, Default)]
struct PassVelocityPlan {
    /// Launch speed (yps) the value trade-off selected for this aim point.
    speed_yps: f64,
    /// Equivalent power bucket that produced `speed_yps`.
    power: f64,
    /// Dynamic lane-interception risk AT the chosen speed (0 clear … 1 blocked).
    lane_interception_risk: f64,
    /// MPC feasibility: the slowest bucket speed whose lane risk falls under the
    /// "threadable" threshold — the minimum pace that gets the ball through the corridor.
    /// Equals the hardest bucket speed when no bucket threads it.
    min_clearing_speed_yps: f64,
    /// MPC receipt probability of the receiver controlling the ball at `speed_yps`.
    mpc_receipt_probability: f64,
}

/// Sweep the candidate launch speeds for a ground pass down `from → aim_point` and choose
/// the pace to strike it at. A weighted ball is easy to control but spends longer in the
/// lane; a driven ball threads a contested corridor but is harder to receive. This returns
/// the value-traded choice plus the MPC feasibility floor (the slowest pace that actually
/// clears the corridor), so the engine PRICES the speed needed to beat a defender in the
/// lane rather than vetoing the pass. Aerial flights keep their own gravity-fixed
/// calibration and are evaluated at the single nominal (0.68 power) speed; the legacy path
/// (layer disabled) does the same so OFF reproduces prior behavior exactly.
fn pass_velocity_plan_for_snapshot(
    snapshot: &WorldSnapshot,
    passer: &PlayerSnapshot,
    passer_position: Vec2,
    aim_point: Vec2,
    flight: PassFlight,
    is_cross: bool,
    receiver: Option<(&PlayerSnapshot, Vec2)>,
) -> PassVelocityPlan {
    let nominal = pass_speed_yps_from_power(0.68, flight, is_cross, &passer.skills);
    let receipt_estimate_at = |speed: f64| -> PassMpcReceiptEstimate {
        receiver
            .map(|(target, target_position)| {
                pass_mpc_receipt_estimate_for_snapshot(
                    snapshot,
                    passer,
                    passer_position,
                    target,
                    target_position,
                    flight,
                    speed,
                    aim_point,
                )
            })
            .unwrap_or(PassMpcReceiptEstimate {
                probability: 0.62,
                race_advantage_seconds: 0.0,
                qp_accel_fit: 0.62,
            })
    };
    let stride_fit_at = |speed: f64| -> f64 {
        receiver
            .map(|(target, target_position)| {
                let target_velocity = snapshot
                    .player_velocity(target.id)
                    .unwrap_or(target.velocity);
                pass_into_stride_fit(
                    passer_position,
                    target_position,
                    target_velocity,
                    aim_point,
                    speed,
                    passer.team,
                )
            })
            .unwrap_or(0.62)
    };
    if flight.is_aerial() || dd_soccer_disable_learnable_pass_velocity() {
        let risk = snapshot
            .pass_lane_interception_risk(
                passer_position,
                aim_point,
                passer.team.other(),
                2.5,
                nominal,
                PASS_LANE_DECISION_LOOKAHEAD_SECONDS,
            )
            .risk;
        return PassVelocityPlan {
            speed_yps: nominal,
            power: 0.68,
            lane_interception_risk: risk,
            min_clearing_speed_yps: nominal,
            mpc_receipt_probability: receipt_estimate_at(nominal).probability,
        };
    }
    // Fast path for the common wide-open pass: if even the SLOWEST (most interceptable)
    // bucket faces a negligible lane, no faster bucket can do better (a quicker ball is only
    // ever safer in the lane but harder to receive), so the value trade-off would pick the
    // weighted ball anyway. Return it without sweeping — this keeps an uncontested ball
    // identical to the full-sweep result while skipping 3 buckets × every opponent (the bulk
    // of passes are to open targets, and this runs per candidate during ranking).
    let slowest_speed = pass_speed_yps_from_power(
        PASS_VELOCITY_POWER_BUCKETS[0],
        flight,
        is_cross,
        &passer.skills,
    );
    let slowest_risk = snapshot
        .pass_lane_interception_risk(
            passer_position,
            aim_point,
            passer.team.other(),
            2.5,
            slowest_speed,
            PASS_LANE_DECISION_LOOKAHEAD_SECONDS,
        )
        .risk;
    if slowest_risk < PASS_VELOCITY_OPEN_LANE_RISK_EPSILON && receiver.is_none() {
        return PassVelocityPlan {
            speed_yps: slowest_speed,
            power: PASS_VELOCITY_POWER_BUCKETS[0],
            lane_interception_risk: slowest_risk,
            min_clearing_speed_yps: slowest_speed,
            mpc_receipt_probability: receipt_estimate_at(slowest_speed).probability,
        };
    }
    let hardest_speed = pass_speed_yps_from_power(
        *PASS_VELOCITY_POWER_BUCKETS.last().unwrap(),
        flight,
        is_cross,
        &passer.skills,
    );
    let mut min_clearing = hardest_speed;
    let mut any_clears = false;
    let mut best: Option<(f64, PassVelocityPlan)> = None;
    for &power in PASS_VELOCITY_POWER_BUCKETS.iter() {
        let speed = pass_speed_yps_from_power(power, flight, is_cross, &passer.skills);
        let risk = snapshot
            .pass_lane_interception_risk(
                passer_position,
                aim_point,
                passer.team.other(),
                2.5,
                speed,
                PASS_LANE_DECISION_LOOKAHEAD_SECONDS,
            )
            .risk;
        // The slowest (first) bucket that brings the lane risk under the threadable line is
        // the MPC feasibility floor — the minimum pace to get the ball through.
        if !any_clears && risk < PASS_LANE_DYNAMIC_RISK_HIGH {
            min_clearing = speed;
            any_clears = true;
        }
        let receipt_estimate = receipt_estimate_at(speed);
        let receipt = receipt_estimate.probability;
        let reaches_target_fit =
            if receiver.is_some() && receipt <= 1e-9 && receipt_estimate.qp_accel_fit <= 1e-9 {
                0.0
            } else {
                1.0
            };
        let stride_fit = stride_fit_at(speed) * reaches_target_fit;
        // Value trade-off: thread the lane (low risk) while timing the receiver's run. The
        // stride/MPC receipt terms penalize BOTH under-hit balls the runner overruns and
        // over-hit balls that arrive before the receiver can control them.
        let speed_mph = speed / mph_to_yps(1.0);
        let distance = passer_position.distance(aim_point);
        let first_touch = receiver
            .map(|(target, _)| ability01(target.skills.first_touch))
            .unwrap_or(0.60);
        let comfort_ceiling_mph = (17.0 + distance * 0.92 + first_touch * 8.0).clamp(18.0, 43.0);
        let overhit_penalty = ((speed_mph - comfort_ceiling_mph) / 22.0).max(0.0) * 0.20
            + (power - 0.74).max(0.0) * 0.045;
        let lane_fit = (1.0 - risk.clamp(0.0, 1.0) * 0.92).clamp(0.0, 1.0);
        let control_fit =
            (receipt * 0.50 + stride_fit * 0.34 + receipt_estimate.qp_accel_fit * 0.16)
                .clamp(0.0, 1.0);
        let stop_short_penalty = if reaches_target_fit <= 0.0 {
            0.12 + (1.0 - power).max(0.0) * 0.24
        } else {
            0.0
        };
        let score = lane_fit * control_fit - overhit_penalty - stop_short_penalty;
        if best
            .as_ref()
            .map_or(true, |(best_score, _)| score > *best_score)
        {
            best = Some((
                score,
                PassVelocityPlan {
                    speed_yps: speed,
                    power,
                    lane_interception_risk: risk,
                    min_clearing_speed_yps: speed,
                    mpc_receipt_probability: receipt,
                },
            ));
        }
    }
    let mut plan = best.map(|(_, plan)| plan).unwrap_or(PassVelocityPlan {
        speed_yps: nominal,
        power: 0.68,
        lane_interception_risk: 0.0,
        min_clearing_speed_yps: nominal,
        mpc_receipt_probability: receipt_estimate_at(nominal).probability,
    });
    plan.min_clearing_speed_yps = min_clearing;
    plan
}

fn pass_target_quality_for_snapshot(
    snapshot: &WorldSnapshot,
    passer: &PlayerSnapshot,
    passer_position: Vec2,
    target: &PlayerSnapshot,
    target_position: Vec2,
    flight: PassFlight,
) -> PassTargetQuality {
    pass_target_quality_for_snapshot_inner(
        snapshot,
        passer,
        passer_position,
        target,
        target_position,
        flight,
        true,
    )
}

/// THREADED / killer-pass variant: identical to [`pass_target_quality_for_snapshot`] but WITHOUT
/// the dynamic lane-interception-risk completion gate. A killer ball through a congested defence is
/// risky by nature; that risk is priced into the killer-pass SCORE (and the assessment's own
/// ground-lane / loft-corridor checks), and must NOT crush its `expected_completion` below the
/// selection floor — doing so hides the option entirely (the bug that regressed killer-pass
/// selection near goal). `lane_interception_risk` is still computed and returned so the threaded
/// caller can price it itself.
fn pass_target_quality_for_snapshot_threaded(
    snapshot: &WorldSnapshot,
    passer: &PlayerSnapshot,
    passer_position: Vec2,
    target: &PlayerSnapshot,
    target_position: Vec2,
    flight: PassFlight,
) -> PassTargetQuality {
    pass_target_quality_for_snapshot_inner(
        snapshot,
        passer,
        passer_position,
        target,
        target_position,
        flight,
        false,
    )
}

fn pass_target_quality_for_snapshot_inner(
    snapshot: &WorldSnapshot,
    passer: &PlayerSnapshot,
    passer_position: Vec2,
    target: &PlayerSnapshot,
    target_position: Vec2,
    flight: PassFlight,
    apply_dynamic_lane_risk_gate: bool,
) -> PassTargetQuality {
    // Per-tick memo choke point. A single carrier decision scores the same
    // (passer, target, flight) several times across independent sub-checks; each score
    // runs a nested MPC receipt estimate (QP solves) plus a full-team lane/occupancy scan —
    // the dominant per-tick cost the profiler flags. Collapse the duplicates. The scorer is
    // pure over the immutable `&WorldSnapshot`, so a cache hit is byte-identical to
    // recomputing; the key carries the exact float bits of both positions and the gate flag.
    // See `WorldSnapshot::pass_target_quality_cache` (auto-invalidated: fresh snapshot/tick).
    let key = (
        passer.id,
        target.id,
        flight,
        passer_position.x.to_bits(),
        passer_position.y.to_bits(),
        target_position.x.to_bits(),
        target_position.y.to_bits(),
        apply_dynamic_lane_risk_gate,
    );
    if let Some(cached) = snapshot.pass_target_quality_cache.borrow().get(&key) {
        return *cached;
    }
    let quality = pass_target_quality_for_snapshot_uncached(
        snapshot,
        passer,
        passer_position,
        target,
        target_position,
        flight,
        apply_dynamic_lane_risk_gate,
    );
    snapshot
        .pass_target_quality_cache
        .borrow_mut()
        .insert(key, quality);
    quality
}

fn pass_target_quality_for_snapshot_uncached(
    snapshot: &WorldSnapshot,
    passer: &PlayerSnapshot,
    passer_position: Vec2,
    target: &PlayerSnapshot,
    target_position: Vec2,
    flight: PassFlight,
    apply_dynamic_lane_risk_gate: bool,
) -> PassTargetQuality {
    let initial_is_cross = pass_would_be_cross(
        passer_position,
        target_position,
        passer.team,
        snapshot.field_width,
        snapshot.field_length,
    );
    let initial_nominal_speed =
        pass_speed_yps_from_power(0.68, flight, initial_is_cross, &passer.skills);
    let target_velocity = snapshot
        .player_velocity(target.id)
        .unwrap_or(target.velocity);
    let initial_anticipated_target = snapshot
        .anticipated_pass_reception_point(passer.id, target.id, flight, initial_nominal_speed)
        .unwrap_or(target_position);
    let is_cross = pass_would_be_cross(
        passer_position,
        initial_anticipated_target,
        passer.team,
        snapshot.field_width,
        snapshot.field_length,
    );
    let pass_skill = pass_execution_skill(&passer.skills, flight, is_cross);
    let nominal_speed = pass_speed_yps_from_power(0.68, flight, is_cross, &passer.skills);
    let anticipated_target = if (nominal_speed - initial_nominal_speed).abs() > 0.5 {
        snapshot
            .anticipated_pass_reception_point(passer.id, target.id, flight, nominal_speed)
            .unwrap_or(initial_anticipated_target)
    } else {
        initial_anticipated_target
    };
    let long_aerial_bounds = long_aerial_bounds_risk_for_target(
        passer_position,
        anticipated_target,
        snapshot.field_width,
        snapshot.field_length,
        flight,
    );
    // Learnable pass velocity: sweep the candidate launch speeds and choose the pace to
    // strike this ball at, given the lane to the anticipated reception point. A contested
    // lane that only a driven ball threads is now scored at that driven speed (lower lane
    // risk, slightly lower receipt) instead of at a fixed weighted 0.68 power — so "drive
    // it through the gap" becomes a scoreable option the value head can learn, not a hidden
    // lane. When the layer is disabled this returns the legacy nominal (0.68) speed and the
    // whole estimate is byte-identical.
    let velocity_plan = pass_velocity_plan_for_snapshot(
        snapshot,
        passer,
        passer_position,
        anticipated_target,
        flight,
        is_cross,
        Some((target, target_position)),
    );
    let effective_pass_speed = velocity_plan.speed_yps;
    let distance = passer_position.distance(anticipated_target);
    let current_receiver_openness = pass_receiver_openness_for_snapshots_with_teammates(
        &snapshot.players,
        passer.team,
        target_position,
        Some(target.id),
    );
    let anticipated_receiver_openness = pass_receiver_openness_for_snapshots_with_teammates(
        &snapshot.players,
        passer.team,
        anticipated_target,
        Some(target.id),
    );
    let target_forward = (anticipated_target.y - passer_position.y) * passer.team.attack_dir();
    let backward_path_traffic = backward_pass_path_traffic_for_snapshot(
        snapshot,
        passer,
        passer_position,
        anticipated_target,
    );
    let anticipation_weight = if target_forward > 2.0 {
        0.38 + pass_skill * 0.34
    } else if target_forward >= -1.25 {
        0.28 + pass_skill * 0.20
    } else {
        0.12 + pass_skill * 0.10
    }
    .clamp(0.12, 0.74);
    let receiver_openness = (current_receiver_openness * (1.0 - anticipation_weight)
        + anticipated_receiver_openness * anticipation_weight)
        .clamp(0.0, 1.0);
    let stride_fit = pass_into_stride_fit(
        passer_position,
        target_position,
        target_velocity,
        anticipated_target,
        nominal_speed,
        passer.team,
    );
    let mpc_receipt = pass_mpc_receipt_estimate_for_snapshot(
        snapshot,
        passer,
        passer_position,
        target,
        target_position,
        flight,
        effective_pass_speed,
        anticipated_target,
    );
    let direct_opponent_control_risk = if flight.is_aerial() {
        0.0
    } else {
        snapshot.pass_point_direct_opponent_control_risk(
            passer.team,
            target_position,
            passer_position,
            anticipated_target,
            effective_pass_speed,
        )
    };
    let perception_context = pass_perception_execution_context(
        snapshot,
        passer,
        passer_position,
        target,
        target_position,
        anticipated_target,
    );
    let position_confidence = snapshot
        .player_position_confidence_for_point(passer.id, target_position)
        .unwrap_or(0.0);
    // Lane clearance is a MULTIPLICATIVE situational gate — "can the ball physically
    // traverse to the receiver" — kept separate from how desirable the target is. A
    // defender physically in the corridor blocks the ball regardless of how open the
    // receiver is downfield, so the block must override target desirability rather than
    // being averaged against it (an additive lane term let an open receiver rescue a
    // blocked lane, reading a ball straight through a set defender as ~0.6 "safe").
    let mut lane_interception_risk = 0.0;
    let mut lane_clearance = if flight.is_aerial() {
        let nearest_interceptor = snapshot
            .players
            .iter()
            .filter(|player| player.team != passer.team)
            .map(|player| {
                snapshot
                    .player_position(player.id)
                    .unwrap_or(player.position)
                    .distance(anticipated_target)
            })
            .fold(f64::INFINITY, f64::min);
        (0.42
            + receiver_openness * 0.18
            + (nearest_interceptor / 16.0).clamp(0.0, 1.0) * 0.16
            + aerial_duel_skill_from_snapshot(target) * 0.16)
            .clamp(0.20, 0.88)
    } else {
        // Movement-aware lane: a defender SITTING in the corridor blocks it now; a
        // defender whose velocity carries them INTO the corridor before the ball
        // passes their point is priced as a partial block. The old static check rated
        // a lane "fully clear" whenever no defender was in it AT DECISION TIME, so the
        // policy perceived a contested ball (a marker one step from the lane) as safe
        // and recycled it straight to the other team under low pressure. Grading the
        // closing defender into the completion estimate is the same fix already used
        // in pass SELECTION (`pass_lane_clearance`), applied here to the policy-facing
        // expected_completion / openness features so perception matches execution.
        let (lane_clear_now, lane_clear_through_flight) = snapshot.pass_lane_clearance(
            passer_position,
            anticipated_target,
            passer.team.other(),
            2.5,
            effective_pass_speed,
        );
        let dynamic_risk = snapshot.pass_lane_interception_risk(
            passer_position,
            anticipated_target,
            passer.team.other(),
            2.5,
            effective_pass_speed,
            PASS_LANE_DECISION_LOOKAHEAD_SECONDS,
        );
        lane_interception_risk = dynamic_risk.risk;
        let base_lane_clearance = if !lane_clear_now {
            // Defender in the corridor now: the ball would have to pass through them.
            // Genuinely low — whether they actually cut it out is left to the simulation.
            0.30
        } else if lane_clear_through_flight {
            1.0
        } else {
            // Clear now but a defender drifts in mid-flight — a real interception risk
            // the static check missed. Priced between blocked and clear (penalty, not veto).
            0.65
        };
        let dynamic_gate = if apply_dynamic_lane_risk_gate {
            (1.0 - lane_interception_risk.clamp(0.0, 1.0) * PASS_LANE_DYNAMIC_RISK_GATE_STRENGTH)
                .clamp(0.18, 1.0)
        } else {
            // Threaded / killer-pass evaluation: don't let the dynamic interception risk crush the
            // completion estimate (it's priced into the killer-pass score instead). Static lane
            // clearance still applies via `base_lane_clearance`.
            1.0
        };
        base_lane_clearance * dynamic_gate
    };
    if backward_path_traffic.risk > 0.0 {
        lane_interception_risk =
            (lane_interception_risk + backward_path_traffic.risk).clamp(0.0, 1.0);
        lane_clearance *= (1.0
            - backward_path_traffic.risk * BACKWARD_PASS_PATH_TRAFFIC_RISK_GATE_STRENGTH)
            .clamp(0.18, 1.0);
    }
    if long_aerial_bounds.risk > 0.0 {
        lane_clearance *= (1.0
            - long_aerial_bounds.risk * LONG_AERIAL_BOUNDS_COMPLETION_GATE_STRENGTH)
            .clamp(0.18, 1.0);
    }
    let distance_fit = if flight.is_aerial() {
        (1.0 - (distance - 32.0).abs() / 58.0).clamp(0.24, 1.0)
    } else {
        (1.0 - (distance - 18.0).abs() / 42.0).clamp(0.20, 1.0)
    };
    let pressure_adjustment = 0.80 + receiver_openness * 0.20;
    // The actual completion is resolved by the SIMULATION (who reaches the rolling ball
    // first — `nearest_ball_controller_for_segment`), never by this scalar. So this
    // decision-time estimate is a PRODUCT of independent factors, each a proxy for part of
    // that physics outcome: target desirability (below) × lane clearance (can the ball get
    // there) × pass precision (skill tightens the release) × pressure. Multiplicative — not
    // additive — so a blocked lane or a marked receiver each pulls the whole estimate down
    // and can't be papered over by another term being high.
    //
    // Skill enters ONLY as the precision multiplier here; its real influence is at the MDP
    // decision (policy/value weighting) and the MPC / execution-noise layer
    // (`noisy_pass_target_*`, `modulated_pass_speed_yps`). We deliberately do NOT collapse
    // the estimate for a slow defender sitting on the line (the old "gift factor"):
    // predicting a CERTAIN interception is as unreliable as predicting a certain completion —
    // whether a sharp/quick opponent actually cuts the ball out is left to the simulation
    // (the lane-clearance gate already prices a defender in the corridor). Previously
    // `pass_skill` was the single largest ADDITIVE term (`* 0.38`); with every player at max
    // skill that was a flat ~0.38 inflation that compressed the open-vs-contested signal and
    // made a contested ball read as safe — i.e. it pre-determined the outcome from skill.
    //
    // Target desirability if the ball gets there: how open the receiver is, the pass
    // distance, how well it's played into the runner's stride, and how sure we are of the
    // target's location.
    let target_quality = 0.16
        + receiver_openness * 0.42
        + distance_fit * 0.24
        + stride_fit * 0.08
        + position_confidence * 0.10;
    let tight_mark_distance =
        snapshot.pass_target_tight_mark_distance(passer.team, target_position, anticipated_target);
    let tight_mark_completion_gate = if tight_mark_distance <= TIGHT_MAN_MARK_RECEIVER_RADIUS_YARDS
    {
        let mark = ((TIGHT_MAN_MARK_RECEIVER_RADIUS_YARDS - tight_mark_distance)
            / TIGHT_MAN_MARK_RECEIVER_RADIUS_YARDS.max(1.0))
        .clamp(0.0, 1.0);
        (1.0 - mark * TIGHT_MAN_MARK_COMPLETION_DAMP).clamp(0.22, 1.0)
    } else {
        1.0
    };
    let pass_precision = 0.80 + pass_skill * 0.20;
    let mpc_receipt_gate = 0.68 + mpc_receipt.probability * 0.32;
    let mut expected_completion = target_quality
        * lane_clearance
        * pass_precision
        * pressure_adjustment
        * mpc_receipt_gate
        * tight_mark_completion_gate
        * pass_perception_completion_gate(&perception_context);
    // Learned pass-completion head (#4): blend the trained P(complete) into the analytic
    // estimate when the gate is on and the carried head has trained enough. The head is
    // conditioned on the 22+ball config along this pass's lane, so it captures completion
    // signal the multiplicative analytic proxy misses. Off / untrained ⇒ analytic stands
    // alone (parity). Same feature builder as the training-capture site, with passer
    // pressure derived from the nearest opponent (the snapshot analogue of the POMDP
    // `perceived_pressure` used at launch).
    if learned_pass_completion_enabled() {
        if let Some(head) = snapshot.pass_completion_head.as_ref() {
            if head.training_steps() >= PASS_COMPLETION_HEAD_MIN_TRAINING_STEPS {
                let passer_pressure = pressure_from_nearest_distance(
                    snapshot.nearest_opponent_distance_at(passer.team, passer_position),
                );
                let features = snapshot.pass_completion_learn_features(
                    passer.team,
                    passer_position,
                    anticipated_target,
                    distance,
                    passer_pressure,
                    receiver_openness,
                    flight,
                );
                if let Some(learned) = head.predict(&features) {
                    let blend_weight = pass_completion_head_blend_weight();
                    expected_completion = expected_completion * (1.0 - blend_weight)
                        + learned.clamp(0.0, 1.0) * blend_weight;
                }
            }
        }
    }
    if !dd_soccer_disable_pass_turnover_safety_hardening() && !flight.is_aerial() {
        let yards_to_goal =
            (passer.team.goal_y(snapshot.field_length) - anticipated_target.y).abs();
        let forward_floor = target_forward > 1.25;
        let final_third_forward = forward_floor && yards_to_goal <= snapshot.field_length / 3.0;
        let lane_risk_floor = if final_third_forward {
            0.74
        } else if forward_floor {
            0.64
        } else {
            0.54
        };
        let lane_gift_risk = ((lane_interception_risk - lane_risk_floor)
            / (1.0 - lane_risk_floor).max(1e-6))
        .clamp(0.0, 1.0);
        let direct_gift_risk = ((direct_opponent_control_risk
            - PASS_TURNOVER_SAFETY_DIRECT_RISK_FLOOR)
            / (1.0 - PASS_TURNOVER_SAFETY_DIRECT_RISK_FLOOR).max(1e-6))
        .clamp(0.0, 1.0);
        let path_gift_risk = lane_gift_risk.max(direct_gift_risk);
        let receipt_gift_risk = ((PASS_TURNOVER_SAFETY_RECEIPT_FLOOR - mpc_receipt.probability)
            / PASS_TURNOVER_SAFETY_RECEIPT_FLOOR.max(1e-6))
        .clamp(0.0, 1.0)
            * path_gift_risk
            * 0.72;
        let gift_risk = path_gift_risk.max(receipt_gift_risk);
        let damp = if final_third_forward {
            PASS_TURNOVER_SAFETY_FINAL_THIRD_FORWARD_DAMP
        } else {
            PASS_TURNOVER_SAFETY_DAMP
        };
        expected_completion *= (1.0 - gift_risk * damp).clamp(0.20, 1.0);
    }
    expected_completion *= backward_pass_completion_multiplier(target_forward);
    PassTargetQuality {
        receiver_openness,
        stride_fit,
        lane_interception_risk,
        chosen_speed_yps: velocity_plan.speed_yps,
        min_clearing_speed_yps: velocity_plan.min_clearing_speed_yps,
        backward_path_opponent_count: backward_path_traffic.opponent_count,
        backward_path_traffic_risk: backward_path_traffic.risk,
        backward_path_traffic_penalty: backward_path_traffic.score_penalty,
        expected_completion: expected_completion.clamp(0.02, 0.98),
        mpc_receipt_probability: mpc_receipt.probability,
        mpc_receipt_race_advantage_seconds: mpc_receipt.race_advantage_seconds,
        mpc_receipt_qp_accel_fit: mpc_receipt.qp_accel_fit,
        long_aerial_bounds_risk: long_aerial_bounds.risk,
        long_aerial_bounds_margin_yards: long_aerial_bounds.margin_yards,
        long_aerial_bounds_inward_correction_yards: long_aerial_bounds.inward_correction_yards,
        distance_yards: passer_position.distance(target_position),
    }
}

/// Evaluate [`pass_target_quality_for_snapshot`] once per target for `flight`, returning the
/// per-target qualities. The `PassTargetQuality` struct carries BOTH `expected_completion`
/// and `stride_fit`, so a caller that needs both (as `observation_for` does, binning them
/// separately) can derive them from a single pass instead of re-running the
/// O(targets × speed-buckets × opponents) MPC pass evaluation twice. Pure refactor: the
/// per-target values and iteration order are identical to the originals.
fn pass_target_qualities_for_snapshot(
    snapshot: &WorldSnapshot,
    player: &PlayerSnapshot,
    player_position: Vec2,
    targets: &[usize],
    flight: PassFlight,
) -> Vec<PassTargetQuality> {
    targets
        .iter()
        .filter_map(|target_id| {
            let target = snapshot.players.iter().find(|p| p.id == *target_id)?;
            let target_position = snapshot
                .player_position(target.id)
                .unwrap_or(target.position);
            Some(pass_target_quality_for_snapshot(
                snapshot,
                player,
                player_position,
                target,
                target_position,
                flight,
            ))
        })
        .collect()
}

/// Best (max) expected completion across already-evaluated `qualities`; `default()` when
/// empty. Byte-identical to the original `.max_by(expected_completion).unwrap_or_default()`.
fn best_pass_quality_from(qualities: &[PassTargetQuality]) -> PassTargetQuality {
    qualities
        .iter()
        .copied()
        .max_by(|a, b| {
            a.expected_completion
                .partial_cmp(&b.expected_completion)
                .unwrap_or(std::cmp::Ordering::Equal)
        })
        .unwrap_or_default()
}

/// Best (max) into-stride fit across already-evaluated `qualities`; `0.0` when empty.
/// Byte-identical to the original `.map(stride_fit).fold(0.0, max)`.
fn best_pass_stride_fit_from(qualities: &[PassTargetQuality]) -> f64 {
    qualities
        .iter()
        .map(|q| q.stride_fit)
        .fold(0.0_f64, f64::max)
}

fn best_pass_target_quality_for_snapshot(
    snapshot: &WorldSnapshot,
    player: &PlayerSnapshot,
    player_position: Vec2,
    targets: &[usize],
    flight: PassFlight,
) -> PassTargetQuality {
    best_pass_quality_from(&pass_target_qualities_for_snapshot(
        snapshot,
        player,
        player_position,
        targets,
        flight,
    ))
}

/// Best pass-into-stride ANTICIPATION available across `targets`, independent of which
/// target offers the highest completion. The observation bins this separately from
/// completion (a safe square ball and an into-stride runner are different signals), so it
/// must not be read off the single best-completion target — otherwise a safer static outlet
/// hides the fact that a runner could be played into space.
fn best_pass_stride_fit_for_snapshot(
    snapshot: &WorldSnapshot,
    player: &PlayerSnapshot,
    player_position: Vec2,
    targets: &[usize],
    flight: PassFlight,
) -> f64 {
    best_pass_stride_fit_from(&pass_target_qualities_for_snapshot(
        snapshot,
        player,
        player_position,
        targets,
        flight,
    ))
}

fn pass_execution_skill(skills: &SkillProfile, flight: PassFlight, is_cross: bool) -> f64 {
    let base = if is_cross {
        ability01(skills.crossing_left.max(skills.crossing_right)) * 0.74
            + ability01(skills.passing_completion_rate) * 0.18
            + ability01(skills.flair_passing) * 0.08
    } else {
        ability01(skills.passing_completion_rate) * 0.72
            + ability01(skills.passing) * 0.20
            + ability01(skills.flair_passing) * 0.08
    };
    if flight.is_aerial() {
        (base * 0.86 + ability01(skills.strength) * 0.08 + ability01(skills.flair_passing) * 0.06)
            .clamp(0.05, 0.99)
    } else {
        base.clamp(0.05, 0.99)
    }
}

fn goalkeeper_flank_width_score(position: Vec2, field_width: f64) -> f64 {
    let center_x = field_width * 0.5;
    let half_width = center_x.max(1.0);
    ((position.x - center_x).abs() / half_width).clamp(0.0, 1.0)
}

fn goalkeeper_backward_emergency_release_allowed(
    team: Team,
    passer_position: Vec2,
    target_position: Vec2,
    field_width: f64,
    pressure: f64,
) -> bool {
    let forward = (target_position.y - passer_position.y) * team.attack_dir();
    if forward >= -1.25 {
        return true;
    }
    if pressure < GOALKEEPER_BACKWARD_EMERGENCY_PRESSURE {
        return false;
    }
    let target_width = goalkeeper_flank_width_score(target_position, field_width);
    let passer_width = goalkeeper_flank_width_score(passer_position, field_width);
    target_width >= GOALKEEPER_FLANK_DISTRIBUTION_MIN_WIDTH && target_width >= passer_width + 0.16
}

fn goalkeeper_distribution_score(
    team: Team,
    passer_position: Vec2,
    target_position: Vec2,
    field_width: f64,
    pressure: f64,
) -> f64 {
    let forward = (target_position.y - passer_position.y) * team.attack_dir();
    let target_width = goalkeeper_flank_width_score(target_position, field_width);
    let passer_width = goalkeeper_flank_width_score(passer_position, field_width);
    let flank_bonus = target_width * 6.4 + (target_width - passer_width).max(0.0) * 2.0;
    // Keepers distribute to the flanks (outer ~25% channels on each side, where
    // target_width >= 0.5). Distributing into the central 50% is heavily
    // discouraged so it stays a rare choice (~80% less common than a flank ball).
    let central_penalty = (1.0 - target_width) * 2.4;
    let central_channel_penalty = if target_width < 0.5 {
        (0.5 - target_width) * 16.0
    } else {
        0.0
    };
    let forward_bonus = forward.max(0.0).min(54.0) * 0.035;
    let backward_penalty = if forward < -1.25 {
        if goalkeeper_backward_emergency_release_allowed(
            team,
            passer_position,
            target_position,
            field_width,
            pressure,
        ) {
            2.8
        } else {
            80.0
        }
    } else {
        0.0
    };
    flank_bonus + forward_bonus - central_penalty - central_channel_penalty - backward_penalty
}

fn goalkeeper_flank_distribution_target(
    team: Team,
    from: Vec2,
    field_width: f64,
    field_length: f64,
    depth_yards: f64,
) -> Vec2 {
    let center_x = field_width * 0.5;
    let side = if from.x <= center_x { -1.0 } else { 1.0 };
    let target_x = (center_x + side * field_width * 0.38).clamp(4.0, field_width - 4.0);
    let territorial_y = from.y + team.attack_dir() * depth_yards;
    let target_y = match team {
        Team::Home => territorial_y
            .max(field_length * 0.38)
            .clamp(6.0, field_length - 8.0),
        Team::Away => territorial_y
            .min(field_length * 0.62)
            .clamp(8.0, field_length - 6.0),
    };
    Vec2::new(target_x, target_y)
}

fn clearance_target_for_actor(
    team: Team,
    from: Vec2,
    field_width: f64,
    field_length: f64,
    role: PlayerRole,
) -> Vec2 {
    if role == PlayerRole::Goalkeeper {
        goalkeeper_flank_distribution_target(team, from, field_width, field_length, 52.0)
    } else {
        clearance_target_for_player(team, from, field_width, field_length)
    }
}

fn route_one_target_for_actor(
    team: Team,
    from: Vec2,
    field_width: f64,
    field_length: f64,
    role: PlayerRole,
) -> Vec2 {
    if role == PlayerRole::Goalkeeper {
        goalkeeper_flank_distribution_target(team, from, field_width, field_length, 64.0)
    } else {
        route_one_target_for_player(team, from, field_width, field_length)
    }
}

fn clearance_target_for_player(
    team: Team,
    from: Vec2,
    field_width: f64,
    field_length: f64,
) -> Vec2 {
    let dir = team.attack_dir();
    let center_x = field_width * 0.5;
    let wide_release = if from.x <= center_x { -12.0 } else { 12.0 };
    let target_x = (from.x + wide_release).clamp(4.0, field_width - 4.0);
    let territorial_y = from.y + dir * 52.0;
    let target_y = match team {
        Team::Home => territorial_y
            .max(field_length * 0.54)
            .clamp(10.0, field_length - 8.0),
        Team::Away => territorial_y
            .min(field_length * 0.46)
            .clamp(8.0, field_length - 10.0),
    };
    Vec2::new(target_x, target_y)
}

fn route_one_target_for_player(
    team: Team,
    from: Vec2,
    field_width: f64,
    field_length: f64,
) -> Vec2 {
    let dir = team.attack_dir();
    let center_x = field_width * 0.5;
    let channel_x = (center_x + (from.x - center_x) * 0.32).clamp(10.0, field_width - 10.0);
    let territorial_y = from.y + dir * 62.0;
    let target_y = match team {
        Team::Home => territorial_y
            .max(field_length * 0.62)
            .clamp(12.0, field_length - 14.0),
        Team::Away => territorial_y
            .min(field_length * 0.38)
            .clamp(14.0, field_length - 12.0),
    };
    Vec2::new(channel_x, target_y)
}

fn incoming_context_from_pass(
    pass: &PendingPass,
    receiver: usize,
    speed_yps: f64,
    received_tick: u64,
) -> IncomingBallContext {
    IncomingBallContext {
        from_player: Some(pass.from),
        target_player: Some(receiver),
        team: Some(pass.team),
        kind: match (pass.flight, pass.is_cross) {
            (PassFlight::Floor, false) => IncomingBallKind::GroundPass,
            (PassFlight::Aerial, false) | (PassFlight::Scoop, _) | (PassFlight::OverTop, false) => {
                IncomingBallKind::AerialPass
            }
            (PassFlight::Floor, true) => IncomingBallKind::Cross,
            (PassFlight::Aerial, true) | (PassFlight::OverTop, true) => {
                IncomingBallKind::AerialCross
            }
        },
        origin: Some(pass.origin),
        intended_target: Some(pass.intended_target),
        speed_yps,
        distance_yards: pass.distance_yards,
        received_tick,
        is_cross: pass.is_cross,
        is_aerial: pass.flight.is_aerial(),
    }
}

fn aerial_interception_multiplier(pass: &PendingPass, ball_position: Vec2) -> f64 {
    if !pass.flight.is_aerial() {
        return 1.0;
    }
    let landing_distance = ball_position.distance(pass.intended_target);
    if landing_distance <= 8.5 {
        2.6
    } else {
        2.0
    }
}

// Gravity in yards/s² (9.81 m/s² ÷ 0.9144 m/yd). The ball is a projectile: its height is
// driven by gravity over TIME, exactly like every other bit of motion in the sim.
const GRAVITY_YPS2: f64 = 9.81 / METERS_PER_YARD;

fn scoop_loft_apex_yards(distance_yards: f64, unit: f64) -> f64 {
    let (apex_min, apex_max) = if scoop_higher_apex_enabled() {
        (
            SCOOP_LOFT_APEX_HIGH_MIN_YARDS,
            SCOOP_LOFT_APEX_HIGH_MAX_YARDS,
        )
    } else {
        (SCOOP_LOFT_APEX_MIN_YARDS, SCOOP_LOFT_APEX_MAX_YARDS)
    };
    let distance_fit = ((distance_yards.max(0.0) - 4.0) / 10.0).clamp(0.0, 1.0);
    (apex_min + distance_fit * 0.84 + unit.clamp(0.0, 1.0) * 0.82).clamp(apex_min, apex_max)
}

/// Apex (peak height, yards) of a lofted NON-scoop pass as a function of its horizontal distance.
/// This is the single source of truth for the loft arc — the launch-speed calibration and the
/// horizontal-speed floor both reference it so they stay consistent. Short lofts peak around ~20ft
/// at 15yd and the apex grows gently to the ~30ft (`MAX_LOFT_APEX_YARDS`) ceiling for the longest
/// balls. Height remains gravity-timed; retaining realistic x-y speed in flight prevents ballooning.
fn lofted_pass_apex_yards(distance_yards: f64) -> f64 {
    (SHORT_LOFT_APEX_YARDS + (distance_yards.max(0.0) - 15.0) * LOFT_APEX_PER_YARD)
        .clamp(LOFT_APEX_MIN_YARDS, MAX_LOFT_APEX_YARDS)
}

/// Apex (yards) of a lofted pass reconstructed from its public [`PendingPassSnapshot`].
/// Mirrors [`pass_loft_apex_yards`] (which reads the internal `PendingPass`) so the
/// aerial-reception descent geometry sees the same arc the ball physics fly.
pub(crate) fn pending_pass_snapshot_apex_yards(pass: &PendingPassSnapshot) -> f64 {
    if pass.flight.is_scoop() {
        let unit = scoop_apex_unit(pass.launch_tick, pass.from);
        scoop_loft_apex_yards(pass.distance_yards, unit)
    } else if pass.flight.is_over_top() {
        tunables().killer_pass_over_top.height_yards
    } else {
        lofted_pass_apex_yards(pass.distance_yards)
    }
}

fn pass_loft_apex_yards(pass: &PendingPass) -> f64 {
    if pass.flight.is_scoop() {
        // A scoop pops over a close blocker and drops onto the receiver, not into a
        // hanging balloon arc. The apex MUST match the one the launch speed was paced from
        // (see `scoop_apex_unit` / `scoop_land_at_target_enabled`) or the ball flies a different
        // hang time than it was struck for and floats; with the fix on, the unit is 0.5.
        let unit = scoop_apex_unit(pass.launch_tick, pass.from);
        scoop_loft_apex_yards(pass.distance_yards, unit)
    } else if pass.flight.is_over_top() {
        tunables().killer_pass_over_top.height_yards
    } else {
        lofted_pass_apex_yards(pass.distance_yards)
    }
}

/// Height of a lofted ball, a plain projectile under gravity as a function of how long it has
/// been in the air. Launched straight up at v = g·T/2, it follows altitude(t) = ½·g·t·(T − t)
/// and lands (altitude 0) at hang time T = 2·√(2·apex/g) — REGARDLESS of horizontal speed.
/// A ball that loses pace to drag still falls on the same gravity schedule; it just lands a
/// little shorter. This is the whole loft model: time in, height out.
fn pass_ball_altitude_yards(pass: &PendingPass, time_aloft_seconds: f64) -> f64 {
    if !pass.flight.is_aerial() {
        return 0.0;
    }
    let apex = pass_loft_apex_yards(pass);
    let hang_time = 2.0 * (2.0 * apex / GRAVITY_YPS2).sqrt();
    let t = time_aloft_seconds.clamp(0.0, hang_time);
    (0.5 * GRAVITY_YPS2 * t * (hang_time - t)).max(0.0)
}

/// Ball height when it reaches a given point on its path. The loft is time-driven, so this
/// converts the point's horizontal progress into an elapsed time (distance covered ÷ launch
/// pace) and feeds the projectile. Used where reception needs the height at a contact spot.
fn pass_altitude_at_point(pass: &PendingPass, point: Vec2) -> f64 {
    let path_len = (pass.intended_target - pass.origin).len();
    let horizontal_traveled = pass_progress_along_path(pass, point) * path_len;
    let time_aloft = horizontal_traveled / pass.launch_speed_yps.max(1.0);
    pass_ball_altitude_yards(pass, time_aloft)
}

fn pass_progress_along_path(pass: &PendingPass, ball_position: Vec2) -> f64 {
    let path = pass.intended_target - pass.origin;
    let denom = path.x * path.x + path.y * path.y;
    if denom <= 1e-9 {
        return 0.0;
    }
    (dot(ball_position - pass.origin, path) / denom).clamp(0.0, 1.0)
}

fn receiver_openness_from_nearest_opponent_distance(distance: f64) -> f64 {
    ((distance - 2.5) / 7.5).clamp(0.0, 1.0)
}

/// How heavily raw receiver openness (space around the receiver) weighs in the
/// recognition blend vs. lane completability; the remainder weights completion.
/// Kept low so a CLEAR, completable lane can carry the recognition even when the
/// receiver's nearest-opponent openness is only moderate.
const FORWARD_OPTION_OPENNESS_WEIGHT: f64 = 0.30;
/// Recognised forward-option quality at/above which a backward/square pass target is
/// demoted in the ranking (a genuinely good forward ball existed, so recycling back is
/// the reported blunder).
const FORWARD_OPTION_RECOGNITION_RANK_THRESHOLD: f64 = 0.50;
/// Score demotion per unit of recognised forward-option quality ABOVE the threshold,
/// applied to a backward pass target. Sized against the own-half short-pass liability
/// (3.4) so a wide-open forward option (~1.0) outweighs a safe recycle.
const FORWARD_OPTION_RECOGNITION_BACKWARD_DEMOTION: f64 = 6.0;

/// Recognition score in `[0, 1]` for how GOOD a forward pass option actually is — a
/// richer signal than raw receiver openness. The legacy `receiver_openness` is only the
/// nearest-opponent distance to the receiver's CURRENT spot, so an advanced teammate on a
/// clear, threadable lane (a trailing/already-beaten defender nominally close) reads as
/// "not open" and the carrier wrongly recycles the ball backward. Blend openness with the
/// lane-aware `expected_completion`, and never report BELOW raw openness so a
/// legacy-open receiver is unaffected (the change only ADDS recognition, never removes).
/// Pure + RNG-free for unit testing.
pub(crate) fn forward_pass_option_quality(receiver_openness: f64, expected_completion: f64) -> f64 {
    let open = receiver_openness.clamp(0.0, 1.0);
    let completion = expected_completion.clamp(0.0, 1.0);
    let lane_aware =
        FORWARD_OPTION_OPENNESS_WEIGHT * open + (1.0 - FORWARD_OPTION_OPENNESS_WEIGHT) * completion;
    open.max(lane_aware)
}

/// Whether the **forward-option recognition** revision is active this process: a richer
/// definition of a "good forward pass option" (lane-aware, not just nearest-opponent
/// distance) feeding the forward-pass-first release and the pass-target ranking, so the
/// carrier recognises and plays an open forward man instead of recycling backward.
/// Default-ON in production (env `DD_SOCCER_ENABLE_FORWARD_OPTION_RECOGNITION=0/false` is
/// the kill switch); default-OFF under test so the option-scoring parity suite stays
/// byte-identical.
pub(crate) fn dd_soccer_enable_forward_option_recognition() -> bool {
    #[cfg(test)]
    {
        soccer_env_flag_enabled("DD_SOCCER_ENABLE_FORWARD_OPTION_RECOGNITION")
    }
    #[cfg(not(test))]
    {
        use std::sync::OnceLock;
        static V: OnceLock<bool> = OnceLock::new();
        *V.get_or_init(|| gate_default_on("DD_SOCCER_ENABLE_FORWARD_OPTION_RECOGNITION"))
    }
}

/// Role-aware pass risk/safety appetite. The MPC/POMDP lane-interception risk
/// (`pass_lane_interception_risk`, a 2-second lookahead — see
/// [`PASS_LANE_DECISION_LOOKAHEAD_SECONDS`]) already QUANTIFIES how dangerous a pass is; this
/// gate changes how that quantity is VALUED by WHO is on the ball and WHERE. Defenders lean
/// into safety (amplify the risk penalty), forwards lean into a slightly higher appetite for a
/// FORWARD ball (mute the risk penalty for forward passes and lift forward-progress weight),
/// especially in the opponent's final third. Sideways/backward balls keep ~full risk pricing so
/// "brave" never means a loose square ball. Default-ON in production now that the ranker and A/B
/// harness share the same gate (`DD_SOCCER_ENABLE_ROLE_PASS_RISK_APPETITE=0/false/no/off` remains
/// the kill switch); default-OFF under test so parity suites stay byte-identical unless opted in.
pub(crate) fn dd_soccer_enable_role_pass_risk_appetite() -> bool {
    #[cfg(test)]
    {
        soccer_env_flag_enabled("DD_SOCCER_ENABLE_ROLE_PASS_RISK_APPETITE")
    }
    #[cfg(not(test))]
    {
        use std::sync::OnceLock;
        static V: OnceLock<bool> = OnceLock::new();
        *V.get_or_init(|| gate_default_on("DD_SOCCER_ENABLE_ROLE_PASS_RISK_APPETITE"))
    }
}

/// A/B MEASUREMENT KNOB (not a gameplay gate). The heuristic match is fully deterministic —
/// skills/positions are keyed on player id and `MatchConfig.seed` is effectively inert — so a
/// multi-seed measurement run produces byte-identical matches (n=1 scenario, no statistical
/// power). When `SOCCER_SEED_VARIED_SKILLS` is set, `default_players` mixes `config.seed` into
/// the per-player skill jitter so each seed is an INDEPENDENT match. Off (default) ⇒
/// byte-identical to the deterministic build. Both A/B arms run with this ON and the same seeds,
/// so skills cancel and the only off-vs-on difference is the feature gate under test.
fn seed_varied_skills_enabled() -> bool {
    std::env::var("SOCCER_SEED_VARIED_SKILLS").is_ok()
}

/// Per-team skill multiplier for an ASYMMETRIC HANDICAP (default 1.0 = no change). Reading it per
/// team lets a trainer weaken one side (e.g. the learner) so it must out-think a stronger
/// opponent — a curriculum lever to break the parity plateau. Env: SOCCER_SKILL_SCALE_HOME /
/// SOCCER_SKILL_SCALE_AWAY. Off by default ⇒ byte-identical to the equal-footing build.
fn soccer_team_skill_scale(team: Team) -> f64 {
    let var = match team {
        Team::Home => "SOCCER_SKILL_SCALE_HOME",
        Team::Away => "SOCCER_SKILL_SCALE_AWAY",
    };
    std::env::var(var)
        .ok()
        .and_then(|v| v.parse::<f64>().ok())
        .filter(|f| f.is_finite() && *f > 0.0)
        .unwrap_or(1.0)
}

fn pass_receiver_openness_for_agents(
    players: &[PlayerAgent],
    receiving_team: Team,
    receiver_position: Vec2,
) -> f64 {
    let nearest = players
        .iter()
        .filter(|player| player.team == receiving_team.other())
        .map(|player| player.position.distance(receiver_position))
        .fold(f64::INFINITY, f64::min);
    receiver_openness_from_nearest_opponent_distance(nearest)
}

fn pass_receiver_openness_for_snapshots(
    players: &[PlayerSnapshot],
    receiving_team: Team,
    receiver_position: Vec2,
) -> f64 {
    let nearest = players
        .iter()
        .filter(|player| player.team == receiving_team.other())
        .map(|player| player.position.distance(receiver_position))
        .fold(f64::INFINITY, f64::min);
    receiver_openness_from_nearest_opponent_distance(nearest)
}

fn pass_receiver_openness_for_snapshots_with_teammates(
    players: &[PlayerSnapshot],
    receiving_team: Team,
    receiver_position: Vec2,
    receiver_id: Option<usize>,
) -> f64 {
    let opponent_openness =
        pass_receiver_openness_for_snapshots(players, receiving_team, receiver_position);
    let nearest_teammate = players
        .iter()
        .filter(|player| player.team == receiving_team)
        .filter(|player| receiver_id != Some(player.id))
        .map(|player| player.position.distance(receiver_position))
        .fold(f64::INFINITY, f64::min);
    let teammate_pressure = teammate_spacing_warning_pressure_from_distance(nearest_teammate);
    (opponent_openness * (1.0 - teammate_pressure * 0.72)).clamp(0.02, 1.0)
}

fn noisy_pass_target(
    from: Vec2,
    target: Vec2,
    passing_skill: f64,
    pressure: f64,
    distance: f64,
    rng: &mut SeededRandom,
) -> Vec2 {
    noisy_pass_target_with_receiver_openness(
        from,
        target,
        passing_skill,
        pressure,
        distance,
        0.50,
        rng,
    )
}

/// Whether the pass-accuracy calibration (zippier + better-threaded passes under pressure, so
/// completion in the crowded opponent's half is realistic rather than punishing) is active. On by
/// default; `DD_SOCCER_DISABLE_PASS_ACCURACY_CALIBRATION` restores the prior model for A/B.
fn pass_accuracy_calibration_enabled() -> bool {
    use std::sync::OnceLock;
    static V: OnceLock<bool> = OnceLock::new();
    *V.get_or_init(|| std::env::var("DD_SOCCER_DISABLE_PASS_ACCURACY_CALIBRATION").is_err())
}

fn noisy_pass_target_with_receiver_openness(
    from: Vec2,
    target: Vec2,
    passing_skill: f64,
    pressure: f64,
    distance: f64,
    receiver_openness: f64,
    _rng: &mut SeededRandom,
) -> Vec2 {
    let dir = (target - from).normalized();
    let lateral = Vec2::new(-dir.y, dir.x);
    let skill_error = 1.0 - passing_skill.clamp(0.05, 0.99);
    let openness = receiver_openness.clamp(0.0, 1.0);
    let receiver_pressure = 1.0 - openness;
    let pressure =
        (pressure * (1.04 - openness * 0.18) + receiver_pressure * 0.22).clamp(0.0, 1.20);
    // A teammate who has opened up (made a good run into space) gets a near-perfect
    // ball: openness sharply shrinks the aim error, so passes to open/opening
    // runners land on target (marked receivers stay contested via receiver_pressure).
    // The more open the receiver, the more reliably the ball finds them.
    let openness_relief = 1.0 - openness * 0.82;
    // Skilled players thread the ball under pressure and to a marked receiver far better than the
    // prior model allowed (which made the crowded opponent's half punishing — ~57% completion vs a
    // realistic ~70%). Cut the pressure / receiver-marking error contributions; the skill-error and
    // distance terms (the bulk of an OPEN own-half pass's tiny error) are untouched, so own-half
    // accuracy is unchanged and the gain lands where the defenders are.
    let (press_scale, recv_press_scale, press_drive, recv_press_drive) =
        if pass_accuracy_calibration_enabled() {
            (0.50, 0.18, 0.24, 0.16)
        } else {
            (0.75, 0.28, 0.36, 0.24)
        };
    let error_scale = (0.35 + distance * 0.020)
        * (0.35 + skill_error * 1.45 + pressure * press_scale)
        * openness_relief
        * (1.0 + receiver_pressure * recv_press_scale);
    let lateral_sign = if target.x >= from.x { 1.0 } else { -1.0 };
    let error_drive =
        (skill_error * 0.58 + pressure * press_drive + receiver_pressure * recv_press_drive
            - openness * 0.42)
            .clamp(0.0, 0.72);
    let lateral_error = lateral_sign * error_scale * error_drive * 0.55;
    let weight_error = -error_scale
        * (skill_error * 0.22 + pressure * 0.12 + receiver_pressure * 0.10).clamp(0.0, 0.34);
    target + lateral * lateral_error + dir * weight_error
}

fn mph_to_yps(mph: f64) -> f64 {
    mph.max(0.0) * YARDS_PER_MILE / SECONDS_PER_HOUR
}

fn shot_power_for_skill(shooting_skill: f64) -> f64 {
    (0.82 + shooting_skill.clamp(0.0, 1.0) * 0.18).clamp(0.82, 1.0)
}

fn shot_power_for_finish_skill(finish_skill: f64) -> f64 {
    (0.78 + finish_skill.clamp(0.0, 1.0) * 0.20).clamp(0.78, 0.98)
}

fn shot_speed_yps_from_power(power: f64, skills: &SkillProfile) -> f64 {
    let shooting = ability01(skills.shooting);
    let foot_power = ability01(
        skills
            .right_foot_shot_power
            .max(skills.left_foot_shot_power),
    );
    let strength = ability01(skills.strength);
    let technique_power = (shooting * 0.42 + foot_power * 0.40 + strength * 0.18).clamp(0.0, 1.0);
    // A real shot on goal travels 40-70mph: even a placed/low-power shot leaves the boot at ~40,
    // and a full-power strike from a powerful technique reaches 70. (Below this is a pass/poke,
    // handled elsewhere — this is the SHOT speed.)
    let mph = SHOT_MIN_SPEED_MPH + power.clamp(0.0, 1.0) * (12.0 + technique_power * 18.0);
    mph_to_yps(mph.clamp(SHOT_MIN_SPEED_MPH, SHOT_MAX_SPEED_MPH))
}

/// Hard-driven launch-speed ceilings (mph) that `power` scales up to in
/// [`pass_speed_yps_from_power`]; a strong, skilled striker overshoots the ceiling by
/// [`PASS_SPEED_CEILING_OVERSHOOT_MPH`]. Sized so a genuinely driven ball is realistic — a
/// ~40mph ground pass, a ~50mph aerial — rather than the old ~34/~46mph caps. Crucially the
/// ground ceiling is set so the hardest power bucket clears
/// [`PASS_FAST_BYPASS_MIN_SPEED_YPS`] (~35mph): the policy can then ELECT a ball driven hard
/// enough to thread a set trap at DECISION time, instead of that relief only emerging from
/// the execution-side speed modulation (which already reached ~42mph).
const GROUND_PASS_CEILING_MPH: f64 = 38.0;
const AERIAL_PASS_CEILING_MPH: f64 = 46.0;
const PASS_SPEED_CEILING_OVERSHOOT_MPH: f64 = 4.0;

fn pass_speed_yps_from_power(
    power: f64,
    flight: PassFlight,
    is_cross: bool,
    skills: &SkillProfile,
) -> f64 {
    // A scoop is a low, short dink over a close defender: slower than a driven aerial but
    // not a balloon. Gravity calibration below still decides the final launch speed.
    if flight.is_scoop() {
        return mph_to_yps(SCOOP_MIN_SPEED_MPH + ability01(skills.flair_passing) * 6.0);
    }
    let passing = ability01(skills.passing_completion_rate);
    let crossing = ability01(skills.crossing_left.max(skills.crossing_right));
    let strength = ability01(skills.strength);
    let skill_power = if is_cross {
        crossing * 0.58 + passing * 0.28 + strength * 0.14
    } else {
        passing * 0.68 + ability01(skills.passing) * 0.20 + strength * 0.12
    }
    .clamp(0.0, 1.0);
    let floor = if flight.is_aerial() {
        14.0
    } else if is_cross {
        10.0
    } else {
        3.0
    };
    let ceiling = if flight.is_aerial() {
        AERIAL_PASS_CEILING_MPH
    } else {
        GROUND_PASS_CEILING_MPH
    };
    let aerial_power_bonus = if flight.is_aerial() { 5.0 } else { 0.0 };
    let mph =
        floor + power.clamp(0.0, 1.0) * (ceiling - floor) + skill_power * 4.0 + aerial_power_bonus;
    mph_to_yps(mph.clamp(3.0, ceiling + PASS_SPEED_CEILING_OVERSHOOT_MPH))
}

const DISCRETIZED_KICK_SPEED_BUCKETS: u8 = 10;
const DISCRETIZED_KICK_DIRECTION_BUCKETS: u8 = 36;
const DISCRETIZED_KICK_DIRECTION_BUCKET_DEGREES: f64 = 10.0;
const DISCRETIZED_KICK_CURVE_MIN_DISTANCE_YARDS: f64 = 10.0;
const DISCRETIZED_KICK_CURVE_MIN_SPEED_MPH: f64 = 18.0;

// Speed envelope (mph) the 10 discrete power buckets span for passes — bracketing all
// pass speeds (ground floor 3 → aerial ceiling + overshoot) so a heuristic pass speed
// always encodes to an in-range bucket. Used to quantize a continuous pass speed into a
// `DiscretizedKickAction` (`discretized_kick_power_for_speed`) and lower it back. See
// `docs/discretized-kick-action-plan.md`.
const DISCRETIZED_KICK_PASS_MIN_SPEED_MPH: f64 = 3.0;
const DISCRETIZED_KICK_PASS_MAX_SPEED_MPH: f64 =
    AERIAL_PASS_CEILING_MPH + PASS_SPEED_CEILING_OVERSHOOT_MPH;

/// Master gate for Phase 0 of the discretized kick action (roadmap Priority 1): route
/// the heuristic pass release through the DISCRETE kick representation — quantize power +
/// direction into buckets, then lower. Off (default) ⇒ the continuous heuristic release
/// stands, byte-identical. On ⇒ a bounded (≤ ½-bucket) quantization; the plumbing later
/// phases swap from heuristic-sourced buckets to learned-head buckets. Read once per
/// process. See `docs/discretized-kick-action-plan.md`.
pub fn dd_soccer_enable_discretized_kick() -> bool {
    #[cfg(test)]
    {
        soccer_env_flag_enabled("DD_SOCCER_ENABLE_DISCRETIZED_KICK")
    }
    #[cfg(not(test))]
    {
        use std::sync::OnceLock;
        static ENABLED: OnceLock<bool> = OnceLock::new();
        *ENABLED.get_or_init(|| soccer_env_flag_enabled("DD_SOCCER_ENABLE_DISCRETIZED_KICK"))
    }
}

#[derive(Clone, Copy, Debug, Default, PartialEq, Eq, Hash, Serialize, Deserialize)]
#[serde(rename_all = "kebab-case")]
pub enum DiscretizedKickCurve {
    #[default]
    None,
    Left,
    Right,
}

impl DiscretizedKickCurve {
    fn lateral_sign(self) -> f64 {
        match self {
            DiscretizedKickCurve::None => 0.0,
            DiscretizedKickCurve::Left => 1.0,
            DiscretizedKickCurve::Right => -1.0,
        }
    }
}

#[derive(Clone, Copy, Debug, Default, PartialEq, Eq, Hash, Serialize, Deserialize)]
#[serde(rename_all = "kebab-case")]
pub enum DiscretizedKickTechnique {
    #[default]
    None,
    InsideFoot,
    OutsideFoot,
}

impl DiscretizedKickTechnique {
    pub(crate) fn as_str(self) -> &'static str {
        match self {
            DiscretizedKickTechnique::None => "none",
            DiscretizedKickTechnique::InsideFoot => "inside-foot",
            DiscretizedKickTechnique::OutsideFoot => "outside-foot",
        }
    }

    pub(crate) fn curl_multiplier(self) -> f64 {
        match self {
            DiscretizedKickTechnique::None => 1.0,
            DiscretizedKickTechnique::InsideFoot => 1.0,
            DiscretizedKickTechnique::OutsideFoot => 1.28,
        }
    }

    fn effective_for_curve(self) -> Self {
        match self {
            DiscretizedKickTechnique::None => DiscretizedKickTechnique::InsideFoot,
            other => other,
        }
    }
}

#[derive(Clone, Copy, Debug, Default, PartialEq, Eq, Hash, Serialize, Deserialize)]
#[serde(rename_all = "kebab-case")]
pub enum DiscretizedKickElevation {
    #[default]
    Floor,
    Aerial,
    Chip,
    Scoop,
}

impl DiscretizedKickElevation {
    fn from_pass_flight(flight: PassFlight) -> Self {
        match flight {
            PassFlight::Floor => DiscretizedKickElevation::Floor,
            PassFlight::Aerial | PassFlight::OverTop => DiscretizedKickElevation::Aerial,
            PassFlight::Scoop => DiscretizedKickElevation::Scoop,
        }
    }

    fn release_altitude_yards(self) -> f64 {
        match self {
            DiscretizedKickElevation::Floor => 0.0,
            DiscretizedKickElevation::Aerial
            | DiscretizedKickElevation::Chip
            | DiscretizedKickElevation::Scoop => BALL_ROLLING_ALTITUDE_YARDS + 0.04,
        }
    }

    fn is_airborne(self) -> bool {
        !matches!(self, DiscretizedKickElevation::Floor)
    }
}

#[derive(Clone, Copy, Debug, PartialEq, Eq, Hash, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct DiscretizedKickAction {
    pub speed_bucket: u8,
    pub direction_bucket: u8,
    #[serde(default)]
    pub curve: DiscretizedKickCurve,
    #[serde(default)]
    pub technique: DiscretizedKickTechnique,
    #[serde(default)]
    pub elevation: DiscretizedKickElevation,
}

impl DiscretizedKickAction {
    pub fn new(
        speed_bucket: u8,
        direction_bucket: u8,
        curve: DiscretizedKickCurve,
        technique: DiscretizedKickTechnique,
        elevation: DiscretizedKickElevation,
    ) -> Self {
        DiscretizedKickAction {
            speed_bucket: speed_bucket.min(DISCRETIZED_KICK_SPEED_BUCKETS - 1),
            direction_bucket: direction_bucket % DISCRETIZED_KICK_DIRECTION_BUCKETS,
            curve,
            technique,
            elevation,
        }
    }

    pub fn from_power_direction(
        power: f64,
        direction: Vec2,
        curve: DiscretizedKickCurve,
        technique: DiscretizedKickTechnique,
        elevation: DiscretizedKickElevation,
    ) -> Self {
        Self::new(
            discretized_kick_speed_bucket_for_power(power),
            discretized_kick_direction_bucket_for_vector(direction),
            curve,
            technique,
            elevation,
        )
    }

    pub fn speed_power_center(self) -> f64 {
        discretized_kick_power_for_bucket(self.speed_bucket, DiscretizedKickDither::none())
    }

    pub fn direction_degrees_center(self) -> f64 {
        discretized_kick_direction_degrees(self.direction_bucket, DiscretizedKickDither::none())
    }

    pub fn direction(self) -> Vec2 {
        discretized_kick_direction_for_bucket(self.direction_bucket, DiscretizedKickDither::none())
    }
}

#[derive(Clone, Copy, Debug, Default, PartialEq, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct DiscretizedKickDither {
    pub speed_power_offset: f64,
    pub direction_degrees_offset: f64,
}

impl DiscretizedKickDither {
    pub fn none() -> Self {
        DiscretizedKickDither {
            speed_power_offset: 0.0,
            direction_degrees_offset: 0.0,
        }
    }

    fn sample(rng: &mut SeededRandom) -> Self {
        let _ = rng;
        DiscretizedKickDither {
            speed_power_offset: 0.0,
            direction_degrees_offset: 0.0,
        }
    }

    fn sanitized(self) -> Self {
        let half_power_bucket = 0.5 / f64::from(DISCRETIZED_KICK_SPEED_BUCKETS);
        let half_direction_bucket = DISCRETIZED_KICK_DIRECTION_BUCKET_DEGREES * 0.5;
        DiscretizedKickDither {
            speed_power_offset: if self.speed_power_offset.is_finite() {
                self.speed_power_offset
                    .clamp(-half_power_bucket, half_power_bucket)
            } else {
                0.0
            },
            direction_degrees_offset: if self.direction_degrees_offset.is_finite() {
                self.direction_degrees_offset
                    .clamp(-half_direction_bucket, half_direction_bucket)
            } else {
                0.0
            },
        }
    }
}

#[derive(Clone, Copy, Debug, PartialEq)]
pub(crate) struct KickReleaseSpec {
    origin: Vec2,
    intended_target: Vec2,
    speed_yps: f64,
    curve: DiscretizedKickCurve,
    technique: DiscretizedKickTechnique,
    curve_bend_yards: f64,
    elevation: DiscretizedKickElevation,
}

#[derive(Clone, Copy, Debug, PartialEq)]
pub(crate) struct LoweredKickRelease {
    launch_target: Vec2,
    intended_target: Vec2,
    velocity: Vec2,
    curl_acceleration: Vec2,
    technique: DiscretizedKickTechnique,
    altitude_yards: f64,
    speed_yps: f64,
}

fn discretized_kick_speed_bucket_for_power(power: f64) -> u8 {
    if !power.is_finite() {
        return 0;
    }
    (power.clamp(0.0, 0.999_999) * f64::from(DISCRETIZED_KICK_SPEED_BUCKETS)) as u8
}

fn discretized_kick_power_for_bucket(speed_bucket: u8, dither: DiscretizedKickDither) -> f64 {
    let bucket = speed_bucket.min(DISCRETIZED_KICK_SPEED_BUCKETS - 1);
    let center = (f64::from(bucket) + 0.5) / f64::from(DISCRETIZED_KICK_SPEED_BUCKETS);
    (center + dither.sanitized().speed_power_offset).clamp(0.0, 1.0)
}

/// Inverse of the lowering's `speed = min + (max-min)·power` mapping: the [0,1] power that
/// encodes `speed_yps` within the `[min_yps, max_yps]` envelope, clamped so an
/// out-of-envelope speed saturates to the end buckets rather than wrapping. Lets a
/// continuous heuristic pass speed be quantized into a `DiscretizedKickAction`.
fn discretized_kick_power_for_speed(speed_yps: f64, min_yps: f64, max_yps: f64) -> f64 {
    if !speed_yps.is_finite() || !(max_yps > min_yps) {
        return 0.0;
    }
    ((speed_yps - min_yps) / (max_yps - min_yps)).clamp(0.0, 1.0)
}

fn discretized_kick_direction_bucket_for_vector(direction: Vec2) -> u8 {
    let dir = direction.normalized();
    if dir.len() <= 1e-9 {
        return 0;
    }
    discretized_kick_direction_bucket_for_degrees(dir.y.atan2(dir.x).to_degrees())
}

fn discretized_kick_direction_bucket_for_degrees(degrees: f64) -> u8 {
    let degrees = if degrees.is_finite() {
        degrees.rem_euclid(360.0)
    } else {
        0.0
    };
    ((degrees / DISCRETIZED_KICK_DIRECTION_BUCKET_DEGREES).round() as i32)
        .rem_euclid(i32::from(DISCRETIZED_KICK_DIRECTION_BUCKETS)) as u8
}

fn discretized_kick_direction_degrees(direction_bucket: u8, dither: DiscretizedKickDither) -> f64 {
    (f64::from(direction_bucket % DISCRETIZED_KICK_DIRECTION_BUCKETS)
        * DISCRETIZED_KICK_DIRECTION_BUCKET_DEGREES
        + dither.sanitized().direction_degrees_offset)
        .rem_euclid(360.0)
}

fn discretized_kick_direction_for_bucket(
    direction_bucket: u8,
    dither: DiscretizedKickDither,
) -> Vec2 {
    let radians = discretized_kick_direction_degrees(direction_bucket, dither).to_radians();
    Vec2::new(radians.cos(), radians.sin()).normalized()
}

fn discretized_kick_curve_allowed(distance_yards: f64, speed_yps: f64) -> bool {
    distance_yards.is_finite()
        && distance_yards >= DISCRETIZED_KICK_CURVE_MIN_DISTANCE_YARDS
        && speed_yps.is_finite()
        && speed_yps >= mph_to_yps(DISCRETIZED_KICK_CURVE_MIN_SPEED_MPH)
}

fn masked_discretized_kick_curve(
    curve: DiscretizedKickCurve,
    distance_yards: f64,
    speed_yps: f64,
) -> DiscretizedKickCurve {
    if curve == DiscretizedKickCurve::None
        || discretized_kick_curve_allowed(distance_yards, speed_yps)
    {
        curve
    } else {
        DiscretizedKickCurve::None
    }
}

fn kick_curve_flight_distance_multiplier(
    elevation: DiscretizedKickElevation,
    distance_yards: f64,
) -> f64 {
    let long_fit = ((distance_yards - 18.0) / 42.0).clamp(0.0, 1.0);
    if elevation.is_airborne() {
        1.0 + long_fit * 0.42
    } else {
        1.0 + long_fit * 0.16
    }
}

pub(crate) fn kick_curve_bend_yards_for_technique(
    base_bend_yards: f64,
    technique: DiscretizedKickTechnique,
    elevation: DiscretizedKickElevation,
    distance_yards: f64,
) -> f64 {
    if !base_bend_yards.is_finite() {
        return 0.0;
    }
    (base_bend_yards.abs()
        * technique.curl_multiplier()
        * kick_curve_flight_distance_multiplier(elevation, distance_yards))
    .clamp(0.0, 9.5)
}

fn kick_release(spec: KickReleaseSpec) -> LoweredKickRelease {
    kick_release_with_pitch_bounds(spec, None)
}

fn kick_release_clamped_to_pitch(
    spec: KickReleaseSpec,
    field_width_yards: f64,
    field_length_yards: f64,
) -> LoweredKickRelease {
    kick_release_with_pitch_bounds(spec, Some((field_width_yards, field_length_yards)))
}

fn kick_release_with_pitch_bounds(
    spec: KickReleaseSpec,
    pitch_bounds: Option<(f64, f64)>,
) -> LoweredKickRelease {
    let origin = finite_vec2(spec.origin, Vec2::zero());
    let mut intended_target = finite_vec2(spec.intended_target, origin + Vec2::new(1.0, 0.0));
    if intended_target.distance(origin) <= 1e-9 {
        intended_target = origin + Vec2::new(1.0, 0.0);
    }
    if let Some((field_width, field_length)) = pitch_bounds {
        intended_target = intended_target.clamp_to_pitch(field_width, field_length);
    }
    let speed_yps = if spec.speed_yps.is_finite() {
        spec.speed_yps.max(0.0)
    } else {
        0.0
    };
    let intended_dir = (intended_target - origin).normalized();
    let curve_sign = spec.curve.lateral_sign();
    let technique = if curve_sign.abs() > 0.0 {
        spec.technique.effective_for_curve()
    } else {
        DiscretizedKickTechnique::None
    };
    let bend_yards = kick_curve_bend_yards_for_technique(
        spec.curve_bend_yards,
        technique,
        spec.elevation,
        origin.distance(intended_target),
    );
    let lateral = Vec2::new(-intended_dir.y, intended_dir.x);
    let launch_target = if curve_sign.abs() > 0.0 && bend_yards > 1e-9 {
        intended_target + lateral * curve_sign * bend_yards
    } else {
        intended_target
    };
    let launch_target = if let Some((field_width, field_length)) = pitch_bounds {
        launch_target.clamp_to_pitch(field_width, field_length)
    } else {
        launch_target
    };
    let launch_dir = (launch_target - origin).normalized();
    let velocity = launch_dir * speed_yps;
    let curl_acceleration = if curve_sign.abs() > 0.0 && bend_yards > 1e-9 {
        curl_acceleration_for_path(
            origin,
            launch_target,
            intended_target,
            speed_yps,
            bend_yards,
        )
    } else {
        Vec2::zero()
    };
    LoweredKickRelease {
        launch_target,
        intended_target,
        velocity,
        curl_acceleration,
        technique,
        altitude_yards: spec.elevation.release_altitude_yards(),
        speed_yps,
    }
}

fn lower_discretized_kick_release(
    origin: Vec2,
    action: DiscretizedKickAction,
    min_speed_yps: f64,
    max_speed_yps: f64,
    reference_distance_yards: f64,
    curve_bend_yards: f64,
    dither: DiscretizedKickDither,
) -> LoweredKickRelease {
    lower_discretized_kick_release_bounded(
        origin,
        action,
        min_speed_yps,
        max_speed_yps,
        reference_distance_yards,
        curve_bend_yards,
        dither,
        None,
    )
}

/// Pitch-clamped production lowering of a `DiscretizedKickAction` — the live analogue of
/// `kick_release_clamped_to_pitch` for the discrete representation (the bare
/// `lower_discretized_kick_release` does not clamp and is test/seed only).
#[allow(clippy::too_many_arguments)]
fn discretized_kick_release_clamped_to_pitch(
    origin: Vec2,
    action: DiscretizedKickAction,
    min_speed_yps: f64,
    max_speed_yps: f64,
    reference_distance_yards: f64,
    curve_bend_yards: f64,
    dither: DiscretizedKickDither,
    field_width_yards: f64,
    field_length_yards: f64,
) -> LoweredKickRelease {
    lower_discretized_kick_release_bounded(
        origin,
        action,
        min_speed_yps,
        max_speed_yps,
        reference_distance_yards,
        curve_bend_yards,
        dither,
        Some((field_width_yards, field_length_yards)),
    )
}

#[allow(clippy::too_many_arguments)]
fn lower_discretized_kick_release_bounded(
    origin: Vec2,
    action: DiscretizedKickAction,
    min_speed_yps: f64,
    max_speed_yps: f64,
    reference_distance_yards: f64,
    curve_bend_yards: f64,
    dither: DiscretizedKickDither,
    pitch_bounds: Option<(f64, f64)>,
) -> LoweredKickRelease {
    let power = discretized_kick_power_for_bucket(action.speed_bucket, dither);
    let min_speed = if min_speed_yps.is_finite() {
        min_speed_yps.max(0.0)
    } else {
        0.0
    };
    let max_speed = if max_speed_yps.is_finite() {
        max_speed_yps.max(min_speed)
    } else {
        min_speed
    };
    let speed_yps = min_speed + (max_speed - min_speed) * power;
    let distance = if reference_distance_yards.is_finite() {
        reference_distance_yards.max(0.1)
    } else {
        20.0
    };
    let direction = discretized_kick_direction_for_bucket(action.direction_bucket, dither);
    let curve = masked_discretized_kick_curve(action.curve, distance, speed_yps);
    kick_release_with_pitch_bounds(
        KickReleaseSpec {
            origin,
            intended_target: origin + direction * distance,
            speed_yps,
            curve,
            technique: if curve == DiscretizedKickCurve::None {
                DiscretizedKickTechnique::None
            } else {
                action.technique
            },
            curve_bend_yards,
            elevation: action.elevation,
        },
        pitch_bounds,
    )
}

fn modulated_pass_speed_yps(
    raw_speed_yps: f64,
    from: Vec2,
    target: Vec2,
    flight: PassFlight,
    is_cross: bool,
    passing_skill: f64,
    receiver_openness: f64,
    _rng: &mut SeededRandom,
) -> f64 {
    let distance = from.distance(target).max(0.1);
    let openness = receiver_openness.clamp(0.0, 1.0);
    let pressure = 1.0 - openness;
    if flight.is_scoop() {
        // A scoop must land on the receiver. The requested 7-12ft apex gives roughly
        // 1.3-1.7s of gravity hang time, so pace it from distance / hang-time.
        let apex_yards = scoop_loft_apex_yards(distance, 0.5);
        let hang_time = 2.0 * (2.0 * apex_yards / GRAVITY_YPS2).sqrt();
        let land_at_target = (distance / hang_time.max(0.35)) * SCOOP_LAND_AT_TARGET_DRAG_COMP;
        let pressure_firm = 1.04 + pressure * 0.10 - openness * 0.02;
        let desired_speed = land_at_target * pressure_firm;
        let skill = passing_skill.clamp(0.0, 1.0);
        let fit = (0.86 + skill * 0.08 + openness * 0.04).clamp(0.84, 0.98);
        let blended = raw_speed_yps + (desired_speed - raw_speed_yps) * fit;
        if scoop_land_at_target_enabled() {
            // The ball's altitude is on a fixed gravity clock T (hang time from the apex), and with
            // the fix the apex it flies == this `apex_yards`. To DROP on the receiver it must cross
            // the horizontal distance in ~T, i.e. at ~`desired_speed`. The flat 16mph min-speed
            // floor over-paced short chips so they reached the spot in a fraction of T and hung in
            // the air (the balloon). Cap the floor at the land-at-target pace and the ceiling just
            // above it, so the chip arrives in ~one hang time and obeys gravity onto the man.
            let floor = desired_speed.min(mph_to_yps(SCOOP_MIN_SPEED_MPH));
            let ceil = (desired_speed * 1.06).clamp(floor, mph_to_yps(SCOOP_MAX_SPEED_MPH));
            return blended.clamp(floor, ceil);
        }
        return blended.clamp(
            mph_to_yps(SCOOP_MIN_SPEED_MPH),
            mph_to_yps(SCOOP_MAX_SPEED_MPH),
        );
    }
    if flight.is_aerial() {
        // Aerial flight calibration ("the MPC should help"): the ball is a projectile aloft for a
        // gravity-fixed hang time T = 2·√(2·apex/g), where the apex scales with distance (see
        // `pass_loft_apex_yards`). Crucially the ball's altitude is integrated by ELAPSED TIME, not
        // by horizontal progress — so a ball struck harder does NOT land at the same spot, it stays
        // up for the same T and simply carries farther. Calibrating launch to power (the old model)
        // therefore launched a short LATERAL loft at ~3x the speed needed and it sailed clean over
        // the receiver, landing 2-3x too far. The only launch speed that LANDS the ball at the
        // target is distance / T (plus a touch for in-flight drag): short/lateral lofts are struck
        // softly, only genuine goal-to-goal balls get real pace.
        let apex_yards = if flight.is_over_top() {
            tunables().killer_pass_over_top.height_yards
        } else {
            lofted_pass_apex_yards(distance)
        };
        let hang_time = 2.0 * (2.0 * apex_yards / GRAVITY_YPS2).sqrt();
        let land_at_target = (distance / hang_time.max(0.35)) * AERIAL_LAND_AT_TARGET_DRAG_COMP;
        // A ball into pressure is struck a touch firmer so it beats the press; an open receiver gets
        // a slightly more weighted ball. Small — the dominant term is landing on the target.
        let pressure_firm = 1.0 + pressure * 0.06;
        return (land_at_target * pressure_firm).clamp(mph_to_yps(7.0), mph_to_yps(66.0));
    }
    // Ground / cross passes only (aerials returned above with their own flight calibration).
    // CRISP-PASS calibration (on by default): a pass arrives in roughly `base_time` seconds; the
    // old curve grew that time too fast with distance (0.58 + d/31), so a 25yd ball took ~1.4s and a
    // 40yd ball ~2.1s — slow enough to sit in the lane and be picked off (the "right angle, too slow"
    // turnovers). Pace it crisper so longer balls are genuinely driven, not floated along the floor.
    let calib = pass_accuracy_calibration_enabled();
    let base_time = if is_cross {
        if calib {
            (0.54 + distance / 44.0).clamp(0.68, 2.2)
        } else {
            (0.68 + distance / 31.0).clamp(0.82, 2.65)
        }
    } else if calib {
        (0.46 + distance / 48.0).clamp(0.60, 2.0)
    } else {
        (0.58 + distance / 31.0).clamp(0.72, 2.55)
    };
    // A pass into pressure is struck FIRMER so it beats the press (less time in the lane for a
    // defender to cut it out) — the main reason completion in the crowded opponent's half is too
    // low. An open receiver still gets a more weighted, easier-to-control ball.
    let pressure_zip = if pass_accuracy_calibration_enabled() {
        0.22
    } else {
        0.10
    };
    let timed_time = base_time * (1.0 + openness * 0.08 - pressure * pressure_zip);
    let desired_speed = (distance / timed_time.max(0.35)).clamp(
        if flight.is_aerial() {
            mph_to_yps(16.0)
        } else {
            mph_to_yps(7.0)
        },
        if flight.is_aerial() {
            mph_to_yps(64.0)
        } else if calib {
            // Let a driven ground/cross ball reach a real pace (a 40yd raking pass ~32yps); the
            // distance-aware cap below still keeps SHORT passes controllable.
            mph_to_yps(58.0)
        } else {
            mph_to_yps(44.0)
        },
    );
    let skill = passing_skill.clamp(0.0, 1.0);
    // Lean the struck pace closer to the receiver-timed `desired_speed` (the old blend dragged it
    // back toward the low power-based `raw_speed`, under-hitting the ball); a skilled, open passer
    // hits it almost exactly on the timed pace.
    let fit = if calib {
        (0.40 + skill * 0.52 + openness * 0.12).clamp(0.34, 0.97)
    } else {
        (0.30 + skill * 0.55 + openness * 0.10).clamp(0.28, 0.94)
    };
    let noise = ((1.0 - skill) * 0.08 + pressure * 0.035 - openness * 0.04).clamp(0.0, 0.16);
    let cap = if flight.is_aerial() {
        mph_to_yps(66.0)
    } else if is_cross {
        mph_to_yps(if calib { 52.0 } else { 48.0 })
    } else if calib {
        // Distance-aware ground cap: a short pass stays controllable (~42mph), a long driven ball
        // is allowed real pace (~54mph) so it doesn't dawdle into an interception.
        mph_to_yps((38.0 + distance * 0.45).clamp(42.0, 54.0))
    } else {
        mph_to_yps(42.0)
    };
    let speed =
        (raw_speed_yps + (desired_speed - raw_speed_yps) * fit) * (1.0 + noise).clamp(0.78, 1.24);
    let aerial_carry_floor = if flight.is_aerial() {
        // Gravity now fixes the hang time (the ball is a projectile that comes down at
        // T = 2·√(2·apex/g) no matter its pace), so a slow ball no longer floats — it just
        // lands SHORT. Floor the horizontal speed at `distance / T` so the ball still covers
        // the ground and arrives at the target within that hang time. Long balls are forced to
        // be driven; short chips stay gentle (a 15yd chip's floor is only ~14mph). Mirrors the
        // apex formula in `pass_loft_apex_yards` (sans the per-pass scoop seed; scoops returned
        // above).
        let apex_yards = lofted_pass_apex_yards(distance);
        let hang_time = 2.0 * (2.0 * apex_yards / GRAVITY_YPS2).sqrt();
        let reach_target_floor = distance / hang_time.max(0.35);
        let lively_floor = mph_to_yps(13.0);
        // Never demand more than the ball can physically be struck (the cap): a ball too far to
        // reach within its hang time simply lands short, it doesn't fly impossibly fast.
        reach_target_floor.max(lively_floor).min(cap)
    } else {
        mph_to_yps(4.0)
    };
    speed.clamp(aerial_carry_floor, cap)
}

fn shot_curl_probability_for_player(
    skills: &SkillProfile,
    pressure: f64,
    yards_to_goal: f64,
    goal_angle_degrees: f64,
) -> f64 {
    let shooting = ability01(skills.shooting);
    let foot_power = ability01(
        skills
            .right_foot_shot_power
            .max(skills.left_foot_shot_power),
    );
    let flair = ability01(skills.flair_passing);
    let technique = (shooting * 0.52 + foot_power * 0.30 + flair * 0.18).clamp(0.0, 1.0);
    let range_fit = (1.0 - (yards_to_goal - 20.0).abs() / 34.0).clamp(0.10, 1.0);
    let narrow_angle_need = (1.0 - goal_angle_degrees / 42.0).clamp(0.0, 1.0);
    (0.03 + technique * 0.50 + range_fit * 0.10 + narrow_angle_need * 0.08
        - pressure.clamp(0.0, 1.0) * 0.20)
        .clamp(0.02, 0.74)
}

pub(crate) fn shot_outside_foot_curve_probability_for_player(
    skills: &SkillProfile,
    pressure: f64,
    yards_to_goal: f64,
    goal_angle_degrees: f64,
    curl_probability: f64,
) -> f64 {
    let shooting = ability01(skills.shooting);
    let foot_power = ability01(
        skills
            .right_foot_shot_power
            .max(skills.left_foot_shot_power),
    );
    let flair = ability01(skills.flair_passing);
    let range_fit = (1.0 - (yards_to_goal - 22.0).abs() / 38.0).clamp(0.0, 1.0);
    let narrow_angle_need = (1.0 - goal_angle_degrees / 38.0).clamp(0.0, 1.0);
    (curl_probability.clamp(0.0, 1.0) * 0.34
        + flair * 0.34
        + shooting * 0.16
        + foot_power * 0.08
        + range_fit * 0.06
        + narrow_angle_need * 0.09
        - pressure.clamp(0.0, 1.0) * 0.18)
        .clamp(0.0, 0.82)
}

pub(crate) fn shot_curve_technique_for_player(
    skills: &SkillProfile,
    pressure: f64,
    yards_to_goal: f64,
    goal_angle_degrees: f64,
    curl_probability: f64,
) -> DiscretizedKickTechnique {
    if curl_probability < 0.36 {
        return DiscretizedKickTechnique::None;
    }
    let outside = shot_outside_foot_curve_probability_for_player(
        skills,
        pressure,
        yards_to_goal,
        goal_angle_degrees,
        curl_probability,
    );
    if outside >= 0.48 {
        DiscretizedKickTechnique::OutsideFoot
    } else {
        DiscretizedKickTechnique::InsideFoot
    }
}

pub(crate) fn shot_curve_bend_yards_for_player(
    skills: &SkillProfile,
    yards_to_goal: f64,
    technique: DiscretizedKickTechnique,
) -> f64 {
    if technique == DiscretizedKickTechnique::None {
        return 0.0;
    }
    let shooting = ability01(skills.shooting);
    let base = (0.75 + yards_to_goal / 18.0).clamp(0.75, 3.6) * (0.78 + shooting * 0.46);
    kick_curve_bend_yards_for_technique(
        base,
        technique,
        DiscretizedKickElevation::Floor,
        yards_to_goal,
    )
}

fn pass_curl_probability_for_player(
    skills: &SkillProfile,
    flight: PassFlight,
    is_cross: bool,
    distance: f64,
    pressure: f64,
) -> f64 {
    let passing = ability01(skills.passing_completion_rate);
    let crossing = ability01(skills.crossing_left.max(skills.crossing_right));
    let flair = ability01(skills.flair_passing);
    let technique = if is_cross {
        crossing * 0.52 + passing * 0.26 + flair * 0.22
    } else {
        passing * 0.54 + ability01(skills.passing) * 0.22 + flair * 0.24
    }
    .clamp(0.0, 1.0);
    let distance_fit = (distance / 34.0).clamp(0.12, 1.0);
    let aerial_bonus = if flight.is_aerial() { 0.08 } else { 0.0 };
    (0.025 + technique * 0.46 + distance_fit * 0.10 + aerial_bonus
        - pressure.clamp(0.0, 1.0) * 0.18)
        .clamp(0.01, 0.72)
}

pub(crate) fn pass_outside_foot_curve_probability_for_player(
    skills: &SkillProfile,
    flight: PassFlight,
    is_cross: bool,
    distance: f64,
    pressure: f64,
    curl_probability: f64,
) -> f64 {
    let passing = ability01(skills.passing_completion_rate);
    let crossing = ability01(skills.crossing_left.max(skills.crossing_right));
    let flair = ability01(skills.flair_passing);
    let technique = if is_cross {
        crossing * 0.40 + passing * 0.20
    } else {
        passing * 0.42 + ability01(skills.passing) * 0.16
    };
    let long_fit = ((distance - 16.0) / 42.0).clamp(0.0, 1.0);
    let aerial_fit = if flight.is_aerial() { 0.14 } else { 0.0 };
    let cross_fit = if is_cross { 0.07 } else { 0.0 };
    (curl_probability.clamp(0.0, 1.0) * 0.28
        + flair * 0.34
        + technique
        + long_fit * 0.13
        + aerial_fit
        + cross_fit
        - pressure.clamp(0.0, 1.0) * 0.20)
        .clamp(0.0, 0.84)
}

pub(crate) fn pass_curve_technique_for_player(
    skills: &SkillProfile,
    flight: PassFlight,
    is_cross: bool,
    distance: f64,
    pressure: f64,
    curl_probability: f64,
) -> DiscretizedKickTechnique {
    if curl_probability < 0.38 {
        return DiscretizedKickTechnique::None;
    }
    let outside = pass_outside_foot_curve_probability_for_player(
        skills,
        flight,
        is_cross,
        distance,
        pressure,
        curl_probability,
    );
    if outside >= 0.52 {
        DiscretizedKickTechnique::OutsideFoot
    } else {
        DiscretizedKickTechnique::InsideFoot
    }
}

pub(crate) fn pass_curve_bend_yards_for_player(
    skills: &SkillProfile,
    flight: PassFlight,
    distance: f64,
    technique: DiscretizedKickTechnique,
) -> f64 {
    if technique == DiscretizedKickTechnique::None {
        return 0.0;
    }
    let flair = ability01(skills.flair_passing);
    let base = (0.55 + distance / 24.0).clamp(0.55, 2.8) * (0.72 + flair * 0.56);
    kick_curve_bend_yards_for_technique(
        base,
        technique,
        DiscretizedKickElevation::from_pass_flight(flight),
        distance,
    )
}

fn pass_curl_probability_for_snapshot(
    snapshot: &WorldSnapshot,
    player: &PlayerSnapshot,
    player_position: Vec2,
    floor_targets: &[usize],
    aerial_targets: &[usize],
    pressure: f64,
) -> f64 {
    let mut best: f64 = 0.0;
    for (targets, flight) in [
        (floor_targets, PassFlight::Floor),
        (aerial_targets, PassFlight::Aerial),
    ] {
        for target_id in targets.iter().take(3) {
            let Some(target) = snapshot.players.iter().find(|p| p.id == *target_id) else {
                continue;
            };
            let target_position = snapshot
                .player_position(target.id)
                .unwrap_or(target.position);
            let is_cross = pass_would_be_cross(
                player_position,
                target_position,
                player.team,
                snapshot.field_width,
                snapshot.field_length,
            );
            best = best.max(pass_curl_probability_for_player(
                &player.skills,
                flight,
                is_cross,
                player_position.distance(target_position),
                pressure,
            ));
        }
    }
    best.clamp(0.0, 1.0)
}

pub(crate) fn pass_outside_foot_curve_probability_for_snapshot(
    snapshot: &WorldSnapshot,
    player: &PlayerSnapshot,
    player_position: Vec2,
    floor_targets: &[usize],
    aerial_targets: &[usize],
    pressure: f64,
) -> f64 {
    let mut best: f64 = 0.0;
    for (targets, flight) in [
        (floor_targets, PassFlight::Floor),
        (aerial_targets, PassFlight::Aerial),
    ] {
        for target_id in targets.iter().take(3) {
            let Some(target) = snapshot.players.iter().find(|p| p.id == *target_id) else {
                continue;
            };
            let target_position = snapshot
                .player_position(target.id)
                .unwrap_or(target.position);
            let is_cross = pass_would_be_cross(
                player_position,
                target_position,
                player.team,
                snapshot.field_width,
                snapshot.field_length,
            );
            let distance = player_position.distance(target_position);
            let curl_probability = pass_curl_probability_for_player(
                &player.skills,
                flight,
                is_cross,
                distance,
                pressure,
            );
            best = best.max(pass_outside_foot_curve_probability_for_player(
                &player.skills,
                flight,
                is_cross,
                distance,
                pressure,
                curl_probability,
            ));
        }
    }
    best.clamp(0.0, 1.0)
}

fn led_pass_target_for_receiver(
    from: Vec2,
    target_position: Vec2,
    target_velocity: Vec2,
    speed_yps: f64,
    skill: f64,
    receiver_openness: f64,
    team: Team,
    field_width: f64,
    field_length: f64,
) -> Vec2 {
    let distance = from.distance(target_position);
    let travel_time = distance / speed_yps.max(1.0);
    let lead = (travel_time * (0.20 + skill.clamp(0.0, 1.0) * 0.55)).clamp(0.0, 1.35);
    let velocity_led = target_position + target_velocity * lead;

    let forward = (target_position.y - from.y) * team.attack_dir();
    let moving_upfield = (target_velocity.y * team.attack_dir()).max(0.0);
    let forward_pass_weight = if forward > 8.0 {
        1.0
    } else if forward > 1.25 {
        0.64
    } else if forward > -1.25 {
        0.28
    } else {
        0.0
    };
    let openness = receiver_openness.clamp(0.0, 1.0);
    let upfield_lead = forward_pass_weight
        * (1.25
            + skill.clamp(0.0, 1.0) * 3.6
            + openness * 2.2
            + moving_upfield * 0.28
            + (distance / 30.0).clamp(0.0, 1.5))
        .clamp(0.0, 8.5);

    (velocity_led + Vec2::new(0.0, team.attack_dir() * upfield_lead))
        .clamp_to_pitch(field_width, field_length)
}

fn pass_into_stride_fit(
    from: Vec2,
    receiver_position: Vec2,
    receiver_velocity: Vec2,
    target_point: Vec2,
    ball_speed_yps: f64,
    team: Team,
) -> f64 {
    let distance = from.distance(target_point).max(0.1);
    let travel_time = (distance / ball_speed_yps.max(1.0)).clamp(0.12, 3.2);
    let receiver_future = receiver_position + receiver_velocity * travel_time * 0.82;
    let receiver_speed = receiver_velocity.len();
    let arrival_tolerance = (2.4 + receiver_speed * 0.90 + travel_time * 1.50).clamp(3.0, 9.5);
    let arrival_fit =
        (1.0 - target_point.distance(receiver_future) / arrival_tolerance).clamp(0.0, 1.0);

    let attack_dir = team.attack_dir();
    let target_forward = (target_point.y - from.y) * attack_dir;
    let receiver_lead = target_point - receiver_position;
    let forward_lead = receiver_lead.y * attack_dir;
    let receiver_forward_speed = (receiver_velocity.y * attack_dir).max(0.0);
    let lead_fit = if target_forward > 3.0 {
        let desired_lead = (receiver_forward_speed * travel_time * 0.70 + 1.4).clamp(1.4, 7.0);
        let run_intent = if receiver_forward_speed >= 0.65 {
            1.0
        } else {
            0.38 + (receiver_forward_speed / 0.65).clamp(0.0, 1.0) * 0.42
        };
        (forward_lead / desired_lead).clamp(0.0, 1.0) * run_intent
    } else if target_forward < -1.25 {
        if forward_lead <= 0.75 {
            0.80
        } else {
            0.36
        }
    } else {
        0.58 + (forward_lead.max(0.0) / 5.0).clamp(0.0, 0.34)
    };

    (arrival_fit * 0.50 + lead_fit * 0.50).clamp(0.0, 1.0)
}

fn pass_into_stride_fit_for_context(context: &SoccerDecisionContext, team: Team) -> f64 {
    let (Some(target_point), Some(receiver_position)) =
        (context.target_point, context.target_player_position)
    else {
        return 0.0;
    };
    let receiver_velocity = context.target_player_velocity.unwrap_or_else(Vec2::zero);
    pass_into_stride_fit(
        context.actor_position,
        receiver_position,
        receiver_velocity,
        target_point,
        context.action_ball_speed_yps,
        team,
    )
}

fn curl_acceleration_for_path(
    from: Vec2,
    initial_target: Vec2,
    final_target: Vec2,
    speed_yps: f64,
    bend_yards: f64,
) -> Vec2 {
    let path = initial_target - from;
    let distance = path.len();
    if distance <= 1e-6 || speed_yps <= 1e-6 || bend_yards.abs() <= 1e-6 {
        return Vec2::zero();
    }
    let dir = path.normalized();
    let lateral = Vec2::new(-dir.y, dir.x);
    let side = dot(final_target - initial_target, lateral).signum();
    if side == 0.0 {
        return Vec2::zero();
    }
    let travel_time = (distance / speed_yps).clamp(0.12, 3.5);
    let magnitude =
        (2.0 * bend_yards.abs() / (travel_time * travel_time)).clamp(0.0, MAX_BALL_CURL_YPS2);
    return lateral * side * magnitude;
}

fn apply_ball_curl(velocity: Vec2, curl_acceleration: Vec2, dt_seconds: f64) -> Vec2 {
    let speed = velocity.len();
    if speed <= 1e-6 || curl_acceleration.len() <= 1e-6 || dt_seconds <= 0.0 {
        return velocity;
    }
    let dir = velocity.normalized();
    let lateral_accel = curl_acceleration - dir * dot(curl_acceleration, dir);
    let curved = velocity + lateral_accel * dt_seconds;
    if curved.len() <= 1e-6 {
        return velocity;
    } else {
        return curved.normalized() * speed;
    }
}

fn decayed_ball_curl(curl_acceleration: Vec2, dt_seconds: f64) -> Vec2 {
    if curl_acceleration.len() <= 1e-6 || dt_seconds <= 0.0 {
        return curl_acceleration;
    }
    let factor = (-BALL_CURL_DECAY_PER_SECOND * dt_seconds).exp();
    let decayed = curl_acceleration * factor;
    if decayed.len() < 0.025 {
        return Vec2::zero();
    } else {
        decayed
    }
}

fn player_reaction_time_seconds_from_traits(
    skills: &SkillProfile,
    fatigue: f64,
    role: PlayerRole,
) -> f64 {
    let quickness = ability01(skills.acceleration) * 0.30
        + ability01(skills.defensive_tracking) * 0.22
        + ability01(skills.defending) * 0.18
        + ability01(skills.aggression) * 0.10
        + ability01(skills.vision) * 0.20;
    let role_floor = if role == PlayerRole::Goalkeeper {
        0.18
    } else {
        0.21
    };
    return (0.44 - quickness * 0.18 + fatigue.clamp(0.0, 1.0) * 0.13).clamp(role_floor, 0.62);
}

fn goalkeeper_reaction_time_seconds(skills: &SkillProfile, fatigue: f64) -> f64 {
    let keeper_quickness = ability01(skills.goalkeeping) * 0.42
        + ability01(skills.acceleration) * 0.22
        + ability01(skills.defensive_tracking) * 0.16
        + ability01(skills.vision) * 0.20;
    (0.36 - keeper_quickness * 0.16 + fatigue.clamp(0.0, 1.0) * 0.11).clamp(0.16, 0.52)
}

fn shot_block_probability_for_candidate(
    skills: &SkillProfile,
    role: PlayerRole,
    fatigue: f64,
    from: Vec2,
    to: Vec2,
    position: Vec2,
    shot_speed_yps: f64,
    quick_release: bool,
) -> Option<(f64, Vec2, f64, f64, f64)> {
    if role == PlayerRole::Goalkeeper {
        return None;
    }
    let path = to - from;
    let distance = path.len();
    if distance <= 0.35 {
        return None;
    }
    let t = segment_projection_factor(from, to, position);
    if !(0.01..=0.99).contains(&t) {
        return None;
    }
    let block_position = from + path * t;
    let lateral_distance = position.distance(block_position);
    if lateral_distance > SHOT_BLOCK_LANE_RADIUS_YARDS {
        return None;
    }
    let line_score = if lateral_distance <= PLAYER_BODY_RADIUS_YARDS {
        1.0
    } else {
        (1.0 - (lateral_distance - PLAYER_BODY_RADIUS_YARDS)
            / (SHOT_BLOCK_LANE_RADIUS_YARDS - PLAYER_BODY_RADIUS_YARDS))
            .clamp(0.0, 1.0)
    };
    let distance_to_ball = from.distance(position);
    let screen_score = if (SHOT_SCREEN_IDEAL_MIN_YARDS..=SHOT_SCREEN_IDEAL_MAX_YARDS)
        .contains(&distance_to_ball)
    {
        1.0
    } else if distance_to_ball < SHOT_SCREEN_IDEAL_MIN_YARDS {
        (0.62 + distance_to_ball / SHOT_SCREEN_IDEAL_MIN_YARDS * 0.38).clamp(0.62, 1.0)
    } else if distance_to_ball <= 18.0 {
        (1.0 - (distance_to_ball - SHOT_SCREEN_IDEAL_MAX_YARDS) / 15.0 * 0.38).clamp(0.62, 1.0)
    } else {
        (0.62 - (distance_to_ball - 18.0) / 46.0 * 0.30).clamp(0.26, 0.62)
    };
    let arrival_time = distance_to_ball / shot_speed_yps.max(1.0);
    let reaction_time = player_reaction_time_seconds_from_traits(skills, fatigue, role);
    let reaction_factor = if arrival_time >= reaction_time {
        1.0
    } else {
        (0.62 + arrival_time / reaction_time.max(1e-6) * 0.38).clamp(0.62, 1.0)
    };
    let readiness = (0.88
        + ability01(skills.defending) * 0.14
        + ability01(skills.defensive_tracking) * 0.09
        + ability01(skills.aggression) * 0.05
        + ability01(skills.strength) * 0.04
        - fatigue.clamp(0.0, 1.0) * 0.14)
        .clamp(0.68, 1.16);
    let quick_release_factor = if quick_release {
        SHOT_BLOCK_QUICK_RELEASE_MULTIPLIER
    } else {
        1.0
    };
    let probability = (SHOT_BLOCK_DIRECT_PROBABILITY
        * line_score
        * (0.72 + screen_score * 0.28)
        * reaction_factor
        * readiness
        * quick_release_factor)
        .clamp(0.0, 0.92);
    return (probability >= 0.025).then_some((
        probability,
        block_position,
        distance_to_ball,
        lateral_distance,
        screen_score,
    ));
}

fn combine_shot_block_assessments(
    mut assessments: Vec<ShotBlockAssessment>,
) -> Option<ShotBlockAssessment> {
    if assessments.is_empty() {
        return None;
    }
    assessments.sort_by(|a, b| {
        b.probability
            .partial_cmp(&a.probability)
            .unwrap_or(std::cmp::Ordering::Equal)
    });
    let combined = (1.0
        - assessments
            .iter()
            .map(|assessment| 1.0 - assessment.probability.clamp(0.0, 1.0))
            .product::<f64>())
    .clamp(0.0, 0.96);
    let mut best = assessments.remove(0);
    best.probability = combined;
    return Some(best);
}

fn shot_block_assessment_for_agents(
    players: &[PlayerAgent],
    from: Vec2,
    to: Vec2,
    attacking_team: Team,
    shot_speed_yps: f64,
    quick_release: bool,
) -> Option<ShotBlockAssessment> {
    let assessments = players
        .iter()
        .filter(|player| player.team == attacking_team.other())
        .filter_map(|player| {
            let (probability, block_position, distance_to_ball, lateral_distance, screen_score) =
                shot_block_probability_for_candidate(
                    &player.skills,
                    player.role,
                    player.fatigue,
                    from,
                    to,
                    player.position,
                    shot_speed_yps,
                    quick_release,
                )?;
            Some(ShotBlockAssessment {
                blocker_id: player.id,
                defending_team: player.team,
                block_position,
                probability,
                distance_to_ball,
                lateral_distance,
                screen_score,
            })
        })
        .collect::<Vec<_>>();
    combine_shot_block_assessments(assessments)
}

fn shot_sightline_screen_probability_for_agents(
    players: &[PlayerAgent],
    from: Vec2,
    to: Vec2,
    attacking_team: Team,
    shot_speed_yps: f64,
    quick_release: bool,
) -> f64 {
    let clear_probability = players
        .iter()
        .filter(|player| {
            player.team == attacking_team.other() && player.role != PlayerRole::Goalkeeper
        })
        .filter_map(|player| {
            shot_block_probability_for_candidate(
                &player.skills,
                player.role,
                player.fatigue,
                from,
                to,
                player.position,
                shot_speed_yps,
                quick_release,
            )
            .map(|(probability, _, _, _, _)| 1.0 - probability.clamp(0.0, 1.0))
        })
        .product::<f64>();
    return (1.0 - clear_probability).clamp(0.0, 1.0);
}

fn shot_goalmouth_target_points(
    field_width: f64,
    field_length: f64,
    goal_width: f64,
    attacking_team: Team,
) -> [Vec2; 5] {
    let goal_y = attacking_team.goal_y(field_length);
    let center_x = field_width * 0.5;
    let half_width = goal_width.max(1.0) * 0.5;
    SHOT_GOALMOUTH_TARGET_FRACTIONS.map(|fraction| {
        Vec2::new(
            (center_x + half_width * fraction).clamp(0.0, field_width),
            goal_y,
        )
    })
}

fn shot_block_assessment_for_snapshot_target(
    snapshot: &WorldSnapshot,
    from: Vec2,
    target: Vec2,
    attacking_team: Team,
    shot_speed_yps: f64,
    quick_release: bool,
) -> Option<ShotBlockAssessment> {
    let assessments = snapshot
        .players
        .iter()
        .filter(|player| player.team == attacking_team.other())
        .filter_map(|player| {
            let position = snapshot
                .player_position(player.id)
                .unwrap_or(player.position);
            let (probability, block_position, distance_to_ball, lateral_distance, screen_score) =
                shot_block_probability_for_candidate(
                    &player.skills,
                    player.role,
                    player.fatigue,
                    from,
                    target,
                    position,
                    shot_speed_yps,
                    quick_release,
                )?;
            Some(ShotBlockAssessment {
                blocker_id: player.id,
                defending_team: player.team,
                block_position,
                probability,
                distance_to_ball,
                lateral_distance,
                screen_score,
            })
        })
        .collect::<Vec<_>>();
    return combine_shot_block_assessments(assessments);
}

fn shot_block_assessment_for_snapshot(
    snapshot: &WorldSnapshot,
    from: Vec2,
    attacking_team: Team,
    shot_speed_yps: f64,
    quick_release: bool,
) -> Option<ShotBlockAssessment> {
    let targets = shot_goalmouth_target_points(
        snapshot.field_width,
        snapshot.field_length,
        snapshot.goal_width,
        attacking_team,
    );
    let mut best: Option<ShotBlockAssessment> = None;
    for target in targets {
        match shot_block_assessment_for_snapshot_target(
            snapshot,
            from,
            target,
            attacking_team,
            shot_speed_yps,
            quick_release,
        ) {
            None => return None,
            Some(assessment)
                if best
                    .as_ref()
                    .map(|best| assessment.probability < best.probability)
                    .unwrap_or(true) =>
            {
                best = Some(assessment);
            }
            Some(_) => {}
        }
    }
    return best;
}

fn shot_miss_window_yards(
    goal_width: f64,
    shooting_skill: f64,
    pressure: f64,
    yards_to_goal: f64,
) -> f64 {
    let skill_error = 1.0 - shooting_skill.clamp(0.05, 0.99);
    let pressure = pressure.clamp(0.0, 1.0);
    goal_width * (0.28 + skill_error * 0.80 + pressure * 0.48)
        + yards_to_goal.max(0.0) * 0.018 * (0.45 + skill_error)
}

fn triangular_abs_within_probability(bound: f64, window: f64) -> f64 {
    if bound <= 0.0 || window <= 0.0 {
        return 0.0;
    }
    if bound >= window {
        return 1.0;
    }
    let ratio = (bound / window).clamp(0.0, 1.0);
    return (2.0 * ratio - ratio * ratio).clamp(0.0, 1.0);
}

fn shot_on_frame_probability(
    goal_width: f64,
    shooting_skill: f64,
    pressure: f64,
    yards_to_goal: f64,
    goal_angle_degrees: f64,
    shot_block_probability: f64,
) -> f64 {
    let miss_window = shot_miss_window_yards(goal_width, shooting_skill, pressure, yards_to_goal);
    let geometry_probability = triangular_abs_within_probability(goal_width * 0.5, miss_window);
    let angle_factor = (0.45 + (goal_angle_degrees / 36.0).clamp(0.0, 1.0) * 0.55).clamp(0.45, 1.0);
    let distance_factor = (1.08 - (yards_to_goal.max(0.0) / 52.0).powi(2) * 0.25).clamp(0.70, 1.0);
    let block_factor = (1.0 - shot_block_probability.clamp(0.0, 1.0) * 0.74).clamp(0.20, 1.0);
    (geometry_probability * angle_factor * distance_factor * block_factor).clamp(0.0, 1.0)
}

#[derive(Clone, Copy, Debug, Default)]
struct ShotMpcAccuracyEstimate {
    target_point: Vec2,
    accuracy_probability: f64,
    qp_target_fit: f64,
    goal_probability: f64,
    goalkeeper_reach_pressure: f64,
    block_probability: f64,
}

fn shot_mpc_accuracy_estimate_for_snapshot(
    snapshot: &WorldSnapshot,
    _player_id: usize,
    attacking_team: Team,
    skills: &SkillProfile,
    fatigue: f64,
    player_position: Vec2,
    player_velocity: Vec2,
    shot_speed_yps: f64,
    quick_release: bool,
    pressure: f64,
) -> ShotMpcAccuracyEstimate {
    let goal_y = attacking_team.goal_y(snapshot.field_length);
    let goal_center_x = snapshot.field_width * 0.5;
    let half_width = (snapshot.goal_width * 0.5).max(0.5);
    let left_post_x = goal_center_x - half_width;
    let right_post_x = goal_center_x + half_width;
    let shot_speed_yps = shot_speed_yps.max(1.0);
    let pressure = pressure.clamp(0.0, 1.0);
    let targets = shot_goalmouth_target_points(
        snapshot.field_width,
        snapshot.field_length,
        snapshot.goal_width,
        attacking_team,
    );
    let mut least_blocked_target = Vec2::new(goal_center_x, goal_y);
    let mut least_block_probability = f64::INFINITY;
    for target in targets {
        let block_probability = shot_block_assessment_for_snapshot_target(
            snapshot,
            player_position,
            target,
            attacking_team,
            shot_speed_yps,
            quick_release,
        )
        .map(|assessment| assessment.probability)
        .unwrap_or(0.0);
        if block_probability < least_block_probability {
            least_block_probability = block_probability;
            least_blocked_target = target;
        }
    }
    if !least_block_probability.is_finite() {
        least_block_probability = 0.0;
    }
    let keeper_position = snapshot
        .goalkeeper_for(attacking_team.other())
        .and_then(|keeper_id| snapshot.player_position(keeper_id))
        .unwrap_or(Vec2::new(goal_center_x, goal_y));
    let keeper_open_x = if keeper_position.x <= goal_center_x {
        goal_center_x + half_width * 0.82
    } else {
        goal_center_x - half_width * 0.82
    };
    let shooter_angle_x = if player_position.x <= goal_center_x {
        goal_center_x + half_width * 0.42
    } else {
        goal_center_x - half_width * 0.42
    };
    let shooting_skill = ability01(skills.shooting);
    let foot_power = ability01(
        skills
            .right_foot_shot_power
            .max(skills.left_foot_shot_power),
    );
    let body_control = (ability01(skills.first_touch) * 0.34
        + ability01(skills.strength) * 0.24
        + ability01(skills.acceleration) * 0.18
        + shooting_skill * 0.24)
        .clamp(0.0, 1.0);
    let shot_skill =
        (shooting_skill * 0.58 + foot_power * 0.22 + body_control * 0.20).clamp(0.0, 1.0);
    let target_weight = 0.82 + shot_skill * 0.72;
    let keeper_weight = 0.56 + (1.0 - pressure) * 0.24;
    let blocker_weight = 0.58 + least_block_probability.clamp(0.0, 1.0) * 0.42;
    let velocity_weight = (player_velocity.len() / 10.0).clamp(0.0, 0.24);
    let fatigue_penalty = fatigue.clamp(0.0, 1.0) * 0.18;
    let unbounded_preference = (target_weight * shooter_angle_x
        + keeper_weight * keeper_open_x
        + blocker_weight * least_blocked_target.x
        + velocity_weight * (goal_center_x + player_velocity.x.clamp(-8.0, 8.0) * 0.18))
        / (target_weight + keeper_weight + blocker_weight + velocity_weight).max(1e-6);
    let program = QuadraticProgram {
        q: vec![vec![
            2.0 * (target_weight + keeper_weight + blocker_weight + 0.08),
        ]],
        c: vec![
            -2.0 * (target_weight * shooter_angle_x
                + keeper_weight * keeper_open_x
                + blocker_weight * least_blocked_target.x),
        ],
        lb: Some(vec![Some(left_post_x)]),
        ub: Some(vec![Some(right_post_x)]),
        var_names: Some(vec!["goal_x".to_string()]),
        ..QuadraticProgram::default()
    };
    let solution = solve_qp_active_set(
        &program,
        QPOptions {
            tol: 1e-7,
            max_active_sets: 32,
        },
    );
    let target_x = if solution.status == QPStatus::Optimal && !solution.x.is_empty() {
        solution.x[0]
    } else {
        unbounded_preference
    }
    .clamp(left_post_x, right_post_x);
    let target_point = Vec2::new(target_x, goal_y);
    let bounded_preference = unbounded_preference.clamp(left_post_x, right_post_x);
    let bound_residual = (target_x - bounded_preference).abs();
    let distance = player_position.distance(target_point);
    let left_post = Vec2::new(left_post_x, goal_y);
    let right_post = Vec2::new(right_post_x, goal_y);
    let goal_angle_degrees =
        angle_between_vectors_degrees(left_post - player_position, right_post - player_position);
    let chosen_block_probability = shot_block_assessment_for_snapshot_target(
        snapshot,
        player_position,
        target_point,
        attacking_team,
        shot_speed_yps,
        quick_release,
    )
    .map(|assessment| assessment.probability)
    .unwrap_or(0.0)
    .clamp(0.0, 1.0);
    let base_on_frame = shot_on_frame_probability(
        snapshot.goal_width,
        shooting_skill,
        pressure,
        distance,
        goal_angle_degrees,
        chosen_block_probability,
    );
    let shot_time = distance / shot_speed_yps.max(1.0);
    let body_fit =
        (0.48 + shot_skill * 0.30 + body_control * 0.22 - fatigue_penalty).clamp(0.22, 1.0);
    let target_fit = (1.0 - bound_residual / (half_width * 1.35).max(0.25)).clamp(0.0, 1.0);
    let time_fit = (1.0 - (shot_time - 1.05).max(0.0) / 2.6).clamp(0.35, 1.0);
    let qp_target_fit =
        (target_fit * 0.46 + body_fit * 0.30 + time_fit * 0.14 + (1.0 - pressure) * 0.10)
            .clamp(0.0, 1.0);
    let save_probability = snapshot
        .goalkeeper_for(attacking_team.other())
        .and_then(|keeper_id| {
            snapshot
                .players
                .iter()
                .find(|keeper| keeper.id == keeper_id)
                .map(|keeper| {
                    let keeper_position = snapshot
                        .player_position(keeper_id)
                        .unwrap_or(keeper.position);
                    let keeper_velocity = snapshot
                        .player_velocity(keeper_id)
                        .unwrap_or(keeper.velocity);
                    goalkeeper_save_probability_from_traits(
                        &keeper.skills,
                        keeper_position,
                        keeper_velocity,
                        keeper.fatigue,
                        player_position,
                        target_point,
                        shot_speed_yps,
                        snapshot.goal_width,
                        chosen_block_probability,
                    )
                })
        })
        .unwrap_or(0.65)
        .clamp(0.0, 0.995);
    let accuracy_probability =
        (base_on_frame * (0.70 + qp_target_fit * 0.30) * (0.88 + body_fit * 0.12)).clamp(0.0, 1.0);
    let goal_probability = (accuracy_probability
        * (1.0 - save_probability)
        * (1.0 - chosen_block_probability * 0.42).clamp(0.12, 1.0))
    .clamp(0.0, 1.0);
    ShotMpcAccuracyEstimate {
        target_point,
        accuracy_probability,
        qp_target_fit,
        goal_probability,
        goalkeeper_reach_pressure: save_probability,
        block_probability: chosen_block_probability,
    }
}

fn noisy_shot_target_x(
    goal_center_x: f64,
    goal_width: f64,
    shooting_skill: f64,
    pressure: f64,
    yards_to_goal: f64,
    _rng: &mut SeededRandom,
) -> f64 {
    let miss_window = shot_miss_window_yards(goal_width, shooting_skill, pressure, yards_to_goal);
    let skill_error = (1.0 - shooting_skill.clamp(0.05, 0.99)).clamp(0.0, 1.0);
    let pressure = pressure.clamp(0.0, 1.0);
    let distance_fit = (yards_to_goal.max(0.0) / 48.0).clamp(0.0, 1.0);
    let deterministic_pull =
        (skill_error * 0.56 + pressure * 0.30 + distance_fit * 0.24 - 0.42).clamp(0.0, 0.62);
    return goal_center_x + deterministic_pull * miss_window;
}

/// Calibrated save probability vs shot distance (a mixed RV, piecewise-linear
/// through fitted knots): farther shots give the keeper more time to read and
/// reach — ≈50% at 20 yd, 70% at 25, 80% at 30, 95% at 40, approaching 1 by
/// ~55 yd — while close shots beat the keeper. Keeper coverage modulates this.
fn goalkeeper_distance_save_baseline(shot_distance_yards: f64) -> f64 {
    // Save probability for a SET, well-positioned keeper, by shot distance. Closer = much
    // lower (less reaction time → the shot beats the keeper), rising with range. Tuned so
    // MORE on-target shots are goals than before (esp. inside the box) while long-range
    // efforts are still mostly stopped. Goal% = 1 − save: 10yd≈82%, 15yd≈66%, 20yd≈47%,
    // 25yd≈33%, 30yd≈23%, 40yd≈11%.
    const POINTS: [(f64, f64); 8] = [
        (5.0, 0.05),
        (10.0, 0.18),
        (15.0, 0.34),
        (20.0, 0.53),
        (25.0, 0.67),
        (30.0, 0.77),
        (40.0, 0.89),
        (55.0, 0.97),
    ];
    let d = shot_distance_yards.max(0.0);
    let first = POINTS[0];
    if d <= first.0 {
        return (first.1 * d / first.0).clamp(0.0, first.1);
    }
    let last = POINTS[POINTS.len() - 1];
    if d >= last.0 {
        return last.1;
    }
    for pair in POINTS.windows(2) {
        let (x0, y0) = pair[0];
        let (x1, y1) = pair[1];
        if d <= x1 {
            let t = (d - x0) / (x1 - x0);
            return y0 + (y1 - y0) * t;
        }
    }
    return last.1;
}

/// Clamp where a keeper ends up after making a save to within its physical reach this tick
/// (its sprint distance plus a dive), so it is never TELEPORTED across to the ball. If the
/// save point is beyond that reach the keeper is moved only as far as it can get.
fn soccer_bounded_keeper_save_position(
    players: &[PlayerAgent],
    keeper_id: usize,
    save_position: Vec2,
    dt_seconds: f64,
) -> Vec2 {
    let Some(keeper) = players.iter().find(|player| player.id == keeper_id) else {
        return save_position;
    };
    let reach = top_speed_yps_from_score(keeper.skills.top_speed) * dt_seconds.max(0.01)
        + GOALKEEPER_SAVE_DIVE_REACH_YARDS;
    let delta = save_position - keeper.position;
    if delta.len() <= reach {
        return save_position;
    } else {
        return keeper.position + delta.normalized() * reach;
    }
}

fn goalkeeper_save_probability_from_traits(
    skills: &SkillProfile,
    keeper_position: Vec2,
    keeper_velocity: Vec2,
    keeper_fatigue: f64,
    shooter_position: Vec2,
    shot_crossing: Vec2,
    shot_speed: f64,
    goal_width: f64,
    sightline_screen_probability: f64,
) -> f64 {
    let keeper_position = finite_vec2(keeper_position, Vec2::zero());
    let keeper_velocity = finite_vec2(keeper_velocity, Vec2::zero());
    let shooter_position = finite_vec2(shooter_position, keeper_position);
    let shot_crossing = finite_vec2(shot_crossing, shooter_position);
    let shot_speed = if shot_speed.is_finite() && shot_speed > 0.0 {
        shot_speed
    } else {
        1.0
    };
    let goal_width = if goal_width.is_finite() && goal_width > 0.0 {
        goal_width
    } else {
        DEFAULT_GOAL_WIDTH_YARDS
    };
    let keeper_fatigue = if keeper_fatigue.is_finite() {
        keeper_fatigue.clamp(0.0, 1.0)
    } else {
        0.0
    };
    let sightline_screen_probability = if sightline_screen_probability.is_finite() {
        sightline_screen_probability.clamp(0.0, 1.0)
    } else {
        0.0
    };
    let reaction = ability01(skills.goalkeeping) * 0.48
        + ability01(skills.defending) * 0.18
        + ability01(skills.first_touch) * 0.20
        + ability01(skills.acceleration) * 0.14;
    let reaction_time = goalkeeper_reaction_time_seconds(skills, keeper_fatigue);
    let shot_distance = shooter_position.distance(shot_crossing);
    let shot_distance = if shot_distance.is_finite() {
        shot_distance.max(0.0)
    } else {
        0.0
    };
    let shot_travel_time = shot_distance / shot_speed.max(1.0);
    let available_move_time = (shot_travel_time - reaction_time).max(0.0);
    let acceleration_reach = 0.5
        * acceleration_yps2_from_score(skills.acceleration)
        * available_move_time
        * available_move_time;
    let keeper_velocity_speed = keeper_velocity.len();
    let keeper_velocity_speed = if keeper_velocity_speed.is_finite() {
        keeper_velocity_speed
    } else {
        0.0
    };
    let velocity_reach = keeper_velocity_speed * available_move_time * 0.34;
    // A keeper cannot relocate its body faster than its TOP SPEED (~23mph ≈ 10yps): cap the
    // movement reach at top_speed × time. A 40-60mph shot (≈18-26yps) gives so little time
    // that a 23mph keeper simply cannot get across to a ball struck away from it — so those
    // are goals, not saves. Only MOVEMENT is capped; the base/dive reach below is in-place.
    let keeper_top_speed = top_speed_yps_from_score(skills.top_speed).max(1.0);
    let movement_reach =
        (acceleration_reach + velocity_reach).min(keeper_top_speed * available_move_time);
    let height_reach = (height_inches_from_score(skills.height) - 66.0).max(0.0) / INCHES_PER_YARD;
    let reachable_radius = 1.05 + reaction * 0.85 + movement_reach + height_reach;
    // Reach is measured against the SHOT'S PATH (perpendicular distance), NOT the keeper's
    // distance to the goal-line crossing. A keeper standing in the ball's lane saves it
    // whatever its depth off the line; the old crossing-distance measure wrongly punished a
    // correctly-positioned keeper for being a few yards off its line, so shots sailed
    // "through" a keeper that was actually right behind the ball.
    let lateral_to_lane =
        segment_distance_to_point(shooter_position, shot_crossing, keeper_position);
    let lateral_to_lane = if lateral_to_lane.is_finite() {
        lateral_to_lane.max(0.0)
    } else {
        goal_width
    };
    let reach_gap = (lateral_to_lane - reachable_radius).max(0.0);
    let reach_penalty = (reach_gap / (goal_width * 0.72).max(0.1)).clamp(0.0, 1.5);
    let speed_penalty = (shot_speed / mph_to_yps(60.0)).clamp(0.0, 1.0) * 0.12;
    let reaction_penalty = if shot_travel_time <= reaction_time {
        ((reaction_time - shot_travel_time) / reaction_time.max(1e-6)).clamp(0.0, 1.0) * 0.22
    } else {
        0.0
    };
    let line_t = segment_projection_factor(shooter_position, shot_crossing, keeper_position);
    let line_t = if line_t.is_finite() {
        line_t.clamp(0.0, 1.0)
    } else {
        0.0
    };
    let angle_cut_score = if (0.05..=0.92).contains(&line_t) {
        (1.0 - lateral_to_lane / (goal_width * 0.62).max(0.1)).clamp(0.0, 1.0)
            * (1.0 - line_t * 0.72).clamp(0.20, 1.0)
    } else {
        0.0
    };
    let rush_dir = (shooter_position - keeper_position).normalized();
    let rush_speed = dot(keeper_velocity, rush_dir);
    let rush_speed = if rush_speed.is_finite() {
        rush_speed.max(0.0)
    } else {
        0.0
    };
    let rush_bonus =
        (rush_speed / top_speed_yps_from_score(skills.top_speed).max(1.0)).clamp(0.0, 1.0) * 0.08;
    let clean_sightline = 1.0 - sightline_screen_probability;
    // The further out the shot, the more time the keeper has to read and reach
    // it — long-range efforts (aerial or ground) are saved far more often.
    let distance_save_bonus = ((shot_distance - 14.0) / 40.0).clamp(0.0, 1.0) * 0.24;
    let clear_long_shot_bonus =
        clean_sightline * ((shot_distance - 24.0) / 38.0).clamp(0.0, 1.0) * 0.10;
    let screened_penalty = sightline_screen_probability * 0.16;
    // Distance is the primary save driver, calibrated to the target curve
    // (≈64% @20yd, 80% @25, 88% @30, 96% @40, →1 by ~55yd; low up close so close
    // shots beat the keeper). The keeper's COVERAGE (positioning/reach/sightline/
    // skill/screen) then modulates it: a set, well-placed keeper achieves the
    // full baseline; a beaten or screened one saves less.
    let _ = (distance_save_bonus, clear_long_shot_bonus);
    let distance_baseline = goalkeeper_distance_save_baseline(shot_distance);
    let coverage =
        (0.55 + reaction * 0.35 + angle_cut_score * 0.12 + rush_bonus + clean_sightline * 0.10
            - reach_penalty * 0.45
            - speed_penalty
            - reaction_penalty
            - screened_penalty)
            .clamp(0.15, 1.0);
    // Distance buys reaction time: a shot from ~40yd gives the keeper ~1.5-2s to
    // read it and get set, so positioning/reach/reaction (the coverage term)
    // should stop dragging the calibrated baseline down at range. Blend coverage
    // toward a full save as the shot lengthens — no effect on close shots (<=22yd),
    // ramping to the pure distance baseline by ~38yd — so a set keeper on their
    // line controls long-range efforts ~95%+ of the time instead of being beaten.
    // The long-range reaction-time rescue must only help a keeper that is ACTUALLY in the
    // shot's lane — otherwise an out-of-position/beaten keeper "magically" saves a ball
    // sailing into an open net. Scale the rescue by how close the keeper is to the lane
    // (1 when set in the lane, 0 when beaten), so a beaten keeper concedes the long shot.
    let in_lane_fraction = (1.0 - reach_penalty.clamp(0.0, 1.0)).clamp(0.0, 1.0);
    let long_range_fraction = ((shot_distance - 22.0) / 16.0).clamp(0.0, 1.0) * in_lane_fraction;
    let effective_coverage = coverage + (1.0 - coverage) * long_range_fraction;
    let base = (distance_baseline * effective_coverage).clamp(0.0, 0.995);
    // Proximity reach-save: a ball crossing within ~1 yard of the keeper (either
    // side, i.e. laterally) that is either slow (<20mph) or struck from distance
    // (>20yd, giving time to set) should be stopped far more often — these are
    // balls a keeper gets a hand/body to rather than watching pass through.
    // Boost the save 50%.
    let lateral_to_keeper = (shot_crossing.x - keeper_position.x).abs();
    let ball_within_reach = lateral_to_keeper <= 1.0;
    let slow_ball = shot_speed < mph_to_yps(20.0);
    let long_range_shot = shot_distance > 20.0;
    if ball_within_reach && (slow_ball || long_range_shot) {
        (base * 1.5).min(0.995)
    } else {
        base
    }
}

fn goalkeeper_save_probability(
    keeper: &PlayerAgent,
    shooter_position: Vec2,
    shot_crossing: Vec2,
    shot_speed: f64,
    goal_width: f64,
    sightline_screen_probability: f64,
) -> f64 {
    goalkeeper_save_probability_from_traits(
        &keeper.skills,
        keeper.position,
        keeper.velocity,
        keeper.fatigue,
        shooter_position,
        shot_crossing,
        shot_speed,
        goal_width,
        sightline_screen_probability,
    )
}

fn goalkeeper_catch_probability_after_save(
    keeper: &PlayerAgent,
    shooter_position: Vec2,
    shot_crossing: Vec2,
    shot_speed: f64,
    goal_width: f64,
    sightline_screen_probability: f64,
) -> f64 {
    let keeper_position = finite_vec2(keeper.position, Vec2::zero());
    let shooter_position = finite_vec2(shooter_position, keeper_position);
    let shot_crossing = finite_vec2(shot_crossing, shooter_position);
    let shot_speed = if shot_speed.is_finite() && shot_speed > 0.0 {
        shot_speed
    } else {
        1.0
    };
    let goal_width = if goal_width.is_finite() && goal_width > 0.0 {
        goal_width
    } else {
        DEFAULT_GOAL_WIDTH_YARDS
    };
    let sightline_screen_probability = if sightline_screen_probability.is_finite() {
        sightline_screen_probability.clamp(0.0, 1.0)
    } else {
        0.0
    };
    let shot_distance = shooter_position.distance(shot_crossing);
    let shot_distance = if shot_distance.is_finite() {
        shot_distance.max(0.0)
    } else {
        0.0
    };
    let clean_sightline = 1.0 - sightline_screen_probability;
    let handling = (ability01(keeper.skills.goalkeeping) * 0.58
        + ability01(keeper.skills.first_touch) * 0.42)
        .clamp(0.0, 1.0);
    let distance_fit = ((shot_distance - 18.0) / 42.0).clamp(0.0, 1.0);
    let high_speed_fit = (shot_speed / mph_to_yps(60.0)).clamp(0.0, 1.25);
    let keeper_to_crossing = keeper_position.distance(shot_crossing);
    let keeper_to_crossing = if keeper_to_crossing.is_finite() {
        keeper_to_crossing.max(0.0)
    } else {
        goal_width
    };
    let near_keeper_fit = (1.0 - keeper_to_crossing / (goal_width * 0.72).max(0.1)).clamp(0.0, 1.0);
    let short_medium_fit = if shot_distance <= 32.0 {
        (1.0 - (shot_distance - 18.0).abs() / 22.0).clamp(0.0, 1.0)
    } else {
        0.0
    };
    // A long shot with a clear sightline is a comfortable, well-read take: the
    // keeper sets early and catches cleanly with their first touch rather than
    // parrying. Ramps in from ~28yd to a near-certain clean catch by ~40yd.
    let long_range_control =
        ((shot_distance - 28.0) / 12.0).clamp(0.0, 1.0) * clean_sightline * 0.40;
    (0.20 + handling * 0.30 + clean_sightline * 0.18 + distance_fit * 0.24 + long_range_control
        - high_speed_fit * 0.18
        - short_medium_fit * near_keeper_fit * 0.28
        - sightline_screen_probability * 0.16)
        .clamp(0.08, 0.96)
}

/// How far the opposing keeper is out of position for a shot from `player_position`,
/// 0.0 (set on his line, on the angle) to 1.0 (totally out). Distance-agnostic on
/// purpose so it can gate long shots ("only from range if the keeper is out") without
/// being swamped by the range-dominated save baseline.
fn opposing_goalkeeper_out_of_position_for_snapshot(
    snapshot: &WorldSnapshot,
    player: &PlayerSnapshot,
    player_position: Vec2,
) -> f64 {
    let Some(keeper_id) = snapshot.goalkeeper_for(player.team.other()) else {
        return 0.0;
    };
    let Some(keeper) = snapshot.players.iter().find(|p| p.id == keeper_id) else {
        return 0.0;
    };
    let keeper_position = snapshot
        .player_position(keeper_id)
        .unwrap_or(keeper.position);
    let goal_y = player.team.goal_y(snapshot.field_length);
    let goal_center_x = snapshot.field_width * 0.5;
    let half_width = (snapshot.goal_width * 0.5).max(1.0);
    // Strayed off his own goal line (rushed out / caught high up the pitch).
    let advance_yards = (keeper_position.y - goal_y).abs();
    let advance_factor = ((advance_yards - 6.0) / 12.0).clamp(0.0, 1.0);
    // Off the angle he should be covering (near-post biased toward the shooter).
    let ideal_x = goal_center_x + (player_position.x - goal_center_x) * 0.25;
    let lateral_offset = (keeper_position.x - ideal_x).abs();
    let lateral_factor = ((lateral_offset - half_width) / (half_width * 2.0)).clamp(0.0, 1.0);
    advance_factor.max(lateral_factor)
}

fn shot_beat_goalkeeper_probability_for_snapshot(
    snapshot: &WorldSnapshot,
    player: &PlayerSnapshot,
    player_position: Vec2,
) -> f64 {
    let Some(keeper_id) = snapshot.goalkeeper_for(player.team.other()) else {
        return 0.35;
    };
    let Some(keeper) = snapshot.players.iter().find(|p| p.id == keeper_id) else {
        return 0.35;
    };
    let keeper_position = snapshot
        .player_position(keeper_id)
        .unwrap_or(keeper.position);
    let goal_y = player.team.goal_y(snapshot.field_length);
    let goal_center_x = snapshot.field_width * 0.5;
    let half_width = snapshot.goal_width * 0.5;
    let keeper_opposite_x = if keeper_position.x <= goal_center_x {
        goal_center_x + half_width * 0.72
    } else {
        goal_center_x - half_width * 0.72
    };
    let shooter_angle_x = if player_position.x <= goal_center_x {
        goal_center_x + half_width * 0.38
    } else {
        goal_center_x - half_width * 0.38
    };
    let crossing_x = (keeper_opposite_x * 0.72 + shooter_angle_x * 0.28)
        .clamp(goal_center_x - half_width, goal_center_x + half_width);
    let shot_crossing = Vec2::new(crossing_x, goal_y);
    let shooting_skill = ability01(player.skills.shooting);
    let foot_power = ability01(
        player
            .skills
            .right_foot_shot_power
            .max(player.skills.left_foot_shot_power),
    );
    let shot_power = shot_power_for_skill(shooting_skill * 0.72 + foot_power * 0.28);
    let shot_speed = shot_speed_yps_from_power(shot_power.clamp(0.0, 1.0), &player.skills);
    let save_probability = goalkeeper_save_probability_from_traits(
        &keeper.skills,
        keeper_position,
        keeper.velocity,
        keeper.fatigue,
        player_position,
        shot_crossing,
        shot_speed,
        snapshot.goal_width,
        0.0,
    );
    (1.0 - save_probability).clamp(0.0, 1.0)
}

fn goalkeeper_for_players(players: &[PlayerAgent], team: Team) -> Option<usize> {
    players
        .iter()
        .find(|player| player.team == team && player.role == PlayerRole::Goalkeeper)
        .map(|player| player.id)
}

fn last_recover_target_for_player(player: &PlayerAgent) -> Option<Vec2> {
    let decision = player.last_decision.as_ref()?;
    let label = normalize_soccer_action_label(&decision.action);
    if !matches!(label, ACTION_LABEL_RECOVER | FIFTY_FIFTY_DUEL_ACTION_LABEL) {
        return None;
    }
    decision
        .action_target
        .as_ref()
        .and_then(|target| target.point)
}

fn teammate_dummy_pass_lane_geometry_applies(
    from: Vec2,
    to: Vec2,
    middle: Vec2,
    receiver_openness: f64,
    lane_gap_yards: f64,
) -> bool {
    let lane = to - from;
    let lane_len = lane.len();
    if lane_len < TEAMMATE_DUMMY_PASS_MIN_TOTAL_YARDS {
        return false;
    }
    let projection = segment_projection_factor(from, to, middle);
    if !(0.0..1.0).contains(&projection) {
        return false;
    }
    let along = lane_len * projection;
    let beyond = lane_len - along;
    if along < TEAMMATE_DUMMY_PASS_MIN_FROM_PASSER_YARDS
        || beyond < TEAMMATE_DUMMY_PASS_MIN_BEYOND_YARDS
    {
        return false;
    }
    if segment_distance_to_point(from, to, middle) > lane_gap_yards {
        return false;
    }
    receiver_openness >= TEAMMATE_DUMMY_PASS_MIN_RECEIVER_OPENNESS
}

fn pending_pass_dummy_through_applies_for_agent(
    player: &PlayerAgent,
    players: &[PlayerAgent],
    pass: &PendingPass,
    control_point: Vec2,
) -> bool {
    if player.team != pass.team
        || player.role == PlayerRole::Goalkeeper
        || pass.from == player.id
        || pass.target == Some(player.id)
        || !matches!(pass.flight, PassFlight::Floor)
    {
        return false;
    }
    let Some(receiver_id) = pass.target else {
        return false;
    };
    let Some(receiver) = players.iter().find(|p| p.id == receiver_id) else {
        return false;
    };
    if receiver.team != pass.team || receiver.role == PlayerRole::Goalkeeper {
        return false;
    }
    if segment_distance_to_point(pass.origin, pass.intended_target, control_point)
        > TEAMMATE_CLEAR_PASS_LANE_DETECTION_RADIUS_YARDS
    {
        return false;
    }
    teammate_dummy_pass_lane_geometry_applies(
        pass.origin,
        pass.intended_target,
        player.position,
        pass.receiver_openness,
        TEAMMATE_DUMMY_PASS_LANE_GAP_YARDS,
    )
}

fn nearest_opponent_distance_to_point(players: &[PlayerAgent], team: Team, point: Vec2) -> f64 {
    players
        .iter()
        .filter(|player| player.team != team && player.role != PlayerRole::Goalkeeper)
        .map(|player| player.position.distance(point))
        .fold(f64::INFINITY, f64::min)
}

fn nearest_ball_controller_for(
    current_tick: u64,
    ball_pos: Vec2,
    ball_velocity: Vec2,
    players: &[PlayerAgent],
    pending_pass: Option<&PendingPass>,
    loose_long_ball_team: Option<Team>,
    same_tick_long_ball_launcher: Option<usize>,
    ball_altitude_yards: f64,
    rng: &mut SeededRandom,
) -> Option<(usize, Team)> {
    nearest_ball_controller_for_segment(
        current_tick,
        ball_pos,
        ball_pos,
        ball_velocity,
        players,
        pending_pass,
        loose_long_ball_team,
        same_tick_long_ball_launcher,
        ball_altitude_yards,
        rng,
    )
    .map(|(id, team, _)| (id, team))
}

fn nearest_ball_controller_for_segment(
    current_tick: u64,
    previous_ball_pos: Vec2,
    ball_pos: Vec2,
    ball_velocity: Vec2,
    players: &[PlayerAgent],
    pending_pass: Option<&PendingPass>,
    loose_long_ball_team: Option<Team>,
    same_tick_long_ball_launcher: Option<usize>,
    ball_altitude_yards: f64,
    rng: &mut SeededRandom,
) -> Option<(usize, Team, Vec2)> {
    // No restart double-touch guard. The guarded entry point below is what the live ball step
    // uses; tests and the loose-ball-winner wrapper go through this no-guard shim.
    nearest_ball_controller_for_segment_with_guard(
        current_tick,
        previous_ball_pos,
        ball_pos,
        ball_velocity,
        players,
        pending_pass,
        loose_long_ball_team,
        same_tick_long_ball_launcher,
        ball_altitude_yards,
        None,
        None,
        rng,
    )
}

fn nearest_ball_controller_for_segment_with_guard(
    current_tick: u64,
    previous_ball_pos: Vec2,
    ball_pos: Vec2,
    ball_velocity: Vec2,
    players: &[PlayerAgent],
    pending_pass: Option<&PendingPass>,
    loose_long_ball_team: Option<Team>,
    same_tick_long_ball_launcher: Option<usize>,
    ball_altitude_yards: f64,
    double_touch_guard: Option<usize>,
    dummy_let_through_guard: Option<usize>,
    rng: &mut SeededRandom,
) -> Option<(usize, Team, Vec2)> {
    let ball_speed = ball_velocity.len();
    let ball_segment = ball_pos - previous_ball_pos;
    let ball_segment_len = ball_segment.len();
    let mut candidates = Vec::new();
    let mut low_pass_body_contact: Option<(f64, f64, usize, Team, Vec2)> = None;
    let mut reactive_ground_pass_trap: Option<(f64, f64, usize, Team, Vec2)> = None;
    let mut rolling_loose_ball_trap: Option<(f64, f64, usize, Team, Vec2)> = None;
    for p in players {
        if same_tick_long_ball_launcher == Some(p.id) {
            continue;
        }
        // No-double-touch on restarts: the taker is INELIGIBLE to (re-)control the ball until
        // another player touches it, so exclude it from the search entirely. The nearest OTHER
        // player — a team-mate receiving the restart — then collects it, instead of the ball
        // stalling at the taker's feet whenever the taker happens to be the closest player.
        if double_touch_guard == Some(p.id) {
            continue;
        }
        // A team-mate dummying the ball lets it run through to the man behind — exclude it
        // from control candidacy this tick so it does not trap a pass aimed past it.
        if dummy_let_through_guard == Some(p.id) {
            continue;
        }
        if let Some(pass) = pending_pass {
            if current_tick <= pass.launch_tick && p.id == pass.from {
                continue;
            }
        }
        let control_projection = if ball_segment_len > 1e-6 {
            segment_projection_factor(previous_ball_pos, ball_pos, p.position)
        } else {
            1.0
        };
        let control_point = if ball_segment_len > 1e-6 {
            previous_ball_pos + ball_segment * control_projection
        } else {
            ball_pos
        };
        if pending_pass.is_some_and(|pass| {
            pending_pass_dummy_through_applies_for_agent(p, players, pass, control_point)
        }) {
            continue;
        }
        if let Some(pass) = pending_pass {
            let is_target = pass.target == Some(p.id);
            let progress = pass_progress_along_path(pass, control_point);
            let same_tick_launch = current_tick <= pass.launch_tick
                && progress < PASS_SAME_TICK_BYSTANDER_IGNORE_PROGRESS;
            let is_own_outgoing_pass = pass.from == p.id && pass.target != Some(p.id);
            // Clamp the pass-model arc height to the ACTUAL ball altitude so a landed/overshot
            // aerial pass (ball physically on the grass, model still high) is correctly treated as
            // a grounded, contestable ball rather than one flying overhead.
            let contact_altitude =
                pass_altitude_at_point(pass, control_point).min(ball_altitude_yards);
            let same_team_launch_bystander = same_tick_launch && p.team == pass.team && !is_target;
            let body_contact_distance = p.position.distance(control_point);
            if contact_altitude <= LOW_BALL_FACING_REQUIRED_ALTITUDE_YARDS
                && !is_own_outgoing_pass
                && !same_team_launch_bystander
                && body_contact_distance <= LOW_PASS_BODY_INTERCEPT_RADIUS_YARDS
            {
                let replace = low_pass_body_contact.as_ref().is_none_or(
                    |(best_projection, best_distance, _, _, _)| {
                        control_projection < *best_projection - 1e-9
                            || ((control_projection - *best_projection).abs() <= 1e-9
                                && body_contact_distance < *best_distance)
                    },
                );
                if replace {
                    low_pass_body_contact = Some((
                        control_projection,
                        body_contact_distance,
                        p.id,
                        p.team,
                        control_point,
                    ));
                }
            }
            if !is_target
                && matches!(pass.flight, PassFlight::Floor)
                && contact_altitude <= BALL_ROLLING_ALTITUDE_YARDS
                && !is_own_outgoing_pass
                && !same_team_launch_bystander
                && body_contact_distance <= REACTIVE_GROUND_PASS_CONTROL_RADIUS_YARDS
            {
                let pass_arrival = (pass.distance_yards
                    / pass
                        .launch_speed_yps
                        .max(REACTIVE_GROUND_PASS_MIN_SPEED_YPS)
                    * progress.clamp(0.0, 1.0))
                .max(
                    (control_point - previous_ball_pos).len()
                        / ball_speed.max(REACTIVE_GROUND_PASS_MIN_SPEED_YPS),
                );
                let reaction_window = (pass_arrival - PASS_LANE_INTERCEPT_REACTION_SECONDS)
                    .clamp(0.0, PASS_LANE_INTERCEPT_MAX_WINDOW_SECONDS);
                let player_speed = player_top_speed_yps(p.role, &p.skills)
                    * fatigue_speed_factor(p.skills.stamina, p.fatigue)
                    * MovementGait::Sprint.speed_multiplier();
                let reach = INTERCEPT_LUNGE_REACH_YARDS + player_speed * reaction_window;
                let cone_quality =
                    player_facing_ball_control_multiplier(p, control_point, ball_speed);
                let mpc_fit = mpc_ball_control_execution_fit(
                    p.role,
                    &p.skills,
                    p.fatigue,
                    p.position,
                    p.velocity,
                    cone_quality,
                    control_point,
                    ball_velocity,
                    pass_arrival,
                    REACTIVE_GROUND_PASS_CONTROL_RADIUS_YARDS,
                );
                if body_contact_distance <= reach
                    && (cone_quality >= CONTROL_MIN_VIABLE_QUALITY
                        || body_contact_distance <= CONTROL_AT_FEET_TRAP_RADIUS_YARDS)
                    && (mpc_fit.qp_accel_fit >= MPC_BALL_CONTROL_FORCED_MIN_QP_ACCEL_FIT
                        || body_contact_distance <= CONTROL_AT_FEET_TRAP_RADIUS_YARDS)
                {
                    let replace = reactive_ground_pass_trap.as_ref().is_none_or(
                        |(best_projection, best_distance, _, _, _)| {
                            control_projection < *best_projection - 1e-9
                                || ((control_projection - *best_projection).abs() <= 1e-9
                                    && body_contact_distance < *best_distance)
                        },
                    );
                    if replace {
                        reactive_ground_pass_trap = Some((
                            control_projection,
                            body_contact_distance,
                            p.id,
                            p.team,
                            control_point,
                        ));
                    }
                }
            }
        } else if ball_altitude_yards <= BALL_ROLLING_ALTITUDE_YARDS
            && ball_speed >= REACTIVE_GROUND_PASS_MIN_SPEED_YPS
            && ball_segment_len > REACTIVE_GROUND_PASS_GEOMETRY_EPSILON_YARDS
        {
            let body_contact_distance = p.position.distance(control_point);
            if body_contact_distance <= REACTIVE_GROUND_PASS_CONTROL_RADIUS_YARDS {
                let ball_arrival = (control_point - previous_ball_pos).len()
                    / ball_speed.max(REACTIVE_GROUND_PASS_MIN_SPEED_YPS);
                let player_speed = player_top_speed_yps(p.role, &p.skills)
                    * fatigue_speed_factor(p.skills.stamina, p.fatigue)
                    * MovementGait::Sprint.speed_multiplier();
                let reach = INTERCEPT_LUNGE_REACH_YARDS
                    + player_speed
                        * ball_arrival.clamp(0.0, PASS_LANE_INTERCEPT_MAX_WINDOW_SECONDS);
                let cone_quality =
                    player_facing_ball_control_multiplier(p, control_point, ball_speed);
                let mpc_fit = mpc_ball_control_execution_fit(
                    p.role,
                    &p.skills,
                    p.fatigue,
                    p.position,
                    p.velocity,
                    cone_quality,
                    control_point,
                    ball_velocity,
                    ball_arrival,
                    REACTIVE_GROUND_PASS_CONTROL_RADIUS_YARDS,
                );
                if body_contact_distance <= reach
                    && (cone_quality >= CONTROL_MIN_VIABLE_QUALITY
                        || body_contact_distance <= CONTROL_AT_FEET_TRAP_RADIUS_YARDS)
                    && (mpc_fit.qp_accel_fit >= MPC_BALL_CONTROL_FORCED_MIN_QP_ACCEL_FIT
                        || body_contact_distance <= CONTROL_AT_FEET_TRAP_RADIUS_YARDS)
                {
                    let replace = rolling_loose_ball_trap.as_ref().is_none_or(
                        |(best_projection, best_distance, _, _, _)| {
                            control_projection < *best_projection - 1e-9
                                || ((control_projection - *best_projection).abs() <= 1e-9
                                    && body_contact_distance < *best_distance)
                        },
                    );
                    if replace {
                        rolling_loose_ball_trap = Some((
                            control_projection,
                            body_contact_distance,
                            p.id,
                            p.team,
                            control_point,
                        ));
                    }
                }
            }
        }
        let mut player_control_position = p.position;
        let mut control_radius = (PLAYER_CONTROL_RADIUS_YARDS
            + ability01(p.skills.first_touch) * 0.48
            + (1.0 - (ball_speed / 28.0).clamp(0.0, 1.0)) * 0.24)
            // A disoriented (dizzy) player tracks and traps the ball less cleanly.
            * (1.0 - p.dizziness.clamp(0.0, 1.0) * DIZZINESS_CONTROL_PENALTY);
        let mut aerial_score_bonus = 0.0;
        let mut pass_reception_score_bonus = 0.0;
        if let Some(pass) = pending_pass {
            let is_target = pass.target == Some(p.id);
            let progress = pass_progress_along_path(pass, control_point);
            let openness = pass.receiver_openness.clamp(0.0, 1.0);
            if is_target {
                if let Some(receiver_position) = pass.receiver_position_at_launch {
                    let route = pass.intended_target - receiver_position;
                    let route_len = route.len();
                    if route_len > 1e-6 {
                        let travel_time =
                            (pass.distance_yards / pass.launch_speed_yps.max(1.0)).clamp(0.12, 3.2);
                        let route_availability = ((openness - 0.25) / 0.75).clamp(0.0, 1.0);
                        let route_speed = player_top_speed_yps(p.role, &p.skills)
                            * fatigue_speed_factor(p.skills.stamina, p.fatigue)
                            * if pass.flight.is_aerial() { 0.78 } else { 0.72 }
                            * route_availability;
                        let reachable =
                            (route_speed * travel_time * progress).clamp(0.0, route_len);
                        player_control_position =
                            receiver_position + route.normalized() * reachable;
                    }
                }
            }
            let same_tick_launch = current_tick <= pass.launch_tick
                && progress < PASS_SAME_TICK_BYSTANDER_IGNORE_PROGRESS;
            if same_tick_launch && p.team == pass.team && !is_target {
                control_radius *= 0.35;
            }
            if is_target {
                control_radius *= 0.48 + openness * 0.62;
                // A settled receiver (walk/jog/skip/run, not a full sprint) takes
                // the ball more cleanly than someone sprinting onto it.
                let gait_control = if matches!(p.movement_gait, MovementGait::Sprint) {
                    0.82
                } else {
                    1.18
                };
                // Control is easiest around a firm ~13 mph pass; a dying ball is
                // awkward and only a truly fierce drive is hard to take. Skilled
                // receivers trap driven passes well, so the window is wide and the
                // floor is high (faster passes still get controlled cleanly).
                let sweet_spot_yps = mph_to_yps(13.0);
                let speed_offset = (pass.launch_speed_yps - sweet_spot_yps).abs();
                let speed_control =
                    (1.18 - (speed_offset / 22.0).clamp(0.0, 0.42)).clamp(0.80, 1.18);
                control_radius *= gait_control * speed_control;
                pass_reception_score_bonus += -0.18 + openness * 0.50 + pass.passer_skill * 0.16;
            } else if p.team == pass.team {
                pass_reception_score_bonus -= 0.08;
            } else {
                let marked_pressure = 1.0 - openness;
                control_radius *= 1.00 + marked_pressure * 0.12;
                pass_reception_score_bonus += marked_pressure * 0.48;
            }
            if pass.flight.is_aerial() {
                let landing_distance = control_point.distance(pass.intended_target);
                let interception_multiplier = aerial_interception_multiplier(pass, control_point);
                if !is_target && landing_distance > 7.5 {
                    control_radius *= if p.team == pass.team { 0.70 } else { 0.55 };
                }
                let aerial_duel = aerial_duel_skill_from_agent(p);
                control_radius += aerial_duel * 0.45;
                aerial_score_bonus += aerial_duel * 0.72;
                if p.team != pass.team {
                    control_radius +=
                        PLAYER_CONTROL_RADIUS_YARDS * (interception_multiplier - 1.0) * 0.26;
                    aerial_score_bonus += (interception_multiplier - 1.0) * 0.34;
                    aerial_score_bonus += if landing_distance <= 8.5 { 0.62 } else { 0.28 };
                }
            }
            // (Facing/control-cone penalty is applied below, where the ball's altitude is
            // known, so it gates only LOW balls — a high ball can be taken backpedalling.)
        } else if let Some(long_ball_team) = loose_long_ball_team {
            if ball_altitude_yards > 0.02 || ball_speed >= 8.0 {
                let airborne = ball_altitude_yards > 0.02;
                if airborne {
                    let aerial_duel = aerial_duel_skill_from_agent(p);
                    let altitude_bonus = (ball_altitude_yards / 0.22).clamp(0.0, 1.0);
                    control_radius += aerial_duel * (0.34 + altitude_bonus * 0.24);
                    aerial_score_bonus += aerial_duel * (0.58 + altitude_bonus * 0.18);
                } else {
                    control_radius += ability01(p.skills.first_touch) * 0.18;
                    pass_reception_score_bonus += ability01(p.skills.dribbling) * 0.08;
                }
                if p.team == long_ball_team {
                    pass_reception_score_bonus += ability01(p.skills.first_touch) * 0.12;
                } else {
                    let defensive_duel_bonus = ability01(p.skills.defending) * 0.18
                        + ability01(p.skills.aggression) * 0.12;
                    if airborne {
                        aerial_score_bonus += defensive_duel_bonus;
                    } else {
                        pass_reception_score_bonus += defensive_duel_bonus * 0.72;
                    }
                    // (Facing/control-cone penalty applied below, low-ball only.)
                }
            }
        }
        // The intended receiver of a pass is meeting a ball played to them (and
        // descending to their feet at the target), so the interception gates
        // below must not apply — otherwise they "let it run" past their own pass.
        let is_pass_target = pending_pass.is_some_and(|pass| pass.target == Some(p.id));
        let dist = player_control_position.distance(control_point);
        // Contact altitude gates whether a player can reach the ball (a high ball flies over a
        // grounded player). For an aerial pass this is normally read from the pass MODEL's arc —
        // but an aerial pass that has LANDED or overshot stays pending while the ball physically
        // sits on the grass, and the model still reports it high in its arc. Reading the model
        // alone then treats a ball at a player's feet as flying overhead, so nobody is eligible to
        // control it and players run straight over it. Clamp to the ACTUAL ball altitude: the
        // physical ball is the authority, so a landed ball is grounded regardless of the stale arc.
        let contact_altitude = pending_pass
            .filter(|pass| pass.flight.is_aerial())
            .map(|pass| pass_altitude_at_point(pass, control_point).min(ball_altitude_yards))
            .unwrap_or(if loose_long_ball_team.is_some() {
                ball_altitude_yards
            } else {
                0.0
            })
            // Ground truth wins. The pass MODEL altitude is only valid while the ball is
            // genuinely following its launch parabola; a pass that has already landed and is now
            // rolling/skidding (or one that wildly overshot its target and is rolling away — a
            // STALE pending pass) is physically a floor ball, however it was launched. Without
            // this clamp such a ball is gated as "airborne", so the floor body-contact / trap
            // logic never fires and it rolls untouched right past players (the reported ghost).
            // For a genuine aerial in flight `ball_altitude_yards` ≈ the model, so this is a
            // no-op; the intended receiver bypasses these gates anyway (`is_pass_target`).
            .min(ball_altitude_yards.max(0.0));
        // Guaranteed trap: a non-aerial (floor) ball within the player's own control radius of
        // their ACTUAL feet is always controlled. A ball passing right under a player's feet is
        // not an "impossible-distance intercept", so it must bypass the kinematic-reach gate —
        // otherwise a quick ball at the feet shrinks the effective radius below where it
        // actually is and rolls past uncontrolled ("reacted too late"). The hard floor keeps a
        // 1yd trap even when facing/other multipliers shrink the control radius.
        let actual_dist = p.position.distance(control_point);
        // ...but the passer must not re-trap their OWN outgoing pass: the ball is still within a
        // yard of their feet for the first tick after launch, and a player can't control a ball
        // they just kicked away. (The receiver is handled by the is_pass_target path above.)
        let is_own_outgoing_pass =
            pending_pass.is_some_and(|pass| pass.from == p.id && pass.target != Some(p.id));
        // Graded control cone (biomechanics first-touch): how cleanly this player can take
        // the ball given facing angle, whether the ball is in view, and its speed. +/-60deg
        // = full, 60-120deg = degraded, >120deg / blind = deflection-only. The intended
        // receiver of a pass is exempt (they turn onto their own ball).
        let cone_quality = player_facing_ball_control_multiplier(p, control_point, ball_speed);
        let low_ball = contact_altitude <= LOW_BALL_FACING_REQUIRED_ALTITUDE_YARDS;
        let facing_viable = cone_quality >= CONTROL_MIN_VIABLE_QUALITY;
        let guaranteed_trap = contact_altitude <= BALL_ROLLING_ALTITUDE_YARDS
            && !is_own_outgoing_pass
            // A floor ball is always "low": it can only be trapped if you can take it —
            // unless it is right at the feet, where it is controlled regardless of facing
            // (a ball at your feet does not roll past because you were looking away).
            && (is_pass_target
                || facing_viable
                || actual_dist <= CONTROL_AT_FEET_TRAP_RADIUS_YARDS)
            && actual_dist <= GUARANTEED_FLOOR_TRAP_RADIUS_YARDS;
        // The control-cone penalty gates only a LOW ball (<=6ft): the degraded angle / blind
        // ball shrinks the control radius and reception value, and a ball you cannot get your
        // body+eyes to at all you simply can't take this tick (turn first). A HIGH ball stays
        // takeable while backpedalling under its descent, so it is left unpenalised.
        if !is_pass_target && low_ball && !guaranteed_trap {
            control_radius *= cone_quality;
            pass_reception_score_bonus *= cone_quality;
            aerial_score_bonus *= cone_quality;
            if !facing_viable {
                continue;
            }
        }
        // Kinematic reach cap (fast balls, non-targets only): the ball reaches the
        // contact point `t_ball = along / ball_speed` seconds into the step, and
        // the player can only close a lunge plus `player_speed * t_ball`. This
        // stops a fast ball being "intercepted" from impossible distances without
        // blocking a legitimate trap.
        let effective_radius = if !is_pass_target
            && !guaranteed_trap
            && ball_speed > KINEMATIC_GATE_MIN_BALL_SPEED_YPS
        {
            let along = (control_point - previous_ball_pos).len();
            let t_ball = along / ball_speed;
            let player_speed = player_top_speed_yps(p.role, &p.skills)
                * fatigue_speed_factor(p.skills.stamina, p.fatigue);
            control_radius.min(INTERCEPT_LUNGE_REACH_YARDS + player_speed * t_ball)
        } else {
            control_radius
        };
        if dist > effective_radius && !guaranteed_trap {
            continue;
        }
        // Physical trap reach: the route/anticipation projection decides WHO is best
        // placed to receive, but the ball can only actually be TAKEN when it is within
        // reach of the player's REAL feet this tick. Without this, a pass target whose
        // projected run point lined up with the ball could "magically" gain control while
        // still 2+ yd away, and the ball would then teleport onto them. (Non-targets
        // already gate on their real feet via `dist`.)
        if is_pass_target
            && !guaranteed_trap
            && actual_dist > control_radius.max(GUARANTEED_FLOOR_TRAP_RADIUS_YARDS)
        {
            continue;
        }
        // Altitude gate (non-targets only): a ball above the ground can only be
        // reached by players who can get up to it. High balls fly over grounded
        // players — but the intended receiver is taking it at the landing. A ball at
        // or below ~6ft is at head/chest height and is reachable by any standing
        // player (the reach floor), so a pass played THROUGH a player at that height
        // is always contestable here regardless of aerial ability; aerial skill only
        // extends reach above the floor for leaping headers.
        if !is_pass_target && !guaranteed_trap && contact_altitude > BALL_ROLLING_ALTITUDE_YARDS {
            let reach_height = (CONTROL_STANDING_REACH_YARDS
                + aerial_duel_skill_from_agent(p) * CONTROL_AERIAL_JUMP_REACH_YARDS)
                .max(LOW_BALL_INTERCEPT_REACH_FLOOR_YARDS);
            if contact_altitude > reach_height {
                continue;
            }
        }
        let mut mpc_control_score_bonus = 0.0;
        if low_ball
            && ball_speed >= REACTIVE_GROUND_PASS_MIN_SPEED_YPS
            && ball_segment_len > REACTIVE_GROUND_PASS_GEOMETRY_EPSILON_YARDS
            && !guaranteed_trap
        {
            let along = (control_point - previous_ball_pos).len();
            let ball_contact_time = along / ball_speed.max(REACTIVE_GROUND_PASS_MIN_SPEED_YPS);
            let mpc_fit = mpc_ball_control_execution_fit(
                p.role,
                &p.skills,
                p.fatigue,
                p.position,
                p.velocity,
                cone_quality,
                control_point,
                ball_velocity,
                ball_contact_time,
                effective_radius.max(CONTROL_AT_FEET_TRAP_RADIUS_YARDS),
            );
            if mpc_fit.qp_accel_fit < MPC_BALL_CONTROL_MIN_QP_ACCEL_FIT {
                continue;
            }
            mpc_control_score_bonus = mpc_fit.probability * MPC_BALL_CONTROL_SCORE_WEIGHT
                + mpc_fit.qp_accel_fit * 0.18
                + mpc_fit.velocity_match * 0.08;
        }
        let to_ball = (control_point - player_control_position).normalized();
        let closing_speed = dot(p.velocity - ball_velocity, to_ball).clamp(-8.0, 8.0);
        // A guaranteed trap is scored by the ball's true closeness to the player's
        // feet, so a ball rolling right under them wins the candidacy instead of
        // losing on an off route-lead projection.
        let score_dist = if guaranteed_trap { actual_dist } else { dist };
        let score = -score_dist * 1.45
            + ability01(p.skills.first_touch) * 0.72
            + ability01(p.skills.aggression) * 0.18
            + closing_speed * 0.055
            + mpc_control_score_bonus
            + pass_reception_score_bonus
            + aerial_score_bonus;
        candidates.push((p.id, p.team, score, control_point));
    }
    let mut forced_ground_control = match (low_pass_body_contact, reactive_ground_pass_trap) {
        (Some(low), Some(reactive)) => {
            if reactive.0 < low.0 - 1e-9
                || ((reactive.0 - low.0).abs() <= 1e-9 && reactive.1 < low.1)
            {
                Some(reactive)
            } else {
                Some(low)
            }
        }
        (Some(low), None) => Some(low),
        (None, Some(reactive)) => Some(reactive),
        (None, None) => None,
    };
    if let Some(rolling) = rolling_loose_ball_trap {
        forced_ground_control = match forced_ground_control {
            Some(existing) => {
                if rolling.0 < existing.0 - 1e-9
                    || ((rolling.0 - existing.0).abs() <= 1e-9 && rolling.1 < existing.1)
                {
                    Some(rolling)
                } else {
                    Some(existing)
                }
            }
            None => Some(rolling),
        };
    }
    if let Some((_, _, id, team, point)) = forced_ground_control {
        return Some((id, team, point));
    }
    sample_control_candidate_with_point(&candidates, rng)
}

fn triangular_sample(_rng: &mut SeededRandom) -> f64 {
    0.0
}

fn boundary_crossing_fraction(start: f64, end: f64, lower: f64, upper: f64) -> Option<f64> {
    let boundary = if end < lower {
        lower
    } else if end > upper {
        upper
    } else {
        return None;
    };
    let delta = end - start;
    if delta.abs() <= 1e-9 {
        return Some(1.0);
    }
    Some(((boundary - start) / delta).clamp(0.0, 1.0))
}

/// Clamp the unit direction `target` to lie within `max_angle` radians of `axis`. If it's already
/// inside the cone it's returned (normalized); otherwise `axis` is rotated toward `target` by
/// exactly `max_angle`. Used so a moving player's facing can lean toward the ball only as far as
/// the gait allows off the movement direction.
fn clamp_dir_to_cone(target: Vec2, axis: Vec2, max_angle: f64) -> Vec2 {
    if axis.len() < 1e-9 {
        return if target.len() >= 1e-9 {
            target.normalized()
        } else {
            target
        };
    }
    let a = axis.normalized();
    if target.len() < 1e-9 {
        return a;
    }
    let t = target.normalized();
    let cos = t.x * a.x + t.y * a.y;
    let angle = cos.clamp(-1.0, 1.0).acos();
    if angle <= max_angle {
        return t;
    }
    // Rotate `axis` toward `target` by max_angle (sign from the 2D cross product).
    let cross = a.x * t.y - a.y * t.x;
    let theta = if cross >= 0.0 { max_angle } else { -max_angle };
    let (s, c) = (theta.sin(), theta.cos());
    return Vec2::new(a.x * c - a.y * s, a.x * s + a.y * c);
}

/// Preference (0..1) for a pass of length `dist`: a single optimum length scores 1.0, with a
/// linear ramp up to it and a linear fade beyond. The optimum is 8yd by default, or 15yd when
/// the ideal-pass-length gate is on (see [`ideal_pass_length_15yd_enabled`]) so the engine
/// favours a meaningful ~15yd progression over a short square pass.
fn pass_length_preference(dist: f64) -> f64 {
    let (optimal, fadeout) = if ideal_pass_length_15yd_enabled() {
        (
            IDEAL_PASS_LENGTH_OPTIMAL_YARDS,
            IDEAL_PASS_LENGTH_FADEOUT_YARDS,
        )
    } else {
        (PASS_LENGTH_OPTIMAL_YARDS, PASS_LENGTH_FADEOUT_YARDS)
    };
    pass_length_preference_curve(dist, optimal, fadeout)
}

/// Pure triangular length-preference curve: 1.0 at `optimal`, linear ramp up to it and linear
/// fade to zero at `fadeout`. Env-free so it is unit-tested directly without the gate.
fn pass_length_preference_curve(dist: f64, optimal: f64, fadeout: f64) -> f64 {
    if !dist.is_finite() || dist <= 0.0 {
        return 0.0;
    }
    if dist <= optimal {
        return (dist / optimal).clamp(0.0, 1.0);
    }
    let fade_band = (fadeout - optimal).max(1.0);
    (1.0 - (dist - optimal) / fade_band).clamp(0.0, 1.0)
}

/// Length preference for a BACKWARD pass. Unlike the forward/lateral curve (which peaks at
/// the 8yd "optimal" length), a backward ball is safest when it's a SHORT drop: full
/// preference up to the 5yd short cap, then fading to zero as the retreat lengthens. This
/// stops the engine treating a long (e.g. 8yd) backward pass as "optimal length".
fn backward_pass_length_preference(dist: f64) -> f64 {
    if !dist.is_finite() || dist <= 0.0 {
        return 0.0;
    }
    if dist <= BACKWARD_PASS_SHORT_MAX_YARDS {
        1.0
    } else {
        (1.0 - (dist - BACKWARD_PASS_SHORT_MAX_YARDS) / BACKWARD_PASS_LENGTH_FADE_BAND_YARDS)
            .clamp(0.0, 1.0)
    }
}

/// Per-passer risk/safety appetite used to shade the (already-quantified) MPC/POMDP pass-lane
/// interception risk when ranking pass options. This does NOT recompute risk — it scales how a
/// given risk value is PRICED for the player on the ball:
///   * `forward_risk_penalty_mult` — multiplier on the interception-risk penalty for a FORWARD
///     ball (`> 1` = more risk-averse, `< 1` = braver going forward).
///   * `sideways_risk_penalty_mult` — same, but for a lateral/backward ball, so a higher forward
///     appetite never loosens square/back balls.
///   * `forward_preference_lift` — additive bump to the forward-progress weight, so a forward is
///     nudged to prefer a forward ball over a lateral/backward one even when it is riskier.
#[derive(Clone, Copy, Debug)]
struct PassRiskAppetite {
    forward_risk_penalty_mult: f64,
    sideways_risk_penalty_mult: f64,
    forward_preference_lift: f64,
}

impl PassRiskAppetite {
    /// Identity appetite: prices risk exactly as the baseline does (gate OFF ⇒ byte-identical).
    const NEUTRAL: PassRiskAppetite = PassRiskAppetite {
        forward_risk_penalty_mult: 1.0,
        sideways_risk_penalty_mult: 1.0,
        forward_preference_lift: 0.0,
    };
}

/// Resolve the [`PassRiskAppetite`] for the passer's role and field zone. Returns
/// [`PassRiskAppetite::NEUTRAL`] (byte-identical) unless
/// [`dd_soccer_enable_role_pass_risk_appetite`] is enabled. Defenders/keeper lean SAFE; forwards
/// lean BRAVE on the FORWARD ball, escalating in the attacking third; midfielders are roughly
/// neutral with a small final-third nudge.
fn pass_risk_appetite_for_passer(
    role: PlayerRole,
    passer_in_attacking_third: bool,
) -> PassRiskAppetite {
    if !dd_soccer_enable_role_pass_risk_appetite() {
        return PassRiskAppetite::NEUTRAL;
    }
    pass_risk_appetite_table(role, passer_in_attacking_third)
}

/// Pure role/zone → appetite mapping (no gate read), so it is unit-testable without touching the
/// process-global gate env var. See [`pass_risk_appetite_for_passer`] for the gated entry point.
fn pass_risk_appetite_table(role: PlayerRole, passer_in_attacking_third: bool) -> PassRiskAppetite {
    match role {
        // The keeper must not gamble in build-up: amplify risk everywhere, prefer the safe ball.
        PlayerRole::Goalkeeper => PassRiskAppetite {
            forward_risk_penalty_mult: 1.50,
            sideways_risk_penalty_mult: 1.55,
            forward_preference_lift: -0.10,
        },
        // Defenders only make safer passes — lean into safety in every direction.
        PlayerRole::Defender => PassRiskAppetite {
            forward_risk_penalty_mult: 1.30,
            sideways_risk_penalty_mult: 1.22,
            forward_preference_lift: -0.05,
        },
        // Midfielders are the pivot: ~neutral, with a small forward nudge in the final third.
        PlayerRole::Midfielder => {
            if passer_in_attacking_third {
                PassRiskAppetite {
                    forward_risk_penalty_mult: 0.90,
                    sideways_risk_penalty_mult: 1.04,
                    forward_preference_lift: 0.08,
                }
            } else {
                PassRiskAppetite {
                    forward_risk_penalty_mult: 1.0,
                    sideways_risk_penalty_mult: 1.0,
                    forward_preference_lift: 0.02,
                }
            }
        }
        // Forwards may play slightly riskier — and in the opponent's final third should prefer a
        // forward ball over a safe lateral/backward one even when it is high-risk.
        PlayerRole::Forward => {
            if passer_in_attacking_third {
                PassRiskAppetite {
                    forward_risk_penalty_mult: 0.66,
                    sideways_risk_penalty_mult: 1.12,
                    forward_preference_lift: 0.22,
                }
            } else {
                PassRiskAppetite {
                    forward_risk_penalty_mult: 0.82,
                    sideways_risk_penalty_mult: 1.06,
                    forward_preference_lift: 0.10,
                }
            }
        }
    }
}

fn directional_pass_progress_score(forward_yards: f64, weight: f64) -> f64 {
    if !forward_yards.is_finite() || !weight.is_finite() {
        return 0.0;
    }
    let weight = weight.max(0.0);
    if forward_yards >= 0.0 {
        forward_yards * weight * FORWARD_PASS_VALUE_MULTIPLIER
    } else {
        forward_yards * weight * BACKWARD_PASS_VALUE_MULTIPLIER
    }
}

fn dd_soccer_disable_illegal_short_pass_ban() -> bool {
    use std::sync::OnceLock;
    static V: OnceLock<bool> = OnceLock::new();
    *V.get_or_init(|| std::env::var("DD_SOCCER_DISABLE_ILLEGAL_SHORT_PASS_BAN").is_ok())
}

fn pass_distance_is_illegal_short(distance_yards: f64) -> bool {
    !dd_soccer_disable_illegal_short_pass_ban()
        && distance_yards.is_finite()
        && distance_yards < ILLEGAL_SHORT_PASS_MAX_YARDS
}

fn backward_pass_distance_risk_units(forward_yards: f64) -> f64 {
    if !forward_yards.is_finite() || forward_yards >= 0.0 {
        return 0.0;
    }
    ((-forward_yards) / BACKWARD_PASS_DISTANCE_RISK_REFERENCE_YARDS.max(1e-6))
        .max(0.0)
        .powf(BACKWARD_PASS_DISTANCE_RISK_EXPONENT)
}

fn backward_pass_completion_multiplier(forward_yards: f64) -> f64 {
    let risk = backward_pass_distance_risk_units(forward_yards);
    (1.0 - risk * BACKWARD_PASS_COMPLETION_RISK_PER_UNIT).clamp(0.32, 1.0)
}

/// Escalating demerit for a backward pass. Returns 0 for forward/square balls, applies a small
/// demotion even to short resets, then compounds with backward distance.
/// `forward_yards` is signed attacking-direction progress (negative = backward).
fn long_backward_pass_penalty(forward_yards: f64) -> f64 {
    if !forward_yards.is_finite() || forward_yards >= 0.0 {
        return 0.0;
    }
    backward_pass_distance_risk_units(forward_yards) * LONG_BACKWARD_PASS_PENALTY_PER_RISK_UNIT
}

fn dd_soccer_disable_backward_pass_pressure_release_gate() -> bool {
    use std::sync::OnceLock;
    static V: OnceLock<bool> = OnceLock::new();
    *V.get_or_init(|| {
        std::env::var("DD_SOCCER_DISABLE_BACKWARD_PASS_PRESSURE_RELEASE_GATE").is_ok()
    })
}

fn backward_pass_pressure_release_score(
    forward_yards: f64,
    passer_pressure: f64,
    nearest_opponent_distance: f64,
    passer_position: Vec2,
    field_width: f64,
    field_length: f64,
) -> f64 {
    if dd_soccer_disable_backward_pass_pressure_release_gate()
        || !forward_yards.is_finite()
        || forward_yards >= -BACKWARD_PASS_MIN_FORWARD_YARDS
    {
        return 1.0;
    }
    let direct_pressure = ((passer_pressure.clamp(0.0, 1.0) - BACKWARD_PASS_HIGH_PRESSURE_MIN)
        / (BACKWARD_PASS_HIGH_PRESSURE_FULL - BACKWARD_PASS_HIGH_PRESSURE_MIN).max(1e-6))
    .clamp(0.0, 1.0);
    let direct_pressure = smoothstep_unit(direct_pressure);
    let (width, length) = sane_pitch_dimensions(field_width, field_length);
    let fallback = Vec2::new(width * 0.5, length * 0.5);
    let position = finite_pitch_point(passer_position, width, length, fallback);
    let touchline_gap = position.x.min(width - position.x);
    let byline_gap = position.y.min(length - position.y);
    let constrained_by_boundary = touchline_gap <= BACKWARD_PASS_CONSTRAINED_TOUCHLINE_MARGIN_YARDS
        || (touchline_gap <= BACKWARD_PASS_CONSTRAINED_TOUCHLINE_MARGIN_YARDS * 1.4
            && byline_gap <= BACKWARD_PASS_CONSTRAINED_CORNER_DEPTH_YARDS);
    let boundary_pressure = if constrained_by_boundary
        && nearest_opponent_distance.is_finite()
        && nearest_opponent_distance <= BACKWARD_PASS_BOUNDARY_PRESSURE_OPP_RADIUS_YARDS
    {
        1.0
    } else {
        0.0
    };
    direct_pressure.max(boundary_pressure)
}

fn backward_pass_pressure_release_penalty(forward_yards: f64, pressure_release_score: f64) -> f64 {
    if dd_soccer_disable_backward_pass_pressure_release_gate()
        || !forward_yards.is_finite()
        || forward_yards >= -BACKWARD_PASS_MIN_FORWARD_YARDS
    {
        return 0.0;
    }
    let missing_pressure = (1.0 - pressure_release_score.clamp(0.0, 1.0)).clamp(0.0, 1.0);
    if missing_pressure <= f64::EPSILON {
        return 0.0;
    }
    missing_pressure
        * (BACKWARD_PASS_LOW_PRESSURE_BASE_PENALTY
            + backward_pass_distance_risk_units(forward_yards)
                * BACKWARD_PASS_LOW_PRESSURE_RISK_PENALTY_PER_UNIT)
}

/// Extra demerit for playing the ball BACKWARD past opponents standing in the pass
/// corridor. Risk grows with BOTH how far backward (toward our own goal) the ball travels
/// and how many opponents sit on the path — a long backward ball through a crowd is the
/// worst case (territory conceded AND a likely interception/charge-down), whether the pass
/// is aerial or grounded. Returns 0 for forward/lateral or near-square balls, and for a
/// clear corridor (no opponents on the path). `forward_yards` is signed attacking-direction
/// progress (negative = backward); `opponents_on_path` is the count of opponents within the
/// lane radius (see [`WorldSnapshot::opponents_on_pass_path`]).
/// Uses the same score-penalty scale as [`backward_pass_path_traffic_for_snapshot`].
fn backward_pass_path_risk_penalty(forward_yards: f64, opponents_on_path: usize) -> f64 {
    if !forward_yards.is_finite()
        || forward_yards >= -BACKWARD_PASS_MIN_FORWARD_YARDS
        || opponents_on_path == 0
    {
        return 0.0;
    }
    let priced_risk_units = (backward_pass_distance_risk_units(forward_yards)
        - backward_pass_distance_risk_units(-BACKWARD_PASS_PATH_TRAFFIC_FREE_YARDS))
    .max(0.0);
    priced_risk_units
        * opponents_on_path as f64
        * BACKWARD_PASS_PATH_TRAFFIC_SCORE_PENALTY_PER_OPPONENT_RISK_UNIT
}

/// Soft risk (in 0..1 quality units) for the BACKWARD component of a one-two leg. A short
/// backpass is a normal part of a give-and-go, so a forward/square leg carries no risk; the
/// further BACK the leg is played and the more opponents sit in its corridor, the higher the
/// demerit, using the same exponential distance-risk units as normal backward passes. This
/// demotes (never vetoes) a long or through-traffic backward give/return. `forward_yards` is
/// signed attacking-direction progress for the leg (negative = backward).
fn wall_pass_leg_backward_risk(forward_yards: f64, opponents_on_path: usize) -> f64 {
    if !forward_yards.is_finite() || forward_yards >= 0.0 {
        return 0.0;
    }
    (backward_pass_distance_risk_units(forward_yards)
        * (1.0 + opponents_on_path as f64)
        * WALL_PASS_BACKWARD_RISK_PER_UNIT_PER_BODY)
        .min(WALL_PASS_BACKWARD_RISK_MAX)
}

fn backward_pass_depth_adjustment(forward_yards: f64) -> f64 {
    if !forward_yards.is_finite() || forward_yards >= -BACKWARD_PASS_MIN_FORWARD_YARDS {
        return 0.0;
    }
    let backward_yards = -forward_yards;
    if (BACKWARD_PASS_SHORT_RESET_MIN_YARDS..=BACKWARD_PASS_SHORT_RESET_MAX_YARDS)
        .contains(&backward_yards)
    {
        return -(backward_yards * BACKWARD_PASS_SHORT_RESET_PENALTY_PER_YARD);
    }
    if backward_yards > BACKWARD_PASS_SHORT_RESET_MAX_YARDS {
        return -(backward_pass_distance_risk_units(forward_yards)
            * BACKWARD_PASS_LONG_RESET_PENALTY_PER_RISK_UNIT);
    }
    0.0
}

fn lateral_pass_penalty(forward_yards: f64, aerial: bool) -> f64 {
    if forward_yards.is_finite() && forward_yards.abs() <= 1.25 {
        if aerial {
            AERIAL_LATERAL_PASS_PENALTY
        } else {
            GROUND_LATERAL_PASS_PENALTY
        }
    } else {
        0.0
    }
}

pub fn segment_distance_to_point(a: Vec2, b: Vec2, p: Vec2) -> f64 {
    let t = segment_projection_factor(a, b, p);
    let projection = a + (b - a) * t;
    let distance = p.distance(projection);
    if distance.is_finite() {
        distance.max(0.0)
    } else {
        f64::INFINITY
    }
}

fn segment_projection_factor(a: Vec2, b: Vec2, p: Vec2) -> f64 {
    let ab = b - a;
    let denom = ab.x * ab.x + ab.y * ab.y;
    if !denom.is_finite() || denom <= 1e-12 {
        return 0.0;
    }
    let ap = p - a;
    let projection = (ap.x * ab.x + ap.y * ab.y) / denom;
    if projection.is_finite() {
        projection.clamp(0.0, 1.0)
    } else {
        0.0
    }
}

fn dot(a: Vec2, b: Vec2) -> f64 {
    a.x * b.x + a.y * b.y
}

fn deterministic_separation_normal(a_id: usize, b_id: usize) -> Vec2 {
    let seed = ((a_id as u64 + 1) * 1_103_515_245) ^ ((b_id as u64 + 7) * 12_345);
    let angle = (seed % 6283) as f64 / 1000.0;
    Vec2::new(angle.cos(), angle.sin()).normalized()
}

/// True if a point lies inside either 18-yard penalty area: within 18 yards of a
/// goal line and within ~22 yards of the centre (the ~44-yard-wide box). Box
/// geometry mirrors the keeper-handball check. Free function so both
/// [`WorldSnapshot`] and [`SoccerMatch`] share one source of truth.
fn soccer_point_in_either_penalty_area(p: Vec2, field_width: f64, field_length: f64) -> bool {
    let near_goal_line = p.y <= 18.0 || p.y >= field_length - 18.0;
    let central = (p.x - field_width * 0.5).abs() <= 22.0;
    near_goal_line && central
}

/// A decongested spot for the yielding player of an over-close pair: straight off
/// the teammate, just past the minimum-spacing radius. The nudge's one job is to
/// open space, so it points purely *away* from the partner — biasing back toward
/// the player's own slot tended to drag it into a fresh neighbour. Holding the
/// overall shape is the formation LP's job; this only breaks the local overlap. A
/// degenerate (exactly coincident) pair falls back to a deterministic normal so
/// the two still separate along a stable, opposing axis. The `yielder_home`
/// argument is retained for callers/telemetry but no longer steers the point.
fn teammate_spacing_suggested_point(
    yielder_id: usize,
    yielder_pos: Vec2,
    _yielder_home: Vec2,
    other_id: usize,
    other_pos: Vec2,
    min_spacing: f64,
    distance: f64,
) -> Vec2 {
    let away = yielder_pos - other_pos;
    let away_dir = if away.len() > 1e-3 {
        away.normalized()
    } else {
        deterministic_separation_normal(yielder_id, other_id)
    };
    // Place the spot a clear minimum-spacing radius off the partner (plus a small
    // margin), measured from the partner so the yielder always ends up properly
    // clear rather than merely a touch further out than it already was.
    let clearance = (min_spacing + 0.75).max(distance + 0.5);
    other_pos + away_dir * clearance
}

fn sample_control_candidate_with_point(
    candidates: &[(usize, Team, f64, Vec2)],
    _rng: &mut SeededRandom,
) -> Option<(usize, Team, Vec2)> {
    if candidates.is_empty() {
        return None;
    }
    if candidates.len() == 1 {
        let (id, team, _, point) = candidates[0];
        return Some((id, team, point));
    }

    candidates
        .iter()
        .max_by(|a, b| {
            a.2.total_cmp(&b.2)
                .then_with(|| b.0.cmp(&a.0))
                .then_with(|| (b.1 as u8).cmp(&(a.1 as u8)))
        })
        .map(|(id, team, _, point)| (*id, *team, *point))
}

fn sample_control_candidate(
    candidates: &[(usize, Team, f64)],
    _rng: &mut SeededRandom,
) -> Option<(usize, Team)> {
    if candidates.is_empty() {
        return None;
    }
    if candidates.len() == 1 {
        let (id, team, _) = candidates[0];
        return Some((id, team));
    }

    candidates
        .iter()
        .max_by(|a, b| {
            a.2.total_cmp(&b.2)
                .then_with(|| b.0.cmp(&a.0))
                .then_with(|| (b.1 as u8).cmp(&(a.1 as u8)))
        })
        .map(|(id, team, _)| (*id, *team))
}

fn learned_generic_pass_killer_upgrade_target_for(
    player: &PlayerAgent,
    snapshot: &WorldSnapshot,
    observation: &SoccerPomdpObservation,
    visible_targets: &[usize],
) -> Option<usize> {
    if !observation.has_ball
        || player.role == PlayerRole::Goalkeeper
        || !observation.threaded_goal_pass_available
        || observation.visible_forward_pass_options == 0
        || observation.yards_to_goal > KILLER_PASS_MAX_YARDS_TO_GOAL
    {
        return None;
    }
    let goal_thread_pressure = single_pass_goal_thread_pressure_score(observation)
        .max(killer_pass_goal_pressure_score(observation))
        .max(observation.killer_pass_goal_pressure.clamp(0.0, 1.0))
        .max(observation.decisive_goal_action_pressure.clamp(0.0, 1.0) * 0.82);
    if goal_thread_pressure < 0.58
        && !threaded_goal_pass_can_override_forced_shot(observation, player.role)
    {
        return None;
    }
    let target = snapshot.killer_pass_target_for(player.id, visible_targets)?;
    if snapshot
        .pending_offside_for_pass(player.id, target)
        .is_some()
    {
        return None;
    }
    Some(target)
}

fn restart_kind_action(kind: BallRestartKind) -> &'static str {
    match kind {
        BallRestartKind::ThrowIn => "throw-in",
        BallRestartKind::GoalKick => "goal-kick",
        BallRestartKind::CornerKick => "corner-kick",
        BallRestartKind::FreeKick => "free-kick",
    }
}

fn restart_kind_label(kind: BallRestartKind) -> &'static str {
    match kind {
        BallRestartKind::ThrowIn => "throw-in",
        BallRestartKind::GoalKick => "goal kick",
        BallRestartKind::CornerKick => "corner",
        BallRestartKind::FreeKick => "free kick",
    }
}

fn learned_action_label_is_legal(action: &str, snapshot: &WorldSnapshot, player_id: usize) -> bool {
    let action = normalize_soccer_action_label(action);
    let Some(player) = snapshot.players.iter().find(|p| p.id == player_id) else {
        return false;
    };
    let observation = snapshot.observation_for(player_id);
    learned_action_label_is_legal_for_observation(action, snapshot, player_id, player, &observation)
}

fn learned_action_label_is_legal_for_observation(
    action: &str,
    snapshot: &WorldSnapshot,
    player_id: usize,
    player: &PlayerSnapshot,
    observation: &SoccerPomdpObservation,
) -> bool {
    let action = normalize_soccer_action_label(action);
    let held_restart = held_restart_action_for_snapshot(snapshot, player_id);
    if let Some(restart_label) = held_restart {
        return match restart_label {
            "throw-in" => is_pass_like_action(action),
            "corner-kick" => is_pass_like_action(action) || matches!(action, "shoot"),
            "goal-kick" | "kickoff" => is_pass_like_action(action),
            "free-kick" => is_pass_like_action(action) || matches!(action, "shoot"),
            _ => false,
        };
    }
    let goal_attack_blocks_alternatives =
        goal_attack_shot_blocks_alternatives(&observation, player.role);
    let player_position = snapshot
        .player_position(player_id)
        .unwrap_or(player.position);
    let directive = snapshot.tactical_directive(player.team);
    let flank_lane_fit = ((player_position.x - snapshot.field_width * 0.5).abs()
        / (snapshot.field_width * 0.5).max(1.0))
    .clamp(0.0, 1.0);
    let outside_midfielder = player.role == PlayerRole::Midfielder
        && (player.home_position.x < snapshot.field_width * 0.30
            || player.home_position.x > snapshot.field_width * 0.70);
    let committed_crash_box_cross_release = directive.attack_strategy
        == TeamAttackStrategy::CrashTheBox
        && wide_final_third_cross_lane_context(
            player.team,
            player_position,
            snapshot.field_width,
            snapshot.field_length,
        );
    let committed_byline_cross_release = (player.role == PlayerRole::Forward || outside_midfielder)
        && (flank_lane_fit >= BYLINE_DRIVE_MIN_WIDTH_FROM_CENTER
            || committed_crash_box_cross_release)
        && directive.attack_strategy == TeamAttackStrategy::CrashTheBox
        && (directive.flank_attack_policy.is_flank() || committed_crash_box_cross_release);
    match action {
        "keeper-survey-hands" => {
            player.role == PlayerRole::Goalkeeper
                && observation.has_ball
                && snapshot.goalkeeper_can_use_hands_at(player.team, player.position)
        }
        "keeper-foot-control-outside-box" => {
            player.role == PlayerRole::Goalkeeper
                && observation.has_ball
                && !snapshot.goalkeeper_can_use_hands_at(player.team, player.position)
        }
        "keeper-mpc-floor-pass" => {
            player.role == PlayerRole::Goalkeeper
                && observation.has_ball
                && snapshot
                    .goalkeeper_mpc_play_out_plan(player_id, None)
                    .is_some_and(|plan| {
                        plan.target_player.is_some() && plan.flight == PassFlight::Floor
                    })
        }
        "keeper-mpc-aerial-pass" => {
            player.role == PlayerRole::Goalkeeper
                && observation.has_ball
                && snapshot
                    .goalkeeper_mpc_play_out_plan(player_id, None)
                    .is_some_and(|plan| {
                        plan.target_player.is_some() && plan.flight != PassFlight::Floor
                    })
        }
        "keeper-mpc-clearance" => {
            player.role == PlayerRole::Goalkeeper
                && observation.has_ball
                && snapshot
                    .goalkeeper_mpc_play_out_plan(player_id, None)
                    .is_some_and(|plan| plan.target_player.is_none())
        }
        "keeper-position" => player.role == PlayerRole::Goalkeeper && !observation.has_ball,
        "keeper-save" => false,
        "shoot" => {
            observation.has_ball
                && (shot_decision_is_qualified_for_role(&observation, player.role)
                    || speculative_long_shot_is_qualified(
                        &observation,
                        player.role,
                        ability01(player.skills.shooting),
                    ))
        }
        "pass" => observation.has_ball && snapshot.best_visible_pass_target(player_id).is_some(),
        "wall-pass" => observation.has_ball && snapshot.wall_pass_option_for(player_id).is_some(),
        "wall-return" => {
            observation.has_ball && snapshot.wall_return_pass_target_for(player_id).is_some()
        }
        "killer-pass" => {
            observation.has_ball
                && (!goal_attack_blocks_alternatives
                    || threaded_goal_pass_can_override_forced_shot(&observation, player.role))
                && snapshot
                    .killer_pass_target_for(
                        player_id,
                        &snapshot.ranked_visible_pass_targets(player_id, 5),
                    )
                    .is_some()
        }
        "aerial-pass" => {
            observation.has_ball && snapshot.best_aerial_pass_target(player_id).is_some()
        }
        "flank-low-cross" => {
            observation.has_ball
                && (flank_cross_context_is_legal(
                    &observation,
                    player_position,
                    snapshot.field_width,
                ) || committed_crash_box_cross_release)
                && (!goal_attack_blocks_alternatives || committed_byline_cross_release)
                && !snapshot
                    .ranked_visible_pass_targets(player_id, 1)
                    .is_empty()
        }
        "flank-high-cross" => {
            observation.has_ball
                && (flank_cross_context_is_legal(
                    &observation,
                    player_position,
                    snapshot.field_width,
                ) || committed_crash_box_cross_release)
                && (!goal_attack_blocks_alternatives || committed_byline_cross_release)
                && !snapshot
                    .ranked_visible_aerial_pass_targets(player_id, 1)
                    .is_empty()
        }
        "corner-flag-cross" => {
            observation.has_ball
                && (flank_cross_context_is_legal(
                    &observation,
                    player_position,
                    snapshot.field_width,
                ) || committed_crash_box_cross_release)
                && (!goal_attack_blocks_alternatives || committed_byline_cross_release)
                && (!snapshot
                    .ranked_visible_pass_targets(player_id, 1)
                    .is_empty()
                    || !snapshot
                        .ranked_visible_aerial_pass_targets(player_id, 1)
                        .is_empty())
        }
        "clearance" => observation.has_ball && observation.perceived_pressure >= 0.35,
        "route-one" => PlayerAgent::learned_route_one_viable(
            &observation,
            player.role,
            ability01(player.skills.dribbling),
            snapshot.route_one_target_for(player_id).is_some(),
        ),
        "first-time-shot" | "first-time-header" => {
            observation.has_ball
                && observation.first_touch_available
                && first_time_shot_decision_is_qualified_for_role(&observation, player.role)
        }
        "first-time-pass" => {
            observation.has_ball
                && observation.first_touch_available
                && snapshot.best_visible_pass_target(player_id).is_some()
        }
        "surprise-pass" => {
            observation.has_ball
                && (snapshot.scoop_pass_target_for(player_id).is_some()
                    || snapshot.best_visible_pass_target(player_id).is_some())
        }
        "flick-on" => {
            observation.has_ball
                && observation.first_touch_available
                && snapshot.best_aerial_pass_target(player_id).is_some()
        }
        "control-touch" => observation.has_ball && observation.first_touch_available,
        "dribble" | "carry-forward" | "open-pass-lane" => observation.has_ball,
        "open-passing-lane" => {
            observation.has_ball
                && player.role != PlayerRole::Goalkeeper
                && snapshot
                    .dribble_to_open_passing_lane_for(player_id)
                    .is_some()
        }
        "wait-for-support" => {
            observation.has_ball && snapshot.hold_for_support_option_for(player_id).is_some()
        }
        "runaround-dribble" => {
            observation.has_ball && snapshot.runaround_dribble_option_for(player_id).is_some()
        }
        "round-goalkeeper" => {
            observation.has_ball
                && player.role != PlayerRole::Goalkeeper
                && (6.0..=26.0).contains(&observation.yards_to_goal)
                && observation.forward_dribble_space_yards >= 0.75
                && snapshot
                    .players
                    .iter()
                    .any(|p| p.team != player.team && p.role == PlayerRole::Goalkeeper)
        }
        "vertical-attack" => {
            observation.has_ball
                || (!observation.has_ball
                    && snapshot.controlled_possession_team() == Some(player.team))
        }
        "turnover-burst" => {
            observation.has_ball
                && observation.perceived_time_on_ball_seconds <= 0.85
                && observation.forward_dribble_space_yards >= 1.0
        }
        "carry-out-left" | "carry-out-right" => {
            observation.has_ball
                && !goal_attack_blocks_alternatives
                && !goal_approach_forces_goalmouth_carry(&observation, player.role)
        }
        "protect-ball" => {
            observation.has_ball
                && (observation.nearest_opponent_distance <= 5.2
                    || observation.perceived_pressure >= 0.24)
        }
        "hold-up-flank" => {
            observation.has_ball
                && player.role == PlayerRole::Forward
                && observation.yards_to_goal
                    > tunables().shooting.striker_hold_up_min_goal_distance_yards
                && snapshot
                    .striker_hold_up_flank_target_for(player_id)
                    .is_some()
        }
        "left-cut" | "right-cut" | "nutmeg" | "fake-left-cut-right" | "fake-right-cut-left" => {
            observation.has_ball && observation.nearest_opponent_distance <= 5.6
        }
        "side-step" => {
            observation.has_ball
                && observation.nearest_opponent_distance <= 4.6
                && observation.perceived_pressure >= 0.28
        }
        "defend" | "defend-shape" | "defend-roam" => {
            snapshot.controlled_possession_team() == Some(player.team.other())
        }
        "press-cover" => {
            player.role != PlayerRole::Goalkeeper
                && snapshot.controlled_possession_team() == Some(player.team.other())
                && snapshot.ball.holder.is_some()
        }
        "recover" => snapshot.controlled_possession_team().is_none(),
        "tackle" => snapshot.ball.holder.is_some_and(|holder| {
            snapshot
                .players
                .iter()
                .find(|p| p.id == holder)
                .is_some_and(|holder_player| {
                    if holder_player.team != player.team.other() {
                        return false;
                    }
                    let player_position = snapshot.player_snapshot_position(player);
                    let holder_position = snapshot.player_snapshot_position(holder_player);
                    let my_depth = snapshot.depth_from_own_goal_y(player.team, player_position.y);
                    let holder_depth =
                        snapshot.depth_from_own_goal_y(player.team, holder_position.y);
                    my_depth <= holder_depth + 0.85
                        && player_position.distance(holder_position) <= 1.85
                })
        }),
        "slide-tackle" => {
            snapshot.slide_tackle_enabled
                && player.role != PlayerRole::Goalkeeper
                && snapshot.ball.holder.is_some_and(|holder| {
                    snapshot
                        .players
                        .iter()
                        .find(|p| p.id == holder)
                        .is_some_and(|holder_player| {
                            if holder_player.team != player.team.other() {
                                return false;
                            }
                            let player_position = snapshot.player_snapshot_position(player);
                            let holder_position = snapshot.player_snapshot_position(holder_player);
                            let distance = player_position.distance(holder_position);
                            let holder_speed = snapshot
                                .player_velocity(holder)
                                .unwrap_or(holder_player.velocity)
                                .len();
                            (SLIDE_TACKLE_MIN_REACH_YARDS..=SLIDE_TACKLE_MAX_REACH_YARDS)
                                .contains(&distance)
                                && !snapshot.tackle_blocked_from_behind(holder, player_position)
                                && holder_speed >= SLIDE_TACKLE_MIN_HOLDER_SPEED_YPS
                                && snapshot.advancing_carrier_steal_urgency(player_id)
                                    >= SLIDE_TACKLE_MIN_COMMIT_URGENCY
                        })
                })
        }
        "blindside-steal" => {
            player.role != PlayerRole::Goalkeeper
                && snapshot.blindside_steal_assessment(player_id).is_some()
        }
        "check-to-ball" => {
            !observation.has_ball
                && snapshot.controlled_possession_team() == Some(player.team)
                && snapshot
                    .check_to_ball_target_for(player_id, player.home_position)
                    .is_some()
        }
        "run-in-behind" => {
            !observation.has_ball
                && snapshot.controlled_possession_team() == Some(player.team)
                && snapshot.in_behind_run_target_for(player_id).is_some()
        }
        "wide-outlet" => {
            !observation.has_ball
                && snapshot.controlled_possession_team() == Some(player.team)
                && snapshot
                    .wide_possession_outlet_target_for(player_id, player.home_position)
                    .is_some()
        }
        "pinch-cross-arrival" => {
            !observation.has_ball
                && snapshot.controlled_possession_team() == Some(player.team)
                && snapshot
                    .flank_cross_arrival_target_for(player_id, player.home_position)
                    .is_some()
        }
        "one-two-run" => {
            !observation.has_ball
                && snapshot.controlled_possession_team() == Some(player.team)
                && snapshot.one_two_run_target_for(player_id).is_some()
        }
        "dummy-clear-lane" => {
            !observation.has_ball
                && snapshot.controlled_possession_team() == Some(player.team)
                && snapshot
                    .teammate_pass_lane_clearance_target_for(player_id)
                    .is_some()
        }
        "dummy-let-run" => {
            !observation.has_ball
                && snapshot
                    .teammate_dummy_let_run_target_for(player_id)
                    .is_some()
        }
        "lane-yield" => {
            !observation.has_ball
                && snapshot.controlled_possession_team() == Some(player.team)
                && snapshot
                    .pass_lane_yield_target_for(player_id, player.home_position)
                    .is_some()
        }
        "buildup-receive" => {
            !observation.has_ball
                && player.role == PlayerRole::Defender
                && snapshot.goalkeeper_will_safely_collect(player.team)
        }
        "exploit-space-run" | "shot-creation-run" | "overlap-run" | "support-push-up"
        | "support-screen" | "vacate-space" | "support-shape" | "support-roam" | "set-play-run" => {
            !observation.has_ball && snapshot.controlled_possession_team() == Some(player.team)
        }
        "space" => !observation.has_ball,
        "hold" => false,
        "human-move" => false,
        _ => false,
    }
}

pub fn shot_lane_is_clear(snapshot: &WorldSnapshot, player_id: usize) -> bool {
    let Some(player) = snapshot.players.iter().find(|p| p.id == player_id) else {
        return false;
    };
    snapshot.shot_lane_clear(player.position, player.team, 3.0)
}

fn approach_velocity(current: Vec2, desired: Vec2, accel: f64, dt: f64) -> Vec2 {
    let delta = desired - current;
    let max_delta = accel * dt;
    if delta.len() <= max_delta {
        desired
    } else {
        current + delta.normalized() * max_delta
    }
}

/// The concrete gait at effort tier `target_tier` to use as an intermediate step while
/// walking a multi-gear change through one tier at a time, taking the forward/backward
/// character from `desired` (which the step is heading toward). Backward travel never
/// reaches a forward run/sprint, so tiers 3-4 are the forward Run/Sprint.
fn gait_at_tier_toward(target_tier: u8, desired: MovementGait) -> MovementGait {
    match target_tier {
        0 => MovementGait::Stand,
        1 => {
            if desired.is_backward() {
                MovementGait::BackWalk
            } else {
                MovementGait::Walk
            }
        }
        2 => {
            if desired.is_backward() {
                MovementGait::BackJog
            } else {
                MovementGait::Jog
            }
        }
        3 => MovementGait::Run,
        _ => MovementGait::Sprint,
    }
}

/// Apply the gait-commitment dwell to a freshly-decided gait, modelling locomotor
/// momentum. Once an effort tier is entered it is held for [`GAIT_COMMIT_SECONDS`]
/// before changing in EITHER direction, so effort cannot oscillate tick-to-tick (the
/// "sprint, run, sprint, run" jitter). Decisive acts bypass the lock: setting off from
/// a standstill, pulling up to a full stop (you can always brake to a halt), and an
/// `emergency` (an explosive reaction to a threat / flat-out recovery). The dwell thus
/// governs only oscillation *between moving gaits*, and only bites within the window
/// after a change: a gait held a while already satisfies it and switches immediately.
///
/// When `step_limited` is set, a change between moving gaits is additionally taken ONE
/// effort tier at a time: a body cannot teleport across gears (sprint→walk, run→walk) in
/// a single tick, so a multi-gear change is walked through its intermediate gaits, one
/// per dwell. Because the committed gait is what drives the body's target speed, both
/// the displayed gait and the acceleration-limited legs then shed (or build) speed
/// together across several ticks rather than the label snapping ahead of the legs.
/// Same-tier swaps (e.g. jog→side-step) and adjacent single-tier changes pass straight
/// through, so this only ever intermediates a genuine multi-gear jump.
fn commit_gait(
    prev: MovementGait,
    desired: MovementGait,
    held_seconds: f64,
    emergency: bool,
    step_limited: bool,
) -> MovementGait {
    if desired == prev {
        return desired;
    }
    // Decisive acts performed without hesitation, never delayed: setting off from a
    // standstill (`prev` is `Stand`), pulling up to a full stop (`desired` is `Stand`),
    // and explosive emergency reactions. The dwell governs only oscillation *between
    // moving gaits* (sprint↔run↔jog), which is the jitter we are damping.
    if prev.effort_tier() == 0 || desired.effort_tier() == 0 || emergency {
        return desired;
    }
    // Hold the committed moving tier until it has been carried for the dwell.
    if held_seconds < GAIT_COMMIT_SECONDS {
        return prev;
    }
    // Dwell satisfied — the tier may change now. Legacy path: adopt the decision in one
    // go. Step-limited path: advance at most one effort tier toward it, so a multi-gear
    // change rolls through its intermediate gaits over successive dwells instead of
    // jumping (the per-tier dwell is the locomotor analogue of a bounded acceleration:
    // ~one gait band of speed change per ~0.2 s, close to a human accel/decel through a
    // gear). Same-tier swaps and single-tier changes are already byte-identical.
    if !step_limited {
        return desired;
    }
    let prev_tier = prev.effort_tier();
    let desired_tier = desired.effort_tier();
    if desired_tier == prev_tier {
        return desired;
    }
    let step_tier = if desired_tier > prev_tier {
        prev_tier + 1
    } else {
        prev_tier - 1
    };
    if step_tier == desired_tier {
        desired
    } else {
        gait_at_tier_toward(step_tier, desired)
    }
}

/// Apply the heading-reversal commitment to a desired velocity, modelling momentum
/// in the direction of travel. Gentle steering (≤90° off the committed heading) is
/// always honoured and continuously updates the committed heading. A sharp change of
/// direction (>90°, a cut-back) is locked until the committed heading has been held
/// for [`HEADING_REVERSAL_COMMIT_SECONDS`]; while locked, the player *brakes* (decided
/// velocity drops to zero so the accel-limiter sheds speed) rather than reversing on a
/// dime — this is the plant-and-cut a real player makes for a >90° change, and it also
/// means the lock never forces the body straight through a teammate it should have
/// steered around. `emergency` (being chased, or a flat-out defensive recovery)
/// bypasses the lock so a turn-and-run to keep up is never delayed. `held_seconds` is
/// the time already spent on the committed heading and `dt` this step's duration; the
/// dwell is accumulated per step rather than read off a clock, so it is correct
/// however the mover is driven. Returns the (possibly braked) desired velocity, the
/// updated committed heading, and the updated time-held.
fn commit_travel_heading(
    desired: Vec2,
    committed_heading: Option<Vec2>,
    held_seconds: f64,
    dt: f64,
    emergency: bool,
) -> (Vec2, Option<Vec2>, f64) {
    let speed = desired.len();
    if speed <= 1e-6 {
        // Not travelling: preserve the committed heading (so a momentary pause doesn't
        // wipe the line the player will resume along) and keep accumulating hold time.
        return (desired, committed_heading, held_seconds + dt);
    }
    let new_dir = desired / speed;
    match committed_heading {
        None => (desired, Some(new_dir), dt),
        Some(heading) => {
            let is_reversal = heading.dot(new_dir) < HEADING_REVERSAL_COS_THRESHOLD;
            let locked =
                is_reversal && !emergency && held_seconds < HEADING_REVERSAL_COMMIT_SECONDS;
            if locked {
                // Plant and brake: shed speed (accel-limiter does the actual decel)
                // rather than carve the reverse on a dime. Keep the committed heading
                // and accumulate hold time so the lock releases once the dwell is met.
                (Vec2::zero(), Some(heading), held_seconds + dt)
            } else if is_reversal {
                // Accept the reversal and restart the dwell on the new heading.
                (desired, Some(new_dir), dt)
            } else {
                // Gentle steering: slide the committed heading along, keep the clock.
                (desired, Some(new_dir), held_seconds + dt)
            }
        }
    }
}

fn classify_movement_gait(team: Team, to_target: Vec2, sprint: bool, chased: bool) -> MovementGait {
    let distance = to_target.len();
    if distance < 0.18 {
        return MovementGait::Stand;
    }

    let dir = to_target.normalized();
    let forwardness = dir.dot(Vec2::new(0.0, team.attack_dir()));
    let lateral = dir.x.abs();
    let vertical = dir.y.abs();
    // Any meaningful component back toward our own goal counts as retreating, so
    // a player keeps their eyes on the ball and back-pedals (walk/jog/skip
    // backward) instead of turning their back and running. Threshold widened
    // from -0.34 so shallow/diagonal recoveries also back-pedal.
    let retreating = forwardness < -0.12;
    let lateral_dominant = lateral > vertical * 1.18;

    if retreating && chased {
        // Being chased down by a fast attacker close behind: you can't back-pedal
        // fast enough, so turn and run/sprint toward your own goal to keep up.
        if sprint && distance > 1.0 {
            MovementGait::Sprint
        } else if distance > 1.0 {
            MovementGait::Run
        } else {
            MovementGait::BackWalk
        }
    } else if retreating && sprint && distance > 4.0 {
        // Urgent retreat means turn and run. A deliberate recovery sprint back toward our own
        // goal should not be reduced to a back-pedal just because the player is not being chased.
        if distance > 8.0 {
            MovementGait::Sprint
        } else {
            MovementGait::Run
        }
    } else if retreating {
        if distance <= 2.4 {
            MovementGait::BackWalk
        } else if distance <= 5.2 {
            MovementGait::BackJog
        } else {
            MovementGait::BackSkip
        }
    } else if sprint && distance > 1.0 {
        MovementGait::Sprint
    } else if lateral_dominant && distance > 0.75 && distance <= 7.0 {
        MovementGait::SideStep
    } else if distance <= 1.8 {
        MovementGait::Walk
    } else if distance <= 4.6 {
        MovementGait::Skip
    } else if distance <= 10.0 {
        MovementGait::Jog
    } else {
        MovementGait::Run
    }
}

#[derive(Clone, Copy, Debug)]
struct BallResistanceStep {
    velocity: Vec2,
    frame: BallResistanceFrame,
}

fn ball_resistance_after(
    velocity: Vec2,
    dt_seconds: f64,
    linear_drag_per_tick: f64,
    air_resistance: f64,
    grass_resistance_yps2: f64,
    altitude_yards: f64,
    stop_speed_yps: f64,
) -> BallResistanceStep {
    let speed = velocity.len();
    if speed <= 0.0 || dt_seconds <= 0.0 {
        return BallResistanceStep {
            velocity,
            frame: BallResistanceFrame {
                speed_before_yps: speed,
                speed_after_yps: speed,
                rolling_contact: if altitude_yards <= BALL_ROLLING_ALTITUDE_YARDS {
                    1.0
                } else {
                    0.0
                },
                stopped_by_threshold: speed > 0.0 && speed < stop_speed_yps.max(0.0),
                ..BallResistanceFrame::default()
            },
        };
    }
    let linear_drag = linear_drag_per_tick.clamp(0.0, 0.95);
    let reference_dt = DEFAULT_DT_SECONDS.max(1e-6);
    let linear_retention = (1.0 - linear_drag).powf((dt_seconds / reference_dt).max(0.0));
    let linear_speed_loss = speed * (1.0 - linear_retention);
    let air_deceleration = air_resistance.clamp(0.0, 0.10) * speed * speed;
    let rolling_contact = if altitude_yards <= BALL_ROLLING_ALTITUDE_YARDS {
        1.0
    } else {
        (1.0 - (altitude_yards - BALL_ROLLING_ALTITUDE_YARDS) / 0.18).clamp(0.0, 1.0)
    };
    let low_speed_grass_bonus = (1.0 - (speed / 12.0).clamp(0.0, 1.0)) * 0.62;
    let high_speed_turf_shear = ((speed - 12.0) / 24.0).clamp(0.0, 1.0).powi(2) * 0.42;
    let skidding_grass_bonus = ((speed - 28.0) / 24.0).clamp(0.0, 1.0) * 0.22;
    let grass_deceleration = grass_resistance_yps2.clamp(0.0, 5.0)
        * (1.0 + low_speed_grass_bonus + high_speed_turf_shear + skidding_grass_bonus)
        * rolling_contact;
    // In flight a ball meets far less effective drag than the per-tick ground
    // model implies over a long trajectory; relieve linear + air losses in
    // proportion to how airborne the ball is, so long aerial passes keep their
    // pace through the final third instead of dying late. A grounded ball
    // (rolling_contact = 1) is unchanged.
    let air_flight_relief = 1.0 - (1.0 - rolling_contact) * AERIAL_FLIGHT_DRAG_RELIEF;
    let linear_speed_loss = linear_speed_loss * air_flight_relief;
    let air_loss = air_deceleration * dt_seconds * air_flight_relief;
    let grass_loss = grass_deceleration * dt_seconds;
    let speed_loss = linear_speed_loss + air_loss + grass_loss;
    let speed_after = (speed - speed_loss).max(0.0);
    let stopped_by_threshold = speed_after > 0.0 && speed_after < stop_speed_yps.max(0.0);
    let final_speed = if stopped_by_threshold {
        0.0
    } else {
        speed_after
    };
    BallResistanceStep {
        velocity: velocity.normalized() * final_speed,
        frame: BallResistanceFrame {
            speed_before_yps: speed,
            speed_after_yps: final_speed,
            linear_drag_loss_yps: linear_speed_loss.min(speed),
            air_loss_yps: air_loss.min(speed),
            grass_loss_yps: grass_loss.min(speed),
            total_loss_yps: (speed - final_speed).max(0.0),
            rolling_contact,
            stopped_by_threshold,
        },
    }
}

fn ball_velocity_after_resistance(
    velocity: Vec2,
    dt_seconds: f64,
    linear_drag_per_tick: f64,
    air_resistance: f64,
    grass_resistance_yps2: f64,
    altitude_yards: f64,
) -> Vec2 {
    ball_resistance_after(
        velocity,
        dt_seconds,
        linear_drag_per_tick,
        air_resistance,
        grass_resistance_yps2,
        altitude_yards,
        0.0,
    )
    .velocity
}

fn zone(v: f64, max: f64, buckets: usize) -> usize {
    ((v / max).clamp(0.0, 0.999_999) * buckets as f64).floor() as usize
}

fn pitch_grid_cell(
    position: Vec2,
    field_width: f64,
    field_length: f64,
    columns: usize,
    rows: usize,
    level: PitchGridLevel,
    parent_id: Option<usize>,
) -> PitchGridCell {
    let columns = columns.max(1);
    let rows = rows.max(1);
    let x = zone(position.x, field_width, columns);
    let y = zone(position.y, field_length, rows);
    PitchGridCell {
        level,
        columns,
        rows,
        x,
        y,
        id: y * columns + x,
        parent_id,
    }
}

fn pitch_grid_address(position: Vec2, field_width: f64, field_length: f64) -> PitchGridAddress {
    let (field_width, field_length) = sane_pitch_dimensions(field_width, field_length);
    let whole_pitch = PitchGridCell::default();
    let macro_zone = pitch_grid_cell(
        position,
        field_width,
        field_length,
        PITCH_MACRO_GRID_COLUMNS,
        PITCH_MACRO_GRID_ROWS,
        PitchGridLevel::Macro,
        Some(whole_pitch.id),
    );
    let tactical = pitch_grid_cell(
        position,
        field_width,
        field_length,
        PITCH_TACTICAL_GRID_COLUMNS,
        PITCH_TACTICAL_GRID_ROWS,
        PitchGridLevel::Tactical,
        Some(macro_zone.id),
    );
    let fine = pitch_grid_cell(
        position,
        field_width,
        field_length,
        PITCH_FINE_GRID_COLUMNS,
        PITCH_FINE_GRID_ROWS,
        PitchGridLevel::Fine,
        Some(tactical.id),
    );
    PitchGridAddress {
        fine,
        tactical,
        macro_zone,
        whole_pitch,
    }
}

/// Cell-centre pitch position (yards) for a per-player genome anchor on the
/// `PITCH_GENOME_LANES × PITCH_GENOME_ROWS` (12 lanes × 24 rows) grid, oriented
/// for `team` (anchor `row` 0 = that team's OWN goal line, increasing toward the
/// opponent goal).
///
/// This is the exact inverse of the [`zone`] bucketing used by [`pitch_grid_cell`]:
/// a `(lane, row)` maps to the CENTRE of its fine cell, so feeding the result back
/// through [`pitch_grid_address`] lands in the same fine cell. It is the bridge
/// that lets the 12×24 grid be the single source of each player's field-position
/// affinity — especially by width, since `lane` is the x-axis and the existing
/// role lane band ([`role_vertical_lane_range`]) keys off `home_position.x`.
fn genome_anchor_home_position(
    lane: u8,
    row: u8,
    team: Team,
    field_width: f64,
    field_length: f64,
) -> Vec2 {
    let (field_width, field_length) = sane_pitch_dimensions(field_width, field_length);
    let lanes = PITCH_GENOME_LANES.max(1) as f64;
    let rows = PITCH_GENOME_ROWS.max(1) as f64;
    let lane = lane.min(PITCH_GENOME_LANES.saturating_sub(1)) as f64;
    let row = row.min(PITCH_GENOME_ROWS.saturating_sub(1)) as f64;
    let x = (lane + 0.5) / lanes * field_width;
    let own_goal_relative_y = (row + 0.5) / rows * field_length;
    let y = match team {
        Team::Home => own_goal_relative_y,
        Team::Away => field_length - own_goal_relative_y,
    };
    Vec2::new(x, y).clamp_to_pitch(field_width, field_length)
}

#[cfg(test)]
mod genome_anchor_home_position_tests {
    use super::*;

    const W: f64 = 80.0;
    const L: f64 = 120.0;

    #[test]
    fn anchor_round_trips_to_the_same_fine_cell() {
        // Every (lane, row) maps to a position that re-buckets to that exact fine
        // cell — the grid<->position bridge is loss-free over the 12×24 basis.
        for lane in 0..PITCH_GENOME_LANES {
            for row in 0..PITCH_GENOME_ROWS {
                let home = genome_anchor_home_position(lane, row, Team::Home, W, L);
                let fine = pitch_grid_address(home, W, L).fine;
                assert_eq!(fine.x, lane as usize, "lane {lane} row {row} x round-trip");
                assert_eq!(fine.y, row as usize, "lane {lane} row {row} y round-trip");
                // Away mirrors the row (own goal at the far end) but keeps the lane.
                let away = genome_anchor_home_position(lane, row, Team::Away, W, L);
                let away_fine = pitch_grid_address(away, W, L).fine;
                assert_eq!(away_fine.x, lane as usize, "away keeps the lane (width)");
                assert_eq!(
                    away_fine.y,
                    (PITCH_GENOME_ROWS - 1 - row) as usize,
                    "away mirrors the row"
                );
            }
        }
    }

    #[test]
    fn width_is_monotonic_in_lane() {
        let left = genome_anchor_home_position(2, 5, Team::Home, W, L);
        let right = genome_anchor_home_position(9, 5, Team::Home, W, L);
        assert!(
            right.x > left.x,
            "a higher lane sits further across the width"
        );
        // Lane is team-independent: away keeps the same x for the same lane.
        let away_left = genome_anchor_home_position(2, 5, Team::Away, W, L);
        assert!(
            (away_left.x - left.x).abs() < 1e-9,
            "lane→x is team-invariant"
        );
    }

    #[test]
    fn row_zero_sits_by_the_teams_own_goal() {
        // Home defends y≈0, Away defends y≈L, so an own-half (low-row) anchor is
        // deep for each team's own goal.
        let home_deep = genome_anchor_home_position(6, 0, Team::Home, W, L);
        let away_deep = genome_anchor_home_position(6, 0, Team::Away, W, L);
        assert!(home_deep.y < L * 0.1, "home row 0 hugs y≈0");
        assert!(away_deep.y > L * 0.9, "away row 0 hugs y≈L");
    }

    #[test]
    fn out_of_range_anchor_is_clamped_not_panicking() {
        let pos = genome_anchor_home_position(250, 250, Team::Home, W, L);
        assert!(pos.x >= 0.0 && pos.x <= W && pos.y >= 0.0 && pos.y <= L);
        let fine = pitch_grid_address(pos, W, L).fine;
        assert_eq!(fine.x, (PITCH_GENOME_LANES - 1) as usize);
        assert_eq!(fine.y, (PITCH_GENOME_ROWS - 1) as usize);
    }
}

fn facing_bucket_from_vector(v: Vec2) -> FacingBucket {
    if v.len() <= 1e-6 {
        return FacingBucket::Unknown;
    }
    facing_bucket_from_degrees(v.y.atan2(v.x).to_degrees())
}

fn facing_bucket_from_degrees(degrees: f64) -> FacingBucket {
    if !degrees.is_finite() {
        return FacingBucket::Unknown;
    }
    let mut degrees = degrees % 360.0;
    if degrees < 0.0 {
        degrees += 360.0;
    }
    let idx = ((degrees + 22.5) / 45.0).floor() as usize % 8;
    match idx {
        0 => FacingBucket::East,
        1 => FacingBucket::SouthEast,
        2 => FacingBucket::South,
        3 => FacingBucket::SouthWest,
        4 => FacingBucket::West,
        5 => FacingBucket::NorthWest,
        6 => FacingBucket::North,
        _ => FacingBucket::NorthEast,
    }
}

fn facing_bucket_to_vector(facing: FacingBucket) -> Option<Vec2> {
    match facing {
        FacingBucket::Unknown => None,
        FacingBucket::East => Some(Vec2::new(1.0, 0.0)),
        FacingBucket::SouthEast => Some(Vec2::new(1.0, 1.0).normalized()),
        FacingBucket::South => Some(Vec2::new(0.0, 1.0)),
        FacingBucket::SouthWest => Some(Vec2::new(-1.0, 1.0).normalized()),
        FacingBucket::West => Some(Vec2::new(-1.0, 0.0)),
        FacingBucket::NorthWest => Some(Vec2::new(-1.0, -1.0).normalized()),
        FacingBucket::North => Some(Vec2::new(0.0, -1.0)),
        FacingBucket::NorthEast => Some(Vec2::new(1.0, -1.0).normalized()),
    }
}

fn facing_bucket_clock_index(facing: FacingBucket) -> Option<i8> {
    match facing {
        FacingBucket::East => Some(0),
        FacingBucket::SouthEast => Some(1),
        FacingBucket::South => Some(2),
        FacingBucket::SouthWest => Some(3),
        FacingBucket::West => Some(4),
        FacingBucket::NorthWest => Some(5),
        FacingBucket::North => Some(6),
        FacingBucket::NorthEast => Some(7),
        FacingBucket::Unknown => None,
    }
}

fn facing_bucket_from_clock_index(index: i8) -> FacingBucket {
    match index.rem_euclid(8) {
        0 => FacingBucket::East,
        1 => FacingBucket::SouthEast,
        2 => FacingBucket::South,
        3 => FacingBucket::SouthWest,
        4 => FacingBucket::West,
        5 => FacingBucket::NorthWest,
        6 => FacingBucket::North,
        _ => FacingBucket::NorthEast,
    }
}

fn facing_bucket_rotate_one_step_toward(
    current: FacingBucket,
    target: FacingBucket,
) -> FacingBucket {
    let (Some(current_idx), Some(target_idx)) = (
        facing_bucket_clock_index(current),
        facing_bucket_clock_index(target),
    ) else {
        return target;
    };
    let clockwise = (target_idx - current_idx).rem_euclid(8);
    if clockwise == 0 {
        current
    } else if clockwise <= 1 || clockwise >= 7 {
        target
    } else if clockwise <= 4 {
        facing_bucket_from_clock_index(current_idx + 1)
    } else {
        facing_bucket_from_clock_index(current_idx - 1)
    }
}

fn ball_facing_bucket_from_position(
    team: Team,
    position: Vec2,
    ball_position: Vec2,
) -> FacingBucket {
    let to_ball = ball_position - position;
    if to_ball.len() > PLAYER_CONTROL_RADIUS_YARDS * 0.6 {
        facing_bucket_from_vector(to_ball)
    } else {
        default_team_facing(team)
    }
}

fn movement_action_facing_bucket(
    team: Team,
    position: Vec2,
    ball_position: Vec2,
    to_target: Vec2,
    velocity: Vec2,
    gait: MovementGait,
    has_ball: bool,
    current_facing: FacingBucket,
) -> FacingBucket {
    if has_ball && to_target.len() > 1e-6 {
        // Hysteresis: a carrier commits to a heading instead of flip-flopping the
        // target bucket on small intent wobbles. Keep the current facing unless the
        // intent points clearly away from it (beyond the deadband); only then
        // re-commit to where the movement now points. (The continuous facing_yaw is
        // still rate/accel-limited on top of this.)
        if current_facing != FacingBucket::Unknown {
            if let Some(current_vec) = facing_bucket_to_vector(current_facing) {
                let cur = current_vec.normalized();
                let intent = to_target.normalized();
                if cur.dot(intent) >= CARRIER_FACING_COMMIT_DOT {
                    return current_facing;
                }
            }
        }
        return facing_bucket_from_vector(to_target);
    }

    let to_ball = ball_position - position;
    if to_ball.len() <= PLAYER_CONTROL_RADIUS_YARDS * 0.6 && current_facing != FacingBucket::Unknown
    {
        return current_facing;
    }

    // A RUN or SPRINT faces the direction of travel — you cannot run/sprint sideways
    // or keep facing the ball while flat-out covering ground. (The slower gaits — walk
    // / jog / skip / side-step / back-pedal — keep the eyes on the ball to track play.)
    if matches!(gait, MovementGait::Run | MovementGait::Sprint)
        && to_target.len() > PLAYER_CONTROL_RADIUS_YARDS
    {
        return facing_bucket_from_vector(to_target);
    }

    let ball_facing = ball_facing_bucket_from_position(team, position, ball_position);
    if matches!(gait, MovementGait::Run | MovementGait::Sprint)
        && velocity.len() >= FAST_AWAY_FACING_MIN_SPEED_YPS
        && to_ball.len() > PLAYER_CONTROL_RADIUS_YARDS
        && to_target.len() > PLAYER_CONTROL_RADIUS_YARDS
        && velocity.normalized().dot(to_ball.normalized()) <= FAST_AWAY_FACING_BALL_DOT
        && to_target.normalized().dot(to_ball.normalized()) <= FAST_AWAY_FACING_BALL_DOT
    {
        return facing_bucket_from_vector(to_target);
    }

    if let Some(current) = facing_bucket_to_vector(current_facing) {
        let to_ball_dir = to_ball.normalized();
        if to_ball.len() > PLAYER_CONTROL_RADIUS_YARDS
            && current.normalized().dot(to_ball_dir) >= STABLE_CURRENT_FACING_BALL_DOT
        {
            return current_facing;
        }
        if to_ball.len() > PLAYER_CONTROL_RADIUS_YARDS {
            let urgent_ball_recovery = matches!(gait, MovementGait::Run | MovementGait::Sprint)
                && to_target.len() > PLAYER_CONTROL_RADIUS_YARDS
                && to_target.normalized().dot(to_ball_dir) >= 0.45;
            if urgent_ball_recovery {
                return ball_facing;
            }
            return facing_bucket_rotate_one_step_toward(current_facing, ball_facing);
        }
    }

    ball_facing
}

fn player_facing_vector_for_ball_control(player: &PlayerAgent, ball_pos: Vec2) -> Vec2 {
    facing_bucket_to_vector(player.action_facing)
        .or_else(|| {
            facing_bucket_to_vector(ball_facing_bucket_from_position(
                player.team,
                player.position,
                ball_pos,
            ))
        })
        .or_else(|| facing_bucket_to_vector(default_team_facing(player.team)))
        .unwrap_or_else(|| Vec2::new(0.0, player.team.attack_dir()))
}

/// Graded first-touch control quality from facing angle, whether the eyes are on the ball,
/// and ball speed. `facing_dot` is cos(angle between nose and ball): 1 dead-ahead, 0 at
/// 90deg, -1 behind. See the CONTROL_CONE_* constants.
fn control_cone_quality(facing_dot: f64, can_see_ball: bool, ball_speed_yps: f64) -> f64 {
    let cone = if facing_dot >= CONTROL_CONE_FULL_DOT {
        1.0
    } else if facing_dot >= CONTROL_CONE_DEFLECTION_DOT {
        // 60-120deg: degrade linearly from the floor (at 120deg) up to full (at 60deg).
        CONTROL_CONE_DEGRADED_FLOOR
            + (facing_dot - CONTROL_CONE_DEFLECTION_DOT)
                / (CONTROL_CONE_FULL_DOT - CONTROL_CONE_DEFLECTION_DOT)
                * (1.0 - CONTROL_CONE_DEGRADED_FLOOR)
    } else {
        CONTROL_CONE_DEFLECTION_QUALITY
    };
    let vision = if can_see_ball {
        1.0
    } else {
        CONTROL_OFF_VISION_FACTOR
    };
    let quality = cone * vision;
    let speed_fit = (ball_speed_yps / CONTROL_BALL_SPEED_REF_YPS).clamp(0.0, 1.0);
    (quality - (1.0 - quality) * speed_fit * CONTROL_BALL_SPEED_MISCONTROL).clamp(0.0, 1.0)
}

/// Whether the ball is within the player's field of view (eyes) — used to relax the control
/// cone, since the eyes (~270deg FOV) compensate for body orientation. Mirrors the
/// perception model's vision range + FOV.
fn player_can_see_ball_for_control(player: &PlayerAgent, ball_pos: Vec2) -> bool {
    let to_ball = ball_pos - player.position;
    let dist = to_ball.len();
    if dist <= FACING_GATE_AT_FEET_RADIUS_YARDS {
        return true;
    }
    if dist > vision_range_yards(player.skills.vision) {
        return false;
    }
    let facing = player_facing_vector_for_ball_control(player, ball_pos);
    let half_fov = field_of_view_degrees(player.skills.vision).to_radians() * 0.5;
    facing.dot(to_ball.normalized()) >= half_fov.cos()
}

fn player_facing_ball_control_multiplier(
    player: &PlayerAgent,
    ball_pos: Vec2,
    ball_speed_yps: f64,
) -> f64 {
    let to_ball = ball_pos - player.position;
    if to_ball.len() <= FACING_GATE_AT_FEET_RADIUS_YARDS {
        return 1.0;
    }
    let facing = player_facing_vector_for_ball_control(player, ball_pos);
    let facing_dot = facing.dot(to_ball.normalized());
    control_cone_quality(
        facing_dot,
        player_can_see_ball_for_control(player, ball_pos),
        ball_speed_yps,
    )
}

fn facing_bucket_matches(a: FacingBucket, b: FacingBucket) -> bool {
    a == b || a == FacingBucket::Unknown || b == FacingBucket::Unknown
}

fn default_team_facing(team: Team) -> FacingBucket {
    facing_bucket_from_vector(Vec2::new(0.0, team.attack_dir()))
}

fn default_agent_preferences(
    role: PlayerRole,
    shirt: u8,
    home_position: Vec2,
    field_width: f64,
) -> AgentPreferences {
    let mut preferences = AgentPreferences::default();
    let wide_position =
        home_position.x < field_width * 0.28 || home_position.x > field_width * 0.72;
    match role {
        PlayerRole::Goalkeeper => {
            preferences.offensive_mindedness = 0.08;
            preferences.defensive_mindedness = 0.92;
        }
        PlayerRole::Defender if wide_position => {
            preferences.open_space_bias = 0.74;
            preferences.offensive_mindedness = 0.58;
            preferences.defensive_mindedness = 0.66;
        }
        PlayerRole::Defender => {
            preferences.offensive_mindedness = 0.22;
            preferences.defensive_mindedness = 0.88;
        }
        PlayerRole::Midfielder if shirt == 6 => {
            preferences.pass_bias = 0.78;
            preferences.open_space_bias = 0.74;
            preferences.offensive_mindedness = 0.42;
            preferences.defensive_mindedness = 0.82;
        }
        PlayerRole::Midfielder if shirt == 8 => {
            preferences.pass_bias = 0.80;
            preferences.open_space_bias = 0.92;
            preferences.offensive_mindedness = 0.76;
            preferences.defensive_mindedness = 0.50;
        }
        PlayerRole::Midfielder => {
            preferences.pass_bias = 0.76;
            preferences.open_space_bias = 0.88;
            preferences.offensive_mindedness = 0.70;
            preferences.defensive_mindedness = 0.52;
        }
        PlayerRole::Forward => {
            preferences.shoot_bias = 0.78;
            preferences.pass_bias = 0.48;
            preferences.dribble_bias = 0.82;
            preferences.open_space_bias = 0.94;
            preferences.offensive_mindedness = 0.88;
            preferences.defensive_mindedness = 0.30;
        }
    }
    preferences
}

fn facing_bucket_for_player_motion(player: &PlayerAgent) -> FacingBucket {
    let facing = facing_bucket_from_vector(player.velocity);
    if facing == FacingBucket::Unknown {
        default_team_facing(player.team)
    } else {
        facing
    }
}

fn mark_player_receive_facing(players: &mut [PlayerAgent], holder_id: usize) {
    let Some(player) = players.iter_mut().find(|player| player.id == holder_id) else {
        return;
    };
    let facing = facing_bucket_for_player_motion(player);
    player.receive_facing = facing;
    player.action_facing = facing;
}

fn distance_bucket(value: f64, edges: &[f64]) -> u8 {
    if value.is_nan() {
        return 0;
    }
    if value == f64::NEG_INFINITY {
        return 0;
    }
    if value == f64::INFINITY {
        return edges.len().min(u8::MAX as usize) as u8;
    }
    edges
        .iter()
        .position(|edge| value <= *edge)
        .unwrap_or(edges.len())
        .min(u8::MAX as usize) as u8
}

fn confidence_bucket(value: f64) -> u8 {
    distance_bucket(value.clamp(0.0, 1.0), &[0.20, 0.40, 0.60, 0.80])
}

fn skill_bucket(value: f64) -> u8 {
    distance_bucket(ability_score(value), &[3.0, 5.0, 7.0, 9.0])
}

fn fatigue_advantage_bucket(value: f64) -> u8 {
    distance_bucket(value.clamp(-1.0, 1.0), &[-0.45, -0.15, 0.15, 0.45])
}

fn loose_ball_time_advantage_bucket(value: f64) -> u8 {
    distance_bucket(
        value.clamp(-3.0, 3.0),
        &[-1.20, -0.40, -0.12, 0.12, 0.40, 1.20],
    )
}

/// De-duplicate the W′-exhaustion speed cliff at the one site it actually double-counts. The
/// quadratic "burst tank empty" cliff in `fatigue_speed_factor` (keyed off the slow aerobic
/// `fatigue`) overlaps [`anaerobic_speed_ceiling`] (keyed off the W′ battery `anaerobic_load`)
/// — but the two are MULTIPLIED only at the executed-speed site (`move_player_towards`), which
/// is also the sole consumer of `anaerobic_speed_ceiling`. There a gassed player is slowed
/// twice for one exhausted state. ON: that site drops the cliff (via `split == true`) so the
/// W′-empty loss is applied ONCE, by `anaerobic_speed_ceiling`, leaving `fatigue_speed_factor`
/// to contribute only its aerobic taper. The ~40 OTHER callers are opponent/teammate speed
/// ESTIMATORS with no separate W′ term, so for them the cliff is a legitimate fatigue proxy
/// (not a duplicate) and is left intact. `DD_SOCCER_ENABLE_AEROBIC_ANAEROBIC_SPEED_SPLIT=1`
/// to enable; OFF is byte-identical. See the audit (finding #1).
pub(crate) fn dd_soccer_enable_aerobic_anaerobic_speed_split() -> bool {
    use std::sync::OnceLock;
    static V: OnceLock<bool> = OnceLock::new();
    *V.get_or_init(|| soccer_env_flag_enabled("DD_SOCCER_ENABLE_AEROBIC_ANAEROBIC_SPEED_SPLIT"))
}

fn player_pomdp_reaction_delay_seconds(read_skill: f64, fatigue: f64) -> f64 {
    let read = ability01(read_skill);
    let fatigue_drag = fatigue.clamp(0.0, 1.0);
    let perception = &tunables().pomdp_perception;
    let span = perception.player_reaction_span_seconds();
    (perception.player_reaction_max_seconds - span * read + fatigue_drag * span * 0.36).clamp(
        perception.player_reaction_min_seconds,
        perception.player_reaction_max_seconds,
    )
}

/// The full historical factor (aerobic taper + the deep-fatigue cliff), used everywhere except
/// the executed-speed site. Estimators have no separate `anaerobic_speed_ceiling` term, so they
/// keep the cliff as their sole gassed-proxy.
fn fatigue_speed_factor(stamina: f64, fatigue: f64) -> f64 {
    fatigue_speed_factor_inner(stamina, fatigue, false)
}

/// `split == false` is the historical factor (aerobic taper + the W′-mislabeled cliff).
/// `split == true` keeps only the aerobic taper, leaving the W′-empty burst loss solely to
/// [`anaerobic_speed_ceiling`] — used at the executed-speed site, which applies that ceiling.
/// Pure (no env read) so both branches are directly testable.
fn fatigue_speed_factor_inner(stamina: f64, fatigue: f64, split: bool) -> f64 {
    let cardio = ability01(stamina);
    let fatigue = fatigue.clamp(0.0, 1.0);
    // Aerobic taper: a gentle linear loss of pace as the player tires (the "all match"
    // critical-power regime).
    let base = 0.78 + 0.22 * cardio - fatigue * (0.18 + (1.0 - cardio) * 0.20);
    if split {
        // Executed-speed site only: `anaerobic_speed_ceiling` (keyed off the real W′ reserve)
        // supplies the burst-empty cliff here, so applying it again off `fatigue` would
        // double-count. Keep just the aerobic taper.
        return base.clamp(0.30, 1.05);
    }
    // Anaerobic reserve (W') exhaustion: past a high-fatigue knee the burst tank is empty,
    // so the player simply CANNOT reach top speed — a sharp drop (quadratic past the knee),
    // not the gentle aerobic taper. This is the hard ceiling, a player "hitting the wall";
    // a higher-stamina engine empties a touch later. Below the knee this is inert.
    // NOTE: this duplicates the W′ ceiling in `anaerobic_speed_ceiling` but keyed off the
    // wrong (aerobic) scalar — removed by `dd_soccer_enable_aerobic_anaerobic_speed_split`.
    let knee = ANAEROBIC_DEPLETION_KNEE + cardio * 0.06;
    let over_knee = ((fatigue - knee) / (1.0 - knee).max(1e-6)).clamp(0.0, 1.0);
    let depletion_drop = over_knee * over_knee * ANAEROBIC_DEPLETION_MAX_DROP;
    (base - depletion_drop).clamp(0.30, 1.05)
}

/// Critical power (metabolic W) — the highest demand a player can hold for
/// ~all match. Scales with cardio (`stamina`) and body mass.
fn player_critical_power_w(skills: &SkillProfile) -> f64 {
    let cardio = ability01(skills.stamina);
    let mass_kg = player_weight_pounds(skills.weight_pounds) * KG_PER_POUND;
    let w_per_kg = CRITICAL_POWER_MIN_W_PER_KG
        + cardio * (CRITICAL_POWER_MAX_W_PER_KG - CRITICAL_POWER_MIN_W_PER_KG);
    w_per_kg * mass_kg
}

/// Anaerobic work capacity W′ (metabolic J) — the finite "sprint battery" that
/// fuels efforts above critical power. Scales with cardio and body mass.
fn player_anaerobic_capacity_j(skills: &SkillProfile) -> f64 {
    let cardio = ability01(skills.stamina);
    let mass_kg = player_weight_pounds(skills.weight_pounds) * KG_PER_POUND;
    let j_per_kg = ANAEROBIC_CAPACITY_MIN_J_PER_KG
        + cardio * (ANAEROBIC_CAPACITY_MAX_J_PER_KG - ANAEROBIC_CAPACITY_MIN_J_PER_KG);
    (j_per_kg * mass_kg).max(1.0)
}

/// Estimated metabolic power demand (W) for moving at `speed_yps` while
/// accelerating at `accel_yps2`. Running cost grows with speed; speed changes
/// (accel/brake) cost more still — which is why repeated sprints, not steady
/// running, are what empty the anaerobic battery.
fn metabolic_power_demand_w(skills: &SkillProfile, speed_yps: f64, accel_yps2: f64) -> f64 {
    let mass_kg = player_weight_pounds(skills.weight_pounds) * KG_PER_POUND;
    // Clamp to the physical single-frame speed ceiling so a transient solver velocity
    // spike can't fabricate a huge demand and spuriously drain W′. (`max` over NaN
    // returns the finite operand, so a non-finite speed sanitises to 0.)
    let v_mps = speed_yps.max(0.0).min(SOCCER_PHYSICS_PLAYER_MAX_SPEED_YPS) * METERS_PER_YARD;
    let a_mps2 = (accel_yps2.abs() * METERS_PER_YARD).min(ACCEL_MAGNITUDE_CAP_MPS2);
    let run_power = mass_kg * RUN_ENERGY_COST_J_PER_KG_M * v_mps;
    let accel_power = mass_kg * a_mps2 * v_mps * ACCEL_POWER_COEFF;
    run_power + accel_power
}

/// Hard burst-speed ceiling from the anaerobic battery: ~full pace while it has
/// charge, with a steep cliff toward [`ANAEROBIC_CEILING_FLOOR`] as W′ → 0, so a
/// gassed player cannot reach top speed until the reserve recovers. This is the
/// *involuntary* limit — the occasional "legs are gone" moment.
fn anaerobic_speed_ceiling(anaerobic_load: f64) -> f64 {
    let load = anaerobic_load.clamp(0.0, 1.0);
    let linear = ANAEROBIC_CEILING_LINEAR_SAG * load;
    let cliff = if load > ANAEROBIC_CEILING_KNEE {
        let t = (load - ANAEROBIC_CEILING_KNEE) / (1.0 - ANAEROBIC_CEILING_KNEE);
        t * t * ANAEROBIC_CEILING_CLIFF_DROP
    } else {
        0.0
    };
    (1.0 - linear - cliff).clamp(ANAEROBIC_CEILING_FLOOR, 1.0)
}

/// Voluntary pacing throttle in `[PACING_FLOOR, 1.0]`. With the battery drawn
/// down and the current moment NOT a peak one (low `urgency`), a player cruises
/// to bank energy for the sprints that decide the game; fresh legs or a genuine
/// peak moment (high urgency) suppress the throttle entirely — that's when you
/// spend. This is the *common* energy constraint, distinct from the rare hard
/// ceiling in [`anaerobic_speed_ceiling`].
fn effort_pacing_factor(anaerobic_load: f64, urgency: f64) -> f64 {
    let load = anaerobic_load.clamp(0.0, 1.0);
    let urgency = urgency.clamp(0.0, 1.0);
    // How much of a non-peak moment is this? High urgency → conserve nothing.
    let conserve_room = 1.0 - urgency;
    // Only meaningfully conserve once the battery is past a comfortable margin.
    let depletion =
        ((load - PACING_RESERVE_COMFORT) / (1.0 - PACING_RESERVE_COMFORT)).clamp(0.0, 1.0);
    (1.0 - PACING_MAX_THROTTLE * conserve_room * depletion).clamp(PACING_FLOOR, 1.0)
}

fn fatigue_dribble_multiplier(observation: &SoccerPomdpObservation) -> f64 {
    let advantage = observation.perceived_fatigue_advantage.clamp(-1.0, 1.0);
    let confidence = observation
        .nearest_defender_fatigue_confidence
        .clamp(0.0, 1.0);
    let fresh_attacker = 1.0 - observation.fatigue.clamp(0.0, 1.0);
    let defender_tired = observation
        .perceived_nearest_defender_fatigue
        .clamp(0.0, 1.0);
    let cue_strength = confidence * (0.45 + fresh_attacker * 0.35 + defender_tired * 0.20);
    let bonus = (advantage - 0.10).max(0.0) * cue_strength * 1.15;
    let penalty = (-advantage - 0.10).max(0.0) * (0.45 + confidence * 0.25)
        + observation.fatigue.clamp(0.0, 1.0) * 0.24;
    (1.0 + bonus - penalty).clamp(0.45, 1.55)
}

fn shot_creation_carry_multiplier(observation: &SoccerPomdpObservation) -> f64 {
    if shot_decision_is_qualified(observation) {
        return 1.0;
    }
    let attacking_range =
        (1.0 - ((observation.yards_to_goal - 14.0).max(0.0) / 54.0)).clamp(0.0, 1.0);
    let almost_on_frame = (observation.shot_on_frame_probability
        / tunables().shooting.shot_on_frame_min_probability)
        .clamp(0.0, 1.0);
    let almost_beats_keeper = (observation.shot_beat_goalkeeper_probability
        / SHOT_KEEPER_BEAT_MIN_PROBABILITY)
        .clamp(0.0, 1.0);
    let low_block = (1.0 - observation.shot_block_probability).clamp(0.0, 1.0);
    let shot_promise =
        (almost_on_frame * 0.54 + almost_beats_keeper * 0.30 + low_block * 0.16).clamp(0.0, 1.0);
    let open_grass = (observation.forward_dribble_space_yards / 16.0).clamp(0.0, 1.0);
    (1.0 + attacking_range * shot_promise * 0.72 + open_grass * 0.18).clamp(1.0, 1.82)
}

fn floor_pass_quality_for_observation(observation: &SoccerPomdpObservation) -> f64 {
    (observation.expected_pass_completion.clamp(0.0, 1.0) * 0.64
        + observation.best_pass_receiver_openness.clamp(0.0, 1.0) * 0.36)
        .clamp(0.0, 1.0)
}

fn open_support_outlet_fit(observation: &SoccerPomdpObservation) -> f64 {
    (observation.open_support_outlets as f64 / 3.0).clamp(0.0, 1.0)
}

/// Multiplier (<=1) that discourages dribbling straight into an opponent: 2yd is
/// the open-play buffer and 3yd applies in the carrier's own half. The penalty is
/// soft, lighter near goal, and relieved when the nearest opponent is moving away.
fn dd_soccer_disable_dribble_turnover_safety_hardening() -> bool {
    use std::sync::OnceLock;
    static V: OnceLock<bool> = OnceLock::new();
    *V.get_or_init(|| std::env::var("DD_SOCCER_DISABLE_DRIBBLE_TURNOVER_SAFETY_HARDENING").is_ok())
}

fn dribble_into_opponent_penalty(
    forward_dribble_space_yards: f64,
    yards_to_goal: f64,
    yards_to_own_goal: f64,
    nearest_opponent_closing_rate_yps: f64,
) -> f64 {
    let own_half = dribble_own_half_from_distances(yards_to_goal, yards_to_own_goal);
    let min_space = dribble_comfort_space_yards_for_state(PlayerRole::Midfielder, own_half);
    if forward_dribble_space_yards >= min_space {
        return 1.0;
    }
    let moving_away_relief =
        dribble_moving_away_relief_from_closing_rate(nearest_opponent_closing_rate_yps);
    if moving_away_relief >= 0.70 && forward_dribble_space_yards >= min_space * 0.62 {
        return 1.0;
    }
    let closeness = (1.0 - forward_dribble_space_yards / min_space).clamp(0.0, 1.0)
        * (1.0 - moving_away_relief);
    let penalty_strength = if yards_to_goal <= FINAL_THIRD_ATTACK_YARDS_TO_GOAL {
        0.48
    } else {
        0.70
    };
    let base = (1.0 - closeness * penalty_strength).clamp(0.30, 1.0);
    if dd_soccer_disable_dribble_turnover_safety_hardening() {
        return base;
    }
    let turnover_safety_strength = if yards_to_goal <= FINAL_THIRD_ATTACK_YARDS_TO_GOAL {
        0.10
    } else if own_half {
        0.20
    } else {
        0.16
    };
    let safety_gate = (1.0 - closeness * turnover_safety_strength).clamp(0.76, 1.0);
    (base * safety_gate).clamp(0.24, 1.0)
}

fn pressure_release_signal(observation: &SoccerPomdpObservation) -> f64 {
    let base = observation
        .perceived_pressure
        .max(observation.pressure_urgency)
        .max(observation.immediate_dispossession_risk);
    let own_half =
        dribble_own_half_from_distances(observation.yards_to_goal, observation.yards_to_own_goal);
    let comfort_space = dribble_comfort_space_yards_for_state(PlayerRole::Midfielder, own_half);
    let moving_away_relief = dribble_moving_away_relief_from_closing_rate(
        observation
            .neural_extended
            .nearest_opponent_closing_rate_yps,
    );
    let close_gap_release = if observation.nearest_opponent_distance.is_finite() {
        (((comfort_space + 0.4 - observation.nearest_opponent_distance) / comfort_space)
            .clamp(0.0, 1.0)
            * 1.05
            * (1.0 - moving_away_relief))
            .clamp(0.0, 0.98)
    } else {
        0.0
    };
    // Rising pressure: a defender closing fast (high closing rate) shrinks the window
    // quickly, so treat it as urgent even before raw pressure has peaked — get rid of it.
    let closing_fit = (observation
        .neural_extended
        .nearest_opponent_closing_rate_yps
        / RISING_PRESSURE_CLOSING_RATE_YPS)
        .clamp(0.0, 1.0);
    ((base.max(close_gap_release).max(closing_fit * 0.9) - 0.34) / 0.48).clamp(0.0, 1.0)
}

fn pressured_release_multiplier(observation: &SoccerPomdpObservation) -> f64 {
    let quality = floor_pass_quality_for_observation(observation);
    let open_receiver = observation.best_pass_receiver_openness.clamp(0.0, 1.0);
    let open_support = open_support_outlet_fit(observation);
    let forward_option = (observation.visible_forward_pass_options as f64 / 2.0).clamp(0.0, 1.0);
    (1.0 + pressure_release_signal(observation)
        * (0.36
            + quality * 0.62
            + open_receiver * 0.24
            + open_support * 0.24
            + forward_option * 0.16))
        .clamp(1.0, 2.34)
}

fn ability_score(value: f64) -> f64 {
    if !value.is_finite() {
        return 1.0;
    }
    if (0.0..1.0).contains(&value) {
        1.0 + value.clamp(0.0, 1.0) * 9.0
    } else {
        value.clamp(1.0, 10.0)
    }
}

fn ability01(value: f64) -> f64 {
    (ability_score(value) - 1.0) / 9.0
}

fn default_player_weight_for_traits(
    role: PlayerRole,
    strength_score: f64,
    height_score: f64,
    jitter: f64,
) -> f64 {
    let role_base = match role {
        PlayerRole::Goalkeeper => 171.0,
        PlayerRole::Defender => 169.0,
        PlayerRole::Midfielder => 158.0,
        PlayerRole::Forward => 163.0,
    };
    let strength = ability01(strength_score);
    let height = ability01(height_score);
    (role_base + strength * 13.0 + height * 24.0 + jitter * 10.0).clamp(135.0, 225.0)
}

fn player_weight_pounds(value: f64) -> f64 {
    if value.is_finite() && value > 0.0 {
        value.clamp(115.0, 245.0)
    } else {
        default_player_weight_pounds()
    }
}

fn player_weight_bucket(value: f64) -> u8 {
    distance_bucket(player_weight_pounds(value), &[145.0, 165.0, 185.0, 205.0])
}

fn strength_to_weight_acceleration_multiplier_from_parts(
    strength_score: f64,
    weight_pounds: f64,
) -> f64 {
    let strength = ability01(strength_score);
    let weight_load = ((player_weight_pounds(weight_pounds) - 135.0) / 90.0).clamp(0.0, 1.0);
    (1.0 + (strength - weight_load) * 0.22).clamp(0.82, 1.18)
}

fn strength_to_weight_acceleration_multiplier(skills: &SkillProfile) -> f64 {
    strength_to_weight_acceleration_multiplier_from_parts(skills.strength, skills.weight_pounds)
}

fn top_speed_yps_from_score(score: f64) -> f64 {
    // `top_speed` is the 1.0-gait reference; a player's flat-out pace is this times the
    // Sprint gait multiplier (~1.12). Pick the reference so that the resulting sprint
    // runs between SPRINT_MIN_SPEED_MPH (low pace rating) and SPRINT_MAX_SPEED_MPH (elite)
    // — i.e. nobody sprints slower than ~22 mph and the quickest top out ~25 mph.
    let sprint_mult = MovementGait::Sprint.speed_multiplier().max(1e-6);
    let min_sprint = mph_to_yps(SPRINT_MIN_SPEED_MPH);
    let max_sprint = mph_to_yps(SPRINT_MAX_SPEED_MPH);
    (min_sprint + ability01(score) * (max_sprint - min_sprint)) / sprint_mult
}

fn player_top_speed_yps(role: PlayerRole, skills: &SkillProfile) -> f64 {
    let role_multiplier = if role == PlayerRole::Forward {
        FORWARD_TOP_SPEED_MULTIPLIER
    } else {
        1.0
    };
    // Cap the reference so even a forward's boosted sprint tops out at SPRINT_MAX, not
    // beyond — the forward bonus just gets them to the top of the band sooner.
    let sprint_mult = MovementGait::Sprint.speed_multiplier().max(1e-6);
    let max_reference = mph_to_yps(SPRINT_MAX_SPEED_MPH) / sprint_mult;
    (top_speed_yps_from_score(skills.top_speed) * role_multiplier).min(max_reference)
}

fn acceleration_yps2_from_score(score: f64) -> f64 {
    5.2 + ability01(score) * 4.1
}

fn height_inches_from_score(score: f64) -> f64 {
    65.0 + ability01(score) * 12.0
}

fn pressure_bucket(nearest_opponent_distance: f64) -> u8 {
    let pressure = (1.0 - nearest_opponent_distance / 18.0).clamp(0.0, 1.0);
    distance_bucket(pressure, &[0.15, 0.35, 0.60, 0.82])
}

// `rng` is retained for signature stability; squad skills are now deterministic
// per shirt (`SkillProfile::for_shirt`), so no randomness is drawn here.
fn default_formation_position(config: &MatchConfig, x: f64, y: f64) -> Vec2 {
    Vec2::new(
        x * config.field_width_yards / DEFAULT_FIELD_WIDTH_YARDS,
        y * config.field_length_yards / DEFAULT_FIELD_LENGTH_YARDS,
    )
    .clamp_to_pitch(config.field_width_yards, config.field_length_yards)
}

fn default_players(config: &MatchConfig, _rng: &mut SeededRandom) -> Vec<PlayerAgent> {
    let home_layout = vec![
        (
            "Home GK".to_string(),
            PlayerRole::Goalkeeper,
            1,
            default_formation_position(config, 40.0, 7.0),
        ),
        (
            "Home LB".to_string(),
            PlayerRole::Defender,
            2,
            default_formation_position(config, 14.0, 24.0),
        ),
        (
            "Home LCB".to_string(),
            PlayerRole::Defender,
            4,
            default_formation_position(config, 31.0, 23.0),
        ),
        (
            "Home RCB".to_string(),
            PlayerRole::Defender,
            5,
            default_formation_position(config, 49.0, 23.0),
        ),
        (
            "Home RB".to_string(),
            PlayerRole::Defender,
            3,
            default_formation_position(config, 66.0, 24.0),
        ),
        (
            "Home LM".to_string(),
            PlayerRole::Midfielder,
            11,
            default_formation_position(config, 17.0, 57.0),
        ),
        (
            "Home CM1".to_string(),
            PlayerRole::Midfielder,
            6,
            default_formation_position(config, 33.0, 55.0),
        ),
        (
            "Home CM2".to_string(),
            PlayerRole::Midfielder,
            8,
            default_formation_position(config, 47.0, 55.0),
        ),
        (
            "Home RM".to_string(),
            PlayerRole::Midfielder,
            7,
            default_formation_position(config, 63.0, 57.0),
        ),
        (
            "Home ST1".to_string(),
            PlayerRole::Forward,
            9,
            default_formation_position(config, 31.0, 78.0),
        ),
        (
            "Home ST2".to_string(),
            PlayerRole::Forward,
            10,
            default_formation_position(config, 49.0, 78.0),
        ),
    ];
    let away_layout = home_layout
        .iter()
        .map(|(name, role, shirt, pos)| {
            (
                name.replacen("Home", "Away", 1),
                *role,
                *shirt,
                Vec2::new(pos.x, config.field_length_yards - pos.y),
            )
        })
        .collect::<Vec<_>>();

    let mut players = Vec::with_capacity(22);
    for (team, layout) in [(Team::Home, home_layout), (Team::Away, away_layout)] {
        for (name, role, shirt, pos) in layout.into_iter() {
            let id = players.len();
            let preferences = default_agent_preferences(role, shirt, pos, config.field_width_yards);
            players.push(PlayerAgent {
                id,
                name,
                team,
                role,
                shirt,
                home_position: pos,
                position: pos,
                velocity: Vec2::zero(),
                acceleration: Vec2::zero(),
                jerk: Vec2::zero(),
                movement_gait: MovementGait::Stand,
                locomotion: LocomotionCommitment::default(),
                position_history: VecDeque::from([pos]),
                receive_facing: FacingBucket::Unknown,
                action_facing: default_team_facing(team),
                // Initial heading points up-pitch toward the attacking goal.
                facing_yaw: std::f64::consts::FRAC_PI_2 * team.attack_dir(),
                yaw_rate: 0.0,
                dizziness: 0.0,
                anaerobic_load: 0.0,
                last_tick_locomotion_joules: 0.0,
                sustained_sprint_seconds: 0.0,
                sustained_sprint_distance_yards: 0.0,
                same_team_proximity_dwell_lt7_seconds: 0.0,
                same_team_proximity_dwell_lt6_seconds: 0.0,
                same_team_proximity_dwell_lt5_seconds: 0.0,
                incoming_ball: None,
                // Deterministic, position-only skills: every player is the same
                // overall standard, shaped by their shirt (1-11) and identical
                // between the two teams, so neither side starts with a skill edge
                // and both learn from an equal footing. The blended-profile call is
                // retained only for signature compatibility; it no longer drives
                // live-match randomness.
                skills: {
                    let base = if seed_varied_skills_enabled() {
                        // A/B MEASUREMENT ONLY: the heuristic match is otherwise fully
                        // deterministic (skills/positions keyed on player id, `config.seed`
                        // inert), so multi-seed runs are byte-identical — n=1 scenario. Mixing
                        // `config.seed` into the skill jitter makes each seed an INDEPENDENT
                        // match. Both A/B arms share a seed ⇒ identical skills ⇒ the feature
                        // gate is the only difference. Off (default) ⇒ byte-identical to the
                        // deterministic build (same `blended` rng draw is still consumed).
                        SkillProfile::blended((id as u64 ^ config.seed as u64) as usize, role, _rng)
                    } else {
                        let _discarded_compat_profile = SkillProfile::blended(id, role, _rng);
                        SkillProfile::for_shirt(shirt, role)
                    };
                    // Asymmetric team handicap (env-gated, default 1.0 = no change).
                    base.handicap_scaled(soccer_team_skill_scale(team))
                },
                fatigue: 0.0,
                controller_slot: None,
                preferences,
                last_decision: None,
                pending_policy_behavior_probability: None,
                decision_confidence: 1.0,
                one_two: None,
                runaround: None,
                hold_for_support: None,
                slide_recovery_seconds: 0.0,
                decision_commit_ticks: VecDeque::new(),
                last_intent: None,
            });
        }
    }
    players
}

#[cfg(test)]
mod locomotion_commitment_tests {
    use super::*;

    fn test_carryover(
        action: &str,
        decision_tick: u64,
        commitment_ticks: Vec<u64>,
    ) -> SoccerPlayerTickCarryover {
        let mut carryover = SoccerPlayerTickCarryover {
            player_id: 7,
            decision_tick,
            observed_at_tick: decision_tick,
            age_ticks: 0,
            clock_seconds: 0.0,
            action: action.to_string(),
            action_target: None,
            mdp_phase: TacticalPhase::Kickoff,
            mdp_ball_grid: PitchGridAddress::default(),
            mdp_player_grid: PitchGridAddress::default(),
            mdp_receive_facing: FacingBucket::Unknown,
            mdp_action_facing: FacingBucket::Unknown,
            pomdp_visible_ball: true,
            pomdp_visible_teammates: 0,
            pomdp_visible_opponents: 0,
            pomdp_ball_position_confidence: 1.0,
            pomdp_teammate_position_confidence: 1.0,
            pomdp_opponent_position_confidence: 1.0,
            pomdp_perceived_pressure: 0.0,
            pomdp_decision_urgency: 0.0,
            decision_confidence: 1.0,
            mpc_guidance_present: false,
            chosen_action_mpc_feasibility: 1.0,
            mpc_comparison: None,
            executed_position: Vec2::zero(),
            executed_velocity: Vec2::zero(),
            executed_acceleration: Vec2::zero(),
            has_ball_after_action: false,
            same_action_ticks: 1,
            commitment_ticks,
            ticks_since_commitment: 0,
            recent_commitment_count_7_ticks: 0,
            decision_cadence_switch_locked: false,
        };
        soccer_refresh_decision_commitment_cadence(&mut carryover, decision_tick);
        carryover
    }

    #[test]
    fn decision_cadence_blocks_new_commitment_inside_three_ticks() {
        let carryover = test_carryover("carry-forward", 0, vec![0]);

        assert!(soccer_decision_commitment_cadence_blocks(
            Some(&carryover),
            "switch-play",
            2
        ));
        assert!(!soccer_decision_commitment_cadence_blocks(
            Some(&carryover),
            "switch-play",
            3
        ));
    }

    #[test]
    fn decision_cadence_allows_third_commitment_on_eighth_tick() {
        let carryover = test_carryover("switch-play", 3, vec![0, 3]);

        assert!(soccer_decision_commitment_cadence_blocks(
            Some(&carryover),
            "carry-forward",
            6
        ));
        assert!(!soccer_decision_commitment_cadence_blocks(
            Some(&carryover),
            "carry-forward",
            7
        ));
    }

    #[test]
    fn decision_cadence_repeating_same_commitment_does_not_spend_budget() {
        let carryover = test_carryover("switch-play", 3, vec![0, 3]);
        let history =
            soccer_decision_commitment_history_after_decision(Some(&carryover), "switch-play", 4);

        assert_eq!(history, vec![0, 3]);
        assert!(!soccer_decision_commitment_cadence_blocks(
            Some(&carryover),
            "switch-play",
            4
        ));
    }

    #[test]
    fn effort_tier_orders_gaits_by_intensity() {
        assert!(MovementGait::Sprint.effort_tier() > MovementGait::Run.effort_tier());
        assert!(MovementGait::Run.effort_tier() > MovementGait::Jog.effort_tier());
        assert!(MovementGait::Jog.effort_tier() > MovementGait::Walk.effort_tier());
        assert!(MovementGait::Walk.effort_tier() > MovementGait::Stand.effort_tier());
        // Backward / lateral variants share their forward intensity peer's tier.
        assert_eq!(
            MovementGait::BackJog.effort_tier(),
            MovementGait::Jog.effort_tier()
        );
        assert_eq!(
            MovementGait::BackWalk.effort_tier(),
            MovementGait::Walk.effort_tier()
        );
    }

    #[test]
    fn gait_holding_same_tier_is_a_no_op() {
        assert_eq!(
            commit_gait(
                MovementGait::Sprint,
                MovementGait::Sprint,
                0.0,
                false,
                false
            ),
            MovementGait::Sprint
        );
    }

    #[test]
    fn gait_change_is_locked_in_both_directions_until_the_dwell() {
        // The exact "sprint, run, sprint, run" case: a downshift before the dwell is
        // refused — the player stays sprinting.
        assert_eq!(
            commit_gait(MovementGait::Sprint, MovementGait::Run, 0.05, false, false),
            MovementGait::Sprint
        );
        // And the symmetric half: bouncing straight back UP to a sprint before the
        // dwell is refused too — this is what stops the half-rate oscillation that a
        // downshift-only lock leaves behind.
        assert_eq!(
            commit_gait(MovementGait::Run, MovementGait::Sprint, 0.05, false, false),
            MovementGait::Run
        );
        // Once the gait has been carried for the dwell, the change is allowed.
        assert_eq!(
            commit_gait(
                MovementGait::Sprint,
                MovementGait::Run,
                GAIT_COMMIT_SECONDS + 0.01,
                false,
                false
            ),
            MovementGait::Run
        );
    }

    #[test]
    fn pulling_up_to_a_stop_is_always_allowed() {
        // Coming to a halt is never locked, even straight from a flat-out sprint.
        assert_eq!(
            commit_gait(MovementGait::Sprint, MovementGait::Stand, 0.0, false, false),
            MovementGait::Stand
        );
        // ...nor under the step-limit (braking to a halt is a decisive single act).
        assert_eq!(
            commit_gait(
                MovementGait::Sprint,
                MovementGait::Stand,
                GAIT_COMMIT_SECONDS + 0.01,
                false,
                true
            ),
            MovementGait::Stand
        );
    }

    #[test]
    fn emergency_bypasses_the_gait_lock() {
        // An explosive reaction to a threat can spike effort instantly, dwell or not.
        assert_eq!(
            commit_gait(MovementGait::Jog, MovementGait::Sprint, 0.0, true, false),
            MovementGait::Sprint
        );
        // The step-limit also yields to an emergency: a flat-out burst is never staged.
        assert_eq!(
            commit_gait(MovementGait::Walk, MovementGait::Sprint, 1.0, true, true),
            MovementGait::Sprint
        );
    }

    #[test]
    fn setting_off_from_a_standstill_is_immediate() {
        // Starting to move is decisive, not jitter — no dwell from rest.
        assert_eq!(
            commit_gait(MovementGait::Stand, MovementGait::Sprint, 0.0, false, false),
            MovementGait::Sprint
        );
    }

    #[test]
    fn step_limit_walks_a_multi_gear_change_through_one_tier_at_a_time() {
        let held = GAIT_COMMIT_SECONDS + 0.01;
        // A run cannot drop straight to a walk: it sheds one tier to a jog first.
        assert_eq!(
            commit_gait(MovementGait::Run, MovementGait::Walk, held, false, true),
            MovementGait::Jog
        );
        // Continuing down from that jog, the next dwell reaches the walk.
        assert_eq!(
            commit_gait(MovementGait::Jog, MovementGait::Walk, held, false, true),
            MovementGait::Walk
        );
        // A flat-out sprint sheds to a run on the way down to a jog — never jog in one
        // tick.
        assert_eq!(
            commit_gait(MovementGait::Sprint, MovementGait::Jog, held, false, true),
            MovementGait::Run
        );
        // Sprint→walk likewise steps one gear: sprint→run.
        assert_eq!(
            commit_gait(MovementGait::Sprint, MovementGait::Walk, held, false, true),
            MovementGait::Run
        );
    }

    #[test]
    fn step_limit_builds_speed_one_gear_at_a_time_too() {
        let held = GAIT_COMMIT_SECONDS + 0.01;
        // A non-emergency upshift ramps: walk → jog, not straight to a sprint.
        assert_eq!(
            commit_gait(MovementGait::Walk, MovementGait::Sprint, held, false, true),
            MovementGait::Jog
        );
        assert_eq!(
            commit_gait(MovementGait::Jog, MovementGait::Sprint, held, false, true),
            MovementGait::Run
        );
    }

    #[test]
    fn step_limit_leaves_single_tier_and_same_tier_changes_untouched() {
        let held = GAIT_COMMIT_SECONDS + 0.01;
        // Adjacent single-tier change passes straight through (byte-identical).
        assert_eq!(
            commit_gait(MovementGait::Run, MovementGait::Jog, held, false, true),
            MovementGait::Jog
        );
        // Same effort tier, different gait (jog ↔ side-step): a free swap.
        assert_eq!(
            commit_gait(MovementGait::Jog, MovementGait::SideStep, held, false, true),
            MovementGait::SideStep
        );
    }

    #[test]
    fn step_limit_preserves_backward_character_on_the_way_down() {
        let held = GAIT_COMMIT_SECONDS + 0.01;
        // Dropping toward a back-walk from a forward run keeps the intermediate
        // backward: run → back-jog (tier 2, backward), not a forward jog.
        assert_eq!(
            commit_gait(MovementGait::Run, MovementGait::BackWalk, held, false, true),
            MovementGait::BackJog
        );
    }

    #[test]
    fn heading_first_move_commits_immediately() {
        let (vel, heading, held) =
            commit_travel_heading(Vec2::new(0.0, 5.0), None, 0.0, 0.1, false);
        assert_eq!(vel, Vec2::new(0.0, 5.0));
        assert!(heading.unwrap().distance(Vec2::new(0.0, 1.0)) < 1e-9);
        assert!((held - 0.1).abs() < 1e-9);
    }

    #[test]
    fn gentle_steering_is_free_and_keeps_accumulating_the_dwell() {
        // ~45° turn (< the 90° reversal threshold): honoured, dwell keeps accruing.
        let committed = Vec2::new(0.0, 1.0);
        let desired = Vec2::new(5.0, 5.0); // 45° off, speed ~7.07
        let (vel, heading, held) = commit_travel_heading(desired, Some(committed), 1.0, 0.1, false);
        assert!(vel.distance(desired) < 1e-9);
        assert!(heading.unwrap().distance(desired.normalized()) < 1e-9);
        assert!(
            (held - 1.1).abs() < 1e-9,
            "gentle steer must not restart the dwell"
        );
    }

    #[test]
    fn sharp_reversal_is_locked_then_released_after_the_dwell() {
        let committed = Vec2::new(0.0, 1.0);
        let reversal = Vec2::new(0.0, -6.0); // 180° about-face, speed 6
                                             // Held less than the dwell: the player plants and brakes (zero decided
                                             // velocity), the committed heading is kept, and the clock accrues toward release.
        let (vel, heading, held) =
            commit_travel_heading(reversal, Some(committed), 0.05, 0.02, false);
        assert!(
            vel.len() < 1e-9,
            "plant-and-brake while the reversal is locked"
        );
        assert!(heading.unwrap().distance(committed) < 1e-9);
        assert!((held - 0.07).abs() < 1e-9);
        // Held past the dwell: the about-face is accepted and the dwell restarts.
        let (vel, heading, held) = commit_travel_heading(
            reversal,
            Some(committed),
            HEADING_REVERSAL_COMMIT_SECONDS + 0.01,
            0.02,
            false,
        );
        assert!(vel.distance(reversal) < 1e-9);
        assert!(heading.unwrap().distance(Vec2::new(0.0, -1.0)) < 1e-9);
        assert!((held - 0.02).abs() < 1e-9);
    }

    #[test]
    fn emergency_bypasses_the_reversal_lock() {
        // A chase / flat-out recovery turn-and-run is never delayed.
        let committed = Vec2::new(0.0, 1.0);
        let reversal = Vec2::new(0.0, -6.0);
        let (vel, _heading, _held) =
            commit_travel_heading(reversal, Some(committed), 0.0, 0.1, true);
        assert!(vel.distance(reversal) < 1e-9);
    }
}

#[cfg(test)]
mod reward_priority_tests {
    use super::*;

    #[test]
    fn outcome_rewards_dominate_pass_only_shaping() {
        let max_completed_forward_pass = (COMPLETED_FORWARD_PASS_BASE_REWARD_OWN_HALF
            + COMPLETED_FORWARD_PASS_PROGRESS_REWARD_MAX_YARDS
                * COMPLETED_FORWARD_PASS_PROGRESS_REWARD_PER_YARD
            + COMPLETED_FLANK_PASS_BONUS_POINTS * COMPLETED_FLANK_PASS_OWN_HALF_MULTIPLIER)
            .max(
                COMPLETED_FORWARD_PASS_BASE_REWARD_OPPONENT_HALF
                    + COMPLETED_FORWARD_PASS_PROGRESS_REWARD_MAX_YARDS
                        * COMPLETED_FORWARD_PASS_PROGRESS_REWARD_PER_YARD
                    + COMPLETED_FLANK_PASS_BONUS_POINTS,
            );
        let max_dense_forward_pass = 24.0 * DENSE_FORWARD_PASS_PROGRESS_REWARD_PER_YARD;
        let three_pass_only_sequence = 3.0 * (max_completed_forward_pass + max_dense_forward_pass)
            + PASS_CHAIN_TWO_FORWARD_EVENT_REWARD_POINTS
            + PASS_CHAIN_THREE_NET_FORWARD_EVENT_REWARD_POINTS;

        assert!(
            three_pass_only_sequence < SHOT_ON_TARGET_REWARD_POINTS,
            "pass-only sequence {three_pass_only_sequence} should stay below shot-on-target {SHOT_ON_TARGET_REWARD_POINTS}"
        );
        assert!(
            SHOT_ON_TARGET_REWARD_POINTS < DIRECT_TURNOVER_GOAL_REWARD_POINTS,
            "any goal reward should outrank a shot on target"
        );
        assert!(
            DIRECT_TURNOVER_GOAL_REWARD_POINTS < GOAL_REWARD_POINTS,
            "full goal reward should outrank direct-turnover goal pool"
        );
        assert!(
            BUILDUP_CHAIN_CREDIT_GOAL_BASE_POINTS
                > BUILDUP_CHAIN_CREDIT_SHOT_ON_FRAME_BASE_POINTS
                    + BUILDUP_CHAIN_CREDIT_SHOT_BASE_POINTS,
            "goal buildup credit should dominate non-goal shot buildup credit"
        );
    }

    #[test]
    fn backward_interception_penalty_doubles_ordinary_pass_interception() {
        let forward = PendingPass {
            team: Team::Home,
            from: 6,
            target: Some(9),
            flight: PassFlight::Floor,
            is_cross: false,
            launch_tick: 0,
            origin: Vec2::new(40.0, 62.0),
            intended_target: Vec2::new(40.0, 74.0),
            distance_yards: 12.0,
            receiver_openness: 0.42,
            passer_skill: 1.0,
            launch_speed_yps: 18.0,
            receiver_position_at_launch: Some(Vec2::new(40.0, 74.0)),
            receiver_velocity_at_launch: Some(Vec2::zero()),
            offside: None,
            offside_candidates: Vec::new(),
            learn_features: Vec::new(),
        };
        let mut lateral = forward.clone();
        lateral.intended_target = Vec2::new(52.0, 62.0);
        lateral.receiver_position_at_launch = Some(lateral.intended_target);
        let mut backward = forward.clone();
        backward.intended_target = Vec2::new(40.0, 50.0);
        backward.receiver_position_at_launch = Some(backward.intended_target);

        let field_length = DEFAULT_FIELD_LENGTH_YARDS;
        let forward_penalty = intercepted_pass_passer_penalty(&forward, field_length);
        let lateral_penalty = intercepted_pass_passer_penalty(&lateral, field_length);
        let backward_penalty = intercepted_pass_passer_penalty(&backward, field_length);

        assert!(
            (forward_penalty - lateral_penalty).abs() < 1e-9,
            "forward/lateral interceptions should share the ordinary penalty curve"
        );
        assert!(
            (backward_penalty - forward_penalty * BACKWARD_INTERCEPTED_PASS_PENALTY_MULTIPLIER)
                .abs()
                < 1e-9,
            "backward intercepted pass penalty should be exactly doubled"
        );
    }
}

#[cfg(test)]
mod discretized_kick_scaffold_tests {
    use super::*;

    fn assert_close(actual: f64, expected: f64, tolerance: f64) {
        assert!(
            (actual - expected).abs() <= tolerance,
            "actual={actual} expected={expected} tolerance={tolerance}"
        );
    }

    #[test]
    fn discretized_kick_buckets_snap_power_and_absolute_direction() {
        let north = Vec2::new(0.0, 1.0);
        let west = Vec2::new(-1.0, 0.0);

        assert_eq!(discretized_kick_speed_bucket_for_power(-1.0), 0);
        assert_eq!(discretized_kick_speed_bucket_for_power(0.0), 0);
        assert_eq!(discretized_kick_speed_bucket_for_power(0.56), 5);
        assert_eq!(discretized_kick_speed_bucket_for_power(1.0), 9);
        assert_eq!(discretized_kick_direction_bucket_for_vector(north), 9);
        assert_eq!(discretized_kick_direction_bucket_for_vector(west), 18);
        assert_eq!(discretized_kick_direction_bucket_for_degrees(356.0), 0);
        assert_eq!(discretized_kick_direction_bucket_for_degrees(354.0), 35);

        let action = DiscretizedKickAction::from_power_direction(
            0.56,
            west,
            DiscretizedKickCurve::Right,
            DiscretizedKickTechnique::OutsideFoot,
            DiscretizedKickElevation::Floor,
        );
        assert_eq!(action.speed_bucket, 5);
        assert_eq!(action.direction_bucket, 18);
        assert_eq!(action.curve, DiscretizedKickCurve::Right);
        assert_eq!(action.technique, DiscretizedKickTechnique::OutsideFoot);
        assert_eq!(action.direction_degrees_center(), 180.0);
    }

    #[test]
    fn discretized_kick_dither_stays_inside_bucket() {
        let mut rng = SeededRandom::new(42);
        for _ in 0..128 {
            let dither = DiscretizedKickDither::sample(&mut rng);
            assert!(dither.speed_power_offset.abs() <= 0.050_000_1);
            assert!(dither.direction_degrees_offset.abs() <= 5.000_001);
            let power = discretized_kick_power_for_bucket(4, dither);
            assert!((0.40..=0.50).contains(&power));
        }

        let sanitized = DiscretizedKickDither {
            speed_power_offset: 9.0,
            direction_degrees_offset: -99.0,
        }
        .sanitized();
        assert_eq!(sanitized.speed_power_offset, 0.05);
        assert_eq!(sanitized.direction_degrees_offset, -5.0);
    }

    #[test]
    fn lower_discretized_kick_release_masks_short_slow_curve() {
        let action = DiscretizedKickAction::new(
            0,
            9,
            DiscretizedKickCurve::Left,
            DiscretizedKickTechnique::InsideFoot,
            DiscretizedKickElevation::Floor,
        );
        let release = lower_discretized_kick_release(
            Vec2::new(50.0, 50.0),
            action,
            0.0,
            mph_to_yps(12.0),
            8.0,
            2.0,
            DiscretizedKickDither::none(),
        );

        assert_eq!(release.launch_target, release.intended_target);
        assert_eq!(release.curl_acceleration, Vec2::zero());
        assert_eq!(release.technique, DiscretizedKickTechnique::None);
        assert_eq!(release.altitude_yards, 0.0);
    }

    #[test]
    fn lower_discretized_kick_release_curves_and_sets_altitude() {
        let action = DiscretizedKickAction::new(
            9,
            9,
            DiscretizedKickCurve::Left,
            DiscretizedKickTechnique::InsideFoot,
            DiscretizedKickElevation::Aerial,
        );
        let origin = Vec2::new(50.0, 40.0);
        let release = lower_discretized_kick_release(
            origin,
            action,
            mph_to_yps(20.0),
            mph_to_yps(50.0),
            30.0,
            2.0,
            DiscretizedKickDither::none(),
        );

        assert!(release.altitude_yards > BALL_ROLLING_ALTITUDE_YARDS);
        assert_eq!(release.technique, DiscretizedKickTechnique::InsideFoot);
        assert!(release.curl_acceleration.len() > 0.0);
        assert!(release.launch_target.x < release.intended_target.x);
        assert_close(release.launch_target.y, origin.y + 30.0, 1e-9);
        assert_close(release.velocity.len(), release.speed_yps, 1e-9);
    }

    #[test]
    fn outside_foot_long_aerial_kick_gets_more_magnus_bend_than_inside_floor() {
        let origin = Vec2::new(50.0, 40.0);
        let inside_floor = kick_release(KickReleaseSpec {
            origin,
            intended_target: Vec2::new(50.0, 72.0),
            speed_yps: mph_to_yps(36.0),
            curve: DiscretizedKickCurve::Left,
            technique: DiscretizedKickTechnique::InsideFoot,
            curve_bend_yards: 2.0,
            elevation: DiscretizedKickElevation::Floor,
        });
        let outside_aerial = kick_release(KickReleaseSpec {
            origin,
            intended_target: Vec2::new(50.0, 72.0),
            speed_yps: mph_to_yps(36.0),
            curve: DiscretizedKickCurve::Left,
            technique: DiscretizedKickTechnique::OutsideFoot,
            curve_bend_yards: 2.0,
            elevation: DiscretizedKickElevation::Aerial,
        });

        assert_eq!(inside_floor.technique, DiscretizedKickTechnique::InsideFoot);
        assert_eq!(
            outside_aerial.technique,
            DiscretizedKickTechnique::OutsideFoot
        );
        assert!(outside_aerial.altitude_yards > BALL_ROLLING_ALTITUDE_YARDS);
        assert!(
            outside_aerial
                .launch_target
                .distance(outside_aerial.intended_target)
                > inside_floor
                    .launch_target
                    .distance(inside_floor.intended_target)
                    * 1.25,
            "outside/aerial bend should exceed inside/floor bend"
        );
        assert!(
            outside_aerial.curl_acceleration.len() > inside_floor.curl_acceleration.len(),
            "outside/aerial curl acceleration should be stronger"
        );
    }

    #[test]
    fn discretized_pass_kick_round_trip_is_bounded() {
        // Phase 0: a continuous heuristic (speed, direction) encoded into the discrete
        // kick representation and lowered back is faithful to within HALF a bucket — the
        // quantization the gated live path will introduce, before any learned head.
        let min_yps = mph_to_yps(DISCRETIZED_KICK_PASS_MIN_SPEED_MPH);
        let max_yps = mph_to_yps(DISCRETIZED_KICK_PASS_MAX_SPEED_MPH);
        let origin = Vec2::new(20.0, 30.0);
        let half_bucket_speed =
            (max_yps - min_yps) / (2.0 * f64::from(DISCRETIZED_KICK_SPEED_BUCKETS));
        let half_bucket_cos = (DISCRETIZED_KICK_DIRECTION_BUCKET_DEGREES * 0.5)
            .to_radians()
            .cos();
        // (speed_yps, aim direction, pass distance) — all targets land well inside the pitch.
        let cases = [
            (mph_to_yps(22.0), Vec2::new(1.0, 0.3), 25.0),
            (mph_to_yps(35.0), Vec2::new(-0.4, 1.0), 18.0),
            (mph_to_yps(9.0), Vec2::new(0.2, -1.0), 12.0),
        ];
        for (speed, dir, distance) in cases {
            let action = DiscretizedKickAction::from_power_direction(
                discretized_kick_power_for_speed(speed, min_yps, max_yps),
                dir,
                DiscretizedKickCurve::None,
                DiscretizedKickTechnique::None,
                DiscretizedKickElevation::Floor,
            );
            let release = discretized_kick_release_clamped_to_pitch(
                origin,
                action,
                min_yps,
                max_yps,
                distance,
                0.0,
                DiscretizedKickDither::none(),
                DEFAULT_FIELD_WIDTH_YARDS,
                DEFAULT_FIELD_LENGTH_YARDS,
            );
            assert!(
                (release.speed_yps - speed).abs() <= half_bucket_speed + 1e-6,
                "speed {speed} -> {} exceeds half a bucket ({half_bucket_speed})",
                release.speed_yps
            );
            let cos = dir.normalized().dot(release.velocity.normalized());
            assert!(
                cos >= half_bucket_cos - 1e-9,
                "direction off by more than half a bucket (cos {cos})"
            );
            assert!(
                release.altitude_yards.abs() < 1e-9,
                "floor elevation lowers to ground altitude"
            );
        }
    }

    #[test]
    fn learned_discretized_kick_labels_preserve_pass_family_and_bucket() {
        let label = learned_discretized_kick_candidate_label("pass4", 7)
            .expect("ranked pass should accept a learned kick bucket");
        assert_eq!(label, "pass4-kp7");
        assert!(ranked_pass_action_label(&label));
        assert_eq!(normalize_soccer_action_label(&label), "pass");
        assert_eq!(
            soccer_policy_action_index(&label),
            soccer_policy_action_index("pass-kp7")
        );
        let pass_bucket_index =
            soccer_policy_action_index("pass-kp7").expect("pass bucket actor index");
        let (pass_bucket_group, pass_bucket_local) =
            soccer_policy_skill_group_for_action_index(pass_bucket_index)
                .expect("pass bucket should train the pass skill policy head");
        assert_eq!(pass_bucket_group, SoccerSkillGroup::Pass);
        assert_eq!(SOCCER_SKILL_PASS_FAMILIES[pass_bucket_local], "pass-kp7");
        assert_ne!(
            soccer_policy_action_index(&label),
            soccer_policy_action_index("pass")
        );
        assert_eq!(
            learned_mpc_action_label_key(&label),
            "pass4-kp7".to_string()
        );
        assert_eq!(
            learned_discretized_kick_speed_bucket_for_action_label(&label),
            Some(7)
        );
        assert!(
            (learned_discretized_kick_power_for_action_label(&label).unwrap() - 0.75).abs() < 1e-9
        );

        let aerial = learned_discretized_kick_candidate_label("aerial-pass2", 4)
            .expect("ranked aerial pass should accept a learned kick bucket");
        assert_eq!(normalize_soccer_action_label(&aerial), "aerial-pass");
        assert_eq!(
            soccer_policy_action_index(&aerial),
            soccer_policy_action_index("aerial-pass-kp4")
        );
        let aerial_bucket_index =
            soccer_policy_action_index("aerial-pass-kp4").expect("aerial bucket actor index");
        let (aerial_bucket_group, aerial_bucket_local) =
            soccer_policy_skill_group_for_action_index(aerial_bucket_index)
                .expect("aerial bucket should train the pass skill policy head");
        assert_eq!(aerial_bucket_group, SoccerSkillGroup::Pass);
        assert_eq!(
            SOCCER_SKILL_PASS_FAMILIES[aerial_bucket_local],
            "aerial-pass-kp4"
        );
        let uniform_pass_prob = 1.0 / SOCCER_SKILL_PASS_FAMILIES.len() as f64;
        let skill_log_probs = SoccerSkillLogProbs {
            pass: Some(vec![uniform_pass_prob; SOCCER_SKILL_PASS_FAMILIES.len()]),
            dribble: None,
            shot: None,
        };
        assert!(
            skill_log_probs
                .centered_log_prob_for_action_index(pass_bucket_index)
                .unwrap()
                .abs()
                < 1e-12
        );
        assert!(
            skill_log_probs
                .centered_log_prob_for_action_index(aerial_bucket_index)
                .unwrap()
                .abs()
                < 1e-12
        );
        assert_eq!(learned_discretized_kick_candidate_label("pass", 4), None);
        assert_eq!(learned_discretized_kick_candidate_label("pass1", 12), None);
    }

    #[test]
    fn kick_release_lowers_uncurled_target_without_changing_direction() {
        let release = kick_release(KickReleaseSpec {
            origin: Vec2::zero(),
            intended_target: Vec2::new(10.0, 0.0),
            speed_yps: 5.0,
            curve: DiscretizedKickCurve::None,
            technique: DiscretizedKickTechnique::None,
            curve_bend_yards: 3.0,
            elevation: DiscretizedKickElevation::from_pass_flight(PassFlight::Scoop),
        });

        assert_eq!(release.launch_target, Vec2::new(10.0, 0.0));
        assert_eq!(release.intended_target, Vec2::new(10.0, 0.0));
        assert_eq!(release.velocity, Vec2::new(5.0, 0.0));
        assert_eq!(release.curl_acceleration, Vec2::zero());
        assert!(release.altitude_yards > BALL_ROLLING_ALTITUDE_YARDS);
    }

    #[test]
    fn kick_release_can_clamp_curved_launch_target_to_pitch() {
        let release = kick_release_clamped_to_pitch(
            KickReleaseSpec {
                origin: Vec2::new(1.0, 10.0),
                intended_target: Vec2::new(1.0, 30.0),
                speed_yps: mph_to_yps(35.0),
                curve: DiscretizedKickCurve::Left,
                technique: DiscretizedKickTechnique::InsideFoot,
                curve_bend_yards: 4.0,
                elevation: DiscretizedKickElevation::Floor,
            },
            100.0,
            100.0,
        );

        assert_eq!(release.launch_target.x, 0.0);
        assert_eq!(release.intended_target, Vec2::new(1.0, 30.0));
        assert!(release.curl_acceleration.len() > 0.0);
    }
}

